INSERT INTO question_hints (question_id, hint_data) VALUES (1, '{"words":[{"plural":"","chinese":"你好","english":"hello","examples":["Hello, how are you?","Hello, nice to meet you."],"phonetic":"/həˈloʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础问候语"],"explanations":["hello是英语中最基础、最常用的问候语，用于见面打招呼、引起他人注意等场景，适用于各种非正式和较为正式的场合，是英语入门必须掌握的基础表达。"]},"sentenceWithHints":"你好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (2, '{"words":[{"plural":"","chinese":"谢谢","english":"thank you","examples":["Thank you for your help.","Thank you very much."],"phonetic":"/θæŋk juː/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["日常交际用语","固定表达"],"explanations":["“谢谢”是日常交际中常用的致谢用语，对应的英文固定表达为“Thank you”，是英语入门阶段需要掌握的基础交际内容，用于向他人表达感激之情。","“Thank you”是固定搭配，不能随意拆分或替换其中的词汇，除此之外，类似的同义表达还有“Thanks”，在非正式场合也可使用。"]},"sentenceWithHints":"谢谢"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (3, '{"words":[{"plural":"","chinese":"再见","english":"goodbye","examples":["Goodbye, see you tomorrow!","She waved and said goodbye."],"phonetic":"/ɡʊdˈbaɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["日常告别用语"],"explanations":["goodbye是英语中最常用的日常告别用语，适用于各种正式和非正式场合，用于结束对话、道别他人，是基础英语交际中必须掌握的表达。"]},"sentenceWithHints":"再见"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (4, '{"words":[{"plural":"mornings","chinese":"早上","english":"morning","examples":["Good morning!","I like to exercise in the morning."],"phonetic":"/ˈmɔːrnɪŋ/","partOfSpeech":"名词"},{"chinese":"好","english":"good","examples":["Good morning!","She is a good girl."],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"}],"examPoints":{"points":["日常问候语","名词与形容词的搭配"],"explanations":["“早上好”是英语中常用的日常问候语，对应英文“Good morning”，通常用于早晨时段（一般指中午之前）的见面问候。","这里形容词“good”用来修饰名词“morning”，构成固定的问候表达，这是英语中常见的形容词修饰名词的搭配方式，用于传递友好的问候语气。"]},"sentenceWithHints":"早上 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (5, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"爱","english":"love","examples":["I love my family.","She loves cats."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"moms","chinese":"妈妈","english":"mom","examples":["My mom cooks delicious food.","Mom is coming home."],"phonetic":"/mɑːm/","partOfSpeech":"名词"}],"examPoints":{"points":["人称代词主格用法","一般现在时动词形式","名词所有格的简略表达"],"explanations":["人称代词主格I在句中作主语，用于指代说话者本人，是第一人称单数的主格形式，在句子开头首字母需要大写。","一般现在时中，当主语是第一人称I时，谓语动词用原形，本句中主语是I，所以动词love用原形。","mom是mother的口语化表达，属于家庭成员类名词，前面加形容词性物主代词my来表示所属关系，这是小学阶段常见的亲属称谓表达。"]},"sentenceWithHints":"我 爱 妈妈"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (6, '{"words":[{"plural":"","chinese":"今天","english":"today","examples":["Today is Monday.","I will go to the park today."],"phonetic":"/təˈdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"天气","english":"weather","examples":["The weather is sunny.","What''s the weather like today?"],"phonetic":"/ˈweðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["The book is good.","You did a good job."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["中英句子语序差异","系动词be的用法","形容词作表语"],"explanations":["中文里时间状语“今天”通常放在句首，而英语中时间状语可以放在句首或句尾，本参考翻译将today放在句尾，符合英语表达习惯，小学阶段需要了解这种语序的转换。","本句主语是不可数名词weather，属于第三人称单数，所以系动词用is，小学二年级需要掌握be动词is用于第三人称单数主语的基本用法。","形容词good在句中作表语，用来描述主语weather的状态，小学阶段需要了解形容词可以放在系动词后，对主语的特征、状态进行说明。"]},"sentenceWithHints":"今天 天气 很 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (7, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去","english":"go","examples":["I go to park every weekend.","She goes to work by bus."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"schools","chinese":"学校","english":"school","examples":["My school is near my home.","There are many schools in this city."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","固定搭配“go to school”"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句描述“我”经常性的上学行为，主语是第一人称“I”，所以动词用原形“go”。当主语是第三人称单数时，动词要变为第三人称单数形式，如“he goes to school”。","“go to school”是固定搭配，意为“去上学”，这里的“school”前不需要加冠词，强调的是上学这个行为；如果要表示去某个具体的学校（比如去学校办事），则用“go to the school”。"]},"sentenceWithHints":"我 去 学校"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (8, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is a cat.","This pen is mine."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["He is a student.","This is my bag."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My dog is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["I have a new book.","Put the book on the desk."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["指示代词的用法","系动词be的单数形式用法","形容词性物主代词的用法"],"explanations":["指示代词this用于指代近处的单数人或事物，在本句中用来指代近处的“书”，对应的英文是this，是小学阶段基础的指代类词汇。","系动词be的单数形式is用于主语是第三人称单数的情况，本句主语this属于第三人称单数，因此搭配is使用，这是小学二年级重点掌握的be动词基础用法。","形容词性物主代词my用来表示所属关系，意为“我的”，后面必须接名词，本句中my修饰book，表明书的所属，是小学阶段物主代词入门知识点。"]},"sentenceWithHints":"这 是 我的 书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (9, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a boy.","He likes cats."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a pen.","She has a dog."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一个","english":"a/an","examples":["I need a ruler.","An orange is on the table."],"phonetic":"/ə/ /æn/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"apples","chinese":"苹果","english":"apple","examples":["I eat an apple every day.","There are many apples in the basket."],"phonetic":"/ˈæpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第三人称单数主语后动词的变化","不定冠词a和an的用法区分"],"explanations":["当句子主语是第三人称单数（如he、she、it或单个的人/物）时，一般现在时里的实义动词要使用第三人称单数形式。本句主语he是第三人称单数，所以动词have要变为has。","不定冠词a用于以辅音音素开头的可数名词单数前，an用于以元音音素开头的可数名词单数前。apple是以元音音素/æ/开头的单词，所以前面要用an。"]},"sentenceWithHints":"他 有 一个 苹果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (10, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like apples.","She likes dancing."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"玩","english":"play","examples":["Let''s play games.","He plays basketball every day."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"footballs","chinese":"足球","english":"football","examples":["I play football after school.","There are two footballs on the ground."],"phonetic":"/ˈfʊtbɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","球类名词的表达"],"explanations":["like后可以接动名词（doing形式）表示喜欢做某事的习惯，本句中like playing football表示喜欢踢足球这个爱好；当主语是第一人称复数we时，like用原形。","表示球类运动的名词前通常不加冠词，直接用play+球类名词，比如play football、play basketball，不需要加a/an或者the。"]},"sentenceWithHints":"我们 喜欢 玩 足球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (11, '{"words":[{"plural":"","chinese":"昨天","english":"yesterday","examples":["I played football yesterday.","Yesterday was a sunny day."],"phonetic":"/ˈjestərdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去了","english":"go","examples":["I go to school every day.","She went to the library yesterday."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"parks","chinese":"公园","english":"park","examples":["Let''s go to the park.","There is a beautiful park near my home."],"phonetic":"/pɑːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般过去时的用法","不规则动词的过去式","时间副词的位置"],"explanations":["一般过去时用来表示过去发生的动作或存在的状态，句中出现“昨天”这类明确的过去时间标志词时，谓语动词要用过去式。本句中“昨天”提示动作发生在过去，所以“去”要用过去式went。","英语中动词分为规则动词和不规则动词，规则动词过去式一般加-ed，而“go”是不规则动词，它的过去式是went，需要特殊记忆，这是小学阶段需要重点掌握的不规则动词之一。","表示时间的副词yesterday在英语句子中可以放在句首或句尾，本参考翻译将其放在句尾，这是英语中时间状语常见的位置，和中文中时间状语常放句首的语序有区别，需要注意中英文语序的转换。"]},"sentenceWithHints":"昨天 我 去了 公园"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (12, '{"words":[{"plural":"","chinese":"她","english":"she","examples":["She is a student.","She likes cats."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"正在","english":"（无对应独立单词，辅助构成进行时）","examples":["我正在看书。","他们正在玩游戏。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吃","english":"eat","examples":["I eat rice every day.","She is eating an apple."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"lunches","chinese":"午饭","english":"lunch","examples":["I have lunch at 12 o''clock.","We had a nice lunch together."],"phonetic":"/lʌntʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构与用法","第三人称单数主语的搭配"],"explanations":["现在进行时表示此时此刻正在进行的动作，结构为“am/is/are + 动词的现在分词”。本句中“正在吃”体现正在进行的动作，所以用“is eating”的结构，eat的现在分词是eating。","当主语是第三人称单数（如she、he、it）时，现在进行时中的be动词要用is，本句主语是“她（she）”，属于第三人称单数，所以搭配be动词is。"]},"sentenceWithHints":"她 正在 吃 午饭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (13, '{"words":[{"plural":"","chinese":"他们","english":"they","examples":["They are my classmates.","They like playing football."],"phonetic":"/ðeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"高兴","english":"happy","examples":["I''m happy to see you.","The happy children are playing games."],"phonetic":"/ˈhæpi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"are","examples":["You are my best friend.","We are going to the park."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["人称代词与be动词的搭配","副词修饰形容词的用法"],"explanations":["人称代词they是第三人称复数，对应的be动词要用are，这是小学阶段需要掌握的be动词基本搭配规则，be动词的形式要根据主语的人称和单复数变化。","副词very用来修饰形容词happy，放在形容词前面，用来加强形容词的语气，说明程度，这是小学阶段副词修饰形容词的基础用法，需要掌握副词在这类结构中的位置。"]},"sentenceWithHints":"他们 很 高兴"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (14, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想","english":"want","examples":["I want a new pen.","She wants to go home."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"喝","english":"drink","examples":["I drink milk every morning.","He is drinking juice now."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"waters","chinese":"水","english":"water","examples":["I need some water.","The waters of the lake are clear."],"phonetic":"/ˈwɔːtər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["want的固定用法","不可数名词的使用"],"explanations":["want作为动词，常见固定搭配为want to do sth.，表示“想要做某事”，这是小学阶段需要掌握的核心动词搭配，本句中want to drink就符合这个结构，用来表达想要做喝水这个动作。","water表示“饮用水”时是不可数名词，前面不能直接加不定冠词a/an，也不能直接用数词修饰，表达数量时需要借助some、a glass of等词，本句中直接用water表示“水”这个事物，符合不可数名词的使用规则。"]},"sentenceWithHints":"我 想 喝 水"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (15, '{"words":[{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","What do you like?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"几点","english":"what time","examples":["What time is it?","What time does the class begin?"],"phonetic":"/wɑːt taɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"起床","english":"get up","examples":["I get up at seven every day.","She got up late this morning."],"phonetic":"/ɡet ʌp/","pastTense":"got up","thirdPerson":"gets up","partOfSpeech":"动词","pastParticiple":"got up","presentParticiple":"getting up"}],"examPoints":{"points":["特殊疑问句的构成","动词短语的用法","助动词do的使用"],"explanations":["询问具体时间的特殊疑问句，用“What time”引导，句式结构为“What time + 助动词 + 主语 + 动词原形 + 其他？”，本句用来询问对方起床的具体时间。","“起床”对应的固定动词短语是“get up”，属于不及物动词短语，后面不需要直接加宾语，在一般现在时的疑问句中要使用动词原形。","当主语是第二人称“you”，且句子是一般现在时的疑问句时，需要借助助动词“do”来构成疑问语序，助动词后接动词原形。"]},"sentenceWithHints":"你 几点 起床？"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (16, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I read books every day.","She exercises every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"mornings","chinese":"早上","english":"morning","examples":["I get up early in the morning.","We have breakfast every morning."],"phonetic":"/ˈmɔːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"跑步","english":"run","examples":["I run for half an hour every day.","He runs faster than me."],"phonetic":"/rʌn/","pastTense":"ran","thirdPerson":"runs","partOfSpeech":"动词","pastParticiple":"run","presentParticiple":"running"}],"examPoints":{"points":["一般现在时的用法","时间状语的表达","动词原形的使用"],"explanations":["一般现在时用于表示经常性、习惯性的动作。本句中“每天早上”是习惯性的时间，所以使用一般现在时。当主语是第一人称“I”时，动词用原形。","“每天早上”对应的英文表达是“every morning”，属于频率时间状语，通常放在句末，用来说明动作发生的频率和时间。","在一般现在时中，当主语是第一人称（I/we）、第二人称（you）或复数主语时，谓语动词使用原形。本句主语是“I”，所以动词“跑步”翻译为原形“run”。"]},"sentenceWithHints":"我 每天 早上 跑步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (17, '{"words":[{"plural":"","chinese":"她","english":"she","examples":["She is my sister.","She likes playing basketball."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","He likes swimming very much."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"看","english":"read","examples":["I read a book every night.","She is reading a story now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"books","chinese":"书","english":"book","examples":["This is my new book.","I have many story books."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","He can sing and dance."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"听","english":"listen","examples":["Listen to the teacher carefully.","She likes listening to music."],"phonetic":"/ˈlɪsən/","pastTense":"listened","thirdPerson":"listens","partOfSpeech":"动词","pastParticiple":"listened","presentParticiple":"listening"},{"plural":"","chinese":"音乐","english":"music","examples":["I love pop music.","She is learning to play music."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词的第三人称单数形式","like后接动名词的用法","并列结构的平行原则"],"explanations":["当主语是第三人称单数（如she、he、it等）时，一般现在时的动词要使用第三人称单数形式，规则动词通常在词尾加-s，本句中主语she是第三人称单数，所以like变为likes，read变为reads，listen变为listens。","like作为动词表示“喜欢”时，后面可以接动名词（即动词的-ing形式），表示长期的、习惯性的爱好，结构为like doing sth.，所以本句中“看书”译为reading books，“听音乐”译为listening to music。","当用连词and连接两个并列的动作时，前后的动词形式要保持一致，本句中and连接的是reading books和listening to music，都是动名词短语，符合平行结构的要求。"]},"sentenceWithHints":"她 喜欢 看 书 和 听 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (18, '{"words":[{"plural":"","chinese":"明天","english":"tomorrow","examples":["I will go to the park tomorrow.","Tomorrow is my birthday."],"phonetic":"/təˈmɑːroʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you with your homework.","Will you come to my party?"],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"下雨","english":"rain","examples":["It rains a lot in spring.","It is raining outside now."],"phonetic":"/reɪn/","pastTense":"rained","thirdPerson":"rains","partOfSpeech":"动词","pastParticiple":"rained","presentParticiple":"raining"},{"plural":"","chinese":"吗","english":"","examples":["你吃饭了吗？","这是你的书吗？"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的一般疑问句结构","时间状语的位置","天气类表达"],"explanations":["一般将来时用will+动词原形表示将来的动作或状态，其一般疑问句结构为Will+主语+动词原形+其他？本句询问明天是否下雨，用该结构构成疑问，符合小学四年级对一般将来时疑问句式的考查要求。","表示时间的状语tomorrow在英语中通常可以放在句末，也可以放在句首，本句参考翻译将其放在句末，是英语中时间状语的常见摆放位置，需要学生了解中英文时间状语位置的差异。","表达天气时，英语常用“It+动词/形容词”的结构，本句中用“It rain”来表示“下雨”，it在这里指代天气，是英语中表达天气的固定常用方式，需要学生掌握这类常用的天气表达句式。"]},"sentenceWithHints":"明天 会 下雨 吗？"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (19, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We love playing games."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"at","examples":["I''m at home.","Look at the blackboard."],"phonetic":"/æt/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","Our school is big and nice."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"learn","examples":["I learn math well.","She learns to dance on weekends."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"英语","english":"English","examples":["I like English.","We have English class on Monday."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词主格的用法","地点介词at的用法","一般现在时的用法"],"explanations":["人称代词主格we在句中作主语，指代说话者及其他人，对应英文中的we，通常位于句首引导句子。","介词at用于表示具体的地点，school是具体的场所，表达“在学校”用固定搭配at school，这是小学阶段需要掌握的常用地点介词搭配。","一般现在时用于表示经常性、习惯性的动作，本句描述“我们在学校学习英语”这一日常行为，主语是第一人称复数we，所以动词用原形learn；如果主语是第三人称单数，动词要变为对应的第三人称单数形式learns。"]},"sentenceWithHints":"我们 在 学校 学习 英语"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (20, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is my brother.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"经常","english":"often","examples":["I often read books after school.","She often goes to the park."],"phonetic":"/ˈɔːfn/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"帮助","english":"help","examples":["I help my mom do housework.","She helps me with my homework."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"","chinese":"别人","english":"others","examples":["We should care about others.","Others may have different ideas."],"phonetic":"/ˈʌðərz/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时第三人称单数动词变化","频度副词的使用","不定代词others的用法"],"explanations":["当句子是一般现在时，主语是第三人称单数（如he、she、it）时，谓语动词要使用第三人称单数形式。规则动词的第三人称单数形式一般在词尾加-s，help的第三人称单数形式是helps。本句主语he是第三人称单数，且表示经常性动作，所以动词用helps。","频度副词often用于表示动作发生的频率，意为“经常”，通常放在实义动词之前，be动词、助动词之后。本句中often放在实义动词helps之前，符合频度副词的使用规则。","others是不定代词，相当于“other+复数名词”，泛指“其他人或物”，在句中可以作宾语、主语等。本句中others作help的宾语，指代“别人”。"]},"sentenceWithHints":"他 经常 帮助 别人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (21, '{"words":[{"plural":"","chinese":"如果","english":"if","examples":["If it rains, we will stay home.","You can go out if you finish your homework."],"phonetic":"/ɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"努力","english":"hard","examples":["She studies hard every day.","He works hard to support his family."],"phonetic":"/hɑːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"工作","english":"work","examples":["I work in a school.","She works very late today."],"phonetic":"/wɜːrk/","pastTense":"worked","thirdPerson":"works","partOfSpeech":"动词","pastParticiple":"worked","presentParticiple":"working"},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","They will visit their grandparents next week."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":""},{"plural":"","chinese":"成功","english":"succeed","examples":["If you try your best, you will succeed.","He succeeded in passing the exam."],"phonetic":"/səkˈsiːd/","pastTense":"succeeded","thirdPerson":"succeeds","partOfSpeech":"动词","pastParticiple":"succeeded","presentParticiple":"succeeding"}],"examPoints":{"points":["if引导的条件状语从句（主将从现）","副词hard的用法","一般将来时的表达"],"explanations":["在if引导的条件状语从句中，要遵循“主将从现”的规则，即主句用一般将来时（will+动词原形），从句用一般现在时表示将来。本句中从句“如果你努力工作”用一般现在时work，主句“你会成功”用一般将来时will succeed。","hard作为副词时，用来修饰动词，表示“努力地”，放在动词之后，本句中修饰work，表示“努力工作”。注意hardly是“几乎不”的意思，不要和hard混淆。","一般将来时用来表示将来要发生的动作或存在的状态，常见的表达结构是“will+动词原形”，本句中用will succeed表示“会成功”，是对未来结果的预测。"]},"sentenceWithHints":"如果 你 努力 工作， 你 会 成功"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (22, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"更","english":"more","examples":["She is more beautiful than me.","I like this book more."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"prefer","examples":["I prefer tea to coffee.","She prefers staying at home."],"phonetic":"/prɪˈfɜːr/","pastTense":"preferred","thirdPerson":"prefers","partOfSpeech":"动词","pastParticiple":"preferred","presentParticiple":"preferring"},{"plural":"","chinese":"看","english":"read","examples":["I read a book every day.","She is reading a novel now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"novels","chinese":"小说","english":"novel","examples":["I like reading science fiction novels.","This novel is very interesting."],"phonetic":"/ˈnɑːvl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"而","english":"to","examples":["I prefer running to swimming.","He prefers cats to dogs."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不是","english":"","examples":["I want apples not bananas.","It is a cat not a dog."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看","english":"watch","examples":["I watch TV every night.","They are watching a movie now."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"movies","chinese":"电影","english":"movie","examples":["Let''s go to see a movie.","I like action movies."],"phonetic":"/ˈmuːvi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["prefer的固定搭配用法","动名词的使用","可数名词复数形式"],"explanations":["prefer doing sth. to doing sth.是固定搭配，意为“比起做某事更喜欢做另一件事”，用来表达两者之间的偏好，本句用这个结构体现“更喜欢看小说而不是看电影”的语义。","在prefer...to...的搭配中，to是介词，后面要接动词的动名词形式（即动词+ing），所以这里read和watch要变成reading和watching。","novel和movie都是可数名词，这里表示一类事物，所以要用复数形式novels和movies，可数名词复数通常在词尾加-s，规则变化。"]},"sentenceWithHints":"我 更 喜欢 看 小说 而 不是 看 电影"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (23, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"（无对应单独英文，辅助构成进行时）","examples":["我在看书。I am reading a book.","她在唱歌。She is singing."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"等","english":"wait","examples":["Wait for me, please.","She waits for the bus every day."],"phonetic":"/weɪt/","pastTense":"waited","thirdPerson":"waits","partOfSpeech":"动词","pastParticiple":"waited","presentParticiple":"waiting"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","My mother loves me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"回家","english":"come home","examples":["I want to come home early.","He comes home at 6 every evening."],"phonetic":"/kʌm hoʊm/","pastTense":"came home","thirdPerson":"comes home","partOfSpeech":"动词短语","pastParticiple":"come home","presentParticiple":"coming home"}],"examPoints":{"points":["现在进行时的结构与用法","固定短语wait for的搭配","动词不定式作宾语补足语"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句主语是第三人称单数he，所以be动词用is，wait的现在分词是waiting。","wait是不及物动词，后面接宾语时需要加介词for，构成固定搭配wait for sb./sth.，意为“等待某人/某物”。","在“wait for sb. to do sth.”结构中，to do（动词不定式）用来补充说明等待的具体内容，作宾语补足语，本句中to come home补充说明等待“我”的具体行为是回家。"]},"sentenceWithHints":"他 在 等 我 回家"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (24, '{"words":[{"chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"应该","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"保护","english":"protect","examples":["We should protect animals.","It''s our duty to protect the earth."],"phonetic":"/prəˈtekt/","pastTense":"protected","thirdPerson":"protects","partOfSpeech":"动词","pastParticiple":"protected","presentParticiple":"protecting"},{"plural":"environments","chinese":"环境","english":"environment","examples":["We need to protect the environment.","The environment here is very clean."],"phonetic":"/ɪnˈvaɪrənmənt/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词should的用法","定冠词the的特指用法","及物动词protect的用法"],"explanations":["should是情态动词，后接动词原形，用来表示义务、建议等，本句中用来表达“应该履行保护环境的义务”，符合小学五年级对情态动词基础用法的考查要求。","定冠词the用于特指双方都知道的事物，这里的environment特指人类共同生活的自然环境，属于特指用法，是小学阶段冠词的核心考点之一。","protect是及物动词，后面可以直接接宾语，本句中接宾语the environment，考查及物动词后直接加宾语的基础用法，符合五年级学生对动词搭配的学习要求。"]},"sentenceWithHints":"我们 应该 保护 环境"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (25, '{"words":[{"chinese":"她","english":"she","examples":["She is a student.","She likes reading."],"phonetic":"/ʃiː/","partOfSpeech":"代词"},{"chinese":"比","english":"than","examples":["He is older than me.","This book is thicker than that one."],"phonetic":"/ðæn/","partOfSpeech":"介词"},{"chinese":"她","english":"her","examples":["Her cat is cute.","I gave her a gift."],"phonetic":"/hɜːr/","partOfSpeech":"代词"},{"plural":"sisters","chinese":"妹妹","english":"sister","examples":["My sister is ten years old.","She has two sisters."],"phonetic":"/ˈsɪstər/","partOfSpeech":"名词"},{"chinese":"高","english":"tall","examples":["He is tall.","The tree is very tall."],"phonetic":"/tɔːl/","partOfSpeech":"形容词"}],"examPoints":{"points":["形容词的比较级用法","比较级的标志性介词than"],"explanations":["当两者进行比较时，形容词需要使用比较级形式。单音节形容词tall的比较级是在词尾加-er，即taller，用来表示“更高的”。","在英语中，表达“比……更……”的比较关系时，需要用介词than连接被比较的对象，本句中用than连接被比较的对象her sister，明确比较的双方是she和her sister。"]},"sentenceWithHints":"她 比 她 妹妹 高"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (26, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"在","english":"in","examples":["I live in Beijing.","There is a cat in the box."],"phonetic":"/ɪn/","partOfSpeech":"介词"},{"plural":"","chinese":"上海","english":"Shanghai","examples":["Shanghai is a big city.","I want to visit Shanghai."],"phonetic":"/ˈʃæŋhaɪ/","partOfSpeech":"名词"},{"chinese":"住","english":"live","examples":["She lives in London.","We have lived here for 10 years."],"phonetic":"/lɪv/","pastTense":"lived","thirdPerson":"lives","partOfSpeech":"动词","pastParticiple":"lived","presentParticiple":"living"},{"chinese":"了","english":"","examples":["I have finished my homework.","She has eaten dinner."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"五","english":"five","examples":["I have five apples.","He is five years old."],"phonetic":"/faɪv/","partOfSpeech":"数词"},{"plural":"years","chinese":"年","english":"year","examples":["I''m ten years old.","We will stay for two years."],"phonetic":"/jɪr/","partOfSpeech":"名词"}],"examPoints":{"points":["现在完成时的用法","表示时间段的介词for的用法","地点介词in的用法"],"explanations":["现在完成时结构为“have/has + 动词过去分词”，用来表示过去发生的动作持续到现在，对现在造成影响或结果。本句中“住了五年”表示从过去开始居住的动作持续到现在，主语是第一人称I，所以用have加上live的过去分词lived。","介词for用来接时间段，说明动作或状态持续的时长，本句中“for five years”表示居住这个动作持续了五年的时间。","表示在大地点（如城市、国家）前面要用介词in，上海是城市，所以用“in Shanghai”来表示“在上海”。"]},"sentenceWithHints":"我 在 上海 住 了 五 年"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (27, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"决定","english":"decide","examples":["I decide to go to the park.","She has decided to study hard."],"phonetic":"/dɪˈsaɪd/","pastTense":"decided","thirdPerson":"decides","partOfSpeech":"动词","pastParticiple":"decided","presentParticiple":"deciding"},{"plural":"","chinese":"学","english":"learn","examples":["I learn English every day.","He learned to swim last summer."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"弹","english":"play","examples":["I play basketball after school.","She played the guitar at the party."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"pianos","chinese":"钢琴","english":"piano","examples":["She plays the piano well.","I want to buy a new piano."],"phonetic":"/piˈænoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词不定式作宾语","定冠词the与乐器的搭配","一般过去时的用法"],"explanations":["在英语中，decide、learn等动词后可以接动词不定式（to+动词原形）作宾语，表示“决定做某事”“学习做某事”，结构为decide to do sth.、learn to do sth.，同时play表示演奏乐器时，也常用learn to play+乐器的结构。","表示演奏西洋乐器时，乐器名词前必须加定冠词the，比如play the piano、play the violin；但表示球类运动时，名词前不加the，比如play basketball。","一般过去时用来表示过去发生的动作或存在的状态，句中decided是decide的过去式，说明“决定”这个动作是在过去发生的，小学阶段需要掌握规则动词变过去式的一般变化（一般加ed），以及部分不规则动词的过去式形式。"]},"sentenceWithHints":"他 决定 学 弹 钢琴"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (28, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"","examples":["我们是好朋友。","他们来自北京。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一","english":"as soon as","examples":["I will call you as soon as I arrive home.","As soon as the bell rings, class begins."],"phonetic":"/æz suːn æz/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"听","english":"hear","examples":["I can hear birds singing outside.","She heard a strange noise last night."],"phonetic":"/hɪr/","pastTense":"heard","thirdPerson":"hears","partOfSpeech":"动词","pastParticiple":"heard","presentParticiple":"hearing"},{"plural":"","chinese":"到","english":"","examples":["我听到了你的声音。","他吃到了美味的蛋糕。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"消息","english":"news","examples":["I have good news for you.","Did you hear the news about the sports meeting?"],"phonetic":"/nuːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"就","english":"","examples":["我一放学就回家。","他一看到我就笑了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"立刻","english":"immediately","examples":["Please call me immediately if you need help.","He left immediately after the meeting."],"phonetic":"/ɪˈmiːdiətli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"出","english":"","examples":["我们准备出发了。","他们已经出发去机场了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"发","english":"set off","examples":["We set off early in the morning.","They will set off for Shanghai tomorrow."],"phonetic":"/set ɔːf/","pastTense":"set off","thirdPerson":"sets off","partOfSpeech":"动词","pastParticiple":"set off","presentParticiple":"setting off"}],"examPoints":{"points":["时间状语从句的用法（as soon as）","不规则动词的过去式","固定短语set off的用法"],"explanations":["本句中“一...就...”对应英文连词as soon as，用来引导时间状语从句，主从句动作先后紧密相连，当描述过去发生的动作时，主从句都使用一般过去时。","hear的过去式是heard，set的过去式和原形一致为set，这些都是小学阶段需要掌握的不规则动词变形，要注意和规则动词变形区分记忆。","set off是固定动词短语，意为“出发；动身”，属于小学阶段需要积累的常用动词短语，在句子中可以作谓语，描述出行类的动作。"]},"sentenceWithHints":"我 们 一 听 到 消 息 就 立 刻 出 发"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (29, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a student.","It is a cat."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I have a dog."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"看过","english":"have seen","examples":["I have seen this movie before.","She has seen the beautiful sunset."],"phonetic":"/hæv sin/","pastTense":"had seen","thirdPerson":"has seen","partOfSpeech":"动词","pastParticiple":"seen","presentParticiple":"having seen"},{"plural":"","chinese":"的","english":"of","examples":["the color of the sky","the name of the cat"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"最","english":"most","examples":["This is the most delicious cake.","She is the most friendly girl in class."],"phonetic":"/moʊst/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有趣","english":"interesting","examples":["This book is interesting.","We had an interesting trip."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"movies","chinese":"电影","english":"movie","examples":["I love watching movies.","This movie is so funny."],"phonetic":"/ˈmuːvi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词最高级的用法","现在完成时的用法","定语从句的省略"],"explanations":["多音节形容词的最高级形式是在形容词前加most，且最高级前要加定冠词the。interesting是多音节形容词，所以最高级是the most interesting，用来表示三者及以上范围内的“最……”。","现在完成时结构为have/has+动词过去分词，用来表示过去发生的动作对现在造成的影响或结果，本句中“看过”这个动作对现在的影响是确定这是最有趣的电影，主语是I，所以用have seen。","当定语从句的关系代词在从句中作宾语时，关系代词可以省略。本句中“I have ever seen”是修饰movie的定语从句，完整形式是“that I have ever seen”，that在从句中作seen的宾语，所以可以省略。"]},"sentenceWithHints":"这 是 我 看过 的 最 有趣 的 电影"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (30, '{"words":[{"plural":"","chinese":"她","english":"she/her","examples":["She is my classmate.","I will give the book to her."],"phonetic":"/ʃiː/ /hɜːr/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"让","english":"ask","examples":["My mom asks me to clean my room every day.","He asked his teacher a question yesterday."],"phonetic":"/æsk/","pastTense":"asked","thirdPerson":"asks","partOfSpeech":"动词","pastParticiple":"asked","presentParticiple":"asking"},{"plural":"","chinese":"我","english":"me/I","examples":["I love reading stories.","Please pass the pen to me."],"phonetic":"/miː/ /aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"帮","english":"help","examples":["Can you help me carry this box?","She helps her grandma cook dinner every weekend."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"做","english":"do","examples":["I do my homework after school.","She did the dishes last night."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"","chinese":"作业","english":"homework","examples":["I have a lot of homework today.","Finish your homework before watching TV."],"phonetic":"/ˈhoʊmwɜːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词短语ask sb. to do sth.的用法","固定搭配help sb. with sth.的用法","人称代词主格和宾格的区分"],"explanations":["ask sb. to do sth.是小学阶段重点动词短语，意为“要求/让某人做某事”，这里的sb.要用宾格形式，to后面接动词原形，本句中“让我帮她”就符合这个结构，用asked me to help her。","help sb. with sth.是固定搭配，意为“帮助某人做某事”，sth.通常是名词或名词短语，本句中表示“帮她做作业”，所以用help her with her homework。","人称代词分为主格和宾格，主格在句中作主语，比如she；宾格在句中作宾语，比如me、her。本句中“她”在开头作主语用主格she，在“让我帮她”和“她的作业”里作宾语和定语用宾格her，“我”作ask的宾语用宾格me。"]},"sentenceWithHints":"她 让 我 帮 她 做 作业"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (31, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am from China."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"太","english":"too","examples":["It''s too hot today.","She is too young to go to school."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"累","english":"tired","examples":["I feel tired after running.","She was tired of waiting."],"phonetic":"/ˈtaɪərd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"了","english":"/","examples":["I have finished my homework.","She is happy now."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不","english":"not","examples":["I do not like coffee.","She is not at home."],"phonetic":"/nɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想","english":"want","examples":["I want to buy a new book.","She wants to go to the park."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"去","english":"go","examples":["I go to school every day.","She went to the cinema yesterday."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"","chinese":"参加","english":"attend","examples":["I will attend the meeting tomorrow.","She attended the wedding last week."],"phonetic":"/əˈtend/","pastTense":"attended","thirdPerson":"attends","partOfSpeech":"动词","pastParticiple":"attended","presentParticiple":"attending"},{"plural":"parties","chinese":"派对","english":"party","examples":["We will have a party this weekend.","She likes going to parties."],"phonetic":"/ˈpɑːrti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["too...to...结构的用法","动词不定式的否定含义","系动词be+形容词的系表结构"],"explanations":["too+形容词/副词+to do sth.是初中重点句型，意为“太……而不能做某事”，本身就包含否定含义，用来表达因某种程度的状态而无法完成某个动作。本句中“太累了，不想去”就符合这个结构的使用场景，对应翻译为too tired to go to the party。","too...to...结构本身自带否定意味，不需要额外加not来表示否定，本句中文的“不想”通过这个结构的否定含义来体现，避免出现重复否定的错误。","系动词be（am/is/are）后接形容词构成系表结构，用来描述主语的状态。本句中I am tired就是典型的系表结构，用am搭配形容词tired来描述“我”的疲惫状态。"]},"sentenceWithHints":"我 太 累 了， 不 想 去 参加 派对"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (32, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不仅","english":"not only","examples":["She is not only smart but also hard-working.","We can not only sing but also dance."],"phonetic":"/nɑːt ˈoʊnli/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"plural":"","chinese":"说","english":"speak","examples":["I speak Chinese every day.","He spoke at the meeting yesterday."],"phonetic":"/spiːk/","pastTense":"spoke","thirdPerson":"speaks","partOfSpeech":"动词","pastParticiple":"spoken","presentParticiple":"speaking"},{"plural":"","chinese":"英语","english":"English","examples":["I learn English at school.","She can speak fluent English."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"还","english":"but also","examples":["This book is not only interesting but also educational.","He not only reads books but also writes articles."],"phonetic":"/bʌt ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"法语","english":"French","examples":["She is learning French.","French is a beautiful language."],"phonetic":"/frentʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["并列连词短语 not only...but also...的用法","情态动词 can 的用法","表示“说某种语言”的动词搭配"],"explanations":["not only...but also...是并列连词短语，用于连接两个并列的成分，本句中连接两个表示语言的名词，意为“不仅……还……”。使用时要注意结构的平行性，连接的成分要在词性、结构上保持一致；此外，当连接两个主语时，谓语动词要遵循“就近原则”。","can 是情态动词，本身没有人称和数的变化，后面要接动词原形，用来表示具备某种能力，本句中用来表达“会说某种语言”的能力，其过去式为 could，可表示过去的能力或委婉请求。","表示“说某种语言”时，通常使用动词 speak 搭配语言类名词，如 speak English、speak French；talk 侧重“交谈、谈论”，常与介词 to/with/about 搭配；say 侧重说话的内容，tell 侧重“告诉、讲述”，这几个动词在使用场景上有明显区别。"]},"sentenceWithHints":"他 不仅 会 说 英语 ， 还 会 说 法语"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (33, '{"words":[{"plural":"","chinese":"无论","english":"wherever","examples":["Wherever you go, I will be right here waiting for you.","Wherever she goes, she takes her cat with her."],"phonetic":"/werˈevər/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去","english":"go","examples":["I go to school every day.","She went to the park yesterday."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"","chinese":"哪里","english":"where","examples":["Where do you live?","I don''t know where he is."],"phonetic":"/wer/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to Beijing tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"will","examples":["I will finish my homework tonight.","She will come to the party."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["We will have a meeting next week.","They will help us move."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":""},{"plural":"","chinese":"跟","english":"follow","examples":["Please follow me to the classroom.","The dog follows its owner everywhere."],"phonetic":"/ˈfɑːloʊ/","pastTense":"followed","thirdPerson":"follows","partOfSpeech":"动词","pastParticiple":"followed","presentParticiple":"following"},{"plural":"","chinese":"着","english":"","examples":["他笑着跑开了。","雨下着下着就停了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You should drink more water.","What do you want for dinner?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["让步状语从句引导词wherever的用法","一般将来时的用法","主将从现时态规则"],"explanations":["wherever是从属连词，引导让步状语从句，意思是“无论在哪里”，相当于no matter where，用来表示在任何地点条件下，主句的动作都会发生，常用来引导让步状语从句放在句首，从句用陈述语序。","一般将来时的基本结构为“will + 动词原形”，用来表示将来某个时间要发生的动作或存在的状态，本句中“will follow”表示“将会跟着”，体现将来要发生的动作。","在含有时间或让步状语从句的复合句中，当主句用一般将来时时，从句要用一般现在时表示将来，也就是“主将从现”。本句中wherever引导的让步状语从句用一般现在时“go”，主句用一般将来时“will follow”，符合这一规则。"]},"sentenceWithHints":"无论 你 去 哪里， 我 都 会 跟 着 你"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (34, '{"words":[{"chinese":"她","english":"she/her","examples":["She is a student.","Her book is on the desk."],"phonetic":"/ʃiː/ /hɜːr/","partOfSpeech":"代词"},{"chinese":"直到","english":"until","examples":["Wait until I come back.","He didn''t leave until the rain stopped."],"phonetic":"/ənˈtɪl/","partOfSpeech":"介词/连词"},{"chinese":"她","english":"her","examples":["Her mother is a doctor.","I gave her a gift."],"phonetic":"/hɜːr/","partOfSpeech":"代词"},{"plural":"mothers","chinese":"妈妈","english":"mother","examples":["My mother can cook well.","She is a mother of two kids."],"phonetic":"/ˈmʌðər/","partOfSpeech":"名词"},{"chinese":"回来","english":"come back","examples":["He will come back tomorrow.","She came back late last night."],"phonetic":"/kʌm bæk/","pastTense":"came back","thirdPerson":"comes back","partOfSpeech":"动词","pastParticiple":"come back","presentParticiple":"coming back"},{"chinese":"才","english":"not...until","examples":["I didn''t know it until you told me.","She didn''t eat until her father arrived."],"phonetic":"/nɑːt ənˈtɪl/","partOfSpeech":"助词"},{"chinese":"睡觉","english":"go to bed","examples":["I usually go to bed at 10 o''clock.","She went to bed early last night."],"phonetic":"/ɡoʊ tuː bed/","pastTense":"went to bed","thirdPerson":"goes to bed","partOfSpeech":"动词","pastParticiple":"gone to bed","presentParticiple":"going to bed"}],"examPoints":{"points":["not...until 句型的用法","一般过去时的运用","动词短语的固定搭配"],"explanations":["not...until 是初中阶段重点句型，意为“直到……才……”，用来表示某个动作直到某个时间或事件发生后才进行，通常需要将否定词与until搭配使用，本句中“直到她妈妈回来才睡觉”就对应“did not go to bed until her mother came back”。","本句描述的是过去发生的动作，因此需要使用一般过去时，谓语动词要用过去式形式，如“did not go”中的“did”是助动词do的过去式，“came”是come的过去式，需要掌握规则和不规则动词的过去式变化。","句中出现了“go to bed（睡觉）”和“come back（回来）”两个固定动词短语，这是初中阶段需要掌握的常用固定搭配，需要牢记短语的构成和含义，不能随意拆分或替换其中的词汇。"]},"sentenceWithHints":"她 直到 她 妈妈 回来 才 睡觉"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (35, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"本","english":"copy","examples":["a copy of book","I need another copy of the report."],"phonetic":"/ˈkɑːpi/","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["I like reading books.","This is a new book."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"值","english":"worth","examples":["The movie is worth watching.","This painting is worth a lot of money."],"phonetic":"/wɜːrθ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"得","english":"","examples":["She is tall enough to reach the shelf.","The book is easy to read."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"读","english":"read","examples":["I read a book every night.","She is reading a novel now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"}],"examPoints":{"points":["固定搭配 be worth doing","动名词的用法"],"explanations":["be worth doing 是初中阶段的核心固定搭配，意为“值得做某事”，这里的 doing 是动名词形式，主动形式表达被动含义，不需要使用被动语态，本句中“值得读”就对应 be worth reading。","在 be worth 这个结构中，后面必须接动名词（动词的-ing形式）作宾语，不能接动词不定式。动名词在这里体现的是该动作值得被实施，虽然形式是主动，但语义上是被动的，比如本句中 reading 实际表达的是“被读”的含义。"]},"sentenceWithHints":"这 本 书 值 得 读"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (36, '{"words":[{"plural":"","chinese":"尽管","english":"although","examples":["Although it is cold, he still goes out.","Although she is tired, she keeps working."],"phonetic":"/ɔːlˈðoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"下雨","english":"rain","examples":["It rains a lot in spring.","It was raining when I got home."],"phonetic":"/reɪn/","pastTense":"rained","thirdPerson":"rains","partOfSpeech":"动词","pastParticiple":"rained","presentParticiple":"raining"},{"plural":"","chinese":"我们","english":"we","examples":["We are good friends.","We will go to the park tomorrow."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"还是","english":"still","examples":["He is still working.","I still love this song."],"phonetic":"/stɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去","english":"go","examples":["I go to school every day.","She went to the library yesterday."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"picnics","chinese":"野餐","english":"picnic","examples":["We had a picnic last weekend.","Let''s go for a picnic this Sunday."],"phonetic":"/ˈpɪknɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She went to the store."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["让步状语从句的用法","过去进行时与一般过去时的搭配使用","固定短语go for a picnic的用法"],"explanations":["although是引导让步状语从句的连词，意思是“尽管，虽然”，用来表示转折关系，引导的从句不能和but连用，本句中用although引导“下雨”这个让步条件，主句说明相反的动作“去野餐”。","过去进行时（was/were + doing）用来表示过去某个时间段正在进行的动作，本句中it was raining表示当时正在下雨的状态；一般过去时（动词过去式）用来表示过去发生的具体动作，本句中went表示过去完成的“去”这个动作，二者搭配使用可以体现动作发生的背景和具体行为的先后与伴随关系。","go for a picnic是固定短语，意思是“去野餐”，其中picnic是可数名词，单数形式前需要加不定冠词a，类似的固定表达还有go for a walk、go for a trip等。"]},"sentenceWithHints":"尽管 下雨， 我们 还是 去 野餐 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (37, '{"words":[{"plural":"","chinese":"自从","english":"since","examples":["I have lived here since 2010.","She hasn''t called since she left."],"phonetic":"/sɪns/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"他","english":"he","examples":["He is my brother.","He likes playing basketball."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"搬到","english":"move to","examples":["I moved to New York last year.","She will move to London next month."],"phonetic":"/muːv tuː/","pastTense":"moved to","thirdPerson":"moves to","partOfSpeech":"动词","pastParticiple":"moved to","presentParticiple":"moving to"},{"plural":"","chinese":"北京","english":"Beijing","examples":["Beijing is the capital of China.","I want to visit Beijing someday."],"phonetic":"/beɪˈdʒɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"后","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我们","english":"we","examples":["We are classmates.","We went to the park yesterday."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"就","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"没","english":"not","examples":["I do not like coffee.","She has not finished her homework."],"phonetic":"/nɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"见过面","english":"see each other","examples":["We see each other every weekend.","They haven''t seen each other for years."],"phonetic":"/siː iːtʃ ˈʌðər/","pastTense":"saw each other","thirdPerson":"sees each other","partOfSpeech":"动词","pastParticiple":"seen each other","presentParticiple":"seeing each other"}],"examPoints":{"points":["since引导的时间状语从句的时态搭配","现在完成时的否定形式","固定短语see each other的用法"],"explanations":["当since引导时间状语从句时，从句通常使用一般过去时，主句使用现在完成时，用来表示从过去某个时间点开始一直持续到现在的动作或状态。本句中从句he moved to Beijing用一般过去时，主句We haven''t seen each other用现在完成时，符合该规则。","现在完成时的否定形式是在助动词have/has后加not，缩写为haven''t/hasn''t，后面接动词的过去分词，用来表示过去发生的动作对现在造成的影响或结果，本句中haven''t seen就是现在完成时的否定结构，表达从过去到现在都没有见面的状态。","see each other是固定短语，意为“见面，彼此见面”，用来描述双方互相碰面的动作，在表达人与人之间的会面时经常使用，相当于meet each other。"]},"sentenceWithHints":"自从 他 搬到 北京 后， 我们 就 没 见过面"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (38, '{"words":[{"chinese":"让","english":"make","examples":["She makes me happy every day.","He made a cake for his sister."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"惊讶","english":"surprise","examples":["The news surprised everyone.","It surprises me that you don''t know this."],"phonetic":"/sərˈpraɪz/","pastTense":"surprised","thirdPerson":"surprises","partOfSpeech":"动词","pastParticiple":"surprised","presentParticiple":"surprising"},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The book on the desk is mine."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"be","examples":["This is my new bike.","They are playing football."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"他","english":"he","examples":["He is a tall boy.","He goes to school by bus."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"通过","english":"pass","examples":["I passed the math test yesterday.","She passes the ball to her teammate."],"phonetic":"/pæs/","pastTense":"passed","thirdPerson":"passes","partOfSpeech":"动词","pastParticiple":"passed","presentParticiple":"passing"},{"plural":"","chinese":"了","english":"","examples":["I ate an apple.","She finished her homework."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"exams","chinese":"考试","english":"exam","examples":["I have an exam tomorrow.","She studied hard for the exams."],"phonetic":"/ɪɡˈzæm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定短语 To one''s surprise 的用法","一般过去时的使用"],"explanations":["To one''s surprise 是初中阶段的常用固定短语，意为“令某人惊讶的是”，在句中作插入语，用来引出说话者的意外情绪。这里的 one''s 要用形容词性物主代词，比如 my、your、his 等。","一般过去时用来表示过去发生的动作或存在的状态，句中“通过了考试”是已经发生的过去动作，所以动词 pass 要用过去式 passed。初中阶段需要掌握规则动词和常见不规则动词的过去式变化，passed 是规则动词 pass 的过去式，直接在词尾加 -ed。"]},"sentenceWithHints":"让 我 惊讶 的 是 ， 他 通过 了 考试"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (39, '{"words":[{"chinese":"她","english":"she","examples":["She is my classmate.","She likes reading books."],"phonetic":"/ʃiː/","partOfSpeech":"代词"},{"chinese":"花费了","english":"spend","examples":["I spend two hours doing homework every day.","He spent a lot of money on the new phone."],"phonetic":"/spend/","pastTense":"spent","thirdPerson":"spends","partOfSpeech":"动词","pastParticiple":"spent","presentParticiple":"spending"},{"chinese":"整个","english":"whole","examples":["I spent the whole day at home.","She ate the whole cake by herself."],"phonetic":"/hoʊl/","partOfSpeech":"形容词"},{"plural":"afternoons","chinese":"下午","english":"afternoon","examples":["I usually play basketball in the afternoon.","We had a meeting yesterday afternoon."],"phonetic":"/ˌæftərˈnuːn/","partOfSpeech":"名词"},{"chinese":"准备","english":"prepare","examples":["I need to prepare for the exam.","She prepared a big meal for us."],"phonetic":"/prɪˈper/","pastTense":"prepared","thirdPerson":"prepares","partOfSpeech":"动词","pastParticiple":"prepared","presentParticiple":"preparing"},{"plural":"speeches","chinese":"演讲","english":"speech","examples":["He gave a wonderful speech.","I''m nervous about my speech tomorrow."],"phonetic":"/spiːtʃ/","partOfSpeech":"名词"}],"examPoints":{"points":["动词spend的用法","动名词作宾语","固定搭配prepare for"],"explanations":["spend作为“花费（时间/金钱）”的动词，常用结构为spend + 时间/金钱 + (in) doing sth.或spend + 时间/金钱 + on sth.，本句中使用的是spend + 时间 + doing sth.的结构，且句子为一般过去时，所以spend用过去式spent。","在spend的结构spend + 时间/金钱 + (in) doing sth.中，in可以省略，后面的动词需要使用动名词形式，也就是动词加-ing，本句中prepare变为preparing符合该规则。","prepare表示“为……做准备”时，需要与介词for搭配构成固定短语prepare for，后接准备的对象，本句中表示为演讲做准备，所以用preparing for the speech。"]},"sentenceWithHints":"她 花费了 整个 下午 准备 演讲"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (40, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"建议","english":"suggest","examples":["I suggest we go to the park.","She suggests taking a bus."],"phonetic":"/səˈdʒest/","pastTense":"suggested","thirdPerson":"suggests","partOfSpeech":"动词","pastParticiple":"suggested","presentParticiple":"suggesting"},{"chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","partOfSpeech":"代词"},{"chinese":"早点","english":"early","examples":["Please arrive early.","She gets up early every morning."],"phonetic":"/ˈɜːrli/","partOfSpeech":"副词"},{"chinese":"出发","english":"start","examples":["We will start at 8 o''clock.","He started his homework just now."],"phonetic":"/stɑːrt/","pastTense":"started","thirdPerson":"starts","partOfSpeech":"动词","pastParticiple":"started","presentParticiple":"starting"}],"examPoints":{"points":["suggest的宾语从句用法","副词early的位置"],"explanations":["suggest表示“建议”时，后面接宾语从句要用虚拟语气，结构为suggest that sb. (should) do sth.，其中should可以省略，本句中you start就省略了should，这是初中阶段需要掌握的重点虚拟语气用法。","early作为副词，在句中通常用来修饰动词，放在动词之后，本句中early修饰动词start，放在start之后，符合副词修饰动词的位置规则。"]},"sentenceWithHints":"我 建议 你 早点 出发"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (41, '{"words":[{"plural":"","chinese":"由于","english":"due to","examples":["The game was canceled due to bad weather.","She missed the exam due to illness."],"phonetic":"/duː tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"heavy rains","chinese":"大雨","english":"heavy rain","examples":["We stayed indoors because of the heavy rain.","The heavy rain caused flooding in the city."],"phonetic":"/ˈhevi reɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"trains","chinese":"火车","english":"train","examples":["I take the train to work every day.","The train arrived ten minutes late."],"phonetic":"/treɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"晚点","english":"delay","examples":["The flight was delayed by fog.","Please don''t delay sending the report."],"phonetic":"/dɪˈleɪ/","pastTense":"delayed","thirdPerson":"delays","partOfSpeech":"动词","pastParticiple":"delayed","presentParticiple":"delaying"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She went to the park yesterday."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["原因状语的表达","一般过去时的被动语态","形容词修饰名词的用法"],"explanations":["表示原因时，due to 后接名词或名词短语，用来引出导致结果的直接原因，在本句中引出火车晚点的原因“大雨”，初中阶段需要区分 due to 和 because of 的用法，二者后都接名词性成分，在日常使用中可互换，但正式语境中 due to 更侧重归因。","本句中火车是“被晚点”的对象，所以使用被动语态“was delayed”，一般过去时的被动语态结构为“was/were + 过去分词”，主语 the train 是单数第三人称，所以用 was，delayed 是 delay 的过去分词形式。","形容“雨下得大”要用形容词 heavy 修饰名词 rain，而不能用 big，这是英语中的固定搭配，类似的还有“heavy snow（大雪）”“heavy traffic（拥堵的交通）”，初中阶段需要积累这类形容词与名词的固定搭配。"]},"sentenceWithHints":"由于 大雨， 火车 晚点 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (42, '{"words":[{"chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","partOfSpeech":"代词"},{"chinese":"宁愿","english":"would rather","examples":["I would rather stay at home.","She would rather read books than play games."],"phonetic":"/wʊd ˈræðər/","partOfSpeech":"短语"},{"chinese":"在","english":"at","examples":["I am at school.","She stays at home."],"phonetic":"/æt/","partOfSpeech":"介词"},{"plural":"homes","chinese":"家","english":"home","examples":["My home is near the park.","She went home early."],"phonetic":"/hoʊm/","partOfSpeech":"名词"},{"chinese":"看","english":"watch","examples":["I watch TV every night.","She is watching a movie."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"TVs","chinese":"电视","english":"TV","examples":["I like watching TV.","There are two TVs in the house."],"phonetic":"/ˌtiːˈviː/","partOfSpeech":"名词"},{"chinese":"也不愿","english":"than","examples":["She is taller than me.","I would rather walk than take a bus."],"phonetic":"/ðæn/","partOfSpeech":"连词"},{"chinese":"去","english":"go","examples":["I go to school every day.","She has gone to the library."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"cinemas","chinese":"电影院","english":"cinema","examples":["I go to the cinema every weekend.","There are three cinemas in this city."],"phonetic":"/ˈsɪnəmə/","partOfSpeech":"名词"}],"examPoints":{"points":["would rather...than...固定句式","动词原形的使用","地点介词搭配"],"explanations":["would rather...than...是初中阶段重点考查的固定句式，意为“宁愿……而不愿……”，用来表达在两个选项中更倾向于前者。","在would rather和than后面都要接动词原形，不需要根据主语的人称和数进行形式变化，本句中watch和go都用原形就是遵循这一规则。","表示“在家”要用固定搭配at home；“去电影院”要用go to the cinema，其中to是介词，和动词go搭配表示前往某个地点。"]},"sentenceWithHints":"他 宁愿 在 家 看 电视 也 不愿 去 电影院"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (43, '{"words":[{"plural":"","chinese":"除非","english":"unless","examples":["Unless you hurry, you''ll miss the bus.","I won''t go unless you go with me."],"phonetic":"/ənˈles/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"努力","english":"hard","examples":["She works hard every day.","You need to try hard to succeed."],"phonetic":"/hɑːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"study","examples":["I study English every night.","She studied for the test last weekend."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"","chinese":"否则","english":"or","examples":["Hurry up, or you''ll be late.","You must stop, or you''ll get hurt."],"phonetic":"/ɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不会","english":"won''t","examples":["I won''t tell anyone your secret.","She won''t come to the party."],"phonetic":"/woʊnt/","pastTense":"wouldn''t","thirdPerson":"won''t","partOfSpeech":"动词","pastParticiple":"will have not","presentParticiple":""},{"plural":"","chinese":"通过","english":"pass","examples":["Did you pass the exam?","She passed the ball to her teammate."],"phonetic":"/pæs/","pastTense":"passed","thirdPerson":"passes","partOfSpeech":"动词","pastParticiple":"passed","presentParticiple":"passing"},{"plural":"exams","chinese":"考试","english":"exam","examples":["I have an exam tomorrow.","She studied hard for the math exam."],"phonetic":"/ɪɡˈzæm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["连词unless的用法","一般将来时的否定形式","副词hard修饰动词的用法"],"explanations":["unless作为连词，引导条件状语从句，含义为“除非，如果不”，相当于if...not。在unless引导的条件状语从句中，遵循“主将从现”的规则，即从句用一般现在时，主句用一般将来时。本句中从句“you study hard”用一般现在时，主句“you won''t pass the exam”用一般将来时。","一般将来时的否定形式是在will后加not，缩写为won''t，用来表示将来不会发生的动作或状态。本句中“won''t pass”表示将来不会通过考试。","hard作为副词时，用来修饰动词，表示“努力地”，通常放在动词之后。本句中“study hard”表示努力学习，hard修饰动词study。"]},"sentenceWithHints":"除非 你 努力 学习， 否则 你 不会 通过 考试"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (44, '{"words":[{"plural":"","chinese":"据说","english":"it is said that","examples":["It is said that he won the prize.","It is said that this old house is haunted."],"phonetic":"/ɪt ɪz sed ðæt/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"这家","english":"this","examples":["This book is mine.","This is my new car."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"restaurants","chinese":"餐厅","english":"restaurant","examples":["We had dinner in a fancy restaurant.","This restaurant serves great Italian food."],"phonetic":"/ˈrestərɑːnt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is broken.","The color of the sky is blue."],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"foods","chinese":"菜","english":"food","examples":["I love Chinese food.","Different foods have different nutrients."],"phonetic":"/fuːd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好吃","english":"delicious","examples":["The cake is delicious.","We had a delicious meal last night."],"phonetic":"/dɪˈlɪʃəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["被动语态固定句式It is said that...的用法","介词短语作后置定语","形容词的用法"],"explanations":["It is said that...是初中阶段需要掌握的常用被动语态固定句式，用来表达“据说……”，属于形式主语句型，真正的主语是that引导的主语从句，该句式常用于转述他人的说法或不确定的信息。","本句中“in this restaurant”是介词短语，在句中作后置定语修饰名词“food”，用来限定食物的所属范围，初中阶段需要掌握介词短语作后置定语的结构，明确其修饰的先行词位置。","“delicious”是形容词，用来描述食物的性质“好吃的”，在句中作表语，初中阶段需要掌握形容词作表语的用法，了解形容词可以放在系动词之后，用来补充说明主语的特征或状态。"]},"sentenceWithHints":"据说 这家 餐厅 的 菜 很 好吃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (45, '{"words":[{"plural":"meetings","chinese":"会议","english":"meeting","examples":["The meeting will start at 9 a.m.","We had a long meeting yesterday."],"phonetic":"/ˈmiːtɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"被","english":"","examples":["The window was broken by the wind.","The cake has been eaten by the kids."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"推迟","english":"postpone","examples":["They decided to postpone the game due to rain.","The meeting has been postponed until next month."],"phonetic":"/poʊˈspoʊn/","pastTense":"postponed","thirdPerson":"postpones","partOfSpeech":"动词","pastParticiple":"postponed","presentParticiple":"postponing"},{"plural":"","chinese":"到","english":"to","examples":["I go to school every day.","We will fly to Paris next week."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"下周","english":"next week","examples":["I will visit my grandma next week.","We have a test next week."],"phonetic":"/nekst wiːk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词短语","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的被动语态","介词to表时间指向的用法"],"explanations":["现在完成时的被动语态结构为“have/has been + 过去分词”，用于表示已经发生且对现在有影响的被动动作。本句中“会议”是“推迟”的承受者，且强调推迟这个动作的结果（会议时间变更为下周），所以使用现在完成时的被动语态has been postponed。","介词to在这里用于表示动作的时间指向，说明会议被推迟的时间目标是“下周”，用来连接动作的结果和对应的时间节点，在表达“到某个时间”的语境中经常使用。"]},"sentenceWithHints":"会议 被 推迟 到 下周"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (46, '{"words":[{"plural":"","chinese":"正","english":"just","examples":["It is just a joke.","I just finished my homework."],"phonetic":"/dʒʌst/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"was","examples":["I was at home yesterday.","She was happy to see me."],"phonetic":"/wʌz/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"你","english":"your","examples":["Your pen is on the table.","This is your book."],"phonetic":"/jʊr/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the flower is red."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"helps","chinese":"帮","english":"help","examples":["Thank you for your help.","I need some help with my math."],"phonetic":"/help/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"helps","chinese":"助","english":"help","examples":["Thank you for your help.","I need some help with my math."],"phonetic":"/help/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"使","english":"enable","examples":["The new software enables us to work faster.","His support enabled me to achieve my goal."],"phonetic":"/ɪˈneɪbl/","pastTense":"enabled","thirdPerson":"enables","partOfSpeech":"动词","pastParticiple":"enabled","presentParticiple":"enabling"},{"plural":"","chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"完","english":"finish","examples":["I finished my homework early.","She finishes work at 5 pm."],"phonetic":"/ˈfɪnɪʃ/","pastTense":"finished","thirdPerson":"finishes","partOfSpeech":"动词","pastParticiple":"finished","presentParticiple":"finishing"},{"chinese":"成","english":"finish","examples":["I finished my homework early.","She finishes work at 5 pm."],"phonetic":"/ˈfɪnɪʃ/","pastTense":"finished","thirdPerson":"finishes","partOfSpeech":"动词","pastParticiple":"finished","presentParticiple":"finishing"},{"plural":"","chinese":"了","english":"","examples":["I ate an apple.","She finished her work."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"这","english":"the","examples":["The book is on the desk.","I like the movie."],"phonetic":"/ðə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"项","english":"","examples":["a piece of paper","an item of clothing"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"works","chinese":"工","english":"work","examples":["I have a lot of work to do.","The work is very difficult."],"phonetic":"/wɜːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"works","chinese":"作","english":"work","examples":["I have a lot of work to do.","The work is very difficult."],"phonetic":"/wɜːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["强调句型（It is/was...that...）","enable的用法","动词不定式作宾语补足语"],"explanations":["强调句型It is/was + 被强调部分 + that/who + 其他部分，用于突出句子中的某个成分，本句强调的是\"your help\"，因为描述的是过去发生的事，所以用was。当被强调部分是人时可用who，其他情况用that。","enable是及物动词，常见用法为enable sb. to do sth.，意为“使某人能够做某事”，此处描述过去的动作，所以使用其过去式enabled。","在enable sb. to do sth.结构中，to finish是动词不定式，在句中作宾语me的补足语，用来补充说明宾语的动作，这是动词不定式的常见用法之一。"]},"sentenceWithHints":"正 是 你 的 帮 助 使 我 完 成 了 这 项 工 作"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (47, '{"words":[{"chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","partOfSpeech":"代词"},{"chinese":"一","english":"no sooner","examples":["No sooner had I left than it began to rain.","No sooner did she arrive than she started complaining."],"phonetic":"/noʊ ˈsuːnər/","partOfSpeech":"副词"},{"chinese":"到达","english":"arrive","examples":["We arrived at the station on time.","She will arrive in Beijing tomorrow."],"phonetic":"/əˈraɪv/","pastTense":"arrived","thirdPerson":"arrives","partOfSpeech":"动词","pastParticiple":"arrived","presentParticiple":"arriving"},{"plural":"airports","chinese":"机场","english":"airport","examples":["I will meet you at the airport.","The airport is very busy during holidays."],"phonetic":"/ˈerpɔːrt/","partOfSpeech":"名词"},{"chinese":"就","english":"than","examples":["No sooner had he finished than he left.","She is taller than her brother."],"phonetic":"/ðæn/","partOfSpeech":"连词"},{"chinese":"给","english":"to","examples":["He gave a gift to me.","Please send the letter to my address."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"我","english":"me","examples":["He called me yesterday.","Please pass me the book."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"打了","english":"call","examples":["She called her friend last night.","He is calling his mother now."],"phonetic":"/kɔːl/","pastTense":"called","thirdPerson":"calls","partOfSpeech":"动词","pastParticiple":"called","presentParticiple":"calling"},{"plural":"calls","chinese":"电话","english":"call","examples":["I received a call from my sister.","She made a phone call to her teacher."],"phonetic":"/kɔːl/","partOfSpeech":"名词"}],"examPoints":{"points":["no sooner...than...倒装结构","动词时态搭配","介词的使用"],"explanations":["no sooner...than...是固定句式，意为“一……就……”，当no sooner置于句首时，主句需要使用部分倒装结构，即把助动词had提到主语之前，本句中had he arrived就是倒装形式，该结构用于描述两个先后发生的过去动作，主句用过去完成时，从句用一般过去时。","在no sooner...than...结构中，主句动作发生在从句动作之前，所以主句用过去完成时（had arrived），表示“到达”这个动作在“打电话”之前完成，从句用一般过去时（called），表示后续发生的动作，体现动作的先后逻辑。","arrive后接小地点（如airport）时，搭配介词at；接大地点（如city, country）时搭配介词in，本句中airport是小地点，所以用arrived at。"]},"sentenceWithHints":"他 一 到达 机场 就 给 我 打了 电话"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (48, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are good friends.","We will go to the park tomorrow."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"正要","english":"be about to","examples":["I was about to go out when it started to rain.","She is about to finish her homework."],"phonetic":"/biː əˈbaʊt tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"动词短语","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"离开","english":"leave","examples":["Please leave the door open.","He left home early this morning."],"phonetic":"/liːv/","pastTense":"left","thirdPerson":"leaves","partOfSpeech":"动词","pastParticiple":"left","presentParticiple":"leaving"},{"plural":"","chinese":"的","english":"","examples":["这是我的书。","他是新来的同学。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"时候","english":"when","examples":["I was reading when she came in.","Call me when you arrive."],"phonetic":"/wen/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"phones","chinese":"电话","english":"phone","examples":["The phone is ringing.","I bought a new phone last week."],"phonetic":"/foʊn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"响了","english":"ring","examples":["The bell rings at 8 o''clock every morning.","The phone rang while I was cooking."],"phonetic":"/rɪŋ/","pastTense":"rang","thirdPerson":"rings","partOfSpeech":"动词","pastParticiple":"rung","presentParticiple":"ringing"}],"examPoints":{"points":["be about to 结构的用法","when 引导的时间状语从句（过去进行时+一般过去时）","不规则动词的过去式变化"],"explanations":["be about to 是固定结构，意为“正要，即将”，后面接动词原形，通常表示即将发生的动作，常与 when 引导的时间状语从句连用，表达“正要做某事，这时突然发生另一件事”。本句中用 were about to 是因为主语是 we，且整体语境为过去时态。","when 引导时间状语从句时，若主句用过去进行时（were about to leave 也属于过去将来范畴，表即将发生的动作），从句用一般过去时，用来表示在一个动作即将发生的瞬间，另一个突发动作发生了。本句中“正要离开”是即将发生的动作，“电话响了”是突发的过去动作，符合该结构。","本句中出现了 leave 和 ring 两个不规则动词，leave 的过去式和过去分词是 left，ring 的过去式是 rang，过去分词是 rung。高中阶段需要掌握常见不规则动词的变形，这类动词没有统一的变形规则，需要重点记忆。"]},"sentenceWithHints":"我们 正要 离开 的 时候， 电话 响了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (49, '{"words":[{"plural":"","chinese":"这个","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"problems","chinese":"问题","english":"problem","examples":["I have a math problem.","We need to solve this problem quickly."],"phonetic":"/ˈprɑːbləm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"太","english":"too","examples":["It''s too hot today.","She is too young to go to school."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"复杂","english":"complex","examples":["The complex problem needs careful thinking.","This is a complex machine."],"phonetic":"/kəmˈpleks/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"了","english":"/","examples":["I have finished my homework.","She is tired now."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"难","english":"hard","examples":["It''s hard to learn a new language.","This is a hard question."],"phonetic":"/hɑːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"解决","english":"solve","examples":["Can you solve this puzzle?","We need to solve the problem as soon as possible."],"phonetic":"/sɑːlv/","pastTense":"solved","thirdPerson":"solves","partOfSpeech":"动词","pastParticiple":"solved","presentParticiple":"solving"}],"examPoints":{"points":["too + 形容词 + to do 结构","动词不定式的用法","副词的修饰作用"],"explanations":["too + 形容词 + to do 是高中英语常见的固定结构，意为“太……而不能……”，用来表示否定的结果。本句中“太复杂了，很难解决”用“too complex to solve”来对应，符合该结构的表达逻辑。","句中“to solve”是动词不定式，在这里作结果状语，补充说明“complex”带来的结果。同时在“too + adj + to do”结构中，不定式的逻辑主语通常和句子主语一致，本句中“solve”的逻辑主语是“this problem”，符合该用法规则。","句中的“too”用来修饰形容词“complex”，加强程度；“easily”用来修饰动词“solve”，说明解决问题的难易程度。副词修饰形容词时放在形容词之前，修饰动词时通常放在动词之后或句末，这是副词的基本修饰规则。"]},"sentenceWithHints":"这个 问题 太 复杂 了， 很 难 解决"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (50, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"后悔","english":"regret","examples":["I regret missing the meeting.","She regrets not studying harder."],"phonetic":"/rɪˈɡret/","pastTense":"regretted","thirdPerson":"regrets","partOfSpeech":"动词","pastParticiple":"regretted","presentParticiple":"regretting"},{"plural":"","chinese":"告诉","english":"tell","examples":["Please tell me your name.","He told us an interesting story."],"phonetic":"/tel/","pastTense":"told","thirdPerson":"tells","partOfSpeech":"动词","pastParticiple":"told","presentParticiple":"telling"},{"plural":"","chinese":"他","english":"him","examples":["I gave him a gift.","Please pass him the book."],"phonetic":"/hɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"truths","chinese":"真相","english":"truth","examples":["He finally told me the truth.","We should always speak the truth."],"phonetic":"/truːθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["regret的用法","动名词作宾语","人称代词宾格"],"explanations":["regret作为动词，常见用法有两种：regret doing sth. 表示后悔做过某事（事情已发生）；regret to do sth. 表示遗憾要做某事（事情未发生）。本句中“告诉真相”是已经发生的动作，所以用regret doing sth.结构。","在英语中，部分动词后只能接动名词作宾语，regret就属于这类动词。动名词由动词原形加-ing构成，在句中可以承担宾语的成分，此处telling作regret的宾语，体现已经完成的动作。","人称代词有主格和宾格之分，主格在句中作主语，宾格在句中作宾语。本句中“他”是tell的宾语，所以要用宾格形式him，而不是主格he。"]},"sentenceWithHints":"我 后悔 告诉 他 真相"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (51, '{"words":[{"chinese":"考虑到","english":"take...into consideration","examples":["You should take his advice into consideration.","Taking the cost into consideration, we choose the cheaper option."],"phonetic":"/teɪk ˈɪntuː kənˌsɪdəˈreɪʃn/","pastTense":"took...into consideration","thirdPerson":"takes...into consideration","partOfSpeech":"动词短语","pastParticiple":"taken...into consideration","presentParticiple":"taking...into consideration"},{"plural":"weathers","chinese":"天气","english":"weather","examples":["The weather is nice today.","We need to check the weather before going out."],"phonetic":"/ˈweðər/","partOfSpeech":"名词"},{"plural":"situations","chinese":"情况","english":"situation","examples":["We are in a difficult situation.","She handled the situation very well."],"phonetic":"/ˌsɪtʃuˈeɪʃn/","partOfSpeech":"名词"},{"chinese":"我们","english":"we","examples":["We are students.","We will go to the park tomorrow."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"决定","english":"decide","examples":["I decide to study hard.","She decided to quit her job."],"phonetic":"/dɪˈsaɪd/","pastTense":"decided","thirdPerson":"decides","partOfSpeech":"动词","pastParticiple":"decided","presentParticiple":"deciding"},{"chinese":"取消","english":"cancel","examples":["They canceled the meeting.","I need to cancel my flight."],"phonetic":"/ˈkænsl/","pastTense":"canceled","thirdPerson":"cancels","partOfSpeech":"动词","pastParticiple":"canceled","presentParticiple":"canceling"},{"plural":"trips","chinese":"行程","english":"trip","examples":["We had a great trip.","The trip to Paris was expensive."],"phonetic":"/trɪp/","partOfSpeech":"名词"}],"examPoints":{"points":["现在分词作状语","动词短语 take...into consideration 的用法","decide to do sth 固定搭配"],"explanations":["现在分词短语作状语时，通常表示与主句动作同时发生的伴随、原因等情况。本句中 Taking the weather into consideration 是现在分词短语作原因状语，逻辑主语与主句主语 we 一致，表主动关系，说明取消行程的原因。","take...into consideration 是固定动词短语，意为“考虑到……；把……考虑在内”，在句中可以转换为被动形式 sth be taken into consideration，也可以用 take...into account 替换，表达相同含义。","decide 后接不定式 to do sth 是固定搭配，意为“决定做某事”，表示主语主动做出的决定，不能接动名词形式，类似的动词还有 hope, plan, want 等。"]},"sentenceWithHints":"考虑到 天气 情况， 我们 决定 取消 行程"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (52, '{"words":[{"plural":"","chinese":"只有","english":"only","examples":["Only you can help me.","We can only finish it tomorrow."],"phonetic":"/ˈoʊnli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"通过","english":"by","examples":["I go to school by bus.","You can improve by practicing every day."],"phonetic":"/baɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"努力","english":"hard","examples":["He works hard every day.","She tried hard to solve the problem."],"phonetic":"/hɑːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"工作","english":"work","examples":["I work in a hospital.","She is working on a new project."],"phonetic":"/wɜːrk/","pastTense":"worked","thirdPerson":"works","partOfSpeech":"动词","pastParticiple":"worked","presentParticiple":"working"},{"plural":"","chinese":"我们","english":"we","examples":["We love our country.","We will go to the park this weekend."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"才能","english":"can","examples":["I can speak English.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"plural":"","chinese":"实现","english":"achieve","examples":["He achieved his dream at last.","We can achieve success by working hard."],"phonetic":"/əˈtʃiːv/","pastTense":"achieved","thirdPerson":"achieves","partOfSpeech":"动词","pastParticiple":"achieved","presentParticiple":"achieving"},{"plural":"goals","chinese":"目标","english":"goal","examples":["My goal is to become a doctor.","They have set clear goals for this year."],"phonetic":"/ɡoʊl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["部分倒装结构","介词by的用法","动词achieve的用法"],"explanations":["当only + 介词短语/副词/状语从句位于句首时，句子需要使用部分倒装结构，即把助动词、情态动词或be动词提到主语之前。本句中“Only by working hard”位于句首，所以将情态动词can提到主语we之前，形成“can we achieve”的倒装结构。","介词by在这里用来表示方式、手段，意为“通过，凭借”，后面接动词时需要使用动名词形式（v-ing），所以此处用working hard来表示“通过努力工作”这一方式。","achieve是及物动词，后面直接接名词或代词作宾语，通常用来表示“实现（目标、梦想、成功等）”，强调通过努力达到预期的结果，常搭配的宾语有goal, dream, success等。"]},"sentenceWithHints":"只有 通过 努力 工作， 我们 才能 实现 目标"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (53, '{"words":[{"plural":"","chinese":"如果","english":"if","examples":["If it rains, we will stay home.","I will help you if you need me."],"phonetic":"/ɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you pass me the pen?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不","english":"not","examples":["I do not like coffee.","She is not at home."],"phonetic":"/nɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"介意","english":"mind","examples":["Would you mind opening the window?","I don''t mind waiting for you."],"phonetic":"/maɪnd/","pastTense":"minded","thirdPerson":"minds","partOfSpeech":"动词","pastParticiple":"minded","presentParticiple":"minding"},{"plural":"","chinese":"的","english":"","examples":["这是我的书。","他说的话很有道理。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"话","english":"","examples":["如果可以的话，我想请假。","方便的话，明天一起吃饭吧。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am going to school."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想","english":"would like","examples":["I would like a cup of tea.","Would you like to go with me?"],"phonetic":"/wʊd laɪk/","pastTense":"would liked","thirdPerson":"would likes","partOfSpeech":"动词","pastParticiple":"would liked","presentParticiple":"would liking"},{"plural":"","chinese":"问","english":"ask","examples":["May I ask you a question?","She asked me for help."],"phonetic":"/æsk/","pastTense":"asked","thirdPerson":"asks","partOfSpeech":"动词","pastParticiple":"asked","presentParticiple":"asking"},{"plural":"","chinese":"一","english":"a","examples":["I have a cat.","She is a doctor."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"个","english":"","examples":["一个苹果","三个学生"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"questions","chinese":"问题","english":"question","examples":["I have a question to ask.","He answered all the questions correctly."],"phonetic":"/ˈkwestʃən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["条件状语从句","委婉表达句型","动词短语用法"],"explanations":["本句中“如果你不介意的话”是由if引导的条件状语从句，用于提出假设性的前提，在英语中此类从句遵循“主将从现”原则，但本句使用了委婉语气，从句用一般现在时（don''t mind）来表达礼貌的前提。","“would like to do sth.”是高中阶段重点掌握的委婉表达句型，相比“want to do”语气更礼貌、委婉，常用于提出请求或表达意愿，符合本句询问他人时的礼貌语境。","动词mind的用法：mind后接动名词形式（mind doing sth.），表示“介意做某事”；其否定形式don''t mind常用于回应请求或表达不在意，本句中用于铺垫后续的提问，体现交际中的礼貌原则。"]},"sentenceWithHints":"如果 你 不 介意 的 话， 我 想 问 你 一 个 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (54, '{"words":[{"chinese":"这","english":"it","examples":["It is a cat.","It is raining outside."],"phonetic":"/ɪt/","partOfSpeech":"代词"},{"chinese":"是","english":"is","examples":["She is a doctor.","It is sunny today."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"他","english":"he","examples":["He likes playing football.","He has finished his homework."],"phonetic":"/hiː/","partOfSpeech":"代词"},{"chinese":"第一","english":"first","examples":["This is my first trip.","She won the first prize."],"phonetic":"/fɜːrst/","partOfSpeech":"形容词"},{"plural":"times","chinese":"次","english":"time","examples":["This is the third time I''ve called you.","I have no time to rest."],"phonetic":"/taɪm/","partOfSpeech":"名词"},{"chinese":"出国","english":"go abroad","examples":["He often goes abroad for business.","She has gone abroad to study."],"phonetic":"/ɡoʊ əˈbrɔːd/","pastTense":"went abroad","thirdPerson":"goes abroad","partOfSpeech":"动词短语","pastParticiple":"gone abroad","presentParticiple":"going abroad"}],"examPoints":{"points":["固定句式\"It is the first time that...\"的用法","现在完成时的应用","副词abroad的用法"],"explanations":["\"It is the first time that...\"是高中阶段重点考查的固定句式，意为“这是某人第一次做某事”。当主句谓语动词为is时，从句需要使用现在完成时；若主句为was，则从句用过去完成时。本句主句是It is，所以从句用has been abroad。","现在完成时的结构为“have/has + 过去分词”，主要用于表示过去发生的动作对现在造成的影响或结果，或是从过去持续到现在的动作。在本句式中，用现在完成时强调“出国”这个动作到目前为止是第一次发生，且对当下的语境有影响。","abroad是副词，意为“在国外；到国外”，在句中通常作状语，前面不需要加介词，比如“go abroad”“live abroad”，不能说“go to abroad”。"]},"sentenceWithHints":"这 是 他 第一 次 出国"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (55, '{"words":[{"chinese":"无论","english":"no matter","examples":["No matter how hard it is, I will keep trying.","No matter who you are, you must follow the rules."],"phonetic":"/noʊ ˈmætər/","partOfSpeech":"连词"},{"chinese":"发生","english":"happen","examples":["What happened to you?","Something strange is happening here."],"phonetic":"/ˈhæpən/","pastTense":"happened","thirdPerson":"happens","partOfSpeech":"动词","pastParticiple":"happened","presentParticiple":"happening"},{"chinese":"什么","english":"what","examples":["What is your name?","I don''t know what he wants."],"phonetic":"/wɑːt/","partOfSpeech":"代词"},{"chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"都","english":"will","examples":["I will help you.","She will arrive at 5 o''clock."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["They will come to the party.","I will finish my homework soon."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"站","english":"stand","examples":["She stands by the window.","I stood there for a long time."],"phonetic":"/stænd/","pastTense":"stood","thirdPerson":"stands","partOfSpeech":"动词","pastParticiple":"stood","presentParticiple":"standing"},{"chinese":"在","english":"by","examples":["I am by the river.","She is standing by my side."],"phonetic":"/baɪ/","partOfSpeech":"介词"},{"chinese":"你","english":"your","examples":["This is your pen.","Your book is on the table."],"phonetic":"/jʊr/","partOfSpeech":"代词"},{"plural":"sides","chinese":"这边","english":"side","examples":["She is on my side.","There are trees on both sides of the road."],"phonetic":"/saɪd/","partOfSpeech":"名词"}],"examPoints":{"points":["让步状语从句","一般将来时的用法","固定短语stand by one''s side"],"explanations":["本句中\"无论发生什么\"是让步状语从句，用\"No matter what\"引导，这类从句表示无论出现何种情况，主句的动作都不受影响。从句中主语what视为第三人称单数，所以谓语动词happen要用第三人称单数形式happens。","主句\"我都会站在你这边\"使用一般将来时will+动词原形的结构，表示将来要发生的动作或存在的状态，用来表达说话人的承诺或决心。","固定短语stand by one''s side意为\"站在某人一边，支持某人\"，是高中阶段需要掌握的常用短语，在语境中用来表达支持的态度。"]},"sentenceWithHints":"无论 发生 什么， 我 都 会 站 在 你 这边"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (56, '{"words":[{"chinese":"正","english":"just","examples":["It is just a cat.","I just finished my homework."],"phonetic":"/dʒʌst/","partOfSpeech":"副词"},{"chinese":"是","english":"be","examples":["I am a student.","They were happy yesterday."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"他","english":"he/his","examples":["He is tall.","His book is on the table."],"phonetic":"/hiː/ /hɪz/","partOfSpeech":"代词"},{"chinese":"的","english":"''s/of","examples":["the cover of the book","Tom''s cat is cute."],"phonetic":"/əv/","partOfSpeech":"助词"},{"chinese":"坚","english":"persist","examples":["He persisted in his efforts.","She will persist until she succeeds."],"phonetic":"/pərˈsɪst/","pastTense":"persisted","thirdPerson":"persists","partOfSpeech":"动词","pastParticiple":"persisted","presentParticiple":"persisting"},{"chinese":"持","english":"maintain","examples":["He maintains a healthy lifestyle.","She maintained her composure."],"phonetic":"/meɪnˈteɪn/","pastTense":"maintained","thirdPerson":"maintains","partOfSpeech":"动词","pastParticiple":"maintained","presentParticiple":"maintaining"},{"chinese":"不","english":"not","examples":["I do not like coffee.","She is not here."],"phonetic":"/nɑːt/","partOfSpeech":"副词"},{"chinese":"懈","english":"slack","examples":["Do not slack off on your work.","He slacked during the summer vacation."],"phonetic":"/slæk/","pastTense":"slacked","thirdPerson":"slacks","partOfSpeech":"动词","pastParticiple":"slacked","presentParticiple":"slacking"},{"chinese":"使","english":"make/lead to","examples":["Hard work makes success.","His efforts led to his victory."],"phonetic":"/meɪk/ /liːd tuː/","pastTense":"made/led","thirdPerson":"makes/leads","partOfSpeech":"动词","pastParticiple":"made/led","presentParticiple":"making/leading"},{"chinese":"最","english":"ultimately","examples":["He ultimately succeeded.","The plan ultimately failed."],"phonetic":"/ˈʌltəmətli/","partOfSpeech":"副词"},{"chinese":"终","english":"finally","examples":["I finally finished my project.","She finally arrived home."],"phonetic":"/ˈfaɪnəli/","partOfSpeech":"副词"},{"chinese":"取","english":"obtain","examples":["He obtained a degree.","She obtained permission to leave."],"phonetic":"/əbˈteɪn/","pastTense":"obtained","thirdPerson":"obtains","partOfSpeech":"动词","pastParticiple":"obtained","presentParticiple":"obtaining"},{"chinese":"得","english":"get","examples":["I get up early every day.","She got a new bike."],"phonetic":"/ɡet/","pastTense":"got","thirdPerson":"gets","partOfSpeech":"动词","pastParticiple":"got/gotten","presentParticiple":"getting"},{"chinese":"了","english":"/","examples":["I ate an apple.","She finished her homework."],"phonetic":"/","partOfSpeech":"助词"},{"chinese":"成","english":"succeed","examples":["He succeeded in the exam.","She will succeed in her career."],"phonetic":"/səkˈsiːd/","pastTense":"succeeded","thirdPerson":"succeeds","partOfSpeech":"动词","pastParticiple":"succeeded","presentParticiple":"succeeding"},{"plural":"successes","chinese":"功","english":"success","examples":["His success is due to hard work.","She has many successes in her life."],"phonetic":"/səkˈses/","partOfSpeech":"名词"}],"examPoints":{"points":["强调句型（It is/was...that...）","固定搭配 lead to","名词 persistence 的用法"],"explanations":["强调句型 It is/was + 被强调部分 + that/who + 其他部分，用于突出句子中的某个成分。本句强调的是主语 his persistence，因为是过去的事情，所以用 It was...that...的结构，who 仅用于强调人，此处强调的是物，所以用 that。","lead to 是固定动词短语，意为“导致，通向”，后面接名词或动名词，在本句中接名词 his success，用来表示某种原因带来的结果。","persistence 是 persist 的名词形式，意为“坚持不懈”，是不可数名词，前面可以用形容词性物主代词 his 来修饰，在句子中可以作主语、宾语等成分，本句中作被强调的主语部分。"]},"sentenceWithHints":"正 是 他 的 坚 持 不 懈 使 他 最 终 取 得 了 成 功"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (57, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are good friends.","We will go to the park tomorrow."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"讨论","english":"discuss","examples":["We need to discuss the plan carefully.","She discusses business with clients every day."],"phonetic":"/dɪˈskʌs/","pastTense":"discussed","thirdPerson":"discusses","partOfSpeech":"动词","pastParticiple":"discussed","presentParticiple":"discussing"},{"plural":"","chinese":"了","english":"","examples":["我吃了饭。","他完成了作业。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很多","english":"a wide range of","examples":["There is a wide range of books in the library.","The shop sells a wide range of clothes."],"phonetic":"/ə waɪd reɪndʒ əv/","pastTense":"","thirdPerson":"","partOfSpeech":"短语","pastParticiple":"","presentParticiple":""},{"plural":"topics","chinese":"话题","english":"topic","examples":["Let''s change the topic.","The topic of the meeting is about climate change."],"phonetic":"/ˈtɑːpɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"从","english":"from","examples":["I come from China.","She works from 9 to 5 every day."],"phonetic":"/frʌm/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"economies","chinese":"经济","english":"economy","examples":["The economy is growing steadily.","Different countries have different economies."],"phonetic":"/ɪˈkɑːnəmi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"到","english":"to","examples":["I go to school by bus.","The movie is from 7 to 9 PM."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"environments","chinese":"环境","english":"environment","examples":["We should protect the natural environment.","Children need a safe environment to grow up."],"phonetic":"/ɪnˈvaɪrənmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般过去时的用法","短语a wide range of的运用","from...to...的搭配"],"explanations":["一般过去时表示过去某个时间里发生的动作或状态，常与表示过去的时间状语（本句通过助词“了”体现过去语境）连用，规则动词的过去式一般在词尾加-ed，discuss的过去式为discussed。","a wide range of是高中阶段重点短语，意为“各种各样的、大范围的”，后接可数名词复数或不可数名词，用来表达数量多、范围广的概念，比单纯的many更正式书面，适合用于议论文等正式文体。","from...to...是常见的介词搭配，用来表示范围，意为“从……到……”，可以连接具体的时间、地点，也可以连接抽象的概念，本句中连接抽象的领域概念“经济”和“环境”，体现讨论话题的跨度。"]},"sentenceWithHints":"我们 讨论 了 很多 话题 ， 从 经济 到 环境"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (58, '{"words":[{"plural":"","chinese":"与其","english":"rather than","examples":["Rather than stay at home, I''d prefer to go out.","He chose to walk rather than take a bus."],"phonetic":"/ˈræðər ðæn/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"抱怨","english":"complain","examples":["She likes to complain about her job.","Don''t complain; just try to solve the problem."],"phonetic":"/kəmˈpleɪn/","pastTense":"complained","thirdPerson":"complains","partOfSpeech":"动词","pastParticiple":"complained","presentParticiple":"complaining"},{"plural":"status quos","chinese":"现状","english":"status quo","examples":["We need to maintain the status quo for now.","He wants to challenge the existing status quo."],"phonetic":"/ˈsteɪtəs kwoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不如","english":"should","examples":["We should finish our homework first.","You should listen to your parents'' advice."],"phonetic":"/ʃʊd/","pastTense":"should","thirdPerson":"should","partOfSpeech":"动词","pastParticiple":"should","presentParticiple":""},{"plural":"","chinese":"努力","english":"strive","examples":["We must strive to achieve our goals.","She strives to be the best in her class."],"phonetic":"/straɪv/","pastTense":"strove","thirdPerson":"strives","partOfSpeech":"动词","pastParticiple":"striven","presentParticiple":"striving"},{"plural":"","chinese":"改变","english":"change","examples":["We need to change our plan.","She changed her mind at the last minute."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"plural":"","chinese":"它","english":"it","examples":["It is a beautiful day.","I like this book because it is interesting."],"phonetic":"/ɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["rather than的用法","固定句式的翻译与应用","动词非谓语形式","正式名词短语status quo的使用"],"explanations":["rather than作为连词，用于对比两个选项，可接动词原形、动名词或名词等结构。在本句中接动名词complaining，与后面的strive to change形成对比，表达“与其…不如…”的取舍关系，是高中阶段重点掌握的连词短语之一。","本句是典型的取舍句式“与其…不如…”，英文中对应使用rather than+非谓语，搭配should的句式来表达建议性的取舍，需要掌握这类中文句式到英文的转化逻辑，符合高中英语写作中句式多样性的考查要求。","rather than后接动名词complaining，这里涉及到非谓语动词的用法：当rather than连接的是平行结构时，若前面是不定式，后面可接不定式或动名词，本句中为了表达伴随性的动作，使用动名词形式，这是高中非谓语动词的常考考点。","status quo是源自拉丁语的固定名词短语，意为“现状”，属于正式英语表达，在书面语和高级英语应用中常用，高中阶段会考查这类固定外来语短语的识记与使用，提升写作的正式性和准确性。"]},"sentenceWithHints":"与其 抱怨 现状， 不如 努力 改变 它"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (59, '{"words":[{"plural":"","chinese":"这个","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"projects","chinese":"项目","english":"project","examples":["We are working on a new project.","The project will be finished next month."],"phonetic":"/ˈprɑːdʒekt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The cover of the book is blue.","This is a photo of my family."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"successes","chinese":"成功","english":"success","examples":["The party was a great success.","She achieved success through hard work."],"phonetic":"/səkˈses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"归功于","english":"be attributed to","examples":["His success is attributed to his hard work.","The accident was attributed to bad weather."],"phonetic":"/biː əˈtrɪbjuːtɪd tuː/","pastTense":"was/were attributed to","thirdPerson":"is/was attributed to","partOfSpeech":"动词","pastParticiple":"been attributed to","presentParticiple":"being attributed to"},{"plural":"teams","chinese":"团队","english":"team","examples":["Our team won the game.","She is a member of the design team."],"phonetic":"/tiːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"efforts","chinese":"努力","english":"effort","examples":["Thank you for your effort.","All our efforts finally paid off."],"phonetic":"/ˈefərt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["名词所有格的用法","固定短语be attributed to的使用","介词of表所属关系的用法"],"explanations":["名词所有格用于表示所属关系，有两种形式：一种是''s所有格，主要用于有生命的事物，如本句的team''s efforts，表示团队的努力；另一种是of所有格，多用于无生命的事物，如the success of this project。","be attributed to是高中阶段重点掌握的固定短语，意为“归功于；被归因于”，常用于正式表达中，主语多为表示结果、成就的名词，如success、failure等，需要注意该短语的被动语态结构，根据主语的单复数调整be动词的形式。","介词of常用来表示无生命事物的所属关系，结构为“名词+of+名词”，相当于中文的“……的”，本句中the success of this project就表示“这个项目的成功”，这是英语中表达所属关系的常见方式，区别于''s所有格的适用场景。"]},"sentenceWithHints":"这个 项目 的 成功 归功于 团队 的 努力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (60, '{"words":[{"plural":"","chinese":"一旦","english":"once","examples":["Once you start, you should finish.","Once he arrives, we''ll leave."],"phonetic":"/wʌns/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"做出","english":"make","examples":["She makes a cake every weekend.","He made a mistake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She went to the park yesterday."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"promises","chinese":"承诺","english":"promise","examples":["He kept his promise.","Don''t make a promise you can''t keep."],"phonetic":"/ˈprɑːmɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"就","english":"","examples":["If you study hard, you will pass the exam.","Once you agree, you must do it."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"必须","english":"must","examples":["You must follow the rules.","We must finish the task on time."],"phonetic":"/mʌst/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"遵守","english":"keep","examples":["Keep your room clean.","She keeps her promises."],"phonetic":"/kiːp/","pastTense":"kept","thirdPerson":"keeps","partOfSpeech":"动词","pastParticiple":"kept","presentParticiple":"keeping"},{"plural":"","chinese":"它","english":"it","examples":["It is a cat.","I like it very much."],"phonetic":"/ɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["连词once引导的条件状语从句","固定搭配make a promise和keep a promise","情态动词must的用法"],"explanations":["once作为连词引导条件状语从句时，遵循“主将从现”原则，即从句用一般现在时表示将来的动作，主句用一般将来时或情态动词表义务、决心等。本句从句用一般现在时make，主句用must keep表必须履行的义务。","make a promise是固定短语，意为“做出承诺”；keep a promise也是固定短语，意为“遵守承诺”，这两个短语在日常交际和书面表达中都很常用，需要牢记。","must作为情态动词，后接动词原形，用来表示义务、必要性，意为“必须”，语气较为强烈，强调说话者的要求或规定的责任。在本句中用来强调做出承诺后履行的必要性。"]},"sentenceWithHints":"一旦 你 做出 了 承诺， 就 必须 遵守 它"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (61, '{"words":[{"chinese":"这","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","partOfSpeech":"代词"},{"chinese":"项","english":"item","examples":["an item of research","three items of news"],"phonetic":"/ˈaɪtəm/","partOfSpeech":"量词"},{"plural":"researches","chinese":"研究","english":"research","examples":["This research is important.","He has done many researches."],"phonetic":"/ˈriːsɜːrtʃ/","partOfSpeech":"名词"},{"chinese":"旨在","english":"aim to","examples":["The project aims to help the poor.","This policy aims to reduce pollution."],"phonetic":"/eɪm tuː/","pastTense":"aimed to","thirdPerson":"aims to","partOfSpeech":"动词","pastParticiple":"aimed to","presentParticiple":"aiming to"},{"chinese":"探讨","english":"explore","examples":["We need to explore new methods.","She explored the ancient city."],"phonetic":"/ɪkˈsplɔːr/","pastTense":"explored","thirdPerson":"explores","partOfSpeech":"动词","pastParticiple":"explored","presentParticiple":"exploring"},{"plural":"climates","chinese":"气候","english":"climate","examples":["The climate here is warm.","Different regions have different climates."],"phonetic":"/ˈklaɪmət/","partOfSpeech":"名词"},{"plural":"changes","chinese":"变化","english":"change","examples":["Climate change is a serious issue.","There are many changes in the city."],"phonetic":"/tʃeɪndʒ/","partOfSpeech":"名词"},{"chinese":"对","english":"on","examples":["The impact on the environment is huge.","This has no effect on me."],"phonetic":"/ɑːn/","partOfSpeech":"介词"},{"plural":"","chinese":"农业","english":"agriculture","examples":["Agriculture is the foundation of the economy.","He studies agriculture at university."],"phonetic":"/ˈæɡrɪkʌltʃər/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The color of the sky is blue.","The impact of the storm is great."],"phonetic":"/əv/","partOfSpeech":"助词"},{"chinese":"潜在","english":"potential","examples":["There is potential danger.","He has potential to be a good singer."],"phonetic":"/pəˈtenʃl/","partOfSpeech":"形容词"},{"plural":"impacts","chinese":"影响","english":"impact","examples":["The impact of the policy is significant.","Climate change has many impacts on nature."],"phonetic":"/ˈɪmpækt/","partOfSpeech":"名词"}],"examPoints":{"points":["动词不定式作目的状语","名词所有格与介词短语的转换","学术英语中固定搭配的使用"],"explanations":["本句中“旨在探讨”翻译为“aims to explore”，其中“to explore”是动词不定式，在句中作目的状语，用来说明主语“research”的目的，这是学术英语中表达研究目的的常用结构。","中文里的“气候变化对农业的潜在影响”在英文中转换为“the potential impact of climate change on agriculture”，使用“of”和“on”构成的介词短语来体现所属关系和作用对象，这是英语中表达事物间关联的常见方式，区别于中文的助词“的”的结构。","在学术英语中，“aim to do”是表达研究目标的固定搭配，“impact of...on...”是表达某事物对另一事物影响的标准搭配，这类固定搭配是大学阶段学术英语考查的重点，需要准确掌握以符合学术文本的表达规范。"]},"sentenceWithHints":"这 项 研究 旨在 探讨 气候 变化 对 农业 的 潜在 影响"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (62, '{"words":[{"plural":"","chinese":"尽管","english":"despite","examples":["Despite the rain, we went out.","She won the race despite her injury."],"phonetic":"/dɪˈspaɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"面临","english":"face","examples":["We face many difficulties every day.","He faced the problem bravely."],"phonetic":"/feɪs/","pastTense":"faced","thirdPerson":"faces","partOfSpeech":"动词","pastParticiple":"faced","presentParticiple":"facing"},{"plural":"","chinese":"诸多","english":"numerous","examples":["There are numerous books in the library.","She has numerous friends."],"phonetic":"/ˈnuːmərəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"challenges","chinese":"挑战","english":"challenge","examples":["We need to overcome this challenge.","The job presents many challenges."],"phonetic":"/ˈtʃælɪndʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"这个","english":"the","examples":["The book is on the desk.","I like the movie."],"phonetic":"/ðə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"projects","chinese":"项目","english":"project","examples":["We are working on a new project.","The project will be finished next month."],"phonetic":"/ˈprɑːdʒekt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"最终","english":"ultimately","examples":["Ultimately, we decided to stay.","The plan ultimately failed."],"phonetic":"/ˈʌltɪmətli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"还是","english":"still","examples":["He still lives here.","We still have time."],"phonetic":"/stɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"取得了","english":"achieve","examples":["She achieved her dream.","We hope to achieve our goals."],"phonetic":"/əˈtʃiːv/","pastTense":"achieved","thirdPerson":"achieves","partOfSpeech":"动词","pastParticiple":"achieved","presentParticiple":"achieving"},{"plural":"","chinese":"显著","english":"remarkable","examples":["She made a remarkable improvement.","The team had a remarkable success."],"phonetic":"/rɪˈmɑːrkəbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"results","chinese":"成果","english":"result","examples":["The results of the test are good.","Hard work brings good results."],"phonetic":"/rɪˈzʌlt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["介词despite的用法","非谓语动词的使用","正式书面语词汇的选用","过去时态的运用"],"explanations":["despite是介词，后接名词、代词或动名词形式，不能直接接从句，本句中接动名词facing，体现了介词后接非谓语动词的规则，与in spite of用法相近，区别在于in spite of是短语介词，despite是单个介词。","本句中despite后接动名词facing，属于非谓语动词的动名词形式作介词宾语，动名词兼具动词和名词的特征，此处facing的逻辑主语可以理解为句子的主语the project。","本句选用了numerous、remarkable、ultimately等正式书面语词汇，符合大学阶段英语书面表达的要求，这类词汇相较于普通词汇（如many、good、finally）更能体现语言的正式性和精准性，适合用于学术或正式报告类文本。","本句描述的是已经完成的动作，所以谓语动词使用一般过去时achieved，体现了过去发生的动作对现在的影响，符合一般过去时用于表述过去完成的具体事件的语法规则。"]},"sentenceWithHints":"尽管 面临 诸多 挑战， 这个 项目 最终 还是 取得了 显著 成果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (63, '{"words":[{"plural":"","chinese":"在","english":"in","examples":["In the morning, I usually read books.","She is interested in painting."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"这个","english":"this","examples":["This is my new phone.","I don''t like this movie."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"信息","english":"information","examples":["We need more information to make a decision.","The website provides useful information."],"phonetic":"/ˌɪnfərˈmeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"explosions","chinese":"爆炸","english":"explosion","examples":["The explosion was heard miles away.","The country has seen an explosion of new businesses."],"phonetic":"/ɪkˈsploʊʒn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is broken.","This is a photo of my family."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"eras","chinese":"时代","english":"era","examples":["We are living in a digital era.","The era of space exploration has just begun."],"phonetic":"/ˈɪrə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"批判性","english":"critical","examples":["Critical thinking is essential for students.","The patient is in critical condition."],"phonetic":"/ˈkrɪtɪkl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"思维","english":"thinking","examples":["His thinking is very logical.","We need to do some careful thinking before acting."],"phonetic":"/ˈθɪŋkɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"变得","english":"become","examples":["She has become a famous writer.","The weather is becoming colder."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"尤为","english":"particularly","examples":["I am particularly fond of classical music.","This problem is particularly difficult."],"phonetic":"/pərˈtɪkjələrli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to get enough sleep.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["介词短语作定语的用法","现在完成时的用法","抽象名词短语的英译","副词修饰形容词的用法"],"explanations":["本句中“of information explosion”是介词短语，用来修饰前面的“era”，在英语中常用“of + 名词”结构来表示所属关系或修饰限定，相当于中文的“……的”，这是书面英语中常见的正式表达，适合大学阶段的英语写作与翻译场景。","参考翻译中使用了现在完成时“has become”，现在完成时的结构为“have/has + 过去分词”，用来表示过去发生的动作对现在造成的影响或结果，本句中“变得尤为重要”强调的是从过去到现在的状态变化，且这个状态对当下有意义，符合现在完成时的使用语境。","“批判性思维”翻译为“critical thinking”，属于抽象名词短语的英译，这类由“形容词+动名词”构成的抽象名词短语是英语学术写作中的常见表达，大学阶段需要掌握这类对应中文抽象概念的固定英译方式，提升学术英语的表达能力。","“尤为重要”翻译为“particularly important”，其中“particularly”是副词，用来修饰形容词“important”，起到加强语气的作用，在英语中副词修饰形容词通常放在形容词之前，这是副词的基本用法之一，在正式文本中常用于突出强调程度。"]},"sentenceWithHints":"在 这个 信息 爆炸 的 时代， 批判性 思维 变得 尤为 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (64, '{"words":[{"plural":"globalizations","chinese":"全球化","english":"globalization","examples":["Globalization has changed the world economy.","The impact of globalization is widespread."],"phonetic":"/ˌɡloʊbələˈzeɪʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"不仅","english":"not only","examples":["She not only sings well but also dances beautifully.","He not only studies hard but also helps others."],"phonetic":"/nɑːt ˈoʊnli/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"促进了","english":"promote","examples":["The new policy will promote economic growth.","We need to promote cultural understanding."],"phonetic":"/prəˈmoʊt/","pastTense":"promoted","thirdPerson":"promotes","partOfSpeech":"动词","pastParticiple":"promoted","presentParticiple":"promoting"},{"plural":"","chinese":"经济","english":"economic","examples":["The country is facing economic challenges.","Economic development is a key goal."],"phonetic":"/ˌiːkəˈnɑːmɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"developments","chinese":"发展","english":"development","examples":["The development of technology is rapid.","We are witnessing new developments in medicine."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"plural":"","chinese":"也","english":"but also","examples":["This book is not only interesting but also educational.","He can not only speak English but also French."],"phonetic":"/bʌt ˈoʊlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"带来了","english":"bring about","examples":["The new law brought about significant changes.","Technological progress brings about new opportunities."],"phonetic":"/brɪŋ əˈbaʊt/","pastTense":"brought about","thirdPerson":"brings about","partOfSpeech":"动词","pastParticiple":"brought about","presentParticiple":"bringing about"},{"plural":"","chinese":"文化","english":"cultural","examples":["We should respect cultural differences.","Cultural exchange enriches our lives."],"phonetic":"/ˈkʌltʃərəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"exchanges","chinese":"交流","english":"exchange","examples":["Cultural exchange is important for international relations.","We had an exchange of ideas during the meeting."],"phonetic":"/ɪksˈtʃeɪndʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["并列连词结构 not only...but also...","动词短语 bring about 的用法","抽象名词的使用","形容词作定语修饰名词"],"explanations":["not only...but also...是英语中常用的并列连词结构，用于连接两个并列的成分，包括动词、名词、形容词等，强调两者兼具。本句中连接的是两个谓语部分promotes economic development和brings about cultural exchange，注意当连接两个谓语时，动词形式要与主语保持一致，本句主语是不可数名词globalization，所以动词用第三人称单数形式。","bring about是固定动词短语，意为“带来，引起，导致”，后面常接表示结果、变化的名词作宾语，属于及物动词短语，不能单独使用，必须接宾语。","本句中出现了globalization、development、exchange等抽象名词，这类名词通常为不可数名词，在表示泛指时不需要加冠词，在正式书面语（如学术文本）中使用频率高，是大学英语写作和翻译的重点词汇。","本句中economic修饰development、cultural修饰exchange，属于形容词作定语修饰抽象名词的用法，在英语中常用形容词来限定抽象名词的范畴，使表达更具体准确，这是正式英语表达的常见结构。"]},"sentenceWithHints":"全球化 不仅 促进了 经济 发展，也 带来了 文化 交流"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (65, '{"words":[{"plural":"technologies","chinese":"技术","english":"technology","examples":["Technology is changing our life.","We need to develop new technology."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Innovation is the key to success.","The company has made many technological innovations."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"在","english":"to","examples":["I go to school every day.","She is talking to her friend."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很大","english":"great","examples":["It is a great idea.","She has a great influence on me."],"phonetic":"/ɡreɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"extents","chinese":"程度","english":"extent","examples":["To some extent, he is right.","I agree with you to a certain extent."],"phonetic":"/ɪkˈstent/","partOfSpeech":"名词"},{"plural":"","chinese":"上","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"推动","english":"drive","examples":["The wind drives the windmill.","Hard work drives his success."],"phonetic":"/draɪv/","pastTense":"drove","thirdPerson":"drives","partOfSpeech":"动词","pastParticiple":"driven","presentParticiple":"driving"},{"plural":"","chinese":"了","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"人类","english":"human","examples":["Human beings need love.","It is a human right."],"phonetic":"/ˈhjuːmən/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"societies","chinese":"社会","english":"society","examples":["We live in a modern society.","Society should care for the poor."],"phonetic":"/səˈsaɪəti/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"进步","english":"progress","examples":["We have made great progress.","Progress is slow but steady."],"phonetic":"/ˈprɑːɡres/","partOfSpeech":"名词"}],"examPoints":{"points":["现在完成时的用法","介词短语作状语的位置","名词性短语的英译","不规则动词的过去分词形式"],"explanations":["本句使用现在完成时“has driven”，强调技术创新对人类社会进步产生的影响持续到现在，符合现在完成时“表示过去发生的动作对现在造成的影响或结果”的用法，常用于正式书面语中，契合大学英语书面表达的语境要求。","“to a great extent”是介词短语作状语，在本句中位于助动词和实义动词之间，这是英语中状语灵活摆放的体现，此类状语也可置于句首或句末，用于说明动作发生的程度，在正式文本中较为常见。","中文“技术创新”“人类社会的进步”这类偏正结构的名词性短语，英译时常用形容词+名词的结构（如“Technological innovation”）或“the + 名词 + of + 名词”的所属结构（如“the progress of human society”），这是汉英翻译中名词性短语转换的核心技巧，也是大学英语翻译的常考内容。","“drive”是不规则动词，其过去分词形式为“driven”，而非规则的“drived”，在现在完成时中需要使用过去分词形式，不规则动词的变形是大学英语词汇考查的重点内容之一。"]},"sentenceWithHints":"技术 创新 在 很大 程度 上 推动 了 人类 社会 的 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (67, '{"words":[{"plural":"afternoons","chinese":"下午","english":"afternoon","examples":["Good afternoon, class!","I will go shopping this afternoon."],"phonetic":"/ˌæftərˈnuːn/","partOfSpeech":"名词"},{"plural":"","chinese":"好","english":"good","examples":["Good morning!","She is a good girl."],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"}],"examPoints":{"points":["日常问候语的英文表达","名词的单复数变化"],"explanations":["在英语中，不同时段的问候语有固定表达，“下午好”对应的标准英文表达是“Good afternoon”，通常用于中午12点到傍晚这段时间的问候。","名词afternoon是可数名词，其复数形式为规则变化，直接在词尾加-s，即afternoons，可用于表示多个下午，如“on rainy afternoons（在下雨的下午）”。"]},"sentenceWithHints":"下午 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (68, '{"words":[{"plural":"evenings","chinese":"晚上","english":"evening","examples":["I usually read books in the evening.","We are going to have a party this evening."],"phonetic":"/ˈiːvnɪŋ/","partOfSpeech":"名词"},{"plural":"","chinese":"好","english":"good","examples":["She is a good girl.","Have a good day!"],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"}],"examPoints":{"points":["日常问候语的英文表达","形容词修饰名词的搭配"],"explanations":["在英语中，不同时段的问候语有区别，“Good evening”用于傍晚到睡前的问候，区别于早上的“Good morning”、下午的“Good afternoon”，是小学阶段需要掌握的基础日常交际用语。","本句中形容词“good”用来修饰名词“evening”，构成常用的问候短语，这是形容词修饰名词的基础搭配形式，是小学低年级需要掌握的基础语法点。"]},"sentenceWithHints":"晚上 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (69, '{"words":[{"plural":"nights","chinese":"晚","english":"night","examples":["Good night, mom.","I sleep at night."],"phonetic":"/naɪt/","partOfSpeech":"名词"},{"plural":"","chinese":"安","english":"good","examples":["She is a good girl.","This is a good book."],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"}],"examPoints":{"points":["日常交际用语","名词和形容词的基础认知"],"explanations":["\"晚安（Good night）\"是小学阶段需要掌握的基础日常交际用语，用于睡前向他人道别，是英语日常对话中的常用表达。","此处\"晚\"对应英文名词night，需要了解其作为表示时间的名词的用法；\"安\"对应英文形容词good，需要掌握其作为形容词用于修饰名词，表达正向评价的基础用法。"]},"sentenceWithHints":"晚 安"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (70, '{"words":[{"plural":"names","chinese":"名","english":"name","examples":["What''s your name?","Her name is Lily."],"phonetic":"/neɪm/","partOfSpeech":"名词"},{"plural":"names","chinese":"字","english":"name","examples":["What''s your name?","Her name is Lily."],"phonetic":"/neɪm/","partOfSpeech":"名词"}],"examPoints":{"points":["名词的单复数变化","自我介绍常用表达"],"explanations":["name是可数名词，单数形式表示单个名字，复数形式names表示多个名字，规则变化直接在词尾加-s。","小学阶段自我介绍常用表达“What''s your name?”（你叫什么名字？）和“My name is...”（我的名字是……），这是日常英语交际的基础句型，用于询问和告知姓名。"]},"sentenceWithHints":"名 字"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (71, '{"words":[{"plural":"ages","chinese":"年龄","english":"age","examples":["What''s your age?","She looks younger than her age."],"phonetic":"/eɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["年龄的英文表达","名词的单复数变化"],"explanations":["在英语中，表达“年龄”常用的结构是“主语 + be + 基数词 + years old”，比如“I am 5 years old.”，同时也可以用“age”直接指代年龄，比如“What''s your age?”。小学一年级阶段重点掌握“...years old”这个常用表达。","“age”是可数名词，其复数形式是规则变化，在词尾加“-s”变为“ages”，用于指代多个年龄或者不同年龄段，比如“People of all ages like this game.”。"]},"sentenceWithHints":"年龄"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (72, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","The school is very beautiful."],"phonetic":"/skuːl/","partOfSpeech":"名词"}],"examPoints":{"points":["名词的单复数用法","固定搭配 go to school"],"explanations":["school作为可数名词，单数形式可表示泛指的上学场所或抽象的上学概念，复数形式schools表示多个具体的学校建筑。在固定搭配go to school中，school用单数且不加冠词，表泛指上学这一行为；若要特指某一所学校，需加冠词，如go to the school。","go to school是小学阶段的核心固定搭配，意为“去上学”，用于描述日常的上学行为，注意和go to the school（去那所学校，不一定是上学）的区别。"]},"sentenceWithHints":"学校"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (73, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["This is my teacher.","The teacher is very kind."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数","介绍他人的常用表达"],"explanations":["teacher是可数名词，单数形式可搭配不定冠词a/an或者形容词性物主代词使用，复数形式为teachers，直接在词尾加-s，符合可数名词变复数的规则变化。小学一年级阶段需要掌握常见可数名词的单复数形式区分。","介绍他人时常用“This is...”的句型，当介绍自己的老师时，可以说“This is my teacher”，这是小学一年级需要掌握的基础日常交际表达，用于向别人介绍身边的人。"]},"sentenceWithHints":"老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (74, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["He is my friend.","I have many friends."],"phonetic":"/frend/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的单复数形式","形容词性物主代词的使用"],"explanations":["friend是可数名词，单数形式表示单个朋友，复数形式是在词尾加-s变成friends，表示多个朋友。小学一年级阶段需要掌握可数名词单复数的基础变化规则，以及单复数在句子中的搭配，比如单数名词前可以用a或者形容词性物主代词修饰，复数名词可以和many等词搭配。","在参考翻译“He is my friend”中，my是形容词性物主代词，用来修饰名词friend，表明朋友的所属关系，意为“我的”。小学一年级需要掌握基础的形容词性物主代词（如my, your, his等），了解它们用来修饰名词、表示所属的用法。"]},"sentenceWithHints":"朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (75, '{"words":[{"plural":"families","chinese":"家庭","english":"family","examples":["This is my family.","Her family is very big."],"phonetic":"/ˈfæməli/","partOfSpeech":"名词"}],"examPoints":{"points":["名词的单复数变化","介绍所属物品/人物的常用表达"],"explanations":["family作为“家庭”讲时是可数名词，以辅音字母+y结尾，变复数时要把y改为i再加-es，即families；当它表示“家人”时，常作复数概念。","小学阶段介绍自己的所属事物常用“This is my + 名词”的句式，用来向他人展示或介绍属于自己的人或物品，本句用该句式介绍自己的家庭，符合一年级英语的基础表达要求。"]},"sentenceWithHints":"家庭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (76, '{"words":[{"plural":"fathers","chinese":"爸爸","english":"father","examples":["This is my father.","Her father works in a hospital."],"phonetic":"/ˈfɑːðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["亲属类名词的英文表达","介绍他人的常用句式"],"explanations":["小学一年级阶段需要掌握常见亲属类名词的英文翻译，“爸爸”对应的英文常用表达为father，此外还有dad，在日常口语中使用更为随意。","介绍他人时常用“This is...”的句式，用于向别人介绍身边的人，这是小学低年级需要掌握的基础交际句型，本句参考翻译用该句式来呈现“爸爸”的语境用法，符合小学一年级的学习要求。"]},"sentenceWithHints":"爸爸"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (77, '{"words":[{"plural":"mothers","chinese":"妈妈","english":"mother","examples":["My mother is nice.","I love my mother."],"phonetic":"/ˈmʌðər/","partOfSpeech":"名词"}],"examPoints":{"points":["家庭成员类名词","介绍他人的常用表达"],"explanations":["小学一年级阶段需要掌握常见的家庭成员类英文名词，mother是表示“妈妈”的正式常用表达，对应中文里的“妈妈”。","介绍他人时常用“This is...”的句式，参考翻译“This is my mother”是向别人介绍自己妈妈的标准表达，适合一年级学生学习日常交际用语。"]},"sentenceWithHints":"妈妈"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (78, '{"words":[{"plural":"brothers","chinese":"兄弟","english":"brother","examples":["He is my elder brother.","I have two brothers."],"phonetic":"/ˈbrʌðər/","partOfSpeech":"名词"}],"examPoints":{"points":["亲属类英语名词的认知","主系表简单句结构"],"explanations":["小学一年级阶段需要掌握常见的亲属类英语名词，“brother”对应中文的“兄弟”，是表示亲属关系的基础名词，需要牢记其拼写、发音和含义。","参考翻译“He is my brother”是典型的主系表结构简单句，主语“He”指代男性，系动词“is”用于第三人称单数主语后，表语“my brother”说明主语的身份，这是小学阶段需要掌握的基础句子结构，用于介绍人物身份。"]},"sentenceWithHints":"兄弟"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (79, '{"words":[{"plural":"elder sisters","chinese":"姐","english":"elder sister","examples":["My elder sister is a nurse.","Her elder sister lives in Beijing."],"phonetic":"/ˈeldər ˈsɪstər/","partOfSpeech":"名词"},{"plural":"younger sisters","chinese":"妹","english":"younger sister","examples":["My younger sister likes drawing.","His younger sister is five years old."],"phonetic":"/ˈjʌŋɡər ˈsɪstər/","partOfSpeech":"名词"},{"plural":"sisters","chinese":"姐妹","english":"sister","examples":["She is my sister.","I have two sisters."],"phonetic":"/ˈsɪstər/","partOfSpeech":"名词"}],"examPoints":{"points":["亲属类名词的英文表达","名词单复数变化"],"explanations":["小学阶段需要掌握常见亲属类名词的英文表达，“姐妹”对应的通用英文是sister，区分长幼的话，姐姐是elder sister，妹妹是younger sister，参考翻译里用sister指代“姐妹”，符合基础阶段的表达要求。","可数名词sister的复数形式是规则变化，在词尾加-s变为sisters，小学一年级需要掌握这类规则可数名词的单复数变形，了解单数表示一个，复数表示多个的用法。"]},"sentenceWithHints":"姐 妹"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (80, '{"words":[{"plural":"colors","chinese":"颜色","english":"color","examples":["What''s your favorite color?","The box has many different colors."],"phonetic":"/ˈkʌlər/","partOfSpeech":"名词"}],"examPoints":{"points":["名词的单复数形式","颜色类词汇的认知"],"explanations":["color作为可数名词，单数形式表示单一颜色，复数形式colors表示多种颜色，规则变化直接在词尾加-s。","小学一年级阶段需要掌握基础的颜色类词汇，比如red（红色）、blue（蓝色）等，同时学会用“I like + 颜色”的句型表达自己的喜好，参考翻译中的“I like red”就是这类基础表达。"]},"sentenceWithHints":"颜色"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (81, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like playing football."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"apples","chinese":"苹果","english":"apple","examples":["I eat an apple every day.","Apples are good for health."],"phonetic":"/ˈæpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称代词作主语","动词原形的使用","可数名词复数表示一类事物"],"explanations":["当主语是第一人称代词“I（我）”时，作主语要使用主格形式I，在一般现在时中搭配动词原形使用。","在一般现在时中，主语是第一人称I时，谓语动词要用原形，本句中“喜欢”对应的like用原形即可，不需要变形。","表示一类事物时，可数名词可以用复数形式来泛指，不需要加冠词，本句中“苹果”用复数apples来表示泛指所有苹果这一类水果。"]},"sentenceWithHints":"我 喜欢 苹果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (82, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"is","examples":["She is singing.","It is a cat."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"看","english":"read","examples":["I read a story every night.","She is reading a newspaper now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"books","chinese":"书","english":"book","examples":["This is my book.","I have many books."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构与用法","第三人称单数主语搭配的be动词形式","可数名词单数的冠词使用"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词+动词的现在分词形式”。本句中“在看书”是正在进行的动作，所以用“is reading”来表达。","当主语是第三人称单数（如he、she、it）时，搭配的be动词要用is，本句主语是“他（he）”，属于第三人称单数，所以用is。","可数名词单数在句中首次出现且表示泛指时，前面要加不定冠词a或an，book是以辅音音素开头的单词，所以用a。"]},"sentenceWithHints":"他 在 看 书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (83, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"高兴","english":"happy","examples":["I am happy to see you.","They look happy today."],"phonetic":"/ˈhæpi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与be动词的搭配","副词修饰形容词的用法"],"explanations":["人称代词we是第一人称复数，对应的be动词一般现在时形式为are，这是小学阶段需要掌握的be动词基本搭配规则，不同人称和数要对应正确的be动词形式。","副词very用来修饰形容词happy，放在形容词之前，用来加强形容词所表达的程度，这是副词修饰形容词的基础用法，小学阶段需要掌握用very来强化形容词语义的表达。"]},"sentenceWithHints":"我们 很 高兴"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (84, '{"words":[{"plural":"cats","chinese":"猫","english":"cat","examples":["The cat is cute.","I have two cats."],"phonetic":"/kæt/","partOfSpeech":"名词"},{"chinese":"在","english":"is","examples":["He is reading.","The flower is red."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"睡觉","english":"sleep","examples":["I sleep well every night.","She is sleeping now."],"phonetic":"/sliːp/","pastTense":"slept","thirdPerson":"sleeps","partOfSpeech":"动词","pastParticiple":"slept","presentParticiple":"sleeping"}],"examPoints":{"points":["现在进行时结构","定冠词 the 的用法","可数名词单数"],"explanations":["现在进行时用来表示正在进行的动作，结构为“be动词（am/is/are）+ 动词的现在分词形式”。本句主语是第三人称单数“the cat”，所以be动词用is，sleep的现在分词是sleeping。","定冠词the用于特指某个事物，本句中特指说话双方都知道的那只猫，所以用the修饰cat。","cat是可数名词，单数形式单独出现时通常需要加冠词，这里用the来特指，符合可数名词单数的使用规则。"]},"sentenceWithHints":"猫 在 睡觉"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (86, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去","english":"go","examples":["I go to park every weekend.","She goes to work by bus."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"","chinese":"上学","english":"go to school","examples":["I go to school at 7 every morning.","He doesn''t go to school today."],"phonetic":"/ɡoʊ tuː skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"动词短语","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格用法","一般现在时的动词形式","固定短语搭配"],"explanations":["人称代词I是主格形式，在句子中作主语，用于指代说话人自己，小学阶段需要掌握主格代词的基本用法和对应语境。","一般现在时中，当主语是第一人称I时，谓语动词用原形。本句主语是I，所以动词go用原形；如果主语是第三人称单数（如he/she），动词要变为goes。","“上学”对应的固定英语表达是go to school，这是小学阶段需要掌握的常用日常短语，注意school前不需要加冠词，泛指上学这个行为。"]},"sentenceWithHints":"我 去 上学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (87, '{"words":[{"plural":"","chinese":"她","english":"she","examples":["She is a student.","She likes cats."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"is","examples":["He is reading a book.","It is raining outside."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"画画","english":"draw","examples":["I draw a picture every day.","She is drawing a flower now."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"}],"examPoints":{"points":["现在进行时的结构与用法","人称代词作主语的主谓一致"],"explanations":["现在进行时表示现在正在进行的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中“在画画”是正在进行的动作，所以用“is drawing”的结构，draw的现在分词是直接在词尾加-ing。","当主语是第三人称单数代词（如she/he/it）时，对应的be动词要用is，本句主语是“她（she）”，属于第三人称单数，因此be动词使用is，符合主谓一致的要求。"]},"sentenceWithHints":"她 在 画画"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (88, '{"words":[{"plural":"dogs","chinese":"狗","english":"dog","examples":["The dog is cute.","I have two dogs."],"phonetic":"/dɔːɡ/","partOfSpeech":"名词"},{"chinese":"在","english":"is","examples":["He is reading.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"跑","english":"run","examples":["I run every morning.","She is running fast."],"phonetic":"/rʌn/","pastTense":"ran","thirdPerson":"runs","partOfSpeech":"动词","pastParticiple":"run","presentParticiple":"running"}],"examPoints":{"points":["现在进行时结构","可数名词单数的定冠词使用"],"explanations":["现在进行时用来表示正在发生的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句主语是单数的the dog，所以be动词用is，run的现在分词是running，构成is running的结构。","当特指某一个事物时，可数名词单数前要加定冠词the，本句中特指这只正在跑的狗，所以用the dog。"]},"sentenceWithHints":"狗 在 跑"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (89, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"","examples":["我们是好朋友。","他们喜欢踢足球。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吃","english":"have","examples":["I have breakfast every day.","She has a cat."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"午","english":"","examples":["中午的太阳很大。","午休时间到了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"lunches","chinese":"饭","english":"lunch","examples":["We have lunch at 12 o''clock.","Lunch is ready."],"phonetic":"/lʌntʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","表示用餐的固定表达","一般现在时的主谓一致"],"explanations":["“我们”对应的英文是第一人称复数代词“We”，在句中作主语时，后面的动词用原形。小学阶段需要掌握常见的人称代词主格形式，包括I, you, he, she, it, we, they。","在英语中，表示“吃某顿饭”常用“have + 三餐”的固定表达，比如have breakfast（吃早饭）、have dinner（吃晚饭），不需要加冠词a/an或the。","本句是一般现在时，主语“We”是第一人称复数，所以后面的动词have用原形。当主语是第三人称单数（he/she/it等）时，动词要变成第三人称单数形式has，比如“He has lunch at school.”。"]},"sentenceWithHints":"我 们 吃 午 饭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (90, '{"words":[{"plural":"birds","chinese":"鸟","english":"bird","examples":["A little bird is singing.","There are many birds in the tree."],"phonetic":"/bɜːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"in","examples":["The cat is in the box.","She is in the classroom."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"skies","chinese":"天上","english":"sky","examples":["The sky is blue.","Birds are flying in the sky."],"phonetic":"/skaɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"飞","english":"fly","examples":["Birds fly south in winter.","He is flying a kite."],"phonetic":"/flaɪ/","pastTense":"flew","thirdPerson":"flies","partOfSpeech":"动词","pastParticiple":"flown","presentParticiple":"flying"}],"examPoints":{"points":["现在进行时的用法","定冠词the的用法","介词in的方位表达"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词(am/is/are)+动词的现在分词形式”。本句中鸟正在飞，主语the bird是第三人称单数，所以be动词用is，fly的现在分词是flying。","定冠词the用于特指某个事物，这里the bird特指说话双方都知道的那只鸟，所以要加the。","介词in可以用来表示在某个空间范围之内，“in the sky”表示在天空这个空间里，是表达方位的常用搭配。"]},"sentenceWithHints":"鸟 在 天上 飞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (91, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"踢","english":"play","examples":["He plays basketball every day.","They are playing games."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"soccers","chinese":"足球","english":"soccer","examples":["I play soccer after school.","Soccer is my favorite sport."],"phonetic":"/ˈsɑːkər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定用法","球类名词的表达"],"explanations":["like后接动词时，常用like doing sth.的结构，表示长期的、习惯性的喜好，本句中like playing soccer就表示习惯性喜欢踢足球；另外like后也可以接like to do sth.，多表示具体某次的喜好，小学阶段重点掌握like doing sth.的用法。","在英语中，表示球类运动的名词前通常不加冠词，比如play soccer、play basketball，这是小学阶段需要掌握的固定搭配，不需要在soccer前加a或the。"]},"sentenceWithHints":"我 喜欢 踢 足球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (92, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"写","english":"do","examples":["I do my homework every day.","She does housework on weekends."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"","chinese":"作业","english":"homework","examples":["I have to finish my homework.","The teacher gave us a lot of homework."],"phonetic":"/ˈhoʊmwɜːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第三人称单数动词变化","不可数名词的用法"],"explanations":["当句子主语是第三人称单数（如he、she、it）时，一般现在时中的实义动词需要变成第三人称单数形式。本句主语是he，属于第三人称单数，所以表示“做（作业）”的do要变成does。","homework是不可数名词，没有复数形式，不能在后面加-s或-es，也不能直接用不定冠词a/an修饰，表达“作业的量”时可以用much、a lot of等词。"]},"sentenceWithHints":"他 写 作业"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (93, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We like playing football."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看","english":"watch","examples":["I watch cartoons every day.","She is watching a movie now."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"TVs","chinese":"电视","english":"TV","examples":["I have a new TV.","We watch TV after dinner."],"phonetic":"/ˌtiːˈviː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词主格的用法","一般现在时主谓一致","固定搭配"],"explanations":["人称代词主格we在句中作主语，用来指代说话者及他人，在本句中作动作“看”的发出者，位于句首引导句子。","本句是一般现在时，主语we是第一人称复数，谓语动词watch用原形即可，不需要进行第三人称单数变形；如果主语是第三人称单数（如he/she/it），谓语动词才需要变为watches。","“看电视”的固定英文表达为watch TV，TV是television的缩写，在这个搭配中不需要加冠词，属于常用的日常生活类固定短语。"]},"sentenceWithHints":"我们 看 电视"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (94, '{"words":[{"plural":"cats","chinese":"猫","english":"cat","examples":["The cat is cute.","I have two cats."],"phonetic":"/kæt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like apples.","She likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"吃","english":"eat","examples":["I eat rice every day.","He is eating a hamburger."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"fish/fishes","chinese":"鱼","english":"fish","examples":["I like eating fish.","There are many fishes in the lake."],"phonetic":"/fɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第三人称单数动词变化","可数名词单复数","动词不定式省略to的用法"],"explanations":["当句子主语是第三人称单数（如本句的the cat）时，一般现在时的谓语动词要使用第三人称单数形式，like的第三人称单数是likes。","fish表示“鱼的条数”时，单复数同形为fish；表示“鱼的种类”时，复数形式为fishes。本句中fish指鱼肉或泛指鱼，常用单数形式表示类别。","在表示“喜欢做某事”时，常用like doing sth或like to do sth的结构，本句中“喜欢吃鱼”翻译为likes fish，也可表达为likes eating fish，这里省略了动词不定式的to或者直接用动名词，符合小学阶段的常用表达。"]},"sentenceWithHints":"猫 喜欢 吃 鱼"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (95, '{"words":[{"plural":"","chinese":"今天","english":"today","examples":["Today is Monday.","I will go to the park today."],"phonetic":"/təˈdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"days","chinese":"星期","english":"day","examples":["What day is it?","Monday is my favorite day."],"phonetic":"/deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"几","english":"what","examples":["What is your name?","What time is it?"],"phonetic":"/wɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["询问星期的固定句型","词汇对应"],"explanations":["询问星期几的固定英文表达为“What day is it today?”，这是小学阶段需要掌握的日常交际句型，注意与询问日期的“What''s the date today?”区分开。","需要掌握“今天（today）”“星期（day）”对应的英文词汇，以及疑问词“几”在该语境下对应疑问代词“what”，明确词汇在日常交际句型中的具体用法。"]},"sentenceWithHints":"今天 星期 几"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (96, '{"words":[{"chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"昨天","english":"yesterday","examples":["I played football yesterday.","She didn''t come to school yesterday."],"phonetic":"/ˈjestərdeɪ/","partOfSpeech":"副词"},{"chinese":"去了","english":"go","examples":["I go to the park every weekend.","He went to Beijing last month."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"parks","chinese":"公园","english":"park","examples":["Let''s go to the park.","There are many parks in the city."],"phonetic":"/pɑːrk/","partOfSpeech":"名词"}],"examPoints":{"points":["一般过去时的用法","不规则动词的过去式","时间副词的位置"],"explanations":["当句子中有表示过去的时间状语（如yesterday）时，谓语动词要用一般过去时，用来描述过去发生的动作。本句中yesterday表明动作发生在昨天，所以动词go要用过去式went。","go是不规则动词，它的过去式不是在词尾加-ed，而是特殊变化形式went，需要单独记忆，小学阶段需要掌握常见的不规则动词过去式变化。","表示时间的副词yesterday在英语句子中通常可以放在句末，这和中文中时间状语常放在句首的位置有所不同，需要注意中英表达的语序差异。"]},"sentenceWithHints":"我 昨天 去了 公园"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (97, '{"words":[{"plural":"","chinese":"她","english":"she","examples":["She is my sister.","She likes reading books."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every","examples":["I go to school every day.","Every student has a book."],"phonetic":"/ˈevri/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"mornings","chinese":"早上","english":"morning","examples":["I get up early in the morning.","We often take a walk on Sunday mornings."],"phonetic":"/ˈmɔːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"跑步","english":"run","examples":["I run for half an hour every day.","She ran to the bus stop quickly."],"phonetic":"/rʌn/","pastTense":"ran","thirdPerson":"runs","partOfSpeech":"动词","pastParticiple":"run","presentParticiple":"running"}],"examPoints":{"points":["一般现在时第三人称单数变化","时间状语的用法"],"explanations":["当句子主语是第三人称单数（如 she、he、it 或单个的人/物），且时态为一般现在时表示经常性、习惯性的动作时，谓语动词需要变成第三人称单数形式。规则动词一般在词尾加-s，以辅音字母加y结尾的变y为i加-es，不规则动词有特殊变化，本句中run的第三人称单数形式是runs。","every morning属于表示经常性时间的状语，用于一般现在时，说明动作是每天都会发生的习惯性行为，在句子中通常放在句末位置。"]},"sentenceWithHints":"她 每天 早上 跑步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (98, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We will go to the park."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"明天","english":"tomorrow","examples":["I will see you tomorrow.","Tomorrow is Sunday."],"phonetic":"/təˈmɑːroʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去","english":"go","examples":["I go to school every day.","She will go to the library."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"zoos","chinese":"动物园","english":"zoo","examples":["Let''s go to the zoo.","The zoo has many animals."],"phonetic":"/zuː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的 will 结构","地点介词 to 的用法","时间状语的位置"],"explanations":["小学阶段一般将来时常用“will + 动词原形”结构，表示将要发生的动作，本句中用 will go 表达“明天要去”的将来动作，主语是 we，will 无需变形，后面接动词原形 go。","表示“去某个地点”时，动词 go 后面要加介词 to，再接地点名词，构成 go to + 地点的结构，本句中 go to the zoo 就是“去动物园”的正确表达。","表示时间的副词 tomorrow 属于时间状语，在英语中可以放在句首或句尾，本参考翻译将其放在句尾，符合英语的表达习惯，小学阶段需要掌握时间状语的常见摆放位置。"]},"sentenceWithHints":"我们 明天 去 动物园"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (99, '{"words":[{"chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","partOfSpeech":"代词"},{"chinese":"正在","english":"is","examples":["He is reading a book.","She is singing."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"吃","english":"have","examples":["I have a cat.","She has breakfast at 7."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"breakfasts","chinese":"早餐","english":"breakfast","examples":["I eat breakfast every day.","We had a big breakfast."],"phonetic":"/ˈbrekfəst/","partOfSpeech":"名词"}],"examPoints":{"points":["现在进行时结构","三餐类名词的用法"],"explanations":["现在进行时用来表示正在进行的动作，结构为“be动词（am/is/are）+ 动词的现在分词形式”。本句主语是第三人称单数“he”，所以be动词用is，动词“吃”对应的have变为现在分词having。","表示“吃三餐”时，三餐名词前通常不加冠词，比如“have breakfast”“have lunch”，不需要说“have a breakfast”，这是小学阶段需要掌握的固定搭配用法。"]},"sentenceWithHints":"他 正在 吃 早餐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (100, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like playing football.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"读","english":"read","examples":["I read a book every day.","He is reading a newspaper."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"story books","chinese":"故事书","english":"story book","examples":["I have many story books.","She gave me a story book as a gift."],"phonetic":"/ˈstɔːri bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词的复数形式"],"explanations":["like作为动词表示“喜欢”时，常用结构为like doing sth.，表示长期的、习惯性的喜好，本句中“喜欢读故事书”是长期爱好，所以用like reading。当主语是第三人称单数时，like要变成likes。","可数名词表示一类事物时，常用复数形式。“故事书”是可数名词，其复数形式是在book后加s，变成story books，用来表示故事书这一类书籍。"]},"sentenceWithHints":"我 喜欢 读 故事书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (102, '{"words":[{"plural":"cats","chinese":"猫","english":"cat","examples":["The cat is cute.","I have two cats."],"phonetic":"/kæt/","partOfSpeech":"名词"},{"chinese":"坐","english":"sit","examples":["She sits by the window.","He is sitting on the chair."],"phonetic":"/sɪt/","pastTense":"sat","thirdPerson":"sits","partOfSpeech":"动词","pastParticiple":"sat","presentParticiple":"sitting"},{"chinese":"在","english":"on","examples":["The book is on the desk.","Put the cup on the table."],"phonetic":"/ɑːn/","partOfSpeech":"介词"},{"plural":"tables","chinese":"桌子","english":"table","examples":["We eat at the table.","There are three tables in the room."],"phonetic":"/ˈteɪbl/","partOfSpeech":"名词"},{"chinese":"上","english":"","examples":["The apple is on the tree.","The pen is on the desk."],"phonetic":"","partOfSpeech":"助词"}],"examPoints":{"points":["现在进行时态","表示方位的介词on","定冠词the的用法"],"explanations":["现在进行时态表示正在进行的动作，结构为“be动词+动词的现在分词”。本句中主语the cat是第三人称单数，be动词用is，sit的现在分词是sitting，所以构成is sitting的结构。","介词on用于表示物体在另一个物体的表面之上，本句中表示猫在桌子的表面，所以用on。","定冠词the用于特指某个特定的人或事物，本句中the cat和the table都是特指双方都知道的那只猫和那张桌子，所以要用the来修饰。"]},"sentenceWithHints":"猫 坐 在 桌子 上"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (103, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"learn","examples":["I learn math every day.","She learns to play the piano."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"英语","english":"English","examples":["We speak English in class.","English is an important language."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词主格的用法","一般现在时的用法","学科类名词的用法"],"explanations":["人称代词主格we在句中作主语，用来指代说话者及其他人，对应中文的“我们”，在一般现在时中，当主语是第一人称复数we时，谓语动词用原形。","一般现在时用来表示经常性、习惯性的动作，本句描述的是日常的学习行为，主语是第一人称复数we，所以谓语动词learn用原形；当主语是第三人称单数时，谓语动词要变为第三人称单数形式learns。","表示学科的名词如English，首字母需要大写，这类名词通常作为不可数名词使用，前面不需要加不定冠词a/an。"]},"sentenceWithHints":"我__们__ 学__习__ 英__语__"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (104, '{"words":[{"chinese":"她","english":"she","examples":["She is a student.","She likes cats."],"phonetic":"/ʃiː/","partOfSpeech":"代词"},{"chinese":"有","english":"have","examples":["I have a pen.","She has a dog."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"chinese":"一个","english":"a","examples":["I have a book.","This is a apple."],"phonetic":"/ə/","partOfSpeech":"冠词"},{"chinese":"大","english":"big","examples":["This is a big apple.","He has a big house."],"phonetic":"/bɪɡ/","partOfSpeech":"形容词"},{"plural":"school bags","chinese":"书包","english":"school bag","examples":["She has a new school bag.","My school bag is blue."],"phonetic":"/ˈskuːl bæɡ/","partOfSpeech":"名词"}],"examPoints":{"points":["第三人称单数动词变化","不定冠词的使用","形容词修饰名词"],"explanations":["当主语是第三人称单数（如 she、he、it）时，一般现在时中的动词要使用第三人称单数形式。本句主语是 she，所以动词 have 要变为 has。","不定冠词 a 用于辅音音素开头的可数名词单数前，用来表示“一个”的泛指概念。本句中 school bag 是可数名词单数，且以辅音音素开头，所以用 a。","形容词用来修饰名词，通常放在名词前面，用来描述名词的特征。本句中 big 是形容词，放在 school bag 前面，用来描述书包的大小。"]},"sentenceWithHints":"她 有 一个 大 书包"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (105, '{"words":[{"plural":"","chinese":"今天","english":"today","examples":["Today is sunny.","I will go to the park today."],"phonetic":"/təˈdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a nurse.","This is my cat."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"birthdays","chinese":"生日","english":"birthday","examples":["Happy birthday to you!","I got a gift on my birthday."],"phonetic":"/ˈbɜːrθdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["系动词be的用法","形容词性物主代词的使用","时间名词的表达"],"explanations":["be动词有am、is、are三种形式，当主语是第三人称单数或者单数名词时，使用is。本句主语today是单数时间名词，所以搭配is。","my是形容词性物主代词，后面必须接名词，用来表示所属关系，说明后面的名词属于说话人，比如my birthday表示“我的生日”。","today是表示时间的名词，在句中可以作主语、状语等，用来指代当前的这一天，在本句中作主语引出当天的情况。"]},"sentenceWithHints":"今天 是 我的 生日"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (107, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes reading."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes to sing songs."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"玩","english":"play","examples":["We play football after school.","He is playing a piano."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"games","chinese":"游戏","english":"game","examples":["Let''s play a game.","I love video games."],"phonetic":"/ɡeɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词的第三人称单数变化","like的固定用法","可数名词的复数形式"],"explanations":["当主语是第三人称单数（如he、she、it）时，一般现在时的动词要变成第三人称单数形式。like的第三人称单数是在词尾加-s，即likes。","like后接动词有两种常用结构：like doing sth. 表示长期的、习惯性的喜好；like to do sth. 表示偶尔的、具体的意愿。本句表达的是习惯性喜好，所以用like playing。","可数名词表示泛指一类事物时，通常用复数形式。game是可数名词，其复数形式是在词尾加-s，即games，这里用games表示游戏这一类事物。"]},"sentenceWithHints":"他 喜欢 玩 游戏"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (108, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"in","examples":["The cat is in the box.","We live in a small town."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"parks","chinese":"公园","english":"park","examples":["Let''s go to the park.","There is a big park near my home."],"phonetic":"/pɑːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"玩","english":"play","examples":["I play football every day.","She is playing with her doll."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"}],"examPoints":{"points":["人称代词的使用","地点介词in的用法","一般现在时的用法"],"explanations":["人称代词we是第一人称复数主格，在句中作主语，指代说话者及其他人，对应英文中的we，在一般现在时中，主语为we时，谓语动词用原形。","介词in表示“在……里面/范围内”，用于表示在某个场所内部，此处用来表示在公园这个地点范围内，构成地点状语in the park。","一般现在时用于表示经常性、习惯性的动作或当前的状态。本句描述的是常见的活动，主语是第一人称复数we，所以谓语动词play用原形。"]},"sentenceWithHints":"我们 在 公园 玩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (109, '{"words":[{"plural":"birds","chinese":"鸟儿","english":"bird","examples":["A bird is flying in the sky.","There are many birds in the forest."],"phonetic":"/bɜːrd/","partOfSpeech":"名词"},{"plural":"","chinese":"在","english":"in","examples":["The cat is in the box.","I live in a small town."],"phonetic":"/ɪn/","partOfSpeech":"介词"},{"plural":"trees","chinese":"树","english":"tree","examples":["We planted a tree last year.","The tree is very tall."],"phonetic":"/triː/","partOfSpeech":"名词"},{"plural":"","chinese":"上","english":"","examples":["书在桌子上。","风筝挂在墙上。"],"phonetic":"","partOfSpeech":"助词"},{"chinese":"唱歌","english":"sing","examples":["She sings very well.","They are singing a happy song."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"}],"examPoints":{"points":["现在进行时的用法","方位介词in的用法","可数名词复数形式"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词(am/is/are)+动词的现在分词形式”。本句中鸟儿正在唱歌，主语birds是复数，所以be动词用are，sing的现在分词是singing，构成are singing的结构。","方位介词in表示“在……里面/内部”，当表示外来的事物在树上时，用in the tree，比如鸟儿、风筝这类不是树本身长出来的东西；如果是树本身的部分，比如树叶、果实，用on the tree。","可数名词表示多个时要使用复数形式，规则名词一般在词尾加-s，bird的复数是birds，本句中表示不止一只鸟，所以用复数形式birds作主语。"]},"sentenceWithHints":"鸟儿 在 树 上 唱歌"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (110, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"帮","english":"help","examples":["I help my sister with her homework.","She helps old people cross the street."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"mothers","chinese":"妈妈","english":"mother","examples":["My mother can cook delicious food.","Mother is watering the flowers."],"phonetic":"/ˈmʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"做","english":"do","examples":["I do my homework after dinner.","He does sports every morning."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"","chinese":"家务","english":"housework","examples":["We should share housework at home.","She spends an hour on housework every day."],"phonetic":"/ˈhaʊswɜːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["help的固定搭配","人称代词的主格用法","不可数名词的用法"],"explanations":["help的常用固定搭配有help sb. (to) do sth.和help sb. with sth.，本句使用的是help sb. with sth.的结构，用来表达“帮助某人做某事”，其中with后接名词或名词短语。","人称代词I是主格形式，在句子中作主语，放在句首，用来指代说话人自己，小学阶段需要掌握主格代词I, you, he, she等的基本用法。","housework是不可数名词，没有复数形式，不能直接在前面加不定冠词a/an，也不能在词尾加-s/-es，表达“做家务”可以说do housework或者help with housework。"]},"sentenceWithHints":"我 帮 妈妈 做 家务"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (111, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["I have a big dream.","Her dreams come true."],"phonetic":"/driːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is tall.","The flower is red."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"成为","english":"become","examples":["I want to become a singer.","She became a teacher last year."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"一名","english":"a","examples":["I have a dog.","She is a student."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"doctors","chinese":"医生","english":"doctor","examples":["My father is a doctor.","The doctor helps sick people."],"phonetic":"/ˈdɑːktər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词不定式作表语","不定冠词a的用法","系动词is的用法"],"explanations":["当句子要说明主语的具体内容或将来的动作时，可用“to+动词原形”的动词不定式结构作表语，本句中“to become a doctor”用来解释“梦想”的具体内容，符合小学四年级对不定式简单用法的考查要求。","不定冠词a用于辅音音素开头的可数名词单数前，doctor以辅音音素/d/开头，所以前面用a，这是小学阶段冠词基础用法的核心考点。","系动词is用于第三人称单数主语后，本句主语“my dream”是单数名词，所以搭配is，这是小学阶段be动词人称和数的一致的基础考查点。"]},"sentenceWithHints":"我的 梦想 是 成为 一名 医生"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (112, '{"words":[{"chinese":"我们","english":"we","examples":["We are students.","We like playing football."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"通常","english":"usually","examples":["I usually get up at 7.","She usually walks to school."],"phonetic":"/ˈjuːʒuəli/","partOfSpeech":"副词"},{"chinese":"在","english":"at","examples":["I go to school at 8.","We meet at the park."],"phonetic":"/æt/","partOfSpeech":"介词"},{"plural":"","chinese":"七点","english":"seven o''clock","examples":["It''s seven o''clock now.","We start class at seven o''clock."],"phonetic":"/ˈsevən əˈklɑːk/","partOfSpeech":"名词"},{"chinese":"吃","english":"have","examples":["I have breakfast every day.","She has a cat."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"晚饭","english":"dinner","examples":["We have dinner at 7.","Dinner is ready."],"phonetic":"/ˈdɪnər/","partOfSpeech":"名词"}],"examPoints":{"points":["频度副词的位置","时间介词at的用法","三餐类名词的用法"],"explanations":["频度副词usually表示“通常”，在一般现在时的句子中，要放在实义动词之前，be动词、助动词之后。本句中实义动词是have，所以usually放在have前面。","介词at用于表示具体的时间点，“七点”是具体的时刻，所以用at来连接时间。","dinner属于三餐类名词，一般情况下前面不加冠词，表达“吃三餐”常用“have+三餐名词”的结构，比如have dinner、have lunch。"]},"sentenceWithHints":"我们 通常 在 七点 吃 晚饭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (113, '{"words":[{"plural":"","chinese":"她","english":"she","examples":["She is a student.","She likes reading."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"比","english":"than","examples":["He is older than me.","This apple is bigger than that one."],"phonetic":"/ðæn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"她的","english":"her","examples":["Her cat is cute.","This is her book."],"phonetic":"/hɜːr/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"brothers","chinese":"哥哥","english":"brother","examples":["My brother is ten years old.","She has two brothers."],"phonetic":"/ˈbrʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"高","english":"tall","examples":["The tree is tall.","He is a tall boy."],"phonetic":"/tɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词的比较级用法","比较级的结构“主语+be动词+比较级+than+比较对象”"],"explanations":["单音节形容词的比较级通常在词尾加-er，tall的比较级是taller，用于两者之间的比较，说明一方在某方面比另一方更突出。","在英语中表达“A比B更……”的常用结构是“主语+be动词+比较级+than+比较对象”，本句中用“She is taller than her brother”来对应中文“她比她的哥哥高”，符合小学阶段的比较句型要求。"]},"sentenceWithHints":"她 比 她的 哥哥 高"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (114, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my pen.","This cat is cute."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"本","english":"","examples":["一本书","三本杂志"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["I have a new book.","She is reading a book."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The food is very delicious."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有趣","english":"interesting","examples":["This movie is interesting.","We had an interesting talk."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"","english":"is","examples":["He is a student.","The flower is beautiful."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["指示代词的使用","系动词be的搭配","副词修饰形容词的用法"],"explanations":["指示代词this用于指代单数的、距离较近的事物，本句中用来指代单数的“书”，对应英文的this，后面接可数名词单数。","当句子是主系表结构表示事物的特征时，主语是单数可数名词（this book），系动词要用is，连接主语和表语（interesting），构成完整的主系表句式。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰interesting，强调“有趣”的程度，符合英语中副词修饰形容词的位置规则。"]},"sentenceWithHints":"这 本 书 很 有趣。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (115, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"要","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"保护","english":"protect","examples":["We should protect animals.","It''s our duty to protect the earth."],"phonetic":"/prəˈtekt/","pastTense":"protected","thirdPerson":"protects","partOfSpeech":"动词","pastParticiple":"protected","presentParticiple":"protecting"},{"plural":"environments","chinese":"环境","english":"environment","examples":["We need to protect the environment.","The environment here is very beautiful."],"phonetic":"/ɪnˈvaɪrənmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词should的用法","定冠词the的特指用法","及物动词protect的使用"],"explanations":["should作为情态动词，后接动词原形，用来表达责任、建议或义务，本句中用来表达我们有保护环境的责任，符合小学四年级对基础情态动词的考查要求。","定冠词the用于特指双方都知道的事物，本句中the environment特指我们共同生活的自然环境，是小学阶段需要掌握的定冠词基础用法。","protect是及物动词，后面可以直接接宾语，本句中接宾语the environment，小学四年级需要掌握这类及物动词的基本搭配和使用场景。"]},"sentenceWithHints":"我们 要 保护 环境"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (116, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"擅长","english":"be good at","examples":["She is good at dancing.","They were good at playing chess when they were young."],"phonetic":"/biː ɡʊd æt/","pastTense":"was/were good at","thirdPerson":"is/was good at","partOfSpeech":"动词短语","pastParticiple":"been good at","presentParticiple":"being good at"},{"plural":"maths","chinese":"数学","english":"math","examples":["I like math very much.","Maths is my favorite subject."],"phonetic":"/mæθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定短语be good at的用法","第三人称单数作主语时be动词的形式"],"explanations":["be good at是固定动词短语，意为“擅长……”，后接名词、代词或动名词，用来表达某人在某方面具备特长或能力，是小学阶段需要掌握的常用表达。","当主语是第三人称单数（如本句中的he）时，一般现在时里的be动词要使用is，这是小学阶段人称与be动词搭配的基础知识点，需要牢记不同人称对应的be动词形式。"]},"sentenceWithHints":"他 擅长 数学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (117, '{"words":[{"chinese":"我们","english":"we","examples":["We are friends.","We like playing football."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"明天","english":"tomorrow","examples":["I will go to park tomorrow.","Tomorrow is Sunday."],"phonetic":"/təˈmɑːroʊ/","partOfSpeech":"副词"},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new pen."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"chinese":"个","english":"a","examples":["I have a book.","He is a boy."],"phonetic":"/ə/","partOfSpeech":"冠词"},{"plural":"tests","chinese":"考试","english":"test","examples":["We will have a math test.","The tests are difficult."],"phonetic":"/test/","partOfSpeech":"名词"}],"examPoints":{"points":["一般现在时用法","时间副词位置","不定冠词a的用法"],"explanations":["当表示计划好的、即将发生的动作（如安排好的考试），可以用一般现在时表达。本句主语是第一人称复数we，所以谓语动词用have的原形。","表示时间的副词tomorrow在英语中通常可以放在句末，也可放在句首，本句放在句末符合英语表达习惯。","不定冠词a用于辅音音素开头的可数名词单数前，test是以辅音音素/t/开头的可数名词单数，所以前面用a来表示“一个”的泛指概念。"]},"sentenceWithHints":"我们 明天 有 个 考试"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (118, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like playing football.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"weekends","chinese":"周末","english":"weekend","examples":["I often go hiking on weekends.","We had a great weekend."],"phonetic":"/ˈwiːkend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看","english":"watch","examples":["I watch TV every night.","He watched a movie yesterday."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"movies","chinese":"电影","english":"movie","examples":["Let''s see a movie.","I love action movies."],"phonetic":"/ˈmuːvi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","时间介词on的用法","可数名词复数"],"explanations":["like后接动词时，可接动名词（doing形式）表示长期的爱好习惯，本句中like watching movies表示长期喜欢看电影的爱好，符合小学阶段对like用法的考查要求。","表示在具体的某天或周末、节日等时间前，要用介词on，本句中on weekends表示在周末，是小学阶段需要掌握的时间介词搭配。","可数名词表示泛指一类事物时，通常用复数形式，movie是可数名词，这里用movies泛指电影这类事物，同时weekend用weekends表示多个周末的泛指情况，符合小学阶段可数名词复数的考查点。"]},"sentenceWithHints":"我 喜欢 周末 看 电影"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (119, '{"words":[{"plural":"","chinese":"她","english":"she","examples":["She is a student.","She likes reading books."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"正在","english":"be + -ing","examples":["I am watching TV now.","They are playing football."],"phonetic":"/biː/ /ˈɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"learn","examples":["I learn English every day.","She is learning to dance."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"弹","english":"play","examples":["He can play basketball.","She is playing the guitar."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"pianos","chinese":"钢琴","english":"piano","examples":["She plays the piano every weekend.","I want to buy a new piano."],"phonetic":"/piˈænoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构与用法","learn to do sth.的固定搭配","乐器前加定冠词the的规则"],"explanations":["现在进行时表示正在进行的动作，结构为“am/is/are + 动词的现在分词”。本句主语是第三人称单数she，所以用is，learn的现在分词是learning。","learn后接动词时，常用learn to do sth.的结构，表示“学习做某事”，所以此处用to play。","表示演奏某种乐器时，乐器名词前必须加定冠词the，比如play the piano、play the violin；而球类运动前不加the，比如play football。"]},"sentenceWithHints":"她 正在 学习 弹 钢琴"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (120, '{"words":[{"chinese":"这","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","partOfSpeech":"代词"},{"plural":"weeks","chinese":"周","english":"week","examples":["I have a busy week.","We will travel next week."],"phonetic":"/wiːk/","partOfSpeech":"名词"},{"chinese":"我们","english":"we","examples":["We are friends.","We love playing football."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"去","english":"go","examples":["I go to school every day.","She went to the park yesterday."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"chinese":"了","english":"","examples":["I ate an apple.","She finished her homework."],"phonetic":"","partOfSpeech":"助词"},{"plural":"libraries","chinese":"图书馆","english":"library","examples":["I often read books in the library.","The new library is very big."],"phonetic":"/ˈlaɪbreri/","partOfSpeech":"名词"}],"examPoints":{"points":["一般过去时的用法","地点介词to的使用","可数名词的定冠词搭配"],"explanations":["句子中“了”提示动作已经完成，对应英语的一般过去时，动词go的过去式是不规则变形went，小学阶段需要重点记忆这类不规则动词的过去式形式。","表示“去某地”时，英语中常用“go to + 地点名词”的结构，这里to作为地点介词，用来连接动词go和目的地library。","当特指某个具体的图书馆时，需要在可数名词library前加定冠词the，本句中对话双方默认知道所指的图书馆，因此使用the。"]},"sentenceWithHints":"这 周 我们 去 了 图书馆"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (121, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I read books every day.","She exercises every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"mornings","chinese":"早上","english":"morning","examples":["I get up early in the morning.","We have breakfast every morning."],"phonetic":"/ˈmɔːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喝","english":"drink","examples":["I drink water every day.","She drinks juice for breakfast."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"milks","chinese":"牛奶","english":"milk","examples":["I like milk.","She drinks milk every morning."],"phonetic":"/mɪlk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时用法","时间状语的位置","不可数名词的使用"],"explanations":["当句子表达经常性、习惯性的动作时，要用一般现在时。本句中“每天早上”表示习惯性动作，主语是第一人称“I”，所以动词用原形“drink”；如果主语是第三人称单数，动词要变为第三人称单数形式，比如“He drinks milk every morning.”。","表示频率的时间状语“every morning”通常放在句末，用来说明动作发生的时间规律，类似的时间状语还有“every day”“every week”等。","“milk”是不可数名词，一般情况下没有复数形式，也不能直接用不定冠词“a/an”修饰，表达数量时需要借助量词，比如“a glass of milk（一杯牛奶）”。"]},"sentenceWithHints":"我 每天 早上 喝 牛奶"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (122, '{"words":[{"plural":"","chinese":"他们","english":"they","examples":["They are students.","They like playing football."],"phonetic":"/ðeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"正在","english":"be + -ing","examples":["I am reading a book.","We are watching TV."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"讨论","english":"discuss","examples":["We will discuss the plan tomorrow.","She discusses the homework with her friend."],"phonetic":"/dɪˈskʌs/","pastTense":"discussed","thirdPerson":"discusses","partOfSpeech":"动词","pastParticiple":"discussed","presentParticiple":"discussing"},{"plural":"problems","chinese":"问题","english":"problem","examples":["I have a math problem.","They solved the problem together."],"phonetic":"/ˈprɑːbləm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构与用法","定冠词the的特指用法"],"explanations":["现在进行时表示正在进行的动作，结构为“am/is/are + 动词的现在分词”。本句主语是复数代词they，所以be动词用are，动词discuss的现在分词是discussing，组合起来就是are discussing，对应中文的“正在讨论”。","定冠词the用于特指双方都知道的人或事物，本句中“问题”是对话双方都明确的特定问题，所以用the来修饰problem。"]},"sentenceWithHints":"他们 正在 讨论 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (123, '{"words":[{"plural":"springs","chinese":"春天","english":"spring","examples":["Spring is my favorite season.","It often rains in spring."],"phonetic":"/sprɪŋ/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"","examples":["The book of my sister is new.","This is the color of the sky."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"times","chinese":"时候","english":"time","examples":["I was busy at that time.","It''s time to go home."],"phonetic":"/taɪm/","partOfSpeech":"名词"},{"plural":"flowers","chinese":"花儿","english":"flower","examples":["The flower is very beautiful.","There are many flowers in the garden."],"phonetic":"/ˈflaʊər/","partOfSpeech":"名词"},{"plural":"","chinese":"开","english":"bloom","examples":["The roses bloom in summer.","The flowers are blooming now."],"phonetic":"/bluːm/","pastTense":"bloomed","thirdPerson":"blooms","partOfSpeech":"动词","pastParticiple":"bloomed","presentParticiple":"blooming"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She went to the park."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["时间介词in的用法","可数名词复数的使用","一般现在时的用法"],"explanations":["表示在某个季节、月份、年份等较长的时间范围时，要用介词in。本句中“春天的时候”翻译为in spring，符合这一用法。","可数名词表示一类事物时，常用复数形式。本句中“花儿”指的是一类事物，所以用复数flowers，不需要加不定冠词。","一般现在时可以用来表示客观事实或普遍存在的现象。本句描述春天花儿开放是自然规律，属于客观事实，所以用一般现在时，主语flowers是复数，谓语动词用原形bloom。"]},"sentenceWithHints":"春天 的 时候 花儿 开 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (124, '{"words":[{"plural":"","chinese":"我","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"sisters","chinese":"妹妹","english":"sister","examples":["My sister loves dancing.","She has two sisters."],"phonetic":"/ˈsɪstər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","He likes playing football."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"吃","english":"eat","examples":["I eat breakfast every day.","She eats an apple after dinner."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"ice creams","chinese":"冰淇淋","english":"ice cream","examples":["I want some ice cream.","She bought three ice creams."],"phonetic":"/ˈaɪs kriːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词第三人称单数变化","like的固定搭配","不可数名词的特殊用法"],"explanations":["当句子主语是第三人称单数（如本句的my sister）时，一般现在时中的谓语动词要使用第三人称单数形式。like的第三人称单数是直接在词尾加s，变为likes。","like后可以接动名词（doing形式）表示长期的爱好，本句中like eating表示长期喜欢吃冰淇淋的习惯，这是小学阶段需要掌握的like的核心搭配之一。","ice cream作为物质名词时是不可数名词，表示泛指的冰淇淋；当表示具体的一份或几份冰淇淋时，也可以作为可数名词，复数形式为ice creams，本句中是泛指冰淇淋这类食物，所以用原形。"]},"sentenceWithHints":"我 妹妹 喜欢 吃 冰淇淋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (125, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love playing football."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"打算","english":"plan","examples":["I plan to visit my grandma this weekend.","She plans to learn English well."],"phonetic":"/plæn/","pastTense":"planned","thirdPerson":"plans","partOfSpeech":"动词","pastParticiple":"planned","presentParticiple":"planning"},{"plural":"","chinese":"去","english":"go","examples":["I go to school every day.","He went to the park yesterday."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"trips","chinese":"旅行","english":"trip","examples":["We had a great trip last summer.","She is on a business trip now."],"phonetic":"/trɪp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词短语plan to do sth的用法","固定搭配go on a trip的用法","人称代词主格的使用"],"explanations":["plan作为动词，常见用法是plan to do sth，意为“打算做某事”，表示将来的计划，小学阶段需要掌握这个动词短语的结构和含义，能正确运用到句子中表达自己的计划。","go on a trip是固定的动词短语，意为“去旅行”，是小学阶段需要掌握的出行类常用表达，要记住这个固定搭配，不能随意替换其中的介词。","we是人称代词主格，在句子中作主语，用来指代说话者及其他人，小学阶段需要区分人称代词主格和宾格的用法，本句中we作主语，所以使用主格形式。"]},"sentenceWithHints":"我们 打算 去 旅行"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (126, '{"words":[{"plural":"","chinese":"如果","english":"if","examples":["If it rains, we will stay home.","You can go if you finish your homework."],"phonetic":"/ɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"努力","english":"hard","examples":["She works hard every day.","He studies hard for the test."],"phonetic":"/hɑːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"study","examples":["I study English every morning.","She studied math last night."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you later."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":"willing"},{"plural":"","chinese":"取得","english":"get","examples":["I get a gift on my birthday.","She got good grades last term."],"phonetic":"/ɡet/","pastTense":"got","thirdPerson":"gets","partOfSpeech":"动词","pastParticiple":"got/gotten","presentParticiple":"getting"},{"plural":"","chinese":"好","english":"good","examples":["This is a good book.","She is a good student."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"grades","chinese":"成绩","english":"grade","examples":["He got high grades in the exam.","My grades are getting better."],"phonetic":"/ɡreɪd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["if引导的条件状语从句（主将从现）","副词hard的用法","可数名词复数形式"],"explanations":["在if引导的条件状语从句中，要遵循“主将从现”的规则：即从句用一般现在时表示将来的条件，主句用一般将来时（will+动词原形）。本句中从句“如果你努力学习”用一般现在时you study hard，主句“你会取得好成绩”用一般将来时you will get good grades，符合这个规则。","hard作为副词时，用来修饰动词，表示“努力地”，通常放在动词后面，本句中hard修饰study，放在study之后，表达“努力学习”的意思。","grade表示“成绩”时是可数名词，当表示多个科目的成绩时要用复数形式grades，本句中“好成绩”指的是各类考试或科目的成绩，所以用复数grades。"]},"sentenceWithHints":"如果 你 努力 学习，你 会 取得 好 成绩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (127, '{"words":[{"plural":"","chinese":"虽然","english":"although","examples":["Although it is cold, he goes out without a coat.","Although she is tired, she finishes her homework."],"phonetic":"/ɔːlˈðoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"chinese":"下雨","english":"rain","examples":["It rains a lot in spring.","It was raining heavily when I got home."],"phonetic":"/reɪn/","pastTense":"rained","thirdPerson":"rains","partOfSpeech":"动词","pastParticiple":"rained","presentParticiple":"raining"},{"plural":"","chinese":"了","english":"/","examples":["我吃饭了。","他已经走了。"],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"但","english":"but","examples":["I like apples, but I don''t like bananas.","She is young, but she is very smart."],"phonetic":"/bʌt/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We will go to the park tomorrow."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"还是","english":"still","examples":["He is still working.","I still remember that day."],"phonetic":"/stɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"出去","english":"go out","examples":["I often go out with my friends on weekends.","She went out to buy some milk yesterday."],"phonetic":"/ɡoʊ aʊt/","pastTense":"went out","thirdPerson":"goes out","partOfSpeech":"动词","pastParticiple":"gone out","presentParticiple":"going out"},{"plural":"","chinese":"了","english":"/","examples":["我吃饭了。","他已经走了。"],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["让步状语从句的引导词","过去进行时的用法","一般过去时的不规则动词变化","副词still的用法"],"explanations":["使用although或but引导让步关系，注意在英语中although和but不能同时出现在一个句子里，本句参考翻译用although引导从句，符合英语表达习惯。","过去进行时（was/were + 现在分词）用来表示过去某个时间段正在进行的动作，本句中“虽然下雨了”是当时正在发生的状态，所以用it was raining。","动词go是不规则动词，它的过去式是went，过去分词是gone，在表达“出去”这个短语的过去式时，要用went out，需要牢记这类不规则动词的变形。","副词still表示“仍然、还是”，通常放在实义动词之前，be动词、助动词之后，本句中放在主语we和实义动词短语went out之间，用来强调尽管下雨，依旧外出的动作。"]},"sentenceWithHints":"虽然 下雨 了， 但 我们 还是 出去 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (128, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不","english":"not","examples":["I do not like coffee.","She is not at home."],"phonetic":"/nɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"知道","english":"know","examples":["I know your name.","She knows how to swim."],"phonetic":"/noʊ/","pastTense":"knew","thirdPerson":"knows","partOfSpeech":"动词","pastParticiple":"known","presentParticiple":"knowing"},{"plural":"","chinese":"他","english":"he","examples":["He is my brother.","He plays football every day."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"be","examples":["I am in the classroom.","They are at the park."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"哪里","english":"where","examples":["Where is my pen?","Do you know where she lives?"],"phonetic":"/wer/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["否定句的构成","宾语从句的语序"],"explanations":["一般现在时中，当主语是第一人称单数I时，实义动词的否定形式要借助助动词do，再加not，缩写为don''t，即I don''t know，这是小学阶段需要掌握的实义动词否定句基本结构。","本句中where he is是宾语从句，在英语中宾语从句要用陈述语序，即主语在前，谓语在后，不能写成where is he，这是小学五年级学习宾语从句的核心知识点之一。"]},"sentenceWithHints":"我 不 知道 他 在 哪里"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (129, '{"words":[{"chinese":"她","english":"she","examples":["She is a student.","She likes reading."],"phonetic":"/ʃiː/","partOfSpeech":"代词"},{"chinese":"告诉","english":"tell","examples":["He tells me a story every day.","She told me the news yesterday."],"phonetic":"/tel/","pastTense":"told","thirdPerson":"tells","partOfSpeech":"动词","pastParticiple":"told","presentParticiple":"telling"},{"chinese":"我","english":"me","examples":["Please give me a pen.","She often helps me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"明天","english":"tomorrow","examples":["I will go to park tomorrow.","She will come tomorrow."],"phonetic":"/təˈmɑːroʊ/","partOfSpeech":"副词"},{"chinese":"会","english":"would","examples":["She said she would help me.","He told us he would arrive soon."],"phonetic":"/wʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"来","english":"come","examples":["Come here, please.","She comes to school early every day."],"phonetic":"/kʌm/","pastTense":"came","thirdPerson":"comes","partOfSpeech":"动词","pastParticiple":"come","presentParticiple":"coming"}],"examPoints":{"points":["宾语从句的时态呼应","一般过去时与过去将来时的用法"],"explanations":["当主句使用一般过去时（本句中told是tell的过去式），从句要使用相应的过去时态。本句中“明天会来”是过去视角下的将来动作，所以要用过去将来时would come，实现主从句的时态呼应。","一般过去时told用于表示过去发生的动作“告诉”；过去将来时would come用于表示在过去某个时间点（“告诉”这个动作发生时）看来，将要在未来发生的动作，符合句子中“她当时说自己之后会来”的语境。"]},"sentenceWithHints":"她 告诉 我 她 明天 会 来"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (131, '{"words":[{"chinese":"我","english":"I","examples":["I like apples.","I am a student."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"做","english":"do/finish","examples":["I do my homework every day.","I finish my homework early."],"phonetic":"/duː/ /ˈfɪnɪʃ/","pastTense":"did/finished","thirdPerson":"does/finishes","partOfSpeech":"动词","pastParticiple":"done/finished","presentParticiple":"doing/finishing"},{"chinese":"完","english":"finish/completed","examples":["I finish my work on time.","The task is completed."],"phonetic":"/ˈfɪnɪʃ/ /kəmˈpliːtɪd/","pastTense":"finished/completed","thirdPerson":"finishes/completes","partOfSpeech":"动词/形容词","pastParticiple":"finished/completed","presentParticiple":"finishing/completing"},{"plural":"","chinese":"作业","english":"homework","examples":["I have a lot of homework.","She is doing her homework."],"phonetic":"/ˈhoʊmwɜːrk/","partOfSpeech":"名词"},{"chinese":"后","english":"after","examples":["After dinner, I watch TV.","I will go after I finish."],"phonetic":"/ˈæftər/","partOfSpeech":"介词/连词"},{"chinese":"可以","english":"can","examples":["Can I help you?","You can go now."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"去","english":"go","examples":["I go to school every day.","She goes to the park."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"chinese":"玩","english":"play","examples":["I play football after school.","They play games together."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"chinese":"吗","english":"","examples":["Are you okay?","Can you help me?"],"phonetic":"","partOfSpeech":"语气词"}],"examPoints":{"points":["情态动词can引导一般疑问句","时间状语从句","并列动词结构"],"explanations":["情态动词can用于表达请求、许可，引导一般疑问句时要将can提前至句首，结构为“Can + 主语 + 动词原形 + 其他”，本句用来请求许可，符合该用法。","用after引导时间状语从句，说明动作发生的先后顺序，从句中主语是I，谓语动词用原形finish，符合小学阶段状语从句的基础用法。","“go play”是小学阶段常见的并列动词结构，省略了不定式符号to，表达“去做某事”的含义，类似结构还有go swim、go run等。"]},"sentenceWithHints":"我 做 完 作业 后 可以 去 玩 吗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (132, '{"words":[{"plural":"","chinese":"因为","english":"because","examples":["Because it rains, we stay at home.","I like cats because they are cute."],"phonetic":"/bɪˈkɔːz/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"chinese":"生病","english":"be sick","examples":["She was sick yesterday.","He is sick and can''t go out."],"phonetic":"/biː sɪk/","pastTense":"was sick/were sick","thirdPerson":"is sick","partOfSpeech":"动词","pastParticiple":"been sick","presentParticiple":"being sick"},{"plural":"","chinese":"了","english":"","examples":["I ate an apple.","She finished her homework."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"所以","english":"so","examples":["I''m tired, so I want to sleep.","She studies hard, so she gets good grades."],"phonetic":"/soʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"他","english":"he","examples":["He is my brother.","He plays football every day."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"没","english":"didn''t","examples":["I didn''t watch TV last night.","She didn''t finish her homework."],"phonetic":"/ˈdɪdnt/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"来","english":"come","examples":["Come here, please.","She came to my party last week."],"phonetic":"/kʌm/","pastTense":"came","thirdPerson":"comes","partOfSpeech":"动词","pastParticiple":"come","presentParticiple":"coming"},{"chinese":"上学","english":"come to school","examples":["I come to school by bike every day.","He didn''t come to school yesterday."],"phonetic":"/kʌm tuː skuːl/","pastTense":"came to school","thirdPerson":"comes to school","partOfSpeech":"动词","pastParticiple":"come to school","presentParticiple":"coming to school"}],"examPoints":{"points":["原因状语从句的用法","一般过去时的否定形式","不规则动词的过去式和过去分词"],"explanations":["在英语中，because 引导原因状语从句，说明事情发生的原因，so 引导结果状语从句说明结果，但英语里 because 和 so 不能同时出现在一个完整句子中，本句参考翻译用 because 引导原因从句，主句说明结果，符合英语表达习惯；小学阶段需要掌握用 because 表达因果关系的基本用法。","一般过去时的否定形式要借助助动词 did 的否定式 didn''t，后面跟动词原形，本句中“没来”翻译为 didn''t come，体现了这一规则，需要注意助动词 did 已经体现过去时态，后面的实义动词要变回原形。","come 是不规则动词，它的过去式是 came，过去分词是 come，小学五年级需要掌握常见不规则动词的变形，本句中涉及到 come 的过去式在否定句中的使用，同时 be 动词的过去式 was/were 也是需要掌握的不规则变形，主语 he 是第三人称单数，所以用 was。"]},"sentenceWithHints":"因为 生病 了， 所以 他 没 来 上学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (133, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my pen.","This cat is cute."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a nurse.","It is a sunny day."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I like reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有史","english":"ever","examples":["Have you ever been to London?","She is the smartest girl I have ever met."],"phonetic":"/ˈevər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"以来","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"吃","english":"eat","examples":["I eat rice every day.","She ate a hamburger for lunch."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"","chinese":"过","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"最","english":"the most","examples":["This is the most interesting book I have read.","She is the most beautiful girl in our class."],"phonetic":"/ðə moʊst/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好吃","english":"delicious","examples":["The cake is delicious.","This soup tastes delicious."],"phonetic":"/dɪˈlɪʃəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"apples","chinese":"苹果","english":"apple","examples":["I have an apple every morning.","There are many apples in the basket."],"phonetic":"/ˈæpl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词最高级的用法","现在完成时的用法","定语从句的省略"],"explanations":["多音节形容词的最高级形式是在前面加the most，本句中“好吃的”对应delicious，属于多音节形容词，所以最高级为the most delicious，用来修饰apple表示“最好吃的苹果”。","现在完成时结构为have/has+动词过去分词，用来表示过去发生的动作对现在造成的影响或从过去持续到现在的动作。本句中“have ever eaten”表示从过去到现在为止吃过的，符合现在完成时的使用场景，主语I是第一人称，所以用have。","在定语从句中，当关系代词that/which在从句中作宾语时可以省略。本句中“I have ever eaten”是修饰apple的定语从句，完整形式为“that I have ever eaten”，此处省略了关系代词that。"]},"sentenceWithHints":"这 是 我 有史 以来 吃 过 的 最 好吃 的 苹果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (134, '{"words":[{"plural":"","chinese":"请","english":"please","examples":["Please sit down.","Please help me with my homework."],"phonetic":"/pliːz/","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"把","english":"","examples":["把窗户关上。","把你的书包拿过来。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"那本","english":"that","examples":["That cat is cute.","Give me that pen."],"phonetic":"/ðæt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["I have a new book.","There are many books on the shelf."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"递给","english":"pass","examples":["Please pass the water.","She passes the ball to her friend."],"phonetic":"/pæs/","pastTense":"passed","thirdPerson":"passes","partOfSpeech":"动词","pastParticiple":"passed","presentParticiple":"passing"},{"plural":"","chinese":"我","english":"me","examples":["He gives a gift to me.","Please wait for me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["祈使句的用法","动词pass的固定搭配","人称代词宾格的使用"],"explanations":["祈使句通常用来表达请求、命令等语气，一般以动词原形开头，句首或句末加please可以使语气更委婉礼貌。本句以Please开头，后跟动词原形pass，是典型的请求类祈使句，符合小学五年级对祈使句的考查要求。","动词pass有固定搭配pass sth. to sb.，意思是“把某物递给某人”，这是小学阶段需要掌握的常用动词短语，在句子中用来准确表达传递物品的动作。","人称代词分为主格和宾格，当代词在句子中作宾语时，需要使用宾格形式。本句中“我”是动词pass的间接宾语，所以使用宾格me，这是小学阶段人称代词的核心考查点之一。"]},"sentenceWithHints":"请 把 那本 书 递给 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (135, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"宁愿","english":"would rather","examples":["I would rather stay at home than go out.","She would rather read than watch TV."],"phonetic":"/wʊd ˈræðər/","pastTense":"","thirdPerson":"","partOfSpeech":"短语","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"步行","english":"walk","examples":["I walk to school every morning.","She is walking in the park."],"phonetic":"/wɔːk/","pastTense":"walked","thirdPerson":"walks","partOfSpeech":"动词","pastParticiple":"walked","presentParticiple":"walking"},{"plural":"","chinese":"也","english":"than","examples":["He is taller than me.","I like cats better than dogs."],"phonetic":"/ðæn/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不","english":"","examples":["I do not like spicy food.","She is not at home."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"愿意","english":"","examples":["I am willing to help you.","She would like to go with us."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"坐","english":"take","examples":["I take the bus to work.","She took a taxi yesterday."],"phonetic":"/teɪk/","pastTense":"took","thirdPerson":"takes","partOfSpeech":"动词","pastParticiple":"taken","presentParticiple":"taking"},{"plural":"buses","chinese":"公交车","english":"bus","examples":["The bus is coming.","We take the bus to the zoo."],"phonetic":"/bʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["would rather...than...句型的用法","动词原形在句型中的使用","take+交通工具的表达"],"explanations":["would rather...than...是小学阶段重点学习的选择偏好句型，意为“宁愿……也不愿……”，用来表达在两个选项中更倾向于前者。","在would rather和than后面都要接动词原形，不需要根据主语的人称和数进行形式变化，本句中walk和take都用原形就是这个规则的体现。","表示乘坐某种交通工具时，可以用“take+the+交通工具”的结构，比如take the bus（坐公交车）、take the train（坐火车），这是小学阶段常见的出行表达方式。"]},"sentenceWithHints":"我 宁愿 步行 也 不 愿意 坐 公交车"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (136, '{"words":[{"chinese":"她","english":"she","examples":["She is my sister.","She likes reading."],"phonetic":"/ʃiː/","partOfSpeech":"代词"},{"chinese":"昨天","english":"yesterday","examples":["I went to park yesterday.","She finished her homework yesterday."],"phonetic":"/ˈjestərdeɪ/","partOfSpeech":"副词"},{"chinese":"买","english":"buy","examples":["I buy a pen every week.","She bought a dress yesterday."],"phonetic":"/baɪ/","pastTense":"bought","thirdPerson":"buys","partOfSpeech":"动词","pastParticiple":"bought","presentParticiple":"buying"},{"chinese":"的","english":"","examples":["The book I read is interesting.","The cat she keeps is cute."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"这件","english":"this","examples":["This is my book.","This dress is nice."],"phonetic":"/ðɪs/","partOfSpeech":"代词"},{"plural":"dresses","chinese":"衣服","english":"dress","examples":["She has a pretty dress.","These dresses are expensive."],"phonetic":"/dres/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very happy.","The food is very delicious."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"漂亮","english":"beautiful","examples":["The flower is beautiful.","She looks beautiful."],"phonetic":"/ˈbjuːtɪfəl/","partOfSpeech":"形容词"}],"examPoints":{"points":["定语从句的省略用法","一般过去式的使用","副词修饰形容词"],"explanations":["在英语中，当定语从句的关系代词在从句中作宾语时，可以省略关系代词。本句中\"she bought yesterday\"是修饰\"the dress\"的定语从句，完整形式是\"The dress that/which she bought yesterday is very beautiful\"，这里省略了that/which，这是小学阶段需要掌握的定语从句简化用法。","句中出现时间状语\"yesterday（昨天）\"，表示动作发生在过去，因此谓语动词要用一般过去式。\"buy\"的过去式是不规则变化的\"bought\"，需要牢记这类不规则动词的过去式形式。","副词\"very\"用来修饰形容词\"beautiful\"，表示程度，说明衣服漂亮的程度很高。在英语中，副词常用来修饰形容词、副词或动词，此处是副词修饰形容词的基础用法。"]},"sentenceWithHints":"她 昨天 买 的 这件 衣服 很 漂亮"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (137, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"","examples":["我们是好朋友。","他们喜欢打篮球。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"必须","english":"must","examples":["You must finish your homework.","We must follow the rules."],"phonetic":"/mʌst/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"按","english":"on","examples":["Put the book on the desk.","I go to school on Monday."],"phonetic":"/ɑːn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"times","chinese":"时","english":"time","examples":["What time is it?","I have no time to play."],"phonetic":"/taɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"完成","english":"finish","examples":["I finish my homework every day.","She finished the work yesterday."],"phonetic":"/ˈfɪnɪʃ/","pastTense":"finished","thirdPerson":"finishes","partOfSpeech":"动词","pastParticiple":"finished","presentParticiple":"finishing"},{"plural":"","chinese":"任","english":"","examples":["我们的任务很简单。","他完成了这项任务。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"tasks","chinese":"务","english":"task","examples":["This is a difficult task.","We have many tasks to do."],"phonetic":"/tæsk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词must的用法","固定短语on time的含义与用法","实义动词finish的用法"],"explanations":["must是情态动词，本身没有人称和数的变化，后面要接动词原形，用来表示“必须、不得不”，表达一种义务或要求，小学阶段需要掌握其基本用法和句式结构。","on time是固定介词短语，意为“按时、准时”，在句中通常作状语，用来说明动作发生的时间要求，是小学阶段需要掌握的常用时间类短语。","finish是实义动词，意为“完成”，后面可以直接接名词作宾语，比如finish the task；也可以接动名词，比如finish reading the book。小学阶段需要掌握其接名词宾语的用法以及它的基本变形形式，比如过去式finished、第三人称单数finishes等。"]},"sentenceWithHints":"我 们 必 须 按 时 完 成 任 务"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (138, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is a student.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一直","english":"always","examples":["I always get up early.","She always helps others."],"phonetic":"/ˈɔːlweɪz/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"等","english":"wait","examples":["Please wait for me.","I waited for an hour."],"phonetic":"/weɪt/","pastTense":"waited","thirdPerson":"waits","partOfSpeech":"动词","pastParticiple":"waited","presentParticiple":"waiting"},{"plural":"","chinese":"到","english":"until","examples":["I will stay here until you come back.","He worked until midnight."],"phonetic":"/ənˈtɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"她","english":"she","examples":["She is my sister.","She can play the piano."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"回来","english":"come back","examples":["When will you come back?","She came back home late yesterday."],"phonetic":"/kʌm bæk/","pastTense":"came back","thirdPerson":"comes back","partOfSpeech":"动词","pastParticiple":"come back","presentParticiple":"coming back"}],"examPoints":{"points":["一般过去时的用法","连词until的用法","短语动词come back的变形"],"explanations":["本句描述过去发生的动作，所以谓语动词要用一般过去时形式。wait的过去式是规则变化waited，come是不规则动词，过去式为came。一般过去时用于表示过去某个时间里发生的动作或存在的状态，常和表示过去的时间状语连用，也可用于描述过去连续发生的动作。","连词until用来引导时间状语从句，意思是“直到……为止”，主句和从句动作都发生在过去时，主从句都要用一般过去时。它可以连接两个过去的动作，说明一个动作持续到另一个动作发生时结束。","come back是短语动词，意为“回来”，在变一般过去时时，要把核心动词come变成过去式came，构成came back；第三人称单数形式是comes back，现在分词形式是coming back，过去分词形式是come back，需要掌握这类短语动词的时态变形规则。"]},"sentenceWithHints":"他 一直 等 到 她 回来。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (139, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my pen.","This cat is cute."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a student.","This is a nice day."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"my","examples":["My bag is red.","This is my favorite toy."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"第一","english":"first","examples":["This is my first gift.","He won the first prize."],"phonetic":"/fɜːrst/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"times","chinese":"次","english":"time","examples":["I have no time to play.","This is my third time here."],"phonetic":"/taɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"去","english":"go","examples":["I go to school every day.","She went to the park yesterday."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"","chinese":"北京","english":"Beijing","examples":["Beijing is the capital of China.","I want to visit Beijing."],"phonetic":"/beɪˈdʒɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["“It/This is one''s first time doing sth.”句型","物主代词的使用","动名词作后置定语"],"explanations":["“It/This is one''s first time doing sth.”是表达“这是某人第一次做某事”的常用固定句型，小学阶段需要掌握这个句型的结构和用法，用来描述首次经历的事情。","物主代词my用来表示所属关系，修饰后面的名词短语“first time”，说明这个“第一次”是属于“我”的，小学阶段需要掌握第一人称物主代词my的用法和含义。","在“this is my first time going to Beijing”中，going是go的动名词形式，在这里作后置定语修饰time，用来具体说明这个“次数”对应的行为是“去北京”，小学阶段需要了解动名词在这类句型中的应用。"]},"sentenceWithHints":"这 是 我 第一 次 去 北京"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (140, '{"words":[{"plural":"","chinese":"如果","english":"if","examples":["If it rains, we will stay home.","If you study hard, you will pass the exam."],"phonetic":"/ɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"没有","english":"without","examples":["I can''t do it without your help.","We can''t go out without umbrellas."],"phonetic":"/wɪˈðaʊt/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the flower is red."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"helps","chinese":"帮助","english":"help","examples":["Thank you for your help.","I need your help with my homework."],"phonetic":"/help/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"I","examples":["I love reading books.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"无法","english":"cannot","examples":["I cannot swim.","He cannot come to the party."],"phonetic":"/ˈkænɑːt/","pastTense":"could not","thirdPerson":"cannot","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"完成","english":"finish","examples":["I finish my homework every day.","She finished the task yesterday."],"phonetic":"/ˈfɪnɪʃ/","pastTense":"finished","thirdPerson":"finishes","partOfSpeech":"动词","pastParticiple":"finished","presentParticiple":"finishing"},{"plural":"","chinese":"这个","english":"this","examples":["This is my pen.","I like this book."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"projects","chinese":"项目","english":"project","examples":["We are working on a new project.","The project is very important."],"phonetic":"/ˈprɑːdʒekt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["介词without的用法","情态动词cannot的用法","实义动词finish的变形"],"explanations":["without是介词，意思是“没有”，后面可以接名词、代词或动名词，用来表示条件，本句中without your help用来引出假设的条件“没有你的帮助”。","cannot是情态动词can的否定形式，意思是“不能、无法”，后面要接动词原形，用来表达能力上的无法做到，小学阶段需要掌握它的基本用法和否定含义。","finish是实义动词，意思是“完成”，它的过去式和过去分词是在词尾加ed变成finished，第三人称单数形式是finishes，现在分词是finishing，小学五年级需要掌握它的基本变形和在句子中的使用。"]},"sentenceWithHints":"如果 没有 你 的 帮助， 我 无法 完成 这个 项目"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (141, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"应该","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"尊重","english":"respect","examples":["We should respect our parents.","Everyone needs to respect others'' feelings."],"phonetic":"/rɪˈspekt/","pastTense":"respected","thirdPerson":"respects","partOfSpeech":"动词","pastParticiple":"respected","presentParticiple":"respecting"},{"plural":"","chinese":"每个人","english":"everyone","examples":["Everyone likes gifts.","Everyone should follow the rules."],"phonetic":"/ˈevriwʌn/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"''s","examples":["Tom''s cat is cute.","The girl''s bag is pink."],"phonetic":"/z/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"choices","chinese":"选择","english":"choice","examples":["It''s your choice.","She has many choices."],"phonetic":"/tʃɔɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词should的用法","名词所有格的构成与用法","实义动词在情态动词后的形式"],"explanations":["should作为情态动词，后接动词原形，用来表示义务、建议或责任，本句中用来表达“应该做某事”的责任，符合小学六年级对情态动词基础用法的考查要求。","表示有生命的名词的所属关系时，可在名词后加''s构成所有格，本句中everyone''s用来表示“每个人的”，是单数不定代词的所有格形式，属于小学阶段名词所有格的重点考查内容。","实义动词在情态动词（如should）后面必须使用原形，本句中respect用在should之后，保持原形，这是小学阶段动词用法的基础考点。"]},"sentenceWithHints":"我 们 应 该 尊 重 每 个 人 的 选 择"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (142, '{"words":[{"plural":"","chinese":"无论","english":"no matter","examples":["No matter how hard it is, I will keep trying.","No matter who you are, you must follow the rules."],"phonetic":"/noʊ ˈmætər/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"chinese":"发生","english":"happen","examples":["What happened to you yesterday?","Something strange is happening here."],"phonetic":"/ˈhæpən/","pastTense":"happened","thirdPerson":"happens","partOfSpeech":"动词","pastParticiple":"happened","presentParticiple":"happening"},{"plural":"","chinese":"什么","english":"what","examples":["What is your name?","I don''t know what he wants."],"phonetic":"/wɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"I","examples":["I love reading books.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"都","english":"will","examples":["I will help you with your homework.","She will come to the party tonight."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":"willing"},{"chinese":"会","english":"will","examples":["They will finish the task on time.","I will never forget this day."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":"willing"},{"chinese":"支持","english":"support","examples":["My parents always support my dreams.","We should support each other."],"phonetic":"/səˈpɔːrt/","pastTense":"supported","thirdPerson":"supports","partOfSpeech":"动词","pastParticiple":"supported","presentParticiple":"supporting"},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you pass me the pen?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["让步状语从句结构 no matter what","一般将来时的用法","动词第三人称单数变化"],"explanations":["no matter what 用来引导让步状语从句，意思是“无论什么”，相当于 whatever，用来表示不管出现什么情况，主句的动作都会发生，小学阶段需要掌握这个基础的让步表达结构。","一般将来时用来表示将来要发生的动作或存在的状态，结构“will + 动词原形”是小学阶段必须掌握的一般将来时基本表达，本句中“will support”就表示将来要做出的“支持”这个动作。","在状语从句中，当主句是一般将来时时，从句要用一般现在时表将来，本句中从句主语 what 视为第三人称单数，所以动词 happen 要变成第三人称单数形式 happens，这是“主将从现”规则的基础应用，是六年级的重点知识点。"]},"sentenceWithHints":"无论 发生 什么 ， 我 都 会 支持 你"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (143, '{"words":[{"plural":"","chinese":"直到","english":"until","examples":["I will wait until you come back.","Don''t leave until the rain stops."],"phonetic":"/ənˈtɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"告诉","english":"tell","examples":["Please tell me your name.","She told me a story yesterday."],"phonetic":"/tel/","pastTense":"told","thirdPerson":"tells","partOfSpeech":"动词","pastParticiple":"told","presentParticiple":"telling"},{"plural":"","chinese":"我","english":"me","examples":["He gave me a gift.","Please wait for me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"truths","chinese":"真相","english":"truth","examples":["Tell me the truth, please.","He always speaks the truth."],"phonetic":"/truːθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"I","examples":["I love reading books.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"才","english":"（与until搭配体现逻辑，无单独对应词）","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to school tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":""},{"plural":"","chinese":"相信","english":"believe","examples":["I believe you are right.","Do you believe in magic?"],"phonetic":"/bɪˈliːv/","pastTense":"believed","thirdPerson":"believes","partOfSpeech":"动词","pastParticiple":"believed","presentParticiple":"believing"},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["not...until...句型的用法","一般将来时的否定结构","实义动词的变形"],"explanations":["not...until...是小学阶段重点句型，意为“直到……才……”，用来表达某个动作或状态直到另一个动作发生才会出现。本句中“won''t believe”（will not believe）和“until”搭配，体现“直到你告诉我真相，我才会相信”的逻辑。","一般将来时的基本结构是“will + 动词原形”，其否定形式是在will后加not，缩写为won''t，用来表达将来不会发生的动作，本句中“won''t believe”就是用这个结构表达“不会相信”的将来状态。","小学阶段需要掌握常见实义动词的变形，比如规则动词believe的过去式、过去分词直接加ed，第三人称单数加s；不规则动词tell的过去式和过去分词是told，这些变形在时态运用中经常考查。"]},"sentenceWithHints":"直到 你 告诉 我 真相， 我 才 会 相信 你"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (144, '{"words":[{"chinese":"她","english":"she","examples":["She is a student.","She likes reading."],"phonetic":"/ʃiː/","partOfSpeech":"代词"},{"chinese":"不仅","english":"not only","examples":["He is not only tall but also strong.","She can not only sing but also dance."],"phonetic":"/nɑːt ˈoʊnli/","partOfSpeech":"连词"},{"chinese":"聪明","english":"smart","examples":["The boy is very smart.","She has a smart cat."],"phonetic":"/smɑːrt/","partOfSpeech":"形容词"},{"chinese":"而且","english":"but also","examples":["This book is not only interesting but also educational.","He is not only rich but also kind."],"phonetic":"/bʌt ˈɔːlsoʊ/","partOfSpeech":"连词"},{"chinese":"很","english":"very","examples":["She is very happy.","The flower is very beautiful."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"勤奋","english":"hardworking","examples":["My sister is a hardworking student.","The hardworking farmer grows lots of crops."],"phonetic":"/ˈhɑːrdwɜːrkɪŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["并列连词短语 not only...but also... 的用法","形容词作表语的用法","副词修饰形容词的用法"],"explanations":["not only...but also... 是常用的并列连词短语，用来连接两个并列的成分，在本句中连接两个描述人物特质的形容词，意为“不仅……而且……”，使用时要注意前后连接的成分词性保持一致。","形容词 smart 和 hardworking 在句中作表语，用来描述主语“she”的特征，系动词 is 之后接形容词作表语是主系表结构的常见用法，用来表示主语的状态或属性。","副词 very 用来修饰形容词 hardworking，用来加强形容词的语气，说明“勤奋”的程度，副词修饰形容词时通常放在形容词的前面。"]},"sentenceWithHints":"她 不仅 聪明， 而且 很 勤奋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (145, '{"words":[{"plural":"","chinese":"既然","english":"since","examples":["Since you are free, let''s go shopping.","I have lived here since 2018."],"phonetic":"/sɪns/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"已经","english":"already","examples":["I have already finished my homework.","She has already left."],"phonetic":"/ɔːlˈredi/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"决定","english":"decide","examples":["I decide to learn English well.","He has decided to go to college."],"phonetic":"/dɪˈsaɪd/","pastTense":"decided","thirdPerson":"decides","partOfSpeech":"动词","pastParticiple":"decided","presentParticiple":"deciding"},{"plural":"","chinese":"了","english":"","examples":["I have eaten dinner already.","She has finished her work."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"那就","english":"just","examples":["Just do it!","Just tell me the truth."],"phonetic":"/dʒʌst/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去","english":"go","examples":["Let''s go to the park.","He goes to school by bike."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"","chinese":"做","english":"do","examples":["Do your homework carefully.","I have done all the chores."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"","chinese":"吧","english":"","examples":["Let''s go now, shall we?","Have a cup of tea, please."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","连词since的用法","祈使句的用法"],"explanations":["现在完成时结构为have/has+动词过去分词，用来表示过去发生的动作对现在造成的影响或结果，本句中“已经决定了”强调这个决定的状态延续到现在，所以用have decided，主语是you，搭配助动词have。","连词since在这里用来引导原因状语从句，引出“已经决定了”这个原因，相当于“既然”，用来连接因果关系的两个分句，小学阶段需要掌握它引导原因状语从句的基础用法。","祈使句通常用来表示请求、命令、建议等，本句中“just do it”是典型的祈使句，以动词原形开头，省略主语you，用来表达建议对方去做已经决定的事。"]},"sentenceWithHints":"既然 你 已经 决定 了， 那就 去 做 吧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (146, '{"words":[{"plural":"","chinese":"尽管","english":"although","examples":["Although it rained, we still had fun.","Although he is young, he can cook well."],"phonetic":"/ɔːlˈðoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"weathers","chinese":"天气","english":"weather","examples":["The weather is sunny today.","What''s the weather like?"],"phonetic":"/ˈweðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","This book is very interesting."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"冷","english":"cold","examples":["It''s cold in winter.","The water is too cold to drink."],"phonetic":"/koʊld/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"但","english":"but","examples":["I like apples but I don''t like bananas.","He is tired but he keeps working."],"phonetic":"/bʌt/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"他","english":"he","examples":["He is my brother.","He plays football every day."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"还是","english":"still","examples":["He still loves reading.","It''s still raining outside."],"phonetic":"/stɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"坚持","english":"insist","examples":["She insists on going to the park.","He insists that he is right."],"phonetic":"/ɪnˈsɪst/","pastTense":"insisted","thirdPerson":"insists","partOfSpeech":"动词","pastParticiple":"insisted","presentParticiple":"insisting"},{"plural":"","chinese":"跑步","english":"run","examples":["I run every morning.","He is running in the playground."],"phonetic":"/rʌn/","pastTense":"ran","thirdPerson":"runs","partOfSpeech":"动词","pastParticiple":"run","presentParticiple":"running"}],"examPoints":{"points":["让步状语从句的引导词","固定搭配insist on的用法","动词的第三人称单数形式"],"explanations":["本句使用although引导让步状语从句，表示“尽管，虽然”，需要注意although和but不能在同一个句子中同时使用，参考翻译中用了although，所以省略了but的对应英文表达，这是英语语法的固定规则。","insist on是固定动词搭配，意为“坚持做某事”，on是介词，后面接动词时需要用动词的ing形式，所以本句中用running。","当主语是第三人称单数（如本句中的he）时，一般现在时里的谓语动词要使用第三人称单数形式，insist的第三人称单数是insists，这是小学阶段需要掌握的动词变形规则。"]},"sentenceWithHints":"尽管 天气 很 冷， 但 他 还是 坚持 跑步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (147, '{"words":[{"plural":"","chinese":"这个","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"cities","chinese":"城市","english":"city","examples":["I live in a small city.","This city is very beautiful."],"phonetic":"/ˈsɪti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"compared to","examples":["Compared to you, I am still young.","This house is big compared to that one."],"phonetic":"/kəmˈperd tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"十年前","english":"ten years ago","examples":["I was a child ten years ago.","Ten years ago, we lived in a village."],"phonetic":"/ten jɪrz əˈɡoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"相比","english":"compare","examples":["Compare this with that, and you will see the difference.","We often compare dogs to loyal friends."],"phonetic":"/kəmˈper/","pastTense":"compared","thirdPerson":"compares","partOfSpeech":"动词","pastParticiple":"compared","presentParticiple":"comparing"},{"plural":"","chinese":"发生","english":"happen","examples":["What happened to you?","An accident happened yesterday."],"phonetic":"/ˈhæpən/","pastTense":"happened","thirdPerson":"happens","partOfSpeech":"动词","pastParticiple":"happened","presentParticiple":"happening"},{"plural":"","chinese":"了","english":"/","examples":["I have eaten the apple.","She has finished her homework."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"巨大","english":"greatly","examples":["He was greatly surprised.","The plan has greatly changed."],"phonetic":"/ˈɡreɪtli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"/","examples":["This is my mother''s bag.","The color of the flower is red."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"变化","english":"change","examples":["The weather changes every day.","She has changed a lot."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"}],"examPoints":{"points":["现在完成时的用法","compared to的用法","副词修饰动词"],"explanations":["现在完成时结构为have/has+动词过去分词，用来表示过去发生的动作对现在造成的影响或结果。本句中城市发生的变化是从过去持续到现在的状态，所以用has changed（主语this city是第三人称单数，助动词用has）。","compared to是固定搭配，意为“与……相比”，用来引出比较的对象，在句中通常作状语，符合本句将现在的城市和十年前的状态作比较的语境。","副词greatly用来修饰动词changed，说明变化的程度很大，在英语中副词常用来修饰动词、形容词或其他副词，放在动词前后都可，此处放在changed后符合表达习惯。"]},"sentenceWithHints":"这个 城市 和 十年前 相比 发生 了 巨大 的 变化"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (148, '{"words":[{"chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"越","english":"the","examples":["The more you read, the more you know.","The sooner, the better."],"phonetic":"/ðə/","partOfSpeech":"冠词"},{"chinese":"努力","english":"hard","examples":["He works hard every day.","Study hard and you will pass the exam."],"phonetic":"/hɑːrd/","partOfSpeech":"副词"},{"chinese":"学习","english":"study","examples":["I study English every night.","She studies very hard."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"就","english":"/","examples":[""],"phonetic":"/","partOfSpeech":"助词"},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":""},{"chinese":"取得","english":"get","examples":["I get good grades in math.","She got a gift on her birthday."],"phonetic":"/ɡet/","pastTense":"got","thirdPerson":"gets","partOfSpeech":"动词","pastParticiple":"got/gotten","presentParticiple":"getting"},{"chinese":"越","english":"the","examples":["The harder you try, the more you achieve.","The colder it is, the more I stay at home."],"phonetic":"/ðə/","partOfSpeech":"冠词"},{"chinese":"好","english":"good","examples":["This is a good book.","She is a good student."],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"},{"chinese":"的","english":"/","examples":[""],"phonetic":"/","partOfSpeech":"助词"},{"plural":"grades","chinese":"成绩","english":"grade","examples":["I got good grades this term.","Her grades are always excellent."],"phonetic":"/ɡreɪd/","partOfSpeech":"名词"}],"examPoints":{"points":["“the+比较级，the+比较级”句型","形容词和副词的比较级变化","一般将来时的用法"],"explanations":["“the+比较级，the+比较级”是小学六年级重点考查的句型，意为“越……，就越……”，用来表示两个变化之间的关联，前半句描述条件，后半句描述对应的结果，本句中表示学习越努力，成绩就越好。","形容词good的比较级是better，副词hard的比较级是harder，属于不规则和规则比较级的变化，小学阶段需要掌握常见形容词和副词的比较级形式，规则变化一般在词尾加-er，不规则变化需要特殊记忆。","一般将来时由“will+动词原形”构成，用来表示将来发生的动作或存在的状态，本句中“will get”表示未来会取得成绩，符合一般将来时的用法场景。"]},"sentenceWithHints":"我们 越 努力 学习，就 会 取得 越 好 的 成绩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (149, '{"words":[{"chinese":"他","english":"he","examples":["He is my brother.","He likes playing football."],"phonetic":"/hiː/","partOfSpeech":"代词"},{"chinese":"是","english":"is","examples":["She is a doctor.","It is a cat."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"班里","english":"in the class","examples":["There are 40 students in the class.","She is the tallest in the class."],"phonetic":"/ɪn ðə klæs/","partOfSpeech":"介词短语"},{"chinese":"最","english":"most","examples":["This is the most interesting book.","She is the most beautiful girl."],"phonetic":"/moʊst/","partOfSpeech":"副词"},{"chinese":"勤奋","english":"hardworking","examples":["He is a hardworking boy.","Hardworking people usually succeed."],"phonetic":"/ˈhɑːrdwɜːrkɪŋ/","partOfSpeech":"形容词"},{"chinese":"的","english":"of","examples":["the top of the mountain","one of my friends"],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"students","chinese":"学生","english":"student","examples":["There are many students in the classroom.","He is a good student."],"phonetic":"/ˈstuːdənt/","partOfSpeech":"名词"},{"chinese":"之一","english":"one of","examples":["She is one of my best friends.","This is one of the best movies."],"phonetic":"/wʌn əv/","partOfSpeech":"固定短语"}],"examPoints":{"points":["“one of + 形容词最高级 + 可数名词复数”结构","形容词最高级的用法","介词短语表地点范围"],"explanations":["“one of + the + 形容词最高级 + 可数名词复数”是小学阶段重点句型，用来表达“……中最……之一”，其中名词必须用复数形式，因为表示的是多个事物中的一个，本句中“students”是“student”的复数形式，符合该结构要求。","多音节形容词“hardworking”的最高级形式是在前面加“most”，同时最高级前要加定冠词“the”，用来表示在特定范围内的最高程度，本句中“the most hardworking”用来修饰“students”，说明是班里最勤奋的学生群体。","介词短语“in the class”用来限定范围，表明描述的对象是在班级这个特定范围内的学生，明确了最高级比较的范围，这是使用形容词最高级时常见的搭配，用来明确比较的语境。"]},"sentenceWithHints":"他 是 班里 最 勤奋 的 学生 之一"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (150, '{"words":[{"plural":"","chinese":"除非","english":"unless","examples":["Unless you study hard, you won''t pass the exam.","I won''t go unless you go with me."],"phonetic":"/ənˈles/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"道歉","english":"apologize","examples":["You should apologize for your mistake.","He apologized to his teacher yesterday."],"phonetic":"/əˈpɑːlədʒaɪz/","pastTense":"apologized","thirdPerson":"apologizes","partOfSpeech":"动词","pastParticiple":"apologized","presentParticiple":"apologizing"},{"plural":"","chinese":"否则","english":"or","examples":["Hurry up, or you''ll be late.","You must study, or you won''t get good grades."],"phonetic":"/ɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"I","examples":["I love reading books.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不会","english":"won''t","examples":["I won''t tell anyone your secret.","She won''t come to the party."],"phonetic":"/woʊnt/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"原谅","english":"forgive","examples":["I will forgive you this time.","She forgave him for forgetting her birthday."],"phonetic":"/fərˈɡɪv/","pastTense":"forgave","thirdPerson":"forgives","partOfSpeech":"动词","pastParticiple":"forgiven","presentParticiple":"forgiving"},{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["连词unless的用法","一般将来时的否定形式","不规则动词的变形"],"explanations":["unless作为连词，引导条件状语从句，意思是“除非，如果不”，相当于if...not。在主从复合句中，遵循“主将从现”的规则，即主句用一般将来时，从句用一般现在时表示将来。","一般将来时的否定形式是在will后面加not，缩写为won''t，用来表示将来不会发生的动作或存在的状态。","forgive是不规则动词，它的过去式是forgave，过去分词是forgiven，需要特殊记忆，区别于规则动词加-ed的变形方式；apologize是规则动词，变形直接在词尾加-ed、-s、-ing即可。"]},"sentenceWithHints":"除非 你 道歉， 否则 我 不会 原谅 你"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (152, '{"words":[{"plural":"","chinese":"她","english":"she","examples":["She is a student.","She likes reading books."],"phonetic":"/ʃiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"看起来","english":"look","examples":["You look tired.","The flowers look beautiful."],"phonetic":"/lʊk/","pastTense":"looked","thirdPerson":"looks","partOfSpeech":"动词","pastParticiple":"looked","presentParticiple":"looking"},{"plural":"","chinese":"比","english":"than","examples":["He is taller than me.","She runs faster than her brother."],"phonetic":"/ðæn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"实际","english":"actual","examples":["What is your actual height?","The actual cost is higher than we thought."],"phonetic":"/ˈæktʃuəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"ages","chinese":"年龄","english":"age","examples":["What''s your age?","Children of all ages love this game."],"phonetic":"/eɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"年轻","english":"young","examples":["She is a young girl.","My brother is younger than me."],"phonetic":"/jʌŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词的比较级用法","感官动词look的第三人称单数形式","比较连词than的用法"],"explanations":["当句子中出现表示比较的“比”时，形容词要使用比较级形式。young的比较级是直接在词尾加-er，即younger，用于两者之间的年龄对比。","感官动词look在这里作连系动词，主语she是第三人称单数，一般现在时中，第三人称单数主语后的动词要使用第三人称单数形式，look的第三人称单数是looks。","than是用于比较级句型的连词，用来引出比较的对象，本句中用than引出被比较的对象“her actual age（她的实际年龄）”，连接前后的比较内容。"]},"sentenceWithHints":"她 看起来 比 实际 年龄 年轻"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (153, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I want to be a writer."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"建议","english":"suggest","examples":["I suggest we go to the park.","She suggests eating out tonight."],"phonetic":"/səˈdʒest/","pastTense":"suggested","thirdPerson":"suggests","partOfSpeech":"动词","pastParticiple":"suggested","presentParticiple":"suggesting"},{"chinese":"你","english":"you","examples":["You are my best friend.","Can you help me?"],"phonetic":"/juː/","partOfSpeech":"代词"},{"chinese":"多","english":"more","examples":["Eat more vegetables.","I need more time."],"phonetic":"/mɔːr/","partOfSpeech":"形容词"},{"chinese":"读书","english":"read books","examples":["I read books every day.","Reading books is good for you."],"phonetic":"/riːd bʊks/","partOfSpeech":"动词短语"},{"chinese":"以","english":"to","examples":["I study hard to get good grades.","She runs every morning to keep fit."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"开阔","english":"broaden","examples":["Travel can broaden your mind.","Reading can broaden your knowledge."],"phonetic":"/ˈbrɔːdn/","pastTense":"broadened","thirdPerson":"broadens","partOfSpeech":"动词","pastParticiple":"broadened","presentParticiple":"broadening"},{"plural":"horizons","chinese":"视野","english":"horizons","examples":["Travel expands our horizons.","Reading opens up new horizons."],"phonetic":"/həˈraɪzənz/","partOfSpeech":"名词"}],"examPoints":{"points":["suggest的用法","动词不定式表目的","固定搭配broaden one''s horizons"],"explanations":["suggest作为及物动词，后接宾语从句时，从句通常用虚拟语气（should+动词原形，should可省略），本句中suggest you read more books就是省略了should的用法，符合小学阶段对该动词基础用法的考查。","介词to在这里引导动词不定式，用来表示目的，说明“多读书”的目的是“开阔视野”，这是小学阶段需要掌握的不定式的核心用法之一。","broaden one''s horizons是固定搭配，意为“开阔某人的视野”，其中horizon常用复数形式horizons，这是小学英语拓展学习中常见的固定短语，考查学生对常用搭配的积累。"]},"sentenceWithHints":"我 建议 你 多 读书 以 开阔 视野"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (154, '{"words":[{"chinese":"这","english":"this","examples":["This is my pen.","This book is interesting."],"phonetic":"/ðɪs/","partOfSpeech":"代词"},{"chinese":"个","english":"a","examples":["a cat","a nice day"],"phonetic":"/ə/","partOfSpeech":"冠词"},{"plural":"problems","chinese":"问题","english":"problem","examples":["I have a math problem.","We need to solve these problems."],"phonetic":"/ˈprɑːbləm/","partOfSpeech":"名词"},{"chinese":"对","english":"for","examples":["This gift is for you.","It''s easy for me."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"chinese":"我","english":"me","examples":["He gave me a book.","Please wait for me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"来","english":"","examples":[],"phonetic":"","partOfSpeech":"助词"},{"chinese":"说","english":"","examples":[],"phonetic":"","partOfSpeech":"助词"},{"chinese":"太","english":"too","examples":["It''s too hot today.","You are too kind."],"phonetic":"/tuː/","partOfSpeech":"副词"},{"chinese":"难","english":"difficult","examples":["English is difficult for me.","This task is difficult."],"phonetic":"/ˈdɪfɪkəlt/","partOfSpeech":"形容词"},{"chinese":"了","english":"","examples":[],"phonetic":"","partOfSpeech":"语气词"}],"examPoints":{"points":["介词for的用法","副词too修饰形容词的用法","人称代词宾格的使用"],"explanations":["介词for在这里用来引出对象，表示“对……来说”，用来说明事物针对的主体，本句中用来表明问题的难度是针对“我”而言的。","副词too用来修饰形容词，表示“太……”，用来加强形容词的程度，说明事物超出了正常的范围或承受度，本句中用来强调问题的难度超出了自己的能力范围。","人称代词me是I的宾格形式，在句子中作介词for的宾语，当人称代词在介词或动词后面作宾语时，需要使用宾格形式，不能使用主格I。"]},"sentenceWithHints":"这 个 问 题 对 我 来 说 太 难 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (156, '{"words":[{"plural":"","chinese":"环境","english":"environmental","examples":["Environmental protection is important.","We need to solve environmental problems."],"phonetic":"/ɪnˌvaɪrənˈmentl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"issues","chinese":"问题","english":"issue","examples":["We are discussing some social issues.","This is a serious issue."],"phonetic":"/ˈɪʃuː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"已经","english":"already","examples":["I have already finished my homework.","She has already left."],"phonetic":"/ɔːlˈredi/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"成为","english":"become","examples":["She has become a doctor.","The weather is becoming cold."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"全球","english":"global","examples":["Global warming is a big problem.","We need global cooperation."],"phonetic":"/ˈgloʊbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"concerns","chinese":"关注","english":"concern","examples":["Safety is our main concern.","The issue has caused public concern."],"phonetic":"/kənˈsɜːrn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["This is a photo of my family.","The top of the mountain is covered with snow."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"concerns","chinese":"焦点","english":"concern","examples":["The focus of the meeting is environmental issues.","This problem has become the focus of attention."],"phonetic":"/kənˈsɜːrn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","形容词作定语的用法","可数名词复数的用法"],"explanations":["现在完成时结构为have/has+动词过去分词，用来表示过去发生的动作对现在造成的影响或结果。本句中“已经成为”强调环境问题从过去到现在的状态变化，主语是复数“environmental issues”，所以用have加上become的过去分词become。","形容词可以用来修饰名词，放在名词前作定语。本句中“environmental（环境的）”修饰“issues（问题）”，“global（全球的）”修饰“concern（关注点）”，用来明确名词的属性和范围。","可数名词表示泛指一类事物时，常用复数形式。本句中“issues”是“issue”的复数形式，用来泛指各类环境问题；当可数名词单数表示泛指时，前面常加不定冠词a/an，“a global concern”中用a来表示“一个（被关注的焦点）”。"]},"sentenceWithHints":"环境 问题 已经 成为 全球 关注 的 焦点"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (157, '{"words":[{"plural":"","chinese":"许多","english":"many","examples":["Many students like reading.","There are many apples on the tree."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"people","chinese":"人","english":"people","examples":["People all over the world love peace.","Many people came to the party."],"phonetic":"/ˈpiːpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"认为","english":"believe","examples":["I believe you are right.","She believes that he will come soon."],"phonetic":"/bɪˈliːv/","pastTense":"believed","thirdPerson":"believes","partOfSpeech":"动词","pastParticiple":"believed","presentParticiple":"believing"},{"plural":"educations","chinese":"教育","english":"education","examples":["Education is very important for everyone.","She received a good education."],"phonetic":"/ˌedʒuˈkeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["This is my book.","He is a clever boy."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"改变","english":"change","examples":["We need to change our plan.","She changed her mind at last."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"plural":"destinies","chinese":"命运","english":"destiny","examples":["We should fight for our own destiny.","Some people believe in destiny."],"phonetic":"/ˈdestəni/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the key of the door","the color of the sky"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"keys","chinese":"关键","english":"key","examples":["Hard work is the key to success.","Do you have the key to the room?"],"phonetic":"/kiː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配 the key to doing sth.","宾语从句的省略用法","形容词many的用法"],"explanations":["the key to doing sth.是固定搭配，意为“做某事的关键”，这里的to是介词，后面要接动词的ing形式，不能接动词原形，本句中to changing destiny就符合这个结构。","在主句谓语动词是believe、think等表示“认为、相信”的动词时，后面的宾语从句如果是that引导的，that可以省略，本句中believe后面省略了that，完整形式是Many people believe that education is the key to changing destiny。","many作为形容词，用来修饰可数名词复数，通常用于肯定句中，本句中many用来修饰可数名词复数people，符合其用法规则；修饰不可数名词时要用much。"]},"sentenceWithHints":"许多 人 认为 教育 是 改变 命运 的 关键"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (158, '{"words":[{"chinese":"我们","english":"we","examples":["We are students.","We love our country."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"应该","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"采取","english":"take","examples":["Take a seat, please.","We need to take action."],"phonetic":"/teɪk/","pastTense":"took","thirdPerson":"takes","partOfSpeech":"动词","pastParticiple":"taken","presentParticiple":"taking"},{"plural":"measures","chinese":"措施","english":"measure","examples":["We need to take measures to solve the problem.","The government has taken new measures."],"phonetic":"/ˈmeʒər/","partOfSpeech":"名词"},{"chinese":"来","english":"to","examples":["I want to go home.","We need to work hard."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"保护","english":"protect","examples":["We should protect the environment.","The law protects animals."],"phonetic":"/prəˈtekt/","pastTense":"protected","thirdPerson":"protects","partOfSpeech":"动词","pastParticiple":"protected","presentParticiple":"protecting"},{"chinese":"濒危","english":"endangered","examples":["Pandas are endangered animals.","We need to save endangered species."],"phonetic":"/ɪnˈdeɪndʒərd/","partOfSpeech":"形容词"},{"plural":"species","chinese":"物种","english":"species","examples":["There are many species of birds.","Endangered species need our help."],"phonetic":"/ˈspiːʃiːz/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词should的用法","动词不定式作目的状语","固定搭配take measures","单复数同形的名词"],"explanations":["情态动词should后接动词原形，用来表达建议、义务，本句中用来提出“采取措施保护物种”的建议，所以take用原形。","动词不定式to protect在句中作目的状语，说明“采取措施”的目的是“保护濒危物种”，不定式作目的状语是初中阶段的重要语法点。","take measures是固定搭配，意为“采取措施”，measure在这里是可数名词，通常使用复数形式measures。","species是单复数同形的名词，它的单数和复数形式一致，这类不规则的名词复数变化是初中词汇考查的内容之一。"]},"sentenceWithHints":"我们 应该 采取 措施 来 保护 濒危 物种"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (159, '{"words":[{"plural":"","chinese":"随着","english":"with","examples":["With the help of my teacher, I passed the exam.","With time going by, we grow up."],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"technologies","chinese":"科技","english":"technology","examples":["Modern technology changes our life a lot.","We need to develop new technology."],"phonetic":"/tekˈnɑːlədʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the door of the room","a cup of tea"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"developments","chinese":"发展","english":"development","examples":["The development of the city is fast.","We welcome new developments in this field."],"phonetic":"/dɪˈveləpmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我们","english":"our","examples":["Our classroom is clean.","We love our country."],"phonetic":"/ˈaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"lives","chinese":"生活","english":"life","examples":["We have a happy life.","People''s lives are getting better."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"变得","english":"become","examples":["The weather becomes cold in winter.","She has become a doctor."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"越来越","english":"more and more","examples":["The city is becoming more and more beautiful.","He runs more and more fast."],"phonetic":"/mɔːr ənd mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"方便","english":"convenient","examples":["It is convenient to take the subway.","This app makes our life convenient."],"phonetic":"/kənˈviːniənt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["介词短语作状语","现在进行时表逐渐变化","形容词比较级的特殊表达","可数名词复数变形"],"explanations":["使用“With + 名词短语”的介词结构作伴随状语，用来引出背景情况，本句中“With the development of technology”用来引出“生活变方便”的前提背景，这是初中阶段常见的状语表达结构。","现在进行时“are becoming”在这里用来表示一种逐渐发生的变化，强调生活是随着科技发展慢慢变得方便的，而非突然变化，符合现在进行时表渐变的用法。","“more and more + 形容词”是初中阶段形容词比较级的特殊表达，用来表示“越来越……”，多用来描述事物逐渐变化的状态，本句中“more convenient”配合“more and more”的结构体现生活便利程度逐步提升。","名词“life”表示“生活”时，复数形式为不规则变形“lives”，属于初中阶段需要掌握的不规则名词复数，要注意和表示“生命”时的复数形式一致，避免和规则复数混淆。"]},"sentenceWithHints":"随着 科技 的 发展， 我们 的 生活 变得 越来越 方便"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (160, '{"words":[{"plural":"","chinese":"健康","english":"healthy","examples":["She has a healthy diet.","It''s important to keep healthy."],"phonetic":"/ˈhelθi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the roof of the house","a friend of mine"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"lifestyles","chinese":"生活方式","english":"lifestyle","examples":["I want to have a healthy lifestyle.","His lifestyle is very active."],"phonetic":"/ˈlaɪfstaɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"对","english":"for","examples":["Milk is good for your bones.","This book is for you."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我们","english":"our","examples":["Our classroom is clean.","We love our school."],"phonetic":"/ˈaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"bodies","chinese":"身体","english":"body","examples":["Exercise is good for your body.","The body needs enough sleep."],"phonetic":"/ˈbɑːdi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","This book is very interesting."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to learn English well.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词作定语","介词for的用法","系动词be的用法","可数名词的单复数"],"explanations":["形容词可以放在名词前修饰名词，起到限定和描述的作用。本句中形容词healthy放在名词lifestyle前，用来描述生活方式的属性，即“健康的生活方式”。","介词for在这里用来表示“对……而言”，引出对象，说明某事物针对特定对象的作用或意义，本句中表示健康生活方式对我们身体而言很重要。","本句主语a healthy lifestyle是单数可数名词，所以系动词用is，用来连接主语和表语important，说明主语的属性和状态。","可数名词body的复数形式是bodies，以辅音字母+y结尾的可数名词，变复数时要把y改为i再加-es；lifestyle是常规可数名词，变复数直接加-s。"]},"sentenceWithHints":"健康 的 生活方式 对 我们 的 身体 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (161, '{"words":[{"plural":"","chinese":"越","english":"more","examples":["The more you read, the more you know.","She wants more time to finish the work."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"来","english":"and","examples":["I like apples and bananas.","He is tall and strong."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"越","english":"more","examples":["The more you read, the more you know.","She wants more time to finish the work."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"多","english":"more","examples":["We need more water.","There are more trees in the park now."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["a cup of tea","the roof of the house"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"年轻","english":"young","examples":["He is a young man.","Young children like playing games."],"phonetic":"/jʌŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"people","chinese":"人","english":"people","examples":["Many people like traveling.","People here are very friendly."],"phonetic":"/ˈpiːpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"选择","english":"choose","examples":["I choose to stay at home.","She chooses a red dress."],"phonetic":"/tʃuːz/","pastTense":"chose","thirdPerson":"chooses","partOfSpeech":"动词","pastParticiple":"chosen","presentParticiple":"choosing"},{"plural":"","chinese":"出国","english":"abroad","examples":["He went abroad last year.","She wants to study abroad."],"phonetic":"/əˈbrɔːd/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"留学","english":"study","examples":["I study English every day.","She is studying in the library."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"}],"examPoints":{"points":["“越来越多”的英文表达","动词不定式作宾语","不规则动词的变形","副词abroad的用法"],"explanations":["“越来越多”对应的固定英文表达为“more and more”，用来修饰可数名词复数或不可数名词，本句中修饰可数名词复数“young people”，表示数量的逐渐增加。","动词“choose”后接动词不定式“to do”作宾语，构成“choose to do sth.”的结构，意为“选择做某事”，本句中“choose to study abroad”即表示“选择出国留学”。","本句中出现了不规则动词“choose”，它的过去式为“chose”，过去分词为“chosen”，第三人称单数为“chooses”，现在分词为“choosing”，需要牢记这些不规则变形，避免和规则动词混淆。","“abroad”是副词，意为“在国外；到国外”，通常放在动词后面作状语，本句中“study abroad”表示“在国外学习”，也就是“留学”的意思。"]},"sentenceWithHints":"越 来 越 多 的 年轻 人 选择 出国 留学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (162, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are good friends.","We will go to the park tomorrow."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"必须","english":"must","examples":["You must finish your homework first.","We must follow the rules."],"phonetic":"/mʌst/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"珍惜","english":"cherish","examples":["We should cherish every moment with our family.","She cherishes the gift from her grandma."],"phonetic":"/ˈtʃerɪʃ/","pastTense":"cherished","thirdPerson":"cherishes","partOfSpeech":"动词","pastParticiple":"cherished","presentParticiple":"cherishing"},{"plural":"times","chinese":"时间","english":"time","examples":["Time flies when you are having fun.","I don''t have much time to play."],"phonetic":"/taɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"因为","english":"because","examples":["I stayed at home because it rained.","She was late because she missed the bus."],"phonetic":"/bɪˈkɔːz/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"chinese":"就是","english":"is","examples":["This is my new pen.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"金钱","english":"money","examples":["Money can''t buy happiness.","I need to save money for my trip."],"phonetic":"/ˈmʌni/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词must的用法","连词because引导原因状语从句","不可数名词的用法","动词cherish的掌握"],"explanations":["情态动词must本身没有人称和数的变化，后面接动词原形，用来表示义务、必要性，翻译为“必须、应当”，在本句中用来表达“我们”有必要做“珍惜时间”这件事。","连词because用来引导原因状语从句，用来说明主句动作或情况发生的原因，本句中用because引出“我们必须珍惜时间”的原因是“时间就是金钱”，注意because不能和so在同一个句子中同时使用。","time（时间含义）和money都属于不可数名词，不可数名词没有复数形式，不能直接用a/an修饰，在表示数量时需要借助量词，比如a lot of time, a sum of money。","cherish是及物动词，后面可以直接接宾语，意为“珍惜、珍视”，属于初中阶段需要掌握的动词，需要掌握它的词形变化和用法，比如过去式cherished、第三人称单数cherishes等。"]},"sentenceWithHints":"我们 必须 珍惜 时间， 因为 时间 就是 金钱"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (163, '{"words":[{"plural":"readings","chinese":"阅读","english":"reading","examples":["Reading is a good habit.","I enjoy reading novels."],"phonetic":"/ˈriːdɪŋ/","partOfSpeech":"名词"},{"chinese":"可以","english":"can","examples":["You can go now.","I can speak English."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"帮助","english":"help","examples":["She helps me with my homework.","We should help others."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some water."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"扩大","english":"expand","examples":["We need to expand our business.","Reading can expand your mind."],"phonetic":"/ɪkˈspænd/","pastTense":"expanded","thirdPerson":"expands","partOfSpeech":"动词","pastParticiple":"expanded","presentParticiple":"expanding"},{"plural":"","chinese":"知识面","english":"knowledge","examples":["He has a lot of knowledge.","We should increase our knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","情态动词can的用法","help的固定搭配","不可数名词的用法"],"explanations":["动词作主语时需要变为动名词形式，即动词后加-ing，本句中\"阅读\"作为主语，所以使用reading。","情态动词can表示\"能够、可以\"，后接动词原形，没有人称和数的变化，过去式为could，用于表达过去的能力或委婉请求。","help的常见搭配为help sb. (to) do sth.，其中to可以省略，本句中help us expand our knowledge就是使用了这个搭配，表示\"帮助我们扩大知识面\"。","knowledge是不可数名词，没有复数形式，不能直接加-s，表达\"大量知识\"时可以用a lot of knowledge、much knowledge等。"]},"sentenceWithHints":"阅读 可以 帮助 我们 扩大 知识面"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (164, '{"words":[{"plural":"","chinese":"互联网","english":"Internet","examples":["The Internet is very useful.","We can search for things on the Internet."],"phonetic":"/ˈɪntərnet/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"改变","english":"change","examples":["She changed her mind.","The weather changes quickly."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"plural":"","chinese":"了","english":"","examples":["我吃了饭。","他完成了作业。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"获取","english":"get","examples":["I get up early every day.","She got a gift yesterday."],"phonetic":"/ɡet/","pastTense":"got","thirdPerson":"gets","partOfSpeech":"动词","pastParticiple":"got/gotten","presentParticiple":"getting"},{"plural":"","chinese":"信息","english":"information","examples":["We need more information.","You can find information online."],"phonetic":"/ˌɪnfərˈmeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["红色的苹果。","我喜欢的书。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"ways","chinese":"方式","english":"way","examples":["This is a good way.","There are many ways to solve the problem."],"phonetic":"/weɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","定语从句的省略用法","不可数名词的用法"],"explanations":["现在完成时结构为have/has+动词过去分词，强调过去发生的动作对现在造成的影响。本句中“改变了”体现互联网的改变对当下的影响，主语The Internet是第三人称单数，所以用has changed。","当先行词是way，且在定语从句中作方式状语时，定语从句的引导词that/in which可以省略，本句中“we get information”就是省略引导词的定语从句，用来修饰the way。","information是不可数名词，没有复数形式，不能在后面加-s，表达“一条信息”可以用a piece of information，本句中直接用information表示泛指的信息。"]},"sentenceWithHints":"互联网 改变 了 我们 获取 信息 的 方式"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (165, '{"words":[{"plural":"teams","chinese":"团队","english":"team","examples":["Our team won the game.","She is the leader of the team."],"phonetic":"/tiːm/","partOfSpeech":"名词"},{"chinese":"合作","english":"work","examples":["We need to work together.","She works hard every day."],"phonetic":"/wɜːrk/","pastTense":"worked","thirdPerson":"works","partOfSpeech":"动词","pastParticiple":"worked","presentParticiple":"working"},{"chinese":"在","english":"in","examples":["The book is in the bag.","She lives in Beijing."],"phonetic":"/ɪn/","partOfSpeech":"介词"},{"chinese":"现代","english":"modern","examples":["Modern technology changes our life.","This is a modern building."],"phonetic":"/ˈmɑːdərn/","partOfSpeech":"形容词"},{"plural":"works","chinese":"工作","english":"work","examples":["My work is interesting.","He has a lot of work to do."],"phonetic":"/wɜːrk/","partOfSpeech":"名词"},{"chinese":"中","english":"in","examples":["I am in the classroom.","The meeting is in the afternoon."],"phonetic":"/ɪn/","partOfSpeech":"介词"},{"chinese":"非常","english":"very","examples":["She is very happy.","The food is very delicious."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"重要","english":"important","examples":["It is important to study hard.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"}],"examPoints":{"points":["名词短语的翻译与使用","介词短语作状语","副词修饰形容词的用法"],"explanations":["中文的“团队合作”对应英文固定名词短语“Teamwork”，属于不可数名词，在句中作主语时，谓语动词用单数形式。","介词短语“in modern work”在句中作地点状语，说明“团队合作重要”的范围，介词in用于表示在某个领域、场景内。","副词“very”用来修饰形容词“important”，表示程度，这是副词修饰形容词的常见用法，通常放在被修饰的形容词之前。"]},"sentenceWithHints":"团队 合作 在 现代 工作 中 非常 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (166, '{"words":[{"chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"应该","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"学会","english":"learn","examples":["I learn English every day.","She has learned to play the piano."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"chinese":"如何","english":"how","examples":["How do you go to school?","I don''t know how to do it."],"phonetic":"/haʊ/","partOfSpeech":"副词"},{"chinese":"管理","english":"manage","examples":["He can manage his work well.","She is managing a small shop."],"phonetic":"/ˈmænɪdʒ/","pastTense":"managed","thirdPerson":"manages","partOfSpeech":"动词","pastParticiple":"managed","presentParticiple":"managing"},{"chinese":"自己的","english":"our","examples":["Our classroom is clean.","This is our new house."],"phonetic":"/ˈaʊər/","partOfSpeech":"代词"},{"plural":"times","chinese":"时间","english":"time","examples":["We don''t have much time.","I have been there several times."],"phonetic":"/taɪm/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词should的用法","疑问词+不定式结构","动词learn的用法"],"explanations":["should作为情态动词，后接动词原形，用来表示建议、义务等含义，本句中用来表达“应该学会”的建议语气。","“how to manage”属于“疑问词+不定式”结构，在句中可以充当宾语，此处作learn的宾语，用来表达“如何管理”的具体内容，这是初中阶段需要掌握的非谓语动词用法之一。","learn作为及物动词，除了可以直接接名词作宾语，还可以接“疑问词+不定式”结构作宾语，用来表达学习做某事的具体方式，本句中learn how to manage our time就体现了这一用法。"]},"sentenceWithHints":"我们 应该 学会 如何 管理 自己的 时间"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (167, '{"words":[{"plural":"exercises","chinese":"运动","english":"exercise","examples":["Daily exercise is good for health.","We do morning exercises every day."],"phonetic":"/ˈeksərsaɪz/","partOfSpeech":"名词"},{"plural":"","chinese":"不仅","english":"not only","examples":["She not only sings well but also dances beautifully.","He not only studies hard but also helps others."],"phonetic":"/nɑːt ˈoʊnli/","partOfSpeech":"连词"},{"plural":"","chinese":"对","english":"for","examples":["This gift is for you.","Fruits are good for your health."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"plural":"","chinese":"身体","english":"physical","examples":["We need to keep physical fitness.","Physical activity can boost your mood."],"phonetic":"/ˈfɪzɪkəl/","partOfSpeech":"形容词"},{"plural":"","chinese":"健康","english":"health","examples":["Health is the most important thing.","Good sleep is good for your health."],"phonetic":"/helθ/","partOfSpeech":"名词"},{"chinese":"有益","english":"benefit","examples":["Reading benefits our mind.","The new policy will benefit many people."],"phonetic":"/ˈbenɪfɪt/","pastTense":"benefited","thirdPerson":"benefits","partOfSpeech":"动词","pastParticiple":"benefited","presentParticiple":"benefiting"},{"plural":"","chinese":"还","english":"but also","examples":["He is not only tall but also strong.","This book is not only interesting but also educational."],"phonetic":"/bʌt ˈoʊlsoʊ/","partOfSpeech":"连词"},{"chinese":"能","english":"can","examples":["I can swim.","She can speak English fluently."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"缓解","english":"relieve","examples":["Listening to music can relieve stress.","The medicine relieved my pain."],"phonetic":"/rɪˈliːv/","pastTense":"relieved","thirdPerson":"relieves","partOfSpeech":"动词","pastParticiple":"relieved","presentParticiple":"relieving"},{"plural":"stresses","chinese":"压力","english":"stress","examples":["Too much stress is bad for you.","He is under great stress at work."],"phonetic":"/stres/","partOfSpeech":"名词"}],"examPoints":{"points":["not only...but also...并列结构的用法","动词第三人称单数形式","抽象名词的使用"],"explanations":["not only...but also...是并列连词，用于连接两个并列的成分，本句中连接两个谓语动词短语benefits physical health和relieves stress，连接并列谓语时，要注意两个动词的形式保持一致，本句主语是不可数名词exercise，所以两个动词都用第三人称单数形式。","当主语是第三人称单数（包括不可数名词、单数可数名词、第三人称单数代词等）时，一般现在时的谓语动词要使用第三人称单数形式，规则变化通常是在动词后加-s或-es，本句中benefit和relieve的第三人称单数形式分别为benefits和relieves。","health和stress都属于抽象名词，这类名词通常表示抽象概念，一般为不可数名词，在句子中不需要变复数，也不能直接用不定冠词a/an修饰，本句中physical health和stress都是作为不可数名词使用。"]},"sentenceWithHints":"运动 不仅 对 身体 健康 有益， 还 能 缓解 压力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (168, '{"words":[{"plural":"","chinese":"每","english":"every","examples":["Every student has a book.","I go there every day."],"phonetic":"/ˈevri/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"个","english":"","examples":["一个苹果","三个杯子"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"people","chinese":"人","english":"person","examples":["She is a kind person.","There are five people in the room."],"phonetic":"/ˈpɜːrsn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"all","examples":["We all like music.","They are all here."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"要","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my mom.","She is responsible for the project."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"自","english":"","examples":["自己","自然"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"己","english":"","examples":["自己","知己"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"one''s","examples":["Do your homework on time.","He forgot his umbrella."],"phonetic":"/wʌnz/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"行","english":"","examples":["行为","行动"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"actions","chinese":"为","english":"action","examples":["His actions made everyone angry.","We need to take action now."],"phonetic":"/ˈækʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"负","english":"","examples":["负责","负担"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"责","english":"responsible","examples":["She is responsible for the team.","We should be responsible for our mistakes."],"phonetic":"/rɪˈspɑːnsəbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配be responsible for的用法","不定代词everyone的指代用法","情态动词should的用法"],"explanations":["be responsible for是初中阶段重点固定搭配，意为“为……负责”，后可接名词、代词或动名词，本句中接名词短语their own actions，表示为自己的行为承担责任。","everyone是不定代词，意为“每个人”，在语法上视为第三人称单数，但在指代时，为了避免性别指代的单一性，常用复数形式的物主代词their来对应，这是初中阶段需要掌握的不定代词指代规则。","should是情态动词，后接动词原形，用来表示义务、责任或建议，本句中用should来强调每个人“应该”承担责任的义务，符合情态动词表责任的用法规则。"]},"sentenceWithHints":"每 个 人 都 要 为 自 己 的 行 为 负 责"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (169, '{"words":[{"chinese":"保持","english":"keep","examples":["Keep quiet in the library.","She keeps a diary every day."],"phonetic":"/kiːp/","pastTense":"kept","thirdPerson":"keeps","partOfSpeech":"动词","pastParticiple":"kept","presentParticiple":"keeping"},{"chinese":"积极","english":"positive","examples":["We should have a positive attitude.","She gave me some positive advice."],"phonetic":"/ˈpɑːzətɪv/","partOfSpeech":"形容词"},{"chinese":"的","english":"of","examples":["the roof of the house","a cup of tea"],"phonetic":"/əv/","partOfSpeech":"助词"},{"plural":"attitudes","chinese":"心态","english":"attitude","examples":["His attitude towards work is very serious.","She has a positive attitude towards life."],"phonetic":"/ˈætɪtuːd/","partOfSpeech":"名词"},{"chinese":"有助于","english":"help","examples":["Reading helps improve your vocabulary.","This book helps you learn English."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"克服","english":"overcome","examples":["We can overcome all the difficulties.","She overcame her fear of speaking in public."],"phonetic":"/ˌoʊvərˈkʌm/","pastTense":"overcame","thirdPerson":"overcomes","partOfSpeech":"动词","pastParticiple":"overcome","presentParticiple":"overcoming"},{"plural":"difficulties","chinese":"困难","english":"difficulty","examples":["We faced many difficulties.","He overcame the difficulty with his hard work."],"phonetic":"/ˈdɪfɪkəlti/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","help的用法","可数名词复数形式"],"explanations":["动词原形不能直接作主语，需要将其变为动名词形式（动词+ing），本句中\"保持\"变为Keeping作句子主语，谓语动词用第三人称单数形式helps。","help作为动词时，常见用法为help (to) do sth.，其中to可以省略，本句中helps overcome difficulties就使用了这个结构，表示\"有助于做某事\"。","可数名词表示泛指的一类事物时，通常使用复数形式。本句中\"困难\"是泛指各类困难，所以使用difficulty的复数形式difficulties。"]},"sentenceWithHints":"保持 积极 的 心态 有助于 克服 困难"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (170, '{"words":[{"chinese":"文化","english":"cultural","examples":["Cultural differences are interesting.","We have a cultural festival every year."],"phonetic":"/ˈkʌltʃərəl/","partOfSpeech":"形容词"},{"plural":"exchanges","chinese":"交流","english":"exchange","examples":["We had an exchange of ideas.","Cultural exchange helps build friendships."],"phonetic":"/ɪksˈtʃeɪndʒ/","partOfSpeech":"名词"},{"chinese":"可以","english":"can","examples":["I can swim.","She can speak English well."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"促进","english":"promote","examples":["Exercise can promote good health.","The event is meant to promote cultural understanding."],"phonetic":"/prəˈmoʊt/","pastTense":"promoted","thirdPerson":"promotes","partOfSpeech":"动词","pastParticiple":"promoted","presentParticiple":"promoting"},{"chinese":"不同","english":"different","examples":["We come from different countries.","She has different hobbies."],"phonetic":"/ˈdɪfrənt/","partOfSpeech":"形容词"},{"plural":"countries","chinese":"国家","english":"country","examples":["There are many countries in the world.","He has visited several European countries."],"phonetic":"/ˈkʌntri/","partOfSpeech":"名词"},{"chinese":"之间","english":"between","examples":["She sits between Tom and Mary.","There is a river between the two cities."],"phonetic":"/bɪˈtwiːn/","partOfSpeech":"介词"},{"chinese":"的","english":"","examples":["The book of mine is new.","This is the house of my grandparents."],"phonetic":"","partOfSpeech":"助词"},{"plural":"understandings","chinese":"理解","english":"understanding","examples":["We need to have a better understanding of each other.","Their understanding of the problem is wrong."],"phonetic":"/ˌʌndərˈstændɪŋ/","partOfSpeech":"名词"}],"examPoints":{"points":["形容词作定语","情态动词can的用法","介词between的用法","可数名词复数变形"],"explanations":["形容词可以放在名词前作定语修饰名词，本句中cultural（文化的）修饰exchange（交流），构成固定搭配cultural exchange（文化交流），用来明确交流的类型。","情态动词can表示“能够、可以”，后面要接动词原形，本句中can后接promote（促进）的原形，用来表达文化交流具备促进理解的能力。","介词between用于表示“在两者或多者之间”，通常连接明确的多个对象，本句中between different countries用来限定理解发生的范围是在不同国家之间。","以辅音字母+y结尾的可数名词，变复数时要把y改为i再加-es，country的复数形式是countries，这类不规则的复数变形是初中阶段需要掌握的重点内容。"]},"sentenceWithHints":"文化 交流 可以 促进 不同 国家 之间 的 理解"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (171, '{"words":[{"plural":"","chinese":"经济","english":"economic","examples":["The country is facing economic problems.","We need to make some economic changes."],"phonetic":"/ˌiːkəˈnɑːmɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"globalizations","chinese":"全球化","english":"globalization","examples":["Globalization has connected the world closely.","We are talking about the impact of globalization."],"phonetic":"/ˌɡloʊbələˈzeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"带来了","english":"bring","examples":["She brings a gift every time she comes.","The new policy will bring many changes."],"phonetic":"/brɪŋ/","pastTense":"brought","thirdPerson":"brings","partOfSpeech":"动词","pastParticiple":"brought","presentParticiple":"bringing"},{"plural":"opportunities","chinese":"机遇","english":"opportunity","examples":["This is a great opportunity for you.","We should seize every opportunity."],"phonetic":"/ˌɑːpərˈtuːnəti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She sings and dances well."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"challenges","chinese":"挑战","english":"challenge","examples":["He faced many challenges in his life.","This is a big challenge for us."],"phonetic":"/ˈtʃælɪndʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词作定语","动词第三人称单数形式","可数名词复数形式","并列连词的使用"],"explanations":["形容词可以放在名词前作定语，用来修饰名词。本句中形容词economic修饰名词globalization，构成固定表达economic globalization，说明全球化的属性是经济领域的。","当句子主语是第三人称单数（本句中主语economic globalization是单数概念），一般现在时的谓语动词需要使用第三人称单数形式，bring的第三人称单数形式是brings。","可数名词表示泛指的多个对象时需要使用复数形式。opportunity的复数是变y为i加es，即opportunities；challenge的复数是直接加s，即challenges。","并列连词and用来连接词性、结构相同的并列成分，本句中and连接opportunities和challenges，二者都是可数名词复数，在句中作宾语；同时参考翻译中使用both...and...结构，用来强调两个事物同时存在，更贴合原句中机遇和挑战并存的含义。"]},"sentenceWithHints":"经济 全球化 带来了 机遇 和 挑战"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (172, '{"words":[{"plural":"","chinese":"人工","english":"artificial","examples":["This is an artificial flower.","Artificial intelligence is developing fast."],"phonetic":"/ˌɑːrtɪˈfɪʃl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"intelligences","chinese":"智能","english":"intelligence","examples":["She has a high level of intelligence.","Artificial intelligence is a hot topic."],"phonetic":"/ɪnˈtelɪdʒəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"正在","english":"be + present participle","examples":["He is reading a book.","They are playing football."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"改变","english":"change","examples":["She wants to change her job.","The weather changes quickly in spring."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"plural":"","chinese":"我们","english":"our","examples":["Our house is big.","This is our classroom."],"phonetic":"/ˈaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of/''s","examples":["This is the cover of the book.","Tom''s cat is cute."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"works","chinese":"工作","english":"work","examples":["I work in a factory.","This is a work of art."],"phonetic":"/wɜːrk/","pastTense":"worked","thirdPerson":"works","partOfSpeech":"动词/名词","pastParticiple":"worked","presentParticiple":"working"},{"plural":"ways","chinese":"方式","english":"way","examples":["This is a good way to learn English.","There are many ways to solve the problem."],"phonetic":"/weɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的用法","名词所有格/所属关系的表达","固定搭配“way of doing sth”"],"explanations":["现在进行时的结构为“am/is/are + 现在分词”，用来表示当前正在进行的动作。本句中“正在改变”对应现在进行时，主语“Artificial intelligence”是单数第三人称，所以用“is changing”。","英语中表达所属关系可以用“of”结构，本句中“我们的工作方式”译为“way of working”，用“of”来体现“工作”和“方式”的所属关联。","“way of doing sth”是固定搭配，用来表示“做某事的方式”，其中“of”后面接动词的现在分词形式，本句中“工作方式”用“way of working”符合这个固定搭配规则。"]},"sentenceWithHints":"人工 智能 正在 改变 我们 的 工作 方式"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (173, '{"words":[{"plural":"","chinese":"社交","english":"social","examples":["She has a busy social life.","Social media is very popular now."],"phonetic":"/ˈsoʊʃl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"media","chinese":"媒体","english":"media","examples":["The media plays an important role in society.","She works in the media industry."],"phonetic":"/ˈmiːdiə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"对","english":"on","examples":["The book has an impact on me.","He is hard on his students."],"phonetic":"/ɑːn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"年轻","english":"young","examples":["Young people like to use social media.","She is a young artist."],"phonetic":"/jʌŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"people","chinese":"人","english":"people","examples":["Many people enjoy traveling.","Young people are full of energy."],"phonetic":"/ˈpiːpl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"产生","english":"have","examples":["The event had a great impact on her.","She has had many interesting experiences."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"了","english":"","examples":["He has finished his homework.","I have eaten dinner already."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"深远","english":"profound","examples":["The book had a profound influence on him.","She has a profound understanding of art."],"phonetic":"/prəˈfaʊnd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is a book of my father''s.","The color of the sky is blue."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"impacts","chinese":"影响","english":"impact","examples":["The storm had a huge impact on the town.","Technology has a great impact on our lives."],"phonetic":"/ˈɪmpækt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","固定搭配 have an impact on 的使用","集体名词的主谓一致"],"explanations":["现在完成时结构为have/has+过去分词，用来表示过去发生的动作对现在造成的影响或结果。本句中“产生了深远的影响”强调这个影响持续到现在，所以使用现在完成时has had，主语Social media是单数概念，助动词用has。","have an impact on是固定搭配，意为“对……产生影响”，其中impact为名词，在具体语境中可以搭配形容词来修饰impact，体现影响的程度，如本句中的profound impact。","Social media是集体名词，在表达整体概念时视为单数，所以谓语动词要用第三人称单数形式，本句中助动词使用has而不是have。"]},"sentenceWithHints":"社交 媒体 对 年轻 人 产生 了 深远 的 影响"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (174, '{"words":[{"plural":"","chinese":"可持续","english":"sustainable","examples":["We need to find sustainable ways to use energy.","Sustainable farming helps protect the land."],"phonetic":"/səˈsteɪnəbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"developments","chinese":"发展","english":"development","examples":["The city''s development has brought many new jobs.","We support the development of small businesses."],"phonetic":"/dɪˈveləpmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["This is my favorite book.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"解决","english":"solve","examples":["She tried to solve the math problem.","We need to solve this issue quickly."],"phonetic":"/sɑːlv/","pastTense":"solved","thirdPerson":"solves","partOfSpeech":"动词","pastParticiple":"solved","presentParticiple":"solving"},{"plural":"","chinese":"环境","english":"environmental","examples":["We should care about environmental protection.","Environmental pollution is a serious problem."],"phonetic":"/ɪnˌvaɪrənˈmentl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"problems","chinese":"问题","english":"problem","examples":["Can you help me with this problem?","We are facing many problems right now."],"phonetic":"/ˈprɑːbləm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["This is the cover of the book.","The top of the mountain is covered with snow."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"keys","chinese":"关键","english":"key","examples":["Hard work is the key to success.","Do you have the key to the door?"],"phonetic":"/kiː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配 the key to doing sth.","形容词作定语","可数名词复数"],"explanations":["the key to doing sth. 是固定搭配，意为“做某事的关键”，这里的 to 是介词，后面要接动词的动名词形式（即动词-ing形式），所以翻译中用 solving 而不是 solve。","形容词可以放在名词前作定语，用来修饰名词，本句中“可持续”对应的 sustainable 修饰“发展”development，“环境”对应的 environmental 修饰“问题”problems，用来明确名词的属性。","可数名词表示泛指的一类事物时，通常用复数形式。本句中“环境问题”指的是各类相关问题，所以用 environmental problems 而不是单数形式。"]},"sentenceWithHints":"可持续 发展 是 解决 环境 问题 的 关键"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (175, '{"words":[{"chinese":"教育","english":"educational","examples":["Educational resources are very important.","We need more educational programs."],"phonetic":"/ˌedʒuˈkeɪʃənl/","partOfSpeech":"形容词"},{"plural":"reforms","chinese":"改革","english":"reform","examples":["The government will carry out a new reform.","Educational reforms are necessary."],"phonetic":"/rɪˈfɔːrm/","partOfSpeech":"名词"},{"chinese":"需要","english":"need","examples":["I need to finish my homework.","She needs your help."],"phonetic":"/niːd/","pastTense":"needed","thirdPerson":"needs","partOfSpeech":"动词","pastParticiple":"needed","presentParticiple":"needing"},{"chinese":"考虑","english":"consider","examples":["You should consider his advice.","We are considering a new plan."],"phonetic":"/kənˈsɪdər/","pastTense":"considered","thirdPerson":"considers","partOfSpeech":"动词","pastParticiple":"considered","presentParticiple":"considering"},{"plural":"students","chinese":"学生","english":"student","examples":["The student is hard-working.","Students should obey school rules."],"phonetic":"/ˈstuːdnt/","partOfSpeech":"名词"},{"chinese":"的","english":"''s","examples":["This is Tom''s book.","The children''s toys are on the floor."],"phonetic":"/z/","partOfSpeech":"助词"},{"chinese":"实际","english":"actual","examples":["What is the actual situation?","The actual cost is higher than expected."],"phonetic":"/ˈæktʃuəl/","partOfSpeech":"形容词"},{"plural":"needs","chinese":"需求","english":"need","examples":["We should meet people''s basic needs.","The company is trying to satisfy customers'' needs."],"phonetic":"/niːd/","partOfSpeech":"名词"}],"examPoints":{"points":["名词所有格的用法","need作实义动词的用法","形容词作定语的用法"],"explanations":["以s结尾的复数名词的所有格直接在词尾加''，本句中students是复数名词，所以所有格形式为students''，用来表示“学生的”，修饰后面的名词needs。","need作为实义动词时，常见用法为need to do sth.，表示“需要做某事”，主语通常是人或有生命的事物，本句中主语Educational reform是单数，所以need用第三人称单数形式needs，搭配to consider构成谓语部分。","形容词可以放在名词前作定语，用来修饰名词，说明名词的特征。本句中educational修饰reform，actual修饰needs，分别说明改革的属性和需求的特点。"]},"sentenceWithHints":"教育 改革 需要 考虑 学生 的 实际 需求"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (176, '{"words":[{"plural":"urbanizations","chinese":"城市化","english":"urbanization","examples":["Urbanization is a global trend.","Rapid urbanization causes many challenges."],"phonetic":"/ˌɜːrbənəˈzeɪʃn/","partOfSpeech":"名词"},{"plural":"processes","chinese":"进程","english":"process","examples":["The process takes time.","We are in the process of moving."],"phonetic":"/ˈprɑːses/","partOfSpeech":"名词"},{"chinese":"给","english":"to","examples":["Give the book to me.","I sent a letter to my friend."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"plural":"societies","chinese":"社会","english":"society","examples":["Society needs more volunteers.","Different societies have different cultures."],"phonetic":"/səˈsaɪəti/","partOfSpeech":"名词"},{"chinese":"带来","english":"bring","examples":["Bring me a glass of water.","Technology brings many changes."],"phonetic":"/brɪŋ/","pastTense":"brought","thirdPerson":"brings","partOfSpeech":"动词","pastParticiple":"brought","presentParticiple":"bringing"},{"chinese":"了","english":"","examples":["I ate an apple.","She finished her homework."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"许多","english":"many","examples":["Many people like coffee.","There are many books on the shelf."],"phonetic":"/ˈmeni/","partOfSpeech":"形容词"},{"plural":"problems","chinese":"问题","english":"problem","examples":["We need to solve this problem.","He has many health problems."],"phonetic":"/ˈprɑːbləm/","partOfSpeech":"名词"}],"examPoints":{"points":["现在完成时的用法","固定搭配 bring sth. to sb./sth.","可数名词的复数形式"],"explanations":["现在完成时结构为“have/has + 过去分词”，强调动作对现在造成的影响。本句中城市化进程带来的问题是对当前社会的影响，主语 urbanization 是第三人称单数，所以用 has brought。","bring 的常见搭配为 bring sth. to sb./sth.，表示“给某人/某物带来某物”，本句中“给社会带来了许多问题”对应 bring many problems to society。","many 后接可数名词复数形式，problem 是可数名词，所以用复数形式 problems；process 和 society 作为可数名词，复数形式分别为 processes 和 societies，符合可数名词变复数的规则。"]},"sentenceWithHints":"城市化 进程 给 社会 带来 了 许多 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (177, '{"words":[{"plural":"technologies","chinese":"科技","english":"technology","examples":["Technology is changing our life.","We need to develop new technology."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Innovation is key to success.","The company has many new innovations."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","This is my book."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"nations","chinese":"国家","english":"nation","examples":["The nation is celebrating its anniversary.","Many nations took part in the meeting."],"phonetic":"/ˈneɪʃn/","partOfSpeech":"名词"},{"plural":"developments","chinese":"发展","english":"development","examples":["The city has seen rapid development.","We are excited about the new developments."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["the roof of the house","a friend of mine"],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"","chinese":"重要","english":"important","examples":["It is important to study hard.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"},{"plural":"driving forces","chinese":"动力","english":"driving force","examples":["Hard work is the driving force of success.","Wind is a natural driving force."],"phonetic":"/ˈdraɪvɪŋ fɔːrs/","partOfSpeech":"名词"}],"examPoints":{"points":["名词短语的翻译与使用","系动词be的主谓一致","不定冠词的用法","介词for表用途的用法"],"explanations":["中文的偏正短语“科技创新”“国家发展”“重要动力”对应英文的名词短语“Technological innovation”“national development”“important driving force”，这类短语在英语中常用来表达抽象概念，是初中阶段需要掌握的核心短语翻译技巧。","本句主语“Technological innovation”是单数可数名词短语，所以系动词用第三人称单数形式is，这是主谓一致的基础规则，初中阶段需要熟练掌握主语为单数/复数时be动词的正确形式。","“important driving force”是可数名词短语单数形式，且important以元音音素开头，所以前面加不定冠词an，不定冠词a/an用于泛指单数可数名词，是初中冠词知识点的核心内容。","介词for在这里用来引出对象或用途，表达“对……而言”，本句中“for national development”表示“对国家发展而言”，是初中阶段需要掌握的介词for的常用用法之一。"]},"sentenceWithHints":"科技 创新 是 国家 发展 的 重要 动力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (178, '{"words":[{"plural":"cultures","chinese":"文化","english":"culture","examples":["Chinese culture is very rich.","We should respect different cultures."],"phonetic":"/ˈkʌltʃər/","partOfSpeech":"名词"},{"plural":"inheritances","chinese":"传承","english":"inheritance","examples":["Cultural inheritance is of great importance.","He received a large inheritance from his father."],"phonetic":"/ɪnˈherɪtəns/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires hard work.","This rule requires everyone to follow it."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"generations","chinese":"代际","english":"generation","examples":["Many generations have lived in this house.","There are differences between generations."],"phonetic":"/ˌdʒenəˈreɪʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"之间","english":"between","examples":["Sit between Tom and me.","There is a river between the two villages."],"phonetic":"/bɪˈtwiːn/","partOfSpeech":"介词"},{"plural":"","chinese":"的","english":"of","examples":["This is a photo of my family.","The color of the sky is blue."],"phonetic":"/əv/","partOfSpeech":"助词"},{"plural":"","chinese":"共同","english":"joint","examples":["We made a joint decision.","They are planning a joint project."],"phonetic":"/dʒɔɪnt/","partOfSpeech":"形容词"},{"plural":"efforts","chinese":"努力","english":"effort","examples":["He put a lot of effort into his study.","Our efforts finally paid off."],"phonetic":"/ˈefərt/","partOfSpeech":"名词"}],"examPoints":{"points":["名词的复数形式","介词between的用法","动词第三人称单数变化"],"explanations":["可数名词表示泛指或数量不止一个时需要使用复数形式，规则名词一般在词尾加-s，如generation变为generations，effort变为efforts。本句中“代际之间”指多个代际，“共同努力”是多方的努力，所以都要用复数形式。","介词between用于表示“在两者或多者之间”，通常连接明确的两个或多个对象，本句中用于连接不同的代际，体现代际间的范围。","当主语是第三人称单数（本句中主语“Cultural inheritance”是单数名词短语，属于第三人称单数）时，一般现在时的动词要使用第三人称单数形式，规则动词通常在词尾加-s，如require变为requires。"]},"sentenceWithHints":"文化 传承 需要 代际 之间 的 共同 努力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (179, '{"words":[{"plural":"climates","chinese":"气候","english":"climate","examples":["The climate here is warm and wet.","Climate change affects the whole world."],"phonetic":"/ˈklaɪmət/","partOfSpeech":"名词"},{"plural":"changes","chinese":"变化","english":"change","examples":["Great changes have taken place in the city.","Climate change is a global issue."],"phonetic":"/tʃeɪndʒ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","This is a difficult problem."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"人类","english":"humanity","examples":["We should protect the earth for humanity.","Humanity faces many challenges."],"phonetic":"/hjuːˈmænəti/","partOfSpeech":"名词"},{"chinese":"面临","english":"face","examples":["We face many difficulties.","He faced a tough choice."],"phonetic":"/feɪs/","pastTense":"faced","thirdPerson":"faces","partOfSpeech":"动词","pastParticiple":"faced","presentParticiple":"facing"},{"chinese":"的","english":"of","examples":["This is a photo of my family.","The color of the sky is blue."],"phonetic":"/əv/","partOfSpeech":"介词"},{"chinese":"重大","english":"major","examples":["This is a major decision.","He made a major mistake."],"phonetic":"/ˈmeɪdʒər/","partOfSpeech":"形容词"},{"plural":"challenges","chinese":"挑战","english":"challenge","examples":["It''s a big challenge for us.","We need to meet the challenge."],"phonetic":"/ˈtʃælɪndʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["固定短语搭配","现在分词作后置定语","系动词的用法"],"explanations":["“气候变化”对应的固定英文表达为“Climate change”，属于常见的环境类固定短语，需要牢记这类专有名词短语的英文表述。","参考翻译中“facing humanity”是现在分词短语作后置定语，用来修饰“challenge”，表示“人类面临的挑战”，现在分词作定语时，与被修饰的名词是主动关系，这里challenge和face是主动的逻辑关系，符合现在分词作定语的用法。","本句主语“Climate change”是单数概念的名词短语，所以系动词使用第三人称单数形式“is”，这是系动词be根据主语单复数变化的基本用法，初中阶段需要掌握be动词（am/is/are）的正确使用场景。"]},"sentenceWithHints":"气候 变化 是 人类 面临 的 重大 挑战"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (180, '{"words":[{"plural":"","chinese":"终身","english":"lifelong","examples":["Lifelong learning is important for everyone.","She has a lifelong passion for painting."],"phonetic":"/ˈlaɪflɔːŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"learning","examples":["Learning new skills can be fun.","Online learning is very popular now."],"phonetic":"/ˈlɜːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is happy.","This is my new book."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"适应","english":"adapt","examples":["We need to adapt to the new environment.","She adapted quickly to the change."],"phonetic":"/əˈdæpt/","pastTense":"adapted","thirdPerson":"adapts","partOfSpeech":"动词","pastParticiple":"adapted","presentParticiple":"adapting"},{"plural":"","chinese":"现代","english":"modern","examples":["Modern technology changes our life.","We live in a modern city."],"phonetic":"/ˈmɑːdərn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"社会","english":"social","examples":["We should pay attention to social issues.","Social media is very popular among teenagers."],"phonetic":"/ˈsoʊʃl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"developments","chinese":"发展","english":"development","examples":["The development of science is fast.","We are happy to see the new developments in the town."],"phonetic":"/dɪˈveləpmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["This is a photo of my family.","The color of the flower is red."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"必要","english":"necessary","examples":["It is necessary to drink enough water every day.","We need to take necessary actions."],"phonetic":"/ˈnesəseri/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"conditions","chinese":"条件","english":"condition","examples":["Good health is an important condition for success.","We need to meet certain conditions to get the prize."],"phonetic":"/kənˈdɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不定式作后置定语","系动词be的用法","形容词作定语的用法"],"explanations":["本句中\"to adapt to modern social development\"是不定式短语，用来后置修饰名词\"condition\"，说明是用于适应现代社会发展的条件。不定式作后置定语常用来修饰表示目的、用途的名词，初中阶段需要掌握这种后置定语的结构。","本句主语是\"Lifelong learning\"，属于动名词短语作主语，视为第三人称单数，因此系动词用\"is\"。初中阶段需要掌握动名词、不定式作主语时，系动词用第三人称单数形式的规则。","句中\"lifelong\"\"modern\"\"necessary\"等形容词都用来修饰后面的名词，放在名词前作前置定语，这是形容词的基本用法之一，初中阶段需要掌握形容词修饰名词的位置和功能。"]},"sentenceWithHints":"终身 学习 是 适应 现代 社会 发展 的 必要 条件"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (181, '{"words":[{"plural":"","chinese":"心理","english":"mental","examples":["Mental health is very important.","She has good mental strength."],"phonetic":"/ˈmentl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"healths","chinese":"健康","english":"health","examples":["Good health is the most valuable thing.","We should care about our health."],"phonetic":"/helθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"与","english":"as...as","examples":["She is as tall as her sister.","This book is as interesting as that one."],"phonetic":"/æz...æz/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"身体","english":"physical","examples":["Physical exercise is good for us.","He has great physical strength."],"phonetic":"/ˈfɪzɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"healths","chinese":"健康","english":"health","examples":["Good health is the most valuable thing.","We should care about our health."],"phonetic":"/helθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"同样","english":"as","examples":["He runs as fast as me.","This apple is as red as that one."],"phonetic":"/æz/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to learn English well.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["as...as 结构的用法","形容词作定语修饰名词","不可数名词的使用"],"explanations":["as...as 是初中阶段重点考查的同级比较结构，用于表示两者在某方面程度相同，基本结构为“as + 形容词/副词原级 + as”，否定形式为“not as/so + 形容词/副词原级 + as”。本句中用“as important as”表示“与……同样重要”，符合同级比较的用法。","形容词可以放在名词前作定语，用来修饰说明名词的属性。本句中“mental（心理的）”修饰“health（健康）”，“physical（身体的）”修饰“health（健康）”，分别构成“mental health（心理健康）”和“physical health（身体健康）”两个名词短语，这是形容词的基础用法之一。","health 是不可数名词，没有具体的数量形式，在句子中表示抽象的“健康”概念，不可直接用数词修饰，也不需要在一般情况下变复数，本句中两次使用都体现了不可数名词的常规用法。"]},"sentenceWithHints":"心理 健康 与 身体 健康 同样 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (182, '{"words":[{"chinese":"提高","english":"improve","examples":["We need to improve our English skills.","The government is trying to improve public services."],"phonetic":"/ɪmˈpruːv/","pastTense":"improved","thirdPerson":"improves","partOfSpeech":"动词","pastParticiple":"improved","presentParticiple":"improving"},{"plural":"citizens","chinese":"公民","english":"citizen","examples":["Every citizen has the right to vote.","He is a citizen of the United States."],"phonetic":"/ˈsɪtɪzn/","partOfSpeech":"名词"},{"plural":"qualities","chinese":"素质","english":"quality","examples":["We should pay attention to the quality of life.","Honesty is an important quality."],"phonetic":"/ˈkwɑːləti/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the table."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"建设","english":"build","examples":["They plan to build a new school.","We are building a better future."],"phonetic":"/bɪld/","pastTense":"built","thirdPerson":"builds","partOfSpeech":"动词","pastParticiple":"built","presentParticiple":"building"},{"chinese":"和谐","english":"harmonious","examples":["We live in a harmonious community.","The harmonious music made us relaxed."],"phonetic":"/hɑːrˈmoʊniəs/","partOfSpeech":"形容词"},{"plural":"societies","chinese":"社会","english":"society","examples":["We should contribute to society.","Different societies have different cultures."],"phonetic":"/səˈsaɪəti/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["the roof of the house","a cup of tea"],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"foundations","chinese":"基础","english":"foundation","examples":["Hard work is the foundation of success.","The foundation of the house is strong."],"phonetic":"/faʊnˈdeɪʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","名词所有格的用法","介词of表所属关系","形容词修饰名词"],"explanations":["当动词需要充当句子主语时，要将其变为动名词形式（即动词+ing），本句中“提高”和“建设”分别以Improving和building的动名词形式作主语和介词of的宾语，符合英语语法中动词不能直接作主语或介词宾语的规则。","表示“公民的素质”时，使用citizens''的所有格形式，以s结尾的复数名词的所有格直接在词尾加''，用来表示所属关系。","介词of可以用来表示事物的所属关系，本句中“of building a harmonious society”用来修饰foundation，说明基础的具体内容，即“建设和谐社会的基础”。","形容词用来修饰名词，本句中形容词harmonious修饰名词society，构成“harmonious society（和谐社会）”的名词短语，符合英语中形容词修饰名词的前置规则。"]},"sentenceWithHints":"提高 公民 素质 是 建设 和谐 社会 的 基础"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (183, '{"words":[{"plural":"","chinese":"国际","english":"international","examples":["International trade is developing fast.","We need international support."],"phonetic":"/ˌɪntərˈnæʃənl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"cooperations","chinese":"合作","english":"cooperation","examples":["International cooperation is needed.","We have good cooperation with them."],"phonetic":"/koʊˌɑːpəˈreɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"对","english":"for","examples":["This book is for you.","Yoga is good for health."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"解决","english":"solve","examples":["I can solve this problem.","He solved the math puzzle quickly."],"phonetic":"/sɑːlv/","pastTense":"solved","thirdPerson":"solves","partOfSpeech":"动词","pastParticiple":"solved","presentParticiple":"solving"},{"plural":"","chinese":"全球性","english":"global","examples":["Global warming is a serious issue.","We face many global challenges."],"phonetic":"/ˈgloʊbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"problems","chinese":"问题","english":"problem","examples":["We need to solve this problem.","There are many problems to deal with."],"phonetic":"/ˈprɑːbləm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"至关重要","english":"crucial","examples":["Water is crucial for life.","It''s crucial to arrive on time."],"phonetic":"/ˈkruːʃl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["介词for的用法","动名词作宾语","形容词修饰名词","系动词的使用"],"explanations":["介词for在这里用来引出对象或用途，表明动作针对的目标，本句中表示“对于解决全球性问题”，符合for引出动作作用对象的用法。","介词for后面接动词时，需要使用动名词形式（即动词加-ing），本句中solve变为solving，作for的宾语，这是介词后接动词的固定规则。","形容词用来修饰名词，本句中international修饰cooperation，global修饰problems，用来明确名词的属性，这是形容词的基本用法，初中阶段需要掌握形容词修饰名词的位置和逻辑关系。","本句使用系动词is连接主语International cooperation和表语crucial，构成主系表结构，主语是单数名词短语，所以使用第三人称单数形式的系动词is，这是主系表结构中系动词和主谓一致的基础考点。"]},"sentenceWithHints":"国际 合作 对 解决 全球性 问题 至关重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (184, '{"words":[{"plural":"","chinese":"互联网","english":"Internet","examples":["The Internet has changed our life greatly.","We can get lots of information from the Internet."],"phonetic":"/ˈɪntərnet/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"securities","chinese":"安全","english":"security","examples":["National security is the top priority.","We need to improve the security of the building."],"phonetic":"/sɪˈkjʊrəti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"成为","english":"become","examples":["She has become a famous singer.","The small village became a big city."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She has gone to the park."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一个","english":"an","examples":["He is an honest boy.","There is an apple on the table."],"phonetic":"/æn/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"重要的","english":"important","examples":["It is important to learn English well.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["The color of the flower is red.","This is my mother''s bag."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"社会","english":"social","examples":["We should pay attention to social problems.","He is active in social activities."],"phonetic":"/ˈsoʊʃl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"issues","chinese":"问题","english":"issue","examples":["We need to discuss this issue carefully.","Environmental protection is a serious issue."],"phonetic":"/ˈɪʃuː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","不定冠词a/an的用法","名词短语的构成"],"explanations":["现在完成时结构为have/has+动词过去分词，强调过去发生的动作对现在造成的影响或结果。本句中“成为了”表示动作已经完成且对现在有影响，主语“Internet security”是单数第三人称，所以用has become。","不定冠词a用于辅音音素开头的单词前，an用于元音音素开头的单词前。本句中important以元音音素/ɪ/开头，所以前面用an。","多个修饰性词语修饰名词时，顺序通常为：限定词+形容词+名词性定语+中心名词。本句中“an important social issue”符合这个顺序，其中an是限定词，important是描述性形容词，social是类别形容词，issue是中心名词。"]},"sentenceWithHints":"互联网 安全 成为 了 一个 重要 的 社会 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (185, '{"words":[{"chinese":"文化","english":"cultural","examples":["Cultural differences are interesting.","We should respect cultural diversity."],"phonetic":"/ˈkʌltʃərəl/","partOfSpeech":"形容词"},{"plural":"heritages","chinese":"遗产","english":"heritage","examples":["Cultural heritage is precious.","We need to protect our national heritage."],"phonetic":"/ˈherɪtɪdʒ/","partOfSpeech":"名词"},{"chinese":"保护","english":"protect","examples":["We should protect the environment.","The law protects people''s rights."],"phonetic":"/prəˈtekt/","pastTense":"protected","thirdPerson":"protects","partOfSpeech":"动词","pastParticiple":"protected","presentParticiple":"protecting"},{"chinese":"是","english":"is","examples":["She is a doctor.","Running is good for health."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"每个","english":"every","examples":["Every student should study hard.","I go to the park every weekend."],"phonetic":"/ˈevri/","partOfSpeech":"形容词"},{"plural":"citizens","chinese":"公民","english":"citizen","examples":["He is a citizen of the United States.","Citizens have certain rights and duties."],"phonetic":"/ˈsɪtɪzn/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["This is the book of my sister.","The responsibility of citizens is important."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"responsibilities","chinese":"责任","english":"responsibility","examples":["It''s my responsibility to help others.","She takes her responsibilities seriously."],"phonetic":"/rɪˌspɑːnsəˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","名词所有格的表达","系动词be的用法"],"explanations":["当动词需要在句子中充当主语时，要将其变为动名词形式（即动词+ing），本句中“保护”作主语，所以使用protecting，动名词作主语时，谓语动词用单数形式。","表示“……的”所属关系时，除了用名词所有格''s形式，还可以用介词of引导的短语，本句中“每个公民的责任”译为the responsibility of every citizen，属于of短语表所属的用法，适用于无生命名词或侧重整体与部分关系的表达。","系动词be的形式要根据主语的单复数变化，本句主语是动名词短语Protecting cultural heritage，属于单数概念，因此搭配系动词is。"]},"sentenceWithHints":"文化 遗产 保护 是 每个 公民 的 责任"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (186, '{"words":[{"plural":"","chinese":"哲学","english":"philosophical","examples":["She has a philosophical attitude towards life.","The book explores philosophical questions."],"phonetic":"/ˌfɪləˈsɑːfɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"thinkings","chinese":"思考","english":"thinking","examples":["Critical thinking is important for problem-solving.","His thinking on this issue has changed."],"phonetic":"/ˈθɪŋkɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"帮助","english":"help","examples":["She helps her mother with housework.","This book will help you learn English."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"","chinese":"我们","english":"us","examples":["He told us a story.","Please give us some advice."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"理解","english":"understand","examples":["I don''t understand this math problem.","She understands how to play the piano."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is full of amazing things.","He wants to travel around the world."],"phonetic":"/wɜːrld/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"essences","chinese":"本质","english":"essence","examples":["The essence of his argument is very simple.","We need to find the essence of the problem."],"phonetic":"/ˈesns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词作定语","动词 help 的用法","名词所有格的表达（of 结构）","动词第三人称单数变化"],"explanations":["形容词可以放在名词前作定语，用来修饰名词。本句中用形容词 philosophical 修饰名词 thinking，说明思考的类型是哲学层面的。","动词 help 常见用法为 help sb. (to) do sth.，其中不定式符号 to 可以省略，本句中 helps us understand 就是使用了这个结构，表示“帮助我们做某事”。","在英语中，表达所属关系除了名词所有格''s 形式外，还可以用“the + 名词 + of + 名词”的结构，本句中 the essence of the world 就用 of 结构表示“世界的本质”，用于无生命事物的所属关系表达。","当主语是第三人称单数（本句中主语 Philosophical thinking 是不可数名词短语，视为第三人称单数）时，一般现在时的动词要使用第三人称单数形式，规则动词直接在词尾加 -s，help 的第三人称单数形式是 helps。"]},"sentenceWithHints":"哲学 思考 帮助 我们 理解 世界 的 本质"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (187, '{"words":[{"plural":"literatures","chinese":"文学","english":"literature","examples":["She loves classic literature.","We are studying American literature."],"phonetic":"/ˈlɪtrətʃər/","partOfSpeech":"名词"},{"plural":"arts","chinese":"艺术","english":"art","examples":["Art is an important part of education.","She is skilled in the arts."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"},{"chinese":"能够","english":"can","examples":["I can speak English.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"丰富","english":"enrich","examples":["Reading can enrich your mind.","Travel enriches our life experience."],"phonetic":"/ɪnˈrɪtʃ/","pastTense":"enriched","thirdPerson":"enriches","partOfSpeech":"动词","pastParticiple":"enriched","presentParticiple":"enriching"},{"plural":"people","chinese":"人们","english":"people","examples":["People all over the world love peace.","Many people attended the meeting."],"phonetic":"/ˈpiːpəl/","partOfSpeech":"名词"},{"chinese":"的","english":"''s","examples":["This is Tom''s book.","The cat''s tail is long."],"phonetic":"/z/","partOfSpeech":"助词"},{"chinese":"精神","english":"spiritual","examples":["We need spiritual support.","She has a rich spiritual life."],"phonetic":"/ˈspɪrɪtʃuəl/","partOfSpeech":"形容词"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is full of surprises.","He dreams of traveling the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词can的用法","名词所有格的表达","及物动词enrich的用法","并列名词的连接"],"explanations":["情态动词can表示“能够、可以”，后接动词原形，用来表达能力或可能性，本句中用来说明文学艺术具备丰富精神世界的作用。","表示所属关系时，复数名词people的所有格形式为people''s，用来修饰spiritual world，表明是“人们的”精神世界，这是名词所有格的常见用法之一。","enrich是及物动词，后面可以直接接宾语，本句中接people''s spiritual world作宾语，表达“使……丰富”的含义，在初中阶段需要掌握这类及物动词的搭配。","当两个并列的名词literature和art共同作主语时，用连词and连接，在英语中and常用于连接并列的成分，保持句子结构的平衡和语义的连贯。"]},"sentenceWithHints":"文学 艺术 能够 丰富 人们 的 精神 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (188, '{"words":[{"plural":"","chinese":"历史","english":"historical","examples":["We should learn from historical events.","The castle has a long historical background."],"phonetic":"/hɪˈstɔːrɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"experiences","chinese":"经验","english":"experience","examples":["We can gain experience from practice.","She shared her interesting experiences abroad."],"phonetic":"/ɪkˈspɪriəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my sister.","This book is for children."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我们","english":"us","examples":["He gave us some advice.","Please wait for us."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"提供","english":"provide","examples":["The hotel provides free breakfast for guests.","We should provide help for those in need."],"phonetic":"/prəˈvaɪd/","pastTense":"provided","thirdPerson":"provides","partOfSpeech":"动词","pastParticiple":"provided","presentParticiple":"providing"},{"plural":"","chinese":"了","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"宝贵","english":"valuable","examples":["Time is a valuable resource.","She gave me some valuable suggestions."],"phonetic":"/ˈvæljuəbəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"lessons","chinese":"教训","english":"lesson","examples":["We should learn a lesson from this mistake.","The teacher gave us a new lesson today."],"phonetic":"/ˈlesn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词短语provide sb. with sth.的用法","可数名词的复数形式","形容词作定语的用法"],"explanations":["provide sb. with sth.是固定动词短语，意为“为某人提供某物”，也可以转换为provide sth. for sb.的结构，本句中使用的是provide us with valuable lessons的结构，符合短语搭配规范。","可数名词表示泛指或数量大于一时需要使用复数形式，本句中“经验”表示泛指经历时为可数名词，“教训”是可数名词，所以分别使用experiences和lessons的复数形式。","形容词可以放在名词前作定语修饰名词，本句中historical修饰experience，valuable修饰lessons，用来明确名词的属性和特征，这是形容词的常见用法之一。"]},"sentenceWithHints":"历史 经验 为 我们 提供 了 宝贵 的 教训"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (189, '{"words":[{"chinese":"科学","english":"scientific","examples":["Scientific research is important.","We need a scientific approach."],"phonetic":"/ˌsaɪənˈtɪfɪk/","partOfSpeech":"形容词"},{"plural":"explorations","chinese":"探索","english":"exploration","examples":["Space exploration is exciting.","The exploration of the ocean continues."],"phonetic":"/ˌekspləˈreɪʃn/","partOfSpeech":"名词"},{"chinese":"推动","english":"promote","examples":["Exercise promotes good health.","The company aims to promote new products."],"phonetic":"/prəˈmoʊt/","pastTense":"promoted","thirdPerson":"promotes","partOfSpeech":"动词","pastParticiple":"promoted","presentParticiple":"promoting"},{"chinese":"人类","english":"human","examples":["Human beings need love.","This is a human right."],"phonetic":"/ˈhjuːmən/","partOfSpeech":"形容词"},{"plural":"civilizations","chinese":"文明","english":"civilization","examples":["Ancient Egyptian civilization is fascinating.","Modern civilization has many advantages."],"phonetic":"/ˌsɪvələˈzeɪʃn/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"","chinese":"进步","english":"progress","examples":["We have made great progress.","Progress takes time."],"phonetic":"/ˈprɑːɡres/","partOfSpeech":"名词"}],"examPoints":{"points":["形容词作定语","名词所有格的表达（of 结构）","动词第三人称单数形式"],"explanations":["形容词可以用来修饰名词，放在名词前起到限定描述的作用。本句中用形容词 scientific 修饰名词 exploration，说明探索的属性是科学领域的；用形容词 human 修饰名词 civilization，明确文明的所属对象。","当表示无生命事物的所属关系时，常用“名词 + of + 名词”的结构来表达所有格。本句中“人类文明的进步”译为“the progress of human civilization”，通过 of 结构清晰体现了进步与人类文明的所属关联。","当主语是第三人称单数（本句中主语 Scientific exploration 是单数名词短语，属于第三人称单数）时，一般现在时的谓语动词需要使用第三人称单数形式。动词 promote 的第三人称单数形式是在词尾加 -s，即 promotes。"]},"sentenceWithHints":"科学 探索 推动 人类 文明 的 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (190, '{"words":[{"plural":"morals","chinese":"道德","english":"moral","examples":["People should follow basic morals.","His morals guide his every action."],"phonetic":"/ˈmɔːrəl/","partOfSpeech":"名词"},{"plural":"constructions","chinese":"建设","english":"construction","examples":["The construction of the bridge will take two years.","Urban construction is developing rapidly."],"phonetic":"/kənˈstrʌkʃən/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"社会","english":"social","examples":["We need to pay attention to social issues.","She is active in social work."],"phonetic":"/ˈsoʊʃəl/","partOfSpeech":"形容词"},{"plural":"developments","chinese":"发展","english":"development","examples":["The city has seen great development in recent years.","New developments in technology change our lives."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["This is the roof of the house.","The color of the flower is red."],"phonetic":"/əv/","partOfSpeech":"介词"},{"chinese":"重要","english":"important","examples":["It''s important to study hard.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"},{"plural":"guarantees","chinese":"保障","english":"guarantee","examples":["Hard work is a guarantee of success.","The policy provides a guarantee for people''s rights."],"phonetic":"/ˌɡærənˈtiː/","partOfSpeech":"名词"}],"examPoints":{"points":["名词短语的英译","不定冠词的使用","介词for表用途/对象的用法"],"explanations":["中文里的偏正结构“道德建设”“社会发展”在英译时转换为名词短语“Moral construction”“social development”，用形容词修饰名词来体现偏正关系，这是汉译英中常见的结构转换，符合英语的表达习惯。","形容词important以元音音素开头，所以前面的不定冠词用an，而不是a，这是不定冠词a/an的核心用法规则，需要根据单词开头的音素而非字母来判断。","介词for在这里用来引出动作或事物的对象，“guarantee for social development”表示“针对社会发展的保障”，体现出保障的作用对象，是介词for的常见实用场景之一。"]},"sentenceWithHints":"道德 建设 是 社会 发展 的 重要 保障"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (191, '{"words":[{"plural":"laws","chinese":"法律","english":"law","examples":["We must obey the law.","The new law will come into effect next month."],"phonetic":"/lɔː/","partOfSpeech":"名词"},{"plural":"awarenesses","chinese":"意识","english":"awareness","examples":["Environmental awareness is very important.","We need to raise public awareness of this issue."],"phonetic":"/əˈwer.nəs/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","This is my favorite book."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"citizens","chinese":"公民","english":"citizen","examples":["Every citizen has the right to vote.","He is a citizen of the United States."],"phonetic":"/ˈsɪt.ə.zən/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["This is the house of my grandfather.","The color of the car is red."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"","chinese":"基本","english":"basic","examples":["We need to learn some basic skills.","This is a basic rule you must follow."],"phonetic":"/ˈbeɪ.sɪk/","partOfSpeech":"形容词"},{"plural":"qualities","chinese":"素质","english":"quality","examples":["Honesty is an important quality.","She has many good qualities."],"phonetic":"/ˈkwɑː.lə.t̬i/","partOfSpeech":"名词"},{"plural":"","chinese":"之","english":"of","examples":["One of my friends is coming.","This is a part of the plan."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"","chinese":"一","english":"one","examples":["One of the books is mine.","I want one apple."],"phonetic":"/wʌn/","partOfSpeech":"代词"}],"examPoints":{"points":["“one of + 复数名词”结构","名词所有格/所属关系的表达","形容词作定语的用法"],"explanations":["“one of + 复数名词”是初中重点结构，意为“……之一”，表示在多个事物中占据一个，后面的可数名词必须用复数形式，谓语动词用第三人称单数形式。本句中“one of the basic qualities”表示“基本素质之一”，qualities用复数，谓语动词is用第三人称单数。","英语中表示所属关系常用“of + 名词”结构，对应中文的“……的”，本句中“the basic qualities of citizens”表示“公民的基本素质”，清晰体现出素质属于公民的所属关系；同时当指代一类人时，常用可数名词复数形式，这里citizens表示“公民”这一类群体。","形容词可以放在名词前作定语，用来修饰名词，说明名词的特征。本句中basic作为形容词放在qualities前，修饰qualities，说明素质的属性是“基本的”；legal作为形容词放在awareness前，修饰awareness，构成“法律意识”的对应表达Legal awareness。"]},"sentenceWithHints":"法律 意识 是 公民 的 基本 素质 之 一"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (192, '{"words":[{"plural":"","chinese":"政治","english":"political","examples":["Political leaders should serve the people.","We are learning about political systems."],"phonetic":"/pəˈlɪtɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"participations","chinese":"参与","english":"participation","examples":["Her participation in the project was very helpful.","We encourage active participation from all members."],"phonetic":"/pɑːrˌtɪsəˈpeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"体现","english":"reflect","examples":["The results reflect our hard work.","Her actions reflect her true feelings."],"phonetic":"/rɪˈflekt/","pastTense":"reflected","thirdPerson":"reflects","partOfSpeech":"动词","pastParticiple":"reflected","presentParticiple":"reflecting"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She has read the book."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"citizens","chinese":"公民","english":"citizen","examples":["He is a citizen of the United States.","Citizens have the right to vote."],"phonetic":"/ˈsɪtɪzn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the sky is blue."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"responsibilities","chinese":"责任","english":"responsibility","examples":["It''s our responsibility to protect the environment.","She takes her responsibilities very seriously."],"phonetic":"/rɪˌspɑːnsəˈbɪləti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She is tall and thin."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"rights","chinese":"权利","english":"right","examples":["Everyone has the right to education.","We should fight for our rights."],"phonetic":"/raɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["名词所有格的用法","可数名词的复数形式","动词第三人称单数的变化"],"explanations":["当表示所属关系时，可数名词复数以s结尾的，直接在词尾加''构成所有格，本句中citizens是citizen的复数形式，所以用citizens''表示“公民的”。","可数名词表示泛指一类事物或数量不止一个时，需要使用复数形式。本句中“责任”和“权利”都是泛指公民的相关内容，所以使用responsibilities和rights这两个复数形式。","一般现在时中，当主语是第三人称单数时，谓语动词需要变为第三人称单数形式。本句主语Political participation是单数概念，所以谓语动词reflect变为reflects。"]},"sentenceWithHints":"政治 参与 体现 了 公民 的 责任 和 权利"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (193, '{"words":[{"chinese":"经济","english":"economic","examples":["economic growth","economic development"],"phonetic":"/ˌiːkəˈnɑːmɪk/","partOfSpeech":"形容词"},{"plural":"growths","chinese":"增长","english":"growth","examples":["economic growth","the growth of plants"],"phonetic":"/ɡroʊθ/","partOfSpeech":"名词"},{"chinese":"不能","english":"cannot","examples":["I cannot swim.","He cannot come today."],"phonetic":"/ˈkænɑːt/","pastTense":"could not","thirdPerson":"cannot","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"以","english":"at","examples":["at home","at the expense of"],"phonetic":"/æt/","partOfSpeech":"介词"},{"plural":"expenses","chinese":"牺牲","english":"expense","examples":["at the expense of","daily expenses"],"phonetic":"/ɪkˈspens/","partOfSpeech":"名词"},{"plural":"environments","chinese":"环境","english":"environment","examples":["protect the environment","a safe environment"],"phonetic":"/ɪnˈvaɪrənmənt/","partOfSpeech":"名词"},{"chinese":"为","english":"of","examples":["a cup of tea","the expense of the environment"],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"expenses","chinese":"代价","english":"expense","examples":["at the expense of","spare no expense"],"phonetic":"/ɪkˈspens/","partOfSpeech":"名词"}],"examPoints":{"points":["固定短语搭配","情态动词的用法","形容词作定语"],"explanations":["本题考查固定短语“at the expense of”，意为“以……为代价”，是初中阶段需要掌握的重点短语，常用于表达事物发展的代价相关内容。","情态动词“cannot”表示“不能、不可以”，后面接动词原形，用于表达禁止、不允许或者能力上的无法做到，本句中用来表示经济增长不允许以牺牲环境为前提。","形容词“economic”作定语修饰名词“growth”，构成“economic growth”（经济增长）这一常用表达，形容词作定语通常放在所修饰的名词之前，用来限定名词的属性。"]},"sentenceWithHints":"经济 增长 不能 以 牺牲 环境 为 代价"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (194, '{"words":[{"plural":"societies","chinese":"社会","english":"society","examples":["We live in a multi-cultural society.","The society is developing rapidly."],"phonetic":"/səˈsaɪəti/","partOfSpeech":"名词"},{"plural":"","chinese":"公平","english":"fairness","examples":["We should strive for fairness in education.","Fairness is an important value in law."],"phonetic":"/ˈfernəs/","partOfSpeech":"名词"},{"plural":"","chinese":"正义","english":"justice","examples":["The court is supposed to uphold justice.","People have a strong desire for justice."],"phonetic":"/ˈdʒʌstɪs/","partOfSpeech":"名词"},{"chinese":"是","english":"are","examples":["You are my best friend.","These books are very interesting."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"社会主义","english":"socialist","examples":["He believes in socialist ideals.","This is a socialist country."],"phonetic":"/ˈsoʊʃəlɪst/","partOfSpeech":"形容词"},{"chinese":"核心","english":"core","examples":["The core idea of the plan is practical.","We need to focus on the core issues."],"phonetic":"/kɔːr/","partOfSpeech":"形容词"},{"plural":"values","chinese":"价值观","english":"values","examples":["Our family values include honesty and kindness.","Different cultures have different values."],"phonetic":"/ˈvæljuːz/","partOfSpeech":"名词"}],"examPoints":{"points":["并列主语与be动词的一致","专有名词的英文表达","形容词作定语的位置"],"explanations":["当句子主语是由and连接的两个并列名词时，整体表示复数概念，be动词需要使用are。本句中主语是“社会公平正义”，对应英文的“fairness and justice”，是两个并列的抽象名词，所以be动词用are。","中文中的特定政治类专有名词有固定的英文译法，比如“社会主义核心价值观”固定译为“core socialist values”，这类专有名词需要准确记忆，不能随意直译。","多个形容词修饰名词时，通常遵循限定词-描绘性形容词-大小/长短/高低-形状-年龄/新旧-颜色-国籍/出处-材料-用途-名词的顺序。本句中“社会主义（socialist）”和“核心（core）”修饰“价值观（values）”，按照语义逻辑，表属性的“socialist”放在表核心属性的“core”之后，符合英语定语修饰的习惯。"]},"sentenceWithHints":"社会 公平 正义 是 社会主义 核心 价值观"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (195, '{"words":[{"plural":"cultures","chinese":"文化","english":"culture","examples":["Chinese culture has a long history.","We should respect different cultures."],"phonetic":"/ˈkʌltʃər/","partOfSpeech":"名词"},{"plural":"confidences","chinese":"自信","english":"confidence","examples":["She has confidence in her ability.","Confidence is important for success."],"phonetic":"/ˈkɑːnfɪdəns/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["This is my pen.","He is a doctor."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一个","english":"a","examples":["I have a cat.","She bought a book."],"phonetic":"/ə/","partOfSpeech":"冠词"},{"plural":"countries","chinese":"国家","english":"country","examples":["China is a great country.","Many countries took part in the meeting."],"phonetic":"/ˈkʌntri/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","He is tall and strong."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"nations","chinese":"民族","english":"nation","examples":["The whole nation was excited.","It''s a nation with rich traditions."],"phonetic":"/ˈneɪʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"souls","chinese":"灵魂","english":"soul","examples":["Music is the soul of life.","He has a kind soul."],"phonetic":"/soʊl/","partOfSpeech":"名词"}],"examPoints":{"points":["名词作定语的用法","介词of表所属关系","系动词be的主谓一致"],"explanations":["当名词作定语时，通常用单数形式修饰另一个名词，本句中“Cultural confidence”里的Cultural是名词culture的形容词形式，用来修饰confidence，体现“文化领域的自信”，这是英语中常见的用名词相关形容词修饰抽象名词的表达，初中阶段需要掌握这类名词衍生形容词的用法。","介词of常用来表示所属关系，即“……的”，本句中“the soul of a country and nation”表示“一个国家和民族的灵魂”，这是英语中表达事物所属的常用结构，区别于中文的“的”字结构，需要掌握该结构的语序和用法。","系动词be的形式要和主语保持主谓一致，本句主语“Cultural confidence”是抽象不可数名词，属于第三人称单数，因此be动词用is，初中阶段需要熟练掌握不同主语对应的be动词形式变化规则。"]},"sentenceWithHints":"文化 自信 是 一个 国家 和 民族 的 灵魂"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (196, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation is key to progress.","The company encourages innovation among its employees."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"plural":"developments","chinese":"发展","english":"development","examples":["The city''s rapid development has attracted many investors.","We are monitoring the development of the project."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"引领","english":"lead","examples":["She leads the team to victory.","The path leads to the mountain top."],"phonetic":"/liːd/","pastTense":"led","thirdPerson":"leads","partOfSpeech":"动词","pastParticiple":"led","presentParticiple":"leading"},{"plural":"developments","chinese":"发展","english":"development","examples":["Sustainable development is crucial for the future.","Recent developments have changed the situation."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The cover of the book is blue.","This is a photo of my family."],"phonetic":"/əv/","partOfSpeech":"介词"},{"chinese":"第一","english":"first","examples":["She won first place in the race.","This is my first time visiting Paris."],"phonetic":"/fɜːrst/","partOfSpeech":"形容词"},{"plural":"forces","chinese":"动力","english":"force","examples":["Wind is a natural force.","The police force is well-trained."],"phonetic":"/fɔːrs/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词短语作定语","主系表句型的运用","序数词的用法"],"explanations":["在英文翻译中，使用了现在分词短语\"leading development\"作后置定语修饰\"driving force\"，相当于定语从句\"which leads development\"，用来补充说明动力的具体作用，这是初中阶段需要掌握的非谓语动词用法之一，现在分词作定语时与被修饰词是主动关系。","本句是典型的主系表句型，中文原句的主语是“创新发展”，英文处理为名词\"Innovation\"作主语，系动词\"is\"连接主语和表语\"the first driving force leading development\"，主系表句型用于说明主语的身份、性质、状态等，是初中英语的核心句型之一。","序数词\"first\"用来表示顺序“第一”，在句中修饰名词\"driving force\"，序数词前通常要加定冠词\"the\"，这是序数词的基本用法，初中阶段需要掌握序数词的形式、用法以及与定冠词的搭配规则。"]},"sentenceWithHints":"创新 发展 是 引领 发展 的 第一 动力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (197, '{"words":[{"chinese":"协调","english":"coordinate","examples":["We need to coordinate our efforts to finish the project.","The manager coordinates the work of all departments."],"phonetic":"/koʊˈɔːrdəneɪt/","pastTense":"coordinated","thirdPerson":"coordinates","partOfSpeech":"动词","pastParticiple":"coordinated","presentParticiple":"coordinating"},{"plural":"developments","chinese":"发展","english":"development","examples":["The city has seen rapid development in recent years.","Sustainable development is important for the future."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"chinese":"旨在","english":"aim to","examples":["The new policy aims to reduce air pollution.","This program aims to help poor children get an education."],"phonetic":"/eɪm tuː/","pastTense":"aimed to","thirdPerson":"aims to","partOfSpeech":"动词短语","pastParticiple":"aimed to","presentParticiple":"aiming to"},{"chinese":"解决","english":"solve","examples":["Can you solve this math problem?","We need to find a way to solve the conflict."],"phonetic":"/sɑːlv/","pastTense":"solved","thirdPerson":"solves","partOfSpeech":"动词","pastParticiple":"solved","presentParticiple":"solving"},{"chinese":"不平衡","english":"unbalanced","examples":["The unbalanced diet made him feel sick.","There is an unbalanced distribution of resources in the region."],"phonetic":"/ˌʌnˈbælənst/","partOfSpeech":"形容词"},{"plural":"problems","chinese":"问题","english":"problem","examples":["We have a problem with the computer system.","She always tries to avoid problems instead of facing them."],"phonetic":"/ˈprɑːbləm/","partOfSpeech":"名词"}],"examPoints":{"points":["过去分词作定语","动词短语aim to的用法","of所属格的使用"],"explanations":["过去分词作定语时，通常表示被动或完成的含义。本句中“Coordinated development”里的coordinated是coordinate的过去分词，作定语修饰development，意为“被协调的、协调型的发展”，符合英文中用分词修饰名词的表达习惯。","aim to是固定动词短语，意为“旨在、目的是”，主语通常是表示计划、政策、项目等的名词，后接动词原形，用来表达某个事物的目的和意图，本句中“Coordinated development aims to solve...”就符合这个用法。","of所属格主要用于表示无生命事物的所属关系，本句中“the problem of unbalanced development”用of连接，表达“发展不平衡的问题”，是英文中表达无生命事物所属关系的常见方式。"]},"sentenceWithHints":"协调 发展 旨在 解决 发展 不平衡 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (198, '{"words":[{"plural":"","chinese":"绿色","english":"green","examples":["Green leaves are beautiful in spring.","We should choose green energy."],"phonetic":"/ɡriːn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"developments","chinese":"发展","english":"development","examples":["The city''s development is fast.","Sustainable development is important."],"phonetic":"/dɪˈveləpmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"强调","english":"emphasize","examples":["Teachers emphasize the importance of homework.","The report emphasizes the need for change."],"phonetic":"/ˈemfəsaɪz/","pastTense":"emphasized","thirdPerson":"emphasizes","partOfSpeech":"动词","pastParticiple":"emphasized","presentParticiple":"emphasizing"},{"plural":"","chinese":"人与","english":"humans and","examples":["Humans and animals need clean water.","The relationship between humans and nature is close."],"phonetic":"/ˈhjuːmənz ənd/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"自然","english":"nature","examples":["We should protect nature.","Nature gives us many resources."],"phonetic":"/ˈneɪtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The color of the sky is blue.","This is a photo of my family."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和谐","english":"harmonious","examples":["We live in a harmonious community.","The harmonious music makes me relaxed."],"phonetic":"/hɑːrˈmoʊniəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"coexistences","chinese":"共生","english":"coexistence","examples":["Coexistence of different cultures is valuable.","The coexistence of humans and animals needs effort."],"phonetic":"/ˌkoʊɪɡˈzɪstəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词作定语","名词所有格/所属关系表达","动词第三人称单数形式"],"explanations":["形容词可以放在名词前作定语，用来修饰名词，本句中“green（绿色的）”修饰“development（发展）”，“harmonious（和谐的）”修饰“coexistence（共生）”，明确被修饰名词的属性。","英语中表达所属关系常用“of”结构，本句中“the harmonious coexistence of humans and nature”用“of”连接，体现“人与自然”和“和谐共生”的所属关联，对应中文里“的”的所属含义。","当句子主语是第三人称单数时，一般现在时的动词要使用第三人称单数形式。本句主语“Green development”是第三人称单数，所以动词“emphasize”变为“emphasizes”。"]},"sentenceWithHints":"绿色 发展 强调 人与 自然 的 和谐 共生"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (199, '{"words":[{"chinese":"开放","english":"open","examples":["We need an open mind.","This is an open market."],"phonetic":"/ˈoʊpən/","partOfSpeech":"形容词"},{"plural":"developments","chinese":"发展","english":"development","examples":["Economic development is important.","There have been new developments in the project."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"chinese":"要求","english":"require","examples":["The job requires hard work.","Rules require us to wear uniforms."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some help."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"拓展","english":"expand","examples":["We need to expand our business.","The city is expanding quickly."],"phonetic":"/ɪkˈspænd/","pastTense":"expanded","thirdPerson":"expands","partOfSpeech":"动词","pastParticiple":"expanded","presentParticiple":"expanding"},{"plural":"developments","chinese":"发展","english":"development","examples":["Sustainable development is our goal.","The development of technology changes our lives."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"plural":"spaces","chinese":"空间","english":"space","examples":["We need more space to work.","There are many empty spaces in the room."],"phonetic":"/speɪs/","partOfSpeech":"名词"}],"examPoints":{"points":["动词短语 require sb. to do sth.","名词作定语","可数名词与不可数名词的用法"],"explanations":["require sb. to do sth. 是固定搭配，意为“要求某人做某事”，其中 to do 是动词不定式作宾语补足语，本句中用该结构表达“要求我们拓展”的语义。","名词可以直接放在另一个名词前作定语，起到修饰限定的作用，本句中“开放发展”译为“Open development”，“发展空间”译为“development space”，都是用名词作定语修饰后面的名词，这种用法在英语中较为常见，用于说明被修饰名词的属性或用途。","space 表示“空间、场所”时，既可以作可数名词也可以作不可数名词，本句中“发展空间”指抽象的发展余地，用作不可数名词，所以直接用“space”；当表示具体的多个空间时，可用复数形式“spaces”。"]},"sentenceWithHints":"开放 发展 要求 我们 拓展 发展 空间"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (200, '{"words":[{"chinese":"共享","english":"shared","examples":["Shared bikes are popular in cities.","We have a shared interest in music."],"phonetic":"/ʃerd/","partOfSpeech":"形容词"},{"plural":"developments","chinese":"发展","english":"development","examples":["Economic development is important.","There have been new developments in the project."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"chinese":"体现了","english":"embody","examples":["The law embodies the values of society.","Her actions embody the spirit of kindness."],"phonetic":"/ɪmˈbɑːdi/","pastTense":"embodied","thirdPerson":"embodies","partOfSpeech":"动词","pastParticiple":"embodied","presentParticiple":"embodying"},{"plural":"","chinese":"社会主义","english":"socialism","examples":["Socialism is a political and economic system.","He is studying the theory of socialism."],"phonetic":"/ˈsoʊʃəlɪzəm/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The color of the sky is blue.","This is a photo of my family."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"chinese":"本质","english":"essential","examples":["Water is essential for life.","We need to make an essential decision."],"phonetic":"/ɪˈsenʃl/","partOfSpeech":"形容词"},{"plural":"requirements","chinese":"要求","english":"requirement","examples":["Meeting the requirements is necessary.","The job has strict requirements."],"phonetic":"/rɪˈkwaɪərmənt/","partOfSpeech":"名词"}],"examPoints":{"points":["过去分词作定语","名词所有格的介词表达","动词第三人称单数形式"],"explanations":["过去分词可以用作定语修饰名词，此处shared修饰development，意为“共享的发展”，过去分词作定语通常表示被动或完成的含义，这里体现“发展”具备被共享的属性。","英语中表示所属关系时，除了''s所有格，还常用介词of构成的短语，本句中“社会主义的本质要求”译为“the essential requirements of socialism”，用of来体现“社会主义”和“本质要求”的所属关系，适用于无生命事物的所属表达。","句子主语“Shared development”是单数概念，谓语动词embody需要使用第三人称单数形式embodies。一般情况下，动词的第三人称单数形式是在词尾加-s，以辅音字母+y结尾的变y为i加-es，以s、x、sh、ch等结尾的加-es，embody属于规则变化，直接加-s变为embodies。"]},"sentenceWithHints":"共享 发展 体现了 社会主义 的 本质 要求"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (201, '{"words":[{"plural":"quanta","chinese":"量子","english":"quantum","examples":["A quantum of light is called a photon.","Quantum theory changed our understanding of the universe."],"phonetic":"/ˈkwɑːntəm/","partOfSpeech":"名词"},{"plural":"","chinese":"力学","english":"mechanics","examples":["Classical mechanics deals with macroscopic objects.","Quantum mechanics studies the behavior of tiny particles."],"phonetic":"/məˈkænɪks/","partOfSpeech":"名词"},{"chinese":"揭示","english":"reveal","examples":["The investigation revealed the truth.","Her smile revealed her happiness."],"phonetic":"/rɪˈviːl/","pastTense":"revealed","thirdPerson":"reveals","partOfSpeech":"动词","pastParticiple":"revealed","presentParticiple":"revealing"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She told me a story."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"微观","english":"microscopic","examples":["Microscopic organisms are too small to see with eyes.","The microscope shows us the microscopic world."],"phonetic":"/ˌmaɪkrəˈskɑːpɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"worlds","chinese":"世界","english":"world","examples":["The natural world is full of wonders.","Scientists are exploring other worlds."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"","examples":["The color of the sky is blue.","This is the book I told you about."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"奇妙","english":"wonderful","examples":["We had a wonderful time at the party.","The view from the mountain is wonderful."],"phonetic":"/ˈwʌndərfl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"laws","chinese":"规律","english":"law","examples":["The laws of nature govern everything.","We must follow the laws of the country."],"phonetic":"/lɔː/","partOfSpeech":"名词"}],"examPoints":{"points":["学科专有名词的翻译与用法","动词第三人称单数形式","介词of构成的所属结构"],"explanations":["本句中的“量子力学”是物理学科专有名词，对应的英文固定表达为“Quantum mechanics”，这类专有名词首字母需要大写，且“mechanics”在这里表示学科，是不可数名词，没有复数形式。","句子主语“Quantum mechanics”是单数概念的学科名词，谓语动词需要使用第三人称单数形式，所以“reveal”要变为“reveals”，这是一般现在时中主语为第三人称单数时的动词变形规则。","英文中表示所属关系常用介词“of”构成的结构，本句中“微观世界的奇妙规律”翻译为“the wonderful laws of the microscopic world”，通过“of”体现“规律”属于“微观世界”，这是英语中表达无生命事物所属关系的常用方式。"]},"sentenceWithHints":"量子 力学 揭示 了 微观 世界 的 奇妙 规律"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (202, '{"words":[{"plural":"relativities","chinese":"相对论","english":"relativity","examples":["Einstein''s theory of relativity revolutionized physics.","We are studying the basics of relativity in class."],"phonetic":"/ˌreləˈtɪvəti/","partOfSpeech":"名词"},{"chinese":"改变了","english":"change","examples":["The new policy changed our daily lives.","She has changed her mind about the trip."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"chinese":"我们","english":"our","examples":["Our team won the game.","This is our new house."],"phonetic":"/ˈaʊər/","partOfSpeech":"代词"},{"chinese":"对","english":"of","examples":["I have a good understanding of this topic.","The map shows the location of the city."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"spaces and times","chinese":"时空","english":"space and time","examples":["Einstein''s theory links space and time.","Scientists are exploring the mysteries of space and time."],"phonetic":"/speɪs ənd taɪm/","partOfSpeech":"名词"},{"chinese":"的","english":"","examples":["The color of the sky is blue.","This is the book I told you about."],"phonetic":"","partOfSpeech":"助词"},{"plural":"understandings","chinese":"认识","english":"understanding","examples":["His understanding of the problem was deep.","We need to reach a mutual understanding."],"phonetic":"/ˌʌndərˈstændɪŋ/","partOfSpeech":"名词"}],"examPoints":{"points":["动词过去式的使用","名词所有格/所属关系的表达","专业名词的英文对应"],"explanations":["本句描述的是过去发生的、对现在产生影响的事件，因此使用动词change的过去式changed。在英语中，描述已经完成的动作且动作的影响持续到现在时，可使用一般过去时或现在完成时，此处参考翻译使用一般过去时，符合高中阶段对时态的考查要求。","中文中“对时空的认识”表达所属关系，英语中使用介词of来体现这种所属关系，即“understanding of space and time”，这是英语中表达事物所属、关联的常见结构，是高中阶段介词用法的核心考点之一。","“相对论”对应的专业英文词汇是relativity，属于高中阶段拓展的科技类专业名词，需要掌握这类学科相关专业词汇的英文表达，同时“时空”对应的固定搭配是“space and time”，也是物理学科相关的常用英文表达。"]},"sentenceWithHints":"相对论 改变了 我们 对 时空 的 认识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (203, '{"words":[{"plural":"","chinese":"生物","english":"biological","examples":["Biological research helps us understand life better.","There are many biological differences between species."],"phonetic":"/ˌbaɪəˈlɑːdʒɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"evolutions","chinese":"进化论","english":"evolution","examples":["The theory of evolution was put forward by Darwin.","Evolution is a slow process over millions of years."],"phonetic":"/ˌevəˈluːʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"解释","english":"explain","examples":["Please explain this math problem to me.","The report explains the reasons for the company''s success."],"phonetic":"/ɪkˈspleɪn/","pastTense":"explained","thirdPerson":"explains","partOfSpeech":"动词","pastParticiple":"explained","presentParticiple":"explaining"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She has gone to the park."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"species","chinese":"物种","english":"species","examples":["There are thousands of species in the rainforest.","This species is in danger of extinction."],"phonetic":"/ˈspiːʃiːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["The color of the sky is blue.","This is the house of my grandfather."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"origins","chinese":"起源","english":"origin","examples":["Scientists are studying the origin of the universe.","The origin of this custom is unknown."],"phonetic":"/ˈɔːrɪdʒɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She is tall and thin."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"developments","chinese":"发展","english":"development","examples":["The development of technology changes our life.","We are watching the development of the project closely."],"phonetic":"/dɪˈveləpmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["名词所有格/所属关系的表达","主谓一致","学术类名词的积累"],"explanations":["在英语中表达所属关系时，常用“of + 名词”的结构，本句中“物种的起源和发展”译为“the origin and development of species”，“生物进化论”译为“the theory of biological evolution”，都使用了该结构来体现事物间的所属关联。","本句主语“The theory of biological evolution”是单数名词短语，所以谓语动词使用第三人称单数形式“explains”，符合英语中“单数主语搭配单数谓语，复数主语搭配复数谓语”的主谓一致规则。","本句涉及多个高中阶段需要掌握的学术类名词，如evolution（进化）、origin（起源）、species（物种）等，这类词汇是高中英语阅读尤其是科普类文本中的核心词汇，需要准确掌握其词义、拼写和用法。"]},"sentenceWithHints":"生物 进化论 解释 了 物种 的 起源 和 发展"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (204, '{"words":[{"plural":"","chinese":"化学","english":"chemical","examples":["Chemical changes are permanent.","She studies chemical engineering."],"phonetic":"/ˈkemɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"reactions","chinese":"反应","english":"reaction","examples":["Chemical reactions produce new substances.","His reaction to the news was surprising."],"phonetic":"/riˈækʃən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"遵循","english":"follow","examples":["You should follow the rules.","The path follows the river."],"phonetic":"/ˈfɑːloʊ/","pastTense":"followed","thirdPerson":"follows","partOfSpeech":"动词","pastParticiple":"followed","presentParticiple":"following"},{"plural":"masses","chinese":"质量","english":"mass","examples":["The mass of the object is 5 kilograms.","Masses of people gathered in the square."],"phonetic":"/mæs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"conservations","chinese":"守恒","english":"conservation","examples":["Conservation of energy is a basic physics law.","We need to promote conservation of natural resources."],"phonetic":"/ˌkɑːnsərˈveɪʃən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"laws","chinese":"定律","english":"law","examples":["The law of gravity was discovered by Newton.","Everyone must obey the law."],"phonetic":"/lɔː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["专业名词的英文表达","介词短语作定语的用法","主谓一致原则"],"explanations":["本句涉及化学专业领域的核心名词，如“质量守恒定律”对应“the law of conservation of mass”，“化学反应”对应“chemical reactions”，这类专业词汇是高一化学英语衔接的重点，需要准确记忆和区分。","翻译中使用了“the law of conservation of mass”的结构，通过介词“of”构成的介词短语层层修饰中心名词“law”，体现了英语中用后置定语修饰名词的表达习惯，与中文的前置定语顺序不同，是高一阶段需要掌握的重要句法结构。","本句主语“chemical reactions”是复数形式，因此谓语动词使用“follow”的原形，遵循了英语中主谓一致的基本规则：复数主语搭配动词原形（一般现在时），这是高一英语语法的基础考点之一。"]},"sentenceWithHints":"化学 反应 遵循 质量 守恒 定律"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (205, '{"words":[{"plural":"electromagnetic waves","chinese":"电磁波","english":"electromagnetic wave","examples":["Electromagnetic waves travel at the speed of light.","We use electromagnetic waves to send signals."],"phonetic":"/ɪˌlektroʊmæɡˈnetɪk weɪv/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The cover of the book is blue.","This is the result of hard work."],"phonetic":"/ʌv/","partOfSpeech":"助词"},{"plural":"discoveries","chinese":"发现","english":"discovery","examples":["The discovery changed the world.","Her discovery won her a prize."],"phonetic":"/dɪˈskʌvəri/","partOfSpeech":"名词"},{"chinese":"开启","english":"open","examples":["She opened the door quietly.","The new project will open many opportunities."],"phonetic":"/ˈoʊpən/","pastTense":"opened","thirdPerson":"opens","partOfSpeech":"动词","pastParticiple":"opened","presentParticiple":"opening"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She has visited the city."],"phonetic":"","partOfSpeech":"助词"},{"plural":"","chinese":"信息","english":"information","examples":["We need more information to make a decision.","The internet provides a lot of information."],"phonetic":"/ˌɪnfərˈmeɪʃn/","partOfSpeech":"名词"},{"plural":"ages","chinese":"时代","english":"age","examples":["We are living in the digital age.","The Stone Age was a prehistoric period."],"phonetic":"/eɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["名词所有格的表达（of结构）","可数名词复数的用法","一般过去时的使用"],"explanations":["在英语中，表达所属关系时，无生命名词的所有格常用“of + 名词”结构，本句中“电磁波的发现”译为“The discovery of electromagnetic waves”，符合这一用法，区别于有生命名词常用的''s所有格。","可数名词表示一类事物时，常用复数形式，“电磁波”是可数名词，所以译为“electromagnetic waves”，在句中表示这一类事物的整体概念。","本句描述的是过去发生的动作“开启”，这个动作已经完成，所以使用动词open的过去式opened，符合一般过去时用于描述过去已发生动作的语法规则。"]},"sentenceWithHints":"电磁波 的 发现 开启 了 信息 时代"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (206, '{"words":[{"plural":"","chinese":"遗传学","english":"genetics","examples":["Genetics is a branch of biology.","She studies genetics at university."],"phonetic":"/dʒəˈnetɪks/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"探索了","english":"explore","examples":["Scientists explore the deep sea every year.","We are exploring new ways to solve the problem."],"phonetic":"/ɪkˈsplɔːr/","pastTense":"explored","thirdPerson":"explores","partOfSpeech":"动词","pastParticiple":"explored","presentParticiple":"exploring"},{"plural":"lives","chinese":"生命","english":"life","examples":["Life is full of surprises.","Many lives were saved by the doctor."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the cover of the book","a friend of mine"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"inheritances","chinese":"传承","english":"inheritance","examples":["Cultural inheritance is very important.","He received a large inheritance from his grandfather."],"phonetic":"/ɪnˈherɪtəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"mechanisms","chinese":"机制","english":"mechanism","examples":["The body has a natural mechanism to fight disease.","We need to improve the mechanism of public supervision."],"phonetic":"/ˈmekənɪzəm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["学科类名词的主谓一致","名词所有格的介词表达","可数名词的复数形式"],"explanations":["以 -ics 结尾的学科类名词（如 genetics, physics）通常作单数看待，作主语时谓语动词用第三人称单数形式，本句中 explore 用第三人称单数 explores 与之匹配。","中文中“的”表示所属关系时，英文常用介词 of 构成名词短语来表达，如“生命的传承”译为 inheritance of life，“传承机制”译为 mechanisms of inheritance，符合英文后置定语的表达习惯。","可数名词表示泛指的一类事物时常用复数形式，本句中“机制”是可数名词，此处表示生命传承的相关各类机制，所以用复数 mechanisms；规则可数名词变复数一般在词尾加 -s，以 -ism 结尾的名词变复数直接加 -s 即可。"]},"sentenceWithHints":"遗传学 探索了 生命 的 传承 机制"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (207, '{"words":[{"plural":"","chinese":"天文学","english":"astronomy","examples":["Astronomy is one of the oldest sciences.","She has a deep interest in astronomy."],"phonetic":"/əˈstrɑːnəmi/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["He studies math every day.","They have studied this problem for years."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is vast and mysterious.","Scientists are exploring the origins of the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["the roof of the house","the color of the sky"],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"origins","chinese":"起源","english":"origin","examples":["The origin of life is a big mystery.","We need to trace the origin of this rumor."],"phonetic":"/ˈɔːrɪdʒɪn/","partOfSpeech":"名词"},{"chinese":"和","english":"and","examples":["She and I are friends.","We need bread and milk."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"evolutions","chinese":"演化","english":"evolution","examples":["The theory of evolution was put forward by Darwin.","We are studying the evolution of language."],"phonetic":"/ˌevəˈluːʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["学科类名词的用法","动词第三人称单数变化","名词所有格的表达（of结构）","并列名词的用法"],"explanations":["学科类名词如astronomy属于抽象名词，通常为不可数名词，一般不需要加冠词，作主语时视为单数。","当主语是第三人称单数（本句中Astronomy为单数主语）时，一般现在时的动词要使用第三人称单数形式，规则动词study的第三人称单数形式是变y为i加es，即studies。","在英语中表达所属关系时，无生命名词的所有格常用of结构，本句中“宇宙的起源和演化”译为the origin and evolution of the universe，符合这一用法。","当两个并列的名词共同表示相关概念时，使用连词and连接，本句中origin和evolution是并列关系，共同作为study的宾语，符合英语并列成分的表达规则。"]},"sentenceWithHints":"天文学 研究 宇宙 的 起源 和 演化"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (208, '{"words":[{"plural":"ecologies","chinese":"生态学","english":"ecology","examples":["Ecology is the study of living things and their environments.","We need to learn more about ecology to protect our planet."],"phonetic":"/iˈkɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["She studies hard every day.","We studied the history of the city last week."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"organisms","chinese":"生物","english":"organism","examples":["All organisms need water to survive.","Scientists are studying small organisms in the ocean."],"phonetic":"/ˈɔːrɡənɪzəm/","partOfSpeech":"名词"},{"chinese":"与","english":"between","examples":["The river runs between the two mountains.","There is a difference between the two books."],"phonetic":"/bɪˈtwiːn/","partOfSpeech":"介词"},{"plural":"environments","chinese":"环境","english":"environment","examples":["We should protect the natural environment.","Children need a safe environment to grow up."],"phonetic":"/ɪnˈvaɪrənmənt/","partOfSpeech":"名词"},{"chinese":"的","english":"","examples":["This is my mother''s book.","The color of the sky is blue."],"phonetic":"","partOfSpeech":"助词"},{"plural":"interactions","chinese":"相互","english":"interaction","examples":["The interaction between teachers and students is important.","We observed the interaction of the two chemicals."],"phonetic":"/ˌɪntərˈækʃn/","partOfSpeech":"名词"},{"plural":"interactions","chinese":"作用","english":"interaction","examples":["The interaction between the two teams was very intense.","The drug''s interaction with alcohol is dangerous."],"phonetic":"/ˌɪntərˈækʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["学科类名词的用法","介词between的搭配","可数名词的单复数"],"explanations":["学科类名词多为不可数名词，通常单独使用表示学科概念，如本句中的ecology，作主语时谓语动词用第三人称单数形式。","介词between用于表示“在两者之间”，常搭配between...and...的结构，用来连接两个并列的对象，本句中用来连接organisms和the environment，体现两者的相互关系。","可数名词表示泛指一类事物时，常用复数形式，如本句中的organisms；特指某个具体环境时，可加定冠词the，如the environment。同时可数名词单数前通常需要限定词，复数形式可直接表示一类事物。"]},"sentenceWithHints":"生态学 研究 生物 与 环境 的 相互 作用"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (209, '{"words":[{"plural":"geographies","chinese":"地理","english":"geography","examples":["Geography is my favorite subject.","We study human geography this semester."],"phonetic":"/dʒiˈɑːɡrəfi/","partOfSpeech":"名词"},{"plural":"sciences","chinese":"科学","english":"science","examples":["Science helps us understand the world.","She majors in environmental science."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"揭示","english":"reveal","examples":["The report reveals the truth.","Research reveals that exercise is good for health."],"phonetic":"/rɪˈviːl/","pastTense":"revealed","thirdPerson":"reveals","partOfSpeech":"动词","pastParticiple":"revealed","presentParticiple":"revealing"},{"chinese":"了","english":"","examples":["I finished my homework.","She has gone to school."],"phonetic":"","partOfSpeech":"助词"},{"plural":"","chinese":"地球","english":"Earth","examples":["The Earth is our home.","We should protect the Earth."],"phonetic":"/ɜːrθ/","partOfSpeech":"名词"},{"plural":"surfaces","chinese":"表面","english":"surface","examples":["The surface of the lake is calm.","The moon''s surface is covered with craters."],"phonetic":"/ˈsɜːrfɪs/","partOfSpeech":"名词"},{"chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the flower is red."],"phonetic":"","partOfSpeech":"助词"},{"plural":"changes","chinese":"变化","english":"change","examples":["Great changes have taken place in the city.","We need to adapt to change."],"phonetic":"/tʃeɪndʒ/","partOfSpeech":"名词"},{"plural":"laws","chinese":"规律","english":"law","examples":["The law of gravity is important.","Scientists discover new laws of nature."],"phonetic":"/lɔː/","partOfSpeech":"名词"}],"examPoints":{"points":["名词所有格的用法","介词短语作定语","动词第三人称单数形式"],"explanations":["表示有生命的事物的所属关系时，通常在名词后加''s，本句中Earth''s surface表示“地球的表面”，属于有生命概念的事物所属，使用''s所有格形式。","介词短语of change和on the Earth''s surface在句中作定语，分别修饰laws和change，用于明确名词的所属和范围，这是英语中后置定语的常见用法，区别于中文的前置定语结构。","当主语是第三人称单数（本句中Geography作为学科名词，属于第三人称单数主语）时，一般现在时的动词要使用第三人称单数形式，reveal的第三人称单数形式是reveals。"]},"sentenceWithHints":"地理 科学 揭示 了 地球 表面 的 变化 规律"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (210, '{"words":[{"plural":"psychologies","chinese":"心理学","english":"psychology","examples":["Psychology is an interesting subject.","She majors in psychology at university."],"phonetic":"/saɪˈkɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["The scientist studies the effects of climate change.","We have studied this problem for years."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"humans","chinese":"人类","english":"human","examples":["Human beings need water to survive.","This discovery benefits all humans."],"phonetic":"/ˈhjuːmən/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"cognitions","chinese":"认知","english":"cognition","examples":["Cognition includes thinking and memory.","The experiment tests human cognition."],"phonetic":"/kɑːɡˈnɪʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She sings and dances very well."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"behaviors","chinese":"行为","english":"behavior","examples":["His behavior in class is very good.","The study focuses on animal behavior."],"phonetic":"/bɪˈheɪvjər/","partOfSpeech":"名词"}],"examPoints":{"points":["学科类名词的用法","动词第三人称单数形式","并列结构的英文表达"],"explanations":["学科类名词多为不可数名词，一般作单数主语，如本句中的psychology，作主语时谓语动词用单数形式；部分学科名词复数形式可表示该学科的不同分支或多种相关理论。","当主语是第三人称单数（包括单数名词、不可数名词、第三人称单数代词等）时，一般现在时的谓语动词要变为第三人称单数形式，规则变化通常在动词后加-s或-es，本句中主语psychology是单数学科名词，所以动词study变为studies。","在英文中表示并列关系常用连词and连接两个词性、结构相同的成分，本句中and连接了两个并列的名词cognition和behavior，共同作动词studies的宾语，符合英文并列结构的表达规范。"]},"sentenceWithHints":"心理学 研究 人类 的 认知 和 行为"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (211, '{"words":[{"plural":"","chinese":"经济学","english":"economics","examples":["Economics is a social science.","He majors in economics at university."],"phonetic":"/ˌekəˈnɑːmɪks/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"分析","english":"analyze","examples":["We need to analyze the data carefully.","She analyzes market trends for the company."],"phonetic":"/ˈænəlaɪz/","pastTense":"analyzed","thirdPerson":"analyzes","partOfSpeech":"动词","pastParticiple":"analyzed","presentParticiple":"analyzing"},{"plural":"resources","chinese":"资源","english":"resource","examples":["Natural resources are very important.","The country lacks water resources."],"phonetic":"/ˈriːsɔːrs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The cover of the book is blue.","This is a photo of my family."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"allocations","chinese":"配置","english":"allocation","examples":["The allocation of funds needs to be fair.","We discussed the allocation of tasks in the meeting."],"phonetic":"/ˌæləˈkeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She is tall and thin."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"uses","chinese":"利用","english":"use","examples":["The use of new technology improved efficiency.","We need to make good use of our time."],"phonetic":"/juːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["学科类集合名词的主谓一致","名词所有格/所属关系的表达","动词第三人称单数变化"],"explanations":["像economics这类表示学科的集合名词，形式上是复数，但在表示学科概念时作单数看待，作主语时谓语动词要用第三人称单数形式，本句中主语Economics为学科名词，所以谓语动词用analyzes。","英语中表示所属关系时，当被修饰的名词在前，修饰的名词在后，常用介词of连接，本句中“资源的配置和利用”采用“the allocation and use of resources”的结构来表达所属关系，符合英语的表达习惯。","一般情况下，动词的第三人称单数形式是在动词原形后加-s，以s、x、sh、ch等结尾的动词加-es，analyze是以不发音的e结尾的动词，变第三人称单数时直接加-s，即analyzes。"]},"sentenceWithHints":"经济学 分析 资源 的 配置 和 利用"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (212, '{"words":[{"plural":"","chinese":"政治学","english":"political science","examples":["Political science is a social science discipline.","She majors in political science at university."],"phonetic":"/pəˈlɪtɪkl ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["She studies hard every day.","We are studying the history of ancient China."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"countries","chinese":"国家","english":"country","examples":["Many countries are members of the United Nations.","She wants to travel to different countries."],"phonetic":"/ˈkʌntri/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"","chinese":"治理","english":"governance","examples":["Good governance is essential for a stable society.","The country is working to improve its governance system."],"phonetic":"/ˈɡʌvərnəns/","partOfSpeech":"名词"},{"chinese":"和","english":"and","examples":["I like apples and bananas.","She sings and dances very well."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"societies","chinese":"社会","english":"society","examples":["Society has changed a lot in the past 100 years.","We should contribute to building a better society."],"phonetic":"/səˈsaɪəti/","partOfSpeech":"名词"},{"plural":"","chinese":"管理","english":"management","examples":["The management of the company is very efficient.","Good time management is important for students."],"phonetic":"/ˈmænɪdʒmənt/","partOfSpeech":"名词"}],"examPoints":{"points":["名词所有格的介词表达（of结构）","主谓一致","可数名词复数的使用"],"explanations":["在英语中，表达所属关系除了''s所有格外，还常用of结构，当被修饰的名词是无生命事物或者较为抽象的名词时，多使用of结构。本句中“国家的治理”“社会的管理”都采用of结构“the governance of countries”“the management of society”来体现所属关系。","本句主语“Political science”是单数学科名词，属于第三人称单数，所以谓语动词study要使用第三人称单数形式studies，这体现了英语中主谓一致的规则，即主语和谓语在人称和数上保持一致。","“国家”对应的英文country是可数名词，这里表示泛指的多个国家，所以需要使用复数形式countries；而“社会”对应的society在这里表示抽象的整体社会概念，常用单数形式，这需要区分可数名词在泛指具体事物和抽象概念时的不同用法。"]},"sentenceWithHints":"政治学 研究 国家 的 治理 和 社会 的 管理"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (213, '{"words":[{"plural":"sociologies","chinese":"社会学","english":"sociology","examples":["Sociology is a fascinating social science.","She is majoring in sociology at university."],"phonetic":"/ˌsoʊsiˈɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["The professor studies ancient civilizations.","We need to study the problem carefully."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"","chinese":"社会","english":"social","examples":["We have many social responsibilities.","She enjoys social activities with friends."],"phonetic":"/ˈsoʊʃl/","partOfSpeech":"形容词"},{"plural":"structures","chinese":"结构","english":"structure","examples":["The structure of the building is very stable.","We need to analyze the social structure of the community."],"phonetic":"/ˈstrʌktʃər/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She is smart and hard-working."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"changes","chinese":"变迁","english":"change","examples":["We are witnessing great social change.","Climate change is a serious global issue."],"phonetic":"/tʃeɪndʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["学科类名词的用法","动词第三人称单数形式","形容词修饰名词的用法","并列连词and的用法"],"explanations":["学科类名词多为不可数名词，作为单数概念使用，作主语时谓语动词用第三人称单数形式，如本句中sociology作主语，谓语动词study用第三人称单数studies。","当主语是第三人称单数（包括单数名词、不可数名词、第三人称单数代词等）时，一般现在时的谓语动词要使用第三人称单数形式，规则变化通常是在动词后加-s，以辅音字母+y结尾的动词变y为i加-es，本句中study以辅音字母+y结尾，第三人称单数形式为studies。","形容词可以用来修饰名词，放在名词前作定语，说明名词的性质或特征，本句中social作为形容词，分别修饰structure和change，说明是“社会的结构”和“社会的变迁”。","并列连词and用来连接语法地位相同的词、短语或句子，本句中and连接social structure和social change两个并列的名词短语，作为动词studies的宾语。"]},"sentenceWithHints":"社会学 研究 社会 结构 和 社会 变迁"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (214, '{"words":[{"plural":"histories","chinese":"历史学","english":"history","examples":["History is my favorite subject.","We are learning about ancient Chinese history."],"phonetic":"/ˈhɪstri/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["She studies hard every day.","We studied the history of Rome last semester."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"humans","chinese":"人类","english":"human","examples":["Humans have existed for thousands of years.","This technology is designed to help humans."],"phonetic":"/ˈhjuːmən/","partOfSpeech":"名词"},{"plural":"civilizations","chinese":"文明","english":"civilization","examples":["Ancient Egypt was a great civilization.","The book explores the rise and fall of civilizations."],"phonetic":"/ˌsɪvələˈzeɪʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"developments","chinese":"发展","english":"development","examples":["The development of technology changes our lives.","We are excited about the new developments in the project."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"plural":"trajectories","chinese":"轨迹","english":"trajectory","examples":["The rocket is on a new trajectory.","We are analyzing the trajectory of the company''s growth."],"phonetic":"/trəˈdʒektəri/","partOfSpeech":"名词"}],"examPoints":{"points":["名词所有格的英文表达","动词第三人称单数形式","抽象名词的用法"],"explanations":["中文中“的”表示所属关系时，英文常用介词“of”构成名词所有格结构，本句中“人类文明的发展轨迹”译为“the trajectory of human civilization”，就是用“of”来体现多层所属关系。","当主语是第三人称单数（本句中“History”为单数名词，属于第三人称单数）时，一般现在时的动词要使用第三人称单数形式，“study”的第三人称单数形式是“studies”。","本句中的“历史学”“文明”“发展”“轨迹”都属于抽象名词，这类名词通常表示抽象概念，多数为不可数名词，部分可数抽象名词有复数形式，可用来表示不同的类别或具体的实例，比如“civilizations”可以表示不同的人类文明。"]},"sentenceWithHints":"历史学 研究 人类 文明 的 发展 轨迹"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (215, '{"words":[{"plural":"philosophies","chinese":"哲学","english":"philosophy","examples":["Philosophy helps us think deeply about life.","She majors in philosophy at university."],"phonetic":"/fəˈlɑːsəfi/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["He studies hard for the exam.","They are studying ancient history."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"existences","chinese":"存在","english":"existence","examples":["We often question the meaning of existence.","The existence of aliens is still a mystery."],"phonetic":"/ɪɡˈzɪstəns/","partOfSpeech":"名词"},{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","She has a wide range of knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She sings and dances well."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"values","chinese":"价值","english":"value","examples":["We need to discuss the value of this project.","Our personal values guide our decisions."],"phonetic":"/ˈvæljuː/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["This is a photo of my family.","The top of the mountain is covered with snow."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"problems","chinese":"问题","english":"problem","examples":["We need to solve this problem quickly.","He has many health problems."],"phonetic":"/ˈprɑːbləm/","partOfSpeech":"名词"}],"examPoints":{"points":["动词第三人称单数变化","名词所有格/所属关系表达","并列结构的英文表达"],"explanations":["本句主语\"philosophy\"是单数可数名词，作主语时谓语动词要用第三人称单数形式，study的第三人称单数是studies，规则动词以辅音字母+y结尾，变y为i加-es。","中文中“存在、知识和价值的问题”表达所属关系，英文中常用介词of来连接，构成“problems of existence, knowledge, and value”的结构，用来指明问题的所属范畴。","中文里用“和”连接并列的名词，英文中用连词and连接多个并列成分，在美式英语中，最后一个并列成分前通常也会加上and（牛津逗号），使并列结构更清晰，本句中“existence, knowledge, and value”就使用了这种规范写法。"]},"sentenceWithHints":"哲学 研究 存在、 知识 和 价值 的 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (216, '{"words":[{"chinese":"数字","english":"digital","examples":["Digital products are very popular now.","We need to improve our digital skills."],"phonetic":"/ˈdɪdʒɪtl/","partOfSpeech":"形容词"},{"plural":"twins","chinese":"孪生","english":"twin","examples":["She has a twin sister.","The twin towers are famous landmarks."],"phonetic":"/twɪn/","partOfSpeech":"名词"},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology makes our life easier.","We should learn new technologies."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"正在","english":"be + -ing","examples":["He is reading a book.","They are playing football."],"phonetic":"/biː/ /ˈɪŋ/","partOfSpeech":"助词"},{"chinese":"改变","english":"change","examples":["She wants to change her job.","The weather changes quickly in spring."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"chinese":"工业","english":"industrial","examples":["Industrial development is important for the country.","This area has many industrial factories."],"phonetic":"/ɪnˈdʌstriəl/","partOfSpeech":"形容词"},{"plural":"productions","chinese":"生产","english":"production","examples":["The factory increases its production every year.","Film production is a complex process."],"phonetic":"/prəˈdʌkʃn/","partOfSpeech":"名词"},{"plural":"models","chinese":"模式","english":"model","examples":["We need a new business model.","This model of car is very popular."],"phonetic":"/ˈmɑːdl/","partOfSpeech":"名词"}],"examPoints":{"points":["现在进行时的用法","复合名词的表达","可数名词复数形式"],"explanations":["现在进行时结构为\"am/is/are + 现在分词\"，表示当前正在进行的动作。本句中主语\"Digital twin technology\"是单数第三人称，所以用\"is changing\"来体现技术当前正在发生的改变。","复合名词由多个名词或形容词加名词构成，本句中\"Digital twin technology\"和\"industrial production models\"都是复合名词结构，用于精准表达特定领域的概念，这类表达在科技类英语中较为常见，需要掌握其组合逻辑。","可数名词表示泛指一类事物时通常用复数形式，本句中\"models\"是\"model\"的复数形式，用来指代各类工业生产模式，符合英语中泛指概念的表达习惯。"]},"sentenceWithHints":"数字 孪生 技术 正在 改变 工业 生产 模式"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (217, '{"words":[{"plural":"blockchains","chinese":"区块链","english":"blockchain","examples":["Blockchain is a secure digital ledger.","Many industries are exploring blockchain applications."],"phonetic":"/ˈblɑːktʃeɪn/","partOfSpeech":"名词"},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology changes our life greatly.","This company is leading in green technology."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"提供","english":"provide","examples":["The hotel provides free breakfast for guests.","We need to provide more support for the project."],"phonetic":"/prəˈvaɪd/","pastTense":"provided","thirdPerson":"provides","partOfSpeech":"动词","pastParticiple":"provided","presentParticiple":"providing"},{"plural":"","chinese":"了","english":"","examples":["我完成了作业。","天气变热了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"新的","english":"new","examples":["She bought a new dress.","This is a new way to solve the problem."],"phonetic":"/nuː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"trusts","chinese":"信任","english":"trust","examples":["Trust is the foundation of a good relationship.","We put our trust in his ability."],"phonetic":"/trʌst/","partOfSpeech":"名词"},{"plural":"mechanisms","chinese":"机制","english":"mechanism","examples":["The body has a natural mechanism to fight disease.","We need a better mechanism for feedback."],"phonetic":"/ˈmekənɪzəm/","partOfSpeech":"名词"}],"examPoints":{"points":["主谓一致","可数名词单数的冠词使用","科技类词汇的识记"],"explanations":["本句主语“Blockchain technology”是单数不可数概念，所以谓语动词使用第三人称单数形式provides，符合英语中“单数主语搭配单数谓语动词”的主谓一致规则。","句中“a new trust mechanism”里的mechanism是可数名词单数，且以辅音音素开头，所以前面用不定冠词a来修饰，这是可数名词单数在泛指时的常规用法。","本句涉及blockchain、mechanism等高中阶段需要掌握的科技类核心词汇，这类词汇在阅读理解和书面表达的科技主题语境中高频出现，需要准确识记其拼写、含义和用法。"]},"sentenceWithHints":"区块链 技术 提供 了 新 的 信任 机制"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (218, '{"words":[{"plural":"","chinese":"虚拟","english":"virtual","examples":["Virtual reality is becoming more popular.","We held a virtual meeting last week."],"phonetic":"/ˈvɜːrtʃuəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"realities","chinese":"现实","english":"reality","examples":["Finally, his dream became a reality.","She can''t distinguish between fantasy and reality."],"phonetic":"/riˈæləti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology changes our life a lot.","This company is good at developing new technologies."],"phonetic":"/tekˈnɑːlədʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"创造","english":"create","examples":["She wants to create a new kind of art.","The artist created a beautiful painting last year."],"phonetic":"/kriˈeɪt/","pastTense":"created","thirdPerson":"creates","partOfSpeech":"动词","pastParticiple":"created","presentParticiple":"creating"},{"plural":"","chinese":"了","english":"/","examples":["I have finished my homework.","She bought a new dress yesterday."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"全新","english":"brand new","examples":["We moved into a brand new house.","The company launched a brand new product."],"phonetic":"/brænd nuː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"/","examples":["This is my mother''s bag.","The book on the desk is mine."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"experiences","chinese":"体验","english":"experience","examples":["Travelling gives us different experiences.","She had a wonderful experience in Paris."],"phonetic":"/ɪkˈspɪriəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"ways","chinese":"方式","english":"way","examples":["There are many ways to solve this problem.","This is the best way to learn English."],"phonetic":"/weɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["专业名词的英文表达","一般现在时主谓一致","形容词短语作定语"],"explanations":["“虚拟现实技术”对应的固定专业英文表达为“Virtual reality technology”，属于科技类常用词汇，是高中阶段需要掌握的专业领域词汇，在阅读和写作中会涉及相关话题。","本句主语“Virtual reality technology”是单数概念的不可数名词短语，谓语动词需要用第三人称单数形式，因此“创造”对应的“create”要变为“creates”，这是一般现在时主谓一致的核心考点，要求根据主语的单复数确定谓语动词形式。","“全新的”对应的英文是形容词短语“brand new”，在句中作定语修饰“experience”，形容词短语作定语通常置于被修饰名词之前，这类固定短语的搭配和用法是高中阶段词汇运用的重点，需要准确记忆和使用。"]},"sentenceWithHints":"虚拟 现实 技术 创造 了 全新 的 体验 方式"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (219, '{"words":[{"plural":"","chinese":"5G","english":"5G","examples":["5G is faster than 4G.","Many countries are developing 5G technology."],"phonetic":"/faɪv dʒiː/","partOfSpeech":"名词"},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology changes our life.","We need to learn new technology."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my mom.","This book is for children."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"plural":"","chinese":"万物互联","english":"the Internet of Everything","examples":["The Internet of Everything connects all devices.","We are entering the era of the Internet of Everything."],"phonetic":"/ðə ˈɪntərnət əv ˈevriθɪŋ/","partOfSpeech":"名词"},{"chinese":"奠定","english":"lay","examples":["This agreement lays a solid foundation for future cooperation.","He laid the groundwork for the project."],"phonetic":"/leɪ/","pastTense":"laid","thirdPerson":"lays","partOfSpeech":"动词","pastParticiple":"laid","presentParticiple":"laying"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She has eaten the cake."],"phonetic":"","partOfSpeech":"助词"},{"plural":"foundations","chinese":"基础","english":"foundation","examples":["Hard work is the foundation of success.","The foundation of the building is strong."],"phonetic":"/faʊnˈdeɪʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["动词 lay 的用法","专有名词的英译","介词 for 的用法"],"explanations":["lay 作为及物动词有“奠定、放置”的含义，属于不规则动词，过去式和过去分词均为 laid，第三人称单数形式为 lays，现在分词为 laying。本句主语“5G technology”是第三人称单数，一般现在时中谓语动词使用第三人称单数形式 lays。","“万物互联”是特定的科技专有名词，固定英译表达为 the Internet of Everything，这类专有名词需要牢记固定搭配，首字母大写。","介词 for 在这里表示“为了、给”，用于引出动作的对象或目的，常用结构为“lay the foundation for sth.”，意为“为某事奠定基础”，是高频固定搭配。"]},"sentenceWithHints":"5G 技术 为 万物互联 奠定 了 基础"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (220, '{"words":[{"plural":"edges","chinese":"边缘","english":"edge","examples":["The edge of the table is broken.","She stood at the edge of the cliff."],"phonetic":"/edʒ/","partOfSpeech":"名词"},{"plural":"","chinese":"计算","english":"computing","examples":["Cloud computing is very popular now.","Edge computing has developed rapidly in recent years."],"phonetic":"/kəmˈpjuːtɪŋ/","partOfSpeech":"名词"},{"chinese":"提高","english":"improve","examples":["Reading can improve your vocabulary.","We need to improve our working efficiency."],"phonetic":"/ɪmˈpruːv/","pastTense":"improved","thirdPerson":"improves","partOfSpeech":"动词","pastParticiple":"improved","presentParticiple":"improving"},{"plural":"","chinese":"了","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"data","chinese":"数据","english":"data","examples":["We need to analyze the data carefully.","This system can store a large amount of data."],"phonetic":"/ˈdeɪtə/","partOfSpeech":"名词"},{"plural":"","chinese":"处理","english":"processing","examples":["Data processing is an important part of the work.","The processing of the application will take a week."],"phonetic":"/ˈproʊsesɪŋ/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"efficiencies","chinese":"效率","english":"efficiency","examples":["We should work to improve efficiency.","The new machine has greatly increased production efficiency."],"phonetic":"/ɪˈfɪʃnsi/","partOfSpeech":"名词"}],"examPoints":{"points":["专业名词的英文表达","动词第三人称单数形式","名词所有格/所属关系的英文表达"],"explanations":["本句涉及科技领域专业名词，如“边缘计算”对应“Edge computing”、“数据处理”对应“data processing”，这类专业词汇是高中阶段科技类英语学习的重点，需要准确记忆和运用。","句子主语“Edge computing”是单数概念的动名词短语，作主语时谓语动词要用第三人称单数形式，所以“提高”对应的动词“improve”要变为“improves”，这是主谓一致语法点的重要应用场景。","中文中“数据处理的效率”表达所属关系，英文中常用“the efficiency of data processing”这种“名词+of+名词短语”的结构来体现所属，这是英语中表达无生命事物所属关系的常用方式，区别于有生命事物的“''s”所有格形式。"]},"sentenceWithHints":"边缘 计算 提高 了 数据 处理 的 效率"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (221, '{"words":[{"plural":"clouds","chinese":"云","english":"cloud","examples":["The sky is full of white clouds.","A dark cloud is coming."],"phonetic":"/klaʊd/","partOfSpeech":"名词"},{"plural":"","chinese":"计算","english":"computing","examples":["Cloud computing is very popular now.","We need more computing power."],"phonetic":"/kəmˈpjuːtɪŋ/","partOfSpeech":"名词"},{"chinese":"为","english":"for","examples":["I bought a gift for my mom.","This book is for children."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"plural":"data（常用复数形式）","chinese":"数据","english":"data","examples":["We need to analyze the data.","The data shows a clear trend."],"phonetic":"/ˈdeɪtə/","partOfSpeech":"名词"},{"plural":"","chinese":"存储","english":"storage","examples":["We need more storage space.","Cloud storage is convenient."],"phonetic":"/ˈstɔːrɪdʒ/","partOfSpeech":"名词"},{"chinese":"和","english":"and","examples":["I like apples and bananas.","He is tall and strong."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"","chinese":"计算","english":"computing","examples":["Cloud computing is very popular now.","We need more computing power."],"phonetic":"/kəmˈpjuːtɪŋ/","partOfSpeech":"名词"},{"chinese":"提供","english":"provide","examples":["The hotel provides free breakfast.","She provides help to the poor."],"phonetic":"/prəˈvaɪd/","pastTense":"provided","thirdPerson":"provides","partOfSpeech":"动词","pastParticiple":"provided","presentParticiple":"providing"},{"chinese":"了","english":"","examples":["I have finished my homework.","She bought a new dress."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"强大","english":"strong","examples":["He has a strong body.","This is a strong team."],"phonetic":"/strɔːŋ/","partOfSpeech":"形容词"},{"plural":"supports","chinese":"支持","english":"support","examples":["We need your support.","The government provides support for small businesses."],"phonetic":"/səˈpɔːrt/","partOfSpeech":"名词"}],"examPoints":{"points":["动宾短语的英文表达","介词for的用法","第三人称单数动词变化"],"explanations":["中文中“提供支持”是动宾结构，英文对应“provide support”，这里support作为名词使用，符合英文的表达习惯，在科技类文本中常这样搭配使用。","介词for在这里用来引出动作的对象或用途，“provide sth. for sth./sb.”是固定搭配，表示“为某事/某人提供某物”，本句中表示云计算为数据存储和计算提供支持。","本句主语“Cloud computing”是不可数名词短语，属于第三人称单数，所以谓语动词provide需要使用第三人称单数形式provides，这是高中阶段主谓一致的重要考点，当主语是单数概念时，一般现在时的谓语动词要使用第三人称单数形式。"]},"sentenceWithHints":"云 计算 为 数据 存储 和 计算 提供 了 强大 支持"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (222, '{"words":[{"plural":"","chinese":"大","english":"big","examples":["This is a big house.","She has a big dream."],"phonetic":"/bɪɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"data","chinese":"数据","english":"data","examples":["We need to analyze the data.","The data shows a clear trend."],"phonetic":"/ˈdeɪtə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"analyses","chinese":"分析","english":"analysis","examples":["The analysis of the results took weeks.","His analysis was very thorough."],"phonetic":"/əˈnæləsɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"帮助","english":"help","examples":["She helps me with my homework.","Technology helps improve our lives."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"","chinese":"我们","english":"us","examples":["He told us a story.","Please give us some advice."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"发现","english":"discover","examples":["Scientists discovered a new species.","I discovered a great café near my house."],"phonetic":"/dɪˈskʌvər/","pastTense":"discovered","thirdPerson":"discovers","partOfSpeech":"动词","pastParticiple":"discovered","presentParticiple":"discovering"},{"plural":"","chinese":"隐藏","english":"hidden","examples":["There are hidden dangers in the forest.","She found a hidden treasure."],"phonetic":"/ˈhɪdn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the color of the sky","the door of the room"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"patterns","chinese":"模式","english":"pattern","examples":["The pattern on the fabric is beautiful.","We can see a pattern in his behavior."],"phonetic":"/ˈpætərn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词 help 的用法","名词的单复数与特殊形式","形容词作定语的用法"],"explanations":["动词 help 常见用法有 help sb. do sth.（帮助某人做某事），此处省略不定式符号 to，这是高中阶段需要掌握的固定搭配；同时本句主语 Big data analysis 是单数概念，所以 help 用第三人称单数形式 helps。","data 是 datum 的复数形式，在现代英语中常被当作复数或不可数名词使用；analysis 是不规则名词，其复数形式为 analyses，需要特殊记忆；pattern 是规则可数名词，复数形式直接加 -s。","hidden 是动词 hide 的过去分词形式，此处用作形容词修饰名词 patterns，作前置定语，过去分词作定语表示被动或完成的含义，此处表示“被隐藏的”，这是非谓语动词作定语的重要用法。"]},"sentenceWithHints":"大 数据 分析 帮助 我们 发现 隐藏 的 模式"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (223, '{"words":[{"plural":"machines","chinese":"机器","english":"machine","examples":["This machine is used for printing.","The old machine doesn''t work anymore."],"phonetic":"/məˈʃiːn/","partOfSpeech":"名词"},{"plural":"","chinese":"学习","english":"learning","examples":["Machine learning is a branch of AI.","Learning a new language takes time."],"phonetic":"/ˈlɜːrnɪŋ/","partOfSpeech":"名词"},{"chinese":"使","english":"enable","examples":["This software enables us to edit videos easily.","The new law will enable more people to get medical care."],"phonetic":"/ɪˈneɪbl/","pastTense":"enabled","thirdPerson":"enables","partOfSpeech":"动词","pastParticiple":"enabled","presentParticiple":"enabling"},{"plural":"computers","chinese":"计算机","english":"computer","examples":["I use my computer to work from home.","The school has a room full of computers."],"phonetic":"/kəmˈpjuːtər/","partOfSpeech":"名词"},{"chinese":"能够","english":"to","examples":["I want to go to the park.","She hopes to become a doctor."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"从","english":"from","examples":["I come from Canada.","We learn a lot from our mistakes."],"phonetic":"/frʌm/","partOfSpeech":"介词"},{"plural":"data","chinese":"数据","english":"data","examples":["We need to analyze the data carefully.","The company collects a large amount of data every day."],"phonetic":"/ˈdeɪtə/","partOfSpeech":"名词"},{"chinese":"中","english":"","examples":["",""],"phonetic":"","partOfSpeech":"助词"},{"chinese":"学习","english":"learn","examples":["Children learn quickly.","I''m learning how to play the guitar."],"phonetic":"/lɜːrn/","pastTense":"learned","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned","presentParticiple":"learning"}],"examPoints":{"points":["固定搭配 enable sb. to do sth.","专有名词翻译","不可数名词/复数同形名词的用法"],"explanations":["enable 作为及物动词，常用固定搭配为 enable sb. to do sth.，意为“使某人能够做某事”，其中 to 是不定式符号，后面接动词原形，本句中“使计算机能够学习”就对应这个搭配，使用 enables computers to learn。","“机器学习”属于专业领域的专有名词，固定翻译为 Machine learning，首字母需要大写，这类词汇在科技类英语中属于常见考点，需要准确记忆。","data 是复数同形的名词，它的单数形式为 datum，但在现代英语中 data 常被当作不可数名词使用，在表示“数据”这一整体概念时，可直接使用，本句中 from data 就体现了这一用法；另外 computer 是可数名词，这里用复数 computers 表示一类事物，也是高中阶段可数名词表类别的常见用法。"]},"sentenceWithHints":"机器 学习 使 计算机 能够 从 数据 中 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (224, '{"words":[{"plural":"","chinese":"深度","english":"deep","examples":["The lake is very deep.","He has a deep understanding of the subject."],"phonetic":"/diːp/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"learnings","chinese":"学习","english":"learning","examples":["Machine learning is a hot topic.","Learning a new language takes time."],"phonetic":"/ˈlɜːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"in","examples":["She is in the classroom.","He works in the IT field."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"images","chinese":"图像","english":"image","examples":["This image is very clear.","She painted an image of a cat."],"phonetic":"/ˈɪmɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"recognitions","chinese":"识别","english":"recognition","examples":["Face recognition is widely used.","Her work received recognition from her peers."],"phonetic":"/ˌrekəɡˈnɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"fields","chinese":"领域","english":"field","examples":["He is an expert in this field.","The field of medicine is constantly developing."],"phonetic":"/fiːld/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"取得","english":"make","examples":["She made a cake for her birthday.","They have made great progress."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"了","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"breakthroughs","chinese":"突破","english":"breakthrough","examples":["Scientists have made a major breakthrough.","This is a breakthrough in technology."],"phonetic":"/ˈbreɪkθruː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","专业领域名词的英译","介词短语表范围的用法"],"explanations":["现在完成时结构为have/has+过去分词，用于表示过去发生的动作对现在造成的影响或结果。本句中“取得了突破”强调这个成果对当下的影响，主语Deep learning是单数概念，所以用has made。","在科技类语境中，“深度学习”固定译为Deep learning，“图像识别”固定译为image recognition，这类专业名词属于高中阶段拓展词汇，需要积累特定领域的固定表达。","介词in用于表示在某个领域、范围之内，“在图像识别领域”译为in the field of image recognition，其中of用于表示所属关系，构成名词所有格结构，说明field的具体内容。"]},"sentenceWithHints":"深度 学习 在 图像 识别 领域 取得 了 突破"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (225, '{"words":[{"chinese":"自然","english":"natural","examples":["Natural resources are important.","She has a natural talent for music."],"phonetic":"/ˈnætʃrəl/","partOfSpeech":"形容词"},{"plural":"languages","chinese":"语言","english":"language","examples":["English is a global language.","She can speak three languages."],"phonetic":"/ˈlæŋɡwɪdʒ/","partOfSpeech":"名词"},{"plural":"processings","chinese":"处理","english":"processing","examples":["Data processing is a key part of the job.","The processing of applications takes two weeks."],"phonetic":"/ˈproʊsesɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"enable","examples":["This tool enables us to work faster.","New technology enables better communication."],"phonetic":"/ɪˈneɪbl/","pastTense":"enabled","thirdPerson":"enables","partOfSpeech":"动词","pastParticiple":"enabled","presentParticiple":"enabling"},{"plural":"computers","chinese":"计算机","english":"computer","examples":["I use a computer for work.","The store sells various computers."],"phonetic":"/kəmˈpjuːtər/","partOfSpeech":"名词"},{"chinese":"能够","english":"to","examples":["I want to go home.","She needs to finish her homework."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"理解","english":"understand","examples":["I don''t understand this question.","She understands French well."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"chinese":"人类","english":"human","examples":["Human rights are important.","This is a human-made problem."],"phonetic":"/ˈhjuːmən/","partOfSpeech":"形容词"}],"examPoints":{"points":["专业术语英译","enable的用法","动词不定式作宾语补足语"],"explanations":["本句涉及专业术语“自然语言处理”，对应的标准英文表达为“Natural language processing”，属于人工智能领域常见术语，需要掌握这类专业词汇的固定译法。","enable作为及物动词，常见用法为enable sb./sth. to do sth.，表示“使某人/某物能够做某事”，主语通常是事物，本句中主语“Natural language processing”是事物，符合该用法。","在enable computers to understand human language结构中，to understand是动词不定式，在句中作宾语computers的补足语，补充说明宾语的动作，这是动词不定式的常见用法之一，需要掌握该结构的使用场景。"]},"sentenceWithHints":"自然 语言 处理 让 计算机 能够 理解 人类 语言"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (226, '{"words":[{"plural":"computers","chinese":"计算机","english":"computer","examples":["I use a computer to study.","The computer is broken."],"phonetic":"/kəmˈpjuːtər/","partOfSpeech":"名词"},{"plural":"visions","chinese":"视觉","english":"vision","examples":["She has poor vision.","The company has a clear vision for the future."],"phonetic":"/ˈvɪʒn/","partOfSpeech":"名词"},{"chinese":"让","english":"enable","examples":["This tool enables us to work faster.","New technology enabled the project to succeed."],"phonetic":"/ɪˈneɪbl/","pastTense":"enabled","thirdPerson":"enables","partOfSpeech":"动词","pastParticiple":"enabled","presentParticiple":"enabling"},{"plural":"machines","chinese":"机器","english":"machine","examples":["The factory uses many machines.","This machine can print documents."],"phonetic":"/məˈʃiːn/","partOfSpeech":"名词"},{"plural":"","chinese":"能够","english":"to","examples":["I want to go home.","She needs to finish her homework."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"看懂","english":"understand","examples":["I don''t understand this question.","She understands how to solve the problem."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He traveled around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"}],"examPoints":{"points":["enable 的用法","动词不定式作宾语补足语","专业名词的英文表达"],"explanations":["enable 作为及物动词，常见用法为 enable sb./sth. to do sth.，意为“使某人/某物能够做某事”，主语通常是某种事物、工具或条件，本句中主语 Computer vision 是抽象事物，符合该用法。","在 enable machines to understand the world 结构中，to understand the world 是动词不定式，在句中作宾语 machines 的补足语，补充说明 machines 被赋予的能力，这是高中阶段需要掌握的非谓语动词核心用法之一。","“计算机视觉”对应的英文专业表达为 Computer vision，属于科技领域固定搭配，这类专业名词在高中英语拓展学习和阅读中会涉及，需要准确记忆其英文表达和含义。"]},"sentenceWithHints":"计算机 视觉 让 机器 能够 看懂 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (227, '{"words":[{"plural":"things","chinese":"物","english":"thing","examples":["I have many things to do today.","This thing is very useful."],"phonetic":"/θɪŋ/","partOfSpeech":"名词"},{"chinese":"联","english":"connect","examples":["Please connect the two wires.","The road connects the two villages."],"phonetic":"/kəˈnekt/","pastTense":"connected","thirdPerson":"connects","partOfSpeech":"动词","pastParticiple":"connected","presentParticiple":"connecting"},{"plural":"networks","chinese":"网","english":"network","examples":["The company has a large computer network.","We need to build a better communication network."],"phonetic":"/ˈnetwɜːrk/","partOfSpeech":"名词"},{"chinese":"实","english":"realize","examples":["I finally realized my dream.","She realized she was wrong."],"phonetic":"/ˈriːəlaɪz/","pastTense":"realized","thirdPerson":"realizes","partOfSpeech":"动词","pastParticiple":"realized","presentParticiple":"realizing"},{"chinese":"现","english":"achieve","examples":["He achieved great success in his career.","We can achieve our goals if we work hard."],"phonetic":"/əˈtʃiːv/","pastTense":"achieved","thirdPerson":"achieves","partOfSpeech":"动词","pastParticiple":"achieved","presentParticiple":"achieving"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She went to the park yesterday."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"设","english":"set","examples":["Please set the table for dinner.","He set a new record in the race."],"phonetic":"/set/","pastTense":"set","thirdPerson":"sets","partOfSpeech":"动词","pastParticiple":"set","presentParticiple":"setting"},{"plural":"","chinese":"备","english":"equipment","examples":["The factory has advanced equipment.","We need to buy some new office equipment."],"phonetic":"/ɪˈkwɪpmənt/","partOfSpeech":"名词"},{"plural":"","chinese":"之","english":"of","examples":["The roof of the house is broken.","This is a photo of my family."],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"间","english":"between","examples":["I sit between Tom and Mary.","There is a river between the two cities."],"phonetic":"/bɪˈtwiːn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the flower is red."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"智","english":"intelligence","examples":["Dogs have a high level of intelligence.","Artificial intelligence is developing rapidly."],"phonetic":"/ɪnˈtelɪdʒəns/","partOfSpeech":"名词"},{"plural":"","chinese":"能","english":"able","examples":["He is able to speak three languages.","I''m not able to come to the party."],"phonetic":"/ˈeɪbəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"互","english":"mutual","examples":["We have mutual respect for each other.","They made a mutual agreement."],"phonetic":"/ˈmjuːtʃuəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"chinese":"联","english":"connect","examples":["Please connect the two wires.","The road connects the two villages."],"phonetic":"/kəˈnekt/","pastTense":"connected","thirdPerson":"connects","partOfSpeech":"动词","pastParticiple":"connected","presentParticiple":"connecting"}],"examPoints":{"points":["专有名词的英译","enable 动词的用法","介词 between 的用法","形容词作定语的用法"],"explanations":["“物联网”是特定领域专有名词，标准英译为“The Internet of Things”，缩写为IoT，属于固定表达，需要掌握这类科技类专有名词的规范翻译。","enable 作为及物动词，常见用法为 enable sb./sth. to do sth.，表示“使……能够做某事”，在本句中主语是“The Internet of Things”，宾语是“intelligent interconnection”，体现了该动词在科技语境下的用法。","between 用于表示“在两者或多者之间”，通常连接明确的个体或群体，本句中“between devices”表示在多个设备彼此之间的范围，要注意其和 among 的区别，among 多用于三者及以上的笼统范围。","形容词“intelligent”在句中作定语修饰名词“interconnection”，用来说明互联的属性是智能的，这是形容词的基本用法之一，在科技文本中常用来修饰专业名词，需要掌握形容词修饰名词的位置和逻辑关系。"]},"sentenceWithHints":"物 联 网 实 现 了 设 备 之 间 的 智 能 互 联"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (228, '{"words":[{"chinese":"智能","english":"smart","examples":["This is a smart phone.","She is a smart girl."],"phonetic":"/smɑːrt/","partOfSpeech":"形容词"},{"plural":"homes","chinese":"家居","english":"home","examples":["Smart homes are popular now.","He has two homes."],"phonetic":"/hoʊm/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"lives","chinese":"生活","english":"life","examples":["Smart homes make life easier.","People''s lives are getting better."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"更加","english":"more","examples":["She is more beautiful than before.","This book is more interesting."],"phonetic":"/mɔːr/","partOfSpeech":"副词"},{"chinese":"便捷","english":"convenient","examples":["Online shopping is very convenient.","It''s convenient to take the subway."],"phonetic":"/kənˈviːniənt/","partOfSpeech":"形容词"},{"chinese":"舒适","english":"comfortable","examples":["This chair is very comfortable.","We had a comfortable stay."],"phonetic":"/ˈkʌmfərtəbl/","partOfSpeech":"形容词"}],"examPoints":{"points":["形容词比较级的用法","使役动词make的用法","可数名词复数"],"explanations":["单音节和部分双音节形容词比较级通常加-er，多音节形容词比较级需在前面加more。本句中convenient和comfortable都是多音节形容词，所以用more来构成比较级，表示“更加”的含义。","使役动词make常用结构为“make + 宾语 + 形容词”，表示“使某物/某人处于某种状态”，本句中make life more convenient and comfortable即表示“让生活更加便捷舒适”。","home作为可数名词，指多个家庭居所时需用复数形式homes，本句中smart homes表示一类事物，用复数形式体现泛指概念。"]},"sentenceWithHints":"智能 家居 让 生活 更加 便捷 舒适"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (229, '{"words":[{"chinese":"自动","english":"autonomous","examples":["Autonomous robots can work without human control.","The country declared autonomous status."],"phonetic":"/ɔːˈtɑːnəməs/","partOfSpeech":"形容词"},{"plural":"","chinese":"驾驶","english":"driving","examples":["Driving at night can be dangerous.","She is learning driving skills."],"phonetic":"/ˈdraɪvɪŋ/","partOfSpeech":"名词"},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology changes our life.","New technologies are developed every year."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"正在","english":"is","examples":["He is reading a book.","The project is going well."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"逐步","english":"gradually","examples":["The weather is gradually getting warmer.","He gradually understood the problem."],"phonetic":"/ˈɡrædʒuəli/","partOfSpeech":"副词"},{"chinese":"成熟","english":"mature","examples":["The wine will mature in three years.","Her ideas are maturing as she gains experience."],"phonetic":"/məˈtʃʊr/","pastTense":"matured","thirdPerson":"matures","partOfSpeech":"动词","pastParticiple":"matured","presentParticiple":"maturing"}],"examPoints":{"points":["现在进行时的用法","形容词作定语修饰名词","副词修饰动词"],"explanations":["现在进行时结构为“be动词+动词现在分词”，表示动作正在进行。本句中“正在逐步成熟”描述自动驾驶技术当前的发展状态，所以使用“is gradually maturing”的现在进行时结构。","形容词可以放在名词前作定语，修饰名词的属性。本句中形容词“autonomous（自动的）”修饰名词短语“driving technology”，明确技术的类型为自动驾驶技术。","副词通常用来修饰动词、形容词或其他副词，说明动作发生的方式、程度等。本句中副词“gradually（逐步地）”修饰动词“maturing”，体现技术成熟是一个渐进的过程。"]},"sentenceWithHints":"自动 驾驶 技术 正在 逐步 成熟"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (230, '{"words":[{"plural":"","chinese":"生物信息学","english":"bioinformatics","examples":["Bioinformatics is an interdisciplinary field.","We use bioinformatics to analyze genetic data."],"phonetic":"/ˌbaɪ.oʊ.ɪn.fərˈmæt.ɪks/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"加速了","english":"accelerate","examples":["New technology accelerates the growth of the industry.","The government plans to accelerate economic reform."],"phonetic":"/əkˈsel.ə.reɪt/","pastTense":"accelerated","thirdPerson":"accelerates","partOfSpeech":"动词","pastParticiple":"accelerated","presentParticiple":"accelerating"},{"plural":"","chinese":"医学","english":"medical","examples":["She is studying medical science.","We need to improve medical care in rural areas."],"phonetic":"/ˈmed.ɪ.kəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"researches","chinese":"研究","english":"research","examples":["He is doing research on cancer.","The research shows a positive result."],"phonetic":"/rɪˈsɜːrtʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the roof of the house","a cup of tea"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"processes","chinese":"进程","english":"process","examples":["We are in the process of moving house.","The manufacturing process is very complex."],"phonetic":"/ˈproʊ.ses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["学科类专有名词的翻译与用法","动词第三人称单数形式","名词所有格/所属关系的英文表达"],"explanations":["生物信息学属于专业学科专有名词，对应的英文是bioinformatics，这类词汇通常为不可数名词，在句中作主语时视为单数概念，需要掌握常见理工医类学科专有名词的英文表达，符合高中阶段拓展词汇的考查要求。","本句主语bioinformatics是单数不可数名词，谓语动词accelerate需要使用第三人称单数形式accelerates，这是高中阶段动词时态语态的基础考点，要求掌握主语为第三人称单数时一般现在时谓语动词的变形规则。","中文中“医学研究的进程”表示所属关系，英文中常用“the process of medical research”这种“名词+of+名词”的结构来表达所属，而非直接用所有格形式，这是中英文所属关系表达的差异点，需要掌握不同所属关系场景下的英文表达结构。"]},"sentenceWithHints":"生物信息学 加速了 医学 研究 的 进程"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (231, '{"words":[{"chinese":"认知","english":"cognitive","examples":["Cognitive development is important for children.","She has good cognitive skills."],"phonetic":"/ˈkɑːɡnətɪv/","partOfSpeech":"形容词"},{"plural":"sciences","chinese":"科学","english":"science","examples":["Cognitive science is an interdisciplinary field.","She studies computer science."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"探索","english":"explore","examples":["Scientists explore the deep sea.","We want to explore new cultures."],"phonetic":"/ɪkˈsplɔːr/","pastTense":"explored","thirdPerson":"explores","partOfSpeech":"动词","pastParticiple":"explored","presentParticiple":"exploring"},{"chinese":"人类","english":"human","examples":["Human behavior is complex.","This is a human-made problem."],"phonetic":"/ˈhjuːmən/","partOfSpeech":"形容词"},{"plural":"thinkings","chinese":"思维","english":"thinking","examples":["Human thinking is hard to fully understand.","His logical thinking helps him solve problems."],"phonetic":"/ˈθɪŋkɪŋ/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["the mysteries of the universe","a friend of mine"],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"mysteries","chinese":"奥秘","english":"mystery","examples":["Scientists try to solve the mysteries of nature.","The old house is full of mysteries."],"phonetic":"/ˈmɪstəri/","partOfSpeech":"名词"}],"examPoints":{"points":["名词性短语作定语","动词第三人称单数形式","名词复数的使用"],"explanations":["本句中“认知科学”是用形容词“cognitive”修饰名词“science”构成的名词性短语，在英文中常用此类结构来表达学科类名称，类似的还有“computer science”“social science”。","句子主语“Cognitive science”是单数第三人称概念，一般现在时中，主语为第三人称单数时，谓语动词要使用第三人称单数形式，所以动词“explore”变为“explores”。","“奥秘”对应的英文“mystery”是可数名词，这里表示“人类思维的诸多奥秘”，是泛指的复数概念，所以要使用其复数形式“mysteries”，同时搭配定冠词“the”来特指这类奥秘。"]},"sentenceWithHints":"认知 科学 探索 人类 思维 的 奥秘"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (232, '{"words":[{"plural":"neurosciences","chinese":"神经科学","english":"neuroscience","examples":["Neuroscience helps us understand the brain.","She studies neuroscience at university."],"phonetic":"/ˌnʊroʊˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"揭示了","english":"reveal","examples":["The report reveals the truth.","Research reveals new facts about the disease."],"phonetic":"/rɪˈviːl/","pastTense":"revealed","thirdPerson":"reveals","partOfSpeech":"动词","pastParticiple":"revealed","presentParticiple":"revealing"},{"plural":"brains","chinese":"大脑","english":"brain","examples":["The brain is the control center of the body.","He has a very clever brain."],"phonetic":"/breɪn/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The door of the room is open.","This is a photo of my family."],"phonetic":"/əv/","partOfSpeech":"介词"},{"chinese":"工作","english":"working","examples":["This is the working model of the machine.","She has a working knowledge of French."],"phonetic":"/ˈwɜːrkɪŋ/","partOfSpeech":"形容词"},{"plural":"principles","chinese":"原理","english":"principle","examples":["We should follow the basic principles of science.","The machine works on the principle of gravity."],"phonetic":"/ˈprɪnsəpl/","partOfSpeech":"名词"}],"examPoints":{"points":["学科类名词的用法","动词第三人称单数形式","名词所有格的介词表达","动名词作形容词的用法"],"explanations":["neuroscience属于学科类抽象名词，通常作为不可数名词使用，表达泛指概念时无需加冠词；当表示多个不同分支的神经科学时，可使用复数形式neurosciences。本句中表示泛指的学科，使用单数形式即可。","句子主语neuroscience是单数第三人称，一般现在时中，谓语动词要使用第三人称单数形式，规则动词reveal的第三人称单数是在词尾加-s，即reveals。","中文中“的”表示所属关系时，在英语中常用介词of来构成名词所有格结构，即“the + 名词 + of + 名词”，本句中“大脑的工作原理”译为“the working principles of the brain”，符合这种表达逻辑。","work的动名词形式working可以用作形容词，用来修饰名词，表示“工作的、运作的”，本句中“working principles”表示“运作原理”，这种用法可以将动词的动作含义转化为形容词的修饰含义，丰富表达。"]},"sentenceWithHints":"神经科学 揭示了 大脑 的 工作 原理"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (233, '{"words":[{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is vast and mysterious.","Scientists are exploring the origins of the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","partOfSpeech":"名词"},{"plural":"microwaves","chinese":"微波","english":"microwave","examples":["Microwaves are a type of electromagnetic radiation.","We use a microwave to heat food quickly."],"phonetic":"/ˈmaɪkrəweɪv/","partOfSpeech":"名词"},{"plural":"backgrounds","chinese":"背景","english":"background","examples":["The photo has a beautiful mountain background.","She has a background in physics."],"phonetic":"/ˈbækɡraʊnd/","partOfSpeech":"名词"},{"plural":"radiations","chinese":"辐射","english":"radiation","examples":["The sun emits harmful ultraviolet radiation.","Nuclear radiation is dangerous to living things."],"phonetic":"/ˌreɪdiˈeɪʃn/","partOfSpeech":"名词"},{"chinese":"提供","english":"provide","examples":["The hotel provides free breakfast for guests.","These data provide strong evidence for the theory."],"phonetic":"/prəˈvaɪd/","pastTense":"provided","thirdPerson":"provides","partOfSpeech":"动词","pastParticiple":"provided","presentParticiple":"providing"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She went to the park yesterday."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"origins","chinese":"起源","english":"origin","examples":["The origin of this tradition is unknown.","Scientists study the origin of life on Earth."],"phonetic":"/ˈɔːrɪdʒɪn/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the sky is blue."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"evidences","chinese":"证据","english":"evidence","examples":["There is no evidence to support his claim.","The police found important evidence at the crime scene."],"phonetic":"/ˈevɪdəns/","partOfSpeech":"名词"}],"examPoints":{"points":["专业领域名词短语翻译","动词第三人称单数形式","介词of表所属关系的用法"],"explanations":["本句涉及天文领域专业名词，如“宇宙微波背景辐射”对应“Cosmic microwave background radiation”，这类专业名词通常有固定的英文译法，需要在学习中积累专业领域的词汇搭配，准确对应中英文的专业表达。","句子主语“Cosmic microwave background radiation”是单数不可数名词短语，作主语时谓语动词要用第三人称单数形式，所以动词“provide”变为“provides”，这是主谓一致规则中不可数名词作主语的常见考点。","本句中多次使用介词“of”来表示所属关系，如“evidence of the origin”“origin of the universe”，在英语中当表示无生命事物的所属关系时，常用“of + 名词”的结构，这是英语表达所属关系的重要方式，区别于有生命事物常用的“''s”所有格。"]},"sentenceWithHints":"宇宙 微波 背景 辐射 提供 了 宇宙 起源 的 证据"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (234, '{"words":[{"plural":"","chinese":"暗物质","english":"dark matter","examples":["Scientists are still studying dark matter.","Dark matter is thought to make up most of the universe."],"phonetic":"/dɑːrk ˈmætər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She sings and dances well."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"暗能量","english":"dark energy","examples":["Dark energy is causing the universe to expand faster.","We know very little about dark energy."],"phonetic":"/dɑːrk ˈenərdʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"占据了","english":"occupy","examples":["The new building will occupy this empty lot.","Her work occupies most of her time."],"phonetic":"/ˈɑːkjupaɪ/","pastTense":"occupied","thirdPerson":"occupies","partOfSpeech":"动词","pastParticiple":"occupied","presentParticiple":"occupying"},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is vast and mysterious.","Scientists are exploring the origins of the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the top of the mountain","a cup of tea"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"大部分","english":"most","examples":["Most students like playing games.","Most of the food has been eaten."],"phonetic":"/moʊst/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["学科专有名词翻译","主谓一致","名词所有格/所属结构表达"],"explanations":["本句涉及天文领域专有名词“暗物质（dark matter）”“暗能量（dark energy）”，这类专有名词属于固定搭配，需要准确记忆，是高中阶段英语拓展词汇和跨学科英语考查的重点。","句子主语是“暗物质和暗能量”，对应英文“Dark matter and dark energy”，属于并列主语，视为复数概念，因此谓语动词使用原形occupy，符合“由and连接的并列主语表示复数含义时，谓语动词用复数形式”的主谓一致规则。","中文“宇宙的大部分”在英文中用“most of the universe”表达，这是英语中表示所属或部分与整体关系的常用结构，“most of + 定冠词 + 名词”用来指代某个整体中的大部分，是高中阶段需要掌握的核心名词短语结构。"]},"sentenceWithHints":"暗物质 和 暗能量 占据了 宇宙 的 大部分"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (235, '{"words":[{"plural":"","chinese":"超导","english":"superconducting","examples":["Superconducting materials have zero electrical resistance.","We are researching superconducting devices."],"phonetic":"/ˌsuːpərkənˈdʌktɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"phenomena","chinese":"现象","english":"phenomenon","examples":["The Northern Lights is a natural phenomenon.","Scientists are studying this strange phenomenon."],"phonetic":"/fəˈnɑːmɪnən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"展示","english":"demonstrate","examples":["The experiment demonstrates the law of gravity.","She demonstrated how to use the machine."],"phonetic":"/ˈdemənstreɪt/","pastTense":"demonstrated","thirdPerson":"demonstrates","partOfSpeech":"动词","pastParticiple":"demonstrated","presentParticiple":"demonstrating"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She has read that book."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"quanta","chinese":"量子","english":"quantum","examples":["Quantum physics is a complex field.","A quantum is the smallest unit of energy."],"phonetic":"/ˈkwɑːntəm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"力学","english":"mechanics","examples":["Classical mechanics describes the motion of large objects.","Quantum mechanics deals with tiny particles."],"phonetic":"/məˈkænɪks/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The cover of the book is blue.","This is a photo of my family."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"奇妙","english":"wonderful","examples":["We had a wonderful time at the party.","The view from the mountain is wonderful."],"phonetic":"/ˈwʌndərfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"properties","chinese":"特性","english":"property","examples":["One property of water is that it freezes at 0°C.","The material has unique chemical properties."],"phonetic":"/ˈprɑːpərti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["学科专业词汇的翻译与运用","名词单复数的不规则变化","介词of表所属关系的用法"],"explanations":["本句涉及物理学科专业词汇，如“超导现象”对应superconductivity、“量子力学”对应quantum mechanics，这类专业词汇是高中阶段英语与学科交叉考查的重点，需要准确记忆对应英文表达，符合高三英语对学术性词汇的考察要求。","句中“现象”对应phenomenon，复数形式为phenomena；“量子”对应quantum，复数形式为quanta，均为名词不规则复数变化，这类不规则名词的复数形式是高中英语语法的常考点，需要特殊记忆区别于常规加-s/-es的规则变化。","本句中“量子力学的奇妙特性”翻译为the wonderful properties of quantum mechanics，使用介词of构成名词所有格来表示所属关系，当表示无生命事物的所属时，通常用“of+名词”的结构，这是高中英语名词所有格的核心考点之一。"]},"sentenceWithHints":"超导 现象 展示 了 量子 力学 的 奇妙 特性"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (236, '{"words":[{"plural":"quanta","chinese":"量子","english":"quantum","examples":["Quantum physics is a complex subject.","A quantum is the smallest unit of something."],"phonetic":"/ˈkwɑːntəm/","partOfSpeech":"名词"},{"plural":"","chinese":"计算","english":"computing","examples":["Quantum computing is a cutting-edge technology.","Cloud computing has changed our work mode."],"phonetic":"/kəmˈpjuːtɪŋ/","partOfSpeech":"名词"},{"chinese":"有望","english":"be expected to","examples":["The new drug is expected to cure the disease.","He is expected to arrive at 8 o''clock."],"phonetic":"/biː ɪkˈspektɪd tuː/","pastTense":"was/were expected to","thirdPerson":"is/are expected to","partOfSpeech":"动词短语","pastParticiple":"been expected to","presentParticiple":"being expected to"},{"chinese":"解决","english":"solve","examples":["We need to solve this problem as soon as possible.","She solved the math puzzle quickly."],"phonetic":"/sɑːlv/","pastTense":"solved","thirdPerson":"solves","partOfSpeech":"动词","pastParticiple":"solved","presentParticiple":"solving"},{"chinese":"传统","english":"traditional","examples":["Traditional Chinese medicine is very popular.","We keep up some traditional customs."],"phonetic":"/trəˈdɪʃənl/","partOfSpeech":"形容词"},{"chinese":"无法","english":"cannot","examples":["I cannot finish the task alone.","He cannot speak French."],"phonetic":"/ˈkænɑːt/","partOfSpeech":"助词"},{"chinese":"处理","english":"handle","examples":["She can handle the difficult situation well.","The new system can handle large amounts of data."],"phonetic":"/ˈhændl/","pastTense":"handled","thirdPerson":"handles","partOfSpeech":"动词","pastParticiple":"handled","presentParticiple":"handling"},{"chinese":"的","english":"of","examples":["This is a photo of my family.","The color of the wall is white."],"phonetic":"/əv/","partOfSpeech":"助词"},{"chinese":"复杂","english":"complex","examples":["The complex problem needs a professional solution.","This is a complex machine with many parts."],"phonetic":"/kəmˈpleks/","partOfSpeech":"形容词"},{"plural":"problems","chinese":"问题","english":"problem","examples":["We are trying to solve the environmental problem.","He has a health problem."],"phonetic":"/ˈprɑːbləm/","partOfSpeech":"名词"}],"examPoints":{"points":["被动语态的用法","定语从句的引导与使用","专业名词的英文表达","动词不定式作补语"],"explanations":["本句中“有望”使用了“be expected to”的被动结构，表达“被期望、有望”的含义，在英语中当主语是动作的承受者或表达客观预期时，常用被动语态来体现正式、客观的语气，符合科技文本的表达习惯。","参考翻译中使用了that引导的定语从句“that traditional computing cannot handle”来修饰先行词“complex problems”，that在从句中作handle的宾语，当先行词是表示事物的名词且在从句中作宾语时，that可以省略，这是高中阶段定语从句的核心考点之一。","句子涉及科技领域专业名词，如“量子计算（quantum computing）”“传统计算（traditional computing）”，这类专业词汇的准确翻译是高中英语科技类文本考查的重点，需要掌握常见科技领域的固定英文表达。","“be expected to do sth”结构中，动词不定式“to solve”作主语补足语，补充说明主语“Quantum computing”被期望的具体动作，动词不定式作补足语是高中阶段非谓语动词的重要考点，需掌握不同动词后接不定式作补语的固定搭配。"]},"sentenceWithHints":"量子 计算 有望 解决 传统 计算 无法 处理 的 复杂 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (237, '{"words":[{"plural":"genes","chinese":"基因","english":"gene","examples":["Genes carry genetic information.","Mutations in genes can cause diseases."],"phonetic":"/dʒiːn/","partOfSpeech":"名词"},{"plural":"","chinese":"编辑","english":"editing","examples":["Video editing requires special software.","Gene editing is a new medical technology."],"phonetic":"/ˈedɪtɪŋ/","partOfSpeech":"名词"},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology changes our life.","This technology is widely used in medicine."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"为","english":"for","examples":["This gift is for you.","We need tools for repairing the car."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"chinese":"治疗","english":"treat","examples":["Doctors treat patients carefully.","This medicine can treat your cold."],"phonetic":"/triːt/","pastTense":"treated","thirdPerson":"treats","partOfSpeech":"动词","pastParticiple":"treated","presentParticiple":"treating"},{"chinese":"遗传","english":"genetic","examples":["Genetic factors affect our health.","She has a genetic disorder."],"phonetic":"/dʒəˈnetɪk/","partOfSpeech":"形容词"},{"plural":"diseases","chinese":"疾病","english":"disease","examples":["Many diseases can be prevented.","He is suffering from a rare disease."],"phonetic":"/dɪˈziːz/","partOfSpeech":"名词"},{"chinese":"带来","english":"bring","examples":["Spring brings warm weather.","She brings a gift to every party."],"phonetic":"/brɪŋ/","pastTense":"brought","thirdPerson":"brings","partOfSpeech":"动词","pastParticiple":"brought","presentParticiple":"bringing"},{"chinese":"了","english":"","examples":["I have finished my homework.","She bought a new dress."],"phonetic":"","partOfSpeech":"助词"},{"plural":"hopes","chinese":"希望","english":"hope","examples":["We have hope for a better future.","She never gives up hope."],"phonetic":"/hoʊp/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作介词宾语","主谓一致规则","名词短语的英译"],"explanations":["介词for后面需要接名词性成分，动词treat要变为动名词形式treating，构成\"for treating genetic diseases\"的介词短语，在句中作后置定语修饰hope，这是高中阶段重点考查的非谓语动词用法。","本句主语\"Gene editing technology\"是单数可数名词短语，谓语动词要使用第三人称单数形式brings，符合英语中主谓一致的核心规则，即主语为单数时谓语动词对应使用单数形式。","中文的偏正短语\"基因编辑技术\"译为\"Gene editing technology\"，采用了名词作定语的英文表达习惯；\"遗传疾病\"译为\"genetic diseases\"，使用形容词修饰名词，这是中英翻译中名词短语转换的常见考查点，需要掌握不同修饰成分的英文表达形式。"]},"sentenceWithHints":"基因 编辑 技术 为 治疗 遗传 疾病 带来 了 希望"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (238, '{"words":[{"plural":"","chinese":"合成","english":"synthetic","examples":["Synthetic materials are widely used in industry.","This is a synthetic version of the natural chemical."],"phonetic":"/sɪnˈθetɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"biologies","chinese":"生物学","english":"biology","examples":["She is studying biology at university.","Molecular biology is a branch of biology."],"phonetic":"/baɪˈɑːlədʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"使","english":"enable","examples":["The new software enables us to work more efficiently.","His wealth enables him to travel around the world."],"phonetic":"/ɪˈneɪbl/","pastTense":"enabled","thirdPerson":"enables","partOfSpeech":"动词","pastParticiple":"enabled","presentParticiple":"enabling"},{"plural":"","chinese":"我们","english":"us","examples":["Please give us a hand.","He invited us to his party."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"能够","english":"to","examples":["I want to go home.","She needs to finish her homework."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"设计","english":"design","examples":["She will design a new dress for the party.","The architect designed a modern house."],"phonetic":"/dɪˈzaɪn/","pastTense":"designed","thirdPerson":"designs","partOfSpeech":"动词","pastParticiple":"designed","presentParticiple":"designing"},{"plural":"","chinese":"和","english":"and","examples":["I like coffee and tea.","He is tall and strong."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"创造","english":"create","examples":["Artists create beautiful paintings.","The company plans to create new jobs."],"phonetic":"/kriˈeɪt/","pastTense":"created","thirdPerson":"creates","partOfSpeech":"动词","pastParticiple":"created","presentParticiple":"creating"},{"plural":"","chinese":"新的","english":"new","examples":["I bought a new phone.","We are moving to a new city."],"phonetic":"/nuː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"lives","chinese":"生命","english":"life","examples":["Life is full of surprises.","Many lives were saved by the doctors."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"forms","chinese":"形式","english":"form","examples":["Water has three forms: solid, liquid and gas.","She filled out the application form."],"phonetic":"/fɔːrm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["enable sb. to do sth. 固定搭配","学科类专有名词的翻译与用法","并列动词的用法","可数名词复数的不规则变化"],"explanations":["enable sb. to do sth. 是高中阶段重点考察的动词固定搭配，意为“使某人能够做某事”，其中 enable 作为及物动词，后面接宾语，再跟不定式作宾语补足语，本句中即 enables us to design and create...，需要注意 enable 的第三人称单数形式变化，主语为单数专有名词 Synthetic biology，所以动词用 enables。","合成生物学对应的英文是 Synthetic biology，属于学科类专有名词，这类名词通常首字母大写，一般作为单数名词使用，在句中作主语时，谓语动词用第三人称单数形式。","句中 design 和 create 是由并列连词 and 连接的两个并列动词，在 enable sb. to do sth. 结构中，不定式符号 to 可以共用，所以后面的动词都用原形，构成并列的不定式结构，表示两个并列的动作。","life 作为“生命”含义时，复数形式是不规则变化 lives，而非直接加 s，这是高中阶段需要掌握的不规则名词复数变化之一，另外 form 作为可数名词，复数形式为规则变化 forms，需要注意可数名词在表示泛指时的复数用法。"]},"sentenceWithHints":"合成 生物学 使 我们 能够 设计 和 创造 新的 生命 形式"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (239, '{"words":[{"plural":"nanotechnologies","chinese":"纳米技术","english":"nanotechnology","examples":["Nanotechnology has a wide range of applications.","Scientists are researching nanotechnology for medical use."],"phonetic":"/ˌnænoʊtekˈnɑːlədʒi/","partOfSpeech":"名词"},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my sister.","This book is for beginners."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"plural":"materials","chinese":"材料","english":"material","examples":["We need new building materials.","This material is very durable."],"phonetic":"/məˈtɪriəl/","partOfSpeech":"名词"},{"plural":"sciences","chinese":"科学","english":"science","examples":["She studies science at university.","Environmental science is an important field."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"开辟","english":"open up","examples":["The new policy opens up more opportunities.","He opened up a new store last year."],"phonetic":"/ˈoʊpən ʌp/","pastTense":"opened up","thirdPerson":"opens up","partOfSpeech":"动词","pastParticiple":"opened up","presentParticiple":"opening up"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She went to the park yesterday."],"phonetic":"","partOfSpeech":"助词"},{"plural":"","chinese":"新","english":"new","examples":["I bought a new phone.","We are starting a new project."],"phonetic":"/nuː/","partOfSpeech":"形容词"},{"plural":"","chinese":"的","english":"","examples":["The color of the sky is blue.","This is my friend''s book."],"phonetic":"","partOfSpeech":"助词"},{"plural":"prospects","chinese":"前景","english":"prospect","examples":["The job has good prospects.","We are excited about the prospects of this new technology."],"phonetic":"/ˈprɑːspekt/","partOfSpeech":"名词"}],"examPoints":{"points":["动词短语的使用","学科类名词的表达","介词for的用法","可数名词的复数形式"],"explanations":["本句中使用动词短语open up表示“开辟、开创”，它是固定搭配，后常接表示机会、前景、市场等的名词，在高中阶段需要掌握这类具有引申义的动词短语，区分其和单个动词open的用法差异。","“材料科学”翻译为materials science，这类学科类名词通常用“名词复数+science”的结构，类似的还有environmental science、computer science，需要掌握常见学科名称的英文表达。","介词for在这里用来表示对象或用途，意为“为了、给”，引出动作的受益方或相关领域，在英语中for的用法多样，这是高中阶段需要重点掌握的介词用法之一。","prospect表示“前景、展望”时是可数名词，在本句中表示多个新前景，所以使用复数形式prospects；material表示“材料”时也是可数名词，表达“材料科学”时用复数materials，需要掌握可数名词变复数的规则以及可数名词在具体语境中的单复数使用。"]},"sentenceWithHints":"纳米技术 为 材料 科学 开辟 了 新 的 前景"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (240, '{"words":[{"chinese":"可再生","english":"renewable","examples":["Renewable energy is good for the environment.","We should use more renewable resources."],"phonetic":"/rɪˈnuːəbəl/","partOfSpeech":"形容词"},{"plural":"energies","chinese":"能源","english":"energy","examples":["We need to save energy.","Solar energy is a type of renewable energy."],"phonetic":"/ˈenərdʒi/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","This is my favorite book."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"实现","english":"achieve","examples":["We achieved our goal.","She hopes to achieve success."],"phonetic":"/əˈtʃiːv/","pastTense":"achieved","thirdPerson":"achieves","partOfSpeech":"动词","pastParticiple":"achieved","presentParticiple":"achieving"},{"chinese":"可持续","english":"sustainable","examples":["We need to promote sustainable development.","Sustainable farming is important."],"phonetic":"/səˈsteɪnəbl/","partOfSpeech":"形容词"},{"plural":"developments","chinese":"发展","english":"development","examples":["The city has seen rapid development.","Sustainable development is our goal."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["This is the key of the problem.","The color of the sky is blue."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"keys","chinese":"关键","english":"key","examples":["Hard work is the key to success.","She lost the key to the door."],"phonetic":"/kiː/","partOfSpeech":"名词"}],"examPoints":{"points":["固定搭配 the key to doing sth","形容词作定语","不可数名词与可数名词的用法"],"explanations":["the key to doing sth 是固定搭配，意为“做某事的关键”，这里的 to 是介词，后面要接动词的动名词形式，所以用 achieving，这是高中阶段重点考查的介词后接动名词的用法。","形容词 renewable 和 sustainable 分别修饰名词 energy 和 development，作前置定语，用来限定名词的属性，这是形容词的基本用法之一，在书面表达和阅读理解中经常出现。","energy 表示“能源”时通常为不可数名词，不需要变复数；development 表示“发展”这一抽象概念时为不可数名词，当表示具体的发展成果时可作可数名词，本句中是抽象概念，所以用单数形式；key 表示“关键”时为可数名词，此处特指“实现可持续发展的关键”，所以用定冠词 the 修饰单数形式。"]},"sentenceWithHints":"可再生 能源 是 实现 可持续 发展 的 关键"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (241, '{"words":[{"plural":"carbons","chinese":"碳","english":"carbon","examples":["Carbon is an important element.","Carbon dioxide is a greenhouse gas."],"phonetic":"/ˈkɑːrbən/","partOfSpeech":"名词"},{"chinese":"捕捉","english":"capture","examples":["The camera can capture beautiful scenery.","They tried to capture the escaped tiger."],"phonetic":"/ˈkæptʃər/","pastTense":"captured","thirdPerson":"captures","partOfSpeech":"动词","pastParticiple":"captured","presentParticiple":"capturing"},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology changes our life.","This new technology is very useful."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"有助","english":"help","examples":["This book helps me learn English.","She helps her mother with housework."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"于","english":"to","examples":["I want to go home.","She needs to finish the task."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"应对","english":"address","examples":["We need to address this problem.","The president addressed the nation."],"phonetic":"/əˈdres/","pastTense":"addressed","thirdPerson":"addresses","partOfSpeech":"动词","pastParticiple":"addressed","presentParticiple":"addressing"},{"plural":"climates","chinese":"气候","english":"climate","examples":["The climate here is warm.","Climate change is a global issue."],"phonetic":"/ˈklaɪmət/","partOfSpeech":"名词"},{"plural":"changes","chinese":"变化","english":"change","examples":["Great changes have taken place.","Climate change affects everyone."],"phonetic":"/tʃeɪndʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["动词短语搭配","不可数名词与可数名词用法","第三人称单数动词形式"],"explanations":["本句中涉及“help do sth.”的固定搭配，help 后接动词原形，所以这里用 address 而不是 to address 或 addressing；另外“address climate change”是固定表达，意为“应对气候变化”，address 在这里表示“处理、应对”的含义，属于熟词生义的考查。","句中“carbon”“technology”“climate”“change”作为抽象或特定概念时，可作为不可数名词使用，比如“climate change”作为固定术语是不可数概念；当表示不同种类时可作为可数名词，如“technologies”表示多种技术，需要区分可数与不可数的语境用法。","句子主语“Carbon capture technology”是单数第三人称概念，所以谓语动词 help 需要使用第三人称单数形式 helps，这是高中阶段主谓一致的核心考点之一，需要根据主语的单复数确定动词形式。"]},"sentenceWithHints":"碳 捕捉 技术 有助 于 应对 气候 变化"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (242, '{"words":[{"plural":"oceans","chinese":"海洋","english":"ocean","examples":["The Pacific Ocean is the largest ocean in the world.","We need to protect the ocean from pollution."],"phonetic":"/ˈoʊʃn/","partOfSpeech":"名词"},{"plural":"explorations","chinese":"探索","english":"exploration","examples":["Space exploration has always been a human dream.","The exploration of the deep sea is full of challenges."],"phonetic":"/ˌekspləˈreɪʃn/","partOfSpeech":"名词"},{"chinese":"为","english":"for","examples":["I bought a gift for my sister.","This book is for children."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"chinese":"我们","english":"us","examples":["He gave us some advice.","Let us go to the park."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"了解","english":"understand","examples":["I can''t understand this math problem.","She understands how to play the piano."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"","chinese":"地球","english":"Earth","examples":["The Earth is our home.","We should take care of the Earth."],"phonetic":"/ɜːrθ/","partOfSpeech":"名词"},{"chinese":"提供","english":"provide","examples":["The hotel provides free breakfast for guests.","We need to provide more help for the poor."],"phonetic":"/prəˈvaɪd/","pastTense":"provided","thirdPerson":"provides","partOfSpeech":"动词","pastParticiple":"provided","presentParticiple":"providing"},{"chinese":"了","english":"","examples":["I have finished my homework.","She told me a story."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"新","english":"new","examples":["I bought a new phone.","She has a new idea."],"phonetic":"/nuː/","partOfSpeech":"形容词"},{"plural":"perspectives","chinese":"视角","english":"perspective","examples":["From my perspective, this plan is not good.","He offered a new perspective on the problem."],"phonetic":"/pərˈspektɪv/","partOfSpeech":"名词"}],"examPoints":{"points":["动词短语 provide sb. with sth. 的用法","介词 on 的搭配使用","不可数名词与可数名词的区分"],"explanations":["provide sb. with sth. 是固定动词短语，意为“为某人提供某物”，也可以转换为 provide sth. for sb. 的结构，本句使用前者结构，符合英语表达习惯，在高中英语中是重点考察的动词搭配。","介词 on 在这里表示“关于，有关”，用于引出相关的主题，与 perspective 搭配表示“关于某方面的视角”，类似的搭配还有 perspective on sth.，是高中阶段需要掌握的介词固定搭配。","本句中的 Earth 作为表示星球的专有名词，属于不可数的专有名词，没有复数形式；而 exploration、perspective 等是可数名词，在表示多个概念时需要使用复数形式，高中英语会考察专有名词的数的用法以及普通可数名词的单复数变化。"]},"sentenceWithHints":"海洋 探索 为 我们 了解 地球 提供 了 新 视角"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (243, '{"words":[{"plural":"spaces","chinese":"太空","english":"space","examples":["Space travel is a dream for many.","There is not enough space in the room."],"phonetic":"/speɪs/","partOfSpeech":"名词"},{"plural":"explorations","chinese":"探索","english":"exploration","examples":["Ocean exploration helps us learn more about marine life.","The exploration of Mars has made great progress."],"phonetic":"/ˌekspləˈreɪʃn/","partOfSpeech":"名词"},{"chinese":"拓展","english":"expand","examples":["Reading can expand your knowledge.","The company plans to expand its business overseas."],"phonetic":"/ɪkˈspænd/","pastTense":"expanded","thirdPerson":"expands","partOfSpeech":"动词","pastParticiple":"expanded","presentParticiple":"expanding"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She went to the park yesterday."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"humans","chinese":"人类","english":"human","examples":["Humans have been on Earth for thousands of years.","This technology is beneficial to human society."],"phonetic":"/ˈhjuːmən/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"","examples":["This is my father''s car.","The color of the sky is blue."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"cognitions","chinese":"认知","english":"cognition","examples":["Human cognition develops with age.","The study focuses on children''s cognitive abilities."],"phonetic":"/kɑːɡˈnɪʃn/","partOfSpeech":"名词"},{"plural":"boundaries","chinese":"边界","english":"boundary","examples":["We should respect the boundaries of others.","The river forms a natural boundary between the two countries."],"phonetic":"/ˈbaʊndri/","partOfSpeech":"名词"}],"examPoints":{"points":["名词短语的英译","动词第三人称单数形式的使用","所属关系的英文表达"],"explanations":["中文的偏正短语“太空探索”“人类的认知边界”在英文中对应名词短语“Space exploration”“the boundaries of human cognition”，这类科技类名词短语是高中阶段重点掌握的内容，常出现在科普类翻译和阅读中，需要准确记忆对应的英文表达。","本句主语“Space exploration”是单数概念，所以谓语动词使用第三人称单数形式“expands”，这是高中阶段主谓一致的核心考点之一，要求掌握单数主语（包括不可数名词、单数可数名词、动名词短语等）作主语时，谓语动词的变化规则。","中文中“的”表示所属关系，在英文中可以用“of”结构来体现，如“人类的认知”译为“human cognition”，“认知边界”译为“boundaries of human cognition”，这是英文表达所属关系的常见方式，需要区分其与名词所有格的使用场景，“of”结构多用于无生命事物的所属表达。"]},"sentenceWithHints":"太空 探索 拓展 了 人类 的 认知 边界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (244, '{"words":[{"plural":"humans","chinese":"人类","english":"human","examples":["Humans are social animals.","The study focuses on human behavior."],"phonetic":"/ˈhjuːmən/","partOfSpeech":"名词"},{"plural":"genomes","chinese":"基因组","english":"genome","examples":["The human genome has been fully sequenced.","Scientists are studying the genome of this species."],"phonetic":"/ˈdʒiːnoʊm/","partOfSpeech":"名词"},{"plural":"projects","chinese":"计划","english":"project","examples":["The new project will start next month.","She is in charge of this research project."],"phonetic":"/ˈprɑːdʒekt/","partOfSpeech":"名词"},{"chinese":"完成了","english":"complete","examples":["They completed the task ahead of schedule.","She has completed her homework."],"phonetic":"/kəmˈpliːt/","pastTense":"completed","thirdPerson":"completes","partOfSpeech":"动词","pastParticiple":"completed","presentParticiple":"completing"},{"plural":"genes","chinese":"基因","english":"gene","examples":["Genes determine many of our traits.","Mutations in genes can cause diseases."],"phonetic":"/dʒiːn/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The cover of the book is blue.","This is a photo of my family."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"","chinese":"测序","english":"sequencing","examples":["DNA sequencing is a key technology in genetics.","The sequencing of the genome took many years."],"phonetic":"/ˈsiːkwənsɪŋ/","partOfSpeech":"名词"}],"examPoints":{"points":["专有名词的大写规则","名词所有格的表达（of 结构）","一般过去时的用法"],"explanations":["表示特定项目、组织等的专有名词每个实词首字母需要大写，本句中\"人类基因组计划\"是特定科研项目，对应英文\"The Human Genome Project\"，每个核心实词首字母大写。","在英语中，当表示无生命事物的所属关系时，通常使用\"of + 名词\"的结构来替代''s所有格，本句中\"人类基因的测序\"译为\"the sequencing of the human genome\"，就是用of结构体现所属关系。","一般过去时用于表示过去某个时间已经完成的动作，本句中\"完成了\"表明动作已经结束，所以动词使用过去式completed，符合一般过去时的使用场景。"]},"sentenceWithHints":"人类 基因组 计划 完成了 人类 基因 的 测序"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (245, '{"words":[{"plural":"","chinese":"脑机","english":"brain-computer","examples":["Brain-computer interface is a cutting-edge technology.","Scientists are researching brain-computer interaction."],"phonetic":"/ˈbreɪn kəmˈpjuːtər/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"interfaces","chinese":"接口","english":"interface","examples":["The new software has a user-friendly interface.","This device acts as an interface between the machine and the user."],"phonetic":"/ˈɪntərfeɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology changes our life greatly.","She is studying information technology."],"phonetic":"/tekˈnɑːlədʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my sister.","This tool is used for cutting metal."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"人机","english":"human-machine","examples":["Human-machine collaboration improves work efficiency.","The conference focuses on human-machine interaction."],"phonetic":"/ˈhjuːmən məˈʃiːn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"integrations","chinese":"融合","english":"integration","examples":["The integration of different systems took a long time.","Cultural integration is a key part of globalization."],"phonetic":"/ˌɪntɪˈɡreɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"提供","english":"make","examples":["The new policy makes it easier to start a business.","She made a delicious cake for the party."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She went to the park yesterday."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"可能","english":"possible","examples":["Hard work makes everything possible.","Is it possible to finish the task today?"],"phonetic":"/ˈpɑːsəbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["复合形容词的用法","make + 宾语 + 宾语补足语的结构","科技类词汇的积累"],"explanations":["本句中出现了brain-computer、human-machine这类由连字符连接的复合形容词，这类形容词通常用于修饰名词，作前置定语，在科技类英语表达中十分常见，需要掌握其构成和用法。","参考翻译中使用了“make + human-machine integration + possible”的结构，这里make是使役动词，possible作为宾语补足语补充说明宾语的状态，这是高中阶段重点掌握的动词复合结构，该结构还可以变形为“make it + 形容词 + to do sth”，其中it作形式宾语。","本句属于科技类话题，涉及brain-computer interface、human-machine integration等专业科技词汇，高三阶段需要积累不同话题领域的核心词汇，提升专业话题的英语读写能力，这类词汇在阅读理解、书面表达的科技类题型中经常出现。"]},"sentenceWithHints":"脑机 接口 技术 为 人机 融合 提供 了 可能"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (246, '{"words":[{"plural":"quanta","chinese":"量子","english":"quantum","examples":["Quantum physics is a complex subject.","A quantum is the smallest unit of energy."],"phonetic":"/ˈkwɑːntəm/","partOfSpeech":"名词"},{"plural":"entanglements","chinese":"纠缠","english":"entanglement","examples":["Quantum entanglement is a key concept in quantum mechanics.","The entanglement of the two particles was confirmed."],"phonetic":"/ɪnˈtæŋɡlmənt/","partOfSpeech":"名词"},{"plural":"phenomena","chinese":"现象","english":"phenomenon","examples":["The Northern Lights is a natural phenomenon.","Scientists are studying this strange phenomenon."],"phonetic":"/fəˈnɑːmɪnən/","partOfSpeech":"名词"},{"chinese":"挑战","english":"challenge","examples":["The new theory challenges traditional beliefs.","She challenged him to a race."],"phonetic":"/ˈtʃælɪndʒ/","pastTense":"challenged","thirdPerson":"challenges","partOfSpeech":"动词","pastParticiple":"challenged","presentParticiple":"challenging"},{"chinese":"了","english":"","examples":["I finished my homework.","She has gone to the park."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"我们","english":"our","examples":["Our team won the game.","This is our house."],"phonetic":"/ˈaʊər/","partOfSpeech":"代词"},{"chinese":"对","english":"of","examples":["the perception of reality","the importance of education"],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"realities","chinese":"现实","english":"reality","examples":["He can''t face reality.","Virtual reality is becoming popular."],"phonetic":"/riˈæləti/","partOfSpeech":"名词"},{"chinese":"的","english":"","examples":["the color of the sky","my friend''s book"],"phonetic":"","partOfSpeech":"助词"},{"plural":"perceptions","chinese":"认知","english":"perception","examples":["Our perception of the world is shaped by experiences.","His perception of the situation was wrong."],"phonetic":"/pərˈsepʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["专业名词翻译","主谓一致","介词短语搭配"],"explanations":["本句涉及量子物理领域的专业名词，“量子纠缠现象”对应“Quantum entanglement phenomenon”，但在英文表达中，“Quantum entanglement”本身已特指该物理现象，常直接作为主语使用，体现了专业领域英文表达的简洁性，需要掌握学科专业词汇的固定译法。","句子主语“Quantum entanglement”是单数名词短语，因此谓语动词“challenge”需要使用第三人称单数形式“challenges”，这是英语主谓一致的核心规则，主语为第三人称单数时，一般现在时的谓语动词要做相应变形。","“对现实的认知”翻译为“perception of reality”，这里使用介词“of”来体现所属关系，构成名词短语的固定搭配，在英语中表示“对……的认知/看法”常用“perception of...”的结构，需要掌握这类抽象名词与介词的搭配规则。"]},"sentenceWithHints":"量子 纠缠 现象 挑战 了 我们 对 现实 的 认知"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (247, '{"words":[{"plural":"strings","chinese":"弦","english":"string","examples":["The string of the guitar broke.","She tied a string around the box."],"phonetic":"/strɪŋ/","partOfSpeech":"名词"},{"plural":"theories","chinese":"理论","english":"theory","examples":["This theory is widely accepted.","He proposed a new theory about black holes."],"phonetic":"/ˈθɪri/","partOfSpeech":"名词"},{"chinese":"试图","english":"attempt","examples":["He attempted to climb the mountain.","The company is attempting to expand its business."],"phonetic":"/əˈtempt/","pastTense":"attempted","thirdPerson":"attempts","partOfSpeech":"动词","pastParticiple":"attempted","presentParticiple":"attempting"},{"chinese":"统一","english":"unify","examples":["The leader tried to unify the divided country.","The new policy aims to unify the two systems."],"phonetic":"/ˈjuːnɪfaɪ/","pastTense":"unified","thirdPerson":"unifies","partOfSpeech":"动词","pastParticiple":"unified","presentParticiple":"unifying"},{"plural":"quanta","chinese":"量子","english":"quantum","examples":["A quantum of light is called a photon.","Quantum physics studies the smallest particles."],"phonetic":"/ˈkwɑːntəm/","partOfSpeech":"名词"},{"plural":"","chinese":"力学","english":"mechanics","examples":["Classical mechanics describes the motion of large objects.","Quantum mechanics deals with subatomic particles."],"phonetic":"/məˈkænɪks/","partOfSpeech":"名词"},{"chinese":"和","english":"and","examples":["I like bread and milk.","She is smart and hardworking."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"chinese":"广义","english":"general","examples":["This is a general rule with few exceptions.","He has a general knowledge of history."],"phonetic":"/ˈdʒenrəl/","partOfSpeech":"形容词"},{"plural":"","chinese":"相对论","english":"relativity","examples":["Einstein''s theory of relativity changed physics.","General relativity explains gravity."],"phonetic":"/ˌreləˈtɪvəti/","partOfSpeech":"名词"}],"examPoints":{"points":["学科专业术语的英译","动词搭配用法","不可数名词与不规则复数名词"],"explanations":["本句涉及物理学专业术语，如“弦理论”对应“String theory”、“量子力学”对应“quantum mechanics”、“广义相对论”对应“general relativity”，这类专业术语是大学物理及相关专业英语的核心考查内容，要求准确掌握固定译法，避免字面直译。","动词“attempt”的常见搭配为“attempt to do sth.”，表示“试图做某事”，在句中“attempts to unify”符合该固定搭配，考查动词与不定式的搭配用法，这是大学英语中动词用法的重要考点。","句中“quantum”的复数形式为不规则变化“quanta”，属于名词不规则复数的考查范畴；“mechanics”“relativity”作为学科类不可数名词，无复数形式，需要区分可数名词的规则/不规则复数变化以及不可数名词的用法，这是大学英语语法中名词用法的深化考点。"]},"sentenceWithHints":"弦 理论 试图 统一 量子 力学 和 广义 相对论"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (248, '{"words":[{"plural":"","chinese":"暗","english":"dark","examples":["The room is dark.","Dark clouds are coming."],"phonetic":"/dɑːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"energies","chinese":"能量","english":"energy","examples":["We need to save energy.","Solar energy is a clean resource."],"phonetic":"/ˈenərdʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the roof of the house","a cup of tea"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"existences","chinese":"存在","english":"existence","examples":["The existence of aliens is still unknown.","She doubts the existence of true love."],"phonetic":"/ɪɡˈzɪstəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"解释","english":"explain","examples":["Please explain this math problem to me.","The report explains the new policy in detail."],"phonetic":"/ɪkˈspleɪn/","pastTense":"explained","thirdPerson":"explains","partOfSpeech":"动词","pastParticiple":"explained","presentParticiple":"explaining"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She has read the book."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is vast.","Scientists are exploring the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"加速","english":"accelerate","examples":["The car accelerated quickly.","We need to accelerate the project progress."],"phonetic":"/əkˈseləreɪt/","pastTense":"accelerated","thirdPerson":"accelerates","partOfSpeech":"动词","pastParticiple":"accelerated","presentParticiple":"accelerating"},{"plural":"expansions","chinese":"膨胀","english":"expansion","examples":["The expansion of the city has caused traffic problems.","The company plans for further expansion."],"phonetic":"/ɪkˈspænʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"phenomena","chinese":"现象","english":"phenomenon","examples":["The Northern Lights is a natural phenomenon.","Scientists are studying this strange phenomenon."],"phonetic":"/fəˈnɑːmɪnən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["名词所有格与所属关系的表达","现在分词作定语的用法","不规则名词的复数形式","主谓一致"],"explanations":["在英语中表示所属关系常用介词of构成的短语，本句中“暗能量的存在”“宇宙加速膨胀的现象”都通过“of”短语来体现所属逻辑，这是科技英语中正式表达所属关系的常用方式，避免使用过多''s所有格，符合学术文本的严谨性。","现在分词accelerating在这里作定语修饰expansion，用来表示“膨胀”是正在进行且具有“加速”的主动动态，体现宇宙膨胀的持续性动作特征，在科技英语中常用于描述持续的自然过程。","phenomenon是不规则名词，其复数形式为phenomena，而非常规的加-s/-es，这类不规则名词是大学英语词汇考查的重点，尤其是在学术类文本中高频出现的专业词汇。","本句主语是the existence of dark energy，核心名词是existence，为单数可数名词，因此谓语动词explain需要使用第三人称单数形式explains，这是主谓一致规则中“以of短语修饰的单数名词作主语时，谓语动词用单数”的具体应用，在正式文本中需严格遵循。"]},"sentenceWithHints":"暗 能量 的 存在 解释 了 宇宙 加速 膨胀 的 现象"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (249, '{"words":[{"plural":"","chinese":"表观遗传学","english":"epigenetics","examples":["Epigenetics focuses on heritable changes in gene expression.","Studies in epigenetics have revealed new insights into disease."],"phonetic":"/ˌepɪdʒəˈnetɪks/","partOfSpeech":"名词"},{"chinese":"研究","english":"study","examples":["She studies molecular biology at university.","We have studied this phenomenon for years."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"genes","chinese":"基因","english":"gene","examples":["This gene is responsible for the trait.","Mutations in certain genes can cause disease."],"phonetic":"/dʒiːn/","partOfSpeech":"名词"},{"plural":"expressions","chinese":"表达","english":"expression","examples":["Gene expression is regulated by various factors.","Her facial expression showed she was upset."],"phonetic":"/ɪkˈspreʃn/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["the roof of the house","a cup of tea"],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"chinese":"调控","english":"regulatory","examples":["regulatory policies","the regulatory mechanisms of the body"],"phonetic":"/ˈreɡjələtɔːri/","partOfSpeech":"形容词"},{"plural":"mechanisms","chinese":"机制","english":"mechanism","examples":["The body has a natural defense mechanism.","We need to understand the mechanism behind this process."],"phonetic":"/ˈmekənɪzəm/","partOfSpeech":"名词"}],"examPoints":{"points":["专业领域词汇的英译","名词所有格/所属关系的表达","主谓一致"],"explanations":["本句属于生物专业领域内容，涉及表观遗传学、基因表达、调控机制等专业术语，需要掌握对应的标准英文专业词汇，如epigenetics、gene expression、regulatory mechanisms等，这类词汇是生物专业英语的核心考点，要求准确记忆和使用。","中文中“的”表示所属关系，在英文中常通过介词of来体现，本句中“基因表达的调控机制”翻译为the regulatory mechanisms of gene expression，符合英文中“所属对象+of+所属主体”的表达逻辑，这是科技英语中表达所属关系的常用结构。","本句主语Epigenetics是单数名词，对应的谓语动词需要使用第三人称单数形式，所以用studies，这是主谓一致在专业英语中的基础应用，主语为单数学科名词时，谓语动词用单数形式。"]},"sentenceWithHints":"表观遗传学 研究 基因 表达 的 调控 机制"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (250, '{"words":[{"plural":"proteins","chinese":"蛋白质","english":"protein","examples":["Protein is essential for muscle growth.","This diet is high in protein."],"phonetic":"/ˈproʊtiːn/","partOfSpeech":"名词"},{"plural":"foldings","chinese":"折叠","english":"folding","examples":["The folding of the paper creates a crane.","Protein folding is a complex process."],"phonetic":"/ˈfoʊldɪŋ/","partOfSpeech":"名词"},{"plural":"problems","chinese":"问题","english":"problem","examples":["We need to solve this problem.","He has a health problem."],"phonetic":"/ˈprɑːbləm/","partOfSpeech":"名词"},{"chinese":"困扰","english":"plague","examples":["Floods have plagued this region for years.","Self-doubt plagues many young people."],"phonetic":"/pleɪɡ/","pastTense":"plagued","thirdPerson":"plagues","partOfSpeech":"动词","pastParticiple":"plagued","presentParticiple":"plaguing"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She told me a story."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"scientists","chinese":"科学家","english":"scientist","examples":["Many scientists are researching climate change.","She wants to be a scientist when she grows up."],"phonetic":"/ˈsaɪəntɪst/","partOfSpeech":"名词"},{"plural":"decades","chinese":"数十","english":"decade","examples":["She has lived here for decades.","Technology has changed a lot in the past two decades."],"phonetic":"/ˈdekeɪd/","partOfSpeech":"名词"},{"plural":"","chinese":"年","english":"","examples":["It takes three years to complete the course.","He is twenty years old."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","名词作定语的结构","高频学术动词的使用"],"explanations":["现在完成时结构为have/has+过去分词，强调动作从过去开始持续到现在，并且对现在仍有影响。本句中“困扰了科学家数十年”表示该问题从过去持续到现在，主语为单数第三人称“the protein folding problem”，因此使用has plagued。","英语中常用名词直接作定语修饰另一个名词，本句中“protein folding problem”就是用“protein（蛋白质）”和“folding（折叠）”两个名词作定语修饰“problem（问题）”，构成学术领域的特定术语，这种结构在科技、学术文本中十分常见。","plague作为动词，除了“使染瘟疫”的本义外，在学术语境中常用来表示“长期困扰、折磨”，比普通动词trouble更具书面性和学术性，适合用于正式的科技文本，符合大学阶段学术英语的用词要求。"]},"sentenceWithHints":"蛋白质 折叠 问题 困扰 了 科学家 数十 年"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (251, '{"words":[{"plural":"quanta","chinese":"量子","english":"quantum","examples":["Quantum physics is a complex subject.","A quantum is the smallest unit of a physical property."],"phonetic":"/ˈkwɑːntəm/","partOfSpeech":"名词"},{"plural":"decoherences","chinese":"退相干","english":"decoherence","examples":["Decoherence is a key concept in quantum mechanics.","The study focuses on the effects of decoherence."],"phonetic":"/ˌdiːkoʊˈhɪrəns/","partOfSpeech":"名词"},{"chinese":"解释了","english":"explain","examples":["The teacher explained the theory clearly.","This book explains how machines work."],"phonetic":"/ɪkˈspleɪn/","pastTense":"explained","thirdPerson":"explains","partOfSpeech":"动词","pastParticiple":"explained","presentParticiple":"explaining"},{"plural":"systems","chinese":"系统","english":"system","examples":["The computer system crashed suddenly.","We need to improve our management system."],"phonetic":"/ˈsɪstəm/","partOfSpeech":"名词"},{"chinese":"如何","english":"how","examples":["Can you tell me how to get there?","I don''t know how she did it."],"phonetic":"/haʊ/","partOfSpeech":"副词"},{"chinese":"与","english":"with","examples":["I often play games with my friends.","The cat sat with its owner."],"phonetic":"/wɪð/","partOfSpeech":"介词"},{"plural":"environments","chinese":"环境","english":"environment","examples":["We should protect the natural environment.","The company provides a positive work environment."],"phonetic":"/ɪnˈvaɪrənmənt/","partOfSpeech":"名词"},{"chinese":"相互作用","english":"interact","examples":["People interact with each other in various ways.","The two chemicals interact to produce a new substance."],"phonetic":"/ˌɪntərˈækt/","pastTense":"interacted","thirdPerson":"interacts","partOfSpeech":"动词","pastParticiple":"interacted","presentParticiple":"interacting"}],"examPoints":{"points":["专业领域词汇的英译","宾语从句的用法","动词时态与主谓一致"],"explanations":["本句涉及量子物理专业领域词汇，如“量子（quantum）”“退相干（decoherence）”，这类专业词汇有固定的英文对应表达，是大学阶段专业英语考查的重点，需要掌握专业领域的术语体系，确保翻译的准确性和专业性。","原句中“量子系统如何与环境相互作用”是宾语从句，在英文中由how引导，作explain的宾语。宾语从句需使用陈述语序，本句中“how quantum systems interact with the environment”符合这一规则，这是大学英语语法中复合句考查的核心知识点之一。","原句谓语“解释了”对应英文的一般现在时第三人称单数形式“explains”，因为主语“Quantum decoherence”是单数不可数名词，主谓一致要求谓语动词使用第三人称单数形式；同时“相互作用”对应“interact”，在宾语从句中因主语“quantum systems”是复数，使用动词原形，这体现了主谓一致和时态在具体语境中的应用，是大学英语语法的常考内容。"]},"sentenceWithHints":"量子 退相干 解释了 量子 系统 如何 与 环境 相互作用"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (252, '{"words":[{"plural":"","chinese":"全息","english":"holographic","examples":["Holographic technology creates 3D images.","The museum has a holographic display of ancient artifacts."],"phonetic":"/ˌhoʊləˈɡræfɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"principles","chinese":"原理","english":"principle","examples":["The principle of gravity was discovered by Newton.","We should follow the basic principles of morality."],"phonetic":"/ˈprɪnsəpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"认为","english":"suggest","examples":["The data suggests that the theory is correct.","I suggest we leave early to avoid traffic."],"phonetic":"/səˈdʒest/","pastTense":"suggested","thirdPerson":"suggests","partOfSpeech":"动词","pastParticiple":"suggested","presentParticiple":"suggesting"},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["Scientists are exploring the mysteries of the universe.","The universe is believed to be expanding."],"phonetic":"/ˈjuːnɪvɜːrs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"中","english":"in","examples":["There is a book in the box.","She lives in a small town."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The cover of the book is blue.","This is a photo of my family."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"所有","english":"all","examples":["All students must attend the meeting.","She ate all the cake."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"信息","english":"information","examples":["We need more information to make a decision.","The website provides useful information about travel."],"phonetic":"/ˌɪnfərˈmeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"all","examples":["They all agreed with the plan.","The books are all on the shelf."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"编码","english":"encode","examples":["We encode the data to protect it.","The message was encoded in a special format."],"phonetic":"/ɪnˈkoʊd/","pastTense":"encoded","thirdPerson":"encodes","partOfSpeech":"动词","pastParticiple":"encoded","presentParticiple":"encoding"},{"plural":"","chinese":"在","english":"on","examples":["The cup is on the table.","She put the keys on the counter."],"phonetic":"/ɑːn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"其","english":"its","examples":["The dog wagged its tail.","The company is known for its innovative products."],"phonetic":"/ɪts/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"boundaries","chinese":"边界","english":"boundary","examples":["The river forms the boundary between the two countries.","We need to set clear boundaries in this project."],"phonetic":"/ˈbaʊndri/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"上","english":"on","examples":["There is a scratch on the wall.","He wrote his name on the paper."],"phonetic":"/ɑːn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["学术词汇的掌握与运用","宾语从句的时态一致性","被动语态的使用","物主代词的指代"],"explanations":["本句属于学术文本，涉及holographic principle、universe、encode等专业学术词汇，这类词汇是大学阶段学术英语的核心考点，要求掌握其准确含义、词性搭配及在专业语境中的使用场景，是物理、天文等学科英文文献阅读与写作的基础。","句子中suggest后接that引导的宾语从句，主句使用一般现在时，从句描述客观科学理论，也使用一般现在时，这体现了宾语从句的时态一致性规则：当主句为一般现在时，从句可根据实际情况使用相应的时态，本句中客观真理类内容使用一般现在时。","从句中is encoded使用了一般现在时的被动语态，结构为“am/is/are+过去分词”，用于强调动作的承受者（information），在学术文本中，被动语态常用于客观陈述事实，避免主观化表达，是正式英语写作的常用结构。","句中的its是形容词性物主代词，指代前文的the universe，在英文写作中，物主代词的准确指代能避免重复，使句子更简洁，需要注意其与指代对象的单复数一致性，本句中universe是单数，所以使用its。"]},"sentenceWithHints":"全息 原理 认为 宇宙 中 的 所有 信息 都 编码 在 其 边界 上"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (253, '{"words":[{"chinese":"多重","english":"multiple","examples":["There are multiple ways to solve this problem.","She has multiple hobbies."],"phonetic":"/ˈmʌltəpəl/","partOfSpeech":"形容词"},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is vast and mysterious.","Scientists are exploring the origins of the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","partOfSpeech":"名词"},{"plural":"hypotheses","chinese":"假说","english":"hypothesis","examples":["The scientist put forward a new hypothesis.","We need to test this hypothesis through experiments."],"phonetic":"/haɪˈpɑːθəsɪs/","partOfSpeech":"名词"},{"chinese":"提出","english":"propose","examples":["He proposed a new plan for the project.","The committee will propose several solutions."],"phonetic":"/prəˈpoʊz/","pastTense":"proposed","thirdPerson":"proposes","partOfSpeech":"动词","pastParticiple":"proposed","presentParticiple":"proposing"},{"plural":"existences","chinese":"存在","english":"existence","examples":["The existence of aliens is still a mystery.","We should value the existence of every living thing."],"phonetic":"/ɪɡˈzɪstəns/","partOfSpeech":"名词"},{"chinese":"多个","english":"multiple","examples":["The project requires multiple resources.","He received multiple awards for his work."],"phonetic":"/ˈmʌltəpəl/","partOfSpeech":"形容词"},{"chinese":"平行","english":"parallel","examples":["There are parallel lines on the paper.","The two events developed in parallel."],"phonetic":"/ˈpærəlel/","partOfSpeech":"形容词"},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is vast and mysterious.","Scientists are exploring the origins of the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","partOfSpeech":"名词"}],"examPoints":{"points":["学术词汇的运用","名词性短语的翻译","可数名词的复数变化"],"explanations":["本句属于学术语境，涉及“multiverse”“hypothesis”“existence”等专业学术词汇，这类词汇是大学阶段英语学习中需要掌握的重点，用于准确表达专业领域的概念，在学术写作和阅读中高频出现。","中文里的动词“存在”在英文翻译中转化为名词性短语“the existence of”，这是汉英翻译中常见的词性转换技巧，符合英文的表达习惯，避免句式冗余，使句子结构更贴合英文的名词化表达特点。","句中“宇宙”对应的“universe”是可数名词，在表达“多个平行宇宙”时需要使用复数形式“universes”；“假说”对应的“hypothesis”是不规则可数名词，复数形式为“hypotheses”，这类可数名词的单复数变化是大学阶段英语语法的重要考点，尤其是不规则复数形式的记忆和运用。"]},"sentenceWithHints":"多重 宇宙 假说 提出 存在 多个 平行 宇宙"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (254, '{"words":[{"plural":"","chinese":"意识","english":"consciousness","examples":["Consciousness is a complex topic in philosophy.","She lost consciousness after the accident."],"phonetic":"/ˈkɑːnʃəsnəs/","partOfSpeech":"名词"},{"chinese":"与","english":"and","examples":["I like tea and coffee.","He is tall and strong."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"matters","chinese":"物质","english":"matter","examples":["Matter exists in three states: solid, liquid and gas.","The relationship between consciousness and matter is debated widely."],"phonetic":"/ˈmætər/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The color of the sky is blue.","This is the result of hard work."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"relationships","chinese":"关系","english":"relationship","examples":["The relationship between them is very close.","We need to improve our working relationship."],"phonetic":"/rɪˈleɪʃnʃɪp/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["This is my favorite book.","The key to success is hard work."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"philosophies","chinese":"哲学","english":"philosophy","examples":["He studies philosophy at university.","Her philosophy of life is to stay positive."],"phonetic":"/fəˈlɑːsəfi/","partOfSpeech":"名词"},{"chinese":"和","english":"and","examples":["She likes singing and dancing.","The conference is for doctors and nurses."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"","chinese":"神经科学","english":"neuroscience","examples":["Neuroscience explores the structure of the brain.","He is doing research in neuroscience."],"phonetic":"/ˈnʊroʊsaɪəns/","partOfSpeech":"名词"},{"chinese":"核心","english":"core","examples":["This is the core part of the plan.","The core issue needs to be solved first."],"phonetic":"/kɔːr/","partOfSpeech":"形容词"},{"plural":"issues","chinese":"问题","english":"issue","examples":["We need to discuss this issue carefully.","The environmental issue is getting more attention."],"phonetic":"/ˈɪʃuː/","partOfSpeech":"名词"}],"examPoints":{"points":["介词短语作定语的用法","学科类名词的使用","主谓一致原则"],"explanations":["本句中“意识与物质的关系”翻译为\"The relationship between consciousness and matter\"，使用介词短语\"between consciousness and matter\"作后置定语修饰relationship，在英语中，当表示两者之间的关系时，常用between连接两个对象，这种介词短语后置修饰名词的结构是英语书面语中常见的定语表达形式。","本句涉及的philosophy（哲学）、neuroscience（神经科学）都属于学科类名词，这类名词通常为不可数名词，一般不需要变复数，且表示“在某学科领域”时，常用介词in搭配，如\"in philosophy and neuroscience\"。","本句主语是\"The relationship\"，为单数可数名词，因此对应的系动词使用第三人称单数形式is，这符合英语主谓一致的原则，即主语为单数时，谓语动词需使用对应的单数形式。"]},"sentenceWithHints":"意识 与 物质 的 关系 是 哲学 和 神经科学 的 核心 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (255, '{"words":[{"plural":"","chinese":"因果","english":"causal","examples":["Causal analysis helps us understand the root cause.","There is a causal link between smoking and lung disease."],"phonetic":"/ˈkɔːzl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"reasonings","chinese":"推理","english":"reasoning","examples":["Logical reasoning is important for problem-solving.","His reasoning was based on solid evidence."],"phonetic":"/ˈriːznɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["She is a scientist.","This is a complex issue."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"人工智能","english":"artificial intelligence","examples":["Artificial intelligence is transforming many industries.","We need to study the ethics of artificial intelligence."],"phonetic":"/ˌɑːrtɪˈfɪʃl ɪnˈtelɪdʒəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"developments","chinese":"发展","english":"development","examples":["The development of new technology takes time.","Recent developments in medicine are promising."],"phonetic":"/dɪˈveləpmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["This is the cover of the book.","The result of the experiment was positive."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"关键","english":"key","examples":["The key factor is communication.","She played a key role in the project."],"phonetic":"/kiː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"challenges","chinese":"挑战","english":"challenge","examples":["This is a major challenge for us.","We need to overcome these challenges."],"phonetic":"/ˈtʃælɪndʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"之一","english":"one of","examples":["She is one of my best friends.","This is one of the most interesting books I''ve read."],"phonetic":"/wʌn əv/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配 one of 的用法","学科领域专业词汇的英译","介词 of 构成的所属结构"],"explanations":["one of 后必须接可数名词的复数形式，意为“……之一”，句子的谓语动词要与 one 保持一致，使用第三人称单数形式。本句中 one of 后接 key challenges，谓语动词用 is，符合该规则。","本句涉及人工智能领域的专业词汇，“因果推理”对应专业术语 causal reasoning，“人工智能”对应 artificial intelligence，这类专业词汇的准确翻译是翻译科技文本的核心要求，需要掌握特定领域的固定译法。","介词 of 用于构成所属结构，用来表示事物之间的所属关系，本句中“人工智能发展”译为 artificial intelligence development，也可表达为 the development of artificial intelligence，两种形式都体现了所属关系，在科技文本中常使用名词连用作定语的形式来简化表达。"]},"sentenceWithHints":"因果 推理 是 人工智能 发展 的 关键 挑战 之一"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (256, '{"words":[{"chinese":"拓扑","english":"topological","examples":["Topological insulators have unique electronic properties.","This is a topological structure."],"phonetic":"/ˌtɑːpəˈlɑːdʒɪkəl/","partOfSpeech":"形容词"},{"plural":"phase transitions","chinese":"相变","english":"phase transitions","examples":["Phase transitions are common in nature.","We study phase transitions in physics."],"phonetic":"/feɪz trænˈzɪʃənz/","partOfSpeech":"名词"},{"chinese":"揭示","english":"reveal","examples":["The research will reveal new secrets of the universe.","Her words revealed her true feelings."],"phonetic":"/rɪˈviːl/","pastTense":"revealed","thirdPerson":"reveals","partOfSpeech":"动词","pastParticiple":"revealed","presentParticiple":"revealing"},{"chinese":"了","english":"","examples":["He finished his homework.","I have eaten dinner."],"phonetic":"","partOfSpeech":"助词"},{"plural":"materials","chinese":"物质","english":"material","examples":["This material is very durable.","We need new building materials."],"phonetic":"/məˈtɪriəl/","partOfSpeech":"名词"},{"plural":"states","chinese":"状态","english":"states","examples":["Water has three states: solid, liquid and gas.","The patient''s state is stable."],"phonetic":"/steɪts/","partOfSpeech":"名词"},{"chinese":"的","english":"","examples":["The color of the sky is blue.","This is the book of my brother."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"深刻","english":"profound","examples":["He has a profound understanding of history.","The book has a profound influence on me."],"phonetic":"/prəˈfaʊnd/","partOfSpeech":"形容词"},{"plural":"laws","chinese":"规律","english":"laws","examples":["We must follow the laws of nature.","The law of gravity is a fundamental physical law."],"phonetic":"/lɔːz/","partOfSpeech":"名词"}],"examPoints":{"points":["专业领域词汇翻译","名词复数的运用","介词短语作定语"],"explanations":["本句属于物理专业领域内容，“拓扑相变”“物质状态”这类专业词汇需要对应英文专业表达“topological phase transitions”“material states”，这类词汇是大学物理及相关专业英语的重点考查内容，要求准确掌握专业术语的英文表述。","句子中“相变”“状态”“规律”均为可数名词，在表达泛指概念时需要使用复数形式，对应英文“phase transitions”“states”“laws”，考查可数名词复数在正式学术语境中的正确运用，体现学术文本中对事物类别的泛指表达习惯。","英文翻译中“of material states”是介词短语作后置定语修饰“laws”，对应中文中“物质状态的深刻规律”的前置定语结构，这是中英双语定语结构转换的重点，在学术英语中，介词短语作后置定语是常见的修饰方式，需要掌握这种结构转换规则，准确实现中英句式的对应翻译。"]},"sentenceWithHints":"拓扑 相变 揭示 了 物质 状态 的 深刻 规律"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (257, '{"words":[{"plural":"superstrings","chinese":"超弦","english":"superstring","examples":["Superstring theory is a complex physics concept.","Scientists study superstrings to understand the universe."],"phonetic":"/ˈsuːpərstrɪŋ/","partOfSpeech":"名词"},{"plural":"theories","chinese":"理论","english":"theory","examples":["This theory has been widely accepted.","He proposed a new theory about black holes."],"phonetic":"/ˈθɪri/","partOfSpeech":"名词"},{"chinese":"认为","english":"posit","examples":["The study posits that climate change affects crop yields.","He posited a new approach to solve the problem."],"phonetic":"/ˈpɑːzɪt/","pastTense":"posited","thirdPerson":"posits","partOfSpeech":"动词","pastParticiple":"posited","presentParticiple":"positing"},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is constantly expanding.","Scientists are exploring the mysteries of the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","partOfSpeech":"名词"},{"plural":"","chinese":"由","english":"of","examples":["The house is made of wood.","This book consists of 10 chapters."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"chinese":"振动","english":"vibrate","examples":["The phone vibrated in my pocket.","The guitar strings vibrate when plucked."],"phonetic":"/ˈvaɪbreɪt/","pastTense":"vibrated","thirdPerson":"vibrates","partOfSpeech":"动词","pastParticiple":"vibrated","presentParticiple":"vibrating"},{"plural":"","chinese":"的","english":"","examples":["The red apple is mine.","This is the book I told you about."],"phonetic":"","partOfSpeech":"助词"},{"plural":"strings","chinese":"弦","english":"string","examples":["The violin has four strings.","Superstring theory focuses on tiny strings."],"phonetic":"/strɪŋ/","partOfSpeech":"名词"},{"chinese":"组成","english":"be composed of","examples":["The committee is composed of five members.","Air is composed of nitrogen and oxygen."],"phonetic":"/biː kəmˈpoʊzd əv/","pastTense":"was/were composed of","thirdPerson":"is/are composed of","partOfSpeech":"动词","pastParticiple":"been composed of","presentParticiple":"being composed of"}],"examPoints":{"points":["专业领域词汇的英译","宾语从句的使用","被动语态短语be composed of的用法","现在分词作定语"],"explanations":["本句涉及物理学专业词汇，如“超弦理论”对应“Superstring theory”，这类专业词汇是大学阶段学术英语和专业英语学习的重点，需要准确掌握其英文表达，用于专业文献阅读和学术写作。","句子中“认为”后接的是宾语从句，在英文中用that引导，“Superstring theory posits that...”符合英语中及物动词后接宾语从句的语法结构，大学阶段需要掌握复杂宾语从句在正式学术语境中的使用。","“由……组成”在本句中译为“be composed of”，这是正式语境中常用的被动语态短语，强调构成的成分，区别于主动语态的“consist of”，在学术英语中常用于描述事物的构成，需要掌握其搭配和语境。","“振动的弦”译为“vibrating strings”，其中vibrating是现在分词作定语，修饰strings，体现弦的主动动作状态，在专业英语中，现在分词作定语常用于描述事物的动态属性，需要掌握其语法功能和使用场景。"]},"sentenceWithHints":"超弦 理论 认为 宇宙 由 振动 的 弦 组成"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (258, '{"words":[{"plural":"quanta","chinese":"量子","english":"quantum","examples":["Quantum physics is a complex subject.","A quantum is the smallest unit of energy."],"phonetic":"/ˈkwɑːntəm/","partOfSpeech":"名词"},{"plural":"tunnelings","chinese":"隧穿","english":"tunneling","examples":["Quantum tunneling is a key quantum phenomenon.","Tunneling enables particles to cross energy barriers."],"phonetic":"/ˈtʌnəlɪŋ/","partOfSpeech":"名词"},{"plural":"effects","chinese":"效应","english":"effect","examples":["The greenhouse effect warms the Earth.","This chemical has a positive effect on plants."],"phonetic":"/ɪˈfekt/","partOfSpeech":"名词"},{"chinese":"使","english":"allow","examples":["The rule allows us to leave early.","Technology allows people to connect easily."],"phonetic":"/əˈlaʊ/","pastTense":"allowed","thirdPerson":"allows","partOfSpeech":"动词","pastParticiple":"allowed","presentParticiple":"allowing"},{"plural":"particles","chinese":"粒子","english":"particle","examples":["Dust particles float in the air.","Subatomic particles include protons and electrons."],"phonetic":"/ˈpɑːrtɪkəl/","partOfSpeech":"名词"},{"chinese":"能够","english":"to","examples":["I want to go home.","She needs to finish her work."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"chinese":"穿过","english":"pass through","examples":["The light passes through the window.","We passed through the small town on our trip."],"phonetic":"/pæs θruː/","pastTense":"passed through","thirdPerson":"passes through","partOfSpeech":"动词短语","pastParticiple":"passed through","presentParticiple":"passing through"},{"plural":"barriers","chinese":"势垒","english":"barrier","examples":["The mountain is a natural barrier.","Energy barriers prevent particles from moving freely."],"phonetic":"/ˈbæriər/","partOfSpeech":"名词"}],"examPoints":{"points":["专业术语英译","动词短语搭配","使役动词用法","可数名词复数"],"explanations":["本句涉及量子物理专业术语，“量子隧穿效应”对应英文专业表达“Quantum tunneling effect”，这类专业术语需要准确记忆，是大学物理相关英语考核的重点内容。","“穿过”在这里对应动词短语“pass through”，该短语强调从物体内部或空间中穿过，在描述粒子穿过势垒的物理场景中是固定搭配，区别于“pass over”（从上方越过）等类似短语。","句中“使”对应使役动词“allow”，其常用结构为“allow sb./sth. to do sth.”，表示“使某人/某物能够做某事”，在正式书面语尤其是科技文本中是常见的使役表达。","句中“粒子”“势垒”均为可数名词，在表示泛指概念时需使用复数形式“particles”“barriers”，这体现了科技英语中名词单复数的规范用法，也是大学英语考核中名词用法的重点。"]},"sentenceWithHints":"量子 隧穿 效应 使 粒子 能够 穿过 势垒"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (259, '{"words":[{"plural":"","chinese":"热力学","english":"thermodynamics","examples":["Thermodynamics is a branch of physics.","We studied thermodynamics in our engineering class."],"phonetic":"/ˌθɜːrmoʊdaɪˈnæmɪks/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"第二","english":"second","examples":["This is my second cup of coffee today.","She won second place in the competition."],"phonetic":"/ˈsekənd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"laws","chinese":"定律","english":"law","examples":["Newton''s laws of motion are fundamental in physics.","We must obey the law."],"phonetic":"/lɔː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"揭示","english":"reveal","examples":["The investigation revealed some shocking facts.","Her smile revealed her true feelings."],"phonetic":"/rɪˈviːl/","pastTense":"revealed","thirdPerson":"reveals","partOfSpeech":"动词","pastParticiple":"revealed","presentParticiple":"revealing"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework.","She told me the truth."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is constantly expanding.","Scientists are exploring the mysteries of the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the sky is blue."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不可逆性","english":"irreversibility","examples":["The irreversibility of time is a common philosophical topic.","The second law of thermodynamics explains the irreversibility of natural processes."],"phonetic":"/ˌɪrɪvɜːrsəˈbɪləti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["专业术语的英译","名词所有格/所属关系的英文表达","谓语动词的第三人称单数形式"],"explanations":["本句涉及物理专业领域术语，如“热力学”对应“thermodynamics”、“不可逆性”对应“irreversibility”，这类专业术语的准确英译是大学专业英语的考查重点，要求学习者掌握学科专属词汇的固定表达。","中文中“宇宙的不可逆性”“热力学第二定律”这类所属关系，在英文中常用“of”结构来表达，即“the irreversibility of the universe”“the second law of thermodynamics”，这是英语中表示无生命事物所属关系的典型结构，是正式书面语尤其是学术文本中的常用表达。","本句主语“the second law of thermodynamics”是单数概念，所以谓语动词“reveal”需要使用第三人称单数形式“reveals”，这是英语主谓一致规则的体现，在正式学术文本中需严格遵循该规则保证语法正确性。"]},"sentenceWithHints":"热力学 第二 定律 揭示 了 宇宙 的 不可逆性"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (260, '{"words":[{"plural":"information theories","chinese":"信息论","english":"information theory","examples":["Information theory is a branch of applied mathematics.","We use information theory to analyze data transmission."],"phonetic":"/ˌɪnfərˈmeɪʃn ˈθɪri/","partOfSpeech":"名词"},{"plural":"","chinese":"为","english":"for","examples":["This book is for you.","She bought a gift for her sister."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"chinese":"理解","english":"understand","examples":["I can''t understand this math problem.","She understands the importance of learning."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"entropies","chinese":"熵","english":"entropy","examples":["Entropy is a key concept in thermodynamics.","The system''s entropy increases over time."],"phonetic":"/ˈentrəpi/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She sings and dances well."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"orders","chinese":"有序性","english":"order","examples":["The teacher maintained order in the classroom.","We need to restore order to the chaotic system."],"phonetic":"/ˈɔːrdər/","partOfSpeech":"名词"},{"chinese":"提供","english":"provide","examples":["The hotel provides free breakfast for guests.","This report provides useful data for our research."],"phonetic":"/prəˈvaɪd/","pastTense":"provided","thirdPerson":"provides","partOfSpeech":"动词","pastParticiple":"provided","presentParticiple":"providing"},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She has read that book."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"新","english":"new","examples":["I bought a new phone yesterday.","This is a new approach to solving the problem."],"phonetic":"/nuː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"perspectives","chinese":"视角","english":"perspective","examples":["From my perspective, this is a good idea.","The article offers a unique perspective on the issue."],"phonetic":"/pərˈspektɪv/","partOfSpeech":"名词"}],"examPoints":{"points":["学科专业词汇的英译","动词短语搭配","介词 for 的用法","动名词作介词宾语"],"explanations":["本句涉及信息论领域的专业词汇，如“信息论（information theory）”“熵（entropy）”，这类专业词汇是大学阶段学术英语的重点考查内容，要求准确掌握特定学科领域的固定英译表达，避免直译错误。","动词 provide 常见搭配为 provide sth. for sb./sth. 或 provide sb. with sth.，本句中使用 provide a new perspective for... 的结构，考查对该动词常用搭配的掌握，需注意介词的正确使用。","介词 for 在这里表用途、对象，引出动作的作用对象“understanding entropy and order”，大学英语中会考查介词在不同语境下的多样用法，区分 for 表目的、对象、原因等不同语义的场景。","介词 for 后面接动词时，需要将动词变为动名词形式（understanding），这是非谓语动词的重要考点，要求掌握介词后接动名词作宾语的规则，避免出现动词原形作宾语的错误。"]},"sentenceWithHints":"信息论 为 理解 熵 和 有序性 提供 了 新 视角"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (261, '{"words":[{"plural":"apples","chinese":"苹果","english":"apple","examples":["I like to eat an apple every day.","There are many apples in the basket."],"phonetic":"/ˈæpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数形式","水果类词汇识记"],"explanations":["apple是可数名词，单数形式表示单个苹果，前面可搭配不定冠词an；复数形式是在词尾加-s，即apples，用来表示多个苹果。","这是小学一年级需要掌握的基础水果类英语词汇，需要准确识记中文对应的英文表达，能在日常表达中正确使用。"]},"sentenceWithHints":"苹果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (262, '{"words":[{"plural":"bananas","chinese":"香蕉","english":"banana","examples":["I like eating bananas.","A banana is a kind of fruit."],"phonetic":"/bəˈnænə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数","水果类英文词汇"],"explanations":["banana是可数名词，单数形式为banana，复数形式是在词尾加-s变为bananas，小学阶段需要掌握常见可数名词的单复数变化规则。","小学一年级阶段需要积累常见的水果类英文词汇，banana是基础的水果词汇，需要掌握其拼写、发音和基本用法。"]},"sentenceWithHints":"香蕉"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (263, '{"words":[{"plural":"oranges","chinese":"橙子","english":"orange","examples":["I like orange.","There are three oranges on the table."],"phonetic":"/ˈɔːrɪndʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["水果类名词认知","可数名词复数变化"],"explanations":["本题考查小学阶段基础水果类名词的中英文对应认知，要求掌握常见水果“橙子”的英文表达orange。","orange作为可数名词，其复数形式遵循规则变化，在词尾直接加-s变为oranges，这是小学一年级需要掌握的基础名词复数变化规则。"]},"sentenceWithHints":"橙子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (264, '{"words":[{"plural":"strawberries","chinese":"草莓","english":"strawberry","examples":["I like strawberry ice cream.","Strawberries are my favorite fruit."],"phonetic":"/ˈstrɔːberi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数变化","水果类词汇识记"],"explanations":["strawberry是以辅音字母+y结尾的可数名词，变复数时需要把y改为i再加-es，即strawberries，这是小学阶段需要掌握的可数名词复数不规则变化规则之一。","小学一年级英语常考查常见水果类词汇的中英对应识记，strawberry是常见的水果词汇，需要掌握其拼写、发音和词义。"]},"sentenceWithHints":"草莓"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (265, '{"words":[{"plural":"grapes","chinese":"葡萄","english":"grape","examples":["I like eating grapes.","There is a grape on the plate."],"phonetic":"/ɡreɪp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数形式","水果类词汇识记"],"explanations":["grape是可数名词，单数形式表示单个葡萄，复数形式直接在词尾加-s变为grapes，用来表示多个葡萄，小学阶段需要掌握常见可数名词的单复数变化规则。","小学一年级英语会接触常见的水果类词汇，grape作为基础水果词汇，需要掌握其拼写、发音和基本用法，能在简单句子中正确使用。"]},"sentenceWithHints":"葡萄"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (266, '{"words":[{"plural":"watermelons","chinese":"西瓜","english":"watermelon","examples":["I like eating watermelon.","There are two watermelons on the table."],"phonetic":"/ˈwɔːtərmelən/","partOfSpeech":"名词"}],"examPoints":{"points":["常见水果类名词的识记","可数名词的复数变化"],"explanations":["小学一年级阶段需要掌握常见的水果类英文词汇，watermelon是表示西瓜的常用名词，属于基础必背词汇。","watermelon是可数名词，其复数形式遵循规则变化，直接在词尾加-s，即watermelons，这是小学阶段可数名词复数变化的基础规则之一。"]},"sentenceWithHints":"西瓜"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (267, '{"words":[{"plural":"pears","chinese":"梨","english":"pear","examples":["I like eating pear.","There are some pears on the table."],"phonetic":"/per/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["水果类名词的认知","可数名词的单复数变化"],"explanations":["小学一年级阶段需要掌握常见的水果类英文名词，pear是表示“梨”的基础名词，属于生活常用词汇，是低年级词汇积累的重点内容。","pear是可数名词，其复数形式遵循规则变化，直接在词尾加-s变为pears，需要掌握可数名词单数变复数的基本规则，了解单数和复数形式在不同语境中的使用。"]},"sentenceWithHints":"梨"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (268, '{"words":[{"plural":"peaches","chinese":"桃子","english":"peach","examples":["I like eating peach.","There are many peaches on the tree."],"phonetic":"/piːtʃ/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的单复数变化","水果类名词的英文表达"],"explanations":["peach是可数名词，以ch结尾的可数名词变复数时要加-es，所以它的复数形式是peaches。小学阶段需要掌握常见可数名词的复数变化规则，尤其是以s、x、ch、sh结尾的名词的复数变化。","小学一年级阶段需要积累常见的水果类英文词汇，peach表示桃子，是基础的水果类名词，需要掌握其拼写、发音和基本用法。"]},"sentenceWithHints":"桃子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (269, '{"words":[{"plural":"cherries","chinese":"樱桃","english":"cherry","examples":["I like eating cherries.","The cherry is red."],"phonetic":"/ˈtʃeri/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数变化","水果类词汇识记"],"explanations":["cherry是以辅音字母+y结尾的可数名词，变复数时要把y改为i再加-es，即cherries，这是小学阶段需要掌握的可数名词复数不规则变化规则之一。","小学一年级阶段需要识记常见的水果类英文词汇，cherry作为常见水果词汇，是基础词汇考察内容，要求能做到中英文对应认读。"]},"sentenceWithHints":"樱桃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (270, '{"words":[{"plural":"lemons","chinese":"柠檬","english":"lemon","examples":["I like lemon juice.","She bought two lemons from the store."],"phonetic":"/ˈlemən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数形式","常见水果类英语词汇"],"explanations":["lemon是可数名词，单数形式表示单个柠檬，复数形式直接在词尾加-s变为lemons，用来表示多个柠檬。小学阶段需要掌握常见可数名词的单复数变化规则。","小学一年级英语会接触常见的水果类词汇，lemon是其中的基础词汇，需要掌握其拼写、发音和基本含义，能对应中英文进行认读和简单表达。"]},"sentenceWithHints":"柠檬"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (271, '{"words":[{"plural":"cats","chinese":"猫","english":"cat","examples":["I have a cat.","The cat is cute."],"phonetic":"/kæt/","partOfSpeech":"名词"}],"examPoints":{"points":["常见动物类名词","可数名词的复数变化"],"explanations":["小学一年级阶段需要掌握常见动物类的英文词汇，cat是表示“猫”的基础名词，属于必学词汇。","cat是可数名词，其复数形式属于规则变化，直接在词尾加-s，变为cats，这是小学阶段可数名词复数变化的基础知识点。"]},"sentenceWithHints":"猫"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (272, '{"words":[{"plural":"dogs","chinese":"狗","english":"dog","examples":["I have a cute dog.","The dogs are playing in the yard."],"phonetic":"/dɔːɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数形式","基础动物类词汇"],"explanations":["dog是可数名词，单数形式为dog，复数形式是在词尾加-s变成dogs，用于表示多个狗的数量概念。","这是小学阶段需要掌握的基础动物类英文词汇，要求能准确对应中文意思，会认读、拼写，了解其单复数变化。"]},"sentenceWithHints":"狗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (273, '{"words":[{"plural":"birds","chinese":"鸟","english":"bird","examples":["A little bird is singing in the tree.","I saw three beautiful birds yesterday."],"phonetic":"/bɜːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数形式","基础动物类词汇"],"explanations":["bird是可数名词，单数形式表示一只鸟，复数形式是在词尾加-s变成birds，用来表示两只及以上的鸟，小学阶段需要掌握常见可数名词的单复数变化规则。","小学一年级英语会接触常见的动物类基础词汇，bird是其中的核心词汇之一，需要掌握其拼写、发音和基本含义，能对应中文和英文表达。"]},"sentenceWithHints":"鸟"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (274, '{"words":[{"plural":"fish/fishes","chinese":"鱼","english":"fish","examples":["I like eating fish.","There are many fish in the river."],"phonetic":"/fɪʃ/","partOfSpeech":"名词"}],"examPoints":{"points":["名词单复数同形/特殊复数形式","常见动物类名词"],"explanations":["fish表示“鱼的条数”时，单复数同形，都为fish；表示“鱼的种类”时，复数形式为fishes。小学阶段主要掌握表示“鱼的条数”时的用法。","fish是小学阶段需要掌握的常见动物类名词，属于基础词汇，需要掌握其拼写、发音和基本含义，能在简单句子中正确使用。"]},"sentenceWithHints":"鱼"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (275, '{"words":[{"plural":"rabbits","chinese":"兔子","english":"rabbit","examples":["A rabbit has long ears.","I saw a white rabbit in the garden."],"phonetic":"/ˈræbɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见动物类名词","名词复数变化规则"],"explanations":["小学一年级阶段需要掌握常见动物的英文表达，rabbit 是表示“兔子”的基础动物名词，属于必学词汇。","rabbit 是规则可数名词，其复数形式是在词尾直接加-s，变为 rabbits，这是小学阶段需要掌握的基础名词复数变化规则之一。"]},"sentenceWithHints":"兔子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (276, '{"words":[{"plural":"ducks","chinese":"鸭子","english":"duck","examples":["I see a duck in the pond.","There are many ducks on the lake."],"phonetic":"/dʌk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数变化","基础动物类词汇掌握"],"explanations":["鸭子是可数名词，属于规则变化的名词，复数形式直接在词尾加-s，即ducks。小学阶段需要掌握常见可数名词的单复数转换规则。","小学一年级英语会接触常见的动物类基础词汇，duck作为典型的动物词汇，是需要认读和拼写的核心基础词汇，要求能将中文和英文对应起来。"]},"sentenceWithHints":"鸭子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (277, '{"words":[{"plural":"chickens","chinese":"鸡","english":"chicken","examples":["I like chicken.","There are three chickens in the yard."],"phonetic":"/ˈtʃɪkɪn/","partOfSpeech":"名词"}],"examPoints":{"points":["常见动物类名词","名词复数变化"],"explanations":["小学一年级阶段需要掌握常见动物类的英文词汇，chicken是表示“鸡”的基础名词，属于重点识记内容。","chicken是可数名词，其复数形式属于规则变化，直接在词尾加-s，这是小学阶段需要掌握的名词复数基本变化规则之一。"]},"sentenceWithHints":"鸡"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (278, '{"words":[{"plural":"horses","chinese":"马","english":"horse","examples":["A horse is running on the grass.","I want to ride a white horse."],"phonetic":"/hɔːrs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见动物类名词的英译","可数名词的单复数变化"],"explanations":["小学一年级阶段需要掌握常见动物的英文表达，“马”对应的英文是horse，是基础的动物类词汇，属于必背词汇。","horse是可数名词，其复数形式遵循规则变化，在词尾加-s变为horses，这是小学阶段需要掌握的可数名词复数规则变化的基础知识点。"]},"sentenceWithHints":"马"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (279, '{"words":[{"plural":"cows","chinese":"牛","english":"cow","examples":["A cow is eating grass.","There are many cows on the farm."],"phonetic":"/kaʊ/","partOfSpeech":"名词"}],"examPoints":{"points":["常见动物类名词","名词复数变化规则"],"explanations":["小学一年级阶段需要掌握常见动物的英文表达，cow 是表示“奶牛；牛”的基础动物类名词，属于重点识记词汇。","可数名词变复数的规则变化：一般情况下在词尾直接加 -s，cow 属于规则变化名词，复数形式为 cows，这是小学阶段名词复数的基础知识点。"]},"sentenceWithHints":"牛"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (280, '{"words":[{"plural":"pigs","chinese":"猪","english":"pig","examples":["A pig is very cute.","There are three pigs on the farm."],"phonetic":"/pɪɡ/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的单复数","基础动物类词汇"],"explanations":["pig是可数名词，单数形式为pig，复数形式遵循规则变化，在词尾直接加-s变为pigs，小学阶段需要掌握常见可数名词的单复数变化规则。","这是小学一年级需要掌握的基础动物类英语词汇，要求能准确对应中文和英文，掌握其发音和基础用法。"]},"sentenceWithHints":"猪"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (281, '{"words":[{"plural":"","chinese":"红","english":"red","examples":["The apple is red.","I like red clothes."],"phonetic":"/red/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础颜色词汇","形容词的基础用法"],"explanations":["小学一年级阶段需要掌握常见基础颜色词汇，red是表示“红色”的核心英语词汇，是英语颜色类词汇学习的基础内容。","red作为形容词，主要用于修饰名词，描述事物的颜色属性，在简单句中常跟在be动词后作表语，如“The flower is red.”，这是形容词最基础的用法之一，适合低年级学生理解掌握。"]},"sentenceWithHints":"红"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (282, '{"words":[{"plural":"","chinese":"蓝","english":"blue","examples":["The sky is blue.","I have a blue pen."],"phonetic":"/bluː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["颜色类形容词的认知与翻译","美式音标发音"],"explanations":["小学一年级阶段开始接触基础颜色词汇，“蓝”对应的英文是blue，作为形容词用于描述事物的颜色，是英语入门的基础词汇，需要掌握其拼写和含义。","需要掌握blue的美式音标/bluː/，了解长元音/uː/的发音方式，准确读出该单词，为后续英语发音学习打基础。"]},"sentenceWithHints":"蓝"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (283, '{"words":[{"plural":"","chinese":"绿","english":"green","examples":["The grass is green.","I like green apples."],"phonetic":"/ɡriːn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础颜色词汇","形容词的基础用法"],"explanations":["小学一年级阶段需要掌握常见基础颜色词汇，green作为表示颜色的核心词汇之一，是重点识记内容，用于描述事物的色彩属性。","green作为形容词，主要用于修饰名词，说明事物的颜色特征，在简单句中常与be动词搭配构成“主语+be+形容词”的基础句型，描述事物的状态。"]},"sentenceWithHints":"绿"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (284, '{"words":[{"plural":"","chinese":"黄","english":"yellow","examples":["The sun is yellow.","I like yellow flowers."],"phonetic":"/ˈjeloʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["颜色类形容词的认知与翻译","美式音标的基础认读"],"explanations":["小学一年级阶段重点学习常见颜色类词汇，“黄”对应的英文是yellow，作为形容词用于描述事物的颜色，是基础的词汇积累内容，需要能准确完成中英互译。","要求掌握yellow的美式音标/ˈjeloʊ/，学会认读基础的美式发音，为后续的单词拼读和口语表达打基础。"]},"sentenceWithHints":"黄"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (285, '{"words":[{"plural":"","chinese":"黑","english":"black","examples":["The cat is black.","I have a black pen."],"phonetic":"/blæk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础颜色类形容词的认知与翻译","美式音标的认读"],"explanations":["小学一年级阶段重点学习常见基础颜色词汇，“黑”对应的英文是black，属于常用颜色形容词，用于描述事物的颜色属性，是英语入门的基础词汇。","需要掌握black的美式音标/blæk/，准确认读发音，这是小学低年级英语语音学习的基础内容，帮助建立音形对应关系。"]},"sentenceWithHints":"黑"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (286, '{"words":[{"plural":"","chinese":"白","english":"white","examples":["The snow is white.","I have a white shirt."],"phonetic":"/waɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础颜色词汇","形容词的基础用法"],"explanations":["小学一年级阶段需要掌握常见基础颜色词汇，white是表示“白色”的核心词汇，是英语颜色类词汇入门内容。","white作为形容词，用来修饰名词，描述事物的颜色属性，在句子中通常放在名词前作定语，比如修饰衣物、自然事物等，是形容词最基础的用法之一。"]},"sentenceWithHints":"白"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (287, '{"words":[{"plural":"oranges","chinese":"橙色","english":"orange","examples":["Orange is my favorite color.","I ate an orange this morning."],"phonetic":"/ˈɔːrɪndʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["颜色类名词的认知与翻译","可数名词的复数变化"],"explanations":["小学一年级阶段常考查基础颜色类词汇的中英对应，orange既可以表示颜色“橙色”，也可以表示水果“橙子”，此处根据语境翻译为表示颜色的名词。","orange作为可数名词（表示橙子时），复数形式为规则变化，直接在词尾加-s，即oranges；当表示颜色时，它也可作为不可数名词使用。"]},"sentenceWithHints":"橙色"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (288, '{"words":[{"plural":"purples","chinese":"紫色","english":"purple","examples":["Purple is my favorite color.","She likes to wear purple."],"phonetic":"/ˈpɜːrpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础颜色词汇认知","名词单复数变化"],"explanations":["小学一年级阶段需要掌握常见基础颜色类词汇，purple作为常见颜色词，是词汇积累的基础内容，用于识别和表达颜色概念。","purple作为可数名词时，复数形式为规则变化，直接在词尾加-s，即purples，可用于表示多种紫色调，这是小学阶段名词单复数基础规则的考查内容。"]},"sentenceWithHints":"紫色"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (289, '{"words":[{"plural":"","chinese":"粉色","english":"pink","examples":["The flower is pink.","She likes pink dresses."],"phonetic":"/pɪŋk/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["颜色类形容词的认知与翻译","基础词汇的拼写与发音"],"explanations":["小学一年级阶段需要掌握常见颜色类词汇的中英文对应，pink作为基础颜色形容词，用于描述事物的色彩属性，是日常英语词汇学习的基础内容。","该阶段要求掌握基础词汇的正确美式发音/pɪŋk/以及拼写，能够准确将中文颜色词“粉色”与英文“pink”对应起来，为后续英语表达打基础。"]},"sentenceWithHints":"粉色"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (290, '{"words":[{"plural":"","chinese":"棕色","english":"brown","examples":["The bear is brown.","I like brown shoes."],"phonetic":"/braʊn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["颜色类形容词的认知与翻译","美式音标的掌握"],"explanations":["小学一年级阶段重点基础词汇认知，brown作为常见的颜色类形容词，需要掌握其中文释义和英文表达，能够将中文颜色词和英文对应起来，满足基础的词汇认读需求。","需要掌握brown的美式音标/braʊn/，准确发音，这是小学低年级英语学习中语音部分的基础内容，为后续的听说能力打基础。"]},"sentenceWithHints":"棕色"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (291, '{"words":[{"plural":"","chinese":"灰色","english":"gray","examples":["The cat is gray.","I like the gray hat."],"phonetic":"/ɡreɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["颜色类词汇的认知与翻译"],"explanations":["小学一年级阶段重点考查基础颜色类词汇的中英文对应，gray是表示“灰色”的常用英文词汇，需要掌握其拼写、发音和基本用法，能够在简单语境中进行中英文转换。"]},"sentenceWithHints":"灰色"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (292, '{"words":[{"plural":"","chinese":"一","english":"one","examples":["I have one apple.","One plus one is two."],"phonetic":"/wʌn/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与运用"],"explanations":["基数词用于表示数量，\"一\"对应的英文基数词是\"one\"，是小学阶段需要掌握的基础数词，常用于表达单个物品的数量、简单的数学运算等场景。"]},"sentenceWithHints":"一"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (293, '{"words":[{"plural":"","chinese":"二","english":"two","examples":["I have two apples.","Two plus three is five."],"phonetic":"/tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与拼写","基数词的基本用法"],"explanations":["小学一年级阶段需要掌握基础基数词的中文与英文对应拼写，“二”对应的英文是two，要能准确识别和书写该单词，区分其与其他数字单词的差异。","基数词two用于表示数量，用来描述人或事物的具体数目，可直接修饰可数名词复数，比如“two apples（两个苹果）”，在简单的数学运算表达中也会用到，比如“Two plus one is three.（二加一等于三）”。"]},"sentenceWithHints":"二"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (294, '{"words":[{"plural":"","chinese":"三","english":"three","examples":["I have three apples.","Three cats are under the tree."],"phonetic":"/θriː/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与翻译","基数词的用法"],"explanations":["本题考查中文基数词“三”对应的英文表达“three”，属于小学一年级基础词汇认知，要求掌握中文数字到英文基数词的对应转换。","基数词“three”用于表示数量，后可接可数名词复数，用来描述具体的数量，是小学阶段数词学习的基础内容，为后续更大数字的学习铺垫。"]},"sentenceWithHints":"三"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (295, '{"words":[{"plural":"","chinese":"四","english":"four","examples":["I have four apples.","There are four seasons in a year."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认读与翻译","基数词的用法"],"explanations":["基数词主要用于表示数量，“四”对应的英文基数词是four，这是小学阶段需要掌握的基础数字词汇，要求能准确认读和互译。","基数词four可以用来修饰可数名词复数，用来描述具体的数量，比如修饰apples、books等可数名词，放在名词前表示数量为四个。"]},"sentenceWithHints":"四"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (296, '{"words":[{"plural":"","chinese":"五","english":"five","examples":["I have five apples.","She is five years old."],"phonetic":"/faɪv/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认读与翻译","基数词的基本用法"],"explanations":["本题考查中文基数词“五”对应的英文表达“five”的认读与互译，是小学低年级英语数字类的基础考点，需要熟练掌握1-10的英文数字拼写与发音。","基数词“five”用于表示数量，可用来描述人或事物的个数，后可接可数名词复数，也可用于表达年龄等场景，是英语中数量表达的基础词汇。"]},"sentenceWithHints":"五"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (297, '{"words":[{"plural":"","chinese":"六","english":"six","examples":["I have six apples.","She is six years old."],"phonetic":"/sɪks/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与翻译"],"explanations":["基数词用于表示数量，“六”对应的英文基数词是six，属于小学一年级需要掌握的基础数字词汇，主要考查对中文数字到英文数字的对应转换，以及该词汇在简单数量表达场景中的运用。"]},"sentenceWithHints":"六"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (298, '{"words":[{"plural":"","chinese":"七","english":"seven","examples":["I have seven apples.","She is seven years old."],"phonetic":"/ˈsevən/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与拼写","基数词的用法"],"explanations":["小学一年级阶段需要掌握基础基数词的中英文对应及拼写，seven是表示数量“七”的英文基数词，是数字类词汇的基础内容，需要准确记忆其发音和拼写。","基数词主要用于表示数量，可用来描述事物的个数、年龄等，如例句中表示苹果的数量和人的年龄，这是小学阶段基数词最基础的应用场景。"]},"sentenceWithHints":"七"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (299, '{"words":[{"plural":"","chinese":"八","english":"eight","examples":["I have eight apples.","She is eight years old."],"phonetic":"/eɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与翻译","基数词的读音"],"explanations":["基数词用于表示数量，“八”对应的英文基数词是eight，属于小学阶段需要掌握的基础数字词汇，用于描述人或事物的数量。","该单词的美式音标为/eɪt/，需要掌握正确的发音，这是小学一年级英语语音学习的基础内容，为后续的数字表达和听力理解打基础。"]},"sentenceWithHints":"八"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (300, '{"words":[{"plural":"","chinese":"九","english":"nine","examples":["I have nine apples.","She is nine years old."],"phonetic":"/naɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与拼写","基数词的用法"],"explanations":["小学一年级阶段需要掌握基础基数词的拼写和对应中文含义，nine是表示数字“九”的英文基数词，是英语数字体系中基础的词汇之一，需要准确记忆其拼写和发音。","基数词nine主要用于表示数量或年龄等，后接可数名词复数时表示具体的数量，如“nine books”（九本书）；用于年龄表达时常见结构为“sb. + be + nine + years old”，表示某人九岁。"]},"sentenceWithHints":"九"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (301, '{"words":[{"plural":"","chinese":"十","english":"ten","examples":["I have ten apples.","She is ten years old."],"phonetic":"/ten/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基数词的认知与翻译","数词的基础用法"],"explanations":["本题考查中文基数词“十”对应的英文表达“ten”，属于小学低年级基础的数词认知内容，需要掌握中文数字与英文基数词的对应转换。","基数词“ten”用于表示数量，可用来描述人或事物的个数，也可用于表达年龄、时间等，是英语数词体系中基础的词汇，是后续学习更大数字和数词相关用法的基础。"]},"sentenceWithHints":"十"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (302, '{"words":[{"plural":"tables","chinese":"桌子","english":"table","examples":["There is a table in the room.","Put the book on the table."],"phonetic":"/ˈteɪbəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见物品类名词的英译","可数名词的复数变化"],"explanations":["小学一年级阶段需要掌握常见生活物品的英文表达，“桌子”对应的英文是table，属于基础必背词汇。","table是可数名词，其复数形式遵循规则变化，在词尾直接加-s变为tables，这是小学阶段需要掌握的名词复数基础变化规则。"]},"sentenceWithHints":"桌子"}');
