INSERT INTO question_hints (question_id, hint_data) VALUES (325, '{"words":[{"plural":"buses","chinese":"公交车","english":"bus","examples":["I take the bus to school every day.","There are many buses on the road."],"phonetic":"/bʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数变化","常见交通工具类名词"],"explanations":["bus是以s结尾的可数名词，变复数时需要加-es，属于可数名词复数变化的规则变形，小学阶段需要掌握这类以s、x、ch、sh结尾的名词变复数加-es的规则。","小学一年级阶段需要积累常见的交通工具类英文名词，bus是最基础的交通工具词汇之一，用于表达日常出行的公共交通工具，需要掌握其拼写、发音和基础用法。"]},"sentenceWithHints":"公交车"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (326, '{"words":[{"plural":"trains","chinese":"火车","english":"train","examples":["I take the train to school every day.","The train is coming."],"phonetic":"/treɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见交通工具类名词","名词复数变化规则"],"explanations":["小学阶段需要掌握常见的交通工具类英文词汇，train是其中基础且常用的一个，用于表达“火车”这一交通工具。","train是规则可数名词，其复数形式直接在词尾加-s，符合一般可数名词变复数的规则，是小学阶段需要掌握的基础语法点。"]},"sentenceWithHints":"火车"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (327, '{"words":[{"plural":"planes","chinese":"飞机","english":"plane","examples":["I see a plane in the sky.","The plane is flying high."],"phonetic":"/pleɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见交通工具类名词","名词复数变化规则"],"explanations":["小学一年级阶段需要掌握常见的交通工具类英文词汇，plane是表示“飞机”的基础英文表达，属于必须掌握的日常词汇。","plane是规则可数名词，其复数形式直接在词尾加-s，变为planes，这是小学阶段需要掌握的名词复数基本变化规则之一。"]},"sentenceWithHints":"飞机"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (328, '{"words":[{"plural":"boats","chinese":"船","english":"boat","examples":["I have a small boat.","We rowed the boat across the lake."],"phonetic":"/boʊt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见物品类名词的认知","名词复数的规则变化"],"explanations":["小学一年级阶段需要掌握常见生活、物品类的英文名词，“船（boat）”属于基础的交通工具类名词，是低年级词汇积累的重点内容。","boat是规则可数名词，其复数形式直接在词尾加-s，这是名词复数最基础的规则变化形式，是低年级需要掌握的名词变形基础知识点。"]},"sentenceWithHints":"船"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (329, '{"words":[{"plural":"suns","chinese":"太阳","english":"sun","examples":["The sun rises in the east.","The sun is shining brightly."],"phonetic":"/sʌn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础名词认知","专有名词的使用"],"explanations":["小学一年级阶段重点积累常见事物的英文对应名词，“太阳”对应的英文是sun，属于生活中常见的自然事物类名词，是基础词汇积累内容。","表示世界上独一无二的事物（如太阳、月亮、地球）时，sun前通常要加定冠词the，构成the sun，这是专有名词类的基础使用规则，也是低年级需要初步接触的知识点。"]},"sentenceWithHints":"太阳"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (330, '{"words":[{"plural":"moons","chinese":"月亮","english":"moon","examples":["The moon is bright tonight.","Some planets have many moons."],"phonetic":"/muːn/","partOfSpeech":"名词"}],"examPoints":{"points":["常见天体类名词","名词复数变化规则"],"explanations":["小学阶段需要掌握常见的自然事物类名词，moon作为表示天体的基础名词，是一年级词汇学习的重点内容，用于描述夜晚的月球。","moon是规则可数名词，其复数形式直接在词尾加-s，符合一般可数名词变复数的规则，这是一年级需要初步接触的名词变形知识点。"]},"sentenceWithHints":"月亮"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (331, '{"words":[{"plural":"stars","chinese":"星星","english":"star","examples":["Look at the bright star in the sky.","There are many stars at night."],"phonetic":"/stɑːr/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数变化","常见天体类名词的英文表达"],"explanations":["star是可数名词，单数形式表示一颗星星，复数形式直接在词尾加-s变为stars，用来表示多颗星星，这是小学阶段需要掌握的规则可数名词复数变化规则。","星星属于常见的天体类词汇，是小学低年级需要积累的基础英文名词，需要掌握其正确的英文拼写和发音，能对应中文和英文的含义。"]},"sentenceWithHints":"星 星"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (332, '{"words":[{"plural":"skies","chinese":"天","english":"sky","examples":["The sky is blue.","Birds fly in the sky."],"phonetic":"/skaɪ/","partOfSpeech":"名词"},{"plural":"skies","chinese":"空","english":"sky","examples":["The sky is blue.","Birds fly in the sky."],"phonetic":"/skaɪ/","partOfSpeech":"名词"}],"examPoints":{"points":["常见名词的英译","名词的复数形式"],"explanations":["“天空”对应的基础英文名词是sky，是小学阶段需要掌握的常见自然类名词，用于描述我们头顶的广阔空间。","sky作为可数名词，复数形式为skies，通常用于描述不同区域的天空或者文学性表达中，小学阶段需要掌握其基础的单复数变化。"]},"sentenceWithHints":"天 空"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (333, '{"words":[{"plural":"clouds","chinese":"云","english":"cloud","examples":["A white cloud is in the sky.","The clouds are turning dark."],"phonetic":"/klaʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见自然类名词的认知","可数名词的单复数变化"],"explanations":["小学一年级阶段需要掌握常见的自然事物类名词，“云”对应的英文cloud是基础自然名词，属于必学词汇，用于识别和表达自然事物。","cloud是可数名词，单数形式为cloud，复数形式直接在词尾加-s变为clouds，这是可数名词复数变化的规则形式，是小学阶段名词变形的基础知识点。"]},"sentenceWithHints":"云"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (334, '{"words":[{"plural":"rains","chinese":"雨","english":"rain","examples":["I love the rain.","The rain is falling."],"phonetic":"/reɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"雨","english":"rain","examples":["It rained all day yesterday.","It is raining outside."],"phonetic":"/reɪn/","pastTense":"rained","thirdPerson":"rains","partOfSpeech":"动词","pastParticiple":"rained","presentParticiple":"raining"}],"examPoints":{"points":["一词多义（兼类词）","名词复数形式","动词变形规则"],"explanations":["“雨”既可以作名词，表示一种自然降水现象；也可以作动词，表示下雨的动作，在英语中对应的rain也兼具名词和动词两种词性，这是小学阶段需要掌握的基础兼类词知识点。","rain作为可数名词（表示阵雨等具体的降雨）时，复数形式是在词尾加-s，变为rains，小学一年级需要初步了解可数名词的复数变形规则。","rain作为规则动词，过去式和过去分词直接在词尾加-ed，第三人称单数形式加-s，现在分词去词尾不发音的e再加-ing，这是小学阶段基础的规则动词变形知识点。"]},"sentenceWithHints":"雨"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (335, '{"words":[{"plural":"snows","chinese":"雪","english":"snow","examples":["It''s going to snow tomorrow.","The snow is white and soft."],"phonetic":"/snoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"雪","english":"snow","examples":["It snowed heavily last night.","It is snowing outside now."],"phonetic":"/snoʊ/","pastTense":"snowed","thirdPerson":"snows","partOfSpeech":"动词","pastParticiple":"snowed","presentParticiple":"snowing"}],"examPoints":{"points":["一词多义（兼类词）","名词复数规则","动词变形规则"],"explanations":["“雪”既可以作名词，表示自然界的降雪物质，也可以作动词，表示下雪的动作，属于兼类词，在不同语境中词性和含义不同。","snow作名词时，属于可数/不可数兼类名词，表“降雪”这类物质时不可数，表“多次降雪”时可数，复数形式为规则变化，直接加-s。","snow作动词时，是规则动词，过去式和过去分词直接加-ed，第三人称单数加-s，现在分词去w加-ing。"]},"sentenceWithHints":"雪"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (336, '{"words":[{"plural":"winds","chinese":"风","english":"wind","examples":["The wind is blowing strongly.","A gentle wind is blowing."],"phonetic":"/wɪnd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见名词的汉英对应","名词复数的规则变化"],"explanations":["小学一年级阶段需要掌握常见自然事物的英文表达，“风”对应的英文是wind，属于基础词汇积累内容。","wind是规则可数名词，其复数形式直接在词尾加-s，变为winds，这是名词复数的基础规则变化，是小学低年级需要掌握的语法点。"]},"sentenceWithHints":"风"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (337, '{"words":[{"plural":"flowers","chinese":"花","english":"flower","examples":["I like this red flower.","There are many beautiful flowers in the garden."],"phonetic":"/ˈflaʊər/","partOfSpeech":"名词"}],"examPoints":{"points":["常见植物类名词的英译","可数名词的复数变化"],"explanations":["小学一年级阶段需掌握常见事物的英文表达，“花”对应的英文是flower，属于基础植物类词汇，是日常英语词汇积累的重点内容。","flower是可数名词，其复数形式属于规则变化，直接在词尾加-s变为flowers，这是小学阶段可数名词复数变化的基础规则之一，需要掌握。"]},"sentenceWithHints":"花"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (338, '{"words":[{"plural":"trees","chinese":"树","english":"tree","examples":["There is a big tree in the yard.","Many trees turn green in spring."],"phonetic":"/triː/","partOfSpeech":"名词"}],"examPoints":{"points":["常见植物类名词","可数名词的单复数变化"],"explanations":["这是小学阶段需要掌握的常见植物类基础名词，用于描述自然界中的树木，是日常词汇积累的重要内容。","tree是可数名词，其复数形式属于规则变化，直接在词尾加-s变为trees，小学阶段需要掌握这类可数名词的基本单复数变形规则。"]},"sentenceWithHints":"树"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (339, '{"words":[{"plural":"grasses","chinese":"草","english":"grass","examples":["The grass is green.","Don''t walk on the grass."],"phonetic":"/ɡræs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见不可数名词的可数用法","小学阶段基础名词认知"],"explanations":["grass表示“草；草地”时通常作为不可数名词使用，当表示“多种草类”时可作为可数名词，复数形式为grasses，小学阶段主要掌握其不可数的常用用法。","这是小学一年级需要掌握的基础植物类名词，要求能识别中文对应的英文单词，掌握其美式发音和基础表意。"]},"sentenceWithHints":"草"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (340, '{"words":[{"plural":"mountains","chinese":"山","english":"mountain","examples":["There is a high mountain near my village.","We climbed the mountain together last weekend."],"phonetic":"/ˈmaʊntn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数","基础名词的中英对应"],"explanations":["mountain是可数名词，其复数形式遵循规则变化，在词尾加-s变为mountains，用于表示多座山的情况。","作为小学一年级的基础词汇，需要掌握“山”与“mountain”的中英对应，能识别并正确拼写该单词，积累常见自然类名词词汇。"]},"sentenceWithHints":"山"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (341, '{"words":[{"plural":"rivers","chinese":"河","english":"river","examples":["There is a small river near my home.","The river is very clean."],"phonetic":"/ˈrɪvər/","partOfSpeech":"名词"}],"examPoints":{"points":["常见可数名词的英译","可数名词的复数变形"],"explanations":["小学一年级阶段需要掌握常见事物的英文对应表达，“河”对应的英文是river，属于基础生活类名词，是低年级英语词汇积累的重点内容。","river是规则可数名词，其复数形式直接在词尾加-s变为rivers，这是可数名词复数变形的基础规则，低年级需要掌握这类规则变化的形式。"]},"sentenceWithHints":"河"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (342, '{"words":[{"plural":"lakes","chinese":"湖","english":"lake","examples":["There is a small lake near my home.","We went fishing by the lake."],"phonetic":"/leɪk/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的单复数","基础名词认知"],"explanations":["lake是可数名词，单数形式表示单个湖泊，复数形式在词尾加-s变为lakes，用来表示多个湖泊。","这是小学一年级需要掌握的基础自然类名词，用于识别和表达自然界中的湖泊这一事物，是英语词汇积累的基础内容。"]},"sentenceWithHints":"湖"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (343, '{"words":[{"plural":"seas","chinese":"海","english":"sea","examples":["The sea is blue.","We went to the sea last summer."],"phonetic":"/siː/","partOfSpeech":"名词"}],"examPoints":{"points":["常见名词的英译","可数名词的复数变化"],"explanations":["这是小学阶段需要掌握的基础名词英译，要求能准确对应中文“海”和英文“sea”。","“sea”是可数名词，其复数形式为规则变化，直接在词尾加“-s”变为“seas”，用于表示多个海域。"]},"sentenceWithHints":"海"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (344, '{"words":[{"plural":"eyes","chinese":"眼睛","english":"eye","examples":["I have two eyes.","Her eyes are blue."],"phonetic":"/aɪ/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的单复数变化","基础身体部位词汇"],"explanations":["eye是可数名词，单数形式表示一只眼睛，复数形式是在词尾加-s变为eyes，用于表示两只或多只眼睛，小学阶段需要掌握这类规则可数名词的复数变化。","身体部位类词汇是小学一年级英语的基础词汇，eye作为常见的身体部位单词，需要掌握其拼写、发音和基本用法，能对应中文含义并在简单句子中使用。"]},"sentenceWithHints":"眼睛"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (345, '{"words":[{"plural":"noses","chinese":"鼻子","english":"nose","examples":["I have a big nose.","The dog''s nose is wet."],"phonetic":"/noʊz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["常见身体部位类名词","名词复数变化规则"],"explanations":["小学一年级阶段需要掌握常见的身体部位类英文词汇，nose 是表示“鼻子”的基础名词，属于必学的身体部位词汇之一。","nose 是规则可数名词，其复数形式直接在词尾加 -s，这是小学阶段需要掌握的基础名词复数变化规则，用于表示多个同类事物。"]},"sentenceWithHints":"鼻子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (346, '{"words":[{"plural":"mouths","chinese":"嘴巴","english":"mouth","examples":["Open your mouth, please.","She has a small mouth."],"phonetic":"/maʊθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["基础身体部位名词识记","名词复数变形规则"],"explanations":["小学一年级阶段重点积累常见身体部位类基础名词，mouth 是表示“嘴巴”的核心词汇，是日常英语表达和基础词汇学习的重要内容。","mouth 作为可数名词，其复数变形属于规则变化，在词尾直接加 -s 变为 mouths，需要掌握这类一般可数名词的复数变化规则。"]},"sentenceWithHints":"嘴巴"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (347, '{"words":[{"plural":"ears","chinese":"耳朵","english":"ear","examples":["I have two ears.","His ear hurts."],"phonetic":"/ɪr/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数","身体部位类词汇"],"explanations":["ear是可数名词，单数形式表示单个耳朵，复数形式在词尾加-s变为ears，用于表示两个或多个耳朵，小学阶段需要掌握可数名词单复数的基础变化规则。","耳朵属于常见的身体部位类英语词汇，是小学低年级英语的基础必学内容，需要掌握这类词汇的拼写、发音和基本用法，能对应身体部位进行词汇认知。"]},"sentenceWithHints":"耳朵"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (348, '{"words":[{"plural":"hands","chinese":"手","english":"hand","examples":["I have two hands.","She raised her hand."],"phonetic":"/hænd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的单复数","基础身体部位词汇"],"explanations":["hand是可数名词，单数形式表示一只手，复数形式在词尾加-s变为hands，表示两只或多只手，小学阶段需要掌握常见可数名词的单复数变化规则。","手是基础的身体部位词汇，小学一年级要求掌握常见身体部位的英文表达，能对应中英文词汇，完成基础的词汇认读和拼写。"]},"sentenceWithHints":"手"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (349, '{"words":[{"plural":"feet","chinese":"脚","english":"foot","examples":["I hurt my foot when I fell.","The table has four feet."],"phonetic":"/fʊt/","partOfSpeech":"名词"}],"examPoints":{"points":["不规则名词的复数变化","常见身体部位词汇"],"explanations":["foot属于不规则变化的名词，它的复数形式不是常规的加-s，而是变为feet，这是小学阶段需要重点记忆的不规则名词复数形式之一。","脚是常见的身体部位，对应的英文foot是小学低年级需要掌握的基础词汇，用于描述身体部位，在日常表达和简单写作中会经常用到。"]},"sentenceWithHints":"脚"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (350, '{"words":[{"plural":"hairs","chinese":"头发","english":"hair","examples":["Her hair is long.","There are two white hairs on his head."],"phonetic":"/her/","partOfSpeech":"名词"}],"examPoints":{"points":["可数与不可数名词的用法","名词单复数变化"],"explanations":["hair表示整体的头发时，是不可数名词，比如描述头发的长短、颜色等整体特征时，不需要变复数；当表示具体的几根头发时，是可数名词，此时可以使用复数形式hairs。","hair作为可数名词时，复数形式是在词尾加-s，属于规则变化。小学阶段需要掌握这类常见名词的可数与不可数两种用法的区分。"]},"sentenceWithHints":"头发"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (501, '{"words":[{"plural":"","chinese":"你","english":"you","examples":["You are my best friend.","What do you want?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"去","english":"go","examples":["I go to school every day.","She goes to the park on weekends."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"","chinese":"哪里","english":"where","examples":["Where is my pen?","Where do you live?"],"phonetic":"/wer/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["特殊疑问句结构","现在进行时表将来用法"],"explanations":["本句是特殊疑问句，特殊疑问词where放在句首，后面跟一般疑问句语序，即be动词are提前至主语you之前，构成\"Where + be动词 + 主语 + 现在分词\"的结构，用来询问对方的去向。","这里使用现在进行时\"are going\"来表示将来的计划或打算，是小学阶段需要掌握的现在进行时的特殊用法，用来询问对方即将要去的地方，这种用法常用于表示位置移动的动词，如go、come等。"]},"sentenceWithHints":"你 去 哪里"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (504, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love apples.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"回家","english":"go home","examples":["I go home at 5 every day.","She is going home now."],"phonetic":"/ɡoʊ hoʊm/","pastTense":"went home","thirdPerson":"goes home","partOfSpeech":"动词","pastParticiple":"gone home","presentParticiple":"going home"}],"examPoints":{"points":["现在进行时表将来","固定短语go home"],"explanations":["现在进行时结构为be动词+动词的现在分词形式，除了表示正在进行的动作，还可以表示即将发生的计划好的动作，本句用I am going home表达“我要回家”这个即将发生的动作，符合小学一年级对将来动作表达的考查要求。","go home是固定动词短语，home在这里是副词，前面不需要加介词to，这是小学阶段需要掌握的常用固定搭配，要和go to school这类加介词的短语区分开。"]},"sentenceWithHints":"我 回家"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (505, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is a cat.","This book is mine."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["She is a student.","It is a dog."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"什么","english":"what","examples":["What is your name?","What do you like?"],"phonetic":"/wɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["特殊疑问句结构","指示代词与be动词的搭配"],"explanations":["本句是询问事物的特殊疑问句，英语中此类疑问句结构为“特殊疑问词 + be动词 + 主语”，这里特殊疑问词是what，用于对事物内容进行提问。","指示代词this表示“这，这个”，属于第三人称单数概念，所以搭配be动词的第三人称单数形式is，这是小学阶段需要掌握的基础主谓一致内容。"]},"sentenceWithHints":"这 是 什么"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (506, '{"words":[{"plural":"","chinese":"那","english":"that","examples":["That is a cat.","I like that book."],"phonetic":"/ðæt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a student.","It is a dog."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"什么","english":"what","examples":["What is your name?","What do you like?"],"phonetic":"/wɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["特殊疑问句的构成","指示代词的用法","be动词的单数形式"],"explanations":["询问事物的特殊疑问句“What is that?”，结构为“特殊疑问词 + be动词 + 主语”，用于对未知事物进行提问，这是小学阶段基础的疑问句式。","指示代词that用于指代远处的单数事物，在本句中作为主语，对应中文的“那”，是小学一年级需要掌握的基础指代词汇。","当主语是单数的指示代词that时，be动词要用单数形式is，这是be动词和主语的主谓一致基础规则，是低年级英语的核心知识点之一。"]},"sentenceWithHints":"那 是 什么"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (507, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my pen.","This cat is cute."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["He is a boy.","It is a dog."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"apples","chinese":"苹果","english":"apple","examples":["I like apples.","An apple a day keeps the doctor away."],"phonetic":"/ˈæpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["指示代词的使用","不定冠词an的用法","系动词is的搭配"],"explanations":["指示代词this用于指代近处的单数人或事物，在本句中用来指代近处的苹果，符合小学一年级对基础指示代词的考查要求。","不定冠词an用于以元音音素开头的可数名词单数前，apple是以元音音素/æ/开头的单词，所以前面要用an而不是a，这是小学阶段冠词使用的基础考点。","系动词is用于第三人称单数主语之后，本句中主语this属于第三人称单数，因此搭配is，这是be动词基础用法的核心考点之一。"]},"sentenceWithHints":"这 是 苹果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (508, '{"words":[{"plural":"","chinese":"那","english":"that","examples":["That is a cat.","Look at that tree."],"phonetic":"/ðæt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["He is a boy.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"bananas","chinese":"香蕉","english":"banana","examples":["I like banana.","She eats a banana every day."],"phonetic":"/bəˈnænə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["指示代词的使用","系动词be的搭配","可数名词单数的冠词使用"],"explanations":["that作为指示代词，用于指代远处的单数人或事物，对应近处的this，小学阶段主要掌握其指代单数事物的基础用法。","系动词is用于第三人称单数主语之后，本句主语that是单数指示代词，因此搭配is，小学一年级需要牢记be动词中is对应单数主语的规则。","可数名词单数形式在泛指时前面要加不定冠词a/an，banana是以辅音音素开头的单词，所以前面用a，这是小学一年级可数名词入门的核心知识点。"]},"sentenceWithHints":"那 是 香蕉"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (509, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my cat.","What is this?"],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a student.","Is this your pen?"],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"谁","english":"who","examples":["Who is that?","Who are you?"],"phonetic":"/huː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["特殊疑问句结构","指示代词与be动词的搭配"],"explanations":["本句是询问人的特殊疑问句，特殊疑问词who放在句首，后接一般疑问句语序is this，用于询问近处的人或事物的身份。","指示代词this指代近处的单数人或事物，搭配be动词的第三人称单数形式is，当指代复数时则搭配are，如Who are these?"]},"sentenceWithHints":"这 是 谁"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (510, '{"words":[{"chinese":"那","english":"that","examples":["That is my cat.","Look at that tree."],"phonetic":"/ðæt/","partOfSpeech":"代词"},{"chinese":"是","english":"is","examples":["She is a student.","It is a dog."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"谁","english":"who","examples":["Who is your friend?","Who is knocking at the door?"],"phonetic":"/huː/","partOfSpeech":"代词"}],"examPoints":{"points":["特殊疑问句构成","代词的用法","be动词的搭配"],"explanations":["本句是对人进行提问的特殊疑问句，结构为“特殊疑问词 + be动词 + 主语”，这里用特殊疑问词who来询问身份，符合小学一年级特殊疑问句的基础考查要求。","that作为指示代词，可指代远处的人或事物；who作为疑问代词，用于对人的身份进行提问，这两个代词是小学阶段需要掌握的基础代词。","当主语是that这类第三人称单数代词时，be动词要选用is，这是小学一年级需要掌握的be动词与主语的基础搭配规则。"]},"sentenceWithHints":"那 是 谁"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (511, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is a cat.","This book is mine."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a nurse.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"my","examples":["My bag is red.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"fathers","chinese":"爸爸","english":"father","examples":["My father is tall.","His father works in a school."],"phonetic":"/ˈfɑːðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["指示代词的使用","系动词be的单数形式","形容词性物主代词的使用"],"explanations":["指示代词this用于指代近处的单数人或事物，在本句中用来引出要介绍的人，符合小学一年级基础指代表达的考查要求。","系动词be的单数形式is用于第三人称单数主语后，本句中主语this是单数指示代词，因此搭配is，这是小学阶段be动词基础用法的核心考点。","形容词性物主代词my用来修饰名词，表示所属关系，本句中my修饰father，表明“爸爸”是“我的”，是小学一年级物主代词入门的考查内容。"]},"sentenceWithHints":"这 是 我 爸爸"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (512, '{"words":[{"plural":"","chinese":"那","english":"that","examples":["That is a cat.","That is my pen."],"phonetic":"/ðæt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a girl.","It is a dog."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"my","examples":["My bag is red.","This is my toy."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"mothers","chinese":"妈妈","english":"mother","examples":["My mother loves me.","Her mother is a nurse."],"phonetic":"/ˈmʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["指示代词的使用","系动词be的单数形式","形容词性物主代词的使用"],"explanations":["指示代词that用于指代远处的单数人或事物，小学阶段主要学习this（近处）和that（远处）的基础区分和简单使用，本句用that指代远处的妈妈。","系动词be的单数形式is用于第三人称单数主语后，本句主语that是单数指示代词，所以搭配is。小学一年级需要掌握be动词is和单数主语的基础搭配。","形容词性物主代词my用来表示所属关系，后面必须接名词，本句中my修饰mother，表明是“我的妈妈”，这是小学一年级需要掌握的基础物主代词用法。"]},"sentenceWithHints":"那 是 我 妈妈"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (513, '{"words":[{"chinese":"你","english":"you","examples":["You are my friend.","What do you like?"],"phonetic":"/juː/","partOfSpeech":"代词"},{"chinese":"想要","english":"want","examples":["I want a toy.","She wants to go home."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"chinese":"什么","english":"what","examples":["What is this?","What color do you like?"],"phonetic":"/wɑːt/","partOfSpeech":"代词"}],"examPoints":{"points":["特殊疑问句结构","实义动词的一般现在时疑问句"],"explanations":["针对事物提问的特殊疑问句，要用疑问词what开头，本句是询问对方的需求，属于常见的日常交际疑问句。","当句子谓语是实义动词want时，一般现在时的疑问句需要借助助动词do/does，本句主语是第二人称you，所以用do，结构为“What + do + 主语 + 动词原形”。"]},"sentenceWithHints":"你 想要 什么"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (514, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like cats."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想要","english":"want","examples":["I want a toy.","She wants a cup of milk."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"一个","english":"an","examples":["I have an orange.","She needs an umbrella."],"phonetic":"/æn/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"apples","chinese":"苹果","english":"apple","examples":["This is a red apple.","I like eating apples."],"phonetic":"/ˈæpl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不定冠词a/an的用法","动词want的基本用法","人称代词I的使用"],"explanations":["不定冠词a用于辅音音素开头的可数名词单数前，an用于元音音素开头的可数名词单数前。apple是以元音音素/æ/开头的单词，所以前面用an。","want是及物动词，基本用法为want + 名词，表示“想要某物”，主语是第一人称I时，动词用原形want。","人称代词I是第一人称主格，在句子中作主语，指代说话人自己，在句首时首字母要大写。"]},"sentenceWithHints":"我 想要 一个 苹果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (516, '{"words":[{"plural":"","chinese":"你","english":"you","examples":["You are my friend.","What do you want?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"想要","english":"would like","examples":["Would you like a cake?","I would like some milk."],"phonetic":"/wʊd laɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"什么","english":"what","examples":["What is this?","What time is it?"],"phonetic":"/wɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["特殊疑问句构成","礼貌表达would like的用法"],"explanations":["本句是特殊疑问句，由疑问代词what引导，用于询问具体事物，小学阶段需要掌握以what开头的基础特殊疑问句结构，即疑问词+情态动词/助动词+主语+动词短语。","would like是小学阶段需要掌握的礼貌表达，用于表达“想要”，比直接用want更委婉，常用搭配有would like sth.（想要某物）、would like to do sth.（想要做某事），在疑问句中需要将would提前至主语前，构成疑问语序。"]},"sentenceWithHints":"你 想要 什么"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (519, '{"words":[{"plural":"","chinese":"你","english":"you","examples":["You are my friend.","Do you like apples?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"游泳","english":"swim","examples":["I can swim fast.","She is swimming in the pool."],"phonetic":"/swɪm/","pastTense":"swam","thirdPerson":"swims","partOfSpeech":"动词","pastParticiple":"swum","presentParticiple":"swimming"},{"plural":"","chinese":"吗","english":"","examples":["你吃饭了吗？","今天下雨了吗？"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时一般疑问句结构","like后接动名词的用法"],"explanations":["一般现在时中，当主语是第二人称you时，构成一般疑问句要借助助动词Do，结构为“Do + 主语 + 动词原形 + 其他”，本句“Do you like swimming”就是符合这个结构的一般疑问句，用来询问对方的喜好。","like作为动词表示“喜欢”时，后面可以接动名词（动词+ing形式）来表示喜欢做某事，swim的动名词形式是swimming，所以这里用like swimming表示“喜欢游泳”。"]},"sentenceWithHints":"你 喜欢 游泳 吗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (521, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"drawings","chinese":"画画","english":"drawing","examples":["She is good at drawing.","I have some nice drawings."],"phonetic":"/ˈdrɔːɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词like的用法","动名词作宾语"],"explanations":["like作为动词，意为“喜欢”，常见用法有like + 名词/代词，或like + 动名词（doing形式）表示喜欢做某事，本句中使用的是like + 动名词的结构。当主语是第三人称单数时，like要变成likes。","drawing在这里是动名词形式，由动词draw变化而来，在句中作like的宾语，表示“画画”这个行为。动名词具有名词的性质，可以在句中充当宾语、主语等成分，小学阶段主要掌握like后接动名词表示爱好的用法。"]},"sentenceWithHints":"我 喜欢 画画"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (522, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"唱歌","english":"sing","examples":["I can sing well.","She is singing a song."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"}],"examPoints":{"points":["like的用法","人称代词主格","动名词作宾语"],"explanations":["like作为动词，表示“喜欢”，常见用法有like + 名词/代词，或者like + doing sth.，表示喜欢做某事，这里的doing是动名词形式，本句中like singing就是喜欢唱歌的意思。","I是第一人称主格代词，在句子中作主语，用于指代说话人自己，小学阶段需要掌握其基本用法和发音。","动名词是动词的-ing形式，在本句中singing作为like的宾语，表达喜欢的具体动作，小学一年级需要初步了解like后接动名词表示长期的喜好这一用法。"]},"sentenceWithHints":"我 喜欢 唱歌"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (523, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"跳舞","english":"dance","examples":["I dance every day.","She is dancing now."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"}],"examPoints":{"points":["人称代词的使用","like后接动名词的用法"],"explanations":["第一人称代词“我”对应的英文是I，在句中作主语时，不需要变形，且首字母必须大写。","like表示“喜欢”时，后面接动词的动名词形式（即动词+ing），表示长期的爱好，这里“喜欢跳舞”是爱好，所以用like dancing。"]},"sentenceWithHints":"我 喜欢 跳舞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (524, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"readings","chinese":"阅读","english":"reading","examples":["I love reading books.","Reading is good for you."],"phonetic":"/ˈriːdɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词主格的使用","动词like的用法","动名词作宾语"],"explanations":["人称代词主格I在句子中作主语，用于指代说话人自己，在一般现在时的陈述句中，当主语是I时，后面的动词用原形。","like作为实义动词，意为“喜欢”，在一般现在时中，主语是第一人称I时，动词用原形like；当主语是第三人称单数时，动词要变为likes。","like后面可以接动名词（即动词的-ing形式）作宾语，表示喜欢做某事，这里reading是read的动名词形式，作like的宾语，表达“喜欢阅读”这个爱好。"]},"sentenceWithHints":"我 喜欢 阅读"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (525, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"看","english":"watch","examples":["I watch TV every day.","He is watching a movie now."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"TVs","chinese":"电视","english":"TV","examples":["I watch TV in the evening.","There is a TV in the living room."],"phonetic":"/ˌtiːˈviː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词 like 的用法","人称代词的主格形式","缩写词汇的使用"],"explanations":["like 作为动词表示“喜欢”时，常用结构为 like doing sth.，表示长期的爱好，本句中“喜欢看电视”是长期爱好，所以用 like watching TV；另外当主语是第三人称单数时，like 要变成 likes。","人称代词“我”在句子中作主语时，要用主格形式 I，它是第一人称单数主格，单独使用时首字母要大写。","TV 是 television 的缩写形式，在日常表达和小学阶段的英语学习中，常用缩写形式来指代电视，书写时要注意大写字母。"]},"sentenceWithHints":"我 喜欢 看 电视"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (526, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"玩","english":"play","examples":["We play football after school.","He is playing a game now."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"games","chinese":"游戏","english":"game","examples":["Let''s play a game.","I love computer games."],"phonetic":"/ɡeɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词复数"],"explanations":["like作为动词表示“喜欢”时，常用结构为like doing sth.，表示长期的、习惯性的喜好，本句中like playing games就符合这个结构，表达习惯性喜欢玩游戏。","game是可数名词，当表示泛指的一类事物时，通常用复数形式，在词尾加-s变成games，这里用games表示游戏这一类事物，而不是单个游戏。"]},"sentenceWithHints":"我 喜欢 玩 游戏"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (527, '{"words":[{"plural":"","chinese":"你","english":"you","examples":["You are my friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can sing.","Can you swim?"],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"说","english":"speak","examples":["I speak Chinese.","She speaks English well."],"phonetic":"/spiːk/","pastTense":"spoke","thirdPerson":"speaks","partOfSpeech":"动词","pastParticiple":"spoken","presentParticiple":"speaking"},{"plural":"","chinese":"英语","english":"English","examples":["I like English.","We learn English every day."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吗","english":"","examples":["你吃饭了吗？","今天冷吗？"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的一般疑问句用法","表示“说语言”的动词搭配","中英文疑问句的表达差异"],"explanations":["情态动词can用于表示能力，构成一般疑问句时直接将can提前至句首，结构为“Can + 主语 + 动词原形 + 其他”，用来询问对方是否具备某种能力，本句就是用这个结构询问对方是否有说英语的能力。","表示“说某种语言”时，常用动词speak搭配语言类名词，比如speak English、speak Chinese，而talk、say通常不这样搭配使用。","中文疑问句常借助语气词“吗”来体现疑问语气，而英文一般疑问句则通过语序变化（情态动词提前）来体现，不需要额外的语气词。"]},"sentenceWithHints":"你 会 说 英语 吗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (529, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"可以","english":"can","examples":["I can swim.","Can you dance?"],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"帮","english":"help","examples":["I can help you.","She helps her mom every day."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"你","english":"you","examples":["You are my friend.","Can you help me?"],"phonetic":"/juː/","partOfSpeech":"代词"},{"chinese":"吗","english":"","examples":["Are you okay?","Do you like cats?"],"phonetic":"","partOfSpeech":"语气词"}],"examPoints":{"points":["情态动词can的用法","一般疑问句结构","人称代词的使用"],"explanations":["情态动词can表示“能够，可以”，后面要接动词原形，用于表达请求、能力等含义，本句中用can来提出帮助的请求。","用情态动词can构成一般疑问句时，要将can提前至句首，结构为“Can + 主语 + 动词原形 + 其他？”，用来礼貌地提出询问或请求。","人称代词I（我）作主语时，在句中位于情态动词之后；you（你）作为第二人称代词，可在疑问句中作宾语，用于指代对方，符合日常交流的称呼习惯。"]},"sentenceWithHints":"我 可以 帮 你 吗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (530, '{"words":[{"plural":"","chinese":"请","english":"please","examples":["Please open the door.","Please pass me the pen."],"phonetic":"/pliːz/","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"帮","english":"help","examples":["I can help you with your homework.","She helps her mom cook every day."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"","chinese":"我","english":"me","examples":["My mom told me a story.","Please give me a cup of water."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["祈使句的基本用法","人称代词宾格的使用","实义动词的基本形式"],"explanations":["祈使句用于表达请求、命令等语气，通常以动词原形开头，本句用please放在句首（也可放在句末）来表示礼貌的请求，符合小学一年级对简单祈使句的考查要求。","人称代词分为主格和宾格，“我”的主格是I，宾格是me，在动词help后面需要用宾格形式作宾语，这是小学阶段代词的基础考点。","实义动词help的原形用于祈使句中，其过去式、第三人称单数等变形是小学阶段动词形式的基础内容，本句考查的是动词原形在祈使句中的使用。"]},"sentenceWithHints":"请 帮 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (532, '{"words":[{"plural":"","chinese":"不","english":"no","examples":["No, I don''t like it.","No smoking here."],"phonetic":"/noʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"用","english":"need","examples":["You don''t need to worry.","She needs a new pen."],"phonetic":"/niːd/","pastTense":"needed","thirdPerson":"needs","partOfSpeech":"动词","pastParticiple":"needed","presentParticiple":"needing"},{"plural":"thanks","chinese":"谢","english":"thanks","examples":["Thanks for your help.","Many thanks to you."],"phonetic":"/θæŋks/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["日常交际用语的英译","名词复数的特殊用法"],"explanations":["“不用谢”是英语日常交际里常用的回应致谢的表达，对应的标准口语表达为“No thanks”，用于礼貌地回应他人的感谢或好意，是小学低年级需要掌握的基础交际用语。","“thanks”作为“感谢”的意思时，本身就是复数形式，通常单独使用或搭配其他词构成交际用语，不需要再做复数变形，这是名词复数的特殊固定用法。"]},"sentenceWithHints":"不 用 谢"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (533, '{"words":[{"plural":"","chinese":"你","english":"you","examples":["You are my friend.","Can you help me?"],"phonetic":"/juː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"能","english":"can","examples":["I can sing.","Can you swim?"],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"来","english":"come","examples":["Come here, please.","She comes to school early."],"phonetic":"/kʌm/","pastTense":"came","thirdPerson":"comes","partOfSpeech":"动词","pastParticiple":"come","presentParticiple":"coming"},{"plural":"","chinese":"吗","english":"","examples":["你好吗？","他去吗？"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的一般疑问句用法","实义动词come的基本用法"],"explanations":["情态动词can用于表示能力、请求或许可，构成一般疑问句时直接将can提前至句首，主语紧随其后，后面接动词原形，用来询问对方是否能够做某事，本句就是用can构成一般疑问句询问对方是否能来。","come是实义动词，意思是“来”，在情态动词can后面要使用动词原形，它的过去式是不规则变化came，过去分词也是come，第三人称单数形式是comes，现在分词是coming，小学阶段需要掌握它的基本含义和在情态动词后的用法。"]},"sentenceWithHints":"你 能 来 吗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (534, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"可以","english":"can","examples":["I can sing.","Can you swim?"],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"来","english":"come","examples":["Come here, please.","She comes from China."],"phonetic":"/kʌm/","pastTense":"came","thirdPerson":"comes","partOfSpeech":"动词","pastParticiple":"come","presentParticiple":"coming"}],"examPoints":{"points":["情态动词can的用法","实义动词come的用法","人称代词主格I的使用"],"explanations":["情态动词can表示“能够、可以”，后接动词原形，没有人称和数的变化，过去式为could，常用于表达能力或请求许可，小学阶段主要学习其表“可以、能够”的基础用法。","come是实义动词，意为“来”，是不规则动词，过去式为came，过去分词为come，第三人称单数形式为comes，现在分词为coming，小学阶段重点掌握其原形在情态动词后的使用以及基本含义。","I是第一人称主格代词，在句中作主语，指代说话人自己，单独使用时永远大写，是小学阶段最先接触的人称代词之一。"]},"sentenceWithHints":"我 可以 来"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (535, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"现在","english":"now","examples":["I am busy now.","Come here now."],"phonetic":"/naʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"不能","english":"cannot","examples":["I cannot swim.","She cannot come to the party."],"phonetic":"/ˈkænɑːt/","pastTense":"could not","thirdPerson":"cannot","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"来","english":"come","examples":["Please come in.","She comes to school early."],"phonetic":"/kʌm/","pastTense":"came","thirdPerson":"comes","partOfSpeech":"动词","pastParticiple":"come","presentParticiple":"coming"}],"examPoints":{"points":["情态动词cannot的用法","实义动词come的形式变化","时间副词now的位置"],"explanations":["cannot是情态动词can的否定形式，用于表达“不能、无法”，后面接动词原形，小学阶段需要掌握其基本含义和后接动词原形的规则。","come是不规则实义动词，需要掌握它的过去式came、过去分词come、第三人称单数comes以及现在分词coming的变化形式，本句中因为前面有情态动词cannot，所以使用动词原形。","now是时间副词，通常放在句末或者句首，用于表示当前的时间，本句中放在句末，符合小学阶段对时间副词位置的基础考查要求。"]},"sentenceWithHints":"我 现在 不能 来"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (537, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"明天","english":"tomorrow","examples":["I will go to park tomorrow.","Tomorrow is Sunday."],"phonetic":"/təˈmɑːroʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"times","chinese":"时间","english":"time","examples":["I don''t have time today.","We had a good time yesterday."],"phonetic":"/taɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词主格的使用","一般现在时的用法","时间副词的位置"],"explanations":["人称代词主格“I”在句子中作主语，用于指代说话人自己，在句首首字母需要大写。","一般现在时用于表达经常性、习惯性的动作或当前的状态，本句表达当前的状态“有时间”，主语是第一人称“I”，所以动词用原形“have”。","时间副词“tomorrow”表示将来的时间，在英语句子中通常可以放在句末，也可以放在句首，本句放在句末符合小学阶段的常用表达。"]},"sentenceWithHints":"我 明天 有 时间"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (539, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We like apples."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"要","english":"be about to","examples":["I am about to go home.","They are about to start."],"phonetic":"/biː əˈbaʊt tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"走","english":"leave","examples":["I leave for school at 7.","She left the room just now."],"phonetic":"/liːv/","pastTense":"left","thirdPerson":"leaves","partOfSpeech":"动词","pastParticiple":"left","presentParticiple":"leaving"},{"plural":"","chinese":"了","english":"","examples":["I have eaten dinner.","She is coming now."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时表将来","人称代词与be动词的搭配"],"explanations":["现在进行时（be+动词现在分词）可以用来表示即将发生的、计划好的动作，本句中are leaving就表示“即将离开、要走了”，符合句子里“要走了”的将来含义，适合小学阶段理解表将来的简单用法。","第一人称复数代词we对应的be动词形式是are，这是小学阶段需要掌握的基础人称与be动词的固定搭配，要区分I对应am，he/she/it对应is，we/you/they对应are。"]},"sentenceWithHints":"我们 要 走 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (540, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We like playing games."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"到了","english":"have arrived","examples":["I have arrived at school.","She has arrived in Beijing."],"phonetic":"/hæv əˈraɪvd/","pastTense":"arrived","thirdPerson":"arrives","partOfSpeech":"动词","pastParticiple":"arrived","presentParticiple":"arriving"}],"examPoints":{"points":["人称代词的使用","现在完成时的基本表达"],"explanations":["人称代词we是第一人称复数主格，在句子中作主语，指代说话者和其他人，对应中文里的“我们”，小学阶段需要掌握常见的主格人称代词如I、you、he、she、it、we、they。","现在完成时结构为“have/has + 动词过去分词”，用于表示动作已经完成，对现在有影响。本句主语是we（第一人称复数），所以用have，arrive的过去分词是arrived，“We have arrived”用来表达“我们已经到了”这个完成的状态，小学一年级阶段重点感知现在完成时表动作完成的基本用法。"]},"sentenceWithHints":"我们 到了。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (541, '{"words":[{"plural":"","chinese":"我们","english":"us","examples":["Let us play together.","Please give us some water."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"回家","english":"go home","examples":["I go home at 5 every day.","She went home early yesterday."],"phonetic":"/ɡoʊ hoʊm/","pastTense":"went home","thirdPerson":"goes home","partOfSpeech":"动词短语","pastParticiple":"gone home","presentParticiple":"going home"},{"plural":"","chinese":"吧","english":"","examples":["Let''s go, shall we?","Have a cup of tea, will you?"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["祈使句 Let us 的用法","固定短语 go home 的表达"],"explanations":["Let us...是表示提议、请求的祈使句结构，用来建议一起做某事，在口语中常缩写为 Let''s，小学阶段主要掌握其表提议的基础用法，后面接动词原形。本句用它来提议一起回家，符合小学一年级的交际用语要求。","go home 是固定动词短语，意为“回家”，这里 home 是副词，前面不能加介词 to，这是小学阶段需要掌握的常用固定表达，用于描述回到家这个动作。"]},"sentenceWithHints":"我们 回家 吧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (544, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"-","examples":["We are friends.","They are playing games."],"phonetic":"/-/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"吃","english":"have","examples":["I have breakfast every day.","She has a new book."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"午","english":"-","examples":[],"phonetic":"/-/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"lunches","chinese":"饭","english":"lunch","examples":["I have lunch at 12 o''clock.","We had a nice lunch."],"phonetic":"/lʌntʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吧","english":"-","examples":["Let''s go, shall we?","Have a try, please."],"phonetic":"/-/","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["祈使句 Let us 的用法","三餐类名词的用法","动词 have 的固定搭配"],"explanations":["Let us 是小学阶段常用的祈使句结构，用来提出建议、请求，意思是“让我们……”，后面接动词原形，符合本句“我们……吧”的提议语气。","lunch 属于三餐类名词，一般情况下前面不加不定冠词 a/an，表达“吃午饭”直接用 have lunch，这是英语中的固定表达。","动词 have 可以和三餐名词搭配，构成 have breakfast/lunch/dinner 的固定短语，用来表达“吃早/午/晚饭”，是小学一年级需要掌握的基础搭配。"]},"sentenceWithHints":"我 们 吃 午 饭 吧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (545, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"","examples":["我们是好朋友。","他们喜欢玩游戏。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"吃","english":"have","examples":["I have a cat.","Let''s have a party."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"晚","english":"dinner","examples":["We have dinner at 7 PM.","Dinner is ready."],"phonetic":"/ˈdɪnər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"饭","english":"","examples":["我喜欢吃米饭。","妈妈做好饭了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吧","english":"","examples":["我们一起走吧。","你喝杯水吧。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["祈使句 Let us 的用法","三餐类名词的用法"],"explanations":["Let us（可缩写为 Let''s）用于提出建议、邀请，意思是“让我们……吧”，后面接动词原形，是小学阶段常用的祈使句结构，用来表达提议做某事。本句用这个结构对应中文里的提议语气。","dinner 表示“晚饭”，属于三餐类名词，这类名词前通常不加冠词，比如 have breakfast（吃早饭）、have lunch（吃午饭），是小学英语中饮食类表达的基础知识点。"]},"sentenceWithHints":"我 们 吃 晚 饭 吧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (546, '{"words":[{"plural":"","chinese":"我们","english":"us/we","examples":["We are friends.","Let us go to the park."],"phonetic":"/ʌs/ /wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看","english":"watch","examples":["I watch TV every day.","She watched a movie last night."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"TVs/televisions","chinese":"电视","english":"TV/television","examples":["I like watching TV.","There are two televisions in the house."],"phonetic":"/ˌtiːˈviː/ /ˈtelɪvɪʒn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吧","english":"","examples":["Let''s go, shall we?","Have a cup of tea, please."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"语气词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["祈使句 Let us 的用法","固定搭配 watch TV"],"explanations":["Let us 是小学阶段常用的祈使句结构，用于提出建议、请求，意思是“让我们……吧”，后面接动词原形，符合小学一年级对提建议句型的考查要求。","watch TV 是固定搭配，“看电视”要用动词 watch 而不是 look 或 see，这是小学阶段需要掌握的常用固定短语，强调观看电视节目这类动态的观看行为。"]},"sentenceWithHints":"我们 看 电视 吧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (547, '{"words":[{"chinese":"我们","english":"us","examples":["Let us go to the park.","Please help us."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"玩","english":"play","examples":["I play football every day.","She is playing with her toys."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"games","chinese":"游戏","english":"game","examples":["We love playing games.","This is a fun game."],"phonetic":"/ɡeɪm/","partOfSpeech":"名词"},{"chinese":"吧","english":"","examples":["Let''s go home, shall we?","Have some cake, please."],"phonetic":"","partOfSpeech":"语气词"}],"examPoints":{"points":["祈使句 Let us 的用法","可数名词复数形式"],"explanations":["Let us + 动词原形是小学阶段常见的祈使句结构，用来提出建议、请求，表达“让我们……吧”的含义，符合句子中提议玩游戏的语境。","game是可数名词，这里表示泛指的游戏，不是单一某一个游戏，所以要用复数形式games，在词尾加-s构成复数，这是可数名词变复数的规则变化。"]},"sentenceWithHints":"我们 玩 游戏 吧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (548, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"开心","english":"happy","examples":["I feel happy today.","The happy children are playing."],"phonetic":"/ˈhæpi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","副词修饰形容词的用法","主系表句型"],"explanations":["人称代词“I”是第一人称单数主格，在句子中作主语，永远大写首字母，对应中文的“我”，用于指代说话人自己。","副词“very”用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中用来强调“开心”的程度。","主系表句型是英语基础句型之一，结构为“主语+系动词+表语”，本句中主语是“I”，对应的系动词是“am”，表语是形容词“happy”，用来描述主语的状态。"]},"sentenceWithHints":"我 很 开心。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (549, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"兴奋","english":"excited","examples":["I''m excited about the trip.","She looks excited to see you."],"phonetic":"/ɪkˈsaɪtɪd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","副词修饰形容词的用法","系动词be的搭配"],"explanations":["第一人称单数“我”对应的英文是主格代词I，在句子中作主语，通常位于句首，后面搭配对应的系动词am。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来强化excited所表达的兴奋程度。","当描述人的状态时，主语为I时，要搭配系动词am，构成“I am + 形容词”的结构来表达自身的情绪或状态，本句就是用这个结构表达“我处于兴奋的状态”。"]},"sentenceWithHints":"我 很 兴奋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (550, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love apples.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cat is very cute."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"无聊","english":"bored","examples":["I am bored at home.","He feels bored in class."],"phonetic":"/bɔːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","程度副词very修饰形容词","形容词bored的用法"],"explanations":["人称代词I是第一人称主格，在句子中作主语，对应的be动词是am，小学阶段需要掌握主格代词的基本用法和搭配的be动词。","程度副词very用来修饰形容词或副词，放在被修饰词的前面，用来加强语气，本句中very用来强化bored所表达的无聊程度，这是小学阶段副词修饰形容词的基础知识点。","bored是形容词，用来描述人的感受，表示“感到无聊的”，小学阶段需要区分bored（形容人）和boring（形容事物）的基础用法，本句主语是I（人），所以用bored。"]},"sentenceWithHints":"我 很 无聊"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (551, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"累","english":"tired","examples":["I feel tired after running.","My mom is tired from work."],"phonetic":"/ˈtaɪərd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","副词修饰形容词的用法","系表结构的基本构成"],"explanations":["第一人称代词“我”对应的英文是“I”，在句子中作主语时，首字母必须大写，且搭配的系动词为“am”。","副词“very”用来修饰形容词，放在形容词前面，用来加强形容词的语气，本句中用来强调“累”的程度。","本句是典型的主系表结构，主语“I”+系动词“am”+表语“very tired”，用来描述主语的状态，小学阶段需要掌握这种基础的状态表达结构。"]},"sentenceWithHints":"我 很 累。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (552, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"饿","english":"hungry","examples":["I''m hungry now.","The little cat is hungry."],"phonetic":"/ˈhʌŋɡri/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与系动词的搭配","副词修饰形容词的用法"],"explanations":["当主语是第一人称单数\"我（I）\"时，对应的be动词要用\"am\"，这是小学阶段基础的人称与be动词的固定搭配规则。","副词\"very\"用来修饰形容词，表示程度，放在形容词前面，用来加强形容词所表达的状态，本句中用\"very\"来强调\"饿（hungry）\"的程度。"]},"sentenceWithHints":"我 很 饿"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (553, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","The cat is very cute."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"渴","english":"thirsty","examples":["I am thirsty. I want some water.","The dog is thirsty after running."],"phonetic":"/ˈθɜːrsti/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与系动词的搭配","副词修饰形容词的用法"],"explanations":["当主语是第一人称单数“I（我）”时，对应的be动词要用“am”，这是小学阶段基础的人称与be动词的固定搭配规则。","副词“very”用来修饰形容词，放在形容词前面，用来加强形容词所表达的程度，本句中用“very”来强调“渴”的程度，这是副词修饰形容词的基础用法。"]},"sentenceWithHints":"我 很 渴。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (554, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"忙","english":"busy","examples":["My mom is busy every day.","Don''t bother her, she''s busy."],"phonetic":"/ˈbɪzi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与系动词的搭配","副词修饰形容词的用法"],"explanations":["当主语是第一人称单数代词“I（我）”时，对应的系动词be要使用“am”，这是固定的人称与系动词的搭配规则，小学阶段需要牢记不同人称对应的be动词形式：I用am，you用are，he/she/it用is。","副词“very（很）”用来修饰形容词，放在形容词的前面，用来加强形容词的语气，说明形容词所描述的状态的程度，本句中用“very”来强调“busy（忙的）”的程度。"]},"sentenceWithHints":"我 很 忙"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (555, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"闲","english":"free","examples":["I am free this weekend.","She has a free ticket."],"phonetic":"/friː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","副词修饰形容词的用法","系动词be的搭配"],"explanations":["人称代词“I”是第一人称单数主格，在句子中作主语，永远大写首字母，对应中文的“我”。","副词“very”用来修饰形容词，放在形容词之前，用来加强形容词的语气，说明形容词所描述的状态的程度，此处用来强调“闲”的程度。","当主语是第一人称单数“I”时，对应的系动词be要用“am”，构成“I am + 形容词”的结构，用来描述主语的状态。"]},"sentenceWithHints":"我 很 闲"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (559, '{"words":[{"plural":"","chinese":"今天","english":"today","examples":["Today is Monday.","I will go to the park today."],"phonetic":"/təˈdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"下雨","english":"rain","examples":["It rains a lot in spring.","It is raining outside now."],"phonetic":"/reɪn/","pastTense":"rained","thirdPerson":"rains","partOfSpeech":"动词","pastParticiple":"rained","presentParticiple":"raining"},{"plural":"","chinese":"了","english":"","examples":["I ate an apple.","She is singing now."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的用法","天气表达的常用句式"],"explanations":["现在进行时用来表示当前正在发生的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中“下雨了”是正在发生的动作，所以用is raining，主语it指代天气，是第三人称单数，be动词用is。","表达天气时，常用“it+be动词+表示天气的动词现在分词/形容词”的句式，it在这里无实际意义，用来指代天气情况，比如“It is sunny.”（天气晴朗），“It is snowing.”（正在下雪）。"]},"sentenceWithHints":"今天 下雨 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (560, '{"words":[{"plural":"","chinese":"今天","english":"today","examples":["Today is sunny.","I will go to park today."],"phonetic":"/təˈdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"下雪","english":"snow","examples":["It snows a lot in winter.","It is snowing heavily outside."],"phonetic":"/snoʊ/","pastTense":"snowed","thirdPerson":"snows","partOfSpeech":"动词","pastParticiple":"snowed","presentParticiple":"snowing"},{"plural":"","chinese":"了","english":"","examples":["I finished my homework了.","It is raining了."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的用法","天气类动词的表达","时间副词的位置"],"explanations":["现在进行时用来表示当前正在发生的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中“下雪了”是正在发生的动作，所以用is snowing，主语it指代天气，是第三人称单数，be动词用is。","描述天气时常用it作形式主语，搭配表示天气的动词，比如snow（下雪）、rain（下雨）等，这是英语中表达天气的固定常用结构。","时间副词today在句中可以放在句尾，也可以放在句首，本参考翻译放在句尾，符合英语表达习惯，用于说明动作发生的时间。"]},"sentenceWithHints":"今天 下雪 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (561, '{"words":[{"plural":"","chinese":"今","english":"this","examples":["This is my pen.","This cat is cute."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"days","chinese":"天","english":"day","examples":["Today is sunny.","I have a good day."],"phonetic":"/deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"be","examples":["It is rainy.","They are happy."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"风","english":"windy","examples":["It is windy outside.","Windy days are good for flying kites."],"phonetic":"/ˈwɪndi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["天气类英语表达结构","形容词描述天气的用法","时间状语的位置"],"explanations":["描述天气的常用英语结构为“It + be动词 + 天气类形容词”，这里用it作为形式主语指代天气，符合英语表达习惯，而不是直接对应中文的“有”来翻译。","表示天气状况时，通常用对应的形容词形式，比如“风”对应的描述天气的形容词是windy，而不是名词wind，用来说明当天的天气特征。","时间状语today在英语句子中可以放在句末，也可以放在句首，本参考翻译放在句末，是小学阶段需要掌握的基础状语位置用法。"]},"sentenceWithHints":"今 天 有 风"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (562, '{"words":[{"plural":"","chinese":"今天","english":"today","examples":["Today is Monday.","I will go to the park today."],"phonetic":"/təˈdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["She is a student.","It is cold outside."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"晴天","english":"sunny","examples":["It''s a sunny day.","We can go hiking on sunny days."],"phonetic":"/ˈsʌni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["天气类形容词的使用","it指代天气的用法","系动词is的搭配"],"explanations":["描述天气状况时常用形容词，sunny表示“晴朗的”，用来形容天气好、有太阳的状态，类似的词还有rainy（下雨的）、windy（有风的）等。","在英语中描述天气时，常用代词it作为形式主语，不需要具体的人或物作主语，直接用it来指代天气情况，比如It is rainy.（下雨了）。","当主语是it（指代天气、时间等）这类第三人称单数时，系动词要用is，构成“主+系+表”的简单句型，用来表达状态，本句中it是主语，is是系动词，sunny是表语，说明天气的状态。"]},"sentenceWithHints":"今天 是 晴天"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (563, '{"words":[{"plural":"","chinese":"今天","english":"today","examples":["Today is sunny.","I will go to the park today."],"phonetic":"/təˈdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["It is rainy.","She is a student."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"阴天","english":"cloudy","examples":["It''s cloudy outside.","A cloudy day is good for reading."],"phonetic":"/ˈklaʊdi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["天气类形容词的使用","it 指代天气的用法","系动词is的搭配"],"explanations":["描述天气时常用对应的形容词，cloudy是cloud（云）的形容词形式，用来表示“阴天的、多云的”，小学阶段需要掌握常见的天气类形容词，如sunny（晴朗的）、rainy（下雨的）等。","在英语中描述天气时，常用it作为形式主语，不需要具体的人或物作主语，这是英语表达天气的固定用法，和中文的表达习惯不同。","当主语是it（指代天气）这类第三人称单数时，系动词要用is，这是be动词的基本搭配规则，小学一年级需要掌握be动词和第三人称单数主语的搭配。"]},"sentenceWithHints":"今天 是 阴天"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (566, '{"words":[{"plural":"stars","chinese":"星星","english":"star","examples":["Look at the bright star in the sky.","The stars are beautiful at night."],"phonetic":"/stɑːr/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"be","examples":["I am reading a book.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"闪烁","english":"twinkle","examples":["The lights twinkle in the distance.","Her eyes twinkle when she laughs."],"phonetic":"/ˈtwɪŋkəl/","pastTense":"twinkled","thirdPerson":"twinkles","partOfSpeech":"动词","pastParticiple":"twinkled","presentParticiple":"twinkling"}],"examPoints":{"points":["现在进行时的用法","可数名词复数形式"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词(am/is/are) + 动词的现在分词形式”。本句中“在闪烁”是正在发生的动作，主语是复数“stars”，所以be动词用are，动词twinkle变为现在分词twinkling。","可数名词表示多个时要使用复数形式，规则名词一般在词尾加-s，“star”的复数形式是“stars”，句子中用“The stars”表示不止一颗星星，符合语境。"]},"sentenceWithHints":"星星 在 闪烁"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (567, '{"words":[{"plural":"birds","chinese":"鸟儿","english":"bird","examples":["A bird is flying in the sky.","There are many birds in the tree."],"phonetic":"/bɜːrd/","partOfSpeech":"名词"},{"chinese":"在","english":"be","examples":["I am reading a book.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"歌唱","english":"sing","examples":["She sings very well.","We are singing a song together."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"}],"examPoints":{"points":["现在进行时的构成与用法","可数名词复数形式"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中主语是复数“鸟儿”，所以be动词用are，“歌唱”的现在分词是singing，构成are singing来表示鸟儿正在进行的动作。","可数名词表示多个时要使用复数形式，规则名词一般在词尾加-s，“bird”的复数形式是“birds”，句中用“The birds”来特指正在歌唱的这些鸟儿。"]},"sentenceWithHints":"鸟儿 在 歌唱"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (568, '{"words":[{"plural":"flowers","chinese":"花","english":"flower","examples":["I like red flowers.","The flower is very beautiful."],"phonetic":"/ˈflaʊər/","partOfSpeech":"名词"},{"plural":"","chinese":"儿","english":"","examples":["这朵花儿真好看。","鸟儿在树上唱歌。"],"phonetic":"","partOfSpeech":"助词"},{"chinese":"在","english":"be","examples":["She is reading a book.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"开","english":"bloom","examples":["The roses bloom in spring.","The flowers are blooming now."],"phonetic":"/bluːm/","pastTense":"bloomed","thirdPerson":"blooms","partOfSpeech":"动词","pastParticiple":"bloomed","presentParticiple":"blooming"},{"plural":"","chinese":"放","english":"","examples":["花儿开放了。","太阳出来了，花儿开放了。"],"phonetic":"","partOfSpeech":"助词"}],"examPoints":{"points":["现在进行时的用法","可数名词复数形式"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词(am/is/are)+动词的现在分词”。本句中“在开放”是正在进行的动作，主语是复数，所以用are加上blooming。","可数名词表示多个时要变成复数形式，规则名词一般在词尾加-s，“flower”的复数是“flowers”，句子中表示不止一朵花，所以用复数形式。"]},"sentenceWithHints":"花 儿 在 开 放"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (569, '{"words":[{"plural":"trees","chinese":"树","english":"tree","examples":["The tree is tall.","There are many trees in the park."],"phonetic":"/triː/","partOfSpeech":"名词"},{"chinese":"在","english":"is","examples":["He is reading a book.","The cat is under the chair."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"生长","english":"grow","examples":["Plants grow with water and sunlight.","The baby is growing fast."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["现在进行时的用法","定冠词 the 的用法"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中“在生长”是正在进行的动作，主语the tree是第三人称单数，所以be动词用is，grow的现在分词是growing。","定冠词the用于特指某个或某些特定的人或事物，本句中the tree特指双方都知道的那棵树，所以用the来限定。"]},"sentenceWithHints":"树 在 生长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (572, '{"words":[{"plural":"birds","chinese":"鸟","english":"bird","examples":["A bird is singing in the tree.","There are many birds in the sky."],"phonetic":"/bɜːrd/","partOfSpeech":"名词"},{"chinese":"在","english":"be","examples":["I am reading a book.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"飞","english":"fly","examples":["Birds fly south in winter.","The plane is flying high."],"phonetic":"/flaɪ/","pastTense":"flew","thirdPerson":"flies","partOfSpeech":"动词","pastParticiple":"flown","presentParticiple":"flying"}],"examPoints":{"points":["现在进行时的用法","定冠词the的用法","可数名词单数的指代"],"explanations":["现在进行时表示现在正在进行的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中“在飞”是正在进行的动作，主语“the bird”是第三人称单数，所以be动词用is，fly的现在分词是flying，构成is flying的结构。","定冠词the用于特指某个或某些特定的人或事物，本句中the bird特指说话双方都知道的那只鸟，所以需要用the来限定。","可数名词单数单独使用时通常需要搭配冠词，本句中bird是可数名词单数，前面用the来特指，明确指代的对象。"]},"sentenceWithHints":"鸟 在 飞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (573, '{"words":[{"plural":"fish/fishes","chinese":"鱼","english":"fish","examples":["I like eating fish.","There are many fishes in the lake."],"phonetic":"/fɪʃ/","partOfSpeech":"名词"},{"chinese":"在","english":"be","examples":["She is reading a book.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"游泳","english":"swim","examples":["I can swim fast.","He is swimming in the pool."],"phonetic":"/swɪm/","pastTense":"swam","thirdPerson":"swims","partOfSpeech":"动词","pastParticiple":"swum","presentParticiple":"swimming"}],"examPoints":{"points":["现在进行时的结构与用法","可数名词单复数的特殊变化"],"explanations":["现在进行时表示此刻正在进行的动作，结构为“am/is/are + 动词的现在分词”。本句中主语“fish”表示单数个体，所以用“is”，动词“swim”的现在分词是双写末尾辅音字母加-ing，即“swimming”。","“fish”表示鱼的条数时，单复数同形，都为“fish”；表示鱼的种类时，复数形式为“fishes”。本句中表示单条鱼，所以用单数形式搭配“is”。"]},"sentenceWithHints":"鱼 在 游泳"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (574, '{"words":[{"plural":"rabbits","chinese":"兔子","english":"rabbit","examples":["The rabbit is white.","I see two rabbits in the garden."],"phonetic":"/ˈræbɪt/","partOfSpeech":"名词"},{"chinese":"在","english":"be","examples":["She is singing.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"跳","english":"jump","examples":["The dog jumps over the fence.","She is jumping rope."],"phonetic":"/dʒʌmp/","pastTense":"jumped","thirdPerson":"jumps","partOfSpeech":"动词","pastParticiple":"jumped","presentParticiple":"jumping"}],"examPoints":{"points":["现在进行时的结构与用法","可数名词单数的特指用法"],"explanations":["现在进行时表示正在发生的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中主语“the rabbit”是第三人称单数，所以be动词用is，动词“jump”的现在分词是jumping，组合起来就是is jumping，体现“正在跳”的含义。","定冠词the用于特指某个具体的人或事物，本句中the rabbit特指说话双方都知道的那只兔子，符合小学阶段对特指名词的用法要求。"]},"sentenceWithHints":"兔子 在 跳"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (575, '{"words":[{"plural":"ducks","chinese":"鸭子","english":"duck","examples":["The duck is yellow.","There are many ducks in the lake."],"phonetic":"/dʌk/","partOfSpeech":"名词"},{"chinese":"在","english":"is","examples":["He is reading a book.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"游泳","english":"swim","examples":["I swim every day.","She is swimming in the pool."],"phonetic":"/swɪm/","pastTense":"swam","thirdPerson":"swims","partOfSpeech":"动词","pastParticiple":"swum","presentParticiple":"swimming"}],"examPoints":{"points":["现在进行时结构","可数名词单数的定冠词使用"],"explanations":["现在进行时用来表示正在发生的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句主语是单数的the duck，所以be动词用is，swim的现在分词是swimming，构成is swimming的结构。","当特指某一个事物时，可数名词单数前要加定冠词the，本句特指正在游泳的那只鸭子，所以用the duck。"]},"sentenceWithHints":"鸭子 在 游泳"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (576, '{"words":[{"plural":"chickens","chinese":"鸡","english":"chicken","examples":["I like eating chicken.","There are three chickens in the yard."],"phonetic":"/ˈtʃɪkɪn/","partOfSpeech":"名词"},{"plural":"","chinese":"在","english":"（无对应独立英文词，辅助构成进行时态）","examples":["我在看书。","他在跑步。"],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"叫","english":"crow","examples":["The rooster crows at dawn.","The chicken is crowing loudly."],"phonetic":"/kroʊ/","pastTense":"crowed","thirdPerson":"crows","partOfSpeech":"动词","pastParticiple":"crowed","presentParticiple":"crowing"}],"examPoints":{"points":["现在进行时态的用法","可数名词的单复数"],"explanations":["现在进行时态表示此时此刻正在进行的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中“在叫”是正在发生的动作，所以用“is crowing”，主语the chicken是第三人称单数，be动词用is。","chicken作为“小鸡；鸡”讲时是可数名词，单数形式前可加定冠词the表示特指，复数形式直接加s变为chickens。本句特指某一只在叫的鸡，所以用单数形式the chicken。"]},"sentenceWithHints":"鸡 在 叫"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (577, '{"words":[{"plural":"horses","chinese":"马","english":"horse","examples":["The horse is very strong.","I want to ride a horse."],"phonetic":"/hɔːrs/","partOfSpeech":"名词"},{"chinese":"在","english":"is","examples":["He is reading a book.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"跑","english":"run","examples":["I run every morning.","She is running fast."],"phonetic":"/rʌn/","pastTense":"ran","thirdPerson":"runs","partOfSpeech":"动词","pastParticiple":"run","presentParticiple":"running"}],"examPoints":{"points":["现在进行时的用法","定冠词the的用法","可数名词单数的指代"],"explanations":["现在进行时用于表示当前正在进行的动作，结构为“be动词（am/is/are）+动词的现在分词形式”。本句中“在跑”是正在进行的动作，主语“马”是第三人称单数，所以用“is running”。","定冠词the用于特指某个具体的人或事物，本句中“马”是特指的某一匹马，所以前面加the。","可数名词单数在句子中出现时，前面通常需要加冠词（a/an/the），本句中horse是可数名词单数，这里用the特指，符合语法规则。"]},"sentenceWithHints":"马 在 跑"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (579, '{"words":[{"plural":"pigs","chinese":"猪","english":"pig","examples":["The pig is very fat.","There are three pigs on the farm."],"phonetic":"/pɪɡ/","partOfSpeech":"名词"},{"chinese":"在","english":"is","examples":["He is reading a book.","The cat is under the chair."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"睡觉","english":"sleep","examples":["I sleep eight hours every day.","The baby is sleeping now."],"phonetic":"/sliːp/","pastTense":"slept","thirdPerson":"sleeps","partOfSpeech":"动词","pastParticiple":"slept","presentParticiple":"sleeping"}],"examPoints":{"points":["定冠词 the 的用法","现在进行时的结构"],"explanations":["定冠词 the 用于特指某个或某些特定的人或事物，本句中特指说话双方都知道的那只猪，所以用 the 修饰 pig。","现在进行时表示正在进行的动作，结构为“be动词（am/is/are）+ 动词的现在分词形式”。本句主语 the pig 是第三人称单数，所以be动词用is，sleep的现在分词是sleeping，构成现在进行时结构表示猪正在睡觉的状态。"]},"sentenceWithHints":"猪 在 睡觉"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (580, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"吃","english":"eat","examples":["I eat rice every day.","She ate a cake yesterday."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"rice","chinese":"饭","english":"rice","examples":["I like rice.","We have rice for lunch."],"phonetic":"/raɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时结构","人称代词与be动词的搭配"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词+动词的现在分词形式”。本句中“吃”的现在分词是eating，搭配be动词am构成现在进行时，体现“正在吃饭”的含义。","人称代词“I（我）”对应的be动词现在时形式是“am”，这是固定搭配，小学阶段需要牢记不同人称对应的be动词形式：I用am，you用are，he/she/it用is。"]},"sentenceWithHints":"我 在 吃 饭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (581, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"喝","english":"drink","examples":["I drink milk every day.","She is drinking juice."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"waters","chinese":"水","english":"water","examples":["I need some water.","The waters of the lake are clear."],"phonetic":"/ˈwɔːtər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构与用法","人称代词与be动词的搭配"],"explanations":["现在进行时表示正在发生的动作，结构为“be动词+动词的现在分词形式”。本句中“在喝水”是正在进行的动作，所以用“am drinking”来表达，drink的现在分词是在词尾加-ing。","第一人称代词“I”搭配的be动词现在时形式是“am”，这是固定的人称与be动词的搭配规则，小学阶段需要牢记不同人称对应的be动词形式。"]},"sentenceWithHints":"我 在 喝 水"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (582, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am happy.","I am playing games."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"读","english":"read","examples":["I read books every day.","She is reading a storybook."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"books","chinese":"书","english":"book","examples":["This is my book.","I have many books."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构","人称代词与be动词的搭配"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词+动词的现在分词形式”。本句中“读”的现在分词是reading，搭配be动词am，构成现在进行时结构，表示正在读书的动作。","第一人称单数“I”对应的be动词是“am”，这是固定搭配，小学阶段需要牢记不同人称对应的be动词形式：I用am，you用are，he/she/it用is。"]},"sentenceWithHints":"我 在 读 书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (583, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am reading a book.","I am happy today."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"写","english":"write","examples":["I write a letter every week.","She is writing a story now."],"phonetic":"/raɪt/","pastTense":"wrote","thirdPerson":"writes","partOfSpeech":"动词","pastParticiple":"written","presentParticiple":"writing"},{"plural":"words","chinese":"字","english":"word","examples":["Write the word on the paper.","There are many words in this book."],"phonetic":"/wɜːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的构成与用法","人称代词与be动词的搭配"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词+动词的现在分词形式”。本句中“在写字”是正在进行的动作，所以用“am writing”，write的现在分词是去e加-ing。","第一人称单数“我（I）”搭配的be动词是am，这是固定的人称与be动词的搭配规则，小学阶段需要掌握不同人称对应的be动词形式。"]},"sentenceWithHints":"我 在 写 字"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (584, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"画画","english":"draw","examples":["I draw a cat every day.","She is drawing a flower."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"}],"examPoints":{"points":["现在进行时的结构","人称代词与be动词的搭配"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词+动词的现在分词形式”。本句中“画画”是正在进行的动作，所以用“am drawing”，其中drawing是draw的现在分词形式。","第一人称单数“I”搭配的be动词是“am”，这是固定的人称与be动词的搭配规则，小学阶段需要牢记不同人称对应的be动词形式：I对应am，you对应are，he/she/it对应is。"]},"sentenceWithHints":"我 在 画画。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (585, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"}],"examPoints":{"points":["现在进行时结构","人称代词与be动词的搭配"],"explanations":["现在进行时用于表示正在进行的动作，结构为“am/is/are + 动词的现在分词”。本句中“唱歌”是正在进行的动作，所以用“am singing”来表达，sing的现在分词是singing。","人称代词“I（我）”作主语时，搭配的be动词是“am”；第三人称单数主语搭配“is”，复数主语和第二人称“you”搭配“are”。本句主语是“I”，所以be动词用“am”。"]},"sentenceWithHints":"我 在 唱歌"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (586, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"跳舞","english":"dance","examples":["I dance every day.","She is dancing in the room."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"}],"examPoints":{"points":["现在进行时结构","人称代词与be动词的搭配"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词+动词的现在分词形式”。本句中“跳舞”是正在进行的动作，所以用“am dancing”，dance的现在分词是在词尾加-ing。","第一人称单数“I”搭配的be动词是“am”，这是固定的人称与be动词的搭配规则，小学阶段需要掌握不同人称对应的be动词形式。"]},"sentenceWithHints":"我 在 跳舞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (587, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"跑步","english":"run","examples":["I run every morning.","She is running in the park."],"phonetic":"/rʌn/","pastTense":"ran","thirdPerson":"runs","partOfSpeech":"动词","pastParticiple":"run","presentParticiple":"running"}],"examPoints":{"points":["现在进行时结构","be动词的人称搭配"],"explanations":["现在进行时用来表示正在进行的动作，结构为“be动词+动词的现在分词形式”。本句中“跑步”是正在进行的动作，所以用“am running”。","be动词要和主语保持人称一致，主语是第一人称单数“I”时，对应的be动词是“am”。"]},"sentenceWithHints":"我 在 跑步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (588, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"走路","english":"walk","examples":["I walk to school every day.","She is walking her dog now."],"phonetic":"/wɔːk/","pastTense":"walked","thirdPerson":"walks","partOfSpeech":"动词","pastParticiple":"walked","presentParticiple":"walking"}],"examPoints":{"points":["现在进行时的构成与用法","人称代词与be动词的搭配"],"explanations":["现在进行时用来表示现在正在进行的动作，结构为“am/is/are + 动词的现在分词形式”。本句中“走路”是正在进行的动作，所以用“am walking”，walk的现在分词是在词尾加-ing变成walking。","人称代词“I（我）”作主语时，对应的be动词只能用“am”，这是固定的人称与be动词的搭配规则，小学阶段需要牢记不同人称对应的be动词形式。"]},"sentenceWithHints":"我 在 走路"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (589, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"睡觉","english":"sleep","examples":["I sleep every night.","She is sleeping now."],"phonetic":"/sliːp/","pastTense":"slept","thirdPerson":"sleeps","partOfSpeech":"动词","pastParticiple":"slept","presentParticiple":"sleeping"}],"examPoints":{"points":["现在进行时的构成与用法","人称代词与be动词的搭配"],"explanations":["现在进行时表示现在正在进行的动作，结构为“am/is/are + 动词的现在分词”。本句中“睡觉”是正在进行的动作，所以用“am sleeping”的结构，sleep的现在分词是在词尾加-ing。","人称代词“I（我）”作主语时，搭配的be动词是“am”，这是固定的人称与be动词的搭配规则，小学阶段需要掌握第一人称单数与be动词的对应使用。"]},"sentenceWithHints":"我 在 睡觉"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (590, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am reading a book.","I am happy today."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"看","english":"watch","examples":["I watch TV every day.","She is watching a movie."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"TVs","chinese":"电视","english":"TV","examples":["I watch TV after dinner.","There is a new TV in the room."],"phonetic":"/ˌtiːˈviː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构","人称代词与be动词的搭配","固定表达watch TV"],"explanations":["现在进行时表示正在进行的动作，结构为“be动词（am/is/are）+ 动词的现在分词形式”。本句中“在看”是正在进行的动作，所以用am watching的结构。","第一人称单数“我”对应的be动词是am，这是固定搭配，不能用is或者are。","“看电视”的固定英文表达是watch TV，TV是television的缩写，在日常表达中常用缩写形式，且watch和TV搭配是固定用法，不能用look或者see替换。"]},"sentenceWithHints":"我 在 看 电视"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (591, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"am","examples":["I am happy.","I am reading a book."],"phonetic":"/æm/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"玩","english":"play","examples":["I play football every day.","She is playing with her doll."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"games","chinese":"游戏","english":"game","examples":["Let''s play a game.","I love computer games."],"phonetic":"/ɡeɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在进行时的结构与用法","可数名词复数形式"],"explanations":["现在进行时表示正在进行的动作，结构为“am/is/are + 动词的现在分词形式”。本句主语是第一人称单数“I”，所以be动词用“am”，动词“play”的现在分词是“playing”。","可数名词表示泛指一类事物时，常用复数形式。“game”是可数名词，这里表示玩游戏这类活动，所以用复数“games”，规则可数名词变复数一般在词尾加-s。"]},"sentenceWithHints":"我 在 玩 游戏"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (595, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一只","english":"a","examples":["a dog","a pen"],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"birds","chinese":"鸟","english":"bird","examples":["The bird can sing.","There are many birds in the tree."],"phonetic":"/bɜːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","不定冠词a的用法","实义动词have的基本用法"],"explanations":["人称代词I是第一人称单数主格，在句子中作主语，用于指代说话人自己，后面搭配的动词用原形（一般现在时）。","不定冠词a用于可数名词单数前，当单词以辅音音素开头时使用，用来表示泛指的“一个”，本句中bird以辅音音素/b/开头，所以用a。","实义动词have表示“拥有”，一般现在时中，主语是第一人称I/we、第二人称you以及复数主语时，用动词原形have；主语是第三人称单数时，要变为has。本句主语是I，所以用have。"]},"sentenceWithHints":"我 有 一只 鸟"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (596, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一只","english":"a","examples":["a dog","a pen"],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"rabbits","chinese":"兔子","english":"rabbit","examples":["The rabbit is white.","I have two rabbits."],"phonetic":"/ˈræbɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","have的基础用法","不定冠词a的用法","可数名词的单复数"],"explanations":["第一人称单数“我”对应的英文是I，在句子中作主语，永远大写首字母，用于指代说话人自己。","have表示“拥有”，当主语是第一人称I、第二人称you以及复数主语时，使用have；当主语是第三人称单数（如he/she/it）时，要变为has。本句主语是I，所以用have。","不定冠词a用于可数名词单数前，泛指“一个”，放在以辅音音素开头的单词前，rabbit是以辅音音素/r/开头，所以用a。","rabbit是可数名词，单数形式表示单个个体，复数形式是在词尾加-s变为rabbits，用于表示多个兔子。"]},"sentenceWithHints":"我 有 一只 兔子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (597, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一","english":"a","examples":["I have a pen.","This is a dog."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"匹","english":"","examples":["一匹马","一匹布"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"horses","chinese":"马","english":"horse","examples":["I have a horse.","The horse is running."],"phonetic":"/hɔːrs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","动词have的基本用法","不定冠词a的用法","中文量词与英文名词的对应"],"explanations":["人称代词I是第一人称单数主格，在句中作主语，用于指代说话者本人，后面搭配动词原形have。","动词have表示“拥有”，主语是第一人称I时，使用原形have；当主语是第三人称单数（如he/she/it）时，要变为has。","不定冠词a用于辅音音素开头的可数名词单数前，horse以辅音音素/h/开头，所以前面用a来表示“一个/一匹”的泛指概念。","中文里表示动物的数量常需要搭配量词，比如“马”搭配“匹”，但英文中可数名词表示数量时不需要对应量词，直接用冠词或数词加名词即可。"]},"sentenceWithHints":"我 有 一 匹 马"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (598, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love apples.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一","english":"a","examples":["I have a dog.","This is a pen."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"头","english":"","examples":["一头猪","一头大象"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"cows","chinese":"牛","english":"cow","examples":["The cow is black and white.","There are three cows on the farm."],"phonetic":"/kaʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","实义动词have的基本用法","不定冠词a的用法","中文量词的英文表达特点"],"explanations":["第一人称代词“I”用于指代说话者本人，作主语时永远大写，小学阶段主要掌握其在陈述句中作主语的基础用法。","实义动词have表示“拥有”，主语是第一人称I、第二人称you以及复数主语时用原形have；主语是第三人称单数时要用has，本句主语是I，所以用have。","不定冠词a用于可数名词单数前，当单词以辅音音素开头时使用，cow以辅音音素/k/开头，所以前面用a来表示“一个/一头”的泛指概念。","中文里表示动物的数量常用特定量词，比如“一头牛”，但英文中没有对应的量词表达，直接用“a + 可数名词单数”即可体现数量，这是中英表达的差异点，小学阶段需要了解这种转换规则。"]},"sentenceWithHints":"我 有 一 头 牛"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (599, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一只","english":"a","examples":["A dog is running.","I need a pen."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"ducks","chinese":"鸭子","english":"duck","examples":["The duck is yellow.","There are two ducks in the pond."],"phonetic":"/dʌk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格使用","不定冠词a的用法","实义动词have的人称变化"],"explanations":["人称代词I是第一人称主格，在句子中作主语，用于指代说话人自己，小学阶段主要掌握其在陈述句中作主语的基础用法。","不定冠词a用于可数名词单数前，当单词以辅音音素开头时使用，本句中duck以辅音音素/d/开头，所以用a来表示“一只”的泛指概念。","实义动词have表示“拥有”，当主语是第一人称I、第二人称you以及复数主语时用have；当主语是第三人称单数（如he、she、it）时，要变为has，本句主语是I，所以用have。"]},"sentenceWithHints":"我 有 一只 鸭子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (600, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"chinese":"一","english":"a","examples":["I have a pen.","This is a dog."],"phonetic":"/ə/","partOfSpeech":"冠词"},{"chinese":"只","english":"","examples":["一只鸟","一只兔子"],"phonetic":"","partOfSpeech":"量词"},{"plural":"chickens","chinese":"鸡","english":"chicken","examples":["I have a chicken.","There are many chickens on the farm."],"phonetic":"/ˈtʃɪkɪn/","partOfSpeech":"名词"}],"examPoints":{"points":["人称代词主格的使用","不定冠词a的用法","动词have的基本用法","可数名词的单复数"],"explanations":["当句子主语是第一人称“我”时，对应的英文主格形式是I，在句中作主语，一般位于句首。","不定冠词a用于可数名词单数前，泛指一个事物，当单词以辅音音素开头时使用a，chicken以辅音音素/tʃ/开头，所以用a。","动词have表示“拥有”，主语是第一人称I时，用原形have；主语是第三人称单数时，要用has。","可数名词chicken表示“鸡”时，复数形式是在词尾加-s变成chickens，用于表示多个个体。"]},"sentenceWithHints":"我 有 一 只 鸡"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (876, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to eat an apple."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats very much."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"在","english":"in","examples":["The cat is in the box.","We study in the classroom."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"parks","chinese":"公园","english":"park","examples":["Let''s go to the park.","There is a lake in the park."],"phonetic":"/pɑːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"玩","english":"play","examples":["Children like playing games.","He plays football every day."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"}],"examPoints":{"points":["like的用法","地点介词in的使用","定冠词the的用法"],"explanations":["like后可以接动名词（doing形式）表示喜欢做某事的习惯，本句中like playing表示长期喜欢在公园玩的状态，这是小学阶段需要掌握的like的核心用法之一。","介词in用于表示在某个场所、空间内部，这里in the park表示在公园这个区域范围内，是小学阶段常见的地点介词搭配。","park是特指的某个公园或者双方都知道的公园，所以前面要加定冠词the，这是定冠词用于特指场所的基础用法，是小学低年级需要掌握的冠词知识点。"]},"sentenceWithHints":"我 喜欢 在 公园 玩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (877, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"在","english":"at","examples":["At seven o''clock, I go to school.","She is at home."],"phonetic":"/æt/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","There are many schools in the city."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"study","examples":["I study math every night.","He is studying English now."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"}],"examPoints":{"points":["like的用法","介词at的地点用法","动名词作宾语"],"explanations":["like作为动词表示“喜欢”时，常见用法有like doing sth.（表示长期的、习惯性的喜欢）和like to do sth.（表示偶尔的、具体的喜欢），本句描述习惯性的喜好，所以用like studying。当主语是第三人称单数时，like要变成likes。","介词at用于表示具体的小地点，school属于具体的场所，所以用at school表示“在学校”，类似的还有at home、at the park。","在like等表示喜好的动词后面，动词要变成动名词形式（即动词+ing），作动词的宾语，所以study要变成studying。"]},"sentenceWithHints":"我 喜欢 在 学校 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (878, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"在","english":"at","examples":["Stay at home.","Look at the blackboard."],"phonetic":"/æt/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"homes","chinese":"家","english":"home","examples":["My home is big.","Let''s go home."],"phonetic":"/hoʊm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"看","english":"watch","examples":["I watch TV every day.","He watched a movie last night."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"TVs","chinese":"电视","english":"TV","examples":["I watch TV after dinner.","There is a new TV in the room."],"phonetic":"/ˌtiːˈviː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定用法","地点介词at的使用","TV的缩写表达"],"explanations":["like作为动词表示“喜欢”时，常用搭配为like doing sth.，表示长期的、习惯性的喜好，本句中“喜欢看电视”是长期爱好，所以用like watching TV；当表示具体某一次想要做某事时用like to do sth.，小学阶段先掌握like doing sth.的基础用法。","at作为地点介词，后接小地点，home属于小地点，所以用at home表示“在家”，这是小学阶段需要掌握的常见地点介词短语。","TV是television的缩写形式，在日常表达中常用缩写，小学阶段需要认识这个缩写并掌握“watch TV”这个固定搭配，不能写成“watch a TV”。"]},"sentenceWithHints":"我 喜欢 在 家 看 电视"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (879, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"和","english":"with","examples":["I go to school with my sister.","He plays football with his friends."],"phonetic":"/wɪð/","partOfSpeech":"介词"},{"plural":"friends","chinese":"朋友","english":"friend","examples":["He is my good friend.","I have many friends."],"phonetic":"/frend/","partOfSpeech":"名词"},{"chinese":"一起","english":"together","examples":["We play together every day.","Let''s eat together."],"phonetic":"/təˈɡeðər/","partOfSpeech":"副词"},{"chinese":"玩","english":"play","examples":["I play basketball after school.","She plays the piano well."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"}],"examPoints":{"points":["like的用法","介词with的用法","可数名词复数"],"explanations":["like表示“喜欢”时，常用结构like doing sth.，表示喜欢做某事的习惯，本句中like playing就是这个用法，符合小学二年级对like基础用法的考查。","介词with在这里表示“和……一起”，用来引出一起做事情的对象，连接动作和伴随的人，是小学阶段需要掌握的基础介词用法。","“朋友”是可数名词，当表示泛指的多个朋友时，要用复数形式friends，在小学二年级阶段需要掌握可数名词变复数的规则变化，一般直接在词尾加s。"]},"sentenceWithHints":"我 喜欢 和 朋友 一起 玩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (880, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"和","english":"with","examples":["I go to school with my sister.","She plays with her dog."],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"parents","chinese":"父母","english":"parents","examples":["My parents love me.","I live with my parents."],"phonetic":"/ˈperənts/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["We play games together.","Let''s sing together."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吃饭","english":"eat","examples":["I eat rice every day.","She eats breakfast at 7."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"}],"examPoints":{"points":["like的用法","介词with的用法","可数名词复数"],"explanations":["like作为动词表示“喜欢”时，常用结构为like doing sth.，表示长期的爱好，本句中like eating就是这个结构的体现；当主语是第三人称单数时，like要变成likes。","介词with在这里表示“和……一起”，用来引出伴随的对象，连接动作的伴随者，本句中with my parents表示和父母一起做吃饭这个动作。","parent表示“父亲”或“母亲”，是可数名词，复数形式parents表示“父母双亲”，在表达父母两个人的概念时要用复数形式。"]},"sentenceWithHints":"我 喜欢 和 父母 一起 吃饭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (881, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"fathers","chinese":"父亲","english":"father","examples":["My father works in a factory.","Her father is a driver."],"phonetic":"/ˈfɑːðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is tall.","The flower is red."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一名","english":"a","examples":["I have a dog.","She wants a cup of milk."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"doctors","chinese":"医生","english":"doctor","examples":["The doctor helps sick people.","My uncle is a doctor."],"phonetic":"/ˈdɑːktər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词性物主代词的使用","系动词be的单数形式用法","不定冠词a的用法","可数名词单数的表达"],"explanations":["形容词性物主代词my用来表示所属关系，修饰后面的名词father，说明是“我的”父亲，这类代词不能单独使用，必须和名词搭配。","系动词is用于第三人称单数主语后，本句主语father是第三人称单数，所以用is来连接主语和表语，表示主语的身份。","不定冠词a用于可数名词单数前，当单词以辅音音素开头时使用，doctor以辅音音素/d/开头，所以前面用a来表示“一名”的泛指概念。","表示职业的可数名词单数，在泛指身份时，前面要搭配不定冠词a/an，doctor是可数名词，这里用单数形式搭配a来表示“一名医生”。"]},"sentenceWithHints":"我的 父亲 是 一名 医生。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (882, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"mothers","chinese":"母亲","english":"mother","examples":["My mother can cook well.","Her mother is a doctor."],"phonetic":"/ˈmʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is tall.","The flower is red."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一名","english":"a","examples":["I have a dog.","She is a singer."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very nice.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词性物主代词的用法","系动词be的单数形式用法","不定冠词a的用法","可数名词单数的用法"],"explanations":["形容词性物主代词my用来修饰名词，表示所属关系，意为“我的”，后面必须跟名词，比如my mother、my book。","系动词is用于第三人称单数主语之后，本句主语mother是第三人称单数，所以用is来连接主语和表语。","不定冠词a用于辅音音素开头的可数名词单数前，用来泛指“一个”，teacher是以辅音音素/t/开头的单词，所以前面用a。","可数名词表示单个的人或事物时用单数形式，当表示泛指单个的这类事物时，前面通常要加不定冠词a/an，比如a teacher、a pen。"]},"sentenceWithHints":"我的 母亲 是 一名 老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (883, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"brothers","chinese":"兄弟","english":"brother","examples":["My brother likes playing football.","He has two brothers."],"phonetic":"/ˈbrʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["She is a nurse.","The flower is red."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一名","english":"a","examples":["I have a dog.","She is a singer."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"students","chinese":"学生","english":"student","examples":["The student is hard-working.","There are many students in the classroom."],"phonetic":"/ˈstuːdənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词性物主代词的用法","系动词be的单数形式用法","不定冠词a的用法","可数名词单数的用法"],"explanations":["形容词性物主代词my用来修饰名词，表明所属关系，意为“我的”，后面必须接名词，不能单独使用，此处用来修饰“兄弟”。","系动词be的单数形式is用于第三人称单数主语后，本句主语“my brother”是第三人称单数，所以使用is。","不定冠词a用于辅音音素开头的可数名词单数前，用来泛指“一个”，student是以辅音音素开头的单词，所以前面用a。","可数名词单数表示单个的人或事物，在泛指时前面通常需要加不定冠词a/an，本句中“student”是可数名词单数，前面用a来修饰。"]},"sentenceWithHints":"我的 兄弟 是 一名 学生"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (884, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my cat."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"sisters","chinese":"姐妹","english":"sister","examples":["My sister likes pink.","She has two sisters."],"phonetic":"/ˈsɪstər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is a doctor.","The flower is beautiful."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一名","english":"a","examples":["I have a dog.","She is a singer."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"students","chinese":"学生","english":"student","examples":["The student is hard-working.","There are many students in the classroom."],"phonetic":"/ˈstuːdənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词性物主代词的使用","系动词be的单复数搭配","不定冠词a的用法","可数名词的单复数形式"],"explanations":["形容词性物主代词my用来表示所属关系，后面必须接名词，用来指代“我的……”，小学阶段需要掌握my, your, his, her等基础物主代词。","系动词be的形式要和主语保持一致，本句主语“sister”是第三人称单数，所以搭配is；如果主语是复数或you，则用are，主语是I则用am。","不定冠词a用于辅音音素开头的可数名词单数前，用来泛指“一个”，student是以辅音音素/st/开头，所以用a；如果是元音音素开头的可数名词单数则用an。","可数名词有单复数形式，规则名词变复数一般在词尾加-s，sister和student都是规则变化，复数形式分别为sisters和students，小学阶段需要掌握这类规则变化的可数名词。"]},"sentenceWithHints":"我的 姐妹 是 一名 学生"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (885, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家庭","english":"family","examples":["My family loves to travel.","She comes from a big family."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have/has","examples":["I have a dog.","He has a new bike."],"phonetic":"/hæv/ /hæz/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"四个","english":"four","examples":["There are four seasons in a year.","I have four apples."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""},{"plural":"people","chinese":"人","english":"people","examples":["Many people like pandas.","There are five people in his family."],"phonetic":"/ˈpiːpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词have/has的用法","集体名词family的主谓一致","数词修饰可数名词"],"explanations":["have和has都表示“有”，当主语是第一人称（I/we）、第二人称（you）或复数主语时用have；当主语是第三人称单数（he/she/it或单数名词）时用has。本句主语family在这里表示一个整体，视为单数，所以用has。","family是集体名词，当表示家庭这个整体概念时，视为单数，谓语动词用第三人称单数形式；当表示家庭里的成员时，视为复数，谓语动词用原形。本句是说家庭作为整体包含的人数，所以视为单数。","数词可以直接修饰可数名词复数，表示数量，本句中four修饰people，明确家庭的人数为4个。people本身是复数名词，不需要再变复数形式。"]},"sentenceWithHints":"我的 家庭 有 四个 人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (887, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一个","english":"a","examples":["I have a pen.","This is a dog."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"快乐","english":"happy","examples":["She is happy.","We had a happy day."],"phonetic":"/ˈhæpi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the color of the sky","a friend of mine"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家庭","english":"family","examples":["My family is big.","Many families live in this building."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与谓语动词的搭配","不定冠词的用法","形容词修饰名词的位置"],"explanations":["当主语是第一人称代词I时，谓语动词用have的原形；如果主语是第三人称单数（如he/she/it），则要用has。本句主语是I，所以用have。","不定冠词a用于辅音音素开头的可数名词单数前，family是以辅音音素/f/开头的可数名词单数，所以前面用a来表示“一个”的概念。","形容词用来修饰名词时，通常放在名词的前面，本句中happy是形容词，用来修饰后面的名词family，表达“快乐的家庭”的意思。"]},"sentenceWithHints":"我 有 一个 快乐 的 家庭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (888, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"homes","chinese":"家","english":"home","examples":["My home is warm.","We go home after school."],"phonetic":"/hoʊm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"is","examples":["The book is on the shelf.","He is tall."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","The school has a big playground."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"附近","english":"near","examples":["The park is near my home.","I sit near the window."],"phonetic":"/nɪr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["物主代词的使用","系动词be的搭配","方位介词near的用法","定冠词the的特指用法"],"explanations":["物主代词my用于修饰名词，表示所属关系，指代“我的”，后面要接名词，比如my home、my book。","系动词be的形式要和主语保持一致，本句主语home是单数名词，所以用is。","方位介词near用来表示位置关系，意为“在……附近”，用来描述两个事物的位置距离较近。","定冠词the用于特指双方都知道的事物，本句中的school是说话双方都明确的特定学校，所以前面加the。"]},"sentenceWithHints":"我的 家 在 学校 附近"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (889, '{"words":[{"plural":"","chinese":"我家","english":"my home","examples":["My home is near the park.","I love my home very much."],"phonetic":"/maɪ hoʊm/","partOfSpeech":"名词"},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"三个","english":"three","examples":["I have three apples.","There are three books on the desk."],"phonetic":"/θriː/","partOfSpeech":"数词"},{"plural":"rooms","chinese":"房间","english":"room","examples":["My room is clean.","There are five rooms in this house."],"phonetic":"/ruːm/","partOfSpeech":"名词"}],"examPoints":{"points":["动词have的第三人称单数形式","可数名词的复数变化"],"explanations":["当主语是第三人称单数（本句中my home属于第三人称单数主语）时，表示“有”的动词have要变为第三人称单数形式has。","可数名词表示数量大于1时，要使用复数形式。room是规则可数名词，直接在词尾加-s变为复数rooms，前面搭配数词three表示具体数量。"]},"sentenceWithHints":"我家 有 三个 房间"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (890, '{"words":[{"plural":"","chinese":"我","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"homes","chinese":"家","english":"home","examples":["I love my home.","We are going home."],"phonetic":"/hoʊm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a dog.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一个","english":"a","examples":["I have a pen.","There is a tree."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"gardens","chinese":"花园","english":"garden","examples":["There are flowers in the garden.","We grow vegetables in the garden."],"phonetic":"/ˈɡɑːrdn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词have的第三人称单数形式","不定冠词a的用法","所属关系的表达"],"explanations":["动词have表示“有”，当主语是第三人称单数（本句中my home属于第三人称单数主语）时，要使用其第三人称单数形式has。","不定冠词a用于辅音音素开头的可数名词单数前，garden是以辅音音素开头的可数名词，所以前面用a来表示“一个”的概念。","中文里“我家”表示所属关系，在英文中用形容词性物主代词my加上名词home来表达，即my home，这是英语中表达所属关系的基础方式。"]},"sentenceWithHints":"我 家 有 一个 花园"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (891, '{"words":[{"plural":"","chinese":"我家","english":"my home","examples":["My home is near the park.","I love my home."],"phonetic":"/maɪ hoʊm/","partOfSpeech":"名词"},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"chinese":"两","english":"two","examples":["I have two apples.","There are two books on the desk."],"phonetic":"/tuː/","partOfSpeech":"数词"},{"chinese":"辆","english":"","examples":["一辆自行车","三辆公交车"],"phonetic":"","partOfSpeech":"量词"},{"plural":"cars","chinese":"车","english":"car","examples":["This is my car.","There are many cars on the road."],"phonetic":"/kɑːr/","partOfSpeech":"名词"}],"examPoints":{"points":["动词have的第三人称单数形式","可数名词的复数变化","中文量词的英文表达特点"],"explanations":["当主语是第三人称单数（如my home、he、she等）时，动词have要变为第三人称单数形式has，本句主语my home属于第三人称单数，所以用has。","可数名词表示数量大于1时，要变为复数形式。规则可数名词car的复数是在词尾加-s，变为cars，本句中数量是two，所以用cars。","中文中表示具体物品数量时常用量词，比如“辆”对应车，但在英文中通常不需要单独翻译这类量词，直接用数词加可数名词复数即可表达对应的数量含义。"]},"sentenceWithHints":"我家 有 两 辆 车"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (892, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","Our school has a big playground."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The apple is very sweet.","She runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"大","english":"big","examples":["That is a big tree.","The box is too big to carry."],"phonetic":"/bɪɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"美","english":"beautiful","examples":["The flower is beautiful.","We live in a beautiful city."],"phonetic":"/ˈbjuːtɪfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["She is happy.","The dog is black."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"和","english":"and","examples":["I like bread and milk.","He sings and dances well."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词的使用","系动词be的搭配","并列连词and的用法"],"explanations":["在描述事物特征时，用形容词来表达，如big（大的）、beautiful（美丽的），副词very（很）用来修饰形容词，加强程度，放在形容词前面。","当主语是第三人称单数（如本句的school）时，系动词要用is，用来连接主语和后面的形容词表语，说明主语的特征。","当需要连接两个词性相同、语义并列的内容时，用并列连词and，本句中用and连接big和beautiful，同时描述学校的两个特点，符合英语并列表达的习惯。"]},"sentenceWithHints":"我的 学校 很 大 很 美"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (894, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher likes reading.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The apple is very sweet.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和蔼","english":"kind","examples":["My grandma is very kind.","It''s kind of you to help me."],"phonetic":"/kaɪnd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["She is a nurse.","The flower is beautiful."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的用法","系动词be的搭配","程度副词very的用法"],"explanations":["形容词用于描述人或事物的特征，本句中kind（和蔼的）用来描述老师的性格特点，在句中跟在系动词is后作表语。","系动词be（am/is/are）用于连接主语和表语，本句主语my teacher是第三人称单数，所以搭配is来构成主系表结构。","程度副词very用来修饰形容词或副词，用来加强语气，本句中very用来修饰形容词kind，强调和蔼的程度。"]},"sentenceWithHints":"我的 老师 很 和蔼。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (895, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"classmates","chinese":"同学们","english":"classmates","examples":["My classmates like playing games.","I walk to school with my classmates."],"phonetic":"/ˈklæsmeɪts/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cat is very cute."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"友好","english":"friendly","examples":["The friendly girl helps me.","Our teacher is friendly to us."],"phonetic":"/ˈfrendli/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词的用法","系动词be的复数形式","名词复数"],"explanations":["形容词用来描述人或事物的特征，本句中friendly用来描述同学们的性格特点，放在系动词are之后作表语。","be动词的复数形式是are，当主语是复数名词（如classmates）时，要用are来连接主语和表语。","可数名词表示多个时要用复数形式，classmate的复数是在词尾直接加s变成classmates，用来表示多个同学。"]},"sentenceWithHints":"我的 同学们 很 友好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (912, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to play football."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes singing songs."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"看","english":"read","examples":["I read a book every day.","He is reading a newspaper now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"storybooks","chinese":"故事书","english":"storybook","examples":["I have many storybooks.","My mom bought me a new storybook."],"phonetic":"/ˈstɔːribʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like doing sth. 固定搭配","可数名词复数形式","动词read的形式变化"],"explanations":["like后接动词时，常用like doing sth.的结构，表示长期的、习惯性的喜好，本句中表示习惯性喜欢看书，所以用like reading。","storybook是可数名词，当表示一类事物时，常用复数形式，直接在词尾加s变为storybooks。","read是不规则动词，它的过去式和过去分词形式和原形拼写一致，发音变为/red/；第三人称单数形式是在词尾加s变为reads，现在分词是在词尾加ing变为reading。"]},"sentenceWithHints":"我 喜欢 看 故事书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (913, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes dancing."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"看","english":"read","examples":["I read books every day.","He is reading a story."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"comic books","chinese":"漫画书","english":"comic book","examples":["I have many comic books.","She is reading a comic book."],"phonetic":"/ˈkɑːmɪk bʊk/","partOfSpeech":"名词"}],"examPoints":{"points":["like的用法","可数名词复数","动词的-ing形式"],"explanations":["like后接动词时，常用like doing sth.的结构，表示长期的、习惯性的喜好，本句中表示喜欢看漫画书这个习惯，所以用like reading。","comic book是可数名词，当表示一类事物或者数量不止一个时，要用复数形式comic books，本句中泛指漫画书这类读物，所以用复数。","动词read在like之后要变成-ing形式reading，这是like doing sth.结构的要求，用来表示喜欢做的具体行为。"]},"sentenceWithHints":"我 喜欢 看 漫画书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (914, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes dancing."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"看","english":"read","examples":["I read books every day.","He is reading a story."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"science books","chinese":"科普书","english":"science books","examples":["I love reading science books.","The library has many science books."],"phonetic":"/ˈsaɪəns bʊks/","partOfSpeech":"名词"}],"examPoints":{"points":["like的用法","可数名词复数","动词短语搭配"],"explanations":["like作为动词表示“喜欢”时，常用搭配为like doing sth.，表示长期的、习惯性的喜好，本句中“喜欢看”是长期爱好，所以用like reading。","科普书是可数名词，这里表示一类事物，要用复数形式science books，不需要加不定冠词a/an。","“看（书）”对应的英文动词是read，read books是固定的动词短语搭配，用来表达阅读书籍的动作。"]},"sentenceWithHints":"我 喜欢 看 科普书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (915, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"看","english":"read","examples":["I read a book every day.","He is reading a story."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"picture books","chinese":"绘本","english":"picture book","examples":["I love reading picture books.","The picture book has colorful pages."],"phonetic":"/ˈpɪktʃər bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定搭配","可数名词复数形式"],"explanations":["like作为动词表示“喜欢”时，常用搭配为like doing sth.，表示长期的、习惯性的喜好，本句中“喜欢看绘本”是长期的爱好，所以用like reading。","绘本对应的英文picture book是可数名词短语，这里表示一类事物，要用复数形式picture books，在可数名词短语的中心词book后加s构成复数。"]},"sentenceWithHints":"我 喜欢 看 绘本"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (916, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一","english":"a","examples":["A dog is running.","I need a pen."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"本","english":"","examples":["一本杂志","一本字典"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["This is a good idea.","He is a good boy."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["红色的花","可爱的猫"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["I read a book every day.","There are many books on the shelf."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不定冠词a的用法","实义动词have的用法","副词修饰形容词的用法"],"explanations":["不定冠词a用于辅音音素开头的可数名词单数前，本句中book是以辅音音素/b/开头的可数名词单数，所以用a修饰。","实义动词have表示“拥有”，主语是第一人称I时，用原形have；主语是第三人称单数（如he/she/it）时，要变为has。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very修饰good，强调书的质量好。"]},"sentenceWithHints":"我 有 一 本 很 好 的 书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (918, '{"words":[{"plural":"","chinese":"这","english":"this","examples":["This is my pen.","This cat is cute."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"本","english":"copy","examples":["a copy of book","I need another copy of the paper."],"phonetic":"/ˈkɑːpi/","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["I have a new book.","She reads books every day."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"教会","english":"teach","examples":["My mom teaches me math.","He taught me to swim last summer."],"phonetic":"/tiːtʃ/","pastTense":"taught","thirdPerson":"teaches","partOfSpeech":"动词","pastParticiple":"taught","presentParticiple":"teaching"},{"plural":"","chinese":"我","english":"me","examples":["She gives me a gift.","Please tell me the story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很多","english":"many","examples":["I have many toys.","Many students like playing games."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"things","chinese":"东西","english":"thing","examples":["I have many things to do.","These things are useful."],"phonetic":"/θɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词第三人称单数变化","可数名词复数形式","人称代词宾格的使用"],"explanations":["当句子主语是第三人称单数（如本句的this book）时，一般现在时的动词要变成第三人称单数形式。teach的第三人称单数是在词尾加-es，即teaches。","many用来修饰可数名词复数，thing是可数名词，所以要变成复数形式things，规则可数名词变复数一般在词尾加-s。","在句子中作动词的宾语时，第一人称代词要用宾格形式，“我”的宾格是me，本句中me作teaches的宾语。"]},"sentenceWithHints":"这 本 书 教会 我 很多 东西"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (923, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"必须","english":"must","examples":["You must finish your homework first.","We must keep quiet in the library."],"phonetic":"/mʌst/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"按时","english":"on time","examples":["Please arrive on time.","The bus came on time."],"phonetic":"/ɑːn taɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"还","english":"return","examples":["Please return the pen to me.","He returns home at 6 every evening."],"phonetic":"/rɪˈtɜːrn/","pastTense":"returned","thirdPerson":"returns","partOfSpeech":"动词","pastParticiple":"returned","presentParticiple":"returning"},{"plural":"books","chinese":"书","english":"book","examples":["I have a new book.","There are many books on the shelf."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词must的用法","固定短语on time的含义","动词return的用法","可数名词复数"],"explanations":["must是情态动词，本身没有人称和数的变化，后面要接动词原形，用来表示“必须、不得不”，强调义务或要求，小学阶段主要学习它表示强制要求的用法。","on time是固定副词短语，意思是“按时、准时”，和它易混淆的是in time（及时），小学阶段需要掌握on time在句子中的位置，通常放在句末。","return作为动词，在这里表示“归还”，是及物动词，后面可以直接接宾语，比如return books（还书），它的过去式和过去分词都是在词尾加ed，属于规则变化。","book是可数名词，当表示一类事物或者数量不止一个时，要变成复数形式books，规则可数名词变复数一般在词尾加s，这是小学阶段名词变形的基础知识点。"]},"sentenceWithHints":"我 必须 按时 还 书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (929, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"in","examples":["The cat is in the box.","We study in the classroom."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"parks","chinese":"公园","english":"park","examples":["Let''s go to the park.","There is a beautiful park near my home."],"phonetic":"/pɑːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"里","english":"","examples":["房间里有一张床。","盒子里装着玩具。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"玩","english":"play","examples":["I play football after school.","She plays the piano well."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"balls","chinese":"球","english":"ball","examples":["The boy is playing with a ball.","I have a red ball."],"phonetic":"/bɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["介词in的用法","一般现在时的陈述句结构","可数名词的定冠词使用"],"explanations":["介词in用于表示在某个空间范围内部，本句中“在公园里”用in the park来表达，是小学阶段需要掌握的地点介词基础用法。","一般现在时陈述句，当主语是第一人称I时，谓语动词用原形，本句中主语是I，所以动词play用原形，结构为主语+谓语+宾语+地点状语，符合小学二年级的句型要求。","表示特指的地点时，名词前要加定冠词the，本句中park是特指说话双方都知道的那个公园，所以用the park，这是小学阶段定冠词的基础用法之一。"]},"sentenceWithHints":"我 在 公园 里 玩 球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (930, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"with","examples":["I go to school with my sister.","She draws with a pencil."],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"friends","chinese":"朋友","english":"friend","examples":["He is my good friend.","I have many friends."],"phonetic":"/frend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["We play games together.","Let''s read books together."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"玩","english":"play","examples":["I play football every day.","She plays the piano well."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"}],"examPoints":{"points":["介词with的用法","可数名词的复数形式","一般现在时动词形式"],"explanations":["介词with在这里表示“和……一起”，用来引出伴随的对象，通常放在动词之后，比如“I play with my friends”里用with连接“我”和“朋友”，说明一起做动作的伙伴。","可数名词表示多个时要变成复数形式，规则名词一般在词尾加-s，“friend”的复数直接加-s变成“friends”，这里用复数是因为没有特指某一个朋友，指多个朋友或者泛指伙伴。","一般现在时中，当主语是第一人称“I”“we”，第二人称“you”或者复数主语时，动词用原形。本句主语是“I”，所以动词“play”用原形；如果主语是第三人称单数（比如he/she/it），动词要变成第三人称单数形式“plays”。"]},"sentenceWithHints":"我 和 朋友 一起 玩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (931, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"玩","english":"play","examples":["We play games after class.","She plays the piano every day."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"","chinese":"得","english":"","examples":["She runs fast.","He sings beautifully."],"phonetic":"/də/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The cat is very cute.","He runs very quickly."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"开心","english":"happily","examples":["She laughs happily.","They live happily together."],"phonetic":"/ˈhæpəli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词修饰动词的用法","人称代词主格的使用","“得”字结构的英语转换"],"explanations":["在英语中，修饰动词表示动作的状态时，需要用副词。本句中“开心”是用来修饰“玩”这个动作的状态，所以要用副词happily，而不是形容词happy。","“我们”是第一人称复数主格代词，在句中作主语，对应的英语是we，主格代词在句中用来发出动作，作句子的主语成分。","中文里“得”用在动词后连接补语，说明动作的状态，转换为英语时，要把表示状态的部分换成对应的副词放在动词之后，来体现动作的状态，本句中“玩得很开心”就转换为“play very happily”。"]},"sentenceWithHints":"我们 玩 得 很 开心"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (934, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看见","english":"see","examples":["I see a cat in the tree.","She sees a bird every morning."],"phonetic":"/siː/","pastTense":"saw","thirdPerson":"sees","partOfSpeech":"动词","pastParticiple":"seen","presentParticiple":"seeing"},{"plural":"tigers","chinese":"老虎","english":"tiger","examples":["The tiger is very strong.","There are two tigers in the zoo."],"phonetic":"/ˈtaɪɡər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","He and I are good friends."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"lions","chinese":"狮子","english":"lion","examples":["The lion is the king of the forest.","We saw three lions at the zoo."],"phonetic":"/ˈlaɪən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的复数形式","连词and的用法","一般现在时动词形式"],"explanations":["可数名词表示一类事物时，常用复数形式，规则名词一般在词尾加-s，本句中tiger和lion都是规则可数名词，复数形式分别为tigers和lions，用来指代老虎和狮子这两类动物。","连词and用来连接两个并列的成分，本句中用来连接两个并列的名词tigers和lions，表达“老虎和狮子”的并列关系。","一般现在时中，当主语是第一人称I时，谓语动词用原形，本句主语是I，所以动词see用原形。"]},"sentenceWithHints":"我 看见 老虎 和 狮子"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (935, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看见","english":"see","examples":["I see a cat under the tree.","She sees a bird in the sky."],"phonetic":"/siː/","pastTense":"saw","thirdPerson":"sees","partOfSpeech":"动词","pastParticiple":"seen","presentParticiple":"seeing"},{"plural":"elephants","chinese":"大象","english":"elephant","examples":["The elephant is very big.","We saw three elephants in the zoo."],"phonetic":"/ˈelɪfənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","She sings and dances well."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"giraffes","chinese":"长颈鹿","english":"giraffe","examples":["The giraffe has a long neck.","Giraffes eat leaves from tall trees."],"phonetic":"/dʒəˈræf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词 see 的用法","可数名词的复数形式","并列连词 and 的用法"],"explanations":["see 是表示“看见”的实义动词，在一般现在时中，当主语是第一人称 I 时，动词用原形；当主语是第三人称单数时，动词要变为 sees。本句主语是 I，所以用 see 的原形。","可数名词表示泛指一类事物时，通常用复数形式。规则的可数名词变复数一般在词尾加 -s，elephant 和 giraffe 都是规则变化，直接加 -s 变为 elephants 和 giraffes。","and 是并列连词，用于连接两个并列的人、事物或句子成分，本句中用来连接“大象”和“长颈鹿”两个并列的名词，体现两者的并列关系。"]},"sentenceWithHints":"我 看见 大象 和 长颈鹿"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (936, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看见","english":"see","examples":["I see a cat in the tree.","She sees a bird every morning."],"phonetic":"/siː/","pastTense":"saw","thirdPerson":"sees","partOfSpeech":"动词","pastParticiple":"seen","presentParticiple":"seeing"},{"plural":"monkeys","chinese":"猴子","english":"monkey","examples":["The monkey is eating bananas.","There are many monkeys in the zoo."],"phonetic":"/ˈmʌŋki/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and oranges.","He and I are good friends."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"pandas","chinese":"熊猫","english":"panda","examples":["The panda is very cute.","We saw two pandas in the zoo."],"phonetic":"/ˈpændə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词的人称搭配","可数名词的复数形式","并列连词and的用法"],"explanations":["当主语是第一人称I时，一般现在时中的实义动词用原形，本句主语是I，所以动词用see的原形。","可数名词表示泛指一类事物时，常用复数形式，规则的可数名词复数一般在词尾加-s，monkey和panda都是规则变化，复数形式分别为monkeys和pandas。","并列连词and用来连接两个并列的成分，本句中用来连接两个并列的名词monkeys和pandas，起到列举的作用。"]},"sentenceWithHints":"我 看见 猴子 和 熊猫"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (937, '{"words":[{"plural":"animals","chinese":"动物们","english":"animal","examples":["I like small animals.","The animals are playing in the zoo."],"phonetic":"/ˈænɪml/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","This book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"可爱","english":"cute","examples":["The cat is so cute.","Look at that cute baby."],"phonetic":"/kjuːt/","partOfSpeech":"形容词"}],"examPoints":{"points":["可数名词复数形式","系动词的主谓一致","副词修饰形容词的用法"],"explanations":["可数名词表示多个时需要使用复数形式，“动物们”是复数概念，所以“animal”要变成复数“animals”，规则名词复数一般直接在词尾加-s。","系动词be的形式要和主语保持一致，本句主语“the animals”是复数，所以对应的系动词要用“are”。","副词“very”用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中“very”修饰形容词“cute”，表示“非常可爱”。"]},"sentenceWithHints":"动物们 很 可爱"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (940, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学到了","english":"learn","examples":["I learn English every day.","She learned to swim last summer."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"很多","english":"a lot of","examples":["There are a lot of books on the shelf.","I have a lot of friends."],"phonetic":"/ə lɑːt əv/","pastTense":"","thirdPerson":"","partOfSpeech":"限定词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词过去式的使用","不可数名词的修饰","人称代词主格的使用"],"explanations":["句子表达“已经学到”的过去动作，所以使用动词learn的过去式learned（美式英语常用），小学阶段需要掌握规则及常见不规则动词过去式的变化和使用场景，用于描述过去发生的动作。","knowledge是不可数名词，不能直接加s变复数，修饰不可数名词表示“很多”时，可以用a lot of，小学阶段需要区分可数名词和不可数名词的修饰词差异。","“我”在句子中作主语，要使用人称代词的主格形式I，主格代词用于句子主语位置，小学阶段需要掌握常见人称代词主格的基本用法。"]},"sentenceWithHints":"我 学到了 很多 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (941, '{"words":[{"plural":"museums","chinese":"博物馆","english":"museum","examples":["Let''s visit the museum.","The museum has many old things."],"phonetic":"/mjuˈziːəm/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["The cat is very cute.","She runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有趣","english":"interesting","examples":["This story is interesting.","The game is very interesting."],"phonetic":"/ˈɪntrəstɪŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["定冠词the的用法","主系表结构","副词very修饰形容词"],"explanations":["定冠词the用于特指的事物前，这里的museum是特指某个双方都知道的博物馆，所以前面加the。","主系表结构是英语基础句式之一，结构为主语+系动词+表语，本句中主语是the museum，系动词是is，表语是interesting，用来描述主语的特征。","副词very用来修饰形容词，表示程度，放在形容词前面，用来加强形容词表达的语气，本句中very用来强调interesting的程度，说明博物馆有趣的程度很高。"]},"sentenceWithHints":"博物馆 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (942, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like cats."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like reading books.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"吃","english":"eat","examples":["I eat breakfast every day.","He is eating an apple."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"fruits","chinese":"水果","english":"fruit","examples":["I like fresh fruit.","There are many kinds of fruits in the shop."],"phonetic":"/fruːt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词的复数形式","人称代词的主格形式"],"explanations":["like作为动词表示“喜欢”时，常用搭配为like doing sth.，表示长期的、习惯性的喜好，本句中like eating fruits就符合这个用法，表达习惯性喜欢吃水果。","fruit表示“各种水果”时是可数名词，复数形式为fruits；表示“水果统称”时可作不可数名词，本句中强调各类水果，所以用复数形式fruits。","“我”在句中作主语，要用人称代词的主格形式I，主格代词在句中用来作主语，发出动作。"]},"sentenceWithHints":"我 喜欢 吃 水果"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (943, '{"words":[{"plural":"apples","chinese":"苹果","english":"apple","examples":["I like eating apples.","An apple a day keeps the doctor away."],"phonetic":"/ˈæpl/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["You and I are good friends.","I like bread and milk."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"bananas","chinese":"香蕉","english":"banana","examples":["Bananas are rich in potassium.","She gave me a bunch of bananas."],"phonetic":"/bəˈnænə/","partOfSpeech":"名词"},{"chinese":"是","english":"are","examples":["We are students.","These books are mine."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to play outside."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"my","examples":["This is my cat.","My favorite color is blue."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"favorites","chinese":"最爱","english":"favorite","examples":["These are my favorites.","What''s your favorite food?"],"phonetic":"/ˈfeɪvərɪt/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的复数形式","系动词be的用法","连词and的用法"],"explanations":["可数名词表示多个时要变成复数形式，规则变化一般在词尾加-s，如apple变apples，banana变bananas；favorite作为可数名词表示“最爱的事物”时，复数形式为favorites。小学阶段需要掌握常见可数名词的复数变化规则。","系动词be有am、is、are三种形式，当主语是复数（本句中apples and bananas是两个事物，属于复数主语）时，be动词要用are。需要根据主语的单复数来选择对应的be动词形式。","连词and用于连接两个并列的成分，本句中用来连接两个并列的名词apples和bananas，表示两者并列的关系，在句子中共同作主语。"]},"sentenceWithHints":"苹果 和 香蕉 是 我 的 最爱"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (944, '{"words":[{"plural":"oranges","chinese":"橙子","english":"orange","examples":["I like eating oranges.","An orange is a kind of fruit."],"phonetic":"/ˈɔːrɪndʒ/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["You and I are good friends.","I like apples and bananas."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"strawberries","chinese":"草莓","english":"strawberry","examples":["Strawberries are red and sweet.","She bought a box of strawberries."],"phonetic":"/ˈstrɔːberi/","partOfSpeech":"名词"},{"plural":"","chinese":"也","english":"also","examples":["I also like cats.","She can also play the piano."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好吃","english":"delicious","examples":["The cake is delicious.","This soup tastes delicious."],"phonetic":"/dɪˈlɪʃəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的复数形式","并列主语与be动词的搭配","副词also的用法"],"explanations":["以e结尾的可数名词orange变复数直接加s；以辅音字母+y结尾的可数名词strawberry，变复数要把y变i再加es，这是小学阶段需要掌握的可数名词复数变形规则。","当主语是由and连接的两个或多个可数名词复数时，属于复数主语，对应的be动词要用are，本句中oranges和strawberries是并列复数主语，所以be动词用are。","副词also表示“也”，通常放在be动词、情态动词之后，实义动词之前，本句中放在be动词are之后，符合小学阶段对also用法的基础要求。"]},"sentenceWithHints":"橙子 和 草莓 也 很 好吃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (945, '{"words":[{"plural":"fruits","chinese":"水果","english":"fruit","examples":["I like eating fresh fruit.","Different fruits have different vitamins."],"phonetic":"/fruːt/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","The book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"健康","english":"healthy","examples":["Vegetables are healthy food.","It''s important to keep healthy."],"phonetic":"/ˈhelθi/","partOfSpeech":"形容词"}],"examPoints":{"points":["可数名词的复数形式","系动词的主谓一致","副词修饰形容词的用法"],"explanations":["fruit表示不同种类的水果时是可数名词，复数形式为fruits，本句泛指各类水果，所以用复数形式。","句子主语fruits是可数名词复数，对应的系动词要用are，遵循主谓一致原则，即主语为复数时，be动词用are。","副词very用来修饰形容词healthy，放在形容词之前，用来加强形容词的语气，说明健康的程度。"]},"sentenceWithHints":"水果 很 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (947, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"也","english":"also","examples":["I also like cats.","She can also sing."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","He likes playing football."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"吃","english":"eat","examples":["I eat rice every day.","She has eaten breakfast."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"vegetables","chinese":"蔬菜","english":"vegetable","examples":["I like eating vegetables.","Vegetables are good for health."],"phonetic":"/ˈvedʒtəbəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词also的用法","like后接动名词的结构","可数名词复数形式"],"explanations":["also是表示“也”的副词，在句子中通常放在实义动词之前，be动词、助动词之后，本句中放在实义动词like之前，符合小学阶段的用法要求。","like作为动词，表示“喜欢”时，后面可以接动名词（即动词的-ing形式），表示长期的喜好，结构为like doing sth.，本句中like eating vegetables就是这个结构的应用。","vegetable是可数名词，当表示一类事物时，通常用复数形式vegetables，在小学阶段需要掌握可数名词变复数的规则，一般情况下在词尾加-s。"]},"sentenceWithHints":"我 也 喜欢 吃 蔬菜"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (948, '{"words":[{"plural":"carrots","chinese":"胡萝卜","english":"carrot","examples":["I like eating carrots.","Carrots are good for your eyes."],"phonetic":"/ˈkærət/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["You and I are good friends.","I like apples and bananas."],"phonetic":"/ænd/","partOfSpeech":"连词"},{"plural":"tomatoes","chinese":"西红柿","english":"tomato","examples":["Tomatoes are red.","I want to eat some tomatoes."],"phonetic":"/təˈmeɪtoʊ/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","The book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"好吃","english":"delicious","examples":["The cake is delicious.","This soup tastes delicious."],"phonetic":"/dɪˈlɪʃəs/","partOfSpeech":"形容词"}],"examPoints":{"points":["可数名词的复数形式","并列主语与be动词的搭配","形容词的用法"],"explanations":["以o结尾的有生命可数名词，变复数时通常加-es，比如tomato的复数是tomatoes；一般的可数名词变复数直接加-s，比如carrot的复数是carrots。在表示一类事物时，常用可数名词复数形式。","当用and连接两个并列的可数名词复数作主语时，主语表示复数概念，对应的be动词要用are，本句中Carrots and tomatoes是复数主语，所以用are。","delicious是形容词，用来描述事物的味道，在句中放在be动词are后面作表语，用来说明主语的特征；副词very用来修饰形容词delicious，加强程度，表示“非常好吃”。"]},"sentenceWithHints":"胡萝卜 和 西红柿 很 好吃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (949, '{"words":[{"plural":"cucumbers","chinese":"黄瓜","english":"cucumber","examples":["I like eating cucumbers in summer.","Cucumbers are good for our health."],"phonetic":"/ˈkjuːkʌmbər/","partOfSpeech":"名词"},{"plural":"","chinese":"和","english":"and","examples":["I and my friend go to school together.","Apples and bananas are my favorite fruits."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"eggplants","chinese":"茄子","english":"eggplant","examples":["My mom cooks eggplants for dinner.","Eggplants are purple vegetables."],"phonetic":"/ˈeɡplænt/","partOfSpeech":"名词"},{"plural":"","chinese":"也","english":"also","examples":["I also like playing football.","She is also a good singer."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The cat is very cute.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好吃","english":"delicious","examples":["The cake is delicious.","This soup tastes delicious."],"phonetic":"/dɪˈlɪʃəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的复数形式","并列主语与be动词的搭配","副词also的用法"],"explanations":["表示一类事物时，可数名词通常要用复数形式，cucumber和eggplant都是可数名词，变复数直接在词尾加-s，分别为cucumbers和eggplants，符合小学二年级可数名词复数的基础知识点。","当主语是由and连接的两个并列可数名词复数时，属于复数主语，对应的be动词要用are，本句中cucumbers和eggplants作为并列主语，所以be动词用are。","副词also用于表示“也”，通常放在be动词之后、实义动词之前，本句中放在be动词are之后，符合also的基础使用规则，是小学阶段需要掌握的副词用法。"]},"sentenceWithHints":"黄瓜 和 茄子 也 很 好吃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (950, '{"words":[{"plural":"vegetables","chinese":"蔬菜","english":"vegetable","examples":["I like eating vegetables.","Vegetables are good for health."],"phonetic":"/ˈvedʒtəbəl/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very happy.","The cat runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有","english":"be","examples":["You are my best friend.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"营养","english":"nutritious","examples":["Milk is nutritious.","This is a nutritious meal."],"phonetic":"/nuˈtrɪʃəs/","partOfSpeech":"形容词"}],"examPoints":{"points":["名词复数与be动词的搭配","副词修饰形容词的用法"],"explanations":["表示一类事物时，可数名词常用复数形式，本句中“蔬菜”指一类食物，所以用vegetables，对应的be动词要用复数形式are。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰nutritious，强调蔬菜营养丰富的程度。"]},"sentenceWithHints":"蔬菜 很 有 营养。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (952, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"吃","english":"eat","examples":["I eat breakfast every day.","He is eating a cake."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"","chinese":"米饭","english":"rice","examples":["I eat rice for lunch.","Rice is a kind of food."],"phonetic":"/raɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定搭配","不可数名词的用法","人称代词主格的使用"],"explanations":["like表示“喜欢”时，常见搭配为like doing sth.，表示长期的、习惯性的喜欢，本句中like eating rice就符合这个用法，表达习惯性喜欢吃米饭。","rice是不可数名词，没有复数形式，不能在后面加s或es，在句子中作宾语时直接使用原形即可。","“我”在句子中作主语，要用人称代词的主格形式I，主格代词在句中用来作动作的发出者，位于句首或谓语动词前。"]},"sentenceWithHints":"我 喜欢 吃 米饭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (953, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"也","english":"also","examples":["I also like cats.","She can also sing well."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","He likes playing football."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"吃","english":"eat","examples":["I eat rice every day.","She ate a cake yesterday."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"noodles","chinese":"面条","english":"noodle","examples":["I like eating noodles.","She cooked noodles for dinner."],"phonetic":"/ˈnuːdl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词also的用法","like的固定搭配","可数名词复数"],"explanations":["副词also表示“也”，通常放在实义动词之前，be动词、助动词之后，本句中放在实义动词like之前，符合小学阶段的用法要求。","like后可以接动名词（doing形式）表示长期的喜好，本句中like eating noodles就是“喜欢吃面条”的正确表达，是小学阶段需要掌握的固定搭配。","noodle是可数名词，通常以复数形式noodles出现，小学阶段需要掌握这类常用可数名词的复数形式变化及使用习惯。"]},"sentenceWithHints":"我 也 喜欢 吃 面条"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (954, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"还","english":"also","examples":["I also like cats.","She also plays football."],"phonetic":"/ˈɔːlsoʊ/","partOfSpeech":"副词"},{"chinese":"喜欢","english":"like","examples":["I like reading.","He likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"吃","english":"eat","examples":["I eat rice every day.","She is eating a cake."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"","chinese":"面包","english":"bread","examples":["I like eating bread.","There is some bread on the table."],"phonetic":"/bred/","partOfSpeech":"名词"}],"examPoints":{"points":["副词also的用法","like后接动词的形式","不可数名词的用法"],"explanations":["also是副词，意为“还，也”，通常放在实义动词之前，be动词、助动词之后。本句中放在实义动词like之前，符合用法规则。","like表示“喜欢”时，后面可以接动词的-ing形式，表示长期的爱好，本句中like eating bread就是这种用法，表达长期喜欢吃面包的习惯。","bread是不可数名词，没有复数形式，不能直接用a/an修饰，表达数量时需要借助量词，比如a piece of bread（一片面包），本句中直接用bread表示这类食物，符合不可数名词的使用规则。"]},"sentenceWithHints":"我 还 喜欢 吃 面包"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (955, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"喝","english":"drink","examples":["I drink water every day.","He likes drinking juice."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"","chinese":"牛奶","english":"milk","examples":["Milk is good for health.","I drink a glass of milk every morning."],"phonetic":"/mɪlk/","partOfSpeech":"名词"}],"examPoints":{"points":["like后接动名词的用法","不可数名词的用法"],"explanations":["like表示“喜欢”时，后面可以接动名词（动词-ing形式），表示长期的、习惯性的喜好，本句中like drinking milk表示习惯性喜欢喝牛奶，符合小学阶段对like用法的考查。","milk是不可数名词，没有复数形式，不能直接用a/an修饰，也不能在词尾加s/es表示复数，在句子中作宾语时直接使用原形，这是小学阶段不可数名词的基础知识点。"]},"sentenceWithHints":"我 喜欢 喝 牛奶"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (956, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"也","english":"also","examples":["I also like cats.","She also plays football."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading.","He likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"喝","english":"drink","examples":["I drink milk every day.","She drank a cup of tea."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"waters","chinese":"水","english":"water","examples":["I need some water.","The waters of the lake are clear."],"phonetic":"/ˈwɔːtər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词also的用法","like后接动名词的用法","不可数名词的使用"],"explanations":["also作为副词表示“也”，在一般现在时的句子中，通常放在实义动词之前，be动词、助动词之后，本句中放在实义动词like之前，符合小学阶段的用法要求。","like作为动词表示“喜欢”时，后面可以接动名词（动词+ing形式），表示长期的爱好，本句中like drinking water就是表达长期喜欢喝水的习惯，这是小学阶段需要掌握的like的常用搭配。","water表示“饮用水”时是不可数名词，前面不能直接加不定冠词a/an，也不能直接加基数词，表达数量时需要借助量词，比如a cup of water，本句中直接用drinking water表示“喝水”，符合不可数名词的使用规则。"]},"sentenceWithHints":"我 也 喜欢 喝 水"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (957, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"还","english":"also","examples":["I also like cats.","She also plays football."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading.","He likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"喝","english":"drink","examples":["I drink milk every day.","She is drinking water now."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"juices","chinese":"果汁","english":"juice","examples":["I like orange juice.","There are many kinds of juices in the shop."],"phonetic":"/dʒuːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词also的用法","like后接动名词的用法","不可数名词的使用"],"explanations":["also是副词，意为“还，也”，通常放在实义动词之前，be动词、助动词之后，用来补充说明额外的喜好或行为，符合小学二年级对副词基础用法的考查。","like作为动词表示“喜欢”时，后面可以接动名词（即动词的-ing形式），表示长期的喜好，这里like drinking juice表示长期喜欢喝果汁，是小学阶段需要掌握的like的常用搭配。","juice作为表示饮品的不可数名词，一般情况下没有复数形式，但若表示不同种类的果汁时可以用复数juices，本句中表示泛指的果汁，用原形即可，这是小学二年级对不可数名词基础概念的考查。"]},"sentenceWithHints":"我 还 喜欢 喝 果汁"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (958, '{"words":[{"plural":"milks","chinese":"牛奶","english":"milk","examples":["I drink milk every morning.","Milk is good for your health."],"phonetic":"/mɪlk/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有","english":"be","examples":["The apple is red.","They are my classmates."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"营养","english":"nutritious","examples":["Vegetables are nutritious.","This is a nutritious meal."],"phonetic":"/nuˈtrɪʃəs/","partOfSpeech":"形容词"}],"examPoints":{"points":["不可数名词的用法","系动词be的搭配","副词修饰形容词的用法"],"explanations":["“牛奶”对应的英文milk是不可数名词，通常不会用复数形式表示泛指，作主语时谓语动词用单数形式。","在英语中描述事物的属性时，常用“主语+be动词+形容词”的结构，本句中用is搭配不可数名词milk，连接形容词nutritious来描述牛奶的属性。","副词very用来修饰形容词nutritious，放在形容词之前，用来加强形容词的语气，表示程度很深，这是副词修饰形容词的常见用法。"]},"sentenceWithHints":"牛奶 很 有 营养"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (960, '{"words":[{"plural":"waters","chinese":"水","english":"water","examples":["We need to drink enough water every day.","The water in the lake is clean."],"phonetic":"/ˈwɔːtər/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to study hard.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"},{"plural":"","chinese":"是","english":"is","examples":["She is happy.","The cat is black."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["不可数名词的用法","系动词be的搭配","副词修饰形容词的用法"],"explanations":["“水”是不可数名词，对应的英文water作为物质名词时通常没有复数形式，表达泛指时直接使用原形，不需要加不定冠词a/an，本句中就是泛指水这种物质。","本句是主系表结构，主语water是不可数名词，属于第三人称单数范畴，所以搭配系动词is来连接主语和表语形容词important。","副词very用来修饰形容词important，用来加强形容词的语气，说明重要的程度，副词修饰形容词时通常放在形容词的前面。"]},"sentenceWithHints":"水 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (962, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不","english":"not","examples":["I do not know.","She is not tall."],"phonetic":"/nɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","He likes playing football."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"喝","english":"drink","examples":["I drink milk every day.","She is drinking water."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"colas","chinese":"可乐","english":"cola","examples":["I want a cola.","Cola is sweet."],"phonetic":"/ˈkoʊlə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的否定结构","like后接动名词的用法"],"explanations":["当主语是第一人称I时，一般现在时的否定句需要借助助动词do，结构为“I do not + 动词原形”，用来表达“我不做某事”的意思。","like后面可以接动名词（动词+ing形式），表示“喜欢做某事”，这里drink变成drinking，用来表达长期的喜好，符合小学阶段对like用法的考查要求。"]},"sentenceWithHints":"我 不 喜欢 喝 可乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (963, '{"words":[{"plural":"colas","chinese":"可乐","english":"cola","examples":["I like drinking cola.","Cola is a kind of carbonated drink."],"phonetic":"/ˈkoʊlə/","partOfSpeech":"名词"},{"chinese":"不","english":"not","examples":["I am not tired.","She does not like apples."],"phonetic":"/nɑːt/","partOfSpeech":"副词"},{"chinese":"健康","english":"healthy","examples":["Vegetables are healthy.","We should keep a healthy diet."],"phonetic":"/ˈhelθi/","partOfSpeech":"形容词"}],"examPoints":{"points":["be动词的否定形式","形容词作表语"],"explanations":["在主系表结构中，否定句需要在be动词后加not来构成，本句主语cola是第三人称单数，be动词用is，所以否定形式为is not，用来表达“不是”的含义。","形容词healthy在句中作表语，放在be动词之后，用来描述主语cola的属性，说明可乐不具备“健康”这个特性，这是主系表结构中形容词的常见用法。"]},"sentenceWithHints":"可乐 不 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (964, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"应该","english":"should","examples":["You should go to bed early.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"少","english":"less","examples":["Eat less junk food.","I have less time today."],"phonetic":"/les/","partOfSpeech":"形容词"},{"chinese":"喝","english":"drink","examples":["I drink milk every day.","She drank a cup of tea."],"phonetic":"/drɪŋk/","pastTense":"drank","thirdPerson":"drinks","partOfSpeech":"动词","pastParticiple":"drunk","presentParticiple":"drinking"},{"plural":"colas","chinese":"可乐","english":"cola","examples":["I don''t like cola.","Can I have a bottle of cola?"],"phonetic":"/ˈkoʊlə/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词should的用法","形容词less的用法","动词drink的变形"],"explanations":["should是情态动词，后接动词原形，用来表达建议、义务等，本句中用来表达建议“应该少喝”。","less是little的比较级，用来修饰不可数名词，表示“更少的”，此处用来修饰cola（不可数名词，指可乐这种饮品），表示“更少的可乐”。","drink作为动词，有不规则的过去式drank和过去分词drunk，规则变化的第三人称单数drinks和现在分词drinking，小学阶段需要掌握它的基本用法和常见变形。"]},"sentenceWithHints":"我 应该 少 喝 可乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (965, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to play outside."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats very much."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"穿","english":"wear","examples":["She wears a blue dress today.","He is wearing a hat."],"phonetic":"/wer/","pastTense":"wore","thirdPerson":"wears","partOfSpeech":"动词","pastParticiple":"worn","presentParticiple":"wearing"},{"plural":"","chinese":"红色","english":"red","examples":["The apple is red.","I have a red pen."],"phonetic":"/red/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The yellow flower is beautiful."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"clothes","chinese":"衣服","english":"clothes","examples":["I need to wash my clothes.","She has many nice clothes."],"phonetic":"/kloʊðz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","形容词作定语","名词复数"],"explanations":["like作为动词表示“喜欢”时，常用结构为like doing sth.，表示长期的、习惯性的喜好，本句中like wearing red clothes就是表达习惯性喜欢穿红色衣服。","形容词可以放在名词前面作定语，用来修饰名词，说明名词的特征，本句中red是形容词，放在clothes前面，用来描述衣服的颜色。","clothes本身就是复数名词，没有单数形式，用来泛指身上穿的各类衣物，小学阶段需要掌握这个特殊的复数名词用法。"]},"sentenceWithHints":"我 喜欢 穿 红色 的 衣服"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (966, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"也","english":"also","examples":["I also like cats.","She also plays football."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading.","He likes playing games."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"穿","english":"wear","examples":["She wears a red dress.","I like wearing hats."],"phonetic":"/wer/","pastTense":"wore","thirdPerson":"wears","partOfSpeech":"动词","pastParticiple":"worn","presentParticiple":"wearing"},{"plural":"","chinese":"蓝色","english":"blue","examples":["The sky is blue.","I have a blue pen."],"phonetic":"/bluː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["a cup of tea","the color of the flower"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"clothes","chinese":"衣服","english":"clothes","examples":["I need new clothes.","She washes her clothes every day."],"phonetic":"/kloʊðz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词also的用法","like后接动名词的用法","名词clothes的用法"],"explanations":["also是表示“也”的副词，通常放在实义动词之前，be动词、助动词之后，本句中放在实义动词like之前，符合小学阶段副词的基础使用规则。","like作为动词表示“喜欢”时，后面可以接动名词（动词+ing形式），表示喜欢做某事的习惯，本句中like wearing就是“喜欢穿”的正确表达，是小学阶段动词搭配的重要知识点。","clothes是集体名词，本身就表示复数概念，没有单数形式，用来泛指衣服，小学阶段需要掌握这个特殊的复数名词的用法，不需要在前面加不定冠词a/an。"]},"sentenceWithHints":"我 也 喜欢 穿 蓝色 的 衣服"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (967, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"穿","english":"wear","examples":["He wears a blue shirt.","I like wearing hats."],"phonetic":"/wer/","pastTense":"wore","thirdPerson":"wears","partOfSpeech":"动词","pastParticiple":"worn","presentParticiple":"wearing"},{"plural":"sports shoes","chinese":"运动鞋","english":"sports shoes","examples":["I have a pair of sports shoes.","Sports shoes are comfortable."],"phonetic":"/spɔːrts ʃuːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","名词复数","动名词作宾语"],"explanations":["like作为动词，表示“喜欢”，常见用法有like doing sth.（表示长期的、习惯性的喜欢）和like to do sth.（表示偶尔的、具体的喜欢），本句中是习惯性喜好，所以用like wearing。","表示成双成对的物品如鞋子（shoes）、袜子（socks）等，通常以复数形式出现，sports shoes是固定的复数表达，指运动鞋这类物品。","like后面可以接动名词（动词+ing形式）作宾语，表达喜欢做某事的习惯，这里wear变成wearing，符合like doing的结构要求。"]},"sentenceWithHints":"我 喜欢 穿 运动鞋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (968, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"上学","english":"to school","examples":["I walk to school.","She takes a bus to school."],"phonetic":"/tuː skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"穿","english":"wear","examples":["I wear a coat in winter.","She wears a red dress today."],"phonetic":"/wer/","pastTense":"wore","thirdPerson":"wears","partOfSpeech":"动词","pastParticiple":"worn","presentParticiple":"wearing"},{"plural":"uniforms","chinese":"校服","english":"uniform","examples":["Students must wear a uniform.","The school has new uniforms this year."],"phonetic":"/ˈjuːnɪfɔːrm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","不定冠词a的用法","目的状语的表达"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句描述“上学穿校服”这一日常习惯，主语是第一人称I，所以动词用原形wear。","不定冠词a用于辅音音素开头的可数名词单数前，uniform虽然以元音字母u开头，但发音以辅音音素/j/开头，所以前面用a。","用“to school”来表达动作的目的，说明“穿校服”的目的是去上学，这是英语中常见的目的状语表达结构。"]},"sentenceWithHints":"我 上学 穿 校服"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (969, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"穿","english":"wear","examples":["She wears a red dress.","He is wearing a hat."],"phonetic":"/wer/","pastTense":"wore","thirdPerson":"wears","partOfSpeech":"动词","pastParticiple":"worn","presentParticiple":"wearing"},{"plural":"","chinese":"舒适的","english":"comfortable","examples":["This is a comfortable chair.","I want comfortable shoes."],"phonetic":"/ˈkʌmfərtəbəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["It''s a red apple.","She is my best friend."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"clothes","chinese":"衣服","english":"clothes","examples":["I need new clothes.","These clothes are nice."],"phonetic":"/kloʊðz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","形容词修饰名词","wear的动名词形式"],"explanations":["like作为动词，表示“喜欢”，常用搭配为like doing sth.，表示长期的爱好，本句中like wearing就是这个用法，符合小学阶段对like基础搭配的考查。","形容词用来修饰名词，放在名词前面，本句中comfortable是形容词，修饰后面的名词clothes，说明衣服的特点，这是小学阶段形容词的基础用法考点。","在like doing sth.的结构中，动词需要使用动名词形式，wear的动名词是wearing，需要掌握动词变动名词的规则，一般直接在动词后加-ing。"]},"sentenceWithHints":"我 喜欢 穿 舒适 的 衣服"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (970, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like music.","There are many books on the shelf."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"漂亮的","english":"beautiful","examples":["She has a beautiful dress.","The park is beautiful in spring."],"phonetic":"/ˈbjuːtɪfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"clothes","chinese":"衣服","english":"clothes","examples":["I need to wash my clothes.","Her clothes are very stylish."],"phonetic":"/kloʊðz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词的用法","限定词many的用法","动词have的人称搭配"],"explanations":["形容词用来修饰名词，放在名词前描述名词的特征。本句中“漂亮的（beautiful）”用来修饰“衣服（clothes）”，说明衣服的外观特点。","限定词many用来修饰可数名词复数，用来表示数量多。本句中“衣服（clothes）”是可数名词复数，所以用many来修饰。","动词have在主语是第一人称I、第二人称you以及复数主语时，用原形have；当主语是第三人称单数（he/she/it等）时，要变为has。本句主语是I，所以用have。"]},"sentenceWithHints":"我 有 很多 漂亮的 衣服"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (971, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my cat."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"clothes","chinese":"衣服","english":"clothes","examples":["These clothes are new.","I need to wash my clothes."],"phonetic":"/kloʊðz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"干净","english":"clean","examples":["The room is clean.","Wash your hands to keep them clean."],"phonetic":"/kliːn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["物主代词的使用","系动词be的单复数搭配","副词修饰形容词的用法"],"explanations":["物主代词my用于表示所属关系，用来修饰名词，说明这个名词属于说话者，本句中my修饰clothes，表明是“我的”衣服。","系动词be的形式要和主语保持一致，clothes是复数名词，所以搭配are，而不是is，这是小学阶段需要掌握的be动词基本搭配规则。","副词very用来修饰形容词，放在形容词前面，用来加强形容词的语气，本句中very修饰clean，强调干净的程度。"]},"sentenceWithHints":"我的 衣服 很 干净。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (972, '{"words":[{"plural":"mothers","chinese":"妈妈","english":"mother","examples":["My mother can cook well.","His mother is a nurse."],"phonetic":"/ˈmʌðər/","partOfSpeech":"名词"},{"chinese":"帮","english":"help","examples":["I help my mom clean the room.","She helps me with my homework."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"我","english":"me","examples":["He gives me a gift.","My teacher teaches me math."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"洗","english":"wash","examples":["I wash my face every morning.","She washes her hair on weekends."],"phonetic":"/wɑːʃ/","pastTense":"washed","thirdPerson":"washes","partOfSpeech":"动词","pastParticiple":"washed","presentParticiple":"washing"},{"plural":"clothes","chinese":"衣服","english":"clothes","examples":["I need to buy new clothes.","She folds her clothes neatly."],"phonetic":"/kloʊðz/","partOfSpeech":"名词"}],"examPoints":{"points":["动词第三人称单数变化","人称代词宾格用法","固定搭配 help sb. do sth."],"explanations":["当句子主语是第三人称单数（如本句的my mother），一般现在时中谓语动词要变成第三人称单数形式。wash的第三人称单数是在词尾加-es，即washes；help的第三人称单数是helps。","人称代词分为主格和宾格，当代词在动词或介词后面作宾语时，要用宾格形式。本句中“我”作动词help的宾语，所以用宾格me，而不用主格I。","help sb. do sth.是固定搭配，表示“帮助某人做某事”，这里的动词要用原形，所以本句中“洗衣服”翻译为wash my clothes，wash用原形。"]},"sentenceWithHints":"妈妈 帮 我 洗 衣服"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (973, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"运动","english":"exercising","examples":["Exercising is good for health.","I enjoy exercising every morning."],"phonetic":"/ˈeksərsaɪzɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格用法","like后接动名词的用法"],"explanations":["人称代词I是主格形式，在句子中作主语，用来指代说话人自己，小学阶段需要掌握主格代词I, you, he, she等的基本用法。","like作为动词，表示“喜欢”时，后面可以接动名词（即动词的-ing形式），表示长期的、习惯性的喜好。本句中exercising是exercise的动名词形式，用来表示“运动”这个行为，符合小学阶段对like用法的考查要求。"]},"sentenceWithHints":"我 喜欢 运动"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (974, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"跑步","english":"running","examples":["Running is good exercise.","I enjoy running in the morning."],"phonetic":"/ˈrʌnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词like的用法","动名词作宾语"],"explanations":["like作为动词，表示“喜欢”，后可接名词、动名词或不定式，小学阶段主要掌握like + 动名词（doing）的结构，表示长期的爱好。当主语是第三人称单数时，like要变成likes。","running是动词run的动名词形式，在本句中作like的宾语，表达“喜欢跑步”这个爱好。动名词由动词原形加-ing构成，run是重读闭音节单词，变动名词时需要双写末尾的辅音字母n再加-ing。"]},"sentenceWithHints":"我 喜欢 跑步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (975, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"跳绳","english":"jump rope","examples":["I like jumping rope after school.","She jumps rope every morning."],"phonetic":"/dʒʌmp roʊp/","pastTense":"jumped rope","thirdPerson":"jumps rope","partOfSpeech":"动词短语","pastParticiple":"jumped rope","presentParticiple":"jumping rope"}],"examPoints":{"points":["like的用法","动名词作宾语","常用运动短语表达"],"explanations":["like作为动词，常见用法为like doing sth.，表示长期的、习惯性的喜欢做某事，符合小学阶段对like基础用法的考查；当主语是第三人称单数时，like要变为likes。","在like doing sth.这个结构中，动词要使用动名词形式（即动词加-ing），本句中jump变为jumping，作like的宾语，这是小学阶段动名词的基础应用考点。","“跳绳”对应的英文固定表达为jump rope（美式英语），是小学阶段需要掌握的常见运动类短语，用于日常活动相关的英语表达考查。"]},"sentenceWithHints":"我 喜欢 跳绳"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (976, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"打","english":"play","examples":["I play football every day.","He is playing games now."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"basketballs","chinese":"篮球","english":"basketball","examples":["I play basketball after school.","Basketball is my favorite sport."],"phonetic":"/ˈbæskɪtbɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定用法","球类名词的表达"],"explanations":["like后接动词有两种常见结构：like to do sth. 表示偶尔喜欢做某事，like doing sth. 表示长期的、习惯性的爱好。本句表达的是习惯性的喜好，所以用like playing的结构。","表示球类运动的名词前通常不加冠词，直接用play + 球类名词，比如play basketball、play football，这是小学阶段需要掌握的固定搭配。"]},"sentenceWithHints":"我 喜欢 打 篮球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (977, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"踢","english":"play","examples":["He plays basketball every day.","They are playing games."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"footballs","chinese":"足球","english":"football","examples":["I play football after school.","The football is under the bed."],"phonetic":"/ˈfʊtbɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定用法","人称代词作主语","球类名词的使用"],"explanations":["like后接动词的ing形式，表示“喜欢做某事”，是固定搭配，所以这里用playing而不是play。","“我”对应的英文是人称代词I，作主语时要用主格形式，在一般现在时中，主语为I时，谓语动词用原形like。","表示球类运动的名词前通常不加冠词，所以直接说play football，不需要加a或the。"]},"sentenceWithHints":"我 喜欢 踢 足球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (978, '{"words":[{"plural":"exercises","chinese":"运动","english":"exercise","examples":["I do exercise every day.","Math exercises are easy for me."],"phonetic":"/ˈeksərsaɪz/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","My mom makes delicious food."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gives me a gift.","Please help me with my homework."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"很","english":"very","examples":["She is very tall.","The cat runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"健康","english":"healthy","examples":["Eating vegetables keeps you healthy.","My grandma is healthy and strong."],"phonetic":"/ˈhelθi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作宾语补足语","不可数名词/可数名词的用法"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me healthy”就是“使我健康”的意思；当主语是第三人称单数时，make要变成makes。","在“make + 宾语 + 形容词”这个结构里，形容词放在宾语后面，用来补充说明宾语的状态，本句中healthy补充说明“我”的状态是健康的。","exercise表示“运动、锻炼”这一泛指的行为时，是不可数名词，作主语时谓语动词用第三人称单数形式；当表示具体的“练习、习题”时，是可数名词，有复数形式exercises。"]},"sentenceWithHints":"运动 让 我 很 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (980, '{"words":[{"plural":"exercises","chinese":"运动","english":"exercise","examples":["I do exercise every day.","Math exercises are easy for me."],"phonetic":"/ˈeksərsaɪz/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","The cat is very cute."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有趣","english":"interesting","examples":["The story is interesting.","Playing games is interesting."],"phonetic":"/ˈɪntrəstɪŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["不可数名词作主语的主谓一致","副词修饰形容词的用法"],"explanations":["当exercise表示“运动，锻炼”这一抽象概念时，是不可数名词，作主语时谓语动词要用第三人称单数形式，所以本句中用is。","副词very用来修饰形容词，放在形容词前面，用来加强形容词的语气，本句中very用来修饰interesting，强调有趣的程度。"]},"sentenceWithHints":"运动 很 有趣。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (981, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like reading books.","She likes cats very much."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"听","english":"listen","examples":["Listen to the teacher carefully.","He is listening to music."],"phonetic":"/ˈlɪsən/","pastTense":"listened","thirdPerson":"listens","partOfSpeech":"动词","pastParticiple":"listened","presentParticiple":"listening"},{"plural":"","chinese":"音乐","english":"music","examples":["I love music.","She plays music every day."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like doing sth. 固定搭配","listen to 固定短语","不可数名词的用法"],"explanations":["like 后接动词时，常用 like doing sth. 的结构，表示长期的、习惯性的喜好，本句中表示习惯性喜欢听音乐，所以用 listening。","listen 是不及物动词，后面接宾语时必须加介词 to，构成 listen to sth. 的固定短语，用来表达“听某物”。","music 是不可数名词，没有复数形式，前面不能直接加不定冠词 a/an，也不能直接用数词修饰，表达“一段音乐”可以用 a piece of music。"]},"sentenceWithHints":"我 喜欢 听 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (982, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"流行","english":"pop","examples":["Pop music is very popular.","She likes pop songs."],"phonetic":"/pɑːp/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"音乐","english":"music","examples":["I listen to music every day.","Music makes me happy."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称主语搭配动词原形","形容词修饰名词","不可数名词的用法"],"explanations":["当句子主语是第一人称“I（我）”时，一般现在时中后面的实义动词要用原形，本句中“喜欢”对应的英文“like”用原形即可。","形容词可以用来修饰名词，放在名词前起到描述作用，本句中“流行（pop）”是形容词，用来修饰“音乐（music）”，说明音乐的类型。","“music（音乐）”是不可数名词，没有复数形式，不能直接在后面加-s/-es，表达“音乐”这类事物时直接用原形即可。"]},"sentenceWithHints":"我 喜欢 流行 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (983, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want an apple."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"古典","english":"classical","examples":["Classical music is very beautiful.","We learned about classical art."],"phonetic":"/ˈklæsɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"音乐","english":"music","examples":["I listen to music every day.","Music makes me happy."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称主语搭配动词原形","形容词修饰名词的用法","不可数名词的使用"],"explanations":["当主语是第一人称“I（我）”时，一般现在时中后面的实义动词要用原形，本句中“like”用原形符合这个规则。","形容词可以用来修饰名词，放在名词前起到描述作用，本句中“classical（古典的）”是形容词，用来修饰“music（音乐）”，说明音乐的类型。","“music（音乐）”是不可数名词，没有复数形式，在句子中表示一类事物时直接使用原形即可，不需要加不定冠词或变为复数。"]},"sentenceWithHints":"我 喜欢 古典 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (984, '{"words":[{"plural":"musics","chinese":"音乐","english":"music","examples":["I love music.","Music can make people relaxed."],"phonetic":"/ˈmjuːzɪk/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes a cake.","The story makes me cry."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gives me a pen.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","They are happy to see you."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作宾语补足语","第三人称单数动词变化"],"explanations":["make作为使役动词，常用结构为make + 宾语 + 形容词，表示“使某人/某物处于某种状态”，本句中make me very happy就是“让我很快乐”的意思。","形容词happy在这里作宾语me的补足语，用来补充说明宾语的状态，说明“我”的状态是快乐的。","当句子主语是第三人称单数（本句中主语music是不可数名词，属于第三人称单数范畴）时，一般现在时中的动词要使用第三人称单数形式，make的第三人称单数形式是makes。"]},"sentenceWithHints":"音乐 让 我 很 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (987, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"唱","english":"sing","examples":["She sings very well.","We are singing a song."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"plural":"","chinese":"很多","english":"many","examples":["Many people like cats.","I have many books."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"songs","chinese":"歌","english":"song","examples":["This is a nice song.","We sang songs together."],"phonetic":"/sɔːŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","形容词many的用法","可数名词的复数形式"],"explanations":["情态动词can表示“能够、会”，后面要接动词原形，没有人称和数的变化，过去式为could，常用于表达能力。本句中can后接sing的原形，体现“会唱歌”的能力。","形容词many用于修饰可数名词的复数形式，用来表示数量多，通常放在可数名词复数前面。本句中many修饰songs，说明歌的数量多。","可数名词表示多个时要变成复数形式，规则名词一般在词尾加-s，“song”是规则可数名词，复数形式为“songs”，当前面有many这类表示数量多的词修饰时，可数名词必须用复数。"]},"sentenceWithHints":"我 会 唱 很多 歌"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (988, '{"words":[{"chinese":"唱","english":"sing","examples":["I sing every day.","She sang a beautiful song yesterday."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"plural":"songs","chinese":"歌","english":"song","examples":["This is a nice song.","We learned three new songs this week."],"phonetic":"/sɔːŋ/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The cat is very cute.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have","examples":["I have a pen.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"趣","english":"interesting","examples":["Reading is interesting.","This game is very interesting."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","形容词的用法","程度副词very的用法"],"explanations":["当表示“做某事”这件事本身作主语时，要把动词变成动名词形式（动词加-ing），本句中“唱歌”作为主语，所以用sing的动名词形式Singing，谓语动词用单数形式is。","interesting是形容词，用来描述事物“有趣的”，在本句中用来说明“唱歌”这件事的特点，放在be动词is后面作表语。","very是程度副词，用来修饰形容词或副词，加强语气，本句中用来修饰形容词interesting，说明有趣的程度很深。"]},"sentenceWithHints":"唱 歌 很 有 趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (990, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I can sing."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can dance."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"画","english":"draw","examples":["I draw a cat.","She draws pictures every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"flowers","chinese":"花","english":"flower","examples":["I like red flowers.","The flower is beautiful."],"phonetic":"/ˈflaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like cats and dogs.","She eats rice and vegetables."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"trees","chinese":"树","english":"tree","examples":["There are many trees in the park.","The tree is tall."],"phonetic":"/triː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","可数名词复数形式","并列连词and的用法"],"explanations":["情态动词can表示“能够、会”，后面要接动词原形，用来表达具备某种能力，本句中can后面接draw的原形，符合语法规则。","可数名词表示一类事物时，常用复数形式，规则名词变复数一般在词尾加-s，以元音字母+y结尾的直接加-s，flower和tree都是规则变化，所以复数形式是flowers和trees。","并列连词and用来连接两个并列的成分，本句中用来连接flowers和trees，表明两者都是draw的对象，起到并列连接的作用。"]},"sentenceWithHints":"我 会 画 花 和 树"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (991, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"画","english":"draw","examples":["I can draw a flower.","She draws pictures every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"cats","chinese":"猫","english":"cat","examples":["I have a cat.","Cats like fish."],"phonetic":"/kæt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"and","examples":["I like apples and bananas.","He and I are friends."],"phonetic":"/ænd/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"dogs","chinese":"狗","english":"dog","examples":["The dog is cute.","Dogs are loyal."],"phonetic":"/dɔːɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","可数名词的复数形式","并列连词and的用法"],"explanations":["情态动词can表示“能够、会”，后面要接动词原形，用来表达具备某种能力，本句中can后面接draw的原形，符合这个用法；can的过去式为could，没有现在分词和常规的过去分词变化，第三人称单数形式也保持can不变。","可数名词表示一类事物时，常用复数形式，规则的可数名词复数一般在词尾加-s，cat的复数是cats，dog的复数是dogs，本句中用复数形式表示猫和狗这两类动物。","并列连词and用来连接两个并列的成分，本句中用and连接cats和dogs，表示两种动物的并列关系，在肯定句中连接并列事物常用and。"]},"sentenceWithHints":"我 会 画 猫 和 狗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (992, '{"words":[{"chinese":"画画","english":"draw","examples":["I like to draw pictures.","She draws a cat every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"","chinese":"很","english":"very","examples":["The book is very interesting.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有趣","english":"interesting","examples":["This game is interesting.","We had an interesting trip."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","副词修饰形容词"],"explanations":["当表示“做某事”这件事本身作主语时，要把动词变成动名词形式（即动词+ing），本句中“画画”作主语，所以用 drawing，此时主语视为单数，搭配系动词 is。","副词very用来修饰形容词，放在形容词前面，用来加强形容词的语气，本句中very用来强调interesting的程度，说明“有趣”的程度很深。"]},"sentenceWithHints":"画画 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (994, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"用","english":"with","examples":["Write with a pen.","I play with my friend."],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"彩色","english":"colored","examples":["I have a colored notebook.","She likes colored balloons."],"phonetic":"/ˈkʌlərd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"pencils","chinese":"铅笔","english":"pencil","examples":["I have a blue pencil.","Please pass me the pencils."],"phonetic":"/ˈpensəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"画画","english":"draw","examples":["I draw a cat.","She draws pictures every weekend."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"}],"examPoints":{"points":["介词with的用法","可数名词复数形式","动词draw的用法"],"explanations":["介词with在这里表示“用（工具）”，用来说明做事情所使用的工具，通常放在动作之后，引出工具类名词，比如“用彩色铅笔”翻译为with colored pencils。","可数名词表示数量不止一个时，需要使用复数形式。pencil是规则可数名词，复数形式直接在词尾加-s，即pencils，这里表示不止一支彩色铅笔，所以用复数。","draw是表示“画画”的实义动词，在一般现在时中，当主语是第一人称I时，动词用原形draw；当主语是第三人称单数时，动词要变为draws。它的过去式是不规则变化drew，过去分词是drawn，现在分词是drawing。"]},"sentenceWithHints":"我 用 彩色 铅笔 画画"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (995, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"drawings","chinese":"画","english":"drawing","examples":["I like your drawing.","She has many beautiful drawings."],"phonetic":"/ˈdrɔːɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very pretty.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"漂亮","english":"beautiful","examples":["The park is beautiful.","She wears a beautiful dress."],"phonetic":"/ˈbjuːtɪfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词性物主代词的使用","可数名词复数形式","系动词be的主谓一致","副词修饰形容词的用法"],"explanations":["形容词性物主代词my用来修饰名词，表明所属关系，后面必须接名词，不能单独使用，比如my drawing表示“我的画”。","drawing是可数名词，当表示一类事物或者数量不止一个时，要使用复数形式drawings，规则可数名词变复数一般在词尾加-s。","系动词be的形式要和主语保持一致，本句主语drawings是复数，所以用are；如果主语是单数，则用is。","副词very用来修饰形容词beautiful，放在形容词前面，用来加强形容词的语气，表示“非常、很”的程度。"]},"sentenceWithHints":"我的 画 很 漂亮"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (997, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"洗","english":"wash","examples":["Wash your hands.","She washes clothes every day."],"phonetic":"/wɑːʃ/","pastTense":"washed","thirdPerson":"washes","partOfSpeech":"动词","pastParticiple":"washed","presentParticiple":"washing"},{"plural":"dishes","chinese":"碗","english":"dish","examples":["Put the dish on the table.","We need to wash the dishes."],"phonetic":"/dɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","可数名词复数的使用","实义动词在情态动词后的形式"],"explanations":["情态动词can表示“能够、会”，后接动词原形，用来表达具备某种能力，过去式为could，没有人称和数的变化，本句中用can表示“我具备洗碗的能力”。","可数名词表示泛指一类事物时，通常用复数形式，dish是可数名词，这里表示“碗”这类餐具，所以用复数dishes。","实义动词在情态动词（如can）后面必须使用原形，所以wash用原形，不需要根据主语变化形式。"]},"sentenceWithHints":"我 会 洗 碗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (998, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"扫","english":"sweep","examples":["Please sweep the floor.","She swept the room yesterday."],"phonetic":"/swiːp/","pastTense":"swept","thirdPerson":"sweeps","partOfSpeech":"动词","pastParticiple":"swept","presentParticiple":"sweeping"},{"plural":"floors","chinese":"地","english":"floor","examples":["The floor is clean.","We mop the floor every day."],"phonetic":"/flɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","固定短语sweep the floor的搭配","人称代词主格的使用"],"explanations":["情态动词can表示“能够、会”，后面要接动词原形，没有人称和数的变化，过去式为could，小学阶段主要掌握其表能力的用法，用于表达某人具备做某事的能力。","sweep the floor是固定短语，意为“扫地”，是小学阶段需要掌握的家务类常用短语，其中floor在这里特指室内的地面，前面通常加定冠词the。","人称代词主格I在句中作主语，用于指代说话人自己，在一般现在时中，当I作主语时，除了be动词用am，实义动词用原形，情态动词直接搭配使用即可。"]},"sentenceWithHints":"我 会 扫 地"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (999, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"整理","english":"tidy","examples":["Please tidy your desk.","She tidied her bedroom yesterday."],"phonetic":"/ˈtaɪdi/","pastTense":"tidied","thirdPerson":"tidies","partOfSpeech":"动词","pastParticiple":"tidied","presentParticiple":"tidying"},{"plural":"rooms","chinese":"房间","english":"room","examples":["This is my room.","There are two rooms in the house."],"phonetic":"/ruːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","实义动词tidy的用法","定冠词the的特指用法"],"explanations":["情态动词can表示“能够、会”，后面要接动词原形，没有人称和数的变化，过去式为could。本句中can后面接tidy的原形，表达“会整理”的能力。","tidy作为实义动词，意思是“整理、收拾”，是规则动词，过去式和过去分词直接加-ed，第三人称单数加-s，现在分词变y为i加-ing。在小学阶段需要掌握它表示整理物品、房间的基础用法。","定冠词the用于特指某个具体的事物，本句中the room特指说话双方都知道的那个房间，小学阶段需要掌握the用于特指的基础用法。"]},"sentenceWithHints":"我 会 整理 房间"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1000, '{"words":[{"chinese":"帮","english":"help","examples":["I help my mom cook dinner.","Can you help me carry this box?"],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"mothers","chinese":"妈妈","english":"mother","examples":["My mother loves to read.","Mother is making breakfast."],"phonetic":"/ˈmʌðər/","partOfSpeech":"名词"},{"chinese":"做","english":"do","examples":["I do my homework every day.","She does yoga in the morning."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"","chinese":"家务","english":"housework","examples":["I have to do housework after school.","Housework is everyone''s responsibility."],"phonetic":"/ˈhaʊswɜːrk/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["The cat is very cute.","She runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有趣","english":"interesting","examples":["This book is interesting.","Playing games is interesting."],"phonetic":"/ˈɪntrəstɪŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","固定搭配 help sb. with sth.","形容词作表语"],"explanations":["当表示某个动作作为主语时，需要把动词变成动名词形式（即动词+ing），本句中“帮妈妈做家务”这个动作作主语，所以用 Helping mother with housework。","help sb. with sth. 是固定搭配，意思是“帮助某人做某事”，其中sb.是帮助的对象，sth.是要做的事情，这里表示帮助妈妈做家务，符合这个搭配的用法。","形容词interesting在句中作表语，用来描述主语“帮妈妈做家务”这件事的性质，放在系动词is后面，说明这件事的特点是有趣的。"]},"sentenceWithHints":"帮 妈妈 做 家务 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1277, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my mom.","This book is for you."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","The school is big and beautiful."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"争光","english":"win honor","examples":["He wants to win honor for his team.","We will win honor for our country."],"phonetic":"/wɪn ˈɑːnər/","pastTense":"won honor","thirdPerson":"wins honor","partOfSpeech":"动词","pastParticiple":"won honor","presentParticiple":"winning honor"}],"examPoints":{"points":["一般将来时的用法","介词for的用法","动词短语win honor的识记"],"explanations":["一般将来时用来表示将要发生的动作或存在的状态，小学阶段常用“will+动词原形”的结构表达，本句中“会”体现将来的意愿，所以用will加动词短语win honor的原形。","介词for在这里用来表示动作的对象或目的，意为“为了、给”，本句中表示“为学校”争光，引出动作的受益对象。","win honor是固定动词短语，意为“争光、赢得荣誉”，是小学阶段需要识记的实用短语，用于表达为集体获取荣誉的场景。"]},"sentenceWithHints":"我 会 为 学校 争光"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1278, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"能","english":"can","examples":["I can swim fast.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"流利地","english":"fluently","examples":["She speaks French fluently.","He can write English fluently."],"phonetic":"/ˈfluːəntli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"使用","english":"use","examples":["We use pens to write.","He uses a computer for work."],"phonetic":"/juːz/","pastTense":"used","thirdPerson":"uses","partOfSpeech":"动词","pastParticiple":"used","presentParticiple":"using"},{"plural":"","chinese":"英语","english":"English","examples":["I learn English every day.","English is a global language."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","副词在句子中的位置","及物动词use的用法"],"explanations":["情态动词can表示“能够、可以”，后接动词原形，没有人称和数的变化，过去式为could，用于表达过去的能力或委婉请求。本句中can后接动词原形use，符合语法规则。","副词fluently是方式副词，用来修饰动词use，在英语中方式副词通常放在实义动词之后，或者句末，本句中放在句末，符合英语语序习惯。","use作为及物动词，后面可以直接接宾语，本句中use后接名词English作宾语，构成“use+语言”的结构，表示“使用某种语言”，是初中阶段需要掌握的常用动词搭配。"]},"sentenceWithHints":"我 能 流利地 使用 英语"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1279, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I can speak English."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"能","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"理解","english":"understand","examples":["I can understand your feelings.","He doesn''t understand the question."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"","chinese":"复杂的","english":"complex","examples":["This is a complex problem.","She explained the complex theory clearly."],"phonetic":"/kəmˈpleks/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["It''s a beautiful flower.","The red apple is mine."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"articles","chinese":"文章","english":"article","examples":["I read an interesting article.","She wrote many articles for the magazine."],"phonetic":"/ˈɑːrtɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","形容词作定语","可数名词复数形式"],"explanations":["情态动词can表示“能够、可以”，后接动词原形，用来表达具备某种能力。其过去式为could，没有人称和数的变化，本句中用来表达“具备理解文章的能力”。","形容词complex在句中作定语，修饰后面的名词articles，放在名词之前，用来描述文章的属性“复杂的”，这是形容词修饰名词的常见用法。","article是可数名词，句中没有特指某一篇文章，所以用复数形式articles表示泛指一类事物，可数名词复数形式通常在词尾加-s。"]},"sentenceWithHints":"我 能 理解 复杂 的 文章"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1280, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"能","english":"can","examples":["I can swim fast.","She can speak English well."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"写","english":"write","examples":["I write a diary every day.","She wrote a letter to her pen pal."],"phonetic":"/raɪt/","pastTense":"wrote","thirdPerson":"writes","partOfSpeech":"动词","pastParticiple":"written","presentParticiple":"writing"},{"chinese":"漂亮的","english":"beautiful","examples":["She has beautiful eyes.","This is a beautiful flower."],"phonetic":"/ˈbjuːtɪfəl/","partOfSpeech":"形容词"},{"chinese":"的","english":"of","examples":["the color of the sky","a friend of mine"],"phonetic":"/əv/","partOfSpeech":"助词"},{"plural":"essays","chinese":"作文","english":"essay","examples":["I have to write an essay for homework.","She got an A on her history essay."],"phonetic":"/ˈeseɪ/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词can的用法","形容词作定语","可数名词复数"],"explanations":["情态动词can后接动词原形，用来表示具备某种能力，本句中表示“具备写作的能力”，后面直接跟动词write的原形。","形容词beautiful用来修饰名词essay，放在名词前作定语，用来描述作文的特征，符合英语中形容词修饰名词的基本语序。","essay是可数名词，此处没有特指某一篇作文，所以用复数形式essays表示泛指这类文体，可数名词泛指时常用复数形式。"]},"sentenceWithHints":"我 能 写 漂亮 的 作文"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1281, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"能","english":"can","examples":["I can swim fast.","She can speak English well."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"with","examples":["I play football with my friends.","She lives with her parents."],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"foreigners","chinese":"外国人","english":"foreigner","examples":["He made friends with a foreigner.","Many foreigners visit China every year."],"phonetic":"/ˈfɔːrənər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"交流","english":"communicate","examples":["We should communicate more with our parents.","They communicate by email every week."],"phonetic":"/kəˈmjuːnɪkeɪt/","pastTense":"communicated","thirdPerson":"communicates","partOfSpeech":"动词","pastParticiple":"communicated","presentParticiple":"communicating"}],"examPoints":{"points":["情态动词can的用法","固定搭配communicate with","可数名词复数形式"],"explanations":["情态动词can表示“能够、可以”，后接动词原形，没有人称和数的变化，过去式为could，用于表达过去的能力或委婉请求。本句中用can表示现在具备和外国人交流的能力，后面直接接动词原形communicate。","communicate是不及物动词，表达“与某人交流”时需要搭配介词with，构成固定搭配communicate with sb.，这是初中阶段需要掌握的常用动词短语。","foreigner是可数名词，此处表示一类人，所以使用复数形式foreigners，可数名词变复数时，以-er结尾的规则名词直接加-s即可。"]},"sentenceWithHints":"我 能 和 外国人 交流"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1282, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"能","english":"can","examples":["I can swim fast.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"看懂","english":"understand","examples":["I can understand your feelings.","Do you understand this math problem?"],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"","chinese":"英文","english":"English","examples":["I like English songs.","She is good at English."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"movies","chinese":"电影","english":"movie","examples":["I watch a movie every weekend.","These movies are very interesting."],"phonetic":"/ˈmuːvi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","及物动词understand的用法","可数名词复数的使用"],"explanations":["情态动词can表示“能够、可以”，后接动词原形，没有人称和数的变化，过去式为could，用于表达过去的能力。本句中can后接understand原形，表达“能够看懂”的能力。","understand是及物动词，后面可以直接接宾语，意为“理解、看懂”，它的过去式和过去分词是不规则变形understood，第三人称单数形式为understands，现在分词为understanding。","movie是可数名词，当表示一类事物时，常用复数形式movies，不需要加不定冠词，此处用English movies表示“英文电影”这一类事物。"]},"sentenceWithHints":"我 能 看懂 英文 电影"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1283, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I can speak English."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"能","english":"can","examples":["I can swim fast.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"阅读","english":"read","examples":["I read a book every night.","He is reading a newspaper now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"","chinese":"英文","english":"English","examples":["I study English grammar.","This is an English dictionary."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书籍","english":"book","examples":["I have many story books.","She bought three books yesterday."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","动词原形在情态动词后的使用","可数名词复数形式"],"explanations":["情态动词can用于表示能力、许可等，后接动词原形，其过去式为could，没有人称和数的变化，本句中用来表达“具备阅读英文书籍的能力”。","情态动词（如can、may、must等）后面必须接动词原形，不能接动词的第三人称单数、现在分词等形式，所以本句中can后面使用read的原形。","可数名词表示泛指一类事物时，常用复数形式。book是可数名词，此处泛指英文书籍这一类事物，所以使用其复数形式books，规则可数名词复数一般在词尾加-s。"]},"sentenceWithHints":"我 能 阅读 英文 书籍"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1284, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"英语","english":"English","examples":["I like English very much.","She is good at English."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"levels","chinese":"水平","english":"level","examples":["His math level is excellent.","We need to improve our skill levels."],"phonetic":"/ˈlevl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The movie is very interesting."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"高","english":"high","examples":["The mountain is high.","He has a high score in the exam."],"phonetic":"/haɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["The sky is blue.","My father is a doctor."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的用法","形容词性物主代词的使用","系动词be的搭配"],"explanations":["形容词用来修饰名词或代词，描述人或事物的特征。本句中“high”作为形容词，用来描述“English level”的状态，在句中作表语，放在系动词is之后。","形容词性物主代词“my”用来修饰后面的名词短语“English level”，表示所属关系，说明是“我的”英语水平，这类代词不能单独使用，必须和名词连用。","系动词be（am/is/are）用来连接主语和表语，说明主语的身份、状态或特征。本句主语“my English level”是单数名词短语，所以搭配系动词is，构成主系表结构表达主语的状态。"]},"sentenceWithHints":"我的 英语 水平 很 高"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1285, '{"words":[{"plural":"","chinese":"英语","english":"English","examples":["English is my favorite subject.","She speaks English fluently."],"phonetic":"/ˈɪŋɡlɪʃ/","partOfSpeech":"名词"},{"chinese":"让","english":"show","examples":["He showed me his new bike.","The map shows us the way to the park."],"phonetic":"/ʃoʊ/","pastTense":"showed","thirdPerson":"shows","partOfSpeech":"动词","pastParticiple":"shown/showed","presentParticiple":"showing"},{"chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"看到","english":"see","examples":["I can see a bird in the tree.","She saw a movie yesterday."],"phonetic":"/siː/","pastTense":"saw","thirdPerson":"sees","partOfSpeech":"动词","pastParticiple":"seen","presentParticiple":"seeing"},{"chinese":"了","english":"","examples":["I finished my homework.","She ate an apple."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"更","english":"more","examples":["She is more beautiful than before.","I need more time to finish it."],"phonetic":"/mɔːr/","partOfSpeech":"副词"},{"chinese":"大","english":"big","examples":["This is a big house.","He has a big dream."],"phonetic":"/bɪɡ/","partOfSpeech":"形容词"},{"chinese":"的","english":"","examples":["The color of the sky is blue.","This is my mother''s bag."],"phonetic":"","partOfSpeech":"助词"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"}],"examPoints":{"points":["动词的过去式用法","形容词比较级的构成与用法","双宾语结构"],"explanations":["本句参考翻译使用了一般过去时，动词show的过去式是showed，see的过去式是saw，一般过去时用于描述过去发生的动作或存在的状态，符合语境中“已经看到了更大的世界”这一完成的动作。","形容词big的比较级有两种表达，一种是直接变形为bigger，另一种是用more+原级，此处bigger更常用，比较级用于两者之间的对比，这里指和之前的认知相比，世界的范围更大。","动词show可以接双宾语结构“show sb. sth.”，表示“向某人展示某物”，在本句中“showed me a bigger world”就是这一结构，其中me是间接宾语，a bigger world是直接宾语，这是初中阶段需要掌握的常用动词搭配结构。"]},"sentenceWithHints":"英语 让 我 看到 了 更 大 的 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1286, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"学习","english":"learn","examples":["I learn English every day.","He has learned a lot."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"英语","english":"English","examples":["I speak English.","English is an important language."],"phonetic":"/ˈɪŋɡlɪʃ/","partOfSpeech":"名词"}],"examPoints":{"points":["like的用法","动名词作宾语"],"explanations":["like作为动词，表示“喜欢”，常见用法有like doing sth.（表示长期的、习惯性的喜欢）和like to do sth.（表示偶尔的、具体的喜欢）。本句表达的是长期的喜好，所以用like learning。","learn是动词，在like后面需要用动名词形式（learning）作宾语，动名词由动词原形加-ing构成，一般情况下直接加-ing即可。"]},"sentenceWithHints":"我 喜欢 学习 英语"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1287, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"继续","english":"continue","examples":["He will continue his study abroad.","We must continue working hard."],"phonetic":"/kənˈtɪnjuː/","pastTense":"continued","thirdPerson":"continues","partOfSpeech":"动词","pastParticiple":"continued","presentParticiple":"continuing"},{"chinese":"提高","english":"improve","examples":["I want to improve my math skills.","Her health has improved a lot."],"phonetic":"/ɪmˈpruːv/","pastTense":"improved","thirdPerson":"improves","partOfSpeech":"动词","pastParticiple":"improved","presentParticiple":"improving"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"英语","english":"English","examples":["I learn English every day.","Her English is very fluent."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","continue的固定搭配","形容词性物主代词的用法"],"explanations":["一般将来时表示将要发生的动作或存在的状态，常用结构为“will + 动词原形”，本句中用“will continue”表达“将会继续”的将来动作，符合初中一年级对一般将来时基础用法的考查要求。","continue作为动词，常见固定搭配有“continue to do sth.”和“continue doing sth.”，前者表示继续做另一件事，后者表示继续做同一件事，本句中使用“continue to improve”，考查该动词后接不定式的用法。","形容词性物主代词“my”用来修饰名词，放在名词前表示所属关系，本句中“my English”表示“我的英语”，考查初中阶段对物主代词分类及基础用法的掌握。"]},"sentenceWithHints":"我 会 继续 提高 我的 英语"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1288, '{"words":[{"plural":"maths","chinese":"数学","english":"math","examples":["Math is my favorite subject.","I''m good at math."],"phonetic":"/mæθ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is cute."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"一","english":"a","examples":["I have a pen.","He is a student."],"phonetic":"/ə/","partOfSpeech":"冠词"},{"chinese":"门","english":"","examples":["一门功课","一门技术"],"phonetic":"","partOfSpeech":"量词"},{"chinese":"很","english":"very","examples":["She is very tall.","This book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有用","english":"useful","examples":["This tool is very useful.","She gave me some useful advice."],"phonetic":"/ˈjuːsfəl/","partOfSpeech":"形容词"},{"chinese":"的","english":"","examples":["红色的花","可爱的猫"],"phonetic":"","partOfSpeech":"助词"},{"plural":"subjects","chinese":"学科","english":"subject","examples":["We have six subjects this term.","What''s your favorite subject?"],"phonetic":"/ˈsʌbdʒekt/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","不定冠词a的用法","副词修饰形容词的用法"],"explanations":["be动词有am、is、are三种形式，当主语是第三人称单数时，be动词用is。本句主语math是第三人称单数，因此使用is。","不定冠词a用于辅音音素开头的可数名词单数前，subject是以辅音音素开头的可数名词单数，所以前面用a；中文里的量词“门”在英文中不需要直接翻译，英文通过不定冠词体现泛指的单数概念。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰useful，强调学科的有用程度。"]},"sentenceWithHints":"数学 是 一 门 很 有用 的 学科"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1289, '{"words":[{"plural":"","chinese":"数学","english":"math","examples":["Math is my favorite subject.","I''m good at math."],"phonetic":"/mæθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"帮助","english":"help","examples":["She helps me with my homework.","We need to help the poor."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"","chinese":"我们","english":"us","examples":["He told us a story.","Please give us some water."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"解决","english":"solve","examples":["Can you solve this problem?","We need to solve the issue quickly."],"phonetic":"/sɑːlv/","pastTense":"solved","thirdPerson":"solves","partOfSpeech":"动词","pastParticiple":"solved","presentParticiple":"solving"},{"plural":"","chinese":"实际","english":"practical","examples":["This is a practical idea.","She has practical experience."],"phonetic":"/ˈpræktɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"problems","chinese":"问题","english":"problem","examples":["I have a problem to ask you.","We solved many problems today."],"phonetic":"/ˈprɑːbləm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["help的固定用法","动词第三人称单数变化","可数名词复数变化"],"explanations":["help作为动词，常见固定用法为help sb. (to) do sth.，表示“帮助某人做某事”，其中不定式符号to可以省略，本句中help us solve就是使用了这个结构。","当主语是第三人称单数（本句中主语math是单数不可数名词，属于第三人称单数范畴）时，一般现在时的动词要使用第三人称单数形式，规则动词通常在词尾加-s，help的第三人称单数形式是helps。","可数名词表示泛指的一类事物时，通常使用复数形式。problem是可数名词，本句中表示泛指的实际问题，所以使用其复数形式problems，规则可数名词变复数一般在词尾加-s。"]},"sentenceWithHints":"数学 帮助 我们 解决 实际 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1290, '{"words":[{"plural":"maths","chinese":"数学","english":"math","examples":["Math is my favorite subject.","I need to study math for the exam."],"phonetic":"/mæθ/","partOfSpeech":"名词"},{"chinese":"培养","english":"cultivate","examples":["Reading can cultivate your imagination.","We should cultivate good habits from childhood."],"phonetic":"/ˈkʌltəveɪt/","pastTense":"cultivated","thirdPerson":"cultivates","partOfSpeech":"动词","pastParticiple":"cultivated","presentParticiple":"cultivating"},{"chinese":"逻辑","english":"logical","examples":["He has a very logical mind.","You need to give a logical explanation."],"phonetic":"/ˈlɑːdʒɪkəl/","partOfSpeech":"形容词"},{"plural":"thinkings","chinese":"思维","english":"thinking","examples":["Critical thinking is important for problem-solving.","His thinking is very creative."],"phonetic":"/ˈθɪŋkɪŋ/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词作主语的主谓一致","形容词作定语修饰名词","动词第三人称单数形式"],"explanations":["math（数学）属于学科类不可数名词，作主语时视为第三人称单数，因此谓语动词需要使用第三人称单数形式。","形容词logical用来修饰名词thinking，放在名词前作定语，用于说明thinking的属性，这是英语中形容词修饰名词的常见用法。","当主语是第三人称单数（本句中math为第三人称单数主语），一般现在时的谓语动词要使用第三人称单数形式，cultivate的第三人称单数形式是cultivates，规则为在动词原形后加-s。"]},"sentenceWithHints":"数学 培养 逻辑 思维"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1291, '{"words":[{"plural":"maths","chinese":"数学","english":"math","examples":["Math is my favorite subject.","I''m good at math."],"phonetic":"/mæθ/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"抽象","english":"abstract","examples":["Abstract art is hard to understand.","This is an abstract concept."],"phonetic":"/æbˈstrækt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"但是","english":"but","examples":["I''m tired but happy.","She is short but strong."],"phonetic":"/bʌt/","pastTense":"","thirdPerson":"","partOfSpeech":"连词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有趣","english":"interesting","examples":["This book is interesting.","We had an interesting talk."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词作表语的用法","转折连词but的用法","程度副词very修饰形容词的用法"],"explanations":["在主系表结构中，形容词可以放在系动词（如本句的is）之后作表语，用来描述主语的特征，本句中abstract和interesting分别描述math的特点。","连词but用来连接两个语义转折的分句或形容词，本句中用but连接“抽象”和“有趣”两个带有转折关系的形容词，体现语义上的反差。","程度副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very分别修饰abstract和interesting，强调抽象和有趣的程度。"]},"sentenceWithHints":"数学 很 抽象 但是 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1292, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes listening to music."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"解决","english":"solve","examples":["He can solve this problem easily.","We need to solve the problem as soon as possible."],"phonetic":"/sɑːlv/","pastTense":"solved","thirdPerson":"solves","partOfSpeech":"动词","pastParticiple":"solved","presentParticiple":"solving"},{"plural":"","chinese":"数学","english":"math","examples":["I am good at math.","Math is my favorite subject."],"phonetic":"/mæθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"problems","chinese":"问题","english":"problem","examples":["There are many problems to deal with.","Can you help me with this problem?"],"phonetic":"/ˈprɑːbləm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词复数","动名词作宾语"],"explanations":["like作为动词表示“喜欢”时，常见用法有like doing sth.（表示长期的、习惯性的喜欢）和like to do sth.（表示偶尔的、具体的喜欢），本句描述的是长期的喜好，所以用like doing sth.的结构。","problem是可数名词，当表示一类事物或多个事物时，需要使用复数形式，规则变化直接在词尾加-s，所以“问题”翻译为problems。","在like等表示喜好的动词后面，动词需要变为动名词形式（即动词+ing）来作宾语，solve的动名词形式是solving，这是初中阶段需要掌握的非谓语动词基本用法。"]},"sentenceWithHints":"我 喜欢 解决 数学 问题"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1293, '{"words":[{"plural":"","chinese":"数学","english":"math","examples":["Math is my favorite subject.","I''m good at math."],"phonetic":"/mæθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"让","english":"make","examples":["My mom makes delicious food.","He made a mistake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"思考","english":"think","examples":["I think you are right.","She is thinking about the problem."],"phonetic":"/θɪŋk/","pastTense":"thought","thirdPerson":"thinks","partOfSpeech":"动词","pastParticiple":"thought","presentParticiple":"thinking"}],"examPoints":{"points":["使役动词make的用法","主谓一致","人称代词的宾格形式"],"explanations":["make作为使役动词，常用结构为make sb. do sth.，表示“让某人做某事”，在这个结构中后面的动词要用原形，本句中make me think就符合这个用法，让我思考。","本句主语math是不可数名词，作主语时谓语动词要用第三人称单数形式，所以make变为makes，这是主谓一致的规则，即主语为第三人称单数时，一般现在时的谓语动词要使用相应的第三人称单数形式。","“我”在本句中作make的宾语，所以要使用人称代词的宾格形式me，人称代词分为主格和宾格，主格作主语，宾格作宾语，在动词或介词后面要使用宾格形式。"]},"sentenceWithHints":"数学 让 我 思考"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1294, '{"words":[{"plural":"maths","chinese":"数学","english":"math","examples":["Math is my favorite subject.","I''m good at math."],"phonetic":"/mæθ/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","The movie is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有挑战性","english":"challenging","examples":["This game is challenging.","Learning a new language is challenging."],"phonetic":"/ˈtʃælɪndʒɪŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["系动词be的用法","形容词作表语","副词修饰形容词"],"explanations":["当描述事物的性质、状态时，常用“主语+be动词+表语”的结构。本句主语math是第三人称单数，所以be动词用is。","形容词challenging在句中作表语，用来描述主语math的性质，表示“具有挑战性的”，说明数学这门学科的特点。","副词very用来修饰形容词challenging，用来加强形容词的语气，程度上表示“非常、很”，体现出数学挑战性的程度。"]},"sentenceWithHints":"数学 很 有挑战性。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1295, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing basketball."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"这种","english":"this","examples":["This book is mine.","I want this cup."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"challenges","chinese":"挑战","english":"challenge","examples":["It''s a big challenge for me.","We face many challenges every day."],"phonetic":"/ˈtʃælɪndʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","实义动词like的用法","指示代词this的用法"],"explanations":["人称代词I是第一人称主格，在句子中作主语，用于指代说话人自身，在一般现在时中，当主语为I时，后面的实义动词用原形。","like作为实义动词，意为“喜欢”，后可接名词、动名词或不定式，在一般现在时中，主语为第三人称单数时，like要变为likes，本句主语为I，所以用原形like。","指示代词this用于指代单数的、距离说话人较近的人或事物，后面接可数名词单数或不可数名词，本句中this用来修饰单数名词challenge，明确指代的是特定的某个挑战。"]},"sentenceWithHints":"我 喜欢 这种 挑战"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1296, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"努力","english":"hard","examples":["He works hard every day.","She studies hard to get good grades."],"phonetic":"/hɑːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"学习","english":"study","examples":["I study English every night.","She is studying for the exam."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"","chinese":"数学","english":"math","examples":["My favorite subject is math.","I need to practice math problems."],"phonetic":"/mæθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","副词在句子中的位置","学科类名词的用法"],"explanations":["一般将来时可以用“will + 动词原形”结构表示将来要发生的动作或存在的状态，本句中“会努力学习”是将来的计划，所以用“will study”来表达。","当hard作为副词表示“努力地”时，通常放在实义动词之后，本句中放在study之后，符合英语中副词修饰实义动词的位置规则。","math是表示学科的不可数名词，这类名词一般没有复数形式，也不需要在前面加不定冠词a/an，直接使用即可，比如“study math”“learn English”都是这类用法。"]},"sentenceWithHints":"我 会 努力 学习 数学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1297, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"提高","english":"improve","examples":["You need to improve your writing skills.","Her health is improving day by day."],"phonetic":"/ɪmˈpruːv/","pastTense":"improved","thirdPerson":"improves","partOfSpeech":"动词","pastParticiple":"improved","presentParticiple":"improving"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my new schoolbag."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"maths","chinese":"数学","english":"math","examples":["I am good at math.","We have math class every Monday."],"phonetic":"/mæθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"abilities","chinese":"能力","english":"ability","examples":["He has the ability to speak three languages.","Reading can improve your language ability."],"phonetic":"/əˈbɪləti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的基本结构","名词所有格/形容词性物主代词的用法","及物动词improve的用法"],"explanations":["一般将来时表示将来要发生的动作或存在的状态，初中阶段常见的结构为“will + 动词原形”，本句中“会提高”用“will improve”来表达，符合该结构，用于表达未来的计划或打算。","形容词性物主代词“我的（my）”用来修饰后面的名词短语“数学能力（math ability）”，表明所属关系，在英语中形容词性物主代词不能单独使用，必须后接名词，这是初中阶段代词用法的重要考点。","improve作为及物动词，后面可以直接接宾语，本句中“improve my math ability”就是“improve + 名词短语”的结构，用来表示“提升某方面的能力/事物”，是初中阶段需要掌握的常用及物动词用法。"]},"sentenceWithHints":"我 会 提高 我的 数学 能力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1298, '{"words":[{"plural":"","chinese":"语文","english":"Chinese","examples":["Chinese is my favorite subject.","She is good at Chinese."],"phonetic":"/ˌtʃaɪˈniːz/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["He is a doctor.","The cat is cute."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我们","english":"our","examples":["Our classroom is big.","This is our new house."],"phonetic":"/ˈaʊər/","partOfSpeech":"代词"},{"chinese":"的","english":"","examples":["This is my father''s car.","The color of the flower is red."],"phonetic":"","partOfSpeech":"助词"},{"plural":"native languages","chinese":"母语","english":"native language","examples":["Chinese is my native language.","Many people have more than one native language."],"phonetic":"/ˈneɪtɪv ˈlæŋɡwɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","物主代词的使用","专有名词的大写规则"],"explanations":["系动词be有am、is、are三种形式，当主语是单数名词或不可数名词时，be动词用is。本句主语Chinese是单数概念的学科名词，因此使用is。","our是形容词性物主代词，后面必须接名词，用来表示所属关系，本句中our用来修饰native language，表明是“我们的”母语。","表示语言的专有名词首字母需要大写，比如Chinese、English等，在本句中“语文”对应的English是Chinese，需要大写首字母，这是初中阶段专有名词拼写的基础考点。"]},"sentenceWithHints":"语文 是 我们 的 母语"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1299, '{"words":[{"plural":"","chinese":"语文","english":"Chinese","examples":["I''m good at Chinese.","Chinese is my favorite subject."],"phonetic":"/ˌtʃaɪˈniːz/","partOfSpeech":"名词"},{"chinese":"让","english":"help","examples":["My mom helps me with homework.","This book helps you learn English."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"我们","english":"us","examples":["He gave us some gifts.","Please wait for us."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"了解","english":"understand","examples":["I understand your feelings.","She doesn''t understand the question."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"chinese":"中华","english":"Chinese","examples":["Chinese food is delicious.","We love Chinese festivals."],"phonetic":"/ˌtʃaɪˈniːz/","partOfSpeech":"形容词"},{"plural":"cultures","chinese":"文化","english":"culture","examples":["We should respect different cultures.","This country has a long history and rich culture."],"phonetic":"/ˈkʌltʃər/","partOfSpeech":"名词"}],"examPoints":{"points":["动词 help 的用法","第三人称单数谓语动词变化","专有名词及名词短语的表达"],"explanations":["help 作为动词常见用法为 help sb. (to) do sth.，其中不定式符号 to 可以省略，本句中 help us understand 就是该结构的体现，意为“帮助某人做某事”。","当句子主语是第三人称单数（本句中主语 Chinese 表示学科，属于第三人称单数概念）时，一般现在时的谓语动词要使用第三人称单数形式，help 的第三人称单数形式是 helps。","“中华文化”对应的英文是 Chinese culture，其中 Chinese 作为形容词修饰名词 culture，这类由形容词加普通名词构成的专有名词短语，首字母无需全部大写，仅Chinese首字母大写；另外表示学科的 Chinese 首字母也需要大写。"]},"sentenceWithHints":"语文 让 我们 了解 中华 文化"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1300, '{"words":[{"plural":"","chinese":"语文","english":"Chinese","examples":["I like Chinese very much.","Chinese is my favorite subject."],"phonetic":"/ˌtʃaɪˈniːz/","partOfSpeech":"名词"},{"chinese":"培养","english":"cultivate","examples":["Reading can cultivate your taste.","Parents should cultivate children''s independence."],"phonetic":"/ˈkʌltəveɪt/","pastTense":"cultivated","thirdPerson":"cultivates","partOfSpeech":"动词","pastParticiple":"cultivated","presentParticiple":"cultivating"},{"chinese":"我们","english":"our","examples":["Our classroom is clean.","This is our new teacher."],"phonetic":"/ˈaʊər/","partOfSpeech":"代词"},{"chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the flower is red."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"表达","english":"expressive","examples":["She has expressive eyes.","His painting is highly expressive."],"phonetic":"/ɪkˈspresɪv/","partOfSpeech":"形容词"},{"plural":"abilities","chinese":"能力","english":"ability","examples":["He has the ability to solve problems.","We should develop our reading ability."],"phonetic":"/əˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["动词第三人称单数变化","形容词作定语","名词所有格/所属关系表达"],"explanations":["当主语是第三人称单数（本句中Chinese作为学科名词，属于第三人称单数）时，一般现在时的动词要使用第三人称单数形式。cultivate的第三人称单数是在词尾加-s，即cultivates。","形容词可以用来修饰名词，放在名词前作定语。本句中expressive（表达的）用来修饰ability（能力），构成expressive ability（表达能力），清晰说明能力的类型。","中文中用助词“的”表达所属关系，在英文中对应的常用表达是形容词性物主代词+名词，本句中“我们的表达能力”翻译为our expressive ability，用our体现所属关系，符合英文的表达逻辑。"]},"sentenceWithHints":"语文 培养 我们 的 表达 能力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1301, '{"words":[{"plural":"","chinese":"语文","english":"Chinese","examples":["I like Chinese very much.","Chinese is my favorite subject."],"phonetic":"/ˌtʃaɪˈniːz/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some water."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"更好地","english":"better","examples":["You can do better next time.","She sings better than me."],"phonetic":"/ˈbetər/","partOfSpeech":"副词"},{"chinese":"沟通","english":"communicate","examples":["We need to communicate more often.","She communicates well with others."],"phonetic":"/kəˈmjuːnɪkeɪt/","pastTense":"communicated","thirdPerson":"communicates","partOfSpeech":"动词","pastParticiple":"communicated","presentParticiple":"communicating"}],"examPoints":{"points":["使役动词let的用法","副词的比较级","动词第三人称单数变化"],"explanations":["使役动词let后接宾语（人称代词宾格形式）+不带to的动词不定式，结构为let sb. do sth.，表示“让某人做某事”，本句中let us communicate符合这个结构。","better是副词well的比较级，用来修饰动词communicate，表示“更好地沟通”，用于强调沟通的程度比之前更优。","当主语是第三人称单数（本句中主语Chinese表示学科，属于第三人称单数）时，谓语动词要使用第三人称单数形式，let的第三人称单数是lets。"]},"sentenceWithHints":"语文 让 我们 更好地 沟通"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1302, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to be a doctor."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes listening to music."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"读","english":"read","examples":["I read a book every night.","He is reading a newspaper now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"","chinese":"中文","english":"Chinese","examples":["I can speak Chinese.","This is a Chinese dictionary."],"phonetic":"/ˌtʃaɪˈniːz/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"articles","chinese":"文章","english":"article","examples":["She wrote an article about animals.","I read many interesting articles."],"phonetic":"/ˈɑːrtɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词复数","动名词作宾语"],"explanations":["like作为动词表示“喜欢”时，常见用法有like to do sth.（表示偶尔或具体的喜欢）和like doing sth.（表示长期的、习惯性的喜欢），本句中用like reading表示习惯性的爱好。","article是可数名词，当表示泛指的一类事物时，常用复数形式articles，前面无需加定冠词the。","在like等表示喜好的动词后面，动词需要用动名词形式（即动词+ing）作宾语，read的动名词形式是reading，这是初中阶段需要掌握的非谓语动词基础用法。"]},"sentenceWithHints":"我 喜欢 读 中文 文章"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1303, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes listening to music."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"写","english":"write","examples":["I write a diary every day.","He wrote a letter to his pen pal."],"phonetic":"/raɪt/","pastTense":"wrote","thirdPerson":"writes","partOfSpeech":"动词","pastParticiple":"written","presentParticiple":"writing"},{"plural":"essays","chinese":"作文","english":"essay","examples":["She wrote an essay about her hometown.","We need to finish the essay this week."],"phonetic":"/ˈeseɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词复数形式"],"explanations":["like作为动词表示“喜欢”时，常见用法有like doing sth.和like to do sth.，其中like doing sth.表示长期的、习惯性的喜好，本句表达的是习惯性的爱好，所以用like writing。","essay是可数名词，当表示一类事物且没有明确数量限定的时候，通常用复数形式essays，泛指各类作文。"]},"sentenceWithHints":"我 喜欢 写 作文"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1304, '{"words":[{"plural":"","chinese":"语文","english":"Chinese","examples":["I love learning Chinese.","Chinese is a beautiful language."],"phonetic":"/ˌtʃaɪˈniːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我","english":"me","examples":["He gave me a gift.","Please pass me the pen."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"更","english":"better","examples":["She sings better than me.","I feel better today."],"phonetic":"/ˈbetər/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"be good at","examples":["He is good at playing basketball.","She is good at drawing."],"phonetic":"/biː ɡʊd æt/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"chinese":"表达","english":"express","examples":["I can''t express my feelings clearly.","He expressed his thanks to us."],"phonetic":"/ɪkˈspres/","pastTense":"expressed","thirdPerson":"expresses","partOfSpeech":"动词","pastParticiple":"expressed","presentParticiple":"expressing"}],"examPoints":{"points":["使役动词make的用法","固定搭配be good at的变形使用","动名词的用法"],"explanations":["make作为使役动词，常见结构为make sb.+形容词/介词短语，表示“使某人处于某种状态”。本句中主语Chinese是第三人称单数，所以make用第三人称单数形式makes。","be good at是固定搭配，意为“擅长……”，本句中要表达“更擅长”，所以将good变为比较级better，结构变为be better at，在make的结构中省略be动词，直接用better at。","介词at后面接动词时，动词要变为动名词形式（即动词加-ing），所以express要变为expressing，这是介词后接动词的固定规则。"]},"sentenceWithHints":"语文 让 我 更 会 表达"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1305, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing basketball."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"语文","english":"Chinese","examples":["I am good at Chinese.","We have Chinese class every day."],"phonetic":"/ˌtʃaɪˈniːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","学科类名词的用法"],"explanations":["一般将来时可以用“will + 动词原形”的结构来表达，表示将来要发生的动作或存在的状态。本句中“会热爱”表达将来的意愿，所以用“will + love”的结构。","表示学科的名词如Chinese（语文）、Math（数学）等，属于专有名词，首字母需要大写，且这类名词通常为不可数名词，不需要变复数。"]},"sentenceWithHints":"我 会 热爱 语文"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1306, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"提高","english":"improve","examples":["You need to improve your listening skills.","The weather is improving day by day."],"phonetic":"/ɪmˈpruːv/","pastTense":"improved","thirdPerson":"improves","partOfSpeech":"动词","pastParticiple":"improved","presentParticiple":"improving"},{"plural":"","chinese":"我的","english":"my","examples":["My favorite subject is math.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"语文","english":"Chinese","examples":["I study Chinese every day.","Chinese is a beautiful language."],"phonetic":"/ˌtʃaɪˈniːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"levels","chinese":"水平","english":"level","examples":["His English level is very high.","We need to reach a higher level."],"phonetic":"/ˈlevəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","物主代词的使用","学科类名词的表达"],"explanations":["一般将来时表示将来要发生的动作或存在的状态，结构为“will + 动词原形”。本句中“会提高”表达将来的动作，所以用“will improve”的结构，符合初中一年级对一般将来时基础用法的考查要求。","形容词性物主代词“my”用来修饰名词，表明所属关系，本句中“my Chinese level”表示“我的语文水平”，初中一年级需要掌握第一人称形容词性物主代词的基本使用场景。","学科类名词如“Chinese（语文）”属于专有名词，首字母需要大写，这类词汇是初中一年级英语词汇积累的重点内容，需要掌握常见学科的英文表达及书写规范。"]},"sentenceWithHints":"我 会 提高 我的 语文 水平"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1307, '{"words":[{"plural":"sciences","chinese":"科学","english":"science","examples":["Science is my favorite subject.","He studies environmental science."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"探索","english":"explore","examples":["We want to explore the old castle.","Scientists explore the deep sea every year."],"phonetic":"/ɪkˈsplɔːr/","pastTense":"explored","thirdPerson":"explores","partOfSpeech":"动词","pastParticiple":"explored","presentParticiple":"exploring"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is full of surprises.","She dreams of traveling around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["the roof of the house","a map of China"],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"mysteries","chinese":"奥秘","english":"mystery","examples":["The pyramid is an ancient mystery.","They are trying to solve the mysteries of the universe."],"phonetic":"/ˈmɪstəri/","partOfSpeech":"名词"}],"examPoints":{"points":["动词第三人称单数变化","名词所有格/所属关系表达","可数名词复数变化"],"explanations":["当主语是第三人称单数（本句中 Science 属于第三人称单数主语）时，一般现在时的动词要使用第三人称单数形式。explore 的第三人称单数是在词尾加 -s，即 explores。","英语中表达所属关系时，常用介词 of 构成短语，结构为“the + 名词 + of + 名词”，对应中文里的“……的……”，本句中“世界的奥秘”译为“the mysteries of the world”就是这种用法。","可数名词表示泛指的多个事物时要使用复数形式。mystery 是以辅音字母加 y 结尾的可数名词，变复数时要把 y 改为 i 再加 -es，即 mysteries，本句中“奥秘”表示多个未知的事物，所以用复数形式。"]},"sentenceWithHints":"科学 探索 世界 的 奥秘"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1308, '{"words":[{"plural":"sciences","chinese":"科学","english":"science","examples":["Science helps us understand the world.","She studies science at school."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"告诉","english":"tell","examples":["My mother tells me stories every night.","He told me the truth yesterday."],"phonetic":"/tel/","pastTense":"told","thirdPerson":"tells","partOfSpeech":"动词","pastParticiple":"told","presentParticiple":"telling"},{"chinese":"我们","english":"us","examples":["He gave us some gifts.","Please help us with the work."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"自然","english":"natural","examples":["It''s a natural phenomenon.","She has a natural talent for music."],"phonetic":"/ˈnætʃrəl/","partOfSpeech":"形容词"},{"plural":"laws","chinese":"规律","english":"law","examples":["We must obey the law.","The law of gravity is a basic physics rule."],"phonetic":"/lɔː/","partOfSpeech":"名词"}],"examPoints":{"points":["动词第三人称单数形式","可数名词复数形式","形容词作定语"],"explanations":["当主语是第三人称单数（本句中主语Science是第三人称单数）时，一般现在时的动词要使用第三人称单数形式。规则动词一般在词尾加-s，tell的第三人称单数形式是tells。","可数名词表示泛指一类事物时，通常使用复数形式。law是可数名词，此处表示“自然规律”这一类规则，所以使用复数形式laws，规则名词变复数一般在词尾加-s。","形容词可以放在名词前作定语，用来修饰名词。本句中natural是形容词，修饰后面的名词laws，说明是“自然的”规律，符合形容词作定语的用法。"]},"sentenceWithHints":"科学 告诉 我们 自然 规律"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1309, '{"words":[{"plural":"sciences","chinese":"科学","english":"science","examples":["Science can help us solve many problems.","I am interested in computer science."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mother lets me watch TV after homework.","Let''s go to the park together."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["The teacher told us a story.","Please wait for us."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"了解","english":"understand","examples":["I can understand your feelings.","She doesn''t understand this math problem."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"universes","chinese":"宇宙","english":"universe","examples":["The universe is very big.","Scientists are exploring the universe."],"phonetic":"/ˈjuːnɪvɜːrs/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","可数名词与不可数名词的区分","动词第三人称单数变化"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中lets us understand就符合这个结构。","句中的science和universe都属于可数名词，其中science表示“科学（学科）”时可数，表泛指的科学概念时也可作不可数名词；universe表示“宇宙”时，通常单独使用加定冠词the来特指我们所处的这个宇宙，复数形式则表示多个宇宙，多用于科幻语境。","当主语是第三人称单数（本句中主语Science是第三人称单数）时，一般现在时的动词要变成第三人称单数形式，let的第三人称单数是直接加s，即lets。"]},"sentenceWithHints":"科学 让 我们 了解 宇宙"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1310, '{"words":[{"plural":"sciences","chinese":"科学","english":"science","examples":["Science is my favorite subject.","We learn different sciences at school."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","The movie is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"神奇","english":"magical","examples":["The magical show surprised everyone.","It''s a magical place."],"phonetic":"/ˈmædʒɪkl/","partOfSpeech":"形容词"}],"examPoints":{"points":["主系表结构","副词修饰形容词","不可数名词的用法"],"explanations":["本句是典型的主系表结构，主语是“科学（science）”，系动词用is（主语是单数名词），表语是形容词“神奇（magical）”，用于描述主语的特征。","副词“very”用来修饰形容词“magical”，表示程度，说明神奇的程度很高，副词修饰形容词时通常放在形容词之前。","“science”表示“科学”这一抽象概念时是不可数名词，作主语时谓语动词用单数形式is；当表示具体的学科门类时，是可数名词，复数形式为sciences。本句中是抽象概念，所以用单数形式。"]},"sentenceWithHints":"科学 很 神奇"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1311, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"做","english":"do","examples":["I do my homework every night.","He does sports after school."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"sciences","chinese":"科学","english":"science","examples":["I study science at school.","Science is interesting."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"plural":"experiments","chinese":"实验","english":"experiment","examples":["We did some experiments in lab.","The experiment was successful."],"phonetic":"/ɪkˈsperɪmənt/","partOfSpeech":"名词"}],"examPoints":{"points":["like的固定搭配","可数名词复数形式"],"explanations":["like后接动词时，常用like doing sth.的结构，表示长期的、习惯性的喜好，本句表达的是长期喜欢做科学实验，所以用like doing science experiments。","experiment是可数名词，此处表示一类事物，要用复数形式experiments，可数名词复数泛指一类事物时，不需要加冠词。"]},"sentenceWithHints":"我 喜欢 做 科学 实验"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1312, '{"words":[{"plural":"experiments","chinese":"实验","english":"experiment","examples":["We did some experiments in the lab.","The experiment was a success."],"phonetic":"/ɪkˈsperəmənt/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me watch TV after homework.","Let''s go to the park together."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"发现","english":"discover","examples":["Columbus discovered America in 1492.","We discovered a new way to solve the problem."],"phonetic":"/dɪˈskʌvər/","pastTense":"discovered","thirdPerson":"discovers","partOfSpeech":"动词","pastParticiple":"discovered","presentParticiple":"discovering"},{"plural":"truths","chinese":"真理","english":"truth","examples":["He always tells the truth.","The truth is hard to accept sometimes."],"phonetic":"/truːθ/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","可数名词复数形式","实义动词discover的用法"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中let me discover truth就符合这个结构。","可数名词表示泛指一类事物时，常用复数形式。本句中“实验”表示一类行为，所以用experiment的复数形式experiments；truth表示泛指真理概念时也可用复数，此处参考翻译用truth也可表示泛指，复数形式truths也可使用。","discover是实义动词，意为“发现”，指发现原本存在但不为人知的事物，在句中作宾语补足语，符合let sb. do sth.的结构要求，用动词原形。"]},"sentenceWithHints":"实验 让 我 发现 真理"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1313, '{"words":[{"plural":"sciences","chinese":"科学","english":"science","examples":["Science is my favorite subject.","We learn about different sciences at school."],"phonetic":"/ˈsaɪəns/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["My mom makes delicious food.","He made a mistake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"思考","english":"think","examples":["I think you are right.","She thought about the problem for hours."],"phonetic":"/θɪŋk/","pastTense":"thought","thirdPerson":"thinks","partOfSpeech":"动词","pastParticiple":"thought","presentParticiple":"thinking"}],"examPoints":{"points":["使役动词make的用法","动词第三人称单数形式","人称代词宾格的使用"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 不带to的动词不定式”，表示“让某人做某事”，本句中“makes me think”就是这个结构，即“让我思考”。","当句子主语是第三人称单数（本句中主语Science是不可数名词，视为第三人称单数）时，一般现在时的动词要使用第三人称单数形式，make的第三人称单数形式是makes。","在句子中作动词或介词的宾语时，人称代词要使用宾格形式，本句中me是I的宾格形式，在make后面作宾语。"]},"sentenceWithHints":"科学 让 我 思考"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1314, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading books."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing basketball."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"sciences","chinese":"科学","english":"science","examples":["I am interested in science.","She studies computer science at university."],"phonetic":"/ˈsaɪəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成与用法","不可数名词与可数名词的区分","及物动词的用法"],"explanations":["一般将来时表示将来发生的动作或存在的状态，由助动词will+动词原形构成，本句中“会热爱”表达将来的意愿，所以使用will+love的结构，主语为第一人称、第二人称或复数主语时，will保持原形，没有人称和数的变化。","science表示“科学”这一抽象概念时是不可数名词，泛指科学领域时可以作可数名词，复数形式为sciences，本句中science表示抽象的科学概念，为不可数名词，前面不需要加冠词。","love作为及物动词，后面可以直接接宾语，本句中直接接名词science作宾语，表达“热爱科学”的语义，及物动词的这一用法是初中阶段需要掌握的基础动词用法。"]},"sentenceWithHints":"我 会 热爱 科学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1315, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"探索","english":"explore","examples":["We want to explore the deep forest.","Scientists explore the universe every day."],"phonetic":"/ɪkˈsplɔːr/","pastTense":"explored","thirdPerson":"explores","partOfSpeech":"动词","pastParticiple":"explored","presentParticiple":"exploring"},{"plural":"sciences","chinese":"科学","english":"science","examples":["I am interested in science.","She studies medical sciences at university."],"phonetic":"/ˈsaɪəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["the door of the room","a map of China"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He dreams of traveling to different worlds."],"phonetic":"/wɜːrld/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","名词所有格的介词结构","定冠词the的用法"],"explanations":["一般将来时可以用“will + 动词原形”的结构表示将来要发生的动作或存在的状态，本句中“会探索”表达将来的意愿和动作，所以使用“I will explore”的结构。","英语中表示所属关系时，除了''s的所有格形式，还可以用“of + 名词”的介词结构，本句中“科学的世界”翻译为“the world of science”，就是用这种结构来体现所属关系。","定冠词the用于特指的名词前，本句中“world”特指“科学的世界”，是特定的范畴，所以前面要加定冠词the。"]},"sentenceWithHints":"我 会 探索 科学 的 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1316, '{"words":[{"plural":"histories","chinese":"历史","english":"history","examples":["We study history at school.","The history of this city is very long."],"phonetic":"/ˈhɪstəri/","partOfSpeech":"名词"},{"chinese":"告诉","english":"tell","examples":["My mother tells me stories every night.","He told me a secret yesterday."],"phonetic":"/tel/","pastTense":"told","thirdPerson":"tells","partOfSpeech":"动词","pastParticiple":"told","presentParticiple":"telling"},{"plural":"","chinese":"我们","english":"us","examples":["She gave us some candies.","Please help us with the work."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"plural":"","chinese":"过去","english":"past","examples":["We should learn from the past.","In the past, people lived a hard life."],"phonetic":"/pæst/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["This is a photo of my family.","The door of the room is open."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"stories","chinese":"故事","english":"story","examples":["I like reading interesting stories.","She wrote two stories last month."],"phonetic":"/ˈstɔːri/","partOfSpeech":"名词"}],"examPoints":{"points":["动词的第三人称单数形式","名词所有格/所属关系的表达","可数名词的复数形式"],"explanations":["当主语是第三人称单数（本句中主语History为单数名词，属于第三人称单数）时，一般现在时的动词要使用第三人称单数形式，规则动词通常在词尾加-s，不规则动词有特殊变形，本句中tell的第三人称单数形式是tells。","英语中表达所属关系时，除了名词所有格''s形式，还可以用介词of构成短语，本句中“过去的故事”用“stories of the past”来表达，符合初中阶段所属关系的常用表达结构。","可数名词表示泛指多个时要使用复数形式，以辅音字母+y结尾的可数名词，变复数时要把y变为i再加-es，story的复数形式是stories，本句中用stories表示不止一个故事，符合语境需求。"]},"sentenceWithHints":"历史 告诉 我们 过去 的 故事"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1317, '{"words":[{"plural":"histories","chinese":"历史","english":"history","examples":["History is full of interesting stories.","We are learning Chinese history."],"phonetic":"/ˈhɪstəri/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mother lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["He told us a funny joke.","Us students need to study hard."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"了解","english":"understand","examples":["I don''t understand this math problem.","She understands how to play the piano."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"cultures","chinese":"文化","english":"culture","examples":["We should respect different cultures.","Chinese culture is very rich."],"phonetic":"/ˈkʌltʃər/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","动词第三人称单数形式","可数名词的泛指用法"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中let us understand符合这个结构。","当句子主语是第三人称单数（本句中主语History是单数名词，属于第三人称单数）时，一般现在时的动词要使用第三人称单数形式，let的第三人称单数是lets。","当表示泛指的概念时，可数名词单数可以直接使用（前面不用加冠词），本句中History和culture都是表示泛指的抽象概念，所以直接使用单数形式即可。"]},"sentenceWithHints":"历史 让 我们 了解 文化"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1318, '{"words":[{"plural":"histories","chinese":"历史","english":"history","examples":["History is my favorite subject.","We should learn from history."],"phonetic":"/ˈhɪstri/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me watch TV.","He lets his dog run in the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some water."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"吸取","english":"learn","examples":["We learn English every day.","She learned to play the piano."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"lessons","chinese":"教训","english":"lesson","examples":["We should learn lessons from mistakes.","The teacher gave us a new lesson."],"phonetic":"/ˈlesn/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","可数名词复数","动词不定式省略to的情况"],"explanations":["let作为使役动词，常见结构为let sb. do sth.，表示“让某人做某事”，主语为第三人称单数时，let要变为lets，本句主语History是第三人称单数，所以用lets。","lesson是可数名词，当表示泛指的“教训”时，常用复数形式lessons，符合句子表达“吸取（诸多）教训”的含义。","在使役动词let、make、have后接宾语补足语时，不定式要省略to，所以本句中用learn而不是to learn，这是初中阶段需要掌握的不定式省略规则。"]},"sentenceWithHints":"历史 让 我们 吸取 教训"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1319, '{"words":[{"plural":"histories","chinese":"历史","english":"history","examples":["I like studying history.","Chinese history is very long."],"phonetic":"/ˈhɪstəri/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有意义","english":"meaningful","examples":["Reading is meaningful.","This is a meaningful activity."],"phonetic":"/ˈmiːnɪŋfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["The book is interesting.","He is a doctor."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["系动词be的用法","副词修饰形容词的用法","抽象名词的使用"],"explanations":["be动词有am、is、are三种形式，本句主语history是第三人称单数的抽象名词，因此搭配系动词is，用于连接主语和表语说明主语的特征。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very修饰meaningful，强调“有意义”的程度。","history属于抽象名词，通常表示学科或整体概念时为不可数名词，不需要变复数；当表示不同国家或时期的多个历史时，可作可数名词变复数为histories，本句中表示“历史学科”，为不可数概念。"]},"sentenceWithHints":"历史 很 有意义"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1320, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading books."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes listening to music."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"学习","english":"study","examples":["He studies hard every day.","We are studying math now."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"histories","chinese":"历史","english":"history","examples":["I am interested in history.","We will learn Chinese history this term."],"phonetic":"/ˈhɪstri/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","名词的分类与使用"],"explanations":["like作为动词表示“喜欢”时，常见用法有like doing sth.和like to do sth.，其中like doing sth.表示长期的、习惯性的喜好，本句表达的是长期的兴趣，所以用studying；like的第三人称单数形式是likes，过去式和过去分词为liked，现在分词为liking。","history表示“历史（学科）”时是不可数名词，泛指历史学科时不需要加冠词；当表示“（某一国家或时期的）历史”时是可数名词，复数形式为histories，本句中是泛指历史学科，所以用单数形式history。"]},"sentenceWithHints":"我 喜欢 学习 历史"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1321, '{"words":[{"plural":"histories","chinese":"历史","english":"history","examples":["I like learning history.","Different countries have different histories."],"phonetic":"/ˈhɪstəri/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["My mom makes delicious food.","He made a mistake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me with my homework."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"思考","english":"think","examples":["I think you are right.","She is thinking about her future."],"phonetic":"/θɪŋk/","pastTense":"thought","thirdPerson":"thinks","partOfSpeech":"动词","pastParticiple":"thought","presentParticiple":"thinking"}],"examPoints":{"points":["使役动词make的用法","动词第三人称单数变化","人称代词宾格"],"explanations":["make作为使役动词，常用结构为make sb. do sth.，表示“让某人做某事”，此处省略不定式符号to，所以后面接动词原形think。","当主语是第三人称单数（本句中主语History是不可数名词，视为第三人称单数）时，一般现在时的动词要使用第三人称单数形式，make的第三人称单数形式是makes。","在动词或介词后面要使用人称代词的宾格形式，me是I的宾格，此处作make的宾语，符合语法规则。"]},"sentenceWithHints":"历史 让 我 思考"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1322, '{"words":[{"plural":"histories","chinese":"历史","english":"history","examples":["History is my favorite subject.","We should learn from history."],"phonetic":"/ˈhɪstri/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["My mom makes delicious food.","The news makes me sad."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"明白","english":"understand","examples":["I understand your feelings.","She doesn''t understand the question."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"chinese":"很多","english":"many","examples":["I have many friends.","There are many books on the shelf."],"phonetic":"/ˈmeni/","partOfSpeech":"形容词"},{"plural":"principles","chinese":"道理","english":"principle","examples":["He always follows his principles.","We need to learn basic principles of math."],"phonetic":"/ˈprɪnsəpl/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词make的用法","可数名词的复数形式","实义动词understand的用法"],"explanations":["make作为使役动词，常见结构为make sb. do sth.，表示“让某人做某事”，此处省略不定式符号to，本句中make me understand即符合这个结构，这是初中阶段使役动词的核心考点之一。","many后接可数名词复数形式，principle是可数名词，所以需要使用其复数形式principles，初中阶段需要掌握可数名词变复数的规则，以及many与可数名词复数搭配的用法。","understand是实义动词，在make sb. do sth.结构中使用原形，同时要掌握它的不规则变形：过去式和过去分词为understood，第三人称单数为understands，现在分词为understanding，这是初中动词变形的常考内容。"]},"sentenceWithHints":"历史 让 我 明白 很多 道理"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1323, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing basketball."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"histories","chinese":"历史","english":"history","examples":["We are learning Chinese history.","She is interested in history."],"phonetic":"/ˈhɪstri/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成与用法","及物动词的用法","不可数名词/抽象名词的用法"],"explanations":["一般将来时表示将来发生的动作或存在的状态，由“will + 动词原形”构成，本句中“会热爱”表达将来的意愿，所以用“will love”的结构，will 在这里作为助动词帮助构成将来时态，无人称和数的变化（除过去式 would）。","love 是及物动词，后面可以直接接宾语，不需要加介词，本句中直接接宾语“history”，表示热爱的对象。","history 作为“历史（学科、整体概念）”讲时是抽象名词，属于不可数名词，不需要变复数；当表示“多个不同的历史事件或历史记载”时，可作可数名词，复数形式为 histories，本句中是指历史学科，所以用单数形式。"]},"sentenceWithHints":"我 会 热爱 历史"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1324, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"learn","examples":["I learn English every day.","He has learned how to play the piano."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"历史","english":"historical","examples":["We visited a historical building.","There are many historical stories in this book."],"phonetic":"/hɪˈstɔːrɪkəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","She has a lot of knowledge about animals."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成","形容词作定语","不可数名词的用法"],"explanations":["一般将来时表示将要发生的动作或存在的状态，由“will + 动词原形”构成，本句中“will learn”表示将要进行“学习”这个动作，符合一般将来时的结构。","形容词可以用来修饰名词，放在名词前作定语，本句中“historical（历史的）”是形容词，用来修饰名词“knowledge（知识）”，说明知识的类型是和历史相关的。","knowledge是不可数名词，没有复数形式，不能在后面加-s或-es，在句子中表示“知识”这一抽象概念时，直接使用原形即可。"]},"sentenceWithHints":"我 会 学习 历史 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1325, '{"words":[{"plural":"geographies","chinese":"地理","english":"geography","examples":["Geography is my favorite subject.","We learn about different countries in geography class."],"phonetic":"/dʒiˈɑːɡrəfi/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me watch TV after homework.","She lets her dog play in the yard."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["He told us a funny story.","Please give us some water."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"了解","english":"understand","examples":["I understand your problem.","She understands how to solve the math question."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is full of amazing things.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","动词第三人称单数变化","动词不定式省略to的情况"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，此处sb.要用宾格形式，本句中用us作let的宾语。","当主语是第三人称单数（本句中主语Geography是单数名词，属于第三人称单数）时，一般现在时的动词要变成第三人称单数形式，let的第三人称单数是lets。","在使役动词let、make、have后接宾语补足语时，不定式要省略to，所以本句中understand前不需要加to，直接用动词原形。"]},"sentenceWithHints":"地理 让 我们 了解 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1326, '{"words":[{"plural":"geographies","chinese":"地理","english":"geography","examples":["Geography is my favorite subject.","We learn about different countries in geography class."],"phonetic":"/dʒiˈɑːɡrəfi/","partOfSpeech":"名词"},{"chinese":"告诉","english":"tell","examples":["My mother tells me stories every night.","He told us the news yesterday."],"phonetic":"/tel/","pastTense":"told","thirdPerson":"tells","partOfSpeech":"动词","pastParticiple":"told","presentParticiple":"telling"},{"chinese":"我们","english":"us","examples":["She gave us some candies.","Please wait for us."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"plural":"","chinese":"各地","english":"different places","examples":["We have friends in different places.","The weather is different in different places."],"phonetic":"/ˈdɪfrənt pleɪsɪz/","partOfSpeech":"名词短语"},{"chinese":"的","english":"of","examples":["This is a photo of my family.","The color of the flower is red."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"customs","chinese":"风土人情","english":"customs","examples":["We should respect local customs when traveling.","The book introduces the customs of various nations."],"phonetic":"/ˈkʌstəmz/","partOfSpeech":"名词"}],"examPoints":{"points":["动词的第三人称单数形式","名词所有格/所属关系表达","可数名词复数"],"explanations":["本句主语“地理（geography）”是第三人称单数，一般现在时中，主语为第三人称单数时，动词要使用第三人称单数形式，tell的第三人称单数是tells。","表达“各地的风土人情”时，使用介词of来体现所属关系，即“customs of different places”，这是初中阶段需要掌握的表示所属关系的常用结构之一。","“风土人情”对应的英文customs是可数名词复数形式，custom作为“风俗、习俗”讲时是可数名词，这里用复数形式泛指不同地区的各类风土人情，初中阶段需要掌握可数名词单复数的正确使用场景。"]},"sentenceWithHints":"地理 告诉 我们 各地 的 风土人情"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1327, '{"words":[{"plural":"geographies","chinese":"地理","english":"geography","examples":["I like geography best among all subjects.","Geography helps us understand the world."],"phonetic":"/dʒiˈɑːɡrəfi/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me watch TV after finishing homework.","She lets her dog run in the park every day."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"plural":"","chinese":"我们","english":"us","examples":["The teacher asked us to be quiet.","He gave us some candies."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"知道","english":"know","examples":["I know the answer to this question.","She has known him for five years."],"phonetic":"/noʊ/","pastTense":"knew","thirdPerson":"knows","partOfSpeech":"动词","pastParticiple":"known","presentParticiple":"knowing"},{"plural":"earths","chinese":"地球","english":"earth","examples":["The earth goes around the sun.","We should protect the earth."],"phonetic":"/ɜːrθ/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The cover of the book is blue.","This is a photo of my family."],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"structures","chinese":"构造","english":"structure","examples":["We learned about the structure of a cell in science class.","The bridge has a strong structure."],"phonetic":"/ˈstrʌktʃər/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","名词所有格/所属关系表达","一般现在时第三人称单数变化"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语。本句中lets us know就是该结构的体现，符合初中阶段对使役动词基础用法的考查。","表示所属关系时，除了名词所有格''s形式，还可以用介词of短语，本句中the structure of the earth就是用of来表达“地球的构造”，这是初中阶段需要掌握的所属关系的重要表达方法。","一般现在时中，当主语是第三人称单数（本句中主语Geography是单数名词，属于第三人称单数）时，谓语动词要发生相应变化，规则动词直接加-s，let的第三人称单数形式是lets，这是初一阶段一般现在时的核心考点之一。"]},"sentenceWithHints":"地理 让 我们 知道 地球 的 构造"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1328, '{"words":[{"plural":"geographies","chinese":"地理","english":"geography","examples":["Geography is my favorite subject.","We are learning about human geography this term."],"phonetic":"/dʒiˈɑːɡrəfi/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The movie is very exciting.","She runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"有趣","english":"interesting","examples":["This book is very interesting.","We had an interesting talk yesterday."],"phonetic":"/ˈɪntrəstɪŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["系动词的用法","副词修饰形容词的规则","学科类名词的用法"],"explanations":["本句是主系表结构，主语“地理（geography）”是第三人称单数的学科名词，因此搭配系动词is，用来连接主语和表语“有趣（interesting）”，说明主语的特征。","副词very用来修饰形容词，表示程度，通常放在被修饰的形容词之前，本句中very用来加强interesting的程度，表达“很有趣”的含义。","geography属于学科类名词，这类名词通常为不可数名词，泛指学科概念时不需要加冠词；当表示具体的地理分支或不同的地理研究内容时，可变为复数形式geographies。"]},"sentenceWithHints":"地理 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1329, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes listening to music."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"看","english":"look at","examples":["Look at the blackboard.","He is looking at a picture."],"phonetic":"/lʊk æt/","pastTense":"looked at","thirdPerson":"looks at","partOfSpeech":"动词","pastParticiple":"looked at","presentParticiple":"looking at"},{"plural":"maps","chinese":"地图","english":"map","examples":["This is a map of China.","We use maps to find directions."],"phonetic":"/mæp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词的复数形式","look的固定搭配"],"explanations":["like作为动词表示“喜欢”时，常用搭配为like doing sth.，表示长期的、习惯性的喜好，本句中“喜欢看地图”是长期爱好，所以用looking at。","map是可数名词，当表示一类事物且没有不定冠词修饰时，要用复数形式maps，规则可数名词变复数一般在词尾加-s。","look表示“看”的具体动作时，是不及物动词，后面接宾语需要加介词at，构成固定搭配look at，不能单独用look直接接宾语。"]},"sentenceWithHints":"我 喜欢 看 地图"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1330, '{"words":[{"plural":"geographies","chinese":"地理","english":"geography","examples":["I like studying geography.","Geography helps us understand different places."],"phonetic":"/dʒiˈɑːɡrəfi/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me go to the park.","She lets her dog play outside every day."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"plural":"","chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me your name."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"认识","english":"know","examples":["I know the answer.","She has known him for five years."],"phonetic":"/noʊ/","pastTense":"knew","thirdPerson":"knows","partOfSpeech":"动词","pastParticiple":"known","presentParticiple":"knowing"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","动词第三人称单数形式","定冠词the的特指用法"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中lets me know即符合该结构。","当句子主语是第三人称单数（本句中主语Geography是单数名词，属于第三人称单数）时，一般现在时的谓语动词要使用第三人称单数形式，let的第三人称单数是lets。","world（世界）是独一无二的事物，前面需要加定冠词the来表示特指，所以翻译中用the world。"]},"sentenceWithHints":"地理 让 我 认识 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1331, '{"words":[{"plural":"geographies","chinese":"地理","english":"geography","examples":["I like geography very much.","Geography helps us know the world."],"phonetic":"/dʒiˈɑːɡrəfi/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","My mom makes delicious food every day."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gives me a gift.","Please call me later."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"想","english":"want","examples":["I want to go home.","She wants a new bike."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"chinese":"去","english":"go","examples":["Let''s go to the park.","He goes to school by bus."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"chinese":"旅行","english":"travel","examples":["I love to travel around the world.","She traveled to Japan last year."],"phonetic":"/ˈtrævl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"}],"examPoints":{"points":["使役动词make的用法","want to do sth.固定搭配","一般现在时第三人称单数变化"],"explanations":["make作为使役动词，常见结构为make sb. do sth.，表示“让某人做某事”，在这个结构中，do要用动词原形，本句中makes me want to travel就符合这个结构，want用原形。","want后接动词时，要使用want to do sth.的固定搭配，意为“想要做某事”，这里want to travel就是该搭配的体现，表达想要旅行的意愿。","一般现在时中，当主语是第三人称单数（本句中主语Geography是单数名词，属于第三人称单数）时，谓语动词要使用第三人称单数形式，make的第三人称单数形式是makes。"]},"sentenceWithHints":"地理 让 我 想 去 旅行"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1332, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading books."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing basketball."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"地理","english":"geography","examples":["We have geography class on Monday.","She is interested in geography."],"phonetic":"/dʒiˈɑːɡrəfi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成与用法","表示学科的不可数名词用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会热爱”表达将来的意愿，所以用“will + love”的结构，will 在这里作为助动词帮助构成将来时态，后接动词原形。","geography（地理）属于表示学科的名词，这类名词通常为不可数名词，在句子中作宾语时不需要变复数，也不需要加不定冠词 a/an，直接使用原形即可。"]},"sentenceWithHints":"我 会 热爱 地理"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1333, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to go to the park."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go home soon.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"了解","english":"understand","examples":["I understand your feelings.","He can''t understand the math problem."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He travels around the world."],"phonetic":"/wɜːrld/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["a map of China","the roof of the house"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"geographies","chinese":"地理","english":"geography","examples":["I like learning geography.","Geography is an interesting subject."],"phonetic":"/dʒiˈɑːɡrəfi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","介词of表所属关系","不可数名词与可数名词的区分"],"explanations":["一般将来时用来表示将要发生的动作或存在的状态，结构为“will + 动词原形”，本句中“会了解”表达将来的动作，所以使用“will understand”的结构。","介词of常用来表示所属关系，意为“……的”，本句中“the geography of the world”表示“世界的地理”，用来体现地理和世界的所属关联。","geography作为学科类名词时属于不可数名词，单独使用时不需要加冠词；但表示不同地区的地理情况时可作可数名词，复数形式为geographies。本句中geography指学科，按不可数名词使用。"]},"sentenceWithHints":"我 会 了解 世界 的 地理"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1334, '{"words":[{"plural":"","chinese":"音乐","english":"music","examples":["I love listening to music.","Music can make people relaxed."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a doctor.","This is my new pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一种","english":"an","examples":["An apple a day keeps the doctor away.","She is an artist."],"phonetic":"/æn/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"arts","chinese":"艺术","english":"art","examples":["Painting is a form of art.","She studies arts in college."],"phonetic":"/ɑːrt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["系动词be的用法","不定冠词a/an的区分","不可数名词与可数名词的用法"],"explanations":["系动词be有am、is、are三种现在时形式，当主语是第三人称单数（本句中music是不可数名词，视为第三人称单数）时，be动词用is。","不定冠词a用于辅音音素开头的单词前，an用于元音音素开头的单词前。art以元音音素/ɑː/开头，所以前面用an。","music表示“音乐”这一抽象概念时是不可数名词，无复数形式；art表示“艺术”这一抽象概念时通常不可数，但表示“艺术门类、文科”时是可数名词，复数形式为arts。本句中art表示抽象的艺术概念，属于不可数名词范畴，但此处用an art是将其具体化，表示“一种艺术类别”。"]},"sentenceWithHints":"音乐 是 一种 艺术"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1335, '{"words":[{"plural":"","chinese":"音乐","english":"music","examples":["I love listening to music.","Music can make people relaxed."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"表达","english":"express","examples":["She can express her ideas clearly.","Art expresses what words cannot say."],"phonetic":"/ɪkˈspres/","pastTense":"expressed","thirdPerson":"expresses","partOfSpeech":"动词","pastParticiple":"expressed","presentParticiple":"expressing"},{"plural":"emotions","chinese":"情感","english":"emotion","examples":["He couldn''t hide his emotions.","Different songs can bring out different emotions."],"phonetic":"/ɪˈmoʊʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["主谓一致","可数名词的复数形式"],"explanations":["本句主语“music”是不可数名词，在一般现在时中，不可数名词作主语时，谓语动词要用第三人称单数形式，所以动词“express”要变为“expresses”。","“emotion”是可数名词，此处表示泛指的各类情感，所以要用其复数形式“emotions”，可数名词表示泛指的多个事物时通常使用复数形式。"]},"sentenceWithHints":"音乐 表达 情感"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1336, '{"words":[{"plural":"","chinese":"音乐","english":"music","examples":["I love listening to music.","Music can help you relax."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"让","english":"make","examples":["The news made her sad.","He makes a cake every weekend."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"people","chinese":"人","english":"people","examples":["People like to travel in summer.","Many people came to the party."],"phonetic":"/ˈpiːpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"快乐","english":"happy","examples":["She looks happy today.","The happy children are playing games."],"phonetic":"/ˈhæpi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["使役动词make的用法","主谓一致规则","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“make people happy”即表示“让人处于快乐的状态”。","本句主语“music”是不可数名词，视为第三人称单数，一般现在时中，主语为第三人称单数时，谓语动词要使用第三人称单数形式，所以make变为makes。","在“make + 宾语 + 宾补”的结构里，形容词可以作宾语补足语，补充说明宾语的状态，本句中happy补充说明people的状态，即人是快乐的。"]},"sentenceWithHints":"音乐 让 人 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1337, '{"words":[{"plural":"musics","chinese":"音乐","english":"music","examples":["I love listening to music.","She is good at playing music."],"phonetic":"/ˈmjuːzɪk/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"美妙","english":"wonderful","examples":["We had a wonderful time.","This is a wonderful idea."],"phonetic":"/ˈwʌndərfl/","partOfSpeech":"形容词"}],"examPoints":{"points":["主系表结构的运用","副词修饰形容词的用法","不可数名词的使用"],"explanations":["本句是典型的主系表结构，主语是“音乐（music）”，系动词用is，表语是形容词“美妙（wonderful）”，用来描述主语的特征，符合英语中描述事物属性的常用句式。","副词“very（很）”用来修饰形容词“wonderful（美妙）”，放在形容词之前，用来加强形容词的程度，这是英语中副词修饰形容词的基本规则。","“music（音乐）”是不可数名词，通常情况下没有复数形式，也不能直接用不定冠词a/an修饰，在句子中作主语时，系动词要用单数形式is。"]},"sentenceWithHints":"音乐 很 美妙"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1339, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like watching movies.","She likes cats very much."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"弹","english":"play","examples":["He can play the guitar.","They play football every weekend."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"pianos","chinese":"钢琴","english":"piano","examples":["She plays the piano well.","We bought a new piano."],"phonetic":"/piˈænoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","乐器前加定冠词the","动名词作宾语"],"explanations":["like作为动词表示“喜欢”时，常见用法有like doing sth.（表示长期的、习惯性的喜欢）和like to do sth.（表示偶尔的、特定的喜欢），本句中用like playing表示习惯性的爱好。","在英语中，演奏西洋乐器时，乐器名词前必须加定冠词the，比如play the piano、play the violin；而球类运动前不加the，比如play football。","like是及物动词，后面可以接动名词（doing形式）作宾语，动名词在这里表示抽象的、习惯性的动作，符合本句表达长期爱好的语境。"]},"sentenceWithHints":"我 喜欢 弹 钢琴"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1340, '{"words":[{"plural":"","chinese":"音乐","english":"music","examples":["I love listening to music.","Music can make people happy."],"phonetic":"/ˈmjuːzɪk/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes a cake every weekend.","The news made him sad."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"放松","english":"relax","examples":["I relax by reading books.","It''s important to relax after work."],"phonetic":"/rɪˈlæks/","pastTense":"relaxed","thirdPerson":"relaxes","partOfSpeech":"动词","pastParticiple":"relaxed","presentParticiple":"relaxing"}],"examPoints":{"points":["使役动词make的用法","主谓一致规则"],"explanations":["make作为使役动词，常见结构为make + 宾语 + 不带to的动词不定式，表示“让某人做某事”，本句中即make me relax，意为“让我放松”。需要注意在被动语态中，不带to的不定式要还原to，即be made to do sth。","本句主语Music是不可数名词，视为第三人称单数，所以谓语动词make要使用第三人称单数形式makes，这是初中阶段主谓一致的基础考点，不可数名词、单数可数名词或第三人称单数代词作主语时，谓语动词要用第三人称单数形式。"]},"sentenceWithHints":"音乐 让 我 放松"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1341, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing basketball."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"音乐","english":"music","examples":["I enjoy listening to music.","She is good at music."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成","不可数名词的用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常见结构为“will + 动词原形”。本句中“会热爱”表达将来的意愿，所以用“will + love”的结构，其中will作为助动词帮助构成将来时态，后面接动词原形love。","music是不可数名词，不可数名词没有复数形式，不能直接用不定冠词a/an修饰，也不能在词尾加-s/-es表示复数，在句中表示泛指时直接使用原形即可。"]},"sentenceWithHints":"我 会 热爱 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1342, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":"willing"},{"plural":"","chinese":"学习","english":"learn","examples":["I learn English every day.","He has learned to play the piano."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"更多","english":"more","examples":["I need more time to finish the task.","She has more books than me."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"音乐","english":"music","examples":["I like listening to music.","She is good at music."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"知识","english":"knowledge","examples":["We should gain more knowledge.","Knowledge is power."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","形容词比较级的用法","不可数名词的用法"],"explanations":["一般将来时用来表示将来要发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会学习”用“will learn”来表达将来要进行的学习动作，符合初中一年级对一般将来时的考查要求。","more 是 many/much 的比较级，既可以修饰可数名词复数也可以修饰不可数名词，本句中用来修饰不可数名词短语“music knowledge”，表示“更多的”，是初中阶段形容词比较级的基础用法。","music 和 knowledge 都属于不可数名词，不可数名词没有复数形式，不能直接加-s或-es，在表示数量时需要借助量词短语，本句中直接用形容词 more 来修饰，体现了不可数名词的基础使用规则。"]},"sentenceWithHints":"我 会 学习 更多 音乐 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1343, '{"words":[{"plural":"arts","chinese":"美术","english":"art","examples":["She majors in art at college.","Art can express people''s emotions."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["He is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一种","english":"an","examples":["I have an apple.","She wants an orange."],"phonetic":"/æn/","partOfSpeech":"冠词"},{"plural":"arts","chinese":"艺术","english":"art","examples":["Music is a form of art.","We should appreciate different kinds of arts."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"}],"examPoints":{"points":["不定冠词a/an的用法","系动词be的主谓一致","抽象名词的可数与不可数用法"],"explanations":["不定冠词a用于以辅音音素开头的单词前，an用于以元音音素开头的单词前。本句中art以元音音素/ɑː/开头，所以使用an。","系动词be的形式要和主语保持主谓一致，本句主语Art是第三人称单数，所以使用be动词的第三人称单数形式is。","art表示“美术、艺术（泛指）”时是不可数名词；表示“一种艺术形式、某类艺术”时是可数名词，本句中第二个art表示“一种艺术形式”，是可数名词，所以前面加an。"]},"sentenceWithHints":"美术 是 一种 艺术"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1344, '{"words":[{"plural":"arts","chinese":"美术","english":"art","examples":["She is good at art.","Art can make our life more colorful."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"},{"chinese":"培养","english":"cultivate","examples":["Reading can cultivate our taste.","We should cultivate good habits from childhood."],"phonetic":"/ˈkʌltəveɪt/","pastTense":"cultivated","thirdPerson":"cultivates","partOfSpeech":"动词","pastParticiple":"cultivated","presentParticiple":"cultivating"},{"chinese":"审美","english":"aesthetic","examples":["We need to improve our aesthetic taste.","This design has a unique aesthetic value."],"phonetic":"/esˈθetɪk/","partOfSpeech":"形容词"},{"plural":"abilities","chinese":"能力","english":"ability","examples":["He has the ability to speak three languages.","We should develop our practical abilities."],"phonetic":"/əˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["主谓一致","形容词作定语","抽象名词的用法"],"explanations":["本句主语“美术（art）”是抽象名词，属于第三人称单数，所以谓语动词“培养（cultivate）”要用第三人称单数形式cultivates，这是初中阶段主谓一致的核心考点之一。","“审美”对应的英文aesthetic是形容词，在句中用来修饰名词“能力（ability）”，作定语，这是形容词的基本用法，初中阶段需要掌握形容词修饰名词的位置和功能。","“美术（art）”和“能力（ability）”都属于抽象名词，抽象名词一般表示抽象概念，通常不可数，但表示不同种类或具体表现时可变为可数名词，本句中art表示学科概念，为不可数抽象名词，ability表示具体的能力范畴，此处为可数名词单数，初中阶段需要区分抽象名词的可数与不可数用法。"]},"sentenceWithHints":"美术 培养 审美 能力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1345, '{"words":[{"plural":"arts","chinese":"美术","english":"art","examples":["Art is my favorite subject.","She studies visual arts at school."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me watch TV after homework.","He lets his dog run in the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["The teacher told us a story.","Please wait for us."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"创造","english":"create","examples":["We can create a better world.","She created a beautiful painting."],"phonetic":"/kriˈeɪt/","pastTense":"created","thirdPerson":"creates","partOfSpeech":"动词","pastParticiple":"created","presentParticiple":"creating"},{"plural":"beauties","chinese":"美","english":"beauty","examples":["We should appreciate the beauty of nature.","The beauty of the song made her cry."],"phonetic":"/ˈbjuːti/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","抽象名词的使用","动词第三人称单数变化"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中let us create beauty即符合该结构。","“美”在这里表示抽象概念，对应的英文beauty是抽象名词，通常不可数，但表示“美好的人或事物”时可作可数名词，本句中是抽象用法，使用单数形式。","主语Art是第三人称单数，一般现在时中，谓语动词let需要变为第三人称单数形式lets，这是一般现在时主谓一致的基本规则。"]},"sentenceWithHints":"美术 让 我们 创造 美"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1346, '{"words":[{"plural":"arts","chinese":"美术","english":"art","examples":["Art is my favorite subject.","She studies visual arts at college."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The movie is very exciting.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有趣","english":"interesting","examples":["This book is interesting.","We had an interesting talk."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词的用法","副词修饰形容词的用法","主系表结构的运用"],"explanations":["表示学科的art（美术）属于不可数名词，作主语时视为第三人称单数，因此搭配系动词is。当art表示“多种艺术形式”时，可作可数名词，复数形式为arts。","副词very用来修饰形容词，放在形容词之前，用于加强形容词的语气，本句中very用来强化interesting的程度，表达“非常有趣”的含义。","本句是典型的主系表结构，主语为Art，系动词为is，表语由副词very修饰的形容词interesting构成，用来描述主语的特征，这是初中阶段需要掌握的基础句子结构。"]},"sentenceWithHints":"美术 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1348, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"欣赏","english":"appreciate","examples":["I appreciate your help.","We appreciate the beautiful scenery."],"phonetic":"/əˈpriːʃieɪt/","pastTense":"appreciated","thirdPerson":"appreciates","partOfSpeech":"动词","pastParticiple":"appreciated","presentParticiple":"appreciating"},{"plural":"paintings","chinese":"画作","english":"painting","examples":["There are many beautiful paintings in the museum.","She is good at creating paintings."],"phonetic":"/ˈpeɪntɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词复数","动名词作宾语"],"explanations":["like作为动词，常见用法有like to do sth.（表示偶尔、具体的喜欢做某事）和like doing sth.（表示长期、习惯性的喜欢做某事），本句中用like doing sth.表达习惯性的喜好。","painting是可数名词，当表示一类事物时，常用复数形式paintings，不需要加不定冠词或定冠词来泛指。","在like等表示喜好的动词后面，动词需要用动名词形式（即动词+ing）作宾语，所以appreciate要变成appreciating。"]},"sentenceWithHints":"我 喜欢 欣赏 画作"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1349, '{"words":[{"plural":"arts","chinese":"美术","english":"art","examples":["She is good at art.","Art can make our life colorful."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"},{"chinese":"让","english":"give","examples":["My mom gives me a gift on my birthday.","He gives his seat to the old man."],"phonetic":"/ɡɪv/","pastTense":"gave","thirdPerson":"gives","partOfSpeech":"动词","pastParticiple":"given","presentParticiple":"giving"},{"chinese":"我","english":"me","examples":["Please give me a pen.","She helps me with my homework."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"创造力","english":"creativity","examples":["Creativity is very important for artists.","We need to develop our creativity."],"phonetic":"/ˌkriːeɪˈtɪvəti/","partOfSpeech":"名词"}],"examPoints":{"points":["动词第三人称单数形式","名词的用法","双宾语结构"],"explanations":["当主语是第三人称单数（本句中Art是第三人称单数名词）时，一般现在时的动词要使用第三人称单数形式，give的第三人称单数是gives。","creativity是不可数名词，表达“创造力”这一抽象概念，不需要变复数，在句中作宾语，补充说明“我”拥有的内容。","give sb. sth.是常见的双宾语结构，其中sb.是间接宾语，sth.是直接宾语，本句中me是间接宾语，creativity是直接宾语，用来表示“给某人某物”，在本句语境中引申为“使某人拥有某物”。"]},"sentenceWithHints":"美术 让 我 有 创造力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1350, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"会","english":"will","examples":["I will go to school tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing football."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"arts","chinese":"美术","english":"art","examples":["She is good at art.","Art is an important subject."],"phonetic":"/ɑːrt/","partOfSpeech":"名词"}],"examPoints":{"points":["一般将来时的表达","不可数名词与可数名词的用法"],"explanations":["一般将来时可以用“will + 动词原形”的结构来表达，表示将来要发生的动作或存在的状态。本句中“会热爱”表达将来的意愿，所以使用“will love”的结构。","art表示“美术、艺术”这一抽象概念时，通常作为不可数名词使用，前面不需要加冠词；当表示“多种艺术形式”时，可作为可数名词使用复数形式arts。本句中art指美术学科这一抽象概念，所以用原形。"]},"sentenceWithHints":"我 会 热爱 美术"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1351, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"提高","english":"improve","examples":["You need to improve your English.","The weather is improving day by day."],"phonetic":"/ɪmˈpruːv/","pastTense":"improved","thirdPerson":"improves","partOfSpeech":"动词","pastParticiple":"improved","presentParticiple":"improving"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"arts","chinese":"美术","english":"art","examples":["She is good at art.","The museum has many amazing arts."],"phonetic":"/ɑːrt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"levels","chinese":"水平","english":"level","examples":["His English level is very high.","We need to reach a higher level."],"phonetic":"/ˈlevəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","形容词性物主代词的使用","及物动词improve的用法"],"explanations":["一般将来时用来表示将来要发生的动作或存在的状态，结构“will + 动词原形”是最基础的一般将来时表达，本句中“会提高”表示将来的动作，所以用“I will improve...”的结构。","形容词性物主代词my用来修饰名词，表明所属关系，本句中my修饰“art level”，说明是“我的美术水平”，形容词性物主代词后面必须接名词，不能单独使用。","improve作为及物动词时，后面可以直接接名词作宾语，本句中improve后接“my art level”作宾语，表示“提高美术水平”，同时它也可以作不及物动词，表示“改进、变好”。"]},"sentenceWithHints":"我 会 提高 我的 美术 水平"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1352, '{"words":[{"plural":"physical educations","chinese":"体育","english":"physical education","examples":["We have physical education twice a week.","Physical education helps students stay active."],"phonetic":"/ˌfɪzɪkl ˌedʒuˈkeɪʃn/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her sister."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["My mother bought me a gift.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"健康","english":"healthy","examples":["Eating vegetables keeps you healthy.","She leads a healthy lifestyle."],"phonetic":"/ˈhelθi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作宾语补足语","第三人称单数动词变化"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，表示“使……处于某种状态”，本句中“make me healthy”就是“使我健康”的意思。","在“make + 宾语 + 宾语补足语”的结构中，宾语补足语可以由形容词来充当，用来补充说明宾语的状态，本句中healthy作为形容词补充说明“我”的状态是健康的。","当句子主语是第三人称单数（本句中主语physical education是不可数名词，视为第三人称单数）时，一般现在时的谓语动词要使用第三人称单数形式，make的第三人称单数形式是makes。"]},"sentenceWithHints":"体育 让 我 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1353, '{"words":[{"plural":"physical educations","chinese":"体育","english":"physical education","examples":["Physical education is an important part of school life.","We have physical education three times a week."],"phonetic":"/ˈfɪzɪkəl ˌedʒuˈkeɪʃn/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for her sister."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["My mother bought me a gift.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"强壮","english":"strong","examples":["He is strong enough to lift the box.","Regular exercise keeps you strong."],"phonetic":"/strɔːŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作宾语补足语","第三人称单数谓语动词变化"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me strong”即表示“使我强壮”。","在“make + 宾语 + 宾补”的结构中，形容词可以充当宾语补足语，用来补充说明宾语的状态，本句中strong补充说明宾语me的身体状态。","当句子主语是第三人称单数时，一般现在时中的谓语动词需要使用第三人称单数形式。本句主语Physical education是单数概念，所以动词make要变为makes。"]},"sentenceWithHints":"体育 让 我 强壮"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1354, '{"words":[{"plural":"","chinese":"体育","english":"physical education","examples":["Physical education is an important part of school life.","We have physical education class twice a week."],"phonetic":"/ˈfɪzɪkəl ˌedʒuˈkeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"培养","english":"cultivate","examples":["Reading can cultivate your mind.","Schools should cultivate students'' creativity."],"phonetic":"/ˈkʌltɪveɪt/","pastTense":"cultivated","thirdPerson":"cultivates","partOfSpeech":"动词","pastParticiple":"cultivated","presentParticiple":"cultivating"},{"plural":"teams","chinese":"团队","english":"team","examples":["Our team won the game.","She is a member of the school basketball team."],"phonetic":"/tiːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"spirits","chinese":"精神","english":"spirit","examples":["We need to show team spirit.","The festival is full of joyful spirits."],"phonetic":"/ˈspɪrɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词短语的用法","动词第三人称单数形式","名词短语的固定搭配"],"explanations":["本句中“团队精神”对应的英文“team spirit”是不可数名词短语，在句中作宾语，无需添加冠词或变为复数形式，用来表示一种抽象的精神概念。","句子主语“Physical education”是单数概念的名词短语，作主语时谓语动词需要使用第三人称单数形式，“cultivate”的第三人称单数是在词尾加-s，即“cultivates”。","“体育”对应的固定英文表达是“physical education”，属于固定的名词短语搭配；“团队精神”对应的“team spirit”也是英语中常用的固定名词短语，需要整体记忆和使用。"]},"sentenceWithHints":"体育 培养 团队 精神"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1355, '{"words":[{"plural":"physical educations","chinese":"体育","english":"physical education","examples":["Physical education is a required course in our school.","We have physical education twice a week."],"phonetic":"/ˈfɪzɪkəl ˌedʒuˈkeɪʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The movie is very exciting.","She runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有趣","english":"interesting","examples":["This book is interesting.","We had an interesting talk."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["学科类名词的英文表达","副词修饰形容词的用法","主系表句型的应用"],"explanations":["“体育”对应的标准英文表达为“physical education”，在日常语境中也可缩写为“PE”，属于初中阶段需要掌握的学科类核心名词。","副词“very”用来修饰形容词，放在形容词之前，用于加强形容词的语气，本句中用来强调“有趣”的程度，这是初中阶段副词的基础用法之一。","本句是典型的主系表句型，结构为“主语（physical education）+系动词（is）+表语（very interesting）”，表语用来描述主语的特征，这是初中英语五大基本句型中需要重点掌握的句型。"]},"sentenceWithHints":"体育 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1358, '{"words":[{"plural":"physical educations","chinese":"体育","english":"physical education","examples":["We have physical education every Friday.","Physical education is good for our health."],"phonetic":"/ˈfɪzɪkəl ˌedʒuˈkeɪʃn/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"充满","english":"full of","examples":["The box is full of books.","Her eyes are full of tears."],"phonetic":"/fʊl əv/","partOfSpeech":"短语"},{"plural":"energies","chinese":"活力","english":"energy","examples":["I have no energy to work today.","Children are full of energy."],"phonetic":"/ˈenərdʒi/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词make的用法","固定短语full of的搭配","可数/不可数名词的使用"],"explanations":["make作为使役动词，常见结构为make sb.+adj./介词短语，表示“使某人处于某种状态”。本句中主语“体育”是第三人称单数，一般现在时中谓语动词make要使用第三人称单数形式makes。","full of是固定介词短语，意为“充满……”，常与be动词或使役动词搭配，用来描述人或事物的状态，后接名词或代词。","energy表示“活力、精力”时多为不可数名词，在表示“不同类型的能量”时可作可数名词。本句中表示“活力”，用作不可数名词，不需要变复数。"]},"sentenceWithHints":"体育 让 我 充满 活力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1359, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing basketball."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"physical educations","chinese":"体育","english":"physical education","examples":["We have physical education every week.","Physical education is important for health."],"phonetic":"/ˈfɪzɪkəl ˌedʒuˈkeɪʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["一般将来时的表达","学科类名词的翻译"],"explanations":["一般将来时可以用“will + 动词原形”的结构表达将来要发生的动作或存在的状态，本句中“会热爱”表示将来的意愿，所以使用“will love”的结构。","“体育”对应的英文正式表达是“physical education”，常缩写为PE，属于学科类名词，在句中作宾语，此类名词通常为不可数或复数形式表示泛指的学科内容。"]},"sentenceWithHints":"我 会 热爱 体育"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1360, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am from China."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"坚持","english":"insist on","examples":["He insists on walking to school every day.","She insisted on helping me clean the room."],"phonetic":"/ɪnˈsɪst ɑːn/","pastTense":"insisted on","thirdPerson":"insists on","partOfSpeech":"动词","pastParticiple":"insisted on","presentParticiple":"insisting on"},{"chinese":"锻炼","english":"exercise","examples":["I exercise for an hour every morning.","She is exercising in the gym now."],"phonetic":"/ˈeksərsaɪz/","pastTense":"exercised","thirdPerson":"exercises","partOfSpeech":"动词","pastParticiple":"exercised","presentParticiple":"exercising"},{"plural":"bodies","chinese":"身体","english":"body","examples":["We need to keep our body healthy.","Yoga is good for the body and mind."],"phonetic":"/ˈbɑːdi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","insist on的固定搭配","动名词作介词宾语"],"explanations":["一般将来时表示将来要发生的动作或存在的状态，will + 动词原形是其基本结构，本句中用will来表达“会（将要）”的将来含义，符合初中一年级对一般将来时的考查要求。","insist on是固定动词短语，意为“坚持”，后接名词、代词或动名词，是初中阶段需要掌握的固定搭配，在本句中用来对应中文的“坚持”。","介词on后面需要接名词性成分，当接动词时，要将动词变为动名词形式（即动词加-ing），所以exercise要变为exercising，这是初中阶段介词后接动名词的基础知识点。"]},"sentenceWithHints":"我 会 坚持 锻炼 身体"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1361, '{"words":[{"chinese":"品德","english":"moral","examples":["Moral values are important.","He has high moral standards."],"phonetic":"/ˈmɔːrəl/","partOfSpeech":"形容词"},{"plural":"educations","chinese":"教育","english":"education","examples":["Education is the key to success.","She received a good education."],"phonetic":"/ˌedʒuˈkeɪʃn/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"重要","english":"important","examples":["It is important to study hard.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"}],"examPoints":{"points":["形容词作定语","副词修饰形容词","主系表句型"],"explanations":["形容词moral用来修饰名词education，构成名词短语moral education，在句中作主语，这是形容词作定语的常见用法，用于说明被修饰名词的属性。","副词very用来修饰形容词important，用来加强形容词的语气，表示程度，这是副词修饰形容词的基本用法，初中阶段需要掌握常见程度副词对形容词的修饰。","本句是典型的主系表句型，主语是moral education，系动词是is，表语是very important，用来描述主语的特征，这是初中阶段需要掌握的基础句型之一。"]},"sentenceWithHints":"品德 教育 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1362, '{"words":[{"chinese":"品德","english":"moral","examples":["Moral values are important.","He has strong moral principles."],"phonetic":"/ˈmɔːrəl/","partOfSpeech":"形容词"},{"plural":"educations","chinese":"教育","english":"education","examples":["Education is the key to success.","She received a good education."],"phonetic":"/ˌedʒuˈkeɪʃn/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for us."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some water."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"成为","english":"become","examples":["I want to become a doctor.","She became a famous singer."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"chinese":"更好的","english":"better","examples":["This book is better than that one.","She is a better cook now."],"phonetic":"/ˈbetər/","partOfSpeech":"形容词"},{"chinese":"的","english":"","examples":["The color of the sky is blue.","This is my father''s car."],"phonetic":"","partOfSpeech":"助词"},{"plural":"people","chinese":"人","english":"people","examples":["Many people like coffee.","People should help each other."],"phonetic":"/ˈpiːpl/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词make的用法","形容词比较级的使用","集体名词people的用法"],"explanations":["make作为使役动词，常见结构为make sb. do sth.，表示“使某人做某事”，本句中make us better people是其拓展用法，意为“使我们成为更好的人”，此处省略了动词原形become，符合make的使役用法逻辑；同时主语Moral education是第三人称单数，所以make要用第三人称单数形式makes。","better是good的比较级，用于两者之间的比较，本句中是将现在的“我们”和之前的“我们”进行对比，表达“更好的”含义，用来修饰名词people。","people是集体名词，本身即可表示复数含义，指“人们、人类”，不需要加-s来变复数，在本句中用来指代“我们”这类群体。"]},"sentenceWithHints":"品德 教育 让 我们 成为 更好 的 人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1363, '{"words":[{"plural":"","chinese":"品德","english":"moral","examples":["Moral values are important for everyone.","We should follow moral principles."],"phonetic":"/ˈmɔːrəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"educations","chinese":"教育","english":"education","examples":["Education is the key to success.","She received a good education."],"phonetic":"/ˌedʒuˈkeɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"培养","english":"cultivate","examples":["We should cultivate good habits from childhood.","The school cultivates students'' creativity."],"phonetic":"/ˈkʌltɪveɪt/","pastTense":"cultivated","thirdPerson":"cultivates","partOfSpeech":"动词","pastParticiple":"cultivated","presentParticiple":"cultivating"},{"plural":"","chinese":"道德","english":"moral","examples":["He has a strong moral sense.","The story teaches us a moral lesson."],"phonetic":"/ˈmɔːrəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"qualities","chinese":"品质","english":"quality","examples":["Honesty is a good quality.","She has many excellent qualities."],"phonetic":"/ˈkwɑːləti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词作定语","动词第三人称单数形式","可数名词复数形式"],"explanations":["在英语中，形容词可以放在名词前作定语，用来修饰名词，本句中moral分别修饰education和qualities，说明教育和品质的属性是和道德相关的。","当句子主语是第三人称单数（本句中主语Moral education是不可数名词短语，视为第三人称单数）时，一般现在时的动词要使用第三人称单数形式，规则动词通常在词尾加-s，cultivate的第三人称单数形式是cultivates。","可数名词表示泛指的一类事物时，通常使用复数形式，quality是可数名词，此处表示各类道德品质，所以使用复数形式qualities，规则可数名词变复数以辅音字母加y结尾的，变y为i再加-es。"]},"sentenceWithHints":"品德 教育 培养 道德 品质"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1364, '{"words":[{"plural":"moralities","chinese":"品德","english":"morality","examples":["Morality is an important part of society.","We should always uphold morality."],"phonetic":"/məˈræləti/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","This book is very interesting."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"be","examples":["There is a cat on the chair.","She is a doctor."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"意义","english":"meaningful","examples":["This is a meaningful experience.","Her words are very meaningful."],"phonetic":"/ˈmiːnɪŋfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["系动词be的用法","副词修饰形容词的用法","抽象名词的使用"],"explanations":["本句中主语“品德（morality）”是第三人称单数的抽象名词，作主语时对应的系动词be要用第三人称单数形式is，符合“第三人称单数主语+is+表语”的主系表结构规则。","副词very用来修饰形容词meaningful，用来加强形容词的语气，这是副词修饰形容词的常见用法，在初中阶段需要掌握副词对形容词的修饰逻辑，即副词通常放在形容词之前来增强或限定其程度。","“品德（morality）”是抽象名词，这类名词表示抽象概念，一般不可数，在句子中作主语时视为第三人称单数，初中阶段需要区分抽象名词和具体名词的用法差异，了解抽象名词在主系表结构中的使用方式。"]},"sentenceWithHints":"品德 很 有 意义"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1365, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"要","english":"want","examples":["I want to go home.","She wants a new bike."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"做","english":"be","examples":["I want to be a doctor.","He is being very quiet today."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一个","english":"a","examples":["I have a cat.","She is a nice girl."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"with","examples":["a girl with long hair","a house with a garden"],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"道德","english":"moral","examples":["He is a moral man.","We should follow moral rules."],"phonetic":"/ˈmɔːrəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["a red apple","the book on the desk"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"people/persons","chinese":"人","english":"person","examples":["He is a kind person.","There are five people in my family."],"phonetic":"/ˈpɜːrsn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["want to do sth. 固定搭配","不定冠词a的用法","形容词作定语的用法"],"explanations":["want to do sth. 是初中阶段核心固定搭配，意为“想要做某事”，表示主语的意愿，其中to后面接动词原形，本句中to be就是符合该结构的用法。","不定冠词a用于可数名词单数前，当名词或其前的形容词以辅音音素开头时使用，本句中moral以辅音音素开头，所以用a来修饰person。","形容词可以放在可数名词单数或复数前作定语，用来修饰、限定名词的特征，本句中moral放在person前，用来描述“人”具备“有道德的”这一特征。"]},"sentenceWithHints":"我 要 做 一个 有 道德 的 人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1366, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"要","english":"want","examples":["I want to go home.","She wants a new bike."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"做","english":"be","examples":["I want to be a doctor.","She is a nice girl."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"一个","english":"a","examples":["I have a cat.","He is a good boy."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"with","examples":["a girl with long hair","a house with a garden"],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"characters","chinese":"品德","english":"character","examples":["He has a good character.","The story has many interesting characters."],"phonetic":"/ˈkærəktər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["a red apple","the book on the desk"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"people/persons","chinese":"人","english":"person","examples":["He is a kind person.","There are five people in my family."],"phonetic":"/ˈpɜːrsn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["want to do 固定搭配","介词with表属性的用法","不定冠词a的使用"],"explanations":["want to do sth是初中阶段核心固定搭配，意为“想要做某事”，其中to后面接动词原形，用来表达主语的意愿。本句中用want to be来表达“想要成为”的意愿。","介词with在这里用来描述人或事物的属性、特征，意为“具有，带有”，常用来后置修饰名词，本句中with good character用来修饰person，说明“具有良好品德的”人。","不定冠词a用于可数名词单数前，当名词或修饰名词的形容词以辅音音素开头时使用。本句中person是以辅音音素开头的可数名词单数，所以前面用a来表示“一个”。"]},"sentenceWithHints":"我 要 做 一个 有 品德 的 人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1367, '{"words":[{"plural":"moralities","chinese":"品德","english":"morality","examples":["Morality is important in society.","He has a strong sense of morality."],"phonetic":"/məˈræləti/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me with this."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"受人","english":"respected by others","examples":["He is respected by others for his honesty.","She wants to be respected by others."],"phonetic":"/rɪˈspektɪd baɪ ˈʌðərz/","partOfSpeech":"其他"},{"chinese":"尊重","english":"respect","examples":["We should respect our elders.","She is respected by everyone in the class."],"phonetic":"/rɪˈspekt/","pastTense":"respected","thirdPerson":"respects","partOfSpeech":"动词","pastParticiple":"respected","presentParticiple":"respecting"}],"examPoints":{"points":["使役动词make的用法","过去分词作宾语补足语","不可数名词与可数名词的区分"],"explanations":["make作为使役动词，常见结构为make + 宾语 + 宾语补足语，本句中me是宾语，respected是宾语补足语，表示“使我处于被尊重的状态”。当主语是第三人称单数时，make要变为makes。","过去分词respected在这里作宾语补足语，与宾语me构成被动关系，说明“我”是“被尊重”的对象，这是初中阶段需要掌握的非谓语动词的用法之一。","morality作为抽象名词，属于不可数名词，在表示泛指时不需要加冠词；当表示不同的道德体系时，可作可数名词，复数形式为moralities，本句中表示抽象的品德，用作不可数名词。"]},"sentenceWithHints":"品德 让 我 受人 尊重"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1368, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"注重","english":"pay attention to","examples":["You should pay attention to your handwriting.","We must pay attention to traffic rules."],"phonetic":"/peɪ əˈtenʃn tuː/","pastTense":"paid attention to","thirdPerson":"pays attention to","partOfSpeech":"动词","pastParticiple":"paid attention to","presentParticiple":"paying attention to"},{"plural":"","chinese":"品德","english":"moral","examples":["We should follow moral principles.","He is a man with high moral standards."],"phonetic":"/ˈmɔːrəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"cultivations","chinese":"修养","english":"cultivation","examples":["Moral cultivation is important for everyone.","He focuses on the cultivation of his mind."],"phonetic":"/ˌkʌltəˈveɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","固定短语pay attention to的使用","形容词作定语的用法"],"explanations":["一般将来时用来表示将要发生的动作或存在的状态，结构为“will + 动词原形”，本句中“会”表达将来的意愿，所以用will加动词短语pay attention to的原形形式。","pay attention to是初中阶段重点固定短语，意为“注意；注重”，其中to是介词，后面可接名词、代词或动名词，本句中接的是名词短语moral cultivation。","形容词可以放在名词前作定语，用来修饰名词，本句中moral（品德的）是形容词，修饰后面的名词cultivation（修养），构成名词短语moral cultivation，符合“形容词+名词”的定语修饰结构。"]},"sentenceWithHints":"我 会 注重 品德 修养"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1369, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"成为","english":"become","examples":["I want to become a doctor.","She became a famous singer."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"一个","english":"a","examples":["I have a cat.","He is a clever boy."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"characters","chinese":"品德","english":"character","examples":["He has a good character.","The story has many interesting characters."],"phonetic":"/ˈkærəktər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"高尚","english":"noble","examples":["He is a man of noble mind.","She has a noble heart."],"phonetic":"/ˈnoʊbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["a cup of tea","the door of the room"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"people","chinese":"人","english":"person","examples":["He is a kind person.","There are five people in my family."],"phonetic":"/ˈpɜːrsn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","介词with的用法","形容词作定语的用法"],"explanations":["一般将来时表示将来发生的动作或存在的状态，初中阶段常用“will + 动词原形”的结构来表达，本句中“will become”就表示将来会达成的状态，符合一般将来时的用法。","介词with在这里用来表示“具有、带有”的含义，用来修饰前面的名词person，说明这个人所具备的属性，是初中阶段需要掌握的with的重要用法之一。","形容词可以放在名词前作定语修饰名词，也可以和介词搭配后置修饰名词，本句中“noble”是形容词，和with搭配后置修饰person，同时也可以理解为修饰character，用来描述品德的属性，这是形容词修饰名词的常见用法。"]},"sentenceWithHints":"我 会 成为 一个 品德 高尚 的 人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1370, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"今年","english":"this year","examples":["I will go to Beijing this year.","This year is very special for me."],"phonetic":"/ðɪs jɪr/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"十","english":"ten","examples":["I have ten pens.","She is ten years old."],"phonetic":"/ten/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"岁","english":"year old","examples":["He is five years old.","My dog is three years old."],"phonetic":"/jɪr oʊld/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"了","english":"","examples":["I have finished my homework.","She has grown up."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["年龄的英文表达","系动词be的用法","数词的使用"],"explanations":["表达年龄的常用结构为“主语 + be动词 + 数词 + years old”，当数词为1时，用“1 year old”，数词大于1时，year要用复数形式years。本句中年龄是十岁，所以用“ten years old”。","be动词有三种形式：am（用于主语I）、is（用于第三人称单数主语）、are（用于复数主语和you）。本句主语是I，所以搭配be动词am。","描述年龄需要用基数词，基数词用来表示数量，这里用基数词ten表示具体的年龄数值，小学阶段需要掌握1-20的基数词英文表达。"]},"sentenceWithHints":"我 今年 十 岁 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1371, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"上","english":"be in","examples":["She is in fifth grade.","They were in the same class last year."],"phonetic":"/biː ɪn/","pastTense":"was/were in","thirdPerson":"is in","partOfSpeech":"动词","pastParticiple":"been in","presentParticiple":"being in"},{"plural":"","chinese":"三","english":"third","examples":["Today is the third day of the month.","He won the third prize."],"phonetic":"/θɜːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"grades","chinese":"年级","english":"grade","examples":["What grade are you in?","There are six grades in this primary school."],"phonetic":"/ɡreɪd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["年级的英文表达结构","序数词的用法","人称代词与be动词的搭配"],"explanations":["表达“上几年级”的固定英文结构为“be + in + 序数词 + grade”，不能直接用“study”等动词直译，这是小学阶段的常用固定表达。","表示“第几个年级”时，要用序数词，“三”对应的序数词是“third”，序数词用于表示顺序，此处用来明确具体的年级序号。","第一人称代词“I”作主语时，对应的be动词一般现在时形式为“am”，这是人称代词与be动词的基础搭配规则，是小学英语的核心基础知识点。"]},"sentenceWithHints":"我 上 三 年级"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1372, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"birthdays","chinese":"生日","english":"birthday","examples":["Happy birthday to you!","My birthday is in May."],"phonetic":"/ˈbɜːrθdeɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"in","examples":["I live in Beijing.","We have class in the morning."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"六月","english":"June","examples":["June is the sixth month of the year.","It''s hot in June."],"phonetic":"/dʒuːn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词性物主代词的用法","月份前介词的使用","系动词is的搭配"],"explanations":["形容词性物主代词my用来修饰名词，表示所属关系，放在名词前，此处修饰birthday，表明是“我的生日”，小学阶段需要掌握常见的形容词性物主代词如my, your, his, her等。","表示在某个月份时，前面要加介词in，这是时间介词的固定用法，类似的还有in January, in July等，小学阶段需要区分in, on, at在时间表达中的不同使用场景。","句子主语birthday是单数可数名词，所以搭配系动词is构成主系表结构，用来表达“生日在六月”这个状态，小学阶段需要了解主语为单数时be动词用is，主语为复数或you时用are。"]},"sentenceWithHints":"我的 生日 在 六月"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1373, '{"words":[{"chinese":"我","english":"I/my","examples":["I love my family.","My cat is cute."],"phonetic":"/aɪ/ /maɪ/","partOfSpeech":"代词"},{"chinese":"很快","english":"soon","examples":["I will come soon.","The movie will start soon."],"phonetic":"/suːn/","partOfSpeech":"副词"},{"chinese":"就","english":"","examples":["I will go home soon.","He will finish the work soon."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"要","english":"will/be going to","examples":["I will go to school tomorrow.","She is going to have a party."],"phonetic":"/wɪl/ /biː ˈɡoʊɪŋ tuː/","pastTense":"would/was/were going to","thirdPerson":"will/is/are going to","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"过","english":"have/celebrate","examples":["I have a birthday party every year.","We celebrate Christmas with our family."],"phonetic":"/hæv/ /ˈselɪbreɪt/","pastTense":"had/celebrated","thirdPerson":"has/celebrates","partOfSpeech":"动词","pastParticiple":"had/celebrated","presentParticiple":"having/celebrating"},{"plural":"birthdays","chinese":"生日","english":"birthday","examples":["Happy birthday to you!","My birthday is in May."],"phonetic":"/ˈbɜːrθdeɪ/","partOfSpeech":"名词"},{"chinese":"了","english":"","examples":["I have finished my homework.","She has gone to the park."],"phonetic":"","partOfSpeech":"助词"}],"examPoints":{"points":["现在进行时表将来","副词soon的用法","物主代词的使用"],"explanations":["在英语中，一些表示位置移动或即将发生的动作的动词，如come, go, leave等，可以用现在进行时（be + doing）来表示即将发生的将来动作，本句中is coming就表示“即将到来”，对应中文里“就要过生日了”的将来含义。","soon是副词，意思是“很快，不久”，通常放在句末或句首，用来表示动作即将发生的时间，本句中放在句末，说明生日很快就要到了。","物主代词my用来表示所属关系，“我的生日”翻译为my birthday，这里my是形容词性物主代词，用来修饰名词birthday，小学阶段需要掌握形容词性物主代词的基本用法，区分第一人称、第二人称和第三人称的物主代词。"]},"sentenceWithHints":"我 很快 就 要 过 生日 了"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1374, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想要","english":"want","examples":["I want a toy car.","She wants to go home."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"一个","english":"a","examples":["I have a cat.","He is a doctor."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"新","english":"new","examples":["This is a new pen.","She has a new dress."],"phonetic":"/nuː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"schoolbags","chinese":"书包","english":"schoolbag","examples":["My schoolbag is blue.","I put my books in the schoolbag."],"phonetic":"/ˈskuːlbæɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不定冠词a的用法","实义动词want的用法","形容词修饰名词的位置"],"explanations":["不定冠词a用于辅音音素开头的可数名词单数前，用来泛指“一个”，本句中schoolbag是以辅音音素开头的可数名词单数，所以用a来修饰。","实义动词want表示“想要”，主语是第一人称I时，用动词原形want；当主语是第三人称单数时，要变成wants，常见搭配有want sth.（想要某物）、want to do sth.（想要做某事）。","形容词用来修饰名词时，通常放在名词的前面，本句中形容词new放在名词schoolbag前面，用来描述书包的属性，即“新的书包”。"]},"sentenceWithHints":"我 想要 一个 新 书包"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1375, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My pen is red.","This is my cat."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"schoolbags","chinese":"书包","english":"schoolbag","examples":["I have a new schoolbag.","Her schoolbag is pink."],"phonetic":"/ˈskuːlbæɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["The flower is yellow.","He is tall."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"蓝色的","english":"blue","examples":["The sky is blue.","I like blue clothes."],"phonetic":"/bluː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词作表语","系动词be的用法","形容词性物主代词"],"explanations":["形容词可以放在系动词后面作表语，用来描述主语的特征，本句中blue（蓝色的）放在is后面，描述schoolbag（书包）的颜色特征。","系动词be有am、is、are三种形式，当主语是第三人称单数时，要用is，本句主语my schoolbag是第三人称单数，所以使用is。","形容词性物主代词my用来修饰名词，说明名词的所属关系，本句中my修饰schoolbag，表明这个书包是“我的”，形容词性物主代词后面必须跟名词。"]},"sentenceWithHints":"我的 书包 是 蓝色的。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1376, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my cat."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"schoolbags","chinese":"书包","english":"schoolbag","examples":["I put my notebook in my schoolbag.","Her schoolbag is pink."],"phonetic":"/ˈskuːlbæɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"里","english":"in","examples":["The cat is in the box.","There is a toy in the drawer."],"phonetic":"/ɪn/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"there be","examples":["There is a tree in the yard.","There are some apples on the table."],"phonetic":"/ðer biː/","pastTense":"there was/there were","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"很多","english":"many","examples":["There are many birds in the sky.","I have many friends."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["I read a book every night.","These books are new."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["there be 句型的主谓一致","many 的用法","介词 in 表示位置"],"explanations":["there be 句型遵循就近原则，be 动词的单复数由后面紧跟的名词决定。本句中紧跟的名词是复数的 books，所以用 are；如果是单数名词或不可数名词，则用 is。","many 是形容词，用来修饰可数名词的复数形式，说明数量多，不能修饰不可数名词，修饰不可数名词表示“很多”要用 much。本句中 books 是可数名词复数，所以用 many。","介词 in 在这里表示“在……里面”，用来指明物品所在的位置范围，常用来描述物体处于某个容器、空间内部的状态，比如 in the box（在盒子里）、in the room（在房间里）。"]},"sentenceWithHints":"我的 书包 里 有 很多 书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1377, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school by bike."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"背着","english":"carry","examples":["I carry my lunch box to school.","She carries a heavy bag."],"phonetic":"/ˈkæri/","pastTense":"carried","thirdPerson":"carries","partOfSpeech":"动词","pastParticiple":"carried","presentParticiple":"carrying"},{"plural":"schoolbags","chinese":"书包","english":"schoolbag","examples":["My schoolbag is blue.","I put my books in the schoolbag."],"phonetic":"/ˈskuːlbæɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"上学","english":"go to school","examples":["I go to school at 7 o''clock.","He goes to school by bus."],"phonetic":"/ɡoʊ tuː skuːl/","pastTense":"went to school","thirdPerson":"goes to school","partOfSpeech":"动词","pastParticiple":"gone to school","presentParticiple":"going to school"}],"examPoints":{"points":["一般现在时的用法","“carry sth to...”结构","时间状语every day的使用"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句描述“每天上学”的日常行为，主语是第一人称I，所以动词用原形carry和go。当主语是第三人称单数时，动词要变成对应的第三人称单数形式，比如He carries his schoolbag to school every day。","“carry sth to...”是“把某物带到某地”的固定结构，这里表示把书包带到学校，符合日常表达逻辑，类似的结构还有take sth to...，但carry更侧重“背负、搬运”的动作，适合描述背书包的行为。","every day是表示频率的时间状语，意为“每天”，通常放在句末，用来说明动作发生的经常性，在一般现在时的句子中常和这类时间状语搭配，需要注意它和everyday的区别，everyday是形容词，意为“日常的”，比如everyday life（日常生活）。"]},"sentenceWithHints":"我 每天 都 背着 书包 上学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1378, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一个","english":"a","examples":["I need a pen.","He is a doctor."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["She is a good girl.","This is a good book."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"friends","chinese":"好朋友","english":"friend","examples":["Tom is my friend.","We are good friends."],"phonetic":"/frend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词主格的使用","实义动词have的用法","不定冠词a的用法","形容词修饰名词的位置"],"explanations":["人称代词主格I在句中作主语，用于指代说话人自己，在一般现在时中，当主语是I时，实义动词用原形。","实义动词have表示“拥有”，主语是第一人称I、第二人称you或复数主语时用原形have；主语是第三人称单数时用has，其过去式和过去分词均为had。","不定冠词a用于辅音音素开头的可数名词单数前，用来泛指“一个”，本句中friend是以辅音音素开头的可数名词单数，所以用a。","形容词用来修饰名词时，通常放在被修饰的名词前面，本句中good是形容词，修饰后面的名词friend，表达“好的朋友”。"]},"sentenceWithHints":"我 有 一个 好 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1379, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We like playing games."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["Let''s sing together.","We go to school together every day."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"玩","english":"play","examples":["I play football after school.","She plays the piano well."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"}],"examPoints":{"points":["人称代词主格的用法","一般现在时的用法","副词在句中的位置"],"explanations":["人称代词主格we在句中作主语，用来指代说话者及其他人，对应中文的“我们”，在一般现在时中，当主语是第一人称复数we时，谓语动词用原形。","一般现在时用来表示经常性、习惯性的动作或当前的状态，本句描述的是当下或经常性的动作，主语是we（第一人称复数），所以谓语动词play用原形。","副词together是方式副词，通常放在句末，用来修饰动词play，说明动作发生的方式是“一起”，在简单的陈述句中，这类副词常位于句尾。"]},"sentenceWithHints":"我们 一起 玩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1380, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"经常","english":"often","examples":["I often read books.","She often plays football."],"phonetic":"/ˈɔːfn/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["Let''s play together.","We go to school together."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"做","english":"do","examples":["I do my homework every day.","He does his chores after school."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"","chinese":"作业","english":"homework","examples":["I have a lot of homework.","She finishes her homework early."],"phonetic":"/ˈhoʊmwɜːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["频度副词的位置","固定搭配 do homework","人称代词作主语的用法"],"explanations":["频度副词often表示动作发生的频率，在一般现在时的句子中，通常放在实义动词之前，be动词之后。本句中实义动词是do，所以often放在do的前面。","homework是不可数名词，“做作业”的固定英文表达是do homework，不需要在homework前加不定冠词a/an，也没有复数形式。","人称代词we是第一人称复数主格，在句子中作主语，一般现在时中，当主语是第一人称复数（we）、第二人称（you）以及第三人称复数时，实义动词用原形，本句中主语是we，所以动词用do的原形。"]},"sentenceWithHints":"我们 经常 一起 做 作业"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1381, '{"words":[{"chinese":"他","english":"he","examples":["He is my brother.","He likes playing football."],"phonetic":"/hiː/","partOfSpeech":"代词"},{"chinese":"学习","english":"study","examples":["I study English every day.","She studies hard for the test."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"好","english":"well","examples":["She sings well.","He does his homework well."],"phonetic":"/wel/","partOfSpeech":"副词"}],"examPoints":{"points":["动词第三人称单数变化","副词修饰动词的用法"],"explanations":["当主语是第三人称单数（如he, she, it）且句子是一般现在时时，动词要变成第三人称单数形式。以辅音字母+y结尾的动词study，要把y变i再加-es，即studies。","副词用来修饰动词、形容词或其他副词，说明动作的方式、程度等。本句中well是副词，修饰动词study，说明学习的状态；very是副词，修饰well，加强“好”的程度。"]},"sentenceWithHints":"他 学习 很 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1382, '{"words":[{"plural":"","chinese":"他","english":"he","examples":["He is my brother.","He likes playing football."],"phonetic":"/hiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"帮助","english":"help","examples":["I help my mom clean the room.","She helps me with my homework."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","My teacher teaches me math."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"study","examples":["I study English every day.","She is studying in the library."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"}],"examPoints":{"points":["动词的第三人称单数形式","help的固定搭配用法"],"explanations":["当句子主语是第三人称单数（如he、she、it）时，一般现在时中的谓语动词需要变为第三人称单数形式。规则动词的第三人称单数形式通常在词尾加-s，以s、x、sh、ch、o结尾的加-es，study属于以辅音字母+y结尾的，变y为i加-es；help属于规则动词，直接加-s。本句主语是he，属于第三人称单数，所以help变为helps。","help作为动词，常见的固定搭配是help sb. (to) do sth.，意为“帮助某人做某事”，其中to可以省略。本句中help me study就使用了这个搭配，省略了to，符合小学阶段的学习要求。"]},"sentenceWithHints":"他 帮助 我 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1383, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"也","english":"also","examples":["I also like apples.","She also plays the piano."],"phonetic":"/ˈɔːlsoʊ/","partOfSpeech":"副词"},{"chinese":"帮助","english":"help","examples":["I help my mom cook.","He helps me with my homework."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"chinese":"他","english":"him","examples":["I give him a gift.","She teaches him math."],"phonetic":"/hɪm/","partOfSpeech":"代词"}],"examPoints":{"points":["副词also的用法","人称代词宾格的使用","一般现在时动词形式"],"explanations":["also作为副词，表示“也”，在一般现在时的陈述句中，通常放在实义动词之前，be动词、情态动词之后。本句中实义动词是help，所以also放在help前面。","人称代词分为主格和宾格，当代词在动词后面作宾语时，要用宾格形式。“他”在动词help后面作宾语，所以用宾格him，而不是主格he。","一般现在时中，当主语是第一人称I时，实义动词用原形。本句主语是I，所以动词help用原形，不需要变形。"]},"sentenceWithHints":"我 也 帮助 他"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1384, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"are","examples":["You are my classmate.","They are playing games."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"最好的","english":"best","examples":["She is my best friend.","This is the best cake I''ve ever eaten."],"phonetic":"/best/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a new friend.","We are good friends."],"phonetic":"/frend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与be动词的搭配","形容词最高级的用法","可数名词复数形式"],"explanations":["人称代词we是第一人称复数，在一般现在时中，搭配的be动词为are，这是小学阶段需要掌握的be动词基础搭配规则。","best是形容词good的最高级形式，用于表示三者及以上的人或物中程度最高的，此处用来修饰friend，体现朋友间的亲密程度，小学阶段需要掌握常见形容词的最高级形式。","friend是可数名词，当表示多个朋友时需要使用复数形式friends，规则可数名词变复数一般直接在词尾加-s，这是小学阶段可数名词复数的基础知识点。"]},"sentenceWithHints":"我们 是 最好的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1386, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I can sing."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can dance."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"画","english":"draw","examples":["Draw a cat, please.","He draws well."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"flowers","chinese":"花","english":"flower","examples":["I like red flowers.","There are many flowers in the garden."],"phonetic":"/ˈflaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","可数名词复数形式","实义动词与情态动词的搭配"],"explanations":["情态动词can表示具备某种能力，后面要接动词原形，没有人称和数的变化，过去式为could，本句用来表达“我具备画画的能力”。","可数名词表示泛指一类事物时，要用复数形式，“花”在这里是泛指这类植物，所以用flower的复数flowers，规则名词变复数一般直接加-s。","情态动词can后面必须接动词原形，不能接动词的其他形式，本句中can后面接draw的原形，符合语法规则。"]},"sentenceWithHints":"我 会 画 花"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1387, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I can sing songs."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim fast.","She can speak English well."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"画","english":"draw","examples":["I can draw a cat.","He draws pictures every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"trees","chinese":"树","english":"tree","examples":["There are many trees in the park.","I can draw a big tree."],"phonetic":"/triː/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","可数名词复数形式","实义动词在情态动词后的形式"],"explanations":["情态动词can表示“能够、会”，后接动词原形，用来表达具备某种能力，没有人称和数的变化，过去式为could。本句中用can表示“我具备画画的能力”。","可数名词表示一类事物时，常用复数形式。tree是可数名词，其复数形式为规则变化，直接在词尾加-s，所以翻译中用trees表示“树”这一类事物。","实义动词在情态动词（如can）后面必须使用原形，不能随主语变化形式，本句中draw用原形就是因为前面有情态动词can。"]},"sentenceWithHints":"我 会 画 树"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1388, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim fast.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"画","english":"draw","examples":["I can draw a dog.","She draws pictures every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"cats","chinese":"猫","english":"cat","examples":["I have a cat.","Cats like fish."],"phonetic":"/kæt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","可数名词复数的用法"],"explanations":["情态动词can表示具备某种能力，后面要接动词原形，没有人称和数的变化，过去式为could。本句中用can表达“具备画画的能力”，后面接动词原形draw。","可数名词表示一类事物时，可以用复数形式，规则名词变复数一般在词尾加-s。本句中用cats表示猫这一类动物，体现了可数名词复数表泛指的用法。"]},"sentenceWithHints":"我 会 画 猫"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1389, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"画","english":"draw","examples":["I draw a cat every day.","He is drawing a picture now."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"dogs","chinese":"狗","english":"dog","examples":["I have a dog.","Dogs are cute animals."],"phonetic":"/dɔːɡ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","可数名词复数的用法","实义动词在情态动词后的形式"],"explanations":["情态动词can表示“能够、会”，后接动词原形，用来表达具备某种能力，过去式为could，没有人称和数的变化，本句用来表达“我具备画画的能力”。","可数名词表示一类事物时，常用复数形式，dog是可数名词，其复数形式直接加-s，此处用dogs表示“狗”这一类动物，而非单指一只狗。","实义动词在情态动词（如can）后面必须使用原形，所以本句中draw用原形，不需要根据主语变化形式。"]},"sentenceWithHints":"我 会 画 狗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1391, '{"words":[{"chinese":"画画","english":"draw","examples":["I like to draw pictures.","She draws a cat every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"让","english":"make","examples":["The story makes me cry.","She makes a cake for us."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gives me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"很","english":"very","examples":["She is very tall.","I am very hungry."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","They are happy to see you."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","make的使役用法","副词修饰形容词"],"explanations":["当表示某个动作作为主语时，要把动词变成动名词形式（即动词+ing），本句中“画画”作为主语，所以用drawing，动名词作主语时，谓语动词要用第三人称单数形式。","make作为使役动词，常见用法是“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me very happy”就是“让我很快乐”的对应表达，符合这个结构。","副词very用来修饰形容词happy，放在形容词前面，用来加强形容词的语气，说明快乐的程度，这是小学阶段副词修饰形容词的基础用法。"]},"sentenceWithHints":"画画 让 我 很 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1395, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"经常","english":"often","examples":["I often play football after school.","She often helps her mom cook."],"phonetic":"/ˈɔːfn/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"听","english":"listen","examples":["Listen to the teacher carefully.","He listens to the radio every morning."],"phonetic":"/ˈlɪsn/","pastTense":"listened","thirdPerson":"listens","partOfSpeech":"动词","pastParticiple":"listened","presentParticiple":"listening"},{"plural":"","chinese":"音乐","english":"music","examples":["I like pop music.","She is learning to play music."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["频度副词的使用","不及物动词listen的搭配","一般现在时的用法"],"explanations":["频度副词often表示“经常”，通常放在主语之后，实义动词之前，用来描述动作发生的频率，符合小学阶段对频度副词位置的考查要求。","listen是不及物动词，后面接宾语时必须加介词to，构成固定搭配listen to，这是小学阶段需要掌握的动词固定搭配知识点。","本句描述的是经常性、习惯性的动作，所以使用一般现在时。当主语是第一人称I时，实义动词用原形listen；如果主语是第三人称单数，则动词要变成对应的第三人称单数形式listens。"]},"sentenceWithHints":"我 经常 听 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1396, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"mornings","chinese":"早上","english":"morning","examples":["I get up early in the morning.","She drinks milk every morning."],"phonetic":"/ˈmɔːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"也","english":"also","examples":["I also like cats.","She can also play the piano."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"听","english":"listen","examples":["Listen to the teacher carefully.","He listens to music every night."],"phonetic":"/ˈlɪsn/","pastTense":"listened","thirdPerson":"listens","partOfSpeech":"动词","pastParticiple":"listened","presentParticiple":"listening"},{"plural":"","chinese":"音乐","english":"music","examples":["I love music.","We are learning about music at school."],"phonetic":"/ˈmjuːzɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["频度副词also的用法","固定搭配listen to的用法","时间状语的位置"],"explanations":["also是频度副词，意为“也”，在一般现在时的句子中，通常放在实义动词之前，be动词、助动词或情态动词之后。本句中实义动词是listen，所以also放在listen前面。","listen是不及物动词，后面接宾语时必须加介词to，构成固定搭配listen to，意为“听……”，后接人或事物，比如listen to music（听音乐）、listen to me（听我说）。","表示时间的状语in the morning在英语句子中通常可以放在句末，用来说明动作发生的时间，本句中用来修饰listen to music这个动作发生的时间是在早上。"]},"sentenceWithHints":"我 早上 也 听 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1397, '{"words":[{"plural":"evenings","chinese":"晚上","english":"evening","examples":["I read books in the evening.","We will have a party this evening."],"phonetic":"/ˈiːvnɪŋ/","partOfSpeech":"名词"},{"plural":"","chinese":"我","english":"I","examples":["I like cats.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"plural":"","chinese":"也","english":"also","examples":["I also like apples.","She also plays the piano."],"phonetic":"/ˈɔːlsoʊ/","partOfSpeech":"副词"},{"chinese":"听","english":"listen","examples":["Listen to the teacher carefully.","She listens to music every night."],"phonetic":"/ˈlɪsn/","pastTense":"listened","thirdPerson":"listens","partOfSpeech":"动词","pastParticiple":"listened","presentParticiple":"listening"},{"plural":"","chinese":"音乐","english":"music","examples":["I love music.","She plays music on weekends."],"phonetic":"/ˈmjuːzɪk/","partOfSpeech":"名词"}],"examPoints":{"points":["副词also的位置","固定搭配listen to","时间状语的位置"],"explanations":["在一般现在时的句子中，副词also通常放在实义动词之前，be动词、助动词之后。本句中实义动词是listen，所以also放在listen前面。","listen是不及物动词，后面接宾语时需要加介词to，构成固定搭配listen to+宾语，表示“听……”，不能直接说listen music。","英语中表示时间的状语可以放在句首或句尾，本句参考翻译将in the evening放在句尾，这是英语中时间状语常见的摆放位置，和中文时间状语在前的语序有区别，需要注意中英语序的转换。"]},"sentenceWithHints":"晚上 我 也 听 音乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1398, '{"words":[{"plural":"musics","chinese":"音乐","english":"music","examples":["I love listening to music.","Music can make people relaxed."],"phonetic":"/ˈmjuːzɪk/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["My mom makes delicious food.","The news made me sad."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"心情","english":"feel","examples":["I feel tired today.","She feels happy."],"phonetic":"/fiːl/","pastTense":"felt","thirdPerson":"feels","partOfSpeech":"动词","pastParticiple":"felt","presentParticiple":"feeling"},{"chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"好","english":"good","examples":["This is a good book.","She has a good idea."],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作表语","人称代词宾格的使用"],"explanations":["make作为使役动词，常见用法为make sb. do sth.，表示“让某人做某事”，这里的动词要用原形，本句中make me feel good就是这个结构，符合小学阶段对使役动词基础用法的考查。","good是形容词，在feel之后作表语，用来描述主语的状态，小学阶段需要掌握形容词在系动词或感官动词后作表语的基本用法。","“我”在本句中作make的宾语，所以要用宾格形式me，小学三年级需要区分人称代词主格和宾格的基本用法，主格作主语，宾格作宾语。"]},"sentenceWithHints":"音乐 让 我 心情 很 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1399, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"chinese":"一","english":"a","examples":["I have a pen.","This is a dog."],"phonetic":"/ə/","partOfSpeech":"冠词"},{"chinese":"张","english":"","examples":["一张纸","一张照片"],"phonetic":"","partOfSpeech":"量词"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is big.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"},{"plural":"maps","chinese":"地图","english":"map","examples":["This is a map of China.","I have two maps."],"phonetic":"/mæp/","partOfSpeech":"名词"}],"examPoints":{"points":["人称代词与谓语动词的搭配","不定冠词的使用","中文量词的英文表达特点","名词短语的构成"],"explanations":["当主语是第一人称代词I时，谓语动词用have的原形，不需要变形；如果主语是第三人称单数（如he/she/it），则要变为has，这是小学阶段需要掌握的主谓一致基础规则。","不定冠词a用于以辅音音素开头的可数名词单数前，本句中map是以辅音音素/m/开头，所以用a来表示“一张”的泛指概念，这是不定冠词的基础用法。","中文里表示物品数量常需要搭配量词，比如“一张地图”的“张”，但在英文中通常不需要单独翻译量词，直接用不定冠词+可数名词单数即可表达对应的数量含义，这是中英表达的差异点。","“世界地图”在英文中构成名词短语world map，用名词world修饰map，说明map的属性，这种名词作定语的结构是小学阶段需要掌握的名词短语构成方式。"]},"sentenceWithHints":"我 有 一 张 世界 地图"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1400, '{"words":[{"plural":"maps","chinese":"地图","english":"map","examples":["I have a map of China.","The map is on the wall."],"phonetic":"/mæp/","partOfSpeech":"名词"},{"chinese":"在","english":"in","examples":["The cat is in the box.","I live in Beijing."],"phonetic":"/ɪn/","partOfSpeech":"介词"},{"chinese":"我的","english":"my","examples":["My pen is blue.","This is my dog."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"rooms","chinese":"房间","english":"room","examples":["My room is clean.","There are three rooms in the house."],"phonetic":"/ruːm/","partOfSpeech":"名词"},{"chinese":"里","english":"","examples":["The book is in the desk里（此处仅为示例，实际英文无需翻译）","The toy is in the box里（此处仅为示例，实际英文无需翻译）"],"phonetic":"","partOfSpeech":"助词"}],"examPoints":{"points":["介词in的用法","系动词is的使用","名词单数形式"],"explanations":["介词in表示“在……里面”，用于描述物体处于某个空间内部的位置，本句中用来表示地图在房间这个空间里。","系动词is用于第三人称单数主语后，本句主语the map是单数名词，所以搭配is构成主系表结构说明位置。","可数名词单数表示单个事物，本句中map和room都是单数形式，特指某个地图和某个房间，单数可数名词前搭配定冠词the或形容词性物主代词my来限定。"]},"sentenceWithHints":"地图 在 我的 房间 里"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1401, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"经常","english":"often","examples":["I often play football after school.","She often reads books in the evening."],"phonetic":"/ˈɔːfn/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"看","english":"look at","examples":["Look at the blackboard, please.","He is looking at a beautiful bird."],"phonetic":"/lʊk æt/","pastTense":"looked at","thirdPerson":"looks at","partOfSpeech":"动词","pastParticiple":"looked at","presentParticiple":"looking at"},{"plural":"maps","chinese":"地图","english":"map","examples":["This is a map of China.","We use maps to find places."],"phonetic":"/mæp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["频率副词的使用","固定短语look at的用法","定冠词the的特指用法"],"explanations":["频率副词often表示“经常”，一般放在主语之后，实义动词之前，用来描述动作发生的频率，符合小学三年级一般现在时的知识点要求。","look作为不及物动词，后面接宾语时需要加介词at，构成固定短语look at，意为“看（某物）”，是小学阶段需要掌握的常用动词短语。","定冠词the在这里用来特指双方都知道的某张地图，当表示特指的人或事物时，名词前要加the，这是小学阶段冠词的基础知识点。"]},"sentenceWithHints":"我 经常 看 地图"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1402, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"认识","english":"know","examples":["I know your name.","She knows how to swim."],"phonetic":"/noʊ/","pastTense":"knew","thirdPerson":"knows","partOfSpeech":"动词","pastParticiple":"known","presentParticiple":"knowing"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like music.","There are many books on the shelf."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"countries","chinese":"国家","english":"country","examples":["China is a great country.","They have visited many countries."],"phonetic":"/ˈkʌntri/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词many的用法","可数名词的复数变形","动词know的基本用法"],"explanations":["many作为形容词，用于修饰可数名词的复数形式，用来表示数量多，本句中修饰复数名词countries，符合其用法规则。","可数名词country以辅音字母+y结尾，变复数时需要把y改为i再加-es，所以复数形式是countries，这是小学阶段需要掌握的可数名词复数不规则变形规则之一。","know是及物动词，后面可以直接接宾语，在一般现在时中，当主语是第一人称I时，动词用原形know，本句就是一般现在时的陈述句，体现了该动词的基础用法。"]},"sentenceWithHints":"我 认识 很多 国家"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1403, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"知道","english":"know","examples":["I know your name.","She knows how to swim."],"phonetic":"/noʊ/","pastTense":"knew","thirdPerson":"knows","partOfSpeech":"动词","pastParticiple":"known","presentParticiple":"knowing"},{"plural":"","chinese":"中国","english":"China","examples":["China is a great country.","I want to visit China."],"phonetic":"/ˈtʃaɪnə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"be","examples":["Where is my pen?","They are in the classroom."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"哪里","english":"where","examples":["Where do you live?","Tell me where you go."],"phonetic":"/wer/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["宾语从句的语序","动词know的用法","国家名称的拼写与使用"],"explanations":["在英语中，宾语从句要用陈述语序，即主语在前，谓语在后。本句中“where China is”是宾语从句，不能说成“where is China”，要把主语China放在谓语is前面。","know作为及物动词，后面可以直接接宾语或宾语从句，表示“知道，了解”。当主语是第三人称单数时，know要变成knows，比如“He knows the answer.”。","国家名称属于专有名词，首字母必须大写，比如China不能写成china（小写china表示瓷器），专有名词通常没有复数形式，直接使用原形即可。"]},"sentenceWithHints":"我 知道 中国 在 哪里"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1404, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"知道","english":"know","examples":["I know your name.","She knows how to swim."],"phonetic":"/noʊ/","pastTense":"knew","thirdPerson":"knows","partOfSpeech":"动词","pastParticiple":"known","presentParticiple":"knowing"},{"plural":"","chinese":"美国","english":"America","examples":["America is a big country.","I want to visit America."],"phonetic":"/əˈmerɪkə/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"be","examples":["Where is my pen?","They are in the classroom."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"哪里","english":"where","examples":["Where do you live?","Tell me where you go."],"phonetic":"/wer/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["宾语从句的语序","动词know的用法","国家名称的表达"],"explanations":["在英语中，宾语从句要用陈述语序，即主语在前，谓语在后。本句中“美国在哪里”作为know的宾语，要变成“where America is”，不能用疑问语序“where is America”。","know是及物动词，后面可以直接接宾语或宾语从句，用来表达“知道”的含义，第三人称单数形式为knows，过去式为不规则变化knew，过去分词为known。","“美国”对应的英语是America，属于专有名词，首字母必须大写，这类国家名称是固定表达，没有复数形式。"]},"sentenceWithHints":"我 知道 美国 在 哪里"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1405, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想","english":"want","examples":["I want a new pen.","She wants to go home."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"去","english":"go","examples":["Let''s go to the park.","He goes to school by bus."],"phonetic":"/ɡoʊ/","pastTense":"went","thirdPerson":"goes","partOfSpeech":"动词","pastParticiple":"gone","presentParticiple":"going"},{"plural":"","chinese":"很多","english":"many","examples":["Many kids like candies.","I have many books."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"countries","chinese":"国家","english":"country","examples":["China is a great country.","We visited many countries last year."],"phonetic":"/ˈkʌntri/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"旅行","english":"travel","examples":["I want to travel around the world.","She travels every summer."],"phonetic":"/ˈtrævl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"}],"examPoints":{"points":["want to do sth. 固定搭配","many 修饰可数名词复数","可数名词的复数变形规则"],"explanations":["want to do sth. 是小学阶段核心固定搭配，意为“想要做某事”，表示主语的意愿，后面要接动词原形。本句中“想旅行”就用 want to travel 来表达。","many 是形容词，意为“许多”，只能用来修饰可数名词的复数形式，不能修饰不可数名词，本句中用来修饰 countries（country的复数），符合这个用法。","以辅音字母+y结尾的可数名词，变复数时要把y改为i，再加-es，country 是以辅音字母r+y结尾，所以复数形式是 countries，这是小学阶段需要掌握的可数名词复数不规则变形规则之一。"]},"sentenceWithHints":"我 想 去 很多 国家 旅行"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1406, '{"words":[{"plural":"maps","chinese":"地图","english":"map","examples":["I have a map of China.","The map on the wall is old."],"phonetic":"/mæp/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gives me a gift.","Please tell me your name."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"了解","english":"understand","examples":["I understand your idea.","She doesn''t understand the question."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"}],"examPoints":{"points":["使役动词let的用法","可数名词的定冠词使用","动词第三人称单数变化"],"explanations":["使役动词let常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式，本句中lets me understand就是这个结构的体现，符合小学阶段对使役动词基础用法的考查。","当特指某个事物时，可数名词单数前要加定冠词the，本句中the map特指说话双方都知道的那张地图，属于小学阶段定冠词基础用法的考查点。","当主语是第三人称单数（如本句中的the map）时，一般现在时的动词要变成第三人称单数形式，let的第三人称单数是直接加s变成lets，这是小学阶段动词变形的基础考点。"]},"sentenceWithHints":"地图 让 我 了解 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1407, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"看","english":"watch","examples":["I watch TV every day.","He is watching a movie now."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"","chinese":"新闻","english":"news","examples":["I watch news in the morning.","The news is interesting."],"phonetic":"/nuːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定搭配","不可数名词的用法","人称代词主格的使用"],"explanations":["like作为动词表示“喜欢”时，常用搭配为like doing sth.，表示长期的、习惯性的喜好，本句中“喜欢看新闻”是长期爱好，所以用like watching。","news是不可数名词，没有复数形式，不能在后面加-s，也不能直接用a/an修饰，表达“一则新闻”可以用a piece of news。","“我”在句中作主语，要用人称代词的主格形式I，主格代词在句中用来作动作的发出者。"]},"sentenceWithHints":"我 喜欢 看 新闻"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1408, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school by bus."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"看","english":"watch","examples":["I watch TV after dinner.","He watches cartoons on weekends."],"phonetic":"/wɑːtʃ/","pastTense":"watched","thirdPerson":"watches","partOfSpeech":"动词","pastParticiple":"watched","presentParticiple":"watching"},{"plural":"","chinese":"新闻","english":"news","examples":["I watch news every morning.","The news is very important."],"phonetic":"/nuːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","时间状语every day的使用","动词watch的搭配"],"explanations":["一般现在时用于表示经常性、习惯性的动作。本句中“每天都看”是习惯性动作，主语是第一人称I，所以动词用原形watch。当主语是第三人称单数时，动词要变成第三人称单数形式，比如He watches news every day。","every day是时间状语，意为“每天”，用来表示动作发生的频率，在句中通常放在句末，说明动作是重复发生的。要注意和everyday（形容词，意为“日常的”）区分开，比如everyday life（日常生活）。","watch作为动词，常用来表示观看动态的画面类内容，比如电视、新闻、比赛等，搭配news表示“看新闻”，是固定的常用表达。"]},"sentenceWithHints":"我 每天 都 看 新闻"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1409, '{"words":[{"plural":"","chinese":"新闻","english":"news","examples":["I watch the news every night.","The good news made us happy."],"phonetic":"/nuːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"让","english":"let","examples":["My mom lets me play outside after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"plural":"","chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me your name."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"了解","english":"understand","examples":["I understand your feelings.","She doesn''t understand the question."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He wants to travel around the world."],"phonetic":"/wɜːrld/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["使役动词let的用法","不可数名词news的用法","动词第三人称单数变化"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中lets me understand就符合这个结构。","news是不可数名词，虽然以s结尾，但本身没有复数形式，在句子中作主语时，谓语动词要用第三人称单数形式，本句中主语news是单数概念，所以谓语动词let用第三人称单数lets。","当主语是第三人称单数（如可数名词单数、不可数名词、he/she/it等）时，一般现在时的谓语动词要变成第三人称单数形式。规则变化一般加-s，不规则变化要记特殊形式，let的第三人称单数是lets。"]},"sentenceWithHints":"新闻 让 我 了解 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1410, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"了解","english":"understand","examples":["I understand your feelings.","She understands English well."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like playing games.","I have many books."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"新闻","english":"news","examples":["I watch the news every night.","The news is very exciting."],"phonetic":"/nuːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","实义动词的基本形式","不可数名词的用法"],"explanations":["人称代词I是第一人称单数主格，在句子中作主语，通常位于句首，后面接谓语动词原形（一般现在时中）。","understand是实义动词，在一般现在时中，当主语是第一人称I时，使用动词原形；当主语是第三人称单数时，要变为understands。同时它是不规则动词，过去式和过去分词都是understood，需要特殊记忆。","news是不可数名词，虽然以s结尾，但本身没有复数形式，不能用many修饰（此处参考翻译为小学阶段简化表达，实际应使用much），在句子中作主语时，谓语动词要用单数形式。"]},"sentenceWithHints":"我 了解 很多 新闻"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1411, '{"words":[{"plural":"","chinese":"新闻","english":"news","examples":["No news is good news.","I like watching the news."],"phonetic":"/nuːz/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有用","english":"useful","examples":["This book is useful.","We need some useful tools."],"phonetic":"/ˈjuːsfl/","partOfSpeech":"形容词"}],"examPoints":{"points":["不可数名词的主谓一致","副词修饰形容词的用法"],"explanations":["news是不可数名词，形式上看似复数但实际表示单数概念，作主语时谓语动词要用第三人称单数形式，所以本句中用is。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰useful，强调有用的程度。"]},"sentenceWithHints":"新闻 很 有用"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1412, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"经常","english":"often","examples":["I often play football.","She often reads books."],"phonetic":"/ˈɔːfn/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"和","english":"with","examples":["I play with my friend.","She goes to park with her mom."],"phonetic":"/wɪð/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"parents","chinese":"父母","english":"parents","examples":["My parents love me.","I live with my parents."],"phonetic":"/ˈperənts/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"讨论","english":"discuss","examples":["We discuss the plan together.","He discusses the problem with his teacher."],"phonetic":"/dɪˈskʌs/","pastTense":"discussed","thirdPerson":"discusses","partOfSpeech":"动词","pastParticiple":"discussed","presentParticiple":"discussing"},{"plural":"news","chinese":"新闻","english":"news","examples":["I watch news every night.","The news is interesting."],"phonetic":"/nuːz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["频度副词的用法","介词with的用法","一般现在时动词形式","集合名词news的用法"],"explanations":["频度副词often表示“经常”，用于一般现在时，通常放在主语之后，实义动词之前，用来描述经常性的动作。本句中often放在主语I和实义动词discuss之间，符合这个规则。","介词with在这里表示“和……一起”，用来引出动作的伴随对象，放在动词短语之后，引出一起做动作的人，结构为“do sth with sb”，本句中“discuss news with my parents”就是这个结构的体现。","本句是一般现在时，主语是第一人称I，所以实义动词discuss用原形；如果主语是第三人称单数，动词需要变成第三人称单数形式，比如“He discusses news with his parents”。","news是集合名词，虽然以s结尾，但它是不可数名词，本身就表示“新闻、消息”的总称，没有常规的可数复数变化，作主语时谓语动词用单数形式，比如“The news is good.”。"]},"sentenceWithHints":"我 经常 和 父母 讨论 新闻"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1413, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to play football."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一个","english":"a","examples":["I have a pen.","This is a dog."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","The cake is very delicious."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好的","english":"good","examples":["He is a good boy.","This is a good book."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家庭","english":"family","examples":["My family is big.","We have a happy family."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与谓语动词的搭配","不定冠词的使用","副词修饰形容词的用法"],"explanations":["当主语是第一人称代词I时，搭配的谓语动词用have；如果主语是第三人称单数（如he/she/it），则谓语动词要用has，本句主语是I，所以用have。","不定冠词a用于辅音音素开头的可数名词单数前，family是以辅音音素开头的可数名词单数，所以前面用a来表示“一个”的概念。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very修饰good，用来强调家庭的好的程度。"]},"sentenceWithHints":"我 有 一个 很 好的 家庭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1414, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"parents","chinese":"父母","english":"parents","examples":["My parents work in a hospital.","Her parents are very kind."],"phonetic":"/ˈperənts/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very much","examples":["I like apples very much.","She loves dancing very much."],"phonetic":"/ˈveri mʌtʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱","english":"love","examples":["I love my family.","He loves playing football."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","My teacher likes me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词性物主代词的用法","人称代词宾格的用法","一般现在时主谓一致","程度副词短语的位置"],"explanations":["形容词性物主代词my用来修饰名词，放在名词前表示所属关系，本句中修饰parents，说明是“我的父母”。","人称代词宾格me在句中作动词的宾语，本句中作love的宾语，放在动词之后。","一般现在时中，当主语是复数（如parents）时，谓语动词用原形，本句主语parents是复数，所以love用原形，不用第三人称单数形式loves。","程度副词短语very much用来修饰动词，表示动作的程度，通常放在句末，本句中放在love me之后，说明父母爱“我”的程度很深。"]},"sentenceWithHints":"我的 父母 很 爱 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1415, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"也","english":"also","examples":["I also like cats.","She also plays the piano."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱","english":"love","examples":["I love my family.","He loves reading books."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"我的","english":"my","examples":["My bag is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"parents","chinese":"父母","english":"parents","examples":["My parents are kind.","I often go shopping with my parents."],"phonetic":"/ˈperənts/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词also的用法","动词love的形式变化","名词复数的表达"],"explanations":["also是表示“也”的副词，在一般现在时的陈述句中，通常放在实义动词之前，be动词、助动词之后。本句中实义动词是love，所以also放在love前面。","love是规则动词，一般现在时中主语是第三人称单数时，动词要变成loves；过去式和过去分词都是在词尾加ed，即loved；现在分词是在词尾加ing，即loving。本句主语是第一人称I，所以用动词原形love。","parent表示“父亲”或“母亲”，是可数名词，复数形式直接在词尾加s变成parents，用来表示“父母双亲”，符合句子中表达的含义。"]},"sentenceWithHints":"我 也 爱 我的 父母"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1416, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"","examples":["我们是好朋友。","他们喜欢打球。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"经常","english":"often","examples":["I often read books.","She often plays football."],"phonetic":"/ˈɔːfn/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["We play games together.","Let''s go home together."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"吃","english":"have","examples":["I have breakfast every day.","She has a cat."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"晚","english":"","examples":["晚上的月亮很圆。","晚饭准备好了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"饭","english":"dinner","examples":["We have dinner at 7 PM.","Dinner is ready."],"phonetic":"/ˈdɪnər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","频度副词的位置","固定搭配 have dinner","副词 together 的位置"],"explanations":["第一人称复数“我们”对应的英文主格是 We，在句中作主语，用于指代说话者和其他人组成的群体，小学阶段需要掌握常见的人称代词主格形式。","频度副词 often 表示“经常”，通常放在实义动词之前，be动词、助动词之后，本句中实义动词是 have，所以 often 放在 have 前面，这是小学阶段需要掌握的副词基本位置规则。","表示“吃晚饭”的固定英文搭配是 have dinner，不需要加不定冠词 a，类似的固定搭配还有 have breakfast、have lunch，小学阶段需要积累这类三餐相关的固定表达。","副词 together 表示“一起”，通常放在句末，用来修饰整个动作，说明动作发生的方式，小学阶段需要掌握这类方式副词的基本位置用法。"]},"sentenceWithHints":"我 们 经 常 一 起 吃 晚 饭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1417, '{"words":[{"plural":"dinners","chinese":"晚饭","english":"dinner","examples":["We have dinner at 7 o''clock.","She made a delicious dinner."],"phonetic":"/ˈdɪnər/","partOfSpeech":"名词"},{"plural":"","chinese":"时","english":"during","examples":["I read during the flight.","We sing songs during the party."],"phonetic":"/ˈdʊrɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我们","english":"we","examples":["We love playing football.","We are going to the park."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"聊天","english":"chat","examples":["We chat every weekend.","She is chatting with her friend."],"phonetic":"/tʃæt/","pastTense":"chatted","thirdPerson":"chats","partOfSpeech":"动词","pastParticiple":"chatted","presentParticiple":"chatting"}],"examPoints":{"points":["介词during的用法","一般现在时的用法","人称代词主格作主语"],"explanations":["during是介词，用来表示在某个时间段内发生的动作，后面接表示时间段的名词，比如dinner、the holiday等，本句中用来表明聊天这个动作发生在晚饭的时间段里。","一般现在时用来表示经常性、习惯性的动作，当主语是第一人称复数we时，谓语动词用原形，本句中chat用原形符合这个规则。","we是第一人称复数主格代词，在句子中作主语，用来指代说话者和其他人，在本句中作为动作chat的发出者，放在句首引导句子。"]},"sentenceWithHints":"晚饭 时 我们 聊天"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1418, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very much","examples":["I like cats very much.","She sings very well."],"phonetic":"/ˈveri mʌtʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"享受","english":"enjoy","examples":["I enjoy reading books.","He enjoys playing football."],"phonetic":"/ɪnˈdʒɔɪ/","pastTense":"enjoyed","thirdPerson":"enjoys","partOfSpeech":"动词","pastParticiple":"enjoyed","presentParticiple":"enjoying"},{"plural":"","chinese":"这种","english":"this","examples":["This is my pen.","I like this book."],"phonetic":"/ðɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"times","chinese":"时光","english":"time","examples":["I have a good time.","Time flies."],"phonetic":"/taɪm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["实义动词的一般现在时用法","程度副词短语的位置","指示代词的使用"],"explanations":["实义动词enjoy在一般现在时中，当主语是第一人称I时，动词用原形，不需要变形；如果主语是第三人称单数，要变为enjoys。本句主语是I，所以用enjoy原形。","程度副词短语very much用来修饰动词，表示“很、非常”，通常放在句子的末尾，用来加强语气，比如本句中放在time之后，说明享受的程度。","指示代词this用来指代单数的、距离较近的人或事物，本句中用来指代“时光”，属于单数事物，所以用this来修饰。"]},"sentenceWithHints":"我 很 享受 这种 时光"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1419, '{"words":[{"plural":"families","chinese":"家庭","english":"family","examples":["My family is big.","Families often get together on holidays."],"phonetic":"/ˈfæməli/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","The book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"温暖","english":"warm","examples":["The room is warm.","She has a warm heart."],"phonetic":"/wɔːrm/","partOfSpeech":"形容词"}],"examPoints":{"points":["名词的单复数用法","副词修饰形容词的用法","主系表句型"],"explanations":["family作为集合名词，当表示“家庭整体”时，视为单数，谓语动词用is；当表示“家庭成员”时，视为复数，谓语动词用are。本句中family表示家庭整体，所以用is。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，说明程度，本句中very用来修饰warm，强调温暖的程度。","本句是主系表结构的简单句，主语是family，系动词是is，表语是形容词warm，用来描述主语的特征，这是小学阶段需要掌握的基础句型结构。"]},"sentenceWithHints":"家庭 很 温暖"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1420, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing football."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"我的","english":"my","examples":["My bag is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家庭","english":"family","examples":["My family is big.","We have a happy family."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格与形容词性物主代词","一般现在时动词形式","可数名词复数变化"],"explanations":["人称代词主格I在句中作主语，形容词性物主代词my用来修饰名词family，表明所属关系，小学阶段需要区分主格和形容词性物主代词的不同用法。","一般现在时中，当主语是第一人称I时，谓语动词用原形like；如果主语是第三人称单数（如she/he），动词要变为第三人称单数形式likes，这是小学阶段一般现在时的核心考点。","以辅音字母+y结尾的可数名词，变复数时要把y变为i再加-es，family的复数形式是families，这是小学阶段名词复数规则变化的重要知识点。"]},"sentenceWithHints":"我 喜欢 我的 家庭"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1421, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一","english":"one","examples":["I have one pen.","There is one book on the desk."],"phonetic":"/wʌn/","pastTense":"","thirdPerson":"","partOfSpeech":"数词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"个","english":"","examples":["这是一个苹果。","我有三个玩具。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"量词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["She is a good girl.","This is a good book."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"习","english":"","examples":[],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"habits","chinese":"惯","english":"habit","examples":["Reading is a good habit.","He has many bad habits."],"phonetic":"/ˈhæbɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词与谓语动词的搭配","不定冠词的使用","形容词修饰名词的用法"],"explanations":["当主语是第一人称代词I时，谓语动词用have；当主语是第三人称单数（如he/she/it）时，谓语动词要用has，本句主语是I，所以用have。","可数名词单数前需要用不定冠词a/an来修饰，habit是以辅音音素开头的单词，所以用a；如果是元音音素开头的单词则用an。","形容词用来修饰名词，通常放在名词的前面，本句中good是形容词，用来修饰后面的名词habit，说明习惯的性质是好的。"]},"sentenceWithHints":"我 有 一 个 好 习 惯"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1422, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She drinks milk every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"mornings","chinese":"早上","english":"morning","examples":["I get up early in the morning.","We often take a walk on Sunday mornings."],"phonetic":"/ˈmɔːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"all","examples":["We all like cats.","They all go to the park."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"刷","english":"brush","examples":["I brush my hair every day.","She brushes her shoes carefully."],"phonetic":"/brʌʃ/","pastTense":"brushed","thirdPerson":"brushes","partOfSpeech":"动词","pastParticiple":"brushed","presentParticiple":"brushing"},{"plural":"teeth","chinese":"牙","english":"tooth","examples":["I have a white tooth.","We should take care of our teeth."],"phonetic":"/tuːθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","可数名词不规则复数变化","日常动作类动词的使用"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句中“每天早上”是习惯性时间，主语是第一人称“I”，所以动词用原形“brush”。当主语是第三人称单数时，动词要变成对应的第三人称单数形式，比如“He brushes his teeth every morning.”。","部分可数名词的复数变化是不规则的，“tooth”的复数不是“tooths”，而是特殊变化的“teeth”，需要特殊记忆，类似的还有“foot-feet”等。","小学阶段需要掌握描述日常动作的基础动词，“brush”作为动词可以表示“刷”，搭配不同的名词构成常用短语，比如“brush teeth（刷牙）”“brush hair（梳头）”，是日常表达的核心词汇。"]},"sentenceWithHints":"我 每天 早上 都 刷 牙"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1423, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","partOfSpeech":"副词"},{"plural":"nights","chinese":"晚上","english":"night","examples":["I sleep early at night.","We had a party last night."],"phonetic":"/naɪt/","partOfSpeech":"名词"},{"chinese":"都","english":"","examples":["We all like apples.","They are all happy."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"刷","english":"brush","examples":["I brush my hair every morning.","She brushes her teeth twice a day."],"phonetic":"/brʌʃ/","pastTense":"brushed","thirdPerson":"brushes","partOfSpeech":"动词","pastParticiple":"brushed","presentParticiple":"brushing"},{"plural":"teeth","chinese":"牙","english":"tooth","examples":["I have a white tooth.","We should brush our teeth every day."],"phonetic":"/tuːθ/","partOfSpeech":"名词"}],"examPoints":{"points":["一般现在时的用法","不规则名词复数","频率时间状语的使用"],"explanations":["本句描述的是每天重复进行的习惯性动作，要用一般现在时。当主语是第一人称I时，谓语动词用原形brush。","tooth表示“牙齿”，是不规则名词，它的复数形式是teeth，属于需要特殊记忆的名词复数变化形式。","every night表示“每天晚上”，属于频率时间状语，用来表示动作发生的频率，通常放在句子末尾，常用于一般现在时的句子中。"]},"sentenceWithHints":"我 每天 晚上 都 刷 牙"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1424, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"teeth","chinese":"牙齿","english":"tooth/teeth","examples":["I brush my teeth every day.","A baby has no teeth."],"phonetic":"/tuːθ/ /tiːθ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"健康","english":"healthy","examples":["We should eat healthy food.","He looks healthy."],"phonetic":"/ˈhelθi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不规则名词复数","系动词be的用法","副词修饰形容词"],"explanations":["“牙齿”对应的英文tooth是不规则名词，它的复数形式不是加-s，而是变为teeth，属于需要特殊记忆的不规则名词复数变化。","系动词be的形式要和主语保持一致，本句主语teeth是复数形式，所以对应的be动词要用are。","副词very用来修饰形容词healthy，用来加强形容词的语气，说明健康的程度，这是副词修饰形容词的基础用法，在描述事物状态时经常用到。"]},"sentenceWithHints":"我的 牙齿 很 健康。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1425, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很少","english":"rarely","examples":["I rarely eat junk food.","She rarely goes out at night."],"phonetic":"/ˈrerli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"牙疼","english":"have toothache","examples":["I have toothache and need to see a dentist.","She often has toothache because she eats too much candy."],"phonetic":"/hæv ˈtuːθeɪk/","pastTense":"had toothache","thirdPerson":"has toothache","partOfSpeech":"动词短语","pastParticiple":"had toothache","presentParticiple":"having toothache"}],"examPoints":{"points":["频度副词的使用","表示身体疼痛的固定表达"],"explanations":["频度副词rarely表示“很少、难得”，用来描述动作发生的频率，通常放在实义动词之前，be动词、助动词之后。本句中实义动词是have，所以rarely放在have前面。","表达身体局部疼痛时，常用“have + 身体部位相关的疼痛名词”结构，如have toothache（牙疼）、have headache（头疼），小学阶段这类表达通常不需要加不定冠词a/an。"]},"sentenceWithHints":"我 很少 牙疼。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1426, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"也","english":"also","examples":["I also like singing.","She also has a cat."],"phonetic":"/ˈɔːlsoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a new pen.","She has a beautiful dress."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一个","english":"a/another","examples":["I have a dog.","You can try another way."],"phonetic":"/ə/ /əˈnʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词/形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["She is a good girl.","This is a good book."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"habits","chinese":"习惯","english":"habit","examples":["Reading is a good habit.","He has a bad habit."],"phonetic":"/ˈhæbɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词also的用法","动词have的人称变化","形容词修饰名词的语序","限定词another的用法"],"explanations":["also是表示“也”的副词，在小学阶段主要学习它在陈述句中的位置：通常放在实义动词之前，be动词、助动词之后。本句中放在实义动词have之前，符合用法。","动词have在主语是第一人称（I/we）、第二人称（you）以及复数主语时用原形have；主语是第三人称单数（he/she/it等）时，要变成has。本句主语是I，所以用have。","形容词用来修饰名词时，通常放在名词的前面，起到描述名词特征的作用。本句中good是形容词，放在名词habit前面，修饰habit表示“好的习惯”，符合形容词修饰名词的基本语序规则。","another作为限定词，意为“另一个”，后接可数名词单数，用来泛指三者或三者以上中的另一个。本句中another good habit表示“另一个好习惯”，符合小学阶段对another的基础用法要求。"]},"sentenceWithHints":"我 也 有 一个 好 习惯"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1427, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She drinks milk every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"mornings","chinese":"早上","english":"morning","examples":["I get up early in the morning.","We have breakfast every morning."],"phonetic":"/ˈmɔːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"all","examples":["We all like cats.","They all go to the park."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"洗","english":"wash","examples":["I wash my hands before meals.","She washes her clothes on weekends."],"phonetic":"/wɑːʃ/","pastTense":"washed","thirdPerson":"washes","partOfSpeech":"动词","pastParticiple":"washed","presentParticiple":"washing"},{"plural":"faces","chinese":"脸","english":"face","examples":["She has a round face.","He washes his face every morning."],"phonetic":"/feɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","人称代词的主格形式","名词所有格/形容词性物主代词的使用"],"explanations":["一般现在时用于表示经常性、习惯性的动作。本句中“每天早上”是习惯性的时间，因此使用一般现在时，主语是第一人称I，谓语动词用原形wash。","人称代词主格I在句中作主语，用于指代说话人自己，在一般现在时中，后面接动词原形。","形容词性物主代词my用来修饰名词face，表示“我的脸”，用来明确动作的对象所属，小学阶段需要掌握常见的形容词性物主代词如my, your, his, her等。"]},"sentenceWithHints":"我 每天 早上 都 洗 脸"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1428, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"nights","chinese":"晚上","english":"night","examples":["I sleep early at night.","We often walk the dog at night."],"phonetic":"/naɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"（无对应独立英文词，表强调）","examples":["我们都喜欢唱歌。","他们都按时到了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"洗","english":"wash","examples":["I wash my hands before meals.","She washes her clothes on weekends."],"phonetic":"/wɑːʃ/","pastTense":"washed","thirdPerson":"washes","partOfSpeech":"动词","pastParticiple":"washed","presentParticiple":"washing"},{"plural":"faces","chinese":"脸","english":"face","examples":["She has a round face.","He washed his face quickly."],"phonetic":"/feɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","物主代词的使用","时间状语的位置"],"explanations":["当表示经常性、习惯性的动作时，要用一般现在时。本句中“每天晚上”是习惯性动作的标志，主语是第一人称“I”，所以动词用原形“wash”；如果主语是第三人称单数，动词要变成第三人称单数形式，比如“She washes her face every night.”。","物主代词“my”用来表示所属关系，指代“我的”，放在名词“face”前面，说明是“我的脸”，小学阶段需要掌握第一人称物主代词my，第二人称your，第三人称his/her等的基础用法。","表示频率的时间状语“every night”通常放在句子末尾，用来说明动作发生的时间规律，类似的时间状语还有every day、every morning等，都遵循这个位置规则。"]},"sentenceWithHints":"我 每天 晚上 都 洗 脸"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1429, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"faces","chinese":"脸","english":"face","examples":["Wash your face before bed.","Her face turns red."],"phonetic":"/feɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"干净","english":"clean","examples":["The room is clean.","Keep your hands clean."],"phonetic":"/kliːn/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is a student.","The flower is beautiful."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的用法","系动词be的搭配","物主代词的使用"],"explanations":["形容词用于修饰名词或代词，描述人或事物的特征。本句中clean是形容词，用来描述face的状态，放在系动词is之后作表语。","系动词be（am/is/are）用于连接主语和表语，说明主语的身份、特征或状态。本句主语my face是第三人称单数，所以搭配系动词is。","物主代词my用来表示所属关系，指代“我的”，后面接名词，用来表明物品或身体部位的所属者，符合小学三年级对物主代词基础用法的考查要求。"]},"sentenceWithHints":"我的 脸 很 干净。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1430, '{"words":[{"plural":"habits","chinese":"习惯","english":"habit","examples":["Good habits are good for us.","It''s a good habit to read every day."],"phonetic":"/ˈhæbɪt/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very happy.","The book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"重要","english":"important","examples":["It''s important to study hard.","Water is important for life."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"}],"examPoints":{"points":["名词复数形式","副词修饰形容词的用法","主系表句型"],"explanations":["当表示一类事物时，可数名词常用复数形式，“习惯”在这里泛指各类习惯，所以用复数habits，规则名词变复数一般在词尾加-s。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰important，强调重要的程度。","本句是主系表结构，主语habits是复数，所以系动词用are，表语是形容词important，用来描述主语的特征，这是小学阶段需要掌握的基础句型结构。"]},"sentenceWithHints":"习惯 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1431, '{"words":[{"plural":"","chinese":"好","english":"good","examples":["She is a good girl.","This is a good book."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"habits","chinese":"习惯","english":"habit","examples":["Reading is a good habit.","We should keep good habits."],"phonetic":"/ˈhæbɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"让","english":"make","examples":["The story makes me happy.","My mom made a cake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"更","english":"more","examples":["She is more beautiful now.","I want more milk."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"健康","english":"healthy","examples":["I eat vegetables to stay healthy.","She looks very healthy."],"phonetic":"/ˈhelθi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词比较级的用法","make的使役用法","可数名词复数形式"],"explanations":["形容词healthy的比较级是healthier，也可以用more healthy，小学阶段常用healthier形式，用来表示两者之间的比较，句子里用“更健康”体现了状态的提升，所以用比较级。","make作为使役动词，常见结构为make + 宾语 + 形容词，表示“使某人/某物处于某种状态”，本句中make me healthier就是“让我更健康”的意思，这是小学阶段需要掌握的核心动词用法。","habit是可数名词，当表示一类事物且没有特指单个时，要用复数形式habits，规则可数名词变复数一般在词尾加-s，这里habit直接加-s变成habits。"]},"sentenceWithHints":"好 习惯 让 我 更 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1432, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"要","english":"want","examples":["I want a toy car.","She wants to go home."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"养成","english":"develop","examples":["We should develop good habits.","He is developing a new skill."],"phonetic":"/dɪˈveləp/","pastTense":"developed","thirdPerson":"develops","partOfSpeech":"动词","pastParticiple":"developed","presentParticiple":"developing"},{"plural":"","chinese":"更多","english":"more","examples":["I need more time.","She has more books than me."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["This is a good book.","She is a good girl."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"habits","chinese":"习惯","english":"habit","examples":["Reading is a good habit.","He has many bad habits."],"phonetic":"/ˈhæbɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["want to do sth 固定搭配","形容词的修饰顺序","可数名词的复数形式"],"explanations":["want to do sth 是小学阶段的核心固定搭配，意为“想要做某事”，表示主语的意愿，后面要接动词原形，本句中 want to develop 就符合这个结构。","多个形容词修饰名词时，通常按照“数量/程度形容词+描绘性形容词+名词”的顺序排列，本句中 more（程度）+ good（描绘性）+ habits（名词）就是符合这个规则的正确语序。","可数名词表示多个时要变为复数形式，habit 是规则可数名词，直接在词尾加 -s 变为 habits，小学阶段需要掌握常见规则可数名词的复数变化。"]},"sentenceWithHints":"我 要 养成 更多 好 习惯"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1433, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"一个","english":"a","examples":["I have a pen.","This is a dog."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["I have a big dream.","His dream is to be a doctor."],"phonetic":"/driːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格用法","不定冠词a的用法","实义动词have的基本用法"],"explanations":["人称代词I是第一人称主格，在句子中作主语，指代说话人自己，通常位于句首，后面接谓语动词。","不定冠词a用于辅音音素开头的可数名词单数前，用来泛指“一个”，本句中dream是以辅音音素开头的可数名词单数，所以用a修饰。","实义动词have表示“拥有”，主语是第一人称I时，用原形have；主语是第三人称单数（如he/she/it）时，要变为has。本句主语是I，所以用have。"]},"sentenceWithHints":"我 有 一个 梦想"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1434, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想要","english":"want","examples":["I want a new toy.","She wants to go home."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"当","english":"become","examples":["I want to become a singer.","He became a doctor last year."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"一名","english":"a","examples":["a cat","a book"],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"doctors","chinese":"医生","english":"doctor","examples":["My father is a doctor.","The doctor helps sick people."],"phonetic":"/ˈdɑːktər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["want to do sth. 固定搭配","不定冠词a的用法","实义动词become的用法"],"explanations":["want后接动词时，要使用want to + 动词原形的结构，表示“想要做某事”，这是小学阶段需要掌握的核心动词搭配之一。","不定冠词a用于辅音音素开头的可数名词单数前，doctor是以辅音音素/d/开头的可数名词，所以前面用a来表示“一名”。","become作为实义动词，意思是“成为，变成”，在本句中和want to搭配，表达想要达成的职业目标，它的过去式是不规则变形became，小学阶段需要掌握它的基本含义和搭配用法。"]},"sentenceWithHints":"我 想要 当 一名 医生"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1435, '{"words":[{"plural":"doctors","chinese":"医生","english":"doctor","examples":["I want to be a doctor.","The doctor helps sick people."],"phonetic":"/ˈdɑːktər/","partOfSpeech":"名词"},{"chinese":"可以","english":"can","examples":["You can play outside.","I can sing a song."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"治","english":"treat","examples":["Doctors treat patients.","My mom treats my cold with soup."],"phonetic":"/triːt/","pastTense":"treated","thirdPerson":"treats","partOfSpeech":"动词","pastParticiple":"treated","presentParticiple":"treating"},{"plural":"illnesses","chinese":"病","english":"illness","examples":["He has a serious illness.","Good rest can help fight illness."],"phonetic":"/ˈɪlnəs/","partOfSpeech":"名词"},{"chinese":"救","english":"save","examples":["Firefighters save people from fires.","We should save water."],"phonetic":"/seɪv/","pastTense":"saved","thirdPerson":"saves","partOfSpeech":"动词","pastParticiple":"saved","presentParticiple":"saving"},{"plural":"people","chinese":"人","english":"people","examples":["Many people like pandas.","People need food and water to live."],"phonetic":"/ˈpiːpəl/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词can的用法","可数名词的复数形式","并列动词的使用"],"explanations":["情态动词can表示“能够、可以”，后面要接动词原形，用来表达某人具备的能力，本句中用来表示医生具备治病救人的能力。","可数名词表示一类事物时，常用复数形式。doctor变复数直接加-s，illness以s结尾加-es，people本身就是复数形式，用来泛指人们。","当表示并列的动作时，用连词and连接两个动词原形，本句中and连接treat和save，体现医生的两个并列行为。"]},"sentenceWithHints":"医生 可以 治 病 救 人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1436, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"想","english":"want","examples":["I want a new pen.","She wants to go home."],"phonetic":"/wɑːnt/","pastTense":"wanted","thirdPerson":"wants","partOfSpeech":"动词","pastParticiple":"wanted","presentParticiple":"wanting"},{"plural":"","chinese":"帮助","english":"help","examples":["Can you help me?","He helps his mom every day."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"},{"plural":"","chinese":"别人","english":"others","examples":["We should care about others.","Others may have different ideas."],"phonetic":"/ˈʌðərz/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["want的固定用法","代词others的用法"],"explanations":["want作为动词，常见用法是want to do sth.，表示“想要做某事”，这是小学阶段需要掌握的核心动词搭配，本句中want to help就是符合这个结构的用法。","others是代词，相当于other people，意为“别人、其他人”，在句中可以直接作宾语，不需要再加名词，小学阶段需要区分它和other的用法，other后面需要接名词复数，而others可以单独使用。"]},"sentenceWithHints":"我 想 帮助 别人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1437, '{"words":[{"chinese":"当","english":"be","examples":["I want to be a nurse.","Being a volunteer makes me happy."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"doctors","chinese":"医生","english":"doctor","examples":["My father is a doctor.","The doctors are working in the hospital."],"phonetic":"/ˈdɑːktər/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The cat is very cute.","She runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有意义","english":"meaningful","examples":["Reading is meaningful.","This is a meaningful gift."],"phonetic":"/ˈmiːnɪŋfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","形容词的用法","不定冠词a的使用"],"explanations":["当表示“做某事（职业）”这类抽象的行为作主语时，要用动词的动名词形式（即动词+ing），本句中“当医生”作为主语，所以用Being a doctor，这是小学阶段需要掌握的非谓语动词基础用法。","形容词用来描述事物的特征，本句中meaningful是形容词，用来描述“当医生”这件事的属性，very作为副词用来修饰形容词meaningful，加强程度，这是小学阶段副词修饰形容词的基础知识点。","可数名词单数doctor在表示泛指“一名医生”时，前面要加不定冠词a，因为doctor是以辅音音素开头的单词，所以用a，这是小学阶段不定冠词的核心用法之一。"]},"sentenceWithHints":"当 医生 很 有意义。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1438, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"会","english":"will","examples":["I will go to school tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"为","english":"for","examples":["I bought a gift for my mom.","He works hard for his family."],"phonetic":"/fɔːr/","partOfSpeech":"介词"},{"chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["My dream is to be a doctor.","She has many beautiful dreams."],"phonetic":"/driːm/","partOfSpeech":"名词"},{"chinese":"努力","english":"work hard","examples":["He works hard every day.","I worked hard to pass the exam."],"phonetic":"/wɜːrk hɑːrd/","pastTense":"worked hard","thirdPerson":"works hard","partOfSpeech":"动词短语","pastParticiple":"worked hard","presentParticiple":"working hard"}],"examPoints":{"points":["一般将来时的表达","介词for的用法","形容词hard修饰动词的用法"],"explanations":["小学阶段一般将来时常用“will+动词原形”结构表示将来要做的动作，本句中“会”表达将来的意愿，所以用will加上动词短语work hard。","介词for在这里用来表示动作的对象或目的，意为“为了”，用来引出努力的目标“我的梦想”。","hard作为副词时可以修饰动词work，表示“努力地”，在英语中表示“努力工作/学习”常用work hard这个固定搭配，这里hard的位置要放在动词work之后。"]},"sentenceWithHints":"我 会 为 我的 梦想 努力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1439, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"相信","english":"believe","examples":["I believe you are right.","She believes in herself."],"phonetic":"/bɪˈliːv/","pastTense":"believed","thirdPerson":"believes","partOfSpeech":"动词","pastParticiple":"believed","presentParticiple":"believing"},{"plural":"","chinese":"我","english":"I","examples":["I want an apple.","I can swim."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"能","english":"can","examples":["I can sing.","Can you help me?"],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"plural":"","chinese":"实现","english":"realize","examples":["I want to realize my goal.","He realized his mistake."],"phonetic":"/ˈriːəlaɪz/","pastTense":"realized","thirdPerson":"realizes","partOfSpeech":"动词","pastParticiple":"realized","presentParticiple":"realizing"},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["I have a big dream.","Her dreams come true."],"phonetic":"/driːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称代词的使用","情态动词can的用法","及物动词believe的宾语从句结构","实义动词的基本形式"],"explanations":["第一人称代词I在句子中作主语，指代说话人本身，永远大写，小学阶段主要掌握其作主语的基础用法。","情态动词can表示“能够、可以”，后接动词原形，没有人称和数的变化，过去式为could，小学阶段重点学习其表能力的用法。","及物动词believe后面可以接宾语从句，本句中“我能实现梦想”作为believe的宾语，省略了引导词that，这是小学阶段接触的简单宾语从句结构。","实义动词有原形、过去式、过去分词、第三人称单数、现在分词的形式变化，如believe的第三人称单数是believes，realize的过去式是realized，小学阶段需要掌握规则动词的基本变形规则。"]},"sentenceWithHints":"我 相信 我 能 实现 梦想"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1440, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like playing games.","There are many books on the shelf."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"plans","chinese":"计划","english":"plan","examples":["I have a plan for the weekend.","We made some plans for our trip."],"phonetic":"/plæn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词have的用法","形容词many的用法","可数名词复数变化"],"explanations":["动词have表示“拥有”，当主语是第一人称（I）、第二人称（you）以及复数主语时，使用原形have；当主语是第三人称单数（he/she/it等）时，要变为has。本句主语是I，所以用have。","形容词many用于修饰可数名词复数，用来表示数量多，通常放在可数名词复数前面，不能修饰不可数名词。本句中many修饰可数名词plan的复数plans。","可数名词变复数时，一般情况在词尾加-s，plan属于规则变化，直接在词尾加-s变为plans。需要注意many后面要搭配可数名词的复数形式。"]},"sentenceWithHints":"我 有 很多 计划"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1441, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"计划","english":"plan","examples":["I plan to go hiking this weekend.","She plans to buy a new bag."],"phonetic":"/plæn/","pastTense":"planned","thirdPerson":"plans","partOfSpeech":"动词","pastParticiple":"planned","presentParticiple":"planning"},{"plural":"","chinese":"明年","english":"next year","examples":["We will travel to Beijing next year.","Next year, I will be ten years old."],"phonetic":"/nekst jɪr/","pastTense":"","thirdPerson":"","partOfSpeech":"其他","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学","english":"learn","examples":["I learn English every day.","She learned to swim last summer."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"pianos","chinese":"钢琴","english":"piano","examples":["She plays the piano very well.","I want to buy a piano."],"phonetic":"/piˈænoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["plan to do sth 固定搭配","一般将来时的表达","乐器类名词的用法"],"explanations":["plan 作为动词时，常用固定搭配 plan to do sth，表示“计划做某事”，这里的 to 是不定式符号，后面接动词原形，符合小学阶段对动词固定搭配的考查要求。","本句中“明年”是将来的时间，用“plan to do sth”的结构可以表达将来要做的计划，这是小学阶段常见的一般将来时表达方法之一，不需要使用 will 也能体现将来含义。","表示演奏某种乐器时，通常要在乐器名词前加定冠词 the，不过在口语或简化表达中有时会省略，小学阶段主要掌握“play the piano”的完整正确用法，同时了解参考翻译的简化表达形式。"]},"sentenceWithHints":"我 计划 明年 学 钢琴"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1442, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"计划","english":"plan","examples":["I plan to go to the park.","She plans to read a book."],"phonetic":"/plæn/","pastTense":"planned","thirdPerson":"plans","partOfSpeech":"动词","pastParticiple":"planned","presentParticiple":"planning"},{"plural":"","chinese":"明年","english":"next year","examples":["I will travel next year.","We will have a party next year."],"phonetic":"/nekst jɪr/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"学","english":"learn","examples":["I learn English every day.","She learned to swim last summer."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"drawings","chinese":"画画","english":"drawing","examples":["I like drawing.","Her drawing is very beautiful."],"phonetic":"/ˈdrɔːɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词plan的固定用法","非谓语动词的形式","时间状语的位置"],"explanations":["plan作为动词，常见固定搭配为plan to do sth.，表示“计划做某事”，这是小学阶段需要掌握的重点动词搭配，本句中plan to learn就符合这个结构。","learn后面接动词的ing形式（动名词）表示学习某项技能或活动，这里learn drawing表示学习画画这项技能，动名词在句中作learn的宾语，是小学阶段接触的非谓语动词基础用法。","表示时间的状语next year通常放在句子末尾，用来说明动作发生的时间，这是小学阶段英语句子成分位置的基础知识点，帮助学生构建正确的句子语序。"]},"sentenceWithHints":"我 计划 明年 学 画画"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1443, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"计划","english":"plan","examples":["I plan to go to the park.","She plans to read a book."],"phonetic":"/plæn/","pastTense":"planned","thirdPerson":"plans","partOfSpeech":"动词","pastParticiple":"planned","presentParticiple":"planning"},{"plural":"","chinese":"明年","english":"next year","examples":["I will travel next year.","We will have a party next year."],"phonetic":"/nekst jɪr/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"参加","english":"participate in","examples":["I want to participate in the game.","He participates in the activity every week."],"phonetic":"/pɑːrˈtɪsɪpeɪt ɪn/","pastTense":"participated in","thirdPerson":"participates in","partOfSpeech":"动词","pastParticiple":"participated in","presentParticiple":"participating in"},{"plural":"competitions","chinese":"比赛","english":"competition","examples":["There is a competition at school.","We won the competition."],"phonetic":"/ˌkɑːmpəˈtɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词短语plan to do的用法","时间状语的位置","participate in的固定搭配"],"explanations":["plan to do是固定表达，意为“计划做某事”，to后面要接动词原形，这是小学阶段需要掌握的常用动词搭配结构。","表示时间的短语next year在英语句子中通常放在句末，这是英语和中文在语序上的小差异，小学阶段需要了解基础的状语位置规则。","participate是不及物动词，后面接宾语时要搭配介词in，构成participate in的固定搭配，意为“参加（活动、比赛等）”，属于小学阶段需要积累的常用动词短语。"]},"sentenceWithHints":"我 计划 明年 参加 比赛"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1444, '{"words":[{"plural":"plans","chinese":"计划","english":"plan","examples":["I have a study plan.","We made plans for the weekend."],"phonetic":"/plæn/","partOfSpeech":"名词"},{"chinese":"让","english":"give","examples":["My mom gives me a gift.","Please give me a pen."],"phonetic":"/ɡɪv/","pastTense":"gave","thirdPerson":"gives","partOfSpeech":"动词","pastParticiple":"given","presentParticiple":"giving"},{"chinese":"我","english":"me","examples":["He helps me with homework.","Give me a cup of water."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"goals","chinese":"目标","english":"goal","examples":["My goal is to learn English well.","We set some goals for this term."],"phonetic":"/ɡoʊl/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的复数形式","动词的主谓一致","人称代词宾格的用法"],"explanations":["可数名词表示泛指一类事物时，通常用复数形式。本句中“计划”和“目标”都是泛指，所以分别用复数plans和goals。","当主语是复数名词时，谓语动词要用原形。本句主语plans是复数，所以谓语动词give用原形，不需要变成第三人称单数形式。","人称代词在动词或介词后面作宾语时，要用宾格形式。“我”在动词give后面作宾语，所以用宾格me，而不用主格I。"]},"sentenceWithHints":"计划 让 我 有 目标"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1445, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"按照","english":"according to","examples":["According to the rules, we can''t run here.","According to my mom, it will rain."],"phonetic":"/əˈkɔːrdɪŋ tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"plans","chinese":"计划","english":"plan","examples":["We have a plan for the trip.","Make a plan before you start."],"phonetic":"/plæn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"做","english":"do","examples":["I do my homework every day.","She does sports after school."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"things","chinese":"事","english":"thing","examples":["I have many things to do.","This thing is easy."],"phonetic":"/θɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","介词短语according to的用法","可数名词的复数形式"],"explanations":["小学阶段用will+动词原形表达一般将来时，表示将要发生的动作或存在的状态，本句中will do表示将要去做事，符合将来时的用法。","according to是固定介词短语，意为“按照、根据”，后面可以接名词、代词等内容，用来引出参照的依据，本句中引出参照的依据是plans（计划）。","可数名词表示多个时需要变成复数形式，规则名词一般在词尾加-s，plan和thing都是规则可数名词，复数形式分别为plans和things。"]},"sentenceWithHints":"我 会 按照 计划 做 事"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1446, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing football."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"schools","chinese":"学校","english":"school","examples":["My school is big.","There are many schools in the city."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"（隐含的程度补充）","english":"much","examples":["Thank you very much.","I don''t like it much."],"phonetic":"/mʌtʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的使用","实义动词like的用法","程度副词very much的位置"],"explanations":["第一人称代词“我”对应英文主格“I”，在句子中作主语，永远大写首字母，小学阶段需要掌握主格代词的基本用法和书写规范。","实义动词like表示“喜欢”，主语是第一人称I时，动词用原形；当主语是第三人称单数（如he/she/it）时，动词要变为第三人称单数形式likes。同时like后可接名词、动名词等作宾语。","中文里“很”放在动词前，而英文中表示“非常喜欢”要用“like...very much”，very much作为程度副词短语要放在句末，这是中英表达语序的差异，是小学阶段需要重点掌握的汉英翻译语序规则。"]},"sentenceWithHints":"我 很 喜欢 我的 学校"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1447, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","Our school has a big playground."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"美","english":"beautiful","examples":["The flower is beautiful.","We live in a beautiful city."],"phonetic":"/ˈbjuːtɪfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is a doctor.","The sky is blue."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的修饰用法","系动词be的单数形式使用","形容词的基础认知"],"explanations":["副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，表示程度，本句中very用来强化beautiful的程度，说明学校美的程度很高。","当主语是第三人称单数（本句中school是单数名词，属于第三人称单数）时，一般现在时中系动词be要使用is的形式，用来连接主语和表语。","beautiful是描述人或事物外观、特质的形容词，在句中作表语，用来说明主语school的特征，小学阶段需要掌握这类描述性形容词的词义和基础用法。"]},"sentenceWithHints":"我的 学校 很 美"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1448, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","The school has a big playground."],"phonetic":"/skuːl/","partOfSpeech":"名词"},{"chinese":"有","english":"there be","examples":["There is a cat under the chair.","There are some books on the table."],"phonetic":"/ðer biː/","pastTense":"there was/there were","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like reading.","I have many toys at home."],"phonetic":"/ˈmeni/","partOfSpeech":"形容词"},{"plural":"flowers","chinese":"花","english":"flower","examples":["The flower is very beautiful.","There are colorful flowers in the garden."],"phonetic":"/ˈflaʊər/","partOfSpeech":"名词"}],"examPoints":{"points":["there be 句型的主谓一致","many 的用法","可数名词复数变化"],"explanations":["there be 句型遵循就近原则，be 动词的单复数由后面紧跟的名词决定。本句中紧跟的是可数名词复数 flowers，所以用 are。","many 是形容词，用来修饰可数名词复数，表示“许多”，不能修饰不可数名词，修饰不可数名词表示“许多”要用 much。","可数名词单数变复数时，一般情况直接在词尾加 -s，flower 属于规则变化，直接加 -s 变为 flowers。"]},"sentenceWithHints":"学校 有 很多 花"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1449, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","The school has a big playground."],"phonetic":"/skuːl/","partOfSpeech":"名词"},{"chinese":"有","english":"there be","examples":["There is a cat under the chair.","There are some books on the table."],"phonetic":"/ðer biː/","pastTense":"there was/there were","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like reading.","I have many toys at home."],"phonetic":"/ˈmeni/","partOfSpeech":"形容词"},{"plural":"trees","chinese":"树","english":"tree","examples":["The tree is very tall.","We planted some trees last week."],"phonetic":"/triː/","partOfSpeech":"名词"}],"examPoints":{"points":["there be 句型的主谓一致","many 的用法","可数名词复数变化"],"explanations":["there be 句型遵循就近原则，be动词的单复数由后面的名词决定。本句中名词是复数的trees，所以用are。","many是形容词，用于修饰可数名词复数，用来表示数量多，不能修饰不可数名词，修饰不可数名词表示“很多”要用much。","可数名词变复数时，一般情况直接在词尾加-s，tree属于规则变化，直接加-s变成trees。"]},"sentenceWithHints":"学校 有 很多 树"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1450, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","Our school has a big playground."],"phonetic":"/skuːl/","partOfSpeech":"名词"},{"plural":"environments","chinese":"环境","english":"environment","examples":["We should protect the environment.","The park has a comfortable environment."],"phonetic":"/ɪnˈvaɪrənmənt/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very delicious."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["This is a good book.","He is a good boy."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["The cat is cute.","My bag is blue."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["定冠词the的用法","系动词be的用法","副词very修饰形容词的用法"],"explanations":["定冠词the用于特指的人或事物前，本句中school environment特指说话双方都明确的那所学校的环境，所以前面加the。","系动词be有am、is、are三种形式，当主语是第三人称单数时，be动词用is。本句主语the school environment是第三人称单数，因此用is。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来加强good的语气，说明环境好的程度。"]},"sentenceWithHints":"学校 环境 很 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1451, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher likes reading.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"good","examples":["She is a good girl.","This apple tastes good."],"phonetic":"/ɡʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is tall.","The book is on the desk."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的修饰用法","系动词be的单复数搭配","形容词作表语的句式"],"explanations":["副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰good，强调好的程度。","系动词is用于第三人称单数主语之后，本句主语my teacher是第三人称单数，因此搭配is，当主语是复数或者第二人称you时，要用are，主语是I时用am。","本句是主系表结构，主语my teacher+系动词is+表语very good，形容词good在这里作表语，用来描述主语的特征和状态。"]},"sentenceWithHints":"我的 老师 很 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1452, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very nice.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"教","english":"teach","examples":["She teaches us math.","I taught him to play chess yesterday."],"phonetic":"/tiːtʃ/","pastTense":"taught","thirdPerson":"teaches","partOfSpeech":"动词","pastParticiple":"taught","presentParticiple":"teaching"},{"plural":"","chinese":"得","english":"","examples":["She runs fast.","He draws beautifully."],"phonetic":"/de/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very quickly."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"well","examples":["She sings well.","He plays basketball well."],"phonetic":"/wel/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词第三人称单数变化","副词修饰动词的用法","定冠词 the 的特指用法"],"explanations":["当主语是第三人称单数（如本句的the teacher）时，一般现在时的动词要变成第三人称单数形式。teach的第三人称单数是在词尾加-es，即teaches。","副词用来修饰动词，说明动作的方式、程度等。本句中well是副词，用来修饰动词teach，说明“教”的状态；very是程度副词，用来修饰well，加强“好”的程度。","定冠词the用于特指某个或某些特定的人或事物，本句中the teacher特指说话双方都知道的那位老师，所以要用the来限定。"]},"sentenceWithHints":"老师 教 得 很 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1453, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very nice.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very much","examples":["I like apples very much.","Thank you very much."],"phonetic":"/ˈveri mʌtʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"关心","english":"care about","examples":["My parents care about my study.","She cares about her friends."],"phonetic":"/ker əˈbaʊt/","pastTense":"cared about","thirdPerson":"cares about","partOfSpeech":"动词","pastParticiple":"cared about","presentParticiple":"caring about"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词短语的第三人称单数变化","人称代词的宾格用法","程度副词短语的位置"],"explanations":["当主语是第三人称单数（如本句的the teacher）时，一般现在时的动词要使用第三人称单数形式，动词短语care about的第三人称单数是cares about，即在核心动词care后加-s。","人称代词在动词或介词后作宾语时，要使用宾格形式，“我”的宾格是me，本句中作care about的宾语，所以用me。","程度副词短语very much用来修饰动词表示程度时，通常放在句子末尾，本句中放在me之后，用来强调关心的程度很深。"]},"sentenceWithHints":"老师 很 关心 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1454, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing football."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is nice.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格与形容词性物主代词的用法","一般现在时中动词的形式","可数名词单数的用法"],"explanations":["人称代词主格“I”在句中作主语，用来指代说话人自己；形容词性物主代词“my”用来修饰名词，表示所属关系，说明是“我的”老师，不能单独使用，后面必须跟名词。","一般现在时中，当主语是第一人称“I”时，谓语动词用原形“like”；如果主语是第三人称单数（如he/she/it），动词要变成第三人称单数形式“likes”。","“teacher”是可数名词，本句中特指“我的老师”，是单数概念，所以直接用单数形式“teacher”；如果表示多个老师，要变成复数“teachers”。"]},"sentenceWithHints":"我 喜欢 我的 老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1455, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"classmates","chinese":"同学","english":"classmate","examples":["I play with my classmate after school.","My classmates all like reading."],"phonetic":"/ˈklæsmeɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"友好","english":"friendly","examples":["The dog is friendly to everyone.","My new neighbor is very friendly."],"phonetic":"/ˈfrendli/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词的使用","系动词be的人称和数的一致","可数名词复数形式"],"explanations":["形容词friendly用来描述人或事物的性格、特征，在句中放在系动词are之后作表语，用来说明主语my classmates的特点。","系动词be的形式要和主语保持一致，本句主语my classmates是可数名词复数，所以搭配系动词are，而不是is。","可数名词classmate表示多个对象时，要变为复数形式classmates，规则变化直接在词尾加-s，用来指代多个同学。"]},"sentenceWithHints":"我的 同学 很 友好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1456, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"","examples":["我们是好朋友。","他们来自中国。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"互相","english":"each other","examples":["We learn from each other.","They help each other every day."],"phonetic":"/iːtʃ ˈʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"帮助","english":"help","examples":["Please help me carry the box.","She helps her mom cook dinner."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"}],"examPoints":{"points":["人称代词的复数形式","固定搭配 each other 的用法","一般现在时的用法"],"explanations":["中文里在人称后加“们”表示复数，对应英文中的第一人称复数主格代词 we，用来指代说话者和其他人组成的群体。","each other 是固定的相互代词，用来表示两者之间的相互关系，在句中通常作宾语，用来描述双方互相做某事的行为。","本句使用一般现在时，主语是第一人称复数 we，谓语动词用原形 help。一般现在时用于表示经常性、习惯性的动作或者客观事实，此处描述的是一种常规的相处行为。"]},"sentenceWithHints":"我 们 互 相 帮 助"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1457, '{"words":[{"chinese":"我们","english":"we","examples":["We are friends.","We like playing games."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"经常","english":"often","examples":["He often reads books.","We often go to the park."],"phonetic":"/ˈɔːfn/","partOfSpeech":"副词"},{"chinese":"一起","english":"together","examples":["Let''s play together.","We study together every day."],"phonetic":"/təˈɡeðər/","partOfSpeech":"副词"},{"chinese":"玩","english":"play","examples":["I play football after school.","She plays the piano well."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"}],"examPoints":{"points":["频度副词的位置","一般现在时的用法","人称代词主格作主语"],"explanations":["频度副词often表示动作发生的频率，在一般现在时的句子中，当主语是人称代词主格（如we）时，频度副词要放在主语之后、实义动词之前，本句中就是放在we和play之间。","一般现在时用于表示经常性、习惯性的动作，本句中“经常一起玩”是习惯性动作，所以使用一般现在时，主语是第一人称复数we，实义动词play用原形即可。","人称代词we是主格形式，在句子中作主语，用来指代说话者及其他人，对应英文中的we，在句中位于句首，引导整个句子。"]},"sentenceWithHints":"我们 经常 一起 玩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1458, '{"words":[{"plural":"classmates","chinese":"同学","english":"classmate","examples":["I play with my classmates after school.","My classmates are very friendly."],"phonetic":"/ˈklæsmeɪt/","partOfSpeech":"名词"},{"plural":"relationships","chinese":"关系","english":"relationship","examples":["The relationship between us is good.","Family relationships are important."],"phonetic":"/rɪˈleɪʃnʃɪp/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very delicious."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"好","english":"good","examples":["This is a good book.","He has a good idea."],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"}],"examPoints":{"points":["名词复数的使用","副词修饰形容词的用法","介词短语作定语"],"explanations":["当指代多个同学时，可数名词classmate需要使用复数形式classmates，符合英语中表示一类人或多个个体的语法规则。","副词very用来修饰形容词good，用来加强形容词的语气，说明程度，这是小学阶段需要掌握的副词基本用法之一。","使用介词短语with classmates来修饰名词relationship，明确说明是和同学之间的关系，这是英语中常用的后置定语结构，用来补充说明名词的具体内容。"]},"sentenceWithHints":"同学 关系 很 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1459, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes reading books."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"我的","english":"my","examples":["My bag is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"classmates","chinese":"同学","english":"classmate","examples":["He is my classmate.","My classmates are friendly."],"phonetic":"/ˈklæsmeɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称主格代词的使用","实义动词like的用法","可数名词复数形式"],"explanations":["第一人称主格代词I在句子中作主语，用于指代说话人自己，在一般现在时中，当主语是I时，后面的实义动词用原形。","like作为实义动词，意为“喜欢”，在一般现在时中，主语是第一人称I时，用动词原形like；当主语是第三人称单数时，like要变为likes。","classmate是可数名词，当表示不止一位同学时，要使用复数形式classmates，规则可数名词变复数一般在词尾加-s。本句中没有特指某一位同学，所以用复数形式表示泛指的同学们。"]},"sentenceWithHints":"我 喜欢 我的 同学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1460, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱","english":"love","examples":["I love my cat.","She loves reading books."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my room."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家人","english":"family","examples":["My family is big.","Families often get together on holidays."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格与形容词性物主代词的用法","一般现在时动词形式","可数名词的复数变化"],"explanations":["人称代词主格I在句中作主语，用于指代说话人自己；形容词性物主代词my用来修饰名词，表示所属关系，意为“我的”，后面必须接名词，本句中修饰family。","一般现在时中，当主语是第一人称I时，谓语动词用原形，本句主语是I，所以动词love用原形；当主语是第三人称单数时，动词要变为第三人称单数形式，如love的第三人称单数是loves。","以辅音字母+y结尾的可数名词，变复数时要把y改为i再加-es，family符合该规则，所以复数形式是families。"]},"sentenceWithHints":"我 爱 我的 家人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1461, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil box."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家人","english":"family","examples":["My family likes to eat together.","She has a big family."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very much","examples":["I like apples very much.","She sings very well."],"phonetic":"/ˈveri mʌtʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱","english":"love","examples":["I love my parents.","He loves playing football."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"我","english":"me","examples":["He gives me a gift.","Please help me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["集体名词的主谓一致","人称代词的宾格用法","副词短语very much的用法"],"explanations":["family属于集体名词，当表示一个整体概念时，视为单数，谓语动词要用第三人称单数形式。本句中family表示家人这个整体，所以动词love要用第三人称单数形式loves。","人称代词分为主格和宾格，当代词在动词后面作宾语时，要用宾格形式。本句中“我”是动词love的宾语，所以用宾格me，而不是主格I。","very much是副词短语，用来修饰动词，表示动作的程度，通常放在句子末尾。本句中用来修饰love，表达家人爱“我”的程度很深。"]},"sentenceWithHints":"我的 家人 很 爱 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1462, '{"words":[{"plural":"homes","chinese":"家","english":"home","examples":["Home is my favorite place.","I want to go home."],"phonetic":"/hoʊm/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a student.","This is my cat."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"最","english":"the most","examples":["This is the most interesting book.","She is the most beautiful girl in class."],"phonetic":"/ðə moʊst/","partOfSpeech":"副词"},{"plural":"","chinese":"温暖","english":"warm","examples":["The room is warm.","She gave me a warm hug."],"phonetic":"/wɔːrm/","partOfSpeech":"形容词"},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The red apple is mine."],"phonetic":"","partOfSpeech":"助词"},{"plural":"places","chinese":"地方","english":"place","examples":["This is a nice place.","I want to visit many places."],"phonetic":"/pleɪs/","partOfSpeech":"名词"}],"examPoints":{"points":["形容词最高级的构成与使用","系动词be的用法","定冠词the的特殊用法"],"explanations":["多音节形容词和部分双音节形容词的最高级形式是在形容词前加the most，warm属于单音节形容词，其最高级也可以直接加-est变为warmest，此处与the most都可表示最高级含义，小学阶段重点掌握单音节形容词加-est的最高级变化，以及最高级前要加定冠词the的规则。","系动词is用于第三人称单数主语之后，本句主语home是单数名词，所以搭配系动词is，构成主系表结构表达事物的属性。","形容词最高级前面必须加定冠词the，用来限定独一无二的最高程度，本句中warmest是warm的最高级，所以前面要加the。"]},"sentenceWithHints":"家 是 最 温暖 的 地方"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1463, '{"words":[{"plural":"family members","chinese":"家人","english":"family members","examples":["My family members love me very much.","Family members should support each other."],"phonetic":"/ˈfæməli ˈmembərz/","partOfSpeech":"名词"},{"plural":"","chinese":"互相","english":"each other","examples":["We help each other every day.","They learn from each other."],"phonetic":"/iːtʃ ˈʌðər/","partOfSpeech":"代词"},{"chinese":"照顾","english":"take care of","examples":["Please take care of my dog when I''m away.","She takes care of her little sister."],"phonetic":"/teɪk ker əv/","pastTense":"took care of","thirdPerson":"takes care of","partOfSpeech":"动词","pastParticiple":"taken care of","presentParticiple":"taking care of"}],"examPoints":{"points":["固定短语 take care of 的用法","相互代词 each other 的用法","名词短语 family members 的表达"],"explanations":["take care of 是固定动词短语，意为“照顾、照料”，相当于 look after，在句子中作谓语，主语是第三人称单数时，要变为 takes care of，过去式为 took care of，过去分词为 taken care of。","each other 是相互代词，用来表示两者之间的“互相、彼此”，在句子中通常作宾语，指代前面提到的两个或多个人/事物之间的相互动作。","family members 是表示“家人”的常用名词短语，family 在这里作定语修饰 members，强调家庭里的成员，是小学阶段需要掌握的常用名词表达。"]},"sentenceWithHints":"家人 互相 照顾"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1464, '{"words":[{"plural":"family members","chinese":"家人","english":"family members","examples":["Family members often gather for dinner.","All my family members love traveling."],"phonetic":"/ˈfæməli ˈmembərz/","partOfSpeech":"名词"},{"chinese":"互相","english":"each other","examples":["We help each other every day.","They often learn from each other."],"phonetic":"/iːtʃ ˈʌðər/","partOfSpeech":"代词"},{"chinese":"支持","english":"support","examples":["My parents support my dream.","We should support each other in hard times."],"phonetic":"/səˈpɔːrt/","pastTense":"supported","thirdPerson":"supports","partOfSpeech":"动词","pastParticiple":"supported","presentParticiple":"supporting"}],"examPoints":{"points":["相互代词的用法","一般现在时主谓一致","动词support的用法"],"explanations":["相互代词each other用于表示两者之间的相互关系，在句中可作宾语，本句中作support的宾语，体现家人之间彼此的动作。","一般现在时中，当主语是复数（本句中family members为复数）时，谓语动词用原形，所以这里support用原形，不需要变形。","support作为及物动词，后面可以直接接宾语，既可以接人也可以接事物，比如support sb.（支持某人）、support a plan（支持一个计划），本句中接each other作宾语，符合及物动词的用法。"]},"sentenceWithHints":"家人 互相 支持"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1465, '{"words":[{"plural":"families","chinese":"家人","english":"family","examples":["My family is very warm.","Families often get together on holidays."],"phonetic":"/ˈfæməli/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","The book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to study hard.","Water is important for life."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"}],"examPoints":{"points":["集体名词的主谓一致","副词修饰形容词的用法"],"explanations":["family 作为集体名词，当表示一个整体概念时，谓语动词用单数形式。本句中 family 指代家庭这个整体，所以用 is。当表示家庭中的成员时，谓语动词用复数，比如 My family are watching TV.","副词 very 用来修饰形容词，放在形容词之前，用来加强形容词的语气，说明形容词所描述的程度。本句中 very 修饰 important，强调重要的程度。"]},"sentenceWithHints":"家人 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1466, '{"words":[{"plural":"homes","chinese":"家","english":"home","examples":["Home is a warm place.","I want to go home."],"phonetic":"/hoʊm/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a student.","The cat is cute."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"harbors","chinese":"港湾","english":"harbor","examples":["The ship entered the harbor.","The harbor is full of boats."],"phonetic":"/ˈhɑːrbər/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","可数名词单数的冠词使用","比喻类句式的英文表达"],"explanations":["be动词的形式要根据主语的单复数和人称变化，本句主语home是第三人称单数，所以使用is。小学阶段需要掌握am、is、are的基础用法区分。","可数名词单数在句中首次出现且表泛指时，前面要加不定冠词a/an，harbor是以辅音音素开头的单词，所以搭配不定冠词a。","本句是比喻句，中文里用“港湾”比喻家的庇护作用，英文翻译直接对应喻体harbor，小学阶段需要掌握这类简单比喻句式的中英对应翻译，理解名词的比喻义用法。"]},"sentenceWithHints":"家 是 港湾"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1467, '{"words":[{"plural":"homes","chinese":"家","english":"home","examples":["My home is near the park.","We went home after school."],"phonetic":"/hoʊm/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["This is my pen.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"starting points","chinese":"起点","english":"starting point","examples":["The square is the starting point of the race.","We need to find a new starting point."],"phonetic":"/ˈstɑːrtɪŋ pɔɪnt/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","可数名词短语的单数表达","合成名词的理解"],"explanations":["be动词有am、is、are三种形式，当主语是第三人称单数（本句中home是单数名词，属于第三人称单数）时，be动词用is。","可数名词短语单数形式前通常需要加不定冠词a/an，starting point是以辅音音素开头的可数名词短语，所以前面加a，表示泛指“一个起点”。","starting point是由动词start的现在分词形式starting和名词point构成的合成名词，用来表示“开始的地方、起点”，这类合成名词在小学阶段需要理解其构成和基础含义。"]},"sentenceWithHints":"家 是 起点"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1468, '{"words":[{"plural":"homes","chinese":"家","english":"home","examples":["My home is near the park.","I want to go home."],"phonetic":"/hoʊm/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is black."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"endpoints","chinese":"终点","english":"endpoint","examples":["The endpoint of the road is a small town.","We finally reached the endpoint."],"phonetic":"/ˈendˌpɔɪnt/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","不定冠词an的用法","可数名词单数的使用"],"explanations":["be动词有am、is、are三种形式，当主语是第三人称单数（本句中home是单数名词，属于第三人称单数）时，be动词用is。","不定冠词an用于以元音音素开头的可数名词单数前，endpoint的发音以元音音素/ˈe/开头，所以前面用an修饰。","可数名词表示单个概念时用单数形式，前面通常需要搭配冠词、物主代词等限定词，本句中endpoint是单数可数名词，搭配an来表示泛指的一个终点。"]},"sentenceWithHints":"家 是 终点"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1469, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱","english":"love","examples":["I love my cat.","She loves reading books."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"homes","chinese":"家","english":"home","examples":["Welcome to my home.","They have two homes."],"phonetic":"/hoʊm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["人称代词的主格与形容词性物主代词的用法","一般现在时动词的形式","可数名词的复数变化"],"explanations":["人称代词主格“I”在句中作主语，放在句首；形容词性物主代词“my”用来修饰名词，放在名词前表示所属关系，本句中“my”修饰“home”，表示“我的家”。","一般现在时中，当主语是第一人称“I”时，谓语动词用原形，本句主语是“I”，所以动词用“love”的原形；当主语是第三人称单数时，动词要变为第三人称单数形式，比如“She loves her home.”。","“home”是可数名词，规则变化的可数名词变复数直接在词尾加“-s”，所以“home”的复数形式是“homes”，表示多个家。"]},"sentenceWithHints":"我 爱 我的 家"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1470, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new bag."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"fathers","chinese":"父亲","english":"father","examples":["My father is a doctor.","Her father likes fishing."],"phonetic":"/ˈfɑːðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very tall.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"勤劳","english":"hardworking","examples":["My teacher is hardworking.","He is a hardworking student."],"phonetic":"/ˈhɑːrdwɜːrkɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is my brother.","The flower is red."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的用法","系动词be的搭配","副词very修饰形容词的规则"],"explanations":["形容词用于描述人或事物的特征，本句中hardworking用来描述父亲“勤劳”的特点，在句中跟在系动词is后作表语。","系动词be（am/is/are）用于连接主语和表语，本句主语my father是第三人称单数，所以搭配系动词is。","副词very用来修饰形容词或副词，表示程度，放在被修饰的形容词之前，本句中very用来加强hardworking的程度，说明父亲勤劳的程度很深。"]},"sentenceWithHints":"我的 父亲 很 勤劳"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1471, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"mothers","chinese":"母亲","english":"mother","examples":["My mother likes cooking.","Her mother is a doctor."],"phonetic":"/ˈmʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"温柔","english":"gentle","examples":["The gentle wind blows.","She has a gentle voice."],"phonetic":"/ˈdʒentl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is tall.","The dog is black."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的修饰用法","系动词be的主谓一致","物主代词的使用"],"explanations":["在英语中，副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰gentle，体现温柔的程度，符合小学阶段对副词修饰形容词的基础考查要求。","系动词be的形式要和主语保持一致，本句主语my mother是第三人称单数，所以对应的be动词用is，这是小学阶段主谓一致的核心基础知识点。","物主代词my用来表示所属关系，指代“我的”，后面接名词，用来表明名词的所属，是小学阶段代词类的基础必学知识点。"]},"sentenceWithHints":"我的 母亲 很 温柔"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1472, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"brothers","chinese":"哥哥","english":"brother","examples":["My brother likes playing football.","She has two brothers."],"phonetic":"/ˈbrʌðər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"聪明","english":"smart","examples":["The smart boy solves the problem quickly.","She is smart and kind."],"phonetic":"/smɑːrt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is a doctor.","The sky is blue."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的修饰用法","物主代词的使用","系动词be的搭配"],"explanations":["在英语中，副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中用very修饰smart，表达“很聪明”的含义，符合小学阶段对副词修饰形容词的知识点考查。","物主代词my用来表示所属关系，放在名词brother之前，说明是“我的哥哥”，小学阶段需要掌握第一人称形容词性物主代词my, your, his等的基础用法。","当主语是第三人称单数（如本句中的brother）时，描述主语的特征要用系动词is+形容词的结构，这是小学阶段主系表结构的基础考查点，需要掌握不同主语对应的be动词形式。"]},"sentenceWithHints":"我的 哥哥 很 聪明"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1473, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is white.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"sisters","chinese":"妹妹","english":"sister","examples":["My sister likes singing.","She has two sisters."],"phonetic":"/ˈsɪstər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"可爱","english":"cute","examples":["The puppy is so cute.","She wears a cute dress."],"phonetic":"/kjuːt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is tall.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词的修饰用法","系动词be的主谓一致","形容词的基础使用"],"explanations":["副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very修饰cute，强调妹妹可爱的程度，这是小学阶段副词修饰形容词的基础考点。","系动词be的形式要和主语保持一致，本句主语my sister是第三人称单数，所以对应的be动词用is，这是小学阶段主谓一致的核心基础考点之一。","形容词cute用来描述主语my sister的特征，在主系表结构中作表语，小学阶段需要掌握用形容词描述人或事物特征的基础表达，以及对应的英文形容词拼写和用法。"]},"sentenceWithHints":"我的 妹妹 很 可爱"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1474, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"family members","chinese":"家人","english":"family members","examples":["My family members love to cook together.","All of her family members are tall."],"phonetic":"/ˈfæməli ˈmembərz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"all","examples":["We all like ice cream.","The books are all on the shelf."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very smart.","The cake tastes very good."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"优秀","english":"excellent","examples":["You did an excellent job.","That''s an excellent idea."],"phonetic":"/ˈeksələnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词的用法","系动词的主谓一致","不定代词all的位置"],"explanations":["形容词excellent用来描述人或事物的性质，在句中跟在系动词are后面作表语，用来说明主语family members的特点，小学阶段需要掌握形容词在主系表结构中的基本用法。","本句主语是family members，是复数形式，所以对应的系动词要用are，这是主谓一致的基础规则：复数主语搭配系动词are，单数主语搭配is，I搭配am，小学四年级需要掌握不同主语对应的be动词形式。","不定代词all在句中作副词时，通常放在系动词、助动词之后，实义动词之前，本句中all放在系动词are之后，用来强调“家人全部”都具备优秀的特点，需要掌握这个常见的副词位置规则。"]},"sentenceWithHints":"我的 家人 都 很 优秀"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1475, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"of","examples":["I am fond of cats.","This is a photo of my family."],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家人","english":"family","examples":["My family lives in Beijing.","She has a big family."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"骄傲","english":"proud","examples":["She is proud of her son.","We are proud of our country."],"phonetic":"/praʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配 be proud of","人称代词的使用","名词复数变化"],"explanations":["be proud of 是固定短语，意为“为……感到骄傲/自豪”，主语不同时be动词要对应变化，本句主语是I，所以用am，整体结构为I am proud of...。","第一人称代词I在句子中作主语时，始终用主格形式I，对应的be动词一般现在时用am，这是小学阶段人称代词和be动词搭配的基础知识点。","family作为“家人”或“家庭”讲时，是可数名词，其复数形式是将y变i加es，即families，需要掌握以辅音字母+y结尾的名词变复数的规则。"]},"sentenceWithHints":"我 为 家人 骄傲"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1476, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"感激","english":"be grateful to","examples":["I am grateful to my parents for their support.","We are grateful to the volunteers for their help."],"phonetic":"/biː ˈɡreɪtfəl tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词短语","pastParticiple":"","presentParticiple":""},{"plural":"families","chinese":"家人","english":"family","examples":["My family likes to have dinner together.","There are many big families in this town."],"phonetic":"/ˈfæməli/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词短语be grateful to的用法","名词family的单复数含义","人称代词主格的使用"],"explanations":["be grateful to是固定短语，意为“感激……”，后面接表示人的名词或代词，表达对他人的谢意。根据主语的人称和数变化be动词的形式，本句主语是I，所以用am。","family作为名词，单数形式通常指“家庭”或“家人（整体）”，复数形式families指“多个家庭”。在本句中family表示“家人”，常用单数形式指代家庭成员整体。","I是第一人称主格代词，在句子中作主语，用于指代说话人自己，后面接对应的be动词或实义动词原形（一般现在时中）。"]},"sentenceWithHints":"我 感激 家人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1477, '{"words":[{"plural":"families","chinese":"家人","english":"family","examples":["My family is very warm.","Families usually get together on holidays."],"phonetic":"/ˈfæməli/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a student.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is blue.","This is my dog."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"supports","chinese":"依靠","english":"support","examples":["My parents are my support.","We need your support."],"phonetic":"/səˈpɔːrt/","partOfSpeech":"名词"}],"examPoints":{"points":["集体名词的用法","形容词性物主代词的使用","系动词be的主谓一致"],"explanations":["family属于集体名词，当表示家庭这个整体概念时，视为单数，作主语时谓语动词用单数形式；当表示家庭里的成员时，视为复数。本句中family表示整体概念，所以用is。","my是形容词性物主代词，后面必须接名词，用来表示所属关系，说明某个事物属于说话者，本句中my修饰support，表明依靠是“我的”。","系动词be的形式要和主语保持一致，主语是单数概念的family，所以对应的be动词用is，这是小学阶段需要掌握的主谓一致基础规则。"]},"sentenceWithHints":"家人 是 我的 依靠"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1478, '{"words":[{"plural":"families","chinese":"家人","english":"family","examples":["My family is very warm.","Families often get together on holidays."],"phonetic":"/ˈfæməli/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a student.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is blue.","This is my dog."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"strengths","chinese":"力量","english":"strength","examples":["Courage is a great strength.","Reading gives me strength."],"phonetic":"/streŋθ/","partOfSpeech":"名词"}],"examPoints":{"points":["集合名词的主谓一致","形容词性物主代词的用法","不可数/抽象名词的使用"],"explanations":["family属于集合名词，当表示“家庭整体”时，视为单数，谓语动词用is；当表示“家庭成员”时视为复数，谓语动词用are。本句中family表示家庭整体，所以用is。","my是形容词性物主代词，后面必须接名词，用来表示所属关系，说明某个事物属于说话者，比如my strength（我的力量）、my book（我的书）。","strength作为“力量、毅力”这类抽象含义时，是不可数名词；表示“优点、长处”时是可数名词，本句中是抽象含义，所以使用单数形式strength。"]},"sentenceWithHints":"家人 是 我的 力量"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1479, '{"words":[{"plural":"families","chinese":"家人","english":"family","examples":["My family is very happy.","Families usually get together on holidays."],"phonetic":"/ˈfæməli/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is red.","This is my dog."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"","chinese":"温暖","english":"warmth","examples":["I feel the warmth of the sun.","Her hug gave me warmth."],"phonetic":"/wɔːrθ/","partOfSpeech":"名词"}],"examPoints":{"points":["集体名词的主谓一致","抽象名词的用法","形容词变抽象名词的构词"],"explanations":["family属于集体名词，当表示一个家庭整体概念时，视为单数，谓语动词用is；当强调家庭里的成员时视为复数，谓语动词用are。本句中family表示整体，所以用is。","warmth是抽象名词，用来表示“温暖”这种抽象的感觉，抽象名词一般为不可数名词，所以没有复数形式，前面通常不用不定冠词a/an。","warmth是由形容词warm（温暖的）加后缀-th构成的抽象名词，这是常见的形容词变名词的构词方式，类似的还有long-length（长度）、strong-strength（力量）。"]},"sentenceWithHints":"家人 是 我的 温暖"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1481, '{"words":[{"chinese":"阅读","english":"read","examples":["I read books every day.","Reading is my hobby."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for me."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","She has a happy family."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法","形容词作宾语补足语"],"explanations":["动词原形不能直接作主语，需要将其变为动名词形式（动词+ing），本句中read变为reading作主语，此时谓语动词要用第三人称单数形式，所以make变为makes。","make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”就是“让我快乐”的对应表达。","happy是形容词，在“make me happy”这个结构中，它用来补充说明宾语me的状态，在句中作宾语补足语，这是形容词的常见用法之一。"]},"sentenceWithHints":"阅读 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1482, '{"words":[{"plural":"","chinese":"阅读","english":"reading","examples":["Reading is my favorite hobby.","I enjoy reading before bed."],"phonetic":"/ˈriːdɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["My teacher helps me with math.","Please pass me the pen."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"学习","english":"learn","examples":["I learn English every day.","She learned to play the piano last year."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"}],"examPoints":{"points":["动名词作主语","使役动词let的用法"],"explanations":["动词原形不能直接作主语，需要变成动名词形式（动词后加-ing），本句中read变成reading作句子的主语，表示“阅读”这个行为。","使役动词let的常用结构是let sb. do sth.，意思是“让某人做某事”，后面接人称代词宾格（如me）和动词原形（如learn），主语是第三人称单数时，let要变成lets。"]},"sentenceWithHints":"阅读 让 我 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1483, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I have a cat."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"读了","english":"have read","examples":["I have read this book twice.","She reads a story every night."],"phonetic":"/hæv riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"","chinese":"很多","english":"many","examples":["There are many apples on the tree.","I have many friends."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"books","chinese":"书","english":"book","examples":["This is my favorite book.","I bought three books yesterday."],"phonetic":"/bʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","many 修饰可数名词复数","不规则动词 read 的形式"],"explanations":["现在完成时结构为have/has+动词过去分词，用来表示过去发生的动作对现在造成的影响，本句中“读了很多书”强调读书这个动作的结果，所以用现在完成时，主语是第一人称I，搭配助动词have。","many是形容词，用来修饰可数名词的复数形式，本句中book是可数名词，所以用many修饰时要变成复数books。","read是不规则动词，它的过去式、过去分词和原形拼写一致，都是read，但发音不同，原形和现在分词发音为/riːd/，过去式和过去分词发音为/red/。"]},"sentenceWithHints":"我 读了 很多 书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1484, '{"words":[{"chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"读了","english":"have read","examples":["I have read this book before.","She reads a story every night."],"phonetic":"/hæv red/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"chinese":"很多","english":"many","examples":["Many students like playing games.","There are many flowers in the garden."],"phonetic":"/ˈmeni/","partOfSpeech":"形容词"},{"plural":"stories","chinese":"故事","english":"story","examples":["She told me a funny story.","I have read many interesting stories."],"phonetic":"/ˈstɔːri/","partOfSpeech":"名词"}],"examPoints":{"points":["现在完成时的用法","可数名词复数变形","形容词many的用法"],"explanations":["现在完成时结构为have/has+动词过去分词，用于表示过去发生的动作对现在造成的影响，本句中“读了很多故事”强调已经完成的阅读动作，主语是第一人称I，所以用have read。","以辅音字母+y结尾的可数名词，变复数时要把y改为i再加-es，story的复数形式是stories。","many用于修饰可数名词复数，用来表示数量多，本句中修饰可数名词复数stories，不能用much（much修饰不可数名词）。"]},"sentenceWithHints":"我 读了 很多 故事"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1485, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to play football."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like eating ice cream.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"读","english":"read","examples":["I read a book every night.","He is reading a newspaper now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"storybooks","chinese":"故事书","english":"storybook","examples":["I have many storybooks.","My little sister loves storybooks."],"phonetic":"/ˈstɔːribʊk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的用法","可数名词复数","动词read的形式"],"explanations":["like作为动词表示“喜欢”时，常用结构为like doing sth.，表示长期的、习惯性的喜好，本句中like reading就符合这个结构，表达“喜欢阅读”的习惯。","可数名词表示一类事物时，常用复数形式，storybook是可数名词，这里用复数storybooks表示“故事书”这类书籍，不需要不定冠词修饰。","read的原形、过去式、过去分词拼写一致但发音不同，原形发音为/riːd/，过去式和过去分词发音为/red/；在like doing sth.结构中，read需要用现在分词形式reading。"]},"sentenceWithHints":"我 喜欢 读 故事书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1486, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to play football."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes singing songs."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"读","english":"read","examples":["I read a story every night.","He is reading a newspaper now."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"plural":"","chinese":"科普书","english":"science books","examples":["I enjoy reading science books.","The library has many interesting science books."],"phonetic":"/ˈsaɪəns bʊks/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["like的固定搭配","可数名词复数形式","动词read的读音变化"],"explanations":["like后接动词时，常用like doing sth.的结构，表示长期的、习惯性的喜好，本句中表示习惯性喜欢读科普书，所以用like reading。","科普书是可数名词，这里表示一类事物，所以用复数形式science books，可数名词复数可以用来泛指一类物品。","动词read的原形和过去式、过去分词拼写相同，但读音不同，原形读作/riːd/，过去式和过去分词读作/red/，本句中是原形，所以读/riːd/。"]},"sentenceWithHints":"我 喜欢 读 科普书"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1487, '{"words":[{"chinese":"阅读","english":"read","examples":["I read books every day.","Reading makes me happy."],"phonetic":"/riːd/","pastTense":"read","thirdPerson":"reads","partOfSpeech":"动词","pastParticiple":"read","presentParticiple":"reading"},{"chinese":"是","english":"is","examples":["She is tall.","Running is good exercise."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"很","english":"very","examples":["She is very nice.","The cake tastes very good."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"好","english":"good","examples":["This is a good idea.","He is a good boy."],"phonetic":"/ɡʊd/","partOfSpeech":"形容词"},{"chinese":"的","english":"of","examples":["a cup of tea","the color of the flower"],"phonetic":"/əv/","partOfSpeech":"助词"},{"plural":"habits","chinese":"习惯","english":"habit","examples":["Reading is a good habit.","He has a bad habit."],"phonetic":"/ˈhæbɪt/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","系动词be的用法","形容词修饰名词"],"explanations":["当动词要在句子中充当主语时，需要变成动名词形式（动词+ing），本句中\"阅读\"作主语，所以用Reading。","系动词be的形式要根据主语的单复数变化，本句主语Reading是动名词，属于第三人称单数概念，所以用is。","形容词用来修饰名词，放在名词前起到描述作用，本句中用形容词good修饰名词habit，说明习惯的性质。"]},"sentenceWithHints":"阅读 是 很 好 的 习惯"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1488, '{"words":[{"plural":"","chinese":"阅读","english":"reading","examples":["Reading is a good habit.","I love reading story books."],"phonetic":"/ˈriːdɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"broaden","examples":["Travel can broaden your mind.","Reading broadens our knowledge."],"phonetic":"/ˈbrɔːdn/","pastTense":"broadened","thirdPerson":"broadens","partOfSpeech":"动词","pastParticiple":"broadened","presentParticiple":"broadening"},{"chinese":"我","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"chinese":"开阔","english":"broaden","examples":["We need to broaden our horizons.","The new road will broaden access to the village."],"phonetic":"/ˈbrɔːdn/","pastTense":"broadened","thirdPerson":"broadens","partOfSpeech":"动词","pastParticiple":"broadened","presentParticiple":"broadening"},{"plural":"horizons","chinese":"视野","english":"horizon","examples":["Travel expands our horizons.","She has a broad horizon."],"phonetic":"/həˈraɪzn/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","动词第三人称单数变化","固定搭配 broaden one''s horizon"],"explanations":["当表示“做某事”这件事本身作主语时，需要把动词变成动名词形式（动词后加-ing），本句中“阅读”作为主语，所以用 reading。","当主语是第三人称单数（本句中主语 reading 属于第三人称单数概念）时，一般现在时的动词要变成第三人称单数形式，broadend 的第三人称单数是在词尾加-s，即 broadens。","broaden one''s horizon 是固定搭配，意为“开阔某人的视野”，这里的 horizon 常用复数形式 horizons，不过单数形式在口语和简单表达中也可使用，适合小学阶段的基础应用。"]},"sentenceWithHints":"阅读 让 我 开阔 视野"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1489, '{"words":[{"plural":"readings","chinese":"阅读","english":"reading","examples":["Reading is a good habit.","I love reading storybooks."],"phonetic":"/ˈriːdɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"enrich","examples":["Reading enriches our minds.","Travel can enrich your experience."],"phonetic":"/ɪnˈrɪtʃ/","pastTense":"enriched","thirdPerson":"enriches","partOfSpeech":"动词","pastParticiple":"enriched","presentParticiple":"enriching"},{"chinese":"我","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"chinese":"丰富","english":"enrich","examples":["Music can enrich our daily life.","Reading enriches my knowledge."],"phonetic":"/ɪnˈrɪtʃ/","pastTense":"enriched","thirdPerson":"enriches","partOfSpeech":"动词","pastParticiple":"enriched","presentParticiple":"enriching"},{"plural":"","chinese":"知识","english":"knowledge","examples":["We need to gain more knowledge.","Knowledge is power."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","不可数名词的用法","动词第三人称单数变化"],"explanations":["当动词要在句子中充当主语时，需要变成动名词形式（动词后加-ing），本句中“阅读”作为主语，所以用 reading。","knowledge 是不可数名词，没有复数形式，不能直接加-s，也不能用不定冠词 a/an 修饰，表达“丰富知识”直接用 enrich knowledge 即可。","当句子主语是第三人称单数（本句中 reading 属于第三人称单数主语）时，谓语动词要变成第三人称单数形式，规则动词一般在词尾加-es，enrich 的第三人称单数形式是 enriches。"]},"sentenceWithHints":"阅读 让 我 丰富 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1490, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"sports","chinese":"运动","english":"sports","examples":["I enjoy playing sports.","Sports are good for health."],"phonetic":"/spɔːrts/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词like的用法","可数名词的复数形式"],"explanations":["like作为实义动词，意为“喜欢”，后可接名词、动名词或不定式。当主语是第一人称I时，动词用原形like；当主语是第三人称单数时，动词要变为likes。本句主语是I，所以用like原形。","“运动”在这里表示各类体育运动，是可数名词，常用复数形式sports。在表达喜欢某类活动时，通常用可数名词的复数形式来泛指这类事物。"]},"sentenceWithHints":"我 喜欢 运动"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1491, '{"words":[{"plural":"sports","chinese":"运动","english":"sport","examples":["I love playing sports.","What''s your favorite sport?"],"phonetic":"/spɔːrt/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","My mom will make a cake for me."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please wait for me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"健康","english":"healthy","examples":["We need to eat healthy food.","She looks healthy and strong."],"phonetic":"/ˈhelθi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","可数名词复数的使用","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“make me healthy”即“使我健康”。同时当主语是复数时，make用原形，主语是第三人称单数时make变为makes。","sport表示“体育运动”时通常用复数形式sports，泛指各类运动，在本句中表示运动这一类活动，所以使用复数sports。","在“make + 宾语 + 宾补”的结构中，形容词可以作宾语补足语，用来补充说明宾语的状态，本句中healthy补充说明宾语me的状态，即“我（处于）健康（的状态）”。"]},"sentenceWithHints":"运动 让 我 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1492, '{"words":[{"plural":"sports","chinese":"运动","english":"sport","examples":["I like playing sports after school.","Basketball is my favorite sport."],"phonetic":"/spɔːrt/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me excited.","My mom made a cake for me yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please pass me the pen.","My friend invited me to the party."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy every day.","The happy children are playing in the park."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","可数名词复数的使用","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“make me happy”即“让我快乐”。同时当主语是第三人称单数时，make要变为makes，本句主语是复数sports，所以用原形make。","sport表示“体育运动”时，通常使用复数形式sports，泛指各类运动项目，在表达喜欢运动、进行运动这类泛指含义时，一般用复数。","在“make + 宾语 + 宾补”的结构中，形容词可以作宾语补足语，用来补充说明宾语的状态，本句中happy补充说明宾语me的状态，即“我”的状态是“快乐的”。"]},"sentenceWithHints":"运动 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1493, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school by bike."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I brush my teeth every day.","She practices dancing every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"运动","english":"exercise","examples":["I exercise for an hour every morning.","He exercises regularly to stay healthy."],"phonetic":"/ˈeksərsaɪz/","pastTense":"exercised","thirdPerson":"exercises","partOfSpeech":"动词","pastParticiple":"exercised","presentParticiple":"exercising"}],"examPoints":{"points":["一般现在时的用法","时间状语every day的使用","动词exercise的形式变化"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句中“每天运动”是日常习惯，因此使用一般现在时，主语是第一人称“I”，动词用原形exercise。","every day是表示频率的时间状语，意为“每天”，用于说明动作发生的经常性，在句中通常位于句末，要注意和形容词性的everyday（日常的）区分开。","exercise作为动词时，属于规则变化动词，过去式和过去分词直接加-ed，第三人称单数形式加-s，现在分词去e加-ing，在一般现在时中，当主语是第三人称单数时要使用其第三人称单数形式。"]},"sentenceWithHints":"我 每天 运动"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1494, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"mornings","chinese":"早上","english":"morning","examples":["I get up early in the morning.","She drinks milk every morning."],"phonetic":"/ˈmɔːrnɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"跑步","english":"run","examples":["I run for half an hour every day.","He runs faster than me."],"phonetic":"/rʌn/","pastTense":"ran","thirdPerson":"runs","partOfSpeech":"动词","pastParticiple":"run","presentParticiple":"running"}],"examPoints":{"points":["一般现在时的用法","时间介词in的搭配","不规则动词的变形"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句描述“我”早上跑步的习惯，主语是第一人称I，所以动词用原形run。","表示在上午、下午、晚上这类时间段时，需要用介词in搭配，即in the morning/afternoon/evening，这是固定的时间介词搭配规则。","run属于不规则动词，它的过去式是ran，过去分词是run，第三人称单数形式是runs，现在分词是running，需要特殊记忆，不能直接加-ed或-s变形。"]},"sentenceWithHints":"我 早上 跑步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1495, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"afternoons","chinese":"下午","english":"afternoon","examples":["I have a class in the afternoon.","We will go shopping this afternoon."],"phonetic":"/ˌæftərˈnuːn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"打","english":"play","examples":["I play football every weekend.","She plays the piano well."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"},{"plural":"ball games","chinese":"球","english":"ball games","examples":["We often play ball games after school.","Ball games are popular among kids."],"phonetic":"/bɔːl ɡeɪmz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","时间介词in的使用","固定搭配play ball games"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句描述日常的活动，主语是第一人称I，所以动词用原形play。当主语是第三人称单数时，动词要变为第三人称单数形式plays。","表示在上午、下午、晚上这类时间段时，要用介词in，构成in the morning/afternoon/evening的固定搭配，注意要加定冠词the。","在英语中表示“打球”这类球类活动，常用固定搭配play ball games，而不是直接翻译为play ball，这是符合英语表达习惯的常用短语。"]},"sentenceWithHints":"我 下午 打 球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1496, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading books."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"soccers","chinese":"足球","english":"soccer","examples":["I play soccer every weekend.","Soccer is a popular sport."],"phonetic":"/ˈsɑːkər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称主语搭配动词原形","球类名词的用法"],"explanations":["当主语是第一人称I（我）时，一般现在时中后面的实义动词要用原形，本句中主语是I，所以动词like用原形。","表示球类运动的名词前通常不加冠词，直接使用，比如“play soccer（踢足球）”，不需要加a/an或the，这是小学阶段需要掌握的名词搭配规则。"]},"sentenceWithHints":"我 喜欢 足球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1497, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading books."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"basketballs","chinese":"篮球","english":"basketball","examples":["He plays basketball every day.","I have a new basketball."],"phonetic":"/ˈbæskɪtbɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称主语搭配动词原形","球类名词的用法"],"explanations":["当主语是第一人称代词I时，一般现在时态下，后面的实义动词要用原形，本句中主语是I，所以动词用like的原形。","表示球类运动的名词前通常不加冠词，直接使用，比如“play basketball”，不需要加a/an或the，这是小学阶段需要掌握的名词固定搭配用法。"]},"sentenceWithHints":"我 喜欢 篮球"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1498, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"游泳","english":"swim","examples":["I swim every weekend.","She is swimming in the pool."],"phonetic":"/swɪm/","pastTense":"swam","thirdPerson":"swims","partOfSpeech":"动词","pastParticiple":"swum","presentParticiple":"swimming"}],"examPoints":{"points":["like后接动名词的用法","人称代词主格的使用","不规则动词的变形"],"explanations":["like作为动词表示“喜欢”时，后面可以接动名词（即动词的-ing形式），表示长期的爱好或习惯，本句中like swimming表示长期喜欢游泳这个爱好。","人称代词主格I在句中作主语，用于指代说话人自己，在一般现在时中，当主语是I时，后面的动词用原形，所以本句中like用原形。","swim是不规则动词，它的过去式是swam，过去分词是swum，第三人称单数形式是swims，现在分词需要双写末尾的辅音字母m再加-ing，即swimming，需要牢记这类不规则动词的变形规则。"]},"sentenceWithHints":"我 喜欢 游泳"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1499, '{"words":[{"plural":"sports","chinese":"运动","english":"sport","examples":["I like playing sports after school.","Basketball is my favorite sport."],"phonetic":"/spɔːrt/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The book is very interesting.","She runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to study hard.","Health is important for everyone."],"phonetic":"/ɪmˈpɔːrtnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["名词复数与主谓一致","副词修饰形容词的用法"],"explanations":["表示泛指的运动类别时，常用sport的复数形式sports，此时主语为复数，对应的be动词要用are，这是小学阶段需要掌握的主谓一致知识点，即复数主语搭配复数形式的be动词。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来强调important的程度，这是小学阶段副词修饰形容词的基础用法。"]},"sentenceWithHints":"运动 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1500, '{"words":[{"plural":"sports","chinese":"运动","english":"sport","examples":["I like playing sports after school.","Basketball is my favorite sport."],"phonetic":"/spɔːrt/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","My mom made a cake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please pass me the book."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"强壮","english":"strong","examples":["He is a strong boy.","The strong wind blew the tree down."],"phonetic":"/strɔːŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","可数名词复数形式","人称代词宾格的使用"],"explanations":["make作为使役动词，常见结构为make + 宾语 + 形容词，表示“使某人/某物处于某种状态”，本句中make me strong即“让我强壮”。当主语是复数时，make用原形；主语是第三人称单数时，make要变为makes。","sport是可数名词，当表示泛指的运动类别时，通常使用复数形式sports，本句中用sports指代各类运动，符合英语表达习惯。","“我”在句中作动词make的宾语，所以要使用人称代词的宾格形式me，而不是主格I，这是人称代词主格和宾格的用法区别，主格用于作主语，宾格用于作宾语。"]},"sentenceWithHints":"运动 让 我 强壮"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1501, '{"words":[{"plural":"sports","chinese":"运动","english":"sport","examples":["I like playing sports after school.","Swimming is my favorite sport."],"phonetic":"/spɔːrt/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The story makes me laugh.","My mom makes delicious food every day."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","My teacher helps me with my homework."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"有","english":"have","examples":["I have a new bag.","She has a cat."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"chinese":"活力","english":"energetic","examples":["After exercising, I feel energetic.","My grandpa is always energetic in the morning."],"phonetic":"/ˌenərˈdʒetɪk/","partOfSpeech":"形容词"}],"examPoints":{"points":["可数名词的复数形式","使役动词make的用法","形容词作宾语补足语"],"explanations":["表示泛指的运动时，sport常用复数形式sports，本句中“运动”是泛指各类运动，所以用sports。","make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中make me energetic意为“让我有活力”。","energetic是形容词，在句中作宾语me的补足语，用来补充说明宾语的状态，这是小学阶段需要掌握的简单复合结构用法。"]},"sentenceWithHints":"运动 让 我 有 活力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1502, '{"words":[{"plural":"sports","chinese":"运动","english":"sport","examples":["I like playing sports after school.","Basketball is my favorite sport."],"phonetic":"/spɔːrt/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["My mom makes me breakfast every day.","Reading makes me happy."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please wait for me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"交","english":"make","examples":["I want to make new friends.","She made a mistake in the test."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have many good friends.","We are friends forever."],"phonetic":"/frend/","partOfSpeech":"名词"}],"examPoints":{"points":["make 的使役用法","可数名词的复数形式","固定搭配 make friends"],"explanations":["make 作为使役动词，常见结构为 make sb. do sth.，意思是“让某人做某事”，这里的动词要用原形。本句中“运动让我交朋友”就用到了这个结构，make me make friends 里的第二个 make 用原形。","可数名词表示泛指一类事物时，常用复数形式。“运动”在这里指各类运动，所以用 sports；“朋友”不是指单个朋友，所以用复数 friends，可数名词变复数一般在词尾加-s。","make friends 是固定搭配，意思是“交朋友”，这里 friend 必须用复数形式，不能用单数 friend。"]},"sentenceWithHints":"运动 让 我 交 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1503, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will help you.","She will come tomorrow."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"坚持","english":"persist","examples":["If you persist, you will succeed.","She persists in learning English every day."],"phonetic":"/pərˈsɪst/","pastTense":"persisted","thirdPerson":"persists","partOfSpeech":"动词","pastParticiple":"persisted","presentParticiple":"persisting"},{"plural":"","chinese":"运动","english":"exercise","examples":["I exercise every morning.","You should exercise more to keep healthy."],"phonetic":"/ˈeksərsaɪz/","pastTense":"exercised","thirdPerson":"exercises","partOfSpeech":"动词","pastParticiple":"exercised","presentParticiple":"exercising"}],"examPoints":{"points":["一般将来时的表达","动词短语persist in的用法","动名词的使用"],"explanations":["小学阶段一般将来时常用“will+动词原形”结构表示将来要做的动作，本句中“会”表达将来的意愿，所以用will加persist的原形构成将来时态。","persist是不及物动词，后面接宾语时需要加介词in，构成persist in doing sth.的固定搭配，意思是“坚持做某事”，这是小学阶段需要掌握的动词短语搭配。","在persist in这个短语中，in是介词，介词后面的动词需要变成动名词形式，也就是动词加-ing，所以exercise要变成exercising，这是介词后接动名词的基础语法点。"]},"sentenceWithHints":"我 会 坚持 运动"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1504, '{"words":[{"plural":"sports","chinese":"运动","english":"sport","examples":["I like playing sports after school.","Basketball is my favorite sport."],"phonetic":"/spɔːrt/","partOfSpeech":"名词"},{"chinese":"是","english":"are","examples":["You are my best friend.","They are playing games."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my new pen."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have many good friends.","She is my close friend."],"phonetic":"/frend/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的复数形式","be动词的主谓一致"],"explanations":["表示泛指的一类事物时，可数名词常用复数形式。这里“运动”指各类运动，所以用sport的复数sports；“朋友”对应各类运动，也用复数friends。规则可数名词变复数一般在词尾加-s。","be动词的形式要和主语保持一致：主语是复数时，be动词用are。本句主语sports是复数名词，所以搭配are，同时表语friends也用复数形式呼应主语，保持语义和语法的一致性。"]},"sentenceWithHints":"运动 是 我的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1506, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes cats very much."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"旅行","english":"travel","examples":["I want to travel around the world.","She is traveling in Japan now."],"phonetic":"/ˈtrævl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"}],"examPoints":{"points":["动词like的用法","动名词作宾语"],"explanations":["like作为动词，常见用法有like + 名词/代词，表示喜欢某物或某人；还有like + doing sth.，表示长期的、习惯性的喜欢做某事，本句使用的是第二种用法。当主语是第三人称单数时，like要变成likes。","在like后面接动词时，需要用该动词的动名词形式（即动词+ing）来作宾语，travel的动名词形式是traveling，这里要注意travel的拼写，双写l再加ing是美式英语的写法，符合参考翻译的要求。"]},"sentenceWithHints":"我 喜欢 旅行"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1507, '{"words":[{"chinese":"旅行","english":"travel","examples":["I love to travel around the world.","Traveling can make us happy."],"phonetic":"/ˈtrævəl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her mom."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please wait for me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"开阔","english":"broaden","examples":["Reading can broaden our minds.","Travel broadens our horizons."],"phonetic":"/ˈbrɔːdn/","pastTense":"broadened","thirdPerson":"broadens","partOfSpeech":"动词","pastParticiple":"broadened","presentParticiple":"broadening"},{"plural":"visions","chinese":"眼界","english":"vision","examples":["We need to have a clear vision for the future.","Travel expands our vision."],"phonetic":"/ˈvɪʒn/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","动词第三人称单数变化","固定搭配"],"explanations":["当表示“旅行”这个行为作主语时，需要将动词 travel 变为动名词形式 traveling，此时主语视为第三人称单数，谓语动词要用第三人称单数形式。本句中用 Traveling 作主语，对应谓语动词 broadens。","一般情况下，动词的第三人称单数形式是在词尾加-s，broaden 属于规则变化，直接加-s 变为 broadens；travel 的第三人称单数形式也是直接加-s 变为 travels。当主语是第三人称单数（如动名词、单数名词、he/she/it 等）时，谓语动词要使用第三人称单数形式。","“开阔眼界”对应的常用英语固定搭配是 broaden one''s vision 或 broaden one''s horizons，本句参考翻译使用的是 broaden my vision，其中 my 对应句中的“我”，符合人称指代一致的要求。"]},"sentenceWithHints":"旅行 让 我 开阔 眼界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1508, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to go to the park."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"去了","english":"have been to","examples":["I have been to Beijing twice.","She has been to the new museum."],"phonetic":"/hæv bɪn tuː/","pastTense":"","thirdPerson":"has been to","partOfSpeech":"动词","pastParticiple":"","presentParticiple":"having been to"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like playing football.","There are many books on the shelf."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"places","chinese":"地方","english":"place","examples":["This is a beautiful place.","I want to visit more interesting places."],"phonetic":"/pleɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时 have been to 的用法","many 修饰可数名词复数","可数名词的复数变化"],"explanations":["have been to 表示“曾经去过某地，现在已经回来了”，是现在完成时的常用结构，主语为第一、二人称或复数时用 have been to，主语为第三人称单数时用 has been to。本句表达“我曾经去过很多地方，现在已经回来”，所以用这个结构。","many 是形容词，用来修饰可数名词的复数形式，强调数量多，不能修饰不可数名词，本句中用来修饰 places（place 的复数形式）。","可数名词变复数时，一般在词尾加 -s，place 是以不发音的字母 e 结尾的名词，直接加 -s 变为 places，属于规则变化。"]},"sentenceWithHints":"我 去了 很多 地方"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1509, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am from China."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"去过","english":"have been to","examples":["I have been to Shanghai twice.","She has been to the Great Wall."],"phonetic":"/hæv bɪn tuː/","pastTense":"","thirdPerson":"has been to","partOfSpeech":"动词","pastParticiple":"","presentParticiple":"having been to"},{"plural":"","chinese":"北京","english":"Beijing","examples":["Beijing is the capital of China.","I want to visit Beijing."],"phonetic":"/beɪˈdʒɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","have been to 的含义与用法"],"explanations":["现在完成时由“助动词have/has + 过去分词”构成，主要用于表示过去发生的动作对现在造成的影响或结果，或是过去的动作或状态持续到现在。本句中“去过北京”表示这个经历对现在有影响，即说话人有了到过北京的经历，所以使用现在完成时。","have been to 是现在完成时的固定表达，意为“曾经去过某地”，表示说话人现在已经不在那个地方了。当主语是第三人称单数时，要将have改为has，即has been to。"]},"sentenceWithHints":"我 去过 北京"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1510, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am from China."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"去过","english":"have been to","examples":["I have been to Beijing twice.","She has been to the park already."],"phonetic":"/hæv bɪn tuː/","pastTense":"","thirdPerson":"has been to","partOfSpeech":"动词","pastParticiple":"","presentParticiple":"having been to"},{"plural":"","chinese":"上海","english":"Shanghai","examples":["Shanghai is a big city.","I want to visit Shanghai."],"phonetic":"/ˈʃæŋhaɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法（have/has been to）","专有名词的大写规则"],"explanations":["have/has been to 是现在完成时的固定表达，意思是“曾经去过某地（现在已经回来了）”，当主语是第一、二人称或复数时用have been to，主语是第三人称单数时用has been to。本句主语是第一人称“I”，所以用have been to，用来表达说话人有去过上海的经历。","表示城市、国家等的专有名词首字母必须大写，Shanghai是中国的城市名，属于专有名词，所以书写时首字母要大写。"]},"sentenceWithHints":"我 去过 上海"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1511, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"去过","english":"have been to","examples":["I have been to Beijing twice.","She has been to the park already."],"phonetic":"/hæv bɪn tuː/","pastTense":"had been to","thirdPerson":"has been to","partOfSpeech":"动词","pastParticiple":"have/has been to","presentParticiple":"having been to"},{"plural":"","chinese":"杭州","english":"Hangzhou","examples":["Hangzhou is a beautiful city.","I want to visit Hangzhou someday."],"phonetic":"/ˈhɑːŋˈdʒoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法：have/has been to","专有名词的拼写"],"explanations":["have/has been to 是现在完成时的固定表达，意为“曾经去过某地（现在已经回来了）”，当主语是第一、二人称或复数时用have been to，主语是第三人称单数时用has been to。本句主语是第一人称“我”，所以用have been to，用来表达说话人有去过杭州的经历。","杭州是中国的城市名称，属于专有名词，英文拼写为Hangzhou，首字母必须大写，这类表示地名的专有名词在翻译和书写时都要注意大写规范。"]},"sentenceWithHints":"我 去过 杭州"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1512, '{"words":[{"plural":"","chinese":"每个","english":"every","examples":["Every student likes reading.","Every day is a new start."],"phonetic":"/ˈevri/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"cities","chinese":"城市","english":"city","examples":["I live in a small city.","This city is very beautiful."],"phonetic":"/ˈsɪti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"all","examples":["We all love our country.","They are all happy."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"features","chinese":"特色","english":"feature","examples":["The hotel has many special features.","This phone''s main feature is its camera."],"phonetic":"/ˈfiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不定代词 every 的用法","动词 have 的第三人称单数变化","可数名词的复数形式"],"explanations":["every 作为形容词，后接可数名词单数，用来表示三者或三者以上的“每一个”，强调全体，在本句中修饰 city，整体作主语时视为第三人称单数。","have 作为实义动词表示“有”，当主语是第三人称单数（如本句的 every city）时，要变为第三人称单数形式 has。","feature 是可数名词，本句中表示多个特色，所以要用复数形式。以“辅音字母+y”结尾的可数名词，变复数时要把 y 改为 i 再加 -es，city 的复数 cities 也遵循该规则。"]},"sentenceWithHints":"每个 城市 都 有 特色"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1513, '{"words":[{"plural":"","chinese":"旅行","english":"traveling","examples":["Traveling is my favorite hobby.","I love traveling to different countries."],"phonetic":"/ˈtrævəlɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","She let her friend borrow her book."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"了解","english":"understand","examples":["I understand your feelings.","She understands how to solve the problem."],"phonetic":"/ˌʌndərˈstænd/","pastTense":"understood","thirdPerson":"understands","partOfSpeech":"动词","pastParticiple":"understood","presentParticiple":"understanding"},{"plural":"cultures","chinese":"文化","english":"culture","examples":["We should respect different cultures.","Chinese culture is very rich."],"phonetic":"/ˈkʌltʃər/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","使役动词let的用法","动词不定式省略to的情况"],"explanations":["当表示“做某事”这个行为作为句子主语时，需要把动词变成动名词形式（即动词后加-ing），本句中“旅行”作为主语，所以用traveling，不能用原形travel。","let作为使役动词，常见用法是“let sb. do sth.”，意思是“让某人做某事”，主语是第三人称单数时，let要变成lets，本句主语Traveling是第三人称单数，所以用lets。","在使役动词let、make、have后面接宾语补足语时，动词不定式要省略to，所以本句中“了解”用动词原形understand，而不是to understand。"]},"sentenceWithHints":"旅行 让 我 了解 文化"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1514, '{"words":[{"chinese":"旅行","english":"travel","examples":["I love to travel around the world.","Traveling broadens our horizons."],"phonetic":"/ˈtrævəl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park this weekend."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"plural":"","chinese":"我","english":"me","examples":["Please pass me the pen.","He told me a funny story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"体验","english":"experience","examples":["We can experience different cultures here.","She experienced a lot of difficulties."],"phonetic":"/ɪkˈspɪriəns/","pastTense":"experienced","thirdPerson":"experiences","partOfSpeech":"动词","pastParticiple":"experienced","presentParticiple":"experiencing"},{"plural":"lives","chinese":"生活","english":"life","examples":["We should enjoy every moment of life.","Many people lost their lives in the accident."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","使役动词let的用法","可数名词不规则复数变化"],"explanations":["动词原形不能直接作主语，需要将其变为动名词形式（即动词+ing），本句中travel变为traveling在句中作主语，表示“旅行”这件事。","使役动词let后接宾语+动词原形，构成“let sb. do sth.”的结构，意思是“让某人做某事”，本句中let后接宾语me，再接动词原形experience。","life作为“生活；生命”讲时，是可数名词，其复数形式属于不规则变化，需要变为lives，而不是直接加s。"]},"sentenceWithHints":"旅行 让 我 体验 生活"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1515, '{"words":[{"chinese":"旅行","english":"travel","examples":["I love to travel around the world.","Traveling is a great way to learn."],"phonetic":"/ˈtrævl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her mom."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me with my homework."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","The happy children are playing."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法"],"explanations":["动词原形不能直接作主语，需要将其变为动名词形式（动词+ing），本句中travel变为traveling作句子主语，此时谓语动词要用第三人称单数形式。","make作为使役动词，常见用法为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”即表示“让我处于快乐的状态”，当主语是第三人称单数时，make要变为makes。"]},"sentenceWithHints":"旅行 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1516, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes cats."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"吃","english":"eat","examples":["I eat rice every day.","He has eaten breakfast."],"phonetic":"/iːt/","pastTense":"ate","thirdPerson":"eats","partOfSpeech":"动词","pastParticiple":"eaten","presentParticiple":"eating"},{"plural":"delicious foods","chinese":"美食","english":"delicious food","examples":["We enjoyed delicious food at the party.","She can cook delicious food."],"phonetic":"/dɪˈlɪʃəs fuːd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词 like 的用法","可数与不可数名词的区分","形容词修饰名词的用法"],"explanations":["like 作为动词表示“喜欢”，常见用法有 like + 名词/代词，或者 like + doing sth.（表示长期的爱好）。本句中参考翻译省略了动词eat，用like直接加名词短语delicious food来表达喜欢美食的意思，符合英语常用表达习惯。","food表示“食物、食品”时，通常是不可数名词；表示“不同种类的食物”时，可作可数名词，复数形式为foods。本句中delicious food指美食这类事物，用作不可数概念。","形容词用来修饰名词，通常放在名词前面，本句中用形容词delicious修饰名词food，用来描述食物的属性“美味的”，符合英语形容词修饰名词的语序规则。"]},"sentenceWithHints":"我 喜欢 吃 美食"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1517, '{"words":[{"plural":"","chinese":"每个","english":"every","examples":["Every student likes reading.","Every day is a new start."],"phonetic":"/ˈevri/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"places","chinese":"地方","english":"place","examples":["This is a beautiful place.","I want to visit many places."],"phonetic":"/pleɪs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has a new bag."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"delicious foods","chinese":"美食","english":"delicious food","examples":["I love trying delicious food.","The city is famous for its delicious foods."],"phonetic":"/dɪˈlɪʃəs fuːd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不定代词every的用法","主谓一致规则","形容词修饰名词的用法"],"explanations":["every是形容词，用来修饰单数可数名词，表示“每个，每一”，强调全体，在句中作定语，常搭配单数可数名词使用，如every place、every student。","当主语是由every修饰的单数可数名词时，谓语动词要用第三人称单数形式。本句中主语every place是单数概念，所以动词have要用第三人称单数形式has。","形容词用来修饰名词，放在名词前起到描述作用，本句中delicious是形容词，用来修饰food，说明食物的特点是美味的，符合“形容词+名词”的名词短语结构。"]},"sentenceWithHints":"每个 地方 都 有 美食"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1518, '{"words":[{"plural":"","chinese":"北京","english":"Beijing","examples":["Beijing is the capital of China.","I want to visit Beijing someday."],"phonetic":"/beɪˈdʒɪŋ/","partOfSpeech":"名词"},{"plural":"ducks","chinese":"烤鸭","english":"duck","examples":["I like roast duck very much.","There are many ducks in the lake."],"phonetic":"/dʌk/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very tall.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"好吃","english":"delicious","examples":["The cake is delicious.","This soup tastes delicious."],"phonetic":"/dɪˈlɪʃəs/","partOfSpeech":"形容词"}],"examPoints":{"points":["专有名词的英文表达","主系表结构的简单句","副词修饰形容词的用法"],"explanations":["表示城市名称的专有名词“北京”英文直接用“Beijing”，属于专有名词，首字母需要大写，这类专有名词在翻译时通常采用音译的方式。","本句是典型的主系表结构简单句，主语“Beijing duck”是单数名词短语，因此系动词用“is”，表语“delicious”用来描述主语的特征，小学阶段需要掌握这类基础的主系表句式来表达事物的属性。","副词“very”用来修饰形容词“delicious”，用来加强形容词的语气，说明“好吃”的程度，小学阶段需要掌握用“very”修饰形容词的基础副词用法。"]},"sentenceWithHints":"北京 烤鸭 很 好吃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1519, '{"words":[{"plural":"","chinese":"上海","english":"Shanghai","examples":["Shanghai is a beautiful city.","I want to visit Shanghai."],"phonetic":"/ˈʃæŋhaɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"soup dumplings","chinese":"小笼包","english":"soup dumplings","examples":["I love eating soup dumplings for breakfast.","The soup dumplings in this restaurant are very tasty."],"phonetic":"/suːp ˈdʌmplɪŋz/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The flower is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好吃","english":"delicious","examples":["The cake is delicious.","This delicious meal makes me happy."],"phonetic":"/dɪˈlɪʃəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["专有名词的拼写与用法","可数名词复数形式","系动词的主谓一致","副词修饰形容词的用法"],"explanations":["表示城市名称的专有名词首字母必须大写，\"上海\"对应的英文\"Shanghai\"属于专有名词，书写时要注意首字母大写，不需要加冠词。","“小笼包”是可数名词，英文对应\"soup dumpling\"，表示一类食物时常用复数形式\"soup dumplings\"，规则可数名词变复数一般在词尾加-s。","本句主语\"soup dumplings\"是复数形式，所以对应的系动词要用复数形式\"are\"，主谓一致要求主语和系动词在单复数形式上保持匹配。","副词\"very\"用来修饰形容词\"delicious\"，用来加强形容词的语气，说明程度，副词修饰形容词时要放在形容词的前面。"]},"sentenceWithHints":"上海 小笼包 很 好吃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1520, '{"words":[{"plural":"","chinese":"杭州","english":"Hangzhou","examples":["Hangzhou is a beautiful city.","I want to visit Hangzhou someday."],"phonetic":"/ˈhɑːŋˈdʒoʊ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"西湖","english":"West Lake","examples":["West Lake is a famous scenic spot in Hangzhou.","We took a walk around West Lake."],"phonetic":"/west leɪk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"vinegar fish","chinese":"醋鱼","english":"vinegar fish","examples":["Vinegar fish is a traditional dish in Hangzhou.","I''d like to try the famous vinegar fish."],"phonetic":"/ˈvɪnɪɡər fɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The book is very interesting.","She runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好吃","english":"delicious","examples":["The cake is delicious.","We had a delicious dinner last night."],"phonetic":"/dɪˈlɪʃəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["专有名词的英文表达","主系表句型的使用","副词修饰形容词的用法"],"explanations":["表示地名、景点名、特色菜名的专有名词，英文表达通常采用拼音（如Hangzhou）或约定俗成的固定搭配（如West Lake、vinegar fish），注意首字母大写规则：单个拼音地名首字母大写，由普通名词构成的景点名每个单词首字母大写。","本句使用主系表基本句型，主语是“West Lake vinegar fish”（单数专有名词），系动词用is，表语是形容词delicious，用来描述主语的特征，小学阶段需要掌握这种用来描述事物属性的基础句型。","副词very用来修饰形容词delicious，放在形容词之前，用来加强形容词的语气，说明“好吃”的程度，这是小学阶段需要掌握的副词修饰形容词的基础用法。"]},"sentenceWithHints":"杭州 西湖 醋鱼 很 好吃"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1521, '{"words":[{"plural":"delicious foods","chinese":"美食","english":"delicious food","examples":["Delicious food makes people feel good.","We enjoyed lots of delicious foods at the party."],"phonetic":"/dɪˈlɪʃəs fuːd/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The story makes me cry.","She made a cake for her sister."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy every day.","The happy children are playing in the park."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作宾语补足语","第三人称单数谓语动词变化"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”就是“使我快乐”的意思，符合这个结构。","在“make + 宾语 + 形容词”的结构里，形容词happy用来补充说明宾语me的状态，在句中充当宾语补足语，这是小学阶段需要掌握的宾语补足语常见用法之一。","当句子主语是第三人称单数时，一般现在时的谓语动词要使用第三人称单数形式。本句主语“delicious food”是不可数名词，属于第三人称单数范畴，所以动词make要变为makes。"]},"sentenceWithHints":"美食 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1522, '{"words":[{"plural":"delicious foods","chinese":"美食","english":"delicious food","examples":["Delicious food makes people happy.","We enjoyed lots of delicious foods at the party."],"phonetic":"/dɪˈlɪʃəs fuːd/","partOfSpeech":"名词"},{"chinese":"让","english":"satisfy","examples":["The good service satisfied all the customers.","She satisfies her hunger with a piece of bread."],"phonetic":"/ˈsætɪsfaɪ/","pastTense":"satisfied","thirdPerson":"satisfies","partOfSpeech":"动词","pastParticiple":"satisfied","presentParticiple":"satisfying"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please pass me the water."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"满足","english":"satisfied","examples":["I am satisfied with the result.","She looks satisfied after the meal."],"phonetic":"/ˈsætɪsfaɪd/","partOfSpeech":"形容词"}],"examPoints":{"points":["动词的第三人称单数形式","代词的宾格用法","形容词作定语的用法"],"explanations":["当句子主语是第三人称单数（本句中delicious food属于第三人称单数主语），一般现在时的谓语动词要使用第三人称单数形式，satisfy的第三人称单数是satisfies，即在词尾加-ies。","在句子中作动词的宾语时，人称代词要使用宾格形式，“我”的宾格是me，本句中me作satisfies的宾语。","形容词可以放在名词前作定语修饰名词，本句中delicious是形容词，放在名词food前，用来修饰food，说明食物的特点是美味的。"]},"sentenceWithHints":"美食 让 我 满足"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1523, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"继续","english":"continue","examples":["He continued his work after lunch.","We will continue our journey."],"phonetic":"/kənˈtɪnjuː/","pastTense":"continued","thirdPerson":"continues","partOfSpeech":"动词","pastParticiple":"continued","presentParticiple":"continuing"},{"plural":"","chinese":"旅行","english":"travel","examples":["I travel to Beijing every year.","She is traveling in Europe now."],"phonetic":"/ˈtrævl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"}],"examPoints":{"points":["一般将来时的表达","continue的用法"],"explanations":["一般将来时可以用“will + 动词原形”结构表示将来要发生的动作，本句中“会”表示将来的意愿，所以用will加continue的原形来表达。","continue后可以接动名词（即动词的-ing形式）表示“继续做某事”，这里travel用traveling的形式，符合continue doing sth.的固定搭配，强调继续进行之前在做的同一件事。"]},"sentenceWithHints":"我 会 继续 旅行"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1524, '{"words":[{"chinese":"旅行","english":"travel","examples":["I love to travel around the world.","Traveling broadens our horizons."],"phonetic":"/ˈtrævəl/","pastTense":"traveled","thirdPerson":"travels","partOfSpeech":"动词","pastParticiple":"traveled","presentParticiple":"traveling"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","She wants to grow into a kind person."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法","不规则动词的变形"],"explanations":["当动词在句子中充当主语时，需要将其变为动名词形式（即动词+ing），本句中“旅行”作主语，所以使用traveling。","使役动词let后接宾语和不带to的动词不定式，结构为let sb. do sth.，表示“让某人做某事”，本句中let me grow就符合这个结构。","部分动词的过去式、过去分词是不规则变化，比如grow的过去式是grew，过去分词是grown；let的过去式和过去分词和原形一致，需要特殊记忆。"]},"sentenceWithHints":"旅行 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1525, '{"words":[{"plural":"","chinese":"旅行","english":"traveling","examples":["Traveling is a great way to relax.","I enjoy traveling to different cities."],"phonetic":"/ˈtrævəlɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is happy.","This is my new pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"hobbies","chinese":"爱好","english":"hobby","examples":["Reading is my hobby.","He has many hobbies like painting and singing."],"phonetic":"/ˈhɑːbi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","名词复数变化"],"explanations":["当表示“做某事”这个行为作为主语时，需要把动词变成动名词形式（动词后加-ing），本句中“旅行”作为主语，所以用traveling，动名词作主语时，谓语动词用单数形式。","系动词be有am、is、are三种形式，当主语是第三人称单数或不可数名词、动名词时，be动词用is，本句主语是动名词traveling，属于第三人称单数概念，所以用is。","以辅音字母+y结尾的可数名词，变复数时要把y改成i再加-es，hobby是以辅音字母b+y结尾，所以复数形式是hobbies。"]},"sentenceWithHints":"旅行 是 我的 爱好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1526, '{"words":[{"chinese":"学习","english":"study","examples":["I study English every day.","Studying hard is the key to success."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"","chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to keep healthy.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","副词修饰形容词"],"explanations":["动词原形不能直接作句子主语，需要将其变为动名词形式（动词后加-ing），本句中\"学习\"作主语，所以使用studying这种动名词形式，此时主语视为单数，搭配系动词is。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very用来修饰形容词important，强调重要的程度。"]},"sentenceWithHints":"学习 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1527, '{"words":[{"chinese":"学习","english":"study","examples":["I study English every day.","Studying hard is important for students."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park together."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"进步","english":"progress","examples":["She is progressing quickly in her math class.","I hope to progress in my speaking skills."],"phonetic":"/ˈprɑːɡres/","pastTense":"progressed","thirdPerson":"progresses","partOfSpeech":"动词","pastParticiple":"progressed","presentParticiple":"progressing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法","动词progress的用法"],"explanations":["当动词需要在句子中充当主语时，要将其变为动名词形式（即动词+ing），本句中“学习”作主语，所以使用studying。动名词作主语时，谓语动词要用第三人称单数形式，因此let变为lets。","let是使役动词，常见用法为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中lets me progress符合这个结构。","progress既可以作名词也可以作动词，在本句中是动词，意为“进步、进展”，表示在能力、知识等方面得到提升，作动词使用时要注意其动词的变形规则，同时在使役动词let后要用原形。"]},"sentenceWithHints":"学习 让 我 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1528, '{"words":[{"chinese":"学习","english":"study","examples":["I study English every day.","Studying hard is important for students."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"让","english":"let","examples":["My mother lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["Please give me a pen.","Me too."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","I want to grow into a kind person."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法","不规则动词的变形"],"explanations":["动词原形不能直接作主语，需要将其变为动名词形式（动词+ing），本句中\"学习\"作主语，所以用studying，此时主语视为第三人称单数，谓语动词要用第三人称单数形式，所以let变为lets。","let作为使役动词，常用结构为\"let sb. do sth.\"，表示\"让某人做某事\"，后面接不带to的动词不定式作宾语补足语，所以本句中\"成长\"用动词原形grow。","本句涉及多个不规则动词变形：let的过去式和过去分词都是原形let；grow的过去式是grew，过去分词是grown；study作为规则动词，变过去式、过去分词要变y为i加ed，第三人称单数变y为i加es，这些都是初中阶段需要重点掌握的动词变形规则。"]},"sentenceWithHints":"学习 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1529, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"努力","english":"hard","examples":["He works hard every day.","She tried hard to finish the task."],"phonetic":"/hɑːrd/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"study","examples":["I study English every night.","She studies hard for the exam."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"}],"examPoints":{"points":["副词的位置","一般现在时的用法"],"explanations":["当hard作为副词表示“努力地”时，通常放在实义动词之后，用来修饰动词说明动作的方式，本句中放在study之后，符合副词修饰实义动词的位置规则。","一般现在时用于表示经常性、习惯性的动作，本句描述的是日常的学习状态，主语是第一人称I，所以谓语动词用原形study；如果主语是第三人称单数，谓语动词要变为studies。"]},"sentenceWithHints":"我 努力 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1530, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"认真","english":"carefully","examples":["He drives carefully on rainy days.","Please listen carefully to the teacher."],"phonetic":"/ˈkerfəli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"听讲","english":"listen","examples":["Listen to the radio, please.","She listens to music every night."],"phonetic":"/ˈlɪsən/","pastTense":"listened","thirdPerson":"listens","partOfSpeech":"动词","pastParticiple":"listened","presentParticiple":"listening"}],"examPoints":{"points":["副词修饰动词的用法","不及物动词listen的用法"],"explanations":["副词用来修饰动词、形容词或其他副词，在本句中，副词carefully修饰动词listen，说明听讲的状态是认真的，通常放在动词之后。","listen是不及物动词，后面不能直接加宾语，若要接听的对象，需要搭配介词to，比如listen to the teacher。本句中没有明确听的对象，所以直接使用listen即可。"]},"sentenceWithHints":"我 认真 听讲"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1531, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"认真","english":"seriously","examples":["You should take this seriously.","He drives seriously and safely."],"phonetic":"/ˈsɪriəsli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"做","english":"do","examples":["I do my housework on weekends.","She does well in math."],"phonetic":"/duː/","pastTense":"did","thirdPerson":"does","partOfSpeech":"动词","pastParticiple":"done","presentParticiple":"doing"},{"plural":"","chinese":"作业","english":"homework","examples":["I have a lot of homework today.","She finished her homework early."],"phonetic":"/ˈhoʊmwɜːrk/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["副词的用法","实义动词的一般现在时形式","不可数名词的用法"],"explanations":["副词seriously用来修饰动词do，说明做这个动作的状态是认真的，在英语中副词通常放在实义动词之后、宾语之后，本句中放在句尾符合英语表达习惯。","本句是一般现在时，主语是第一人称I，实义动词do用原形；如果主语是第三人称单数，do要变为does。","homework是不可数名词，没有复数形式，不能在后面加-s或-es，表达“很多作业”要用a lot of homework，而不是many homeworks。"]},"sentenceWithHints":"我 认真 做 作业"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1532, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"认真","english":"seriously","examples":["You should take this seriously.","He drives seriously and safely."],"phonetic":"/ˈsɪriəsli/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"复习","english":"review","examples":["I need to review my lessons for the exam.","She reviews her notes every night."],"phonetic":"/rɪˈvjuː/","pastTense":"reviewed","thirdPerson":"reviews","partOfSpeech":"动词","pastParticiple":"reviewed","presentParticiple":"reviewing"}],"examPoints":{"points":["副词的位置","一般现在时的用法"],"explanations":["当副词用来修饰动词时，通常放在动词之后。本句中“seriously”是副词，用来修饰动词“review”，所以放在“review”的后面，符合英语中副词修饰动词的位置规则。","一般现在时用来表示经常性、习惯性的动作或者当前的状态。本句描述的是一种学习行为，属于经常性的动作，主语是第一人称“I”，所以动词用原形“review”。当主语是第三人称单数时，动词要变为第三人称单数形式“reviews”。"]},"sentenceWithHints":"我 认真 复习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1533, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"喜欢","english":"like","examples":["I like playing basketball.","She likes cats very much."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"chinese":"学习","english":"study","examples":["He is studying math now.","She studied hard for the exam."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"}],"examPoints":{"points":["动词like的用法","动词的现在分词形式"],"explanations":["like作为动词表示“喜欢”时，常见用法有like to do sth.（表示偶尔或具体的喜欢）和like doing sth.（表示长期的、习惯性的喜欢），本句中使用like doing sth.结构，表达习惯性的喜好。","动词变现在分词时，以辅音字母+y结尾的动词，先将y变为i，再加-ing，study的现在分词为studying；同时在like doing结构中，需要使用动词的现在分词形式作宾语。"]},"sentenceWithHints":"我 喜欢 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1534, '{"words":[{"chinese":"学习","english":"study","examples":["I study English every day.","Studying hard is important for exams."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her mom."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He told me a story.","Please give me that pen."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","She is a happy girl."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法","形容词作宾语补足语"],"explanations":["动词原形不能直接作句子主语，需要将其变为动名词形式（动词+ing），本句中study变为studying作主语，此时谓语动词要用第三人称单数形式，所以make变为makes。","make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”即表示“让我处于快乐的状态”。","在“make + 宾语 + 宾补”的结构中，形容词可以用来补充说明宾语的状态，本句中happy补充说明宾语me的情绪状态，在句中作宾语补足语。"]},"sentenceWithHints":"学习 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1535, '{"words":[{"chinese":"学习","english":"study","examples":["I study English every day.","Studying hard is important for exams."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for her mom."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Me and my friend go to school together."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"充实","english":"fulfilled","examples":["She feels fulfilled after helping others.","A meaningful job makes people fulfilled."],"phonetic":"/fʊlˈfɪld/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法","形容词作宾语补足语"],"explanations":["动词原形不能直接作主语，需要将其变为动名词形式（即动词+ing）来充当句子主语，本句中study变为studying作主语，此时谓语动词要用第三人称单数形式，所以make变为makes。","make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，表示“使某人/某物处于某种状态”，本句中me是宾语，fulfilled是宾语补足语。","此处fulfilled是形容词，在“make + 宾语 + 形容词”结构中作宾语补足语，用来补充说明宾语me的状态，表达“我感到充实的”含义。"]},"sentenceWithHints":"学习 让 我 充实"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1536, '{"words":[{"chinese":"学习","english":"study","examples":["I study English every day.","Studying hard is important for students."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"是","english":"is","examples":["She is a doctor.","Swimming is my favorite sport."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is very cute.","This is my new bag."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"responsibilities","chinese":"责任","english":"responsibility","examples":["It''s my responsibility to take care of my sister.","Everyone has their own responsibilities."],"phonetic":"/rɪˌspɑːnsəˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","系动词be的用法","名词单复数"],"explanations":["当需要将动词作为句子主语时，要将动词变为动名词形式（即动词后加-ing），本句中“学习”作主语，所以使用studying，动名词作主语时，谓语动词要用单数形式。","系动词be有am、is、are三种形式，本句主语是动名词studying，属于第三人称单数概念，因此搭配系动词is。","responsibility是可数名词，单数形式表示单个责任，复数形式responsibilities表示多个责任，本句中表示“我的（一项）责任”，所以使用单数形式，当表示多个责任场景时需使用复数。"]},"sentenceWithHints":"学习 是 我的 责任"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1537, '{"words":[{"chinese":"学习","english":"study","examples":["I study English every day.","She is studying for a test."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"是","english":"is","examples":["He is a doctor.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"missions","chinese":"使命","english":"mission","examples":["His mission is to help others.","The team completed their mission."],"phonetic":"/ˈmɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","形容词性物主代词的使用"],"explanations":["当动词需要在句中充当主语时，要将其变为动名词形式（动词后加-ing），本句中“学习”作为主语，所以使用studying，动名词作主语时，谓语动词要用单数形式。","系动词be的形式要根据主语的单复数变化，本句主语是动名词studying，属于单数概念，因此搭配系动词is。","形容词性物主代词my用来修饰后面的名词mission，表明所属关系，意为“我的”，这类代词不能单独使用，必须和名词连用。"]},"sentenceWithHints":"学习 是 我的 使命"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1539, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"不断","english":"keep","examples":["Keep trying and you will succeed.","She keeps a diary every day."],"phonetic":"/kiːp/","pastTense":"kept","thirdPerson":"keeps","partOfSpeech":"动词","pastParticiple":"kept","presentParticiple":"keeping"},{"chinese":"进步","english":"progress","examples":["He is progressing well in his studies.","The project has progressed smoothly."],"phonetic":"/ˈproʊɡres/","pastTense":"progressed","thirdPerson":"progresses","partOfSpeech":"动词","pastParticiple":"progressed","presentParticiple":"progressing"}],"examPoints":{"points":["一般将来时的表达","keep doing sth. 固定搭配"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常用“will + 动词原形”的结构表达，本句中用“will keep”来表达将来会持续进行的动作。","keep 后接动词的现在分词形式，构成 keep doing sth. 的固定搭配，意为“持续做某事，不断做某事”，此处用 keep progressing 表示“不断进步”，这是初中阶段需要掌握的重要动词搭配。"]},"sentenceWithHints":"我 会 不断 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1540, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"成为","english":"become","examples":["I want to become a doctor.","She became a famous singer."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"一个","english":"an","examples":["I have an apple.","She is an honest girl."],"phonetic":"/æn/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"优秀","english":"excellent","examples":["He is an excellent player.","We had an excellent time."],"phonetic":"/ˈeksələnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The red book is mine."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"people","chinese":"人","english":"person","examples":["He is a kind person.","There are five people in my family."],"phonetic":"/ˈpɜːrsn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","不定冠词a/an的用法","不规则动词become的变形"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“will become”就用来表达未来“会成为”的状态，符合初中二年级对一般将来时的考查要求。","不定冠词a用于以辅音音素开头的单词前，an用于以元音音素开头的单词前。本句中excellent以元音音素/ˈe/开头，所以用an，这是初中阶段不定冠词的核心考点之一。","become是不规则动词，它的过去式为became，过去分词为become，第三人称单数为becomes，现在分词为becoming，初中阶段需要掌握常见不规则动词的变形，become是重点考查的不规则动词之一。"]},"sentenceWithHints":"我 会 成为 一个 优秀 的 人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1541, '{"words":[{"plural":"","chinese":"学习","english":"study/studying","examples":["I study English every day.","Studying hard is important for students."],"phonetic":"/ˈstʌdi/ /ˈstʌdiɪŋ/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词/名词","pastParticiple":"studied","presentParticiple":"studying"},{"chinese":"是","english":"is","examples":["She is a doctor.","Running is my favorite sport."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"my","examples":["My cat is very cute.","This is my new pen."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"lives","chinese":"生命","english":"life","examples":["We should cherish life.","Many lives were saved in the accident."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of/''s","examples":["the roof of the house","Tom''s book"],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"parts","chinese":"一部分","english":"part","examples":["This is an important part of the plan.","The machine is made up of many parts."],"phonetic":"/pɑːrt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","名词所有格/所属关系表达","系动词的主谓一致"],"explanations":["当动词需要在句子中充当主语时，要将其变为动名词形式（即动词后加-ing），本句中“学习”作主语，所以使用studying，这是初中阶段非谓语动词的基础考点。","表达“……的”所属关系时，除了名词所有格（''s），还可以用介词of构成的短语，本句中“生命的一部分”译为“a part of my life”，是初中阶段常见的所属关系表达结构。","动名词作主语时，属于第三人称单数概念，对应的系动词要用is，这是主谓一致的基础规则，本句主语Studying是第三人称单数，因此系动词使用is。"]},"sentenceWithHints":"学习 是 我 生命 的 一部分"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1542, '{"words":[{"plural":"friendships","chinese":"友谊","english":"friendship","examples":["True friendship is hard to find.","Their friendship lasted for decades."],"phonetic":"/ˈfrendʃɪp/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The book is very interesting.","She runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"珍贵","english":"precious","examples":["Time is precious.","She has a precious collection of stamps."],"phonetic":"/ˈpreʃəs/","partOfSpeech":"形容词"}],"examPoints":{"points":["主系表结构的运用","副词修饰形容词的用法","不可数名词的使用"],"explanations":["本句是典型的主系表结构，主语是“友谊（friendship）”，系动词用is，表语是形容词“珍贵（precious）”，用于说明主语的性质和特征，这是初中阶段需要掌握的基础句子结构。","副词very用来修饰形容词precious，用来加强形容词的语气，说明珍贵的程度，在英语中副词常用来修饰形容词、副词或动词，这是副词的常见用法之一。","friendship是抽象不可数名词，没有复数形式（表示多种不同的友谊时可加s，此处表示抽象概念时为不可数），在句子中作主语时，系动词用单数形式is，初中阶段需要区分可数名词和不可数名词的用法差异。"]},"sentenceWithHints":"友谊 很 珍贵"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1543, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends often play with me."],"phonetic":"/frend/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"重要","english":"important","examples":["It is important to study hard.","Family is important to everyone."],"phonetic":"/ɪmˈpɔːrtnt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["可数名词的复数形式","系动词与主语的主谓一致","副词修饰形容词的用法"],"explanations":["可数名词表示一类事物时，常用复数形式。本句中“朋友”指代一类人，所以使用复数friends，规则名词变复数直接在词尾加-s。","系动词be的形式要和主语保持一致：主语是复数时，系动词用are；主语是第三人称单数时用is，主语是I时用am。本句主语friends是复数，所以搭配系动词are。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，说明形容词所描述的程度，本句中very用来强调important的程度。"]},"sentenceWithHints":"朋友 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1545, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends often play with me."],"phonetic":"/frend/","partOfSpeech":"名词"},{"chinese":"互相","english":"each other","examples":["We should help each other.","They learn from each other every day."],"phonetic":"/iːtʃ ˈʌðər/","partOfSpeech":"代词"},{"chinese":"帮助","english":"help","examples":["Please help me carry the box.","She helps her mom cook dinner every weekend."],"phonetic":"/help/","pastTense":"helped","thirdPerson":"helps","partOfSpeech":"动词","pastParticiple":"helped","presentParticiple":"helping"}],"examPoints":{"points":["名词复数形式的使用","相互代词的用法","一般现在时主谓一致"],"explanations":["当指代的人或事物是两个及以上时，可数名词需要使用复数形式。本句中“朋友”指的是多个朋友，所以用 friend 的复数形式 friends。","each other 是相互代词，用于指代两者之间的相互关系，在句中可以作宾语，本句中作 help 的宾语，表达朋友之间彼此帮助的关系。","一般现在时中，当主语是复数名词时，谓语动词用原形。本句主语 friends 是复数，所以谓语动词 help 用原形，不需要加 -s 或 -es。"]},"sentenceWithHints":"朋友 互相 帮助"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1546, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends often play with me."],"phonetic":"/frend/","partOfSpeech":"名词"},{"chinese":"互相","english":"each other","examples":["We help each other.","They learn from each other."],"phonetic":"/iːtʃ ˈʌðər/","partOfSpeech":"代词"},{"chinese":"鼓励","english":"encourage","examples":["My parents always encourage me to study hard.","She encouraged her brother to try again."],"phonetic":"/ɪnˈkɜːrɪdʒ/","pastTense":"encouraged","thirdPerson":"encourages","partOfSpeech":"动词","pastParticiple":"encouraged","presentParticiple":"encouraging"}],"examPoints":{"points":["可数名词的复数形式","相互代词的用法","一般现在时主谓一致"],"explanations":["可数名词表示一类人或事物时，常用复数形式。“朋友”在这里指的是一类群体，所以使用friend的复数形式friends，规则名词变复数直接在词尾加-s。","each other是相互代词，用于指代两个或两个以上的人或事物之间的相互关系，在句中可作宾语，本句中作encourage的宾语，表达朋友之间彼此鼓励的关系。","一般现在时中，当主语是第三人称复数时，谓语动词用原形。本句主语friends是第三人称复数，所以谓语动词encourage用原形，不需要进行第三人称单数变形。"]},"sentenceWithHints":"朋友 互相 鼓励"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1547, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends and I like playing basketball."],"phonetic":"/frend/","partOfSpeech":"名词"},{"plural":"","chinese":"一起","english":"together","examples":["Let''s go to school together.","We work together every day."],"phonetic":"/təˈɡeðər/","partOfSpeech":"副词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","She wants to grow into a kind person."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["可数名词的复数形式","一般现在时的主谓一致","副词的用法"],"explanations":["可数名词表示泛指一类人或事物时，常用复数形式。本句中“朋友”是泛指，所以使用friend的复数形式friends，规则名词直接加-s构成复数。","一般现在时中，当主语是复数名词时，谓语动词用原形。本句主语friends是复数，所以谓语动词grow用原形；若主语是第三人称单数，则谓语动词要使用第三人称单数形式grows。","副词together在句中通常作状语，用来修饰动词，说明动作发生的方式，本句中它修饰动词grow，表明成长这个动作是共同发生的。"]},"sentenceWithHints":"朋友 一起 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1548, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends and I often play basketball."],"phonetic":"/frend/","partOfSpeech":"名词"},{"plural":"","chinese":"一起","english":"together","examples":["Let''s go to school together.","We work together to finish the task."],"phonetic":"/təˈɡeðər/","partOfSpeech":"副词"},{"chinese":"进步","english":"progress","examples":["She progresses quickly in her studies.","We have progressed a lot this year."],"phonetic":"/ˈprɑːɡres/","pastTense":"progressed","thirdPerson":"progresses","partOfSpeech":"动词","pastParticiple":"progressed","presentParticiple":"progressing"}],"examPoints":{"points":["名词复数形式","作动词的progress用法","副词在句中的位置"],"explanations":["本句中“朋友”表示泛指的多个朋友，所以使用可数名词friend的复数形式friends，可数名词表示泛指复数概念时无需加冠词。","progress既可以作名词也可以作动词，此处在句中作谓语，是动词用法，意为“进步，进展”，在一般现在时中，主语为复数时，动词用原形。","副词together属于方式副词，在本句中位于实义动词progress之后，用来修饰动词，说明动作进行的方式，这是方式副词在陈述句中的常见位置之一。"]},"sentenceWithHints":"朋友 一起 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1549, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends often play with me."],"phonetic":"/frend/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her mom."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me with my homework."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","She is a happy girl."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","可数名词复数形式","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“make me happy”即表示“使我快乐”；同时当主语是第三人称单数时，make要变为makes，主语是复数时用原形make。","可数名词表示泛指一类人或事物时，常用复数形式，“朋友”在这里表示泛指的朋友群体，所以用复数friends，规则名词变复数一般在词尾加-s。","在“make + 宾语 + 宾补”的结构中，形容词可以作宾语补足语，用来补充说明宾语的状态，本句中happy补充说明宾语“me”的状态，即“我”是快乐的。"]},"sentenceWithHints":"朋友 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1550, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends often play with me."],"phonetic":"/frend/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me laugh every day.","The news made him sad."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","My mother loves me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"温暖","english":"warm","examples":["The sun makes the room warm.","She has a warm heart."],"phonetic":"/wɔːrm/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","可数名词复数形式","人称代词宾格的使用"],"explanations":["使役动词make的常用结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“make me warm”即表示“让我温暖”；同时make作为不规则动词，过去式和过去分词均为made，第三人称单数形式为makes，现在分词为making，需要特殊记忆。","可数名词“friend”表示一类人时，常用复数形式friends，在句中作主语时，谓语动词用原形，本句中主语friends为复数，所以谓语动词用make而非makes。","人称代词“我”在句子中作动词make的宾语，需要使用宾格形式me，而不是主格形式I，主格通常在句中作主语。"]},"sentenceWithHints":"朋友 让 我 温暖"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1551, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to go home."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will visit you tomorrow.","She will help us finish the work."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"珍惜","english":"cherish","examples":["We should cherish every moment together.","She cherishes the gift from her grandma."],"phonetic":"/ˈtʃerɪʃ/","pastTense":"cherished","thirdPerson":"cherishes","partOfSpeech":"动词","pastParticiple":"cherished","presentParticiple":"cherishing"},{"plural":"friends","chinese":"朋友","english":"friend","examples":["He is my best friend.","We made many friends at the party."],"phonetic":"/frend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","及物动词cherish的用法","可数名词复数的用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，结构为“will + 动词原形”，本句中“会”表达将来的意愿，所以用will加动词原形cherish构成一般将来时。","cherish是及物动词，后面可以直接接名词作宾语，表达珍视、珍惜的含义，在本句中直接接宾语friends，符合及物动词的用法规则。","friend是可数名词，当表示泛指的多个朋友时，需要使用复数形式friends，一般可数名词变复数在词尾加-s即可。"]},"sentenceWithHints":"我 会 珍惜 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1552, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to go home."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will come tomorrow."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"珍惜","english":"cherish","examples":["We should cherish every moment.","She cherishes her family very much."],"phonetic":"/ˈtʃerɪʃ/","pastTense":"cherished","thirdPerson":"cherishes","partOfSpeech":"动词","pastParticiple":"cherished","presentParticiple":"cherishing"},{"plural":"friendships","chinese":"友谊","english":"friendship","examples":["True friendship is precious.","We have a deep friendship."],"phonetic":"/ˈfrendʃɪp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","及物动词cherish的用法","抽象名词friendship的用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，结构为“will + 动词原形”，本句中“会”表达将来的意愿，所以用will加动词原形cherish构成一般将来时。","cherish是及物动词，后面可以直接接宾语，不需要加介词，常见搭配是cherish sth.，表示珍视、珍惜某物，本句中直接接抽象名词friendship作宾语。","friendship是抽象名词，意为“友谊”，表示泛指概念时通常不需要加冠词；它也可作可数名词，强调不同的友谊时可以用复数形式friendships。"]},"sentenceWithHints":"我 会 珍惜 友谊"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1553, '{"words":[{"plural":"friendships","chinese":"友谊","english":"friendship","examples":["True friendship is hard to find.","Their friendship lasted for decades."],"phonetic":"/ˈfrendʃɪp/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"","chinese":"财富","english":"wealth","examples":["Health is more important than wealth.","He inherited a large amount of wealth."],"phonetic":"/welθ/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词的用法","形容词性物主代词的使用","系动词be的主谓一致"],"explanations":["wealth是不可数名词，没有复数形式，不能直接用不定冠词a/an修饰，表达数量时需要借助量词，比如a large amount of wealth。本句中直接使用wealth表示抽象的财富概念，符合不可数名词的用法规范。","my是形容词性物主代词，后面必须接名词，用来表示所属关系，说明该名词所代表的事物属于说话者，本句中my修饰wealth，表明财富是“我的”。","本句主语friendship是单数可数名词，根据主谓一致原则，系动词be需要使用第三人称单数形式is，这是初中阶段需要掌握的基础主谓一致规则。"]},"sentenceWithHints":"友谊 是 我的 财富"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1554, '{"words":[{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have a good friend.","My friends and I like playing basketball."],"phonetic":"/frend/","partOfSpeech":"名词"},{"chinese":"是","english":"are","examples":["You are my best friend.","They are playing games outside."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is very cute.","This is my new schoolbag."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"treasures","chinese":"宝贝","english":"treasure","examples":["Family is my greatest treasure.","The museum has many ancient treasures."],"phonetic":"/ˈtreʒər/","partOfSpeech":"名词"}],"examPoints":{"points":["名词的复数形式及主谓一致","物主代词的使用"],"explanations":["当表示一类人或事物的泛指时，可数名词常用复数形式。本句中“朋友”和“宝贝”都表示泛指的概念，所以使用复数friends和treasures；主谓一致要求谓语动词的形式和主语保持一致，主语是复数friends，因此be动词用are。","my是形容词性物主代词，后面必须接名词，用来表示所属关系，说明事物的归属，本句中my treasures表示“我的宝贝”，体现了“宝贝”属于说话者。"]},"sentenceWithHints":"朋友 是 我的 宝贝"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1555, '{"words":[{"plural":"friendships","chinese":"友谊","english":"friendship","examples":["True friendship is priceless.","We have maintained our friendship for years."],"phonetic":"/ˈfrendʃɪp/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me go to the party.","She lets her dog play in the yard."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","She has grown into a smart young woman."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["使役动词let的用法","动词不定式的省略","主谓一致"],"explanations":["let作为使役动词，常见结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中let me grow就符合这个结构。","在使役动词let, make, have以及感官动词see, hear等后面，作宾语补足语的动词不定式要省略to，所以此处用grow而不是to grow。","句子主语Friendship是不可数名词，视为第三人称单数，所以谓语动词let要用其第三人称单数形式lets，这是主谓一致规则中“不可数名词作主语，谓语动词用单数形式”的体现。"]},"sentenceWithHints":"友谊 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1556, '{"words":[{"plural":"friendships","chinese":"友谊","english":"friendship","examples":["True friendship is hard to find.","Their friendship has lasted for years."],"phonetic":"/ˈfrendʃɪp/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我","english":"my","examples":["My bag is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"lives","chinese":"生命","english":"life","examples":["She loves her life very much.","Many lives were saved by the doctor."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["a cup of tea","the top of the mountain"],"phonetic":"/ʌv/","partOfSpeech":"介词"},{"plural":"parts","chinese":"一部分","english":"part","examples":["This is an important part of the plan.","She played a key part in the project."],"phonetic":"/pɑːrt/","partOfSpeech":"名词"}],"examPoints":{"points":["名词所有格/所属关系表达","不可数名词与可数名词的用法","系动词be的主谓一致"],"explanations":["中文中“的”表示所属关系时，英文常用介词of来表达，结构为“a part of + 名词”，用来说明前者是后者的组成部分，本句中“生命的一部分”译为“a part of my life”就是该结构的典型应用。","friendship是不可数名词，泛指友谊这一抽象概念；life表示“生命、生活”时，作为抽象概念时不可数，指具体的生命个体时为可数名词，复数形式为lives；part作为“部分”讲时是可数名词，单数形式前需加不定冠词a。","句子主语friendship是单数抽象名词，系动词需用第三人称单数形式is，符合主谓一致原则，即主语为第三人称单数时，一般现在时的系动词用is。"]},"sentenceWithHints":"友谊 是 我 生命 的 一部分"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1557, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","Many people enjoy country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very kind.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"美好","english":"beautiful","examples":["The sunset is beautiful.","She has a beautiful voice."],"phonetic":"/ˈbjuːtɪfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["The flower is red.","He is a doctor."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["不可数名词/抽象名词的用法","副词修饰形容词的规则","系动词be的主谓一致"],"explanations":["“生活”在这里表示抽象概念，属于抽象名词，对应的英文life表示抽象概念时通常作为不可数名词使用；当表示具体的“生命”时是可数名词，复数形式为lives，本句中是抽象概念，所以用life原形作主语。","副词very用来修饰形容词，表示程度，通常放在被修饰的形容词之前，本句中very修饰beautiful，用来加强“美好”的程度，符合副词修饰形容词的位置规则。","本句主语life是抽象名词，视为第三人称单数，所以系动词be要用第三人称单数形式is，遵循主谓一致的原则，即主语为第三人称单数时，对应的系动词要用is。"]},"sentenceWithHints":"生活 很 美好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1558, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"plural":"","chinese":"充满","english":"be full of","examples":["The box is full of books.","Her eyes are full of tears."],"phonetic":"/biː fʊl əv/","pastTense":"","thirdPerson":"","partOfSpeech":"短语","pastParticiple":"","presentParticiple":""},{"plural":"hopes","chinese":"希望","english":"hope","examples":["Never give up hope.","She has high hopes for the future."],"phonetic":"/hoʊp/","partOfSpeech":"名词"}],"examPoints":{"points":["固定短语 be full of 的用法","不可数名词与可数名词的灵活使用"],"explanations":["be full of 是初中阶段重点掌握的固定短语，意为“充满……”，在句中作谓语，be 动词的形式要根据主语的人称和数进行变化，本句主语 Life 是第三人称单数，所以使用 is full of。","hope 既可以作可数名词也可以作不可数名词，在本句中 hope 表示“希望”这一抽象概念，用作不可数名词；当表示具体的期望、愿望时，可作可数名词，复数形式为 hopes。"]},"sentenceWithHints":"生活 充满 希望"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1559, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"plural":"","chinese":"充满","english":"be full of","examples":["The box is full of books.","Her eyes are full of tears."],"phonetic":"/biː fʊl əv/","pastTense":"","thirdPerson":"","partOfSpeech":"短语","pastParticiple":"","presentParticiple":""},{"plural":"challenges","chinese":"挑战","english":"challenge","examples":["We face many challenges every day.","It''s a big challenge for us."],"phonetic":"/ˈtʃælɪndʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["固定短语be full of的用法","可数名词的复数形式","不可数名词的用法"],"explanations":["be full of是初中阶段重点掌握的固定短语，意为“充满；装满”，后接名词或代词，在句中作表语，be动词的形式要根据主语的人称和数进行变化，本句主语life为单数，所以用is full of。","challenge是可数名词，意为“挑战”，表示多个挑战时需要使用复数形式challenges，规则变化直接在词尾加-s。","life表示“生活”时通常作为不可数名词使用，作主语时谓语动词用单数形式；当表示“生命”时为可数名词，复数形式为lives。本句中life表示“生活”，作单数主语，所以谓语动词用is。"]},"sentenceWithHints":"生活 充满 挑战"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1560, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of challenges.","She enjoys country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"plural":"","chinese":"充满","english":"be full of","examples":["The box is full of books.","His heart is full of joy."],"phonetic":"/biː fʊl əv/","pastTense":"","thirdPerson":"","partOfSpeech":"短语","pastParticiple":"","presentParticiple":""},{"plural":"surprises","chinese":"惊喜","english":"surprise","examples":["There are many surprises in the story.","She gave me a big surprise."],"phonetic":"/sərˈpraɪz/","partOfSpeech":"名词"}],"examPoints":{"points":["固定短语be full of的用法","可数名词的复数形式","不可数名词的用法"],"explanations":["be full of是初中阶段重点掌握的固定短语，意为“充满……”，后接名词或代词，在句中作表语，根据主语的人称和数来变化be动词的形式，本句主语life为单数，所以用is full of。","surprise作“惊喜，意想不到的事”讲时是可数名词，在表示多个惊喜时需要使用复数形式surprises，在本句中没有特定冠词限定，所以用复数形式表示泛指的各类惊喜。","life表示“生活”这一抽象概念时是不可数名词，作主语时谓语动词用单数形式；当表示“生命，一生”时是可数名词，复数形式为lives。本句中life表示抽象的生活，所以视为不可数名词，谓语用is。"]},"sentenceWithHints":"生活 充满 惊喜"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1561, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like reading."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"热爱","english":"love","examples":["I love my family.","She loves playing the piano."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"lives","chinese":"生活","english":"life","examples":["Life is beautiful.","They enjoy their lives."],"phonetic":"/laɪf/","partOfSpeech":"名词"}],"examPoints":{"points":["一般现在时的用法","不可数名词与可数名词的区分","动词第三人称单数变化"],"explanations":["一般现在时用于表示经常性、习惯性的动作或客观事实、普遍真理。本句表达主语“我”的一种持久的情感态度，所以使用一般现在时，主语为第一人称“I”，动词用原形“love”。","“life”表示“生活”这一抽象概念时，通常作为不可数名词使用，不需要加冠词或变为复数；当表示“生命”时，是可数名词，复数形式为“lives”。本句中“生活”是抽象概念，所以用原形“life”。","当主语是第三人称单数（如he、she、it）时，一般现在时的动词要变为第三人称单数形式，“love”的第三人称单数是在词尾加“s”，即“loves”。"]},"sentenceWithHints":"我 热爱 生活"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1562, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am from China."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"享受","english":"enjoy","examples":["I enjoy playing basketball.","She enjoys listening to music."],"phonetic":"/ɪnˈdʒɔɪ/","pastTense":"enjoyed","thirdPerson":"enjoys","partOfSpeech":"动词","pastParticiple":"enjoyed","presentParticiple":"enjoying"},{"plural":"lives","chinese":"生活","english":"life","examples":["Life is beautiful.","They live happy lives."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["实义动词的一般现在时用法","不可数/可数名词的用法"],"explanations":["实义动词enjoy在一般现在时中，当主语是第一人称I时，使用动词原形；当主语是第三人称单数时，动词要变为enjoys。本句主语是I，所以用enjoy原形。","life表示“生活”时，通常作为不可数名词使用，不需要加冠词或变为复数；当表示“生命”时，是可数名词，复数形式为lives。本句中life表示“生活”，所以用原形life。"]},"sentenceWithHints":"我 享受 生活"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1563, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"感恩","english":"be grateful for","examples":["We are grateful for your help.","She was grateful for the warm welcome."],"phonetic":"/biː ˈɡreɪtfəl fɔːr/","pastTense":"was/were grateful for","thirdPerson":"is/are grateful for","partOfSpeech":"短语动词","pastParticiple":"been grateful for","presentParticiple":"being grateful for"},{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","Many lives were saved by the doctor."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["感恩的英文表达","不可数名词与可数名词的用法","系动词与形容词搭配"],"explanations":["“感恩”在英语中常用固定短语be grateful for来表达，后接感谢的对象，不能直接逐字翻译为类似\"thank life\"的中式表达，这是初中阶段需要掌握的常用情感表达短语。","life表示“生活”时通常作为不可数名词使用，不需要加冠词或变为复数；表示“生命”时是可数名词，复数形式为lives，本题中life表示生活，按不可数名词使用。","形容词grateful不能单独作谓语，需要和系动词be（am/is/are/was/were等）搭配构成系表结构作谓语，根据主语的人称和时态选择对应的系动词形式，本句主语为I，所以使用am。"]},"sentenceWithHints":"我 感恩 生活"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1564, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys her life in the countryside."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom let me watch TV after homework.","He lets his dog run in the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please pass me the pen."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","She has grown into a beautiful young woman."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["使役动词let的用法","动词第三人称单数变化","不规则动词变形"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中let me grow就符合这个结构。","当主语是第三人称单数（本句中主语Life是不可数名词，视为第三人称单数）时，一般现在时的动词要变成第三人称单数形式，let的第三人称单数是lets。","grow是不规则动词，它的过去式为grew，过去分词为grown，需要特殊记忆；let属于不规则动词中过去式和过去分词与原形一致的情况，也需要重点掌握。"]},"sentenceWithHints":"生活 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1565, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys her country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news made her sad.","He makes a cake every weekend."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"坚强","english":"strong","examples":["She is a strong woman.","Wind makes the tree strong."],"phonetic":"/strɔːŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","名词的数","人称代词宾格"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me strong”即表示“让我坚强”；同时make的第三人称单数形式为makes，当主语是第三人称单数（如本句的life）时，谓语动词要用第三人称单数形式。","life表示“生活”时是可数名词，其复数形式为不规则变形lives，需要注意与原形的区分，在表示泛指的抽象生活时也可作为不可数名词使用，本句中life表示抽象的生活，用作不可数名词作主语。","人称代词分为主格和宾格，“我”的主格是I，宾格是me，在句子中作宾语时要用宾格形式，本句中“我”是make的宾语，所以使用宾格me。"]},"sentenceWithHints":"生活 让 我 坚强"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1566, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news made her sad.","He makes a cake every weekend."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please pass me the pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"勇敢","english":"brave","examples":["She is a brave girl.","It was brave of him to help others."],"phonetic":"/breɪv/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","可数名词的不规则复数变化","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词/不带to的动词不定式”，表示“使某人/某物处于某种状态/做某事”。本句中“makes me brave”就是“make + 宾语me + 形容词brave”的结构，用来表达“使我变得勇敢”。","life表示“生活；生命”时，是可数名词，其复数形式属于不规则变化，要将fe改为v再加es，即lives，需要注意和原形的区分记忆。","在使役动词make的宾语之后接形容词，这个形容词在句子中充当宾语补足语，用来补充说明宾语的状态，本句中brave补充说明“我”的状态是勇敢的，这是初中阶段需要掌握的宾语补足语的常见用法之一。"]},"sentenceWithHints":"生活 让 我 勇敢"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1567, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys her country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","She has a happy family."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","名词life的单复数变化","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”即表示“使我快乐”；同时主语是第三人称单数life时，make要使用第三人称单数形式makes。","life表示“生活”时是可数名词，其复数形式为不规则变化lives，区别于“生命”含义时的单复数变化，需要注意不同语境下的形式使用。","在“make + 宾语 + 宾补”的结构中，形容词可以作宾语补足语，用来补充说明宾语的状态，本句中happy补充说明宾语me的状态，即“我”处于快乐的状态。"]},"sentenceWithHints":"生活 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1568, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys her country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me happy.","This movie made me cry."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我","english":"me","examples":["He gave me a gift.","Please help me with this."],"phonetic":"/miː/","partOfSpeech":"代词"},{"plural":"","chinese":"充实","english":"fulfilled","examples":["She feels fulfilled after helping others.","A meaningful job makes people fulfilled."],"phonetic":"/fʊlˈfɪld/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作宾语补足语","可数名词的单复数"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，表示“使/让某人/某物处于某种状态”。本句中主语life是第三人称单数，所以make用第三人称单数形式makes。","在“make + 宾语 + 宾语补足语”结构中，宾语补足语可以由形容词充当，用来补充说明宾语的状态。本句中fulfilled作为形容词，补充说明宾语me的状态，表达“我处于充实的状态”。","life表示“生活”时是不可数名词，但表示“生命”时是可数名词，复数形式为lives。本句中life表示“生活”，作主语时视为单数概念，因此谓语动词用第三人称单数形式。"]},"sentenceWithHints":"生活 让 我 充实"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1569, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am going to school."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"would","presentParticiple":"willing"},{"chinese":"珍惜","english":"cherish","examples":["We should cherish our time.","She cherishes the gift from her friend."],"phonetic":"/ˈtʃerɪʃ/","pastTense":"cherished","thirdPerson":"cherishes","partOfSpeech":"动词","pastParticiple":"cherished","presentParticiple":"cherishing"},{"plural":"lives","chinese":"生活","english":"life","examples":["Life is beautiful.","They enjoy their lives."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","及物动词的用法","可数名词的不规则复数"],"explanations":["一般将来时可以用“will + 动词原形”结构表达，表示将来要发生的动作或存在的状态，本句中“会珍惜”对应“will cherish”，用来表达未来的意愿和态度。","cherish是及物动词，后面可以直接接宾语，本句中直接接名词life作宾语，不需要添加介词，这类动词在句子中需要搭配宾语来完整表达语义。","life作为“生活；生命”讲时，是可数名词，其复数形式属于不规则变化，需要将fe变为v再加es，即lives，需要注意和原形的区分，避免出现拼写错误。"]},"sentenceWithHints":"我 会 珍惜 生活"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1570, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I love reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"热爱","english":"love","examples":["I love my family.","He loves playing basketball."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"lives","chinese":"生活","english":"life","examples":["We should enjoy life.","Many lives were saved in the accident."],"phonetic":"/laɪf/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成","不可数名词与可数名词的用法","实义动词的形式变化"],"explanations":["一般将来时表示将来发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会”体现将来的意愿，所以用“will + love”的结构来表达。","life表示“生活”时通常作为不可数名词使用，不需要加冠词；当表示“生命”时为可数名词，复数形式为lives。本句中life意为“生活”，按不可数名词使用。","实义动词love有多种形式变化：过去式和过去分词为loved，第三人称单数形式为loves，现在分词为loving，在不同的时态和主语搭配中需要使用对应的正确形式。"]},"sentenceWithHints":"我 会 热爱 生活"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1571, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["This is my new pen.","He is from Canada."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"gifts","chinese":"礼物","english":"gift","examples":["I received a gift from my uncle.","She made a handmade gift for her friend."],"phonetic":"/ɡɪft/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词与可数名词的用法","形容词性物主代词的使用","系动词be的主谓一致"],"explanations":["life表示“生活”时通常作为不可数名词使用，当表示“生命”时为可数名词，复数形式为lives；gift是可数名词，单数形式前如果没有特指限定词，可根据语境选择是否加不定冠词，本句中前面有形容词性物主代词my修饰，所以不需要加冠词。","my是形容词性物主代词，后面必须接名词，用来表示所属关系，说明某个事物属于说话者，类似的形容词性物主代词还有your, his, her等。","系动词be的形式要和主语保持主谓一致，本句主语life是单数概念，所以使用be动词的第三人称单数形式is；当主语为复数或第二人称you时，要用are，主语为I时用am。"]},"sentenceWithHints":"生活 是 我的 礼物"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1572, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["This is my new bag.","He is from Canada."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","I love my family."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"journeys","chinese":"旅程","english":"journey","examples":["We had a long journey by train.","Life is a wonderful journey."],"phonetic":"/ˈdʒɜːrni/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词/抽象名词的用法","系动词be的主谓一致","形容词性物主代词的使用"],"explanations":["句中的“生活”（life）作为抽象名词时，通常表示泛指的人生、生活概念，此时多作不可数名词使用；当表示具体的“生命”时为可数名词，复数形式为lives。本句中life表示抽象的人生，作不可数名词，谓语动词用单数形式。","系动词be的形式需要和主语保持主谓一致，本句主语life是单数概念，因此使用be动词的第三人称单数形式is。","“我的”（my）是形容词性物主代词，后面必须接名词，用来表示所属关系，本句中my修饰名词journey，表明旅程的所属者是“我”。"]},"sentenceWithHints":"生活 是 我的 旅程"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1573, '{"words":[{"plural":"lives","chinese":"生活","english":"life","examples":["Life is full of surprises.","She enjoys her country life."],"phonetic":"/laɪf/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["He is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"stages","chinese":"舞台","english":"stage","examples":["She is performing on the stage.","The project is in its final stage."],"phonetic":"/steɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","名词的数与不定冠词的省略","形容词性物主代词的使用"],"explanations":["系动词be有am、is、are三种现在时形式，其中is用于第三人称单数主语后。本句主语life是第三人称单数，因此搭配is。","当抽象名词或可数名词单数在句中表示泛指概念且带有物主代词修饰时，无需添加不定冠词a/an。本句中stage被my修饰，直接使用单数形式即可。","形容词性物主代词my用于名词前，表明所属关系，指代“我的”，在句中修饰名词stage，体现舞台的所属者。"]},"sentenceWithHints":"生活 是 我的 舞台"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1574, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My dream will come true someday.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"futures","chinese":"未来","english":"future","examples":["I''m looking forward to my bright future.","The future of the company looks promising."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"充满","english":"be full of","examples":["The room is full of sunshine.","Her heart is full of joy."],"phonetic":"/biː fʊl əv/","pastTense":"","thirdPerson":"","partOfSpeech":"短语","pastParticiple":"","presentParticiple":""},{"plural":"hopes","chinese":"希望","english":"hope","examples":["Never lose hope in difficult times.","She has high hopes for her children."],"phonetic":"/hoʊp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["形容词短语 be full of 的用法","不可数名词与可数名词的灵活使用"],"explanations":["be full of 是固定形容词短语，意为“充满……”，在句中作表语，需要根据主语的人称和数搭配对应的be动词形式，本句主语my future是第三人称单数，所以搭配is。","hope作为“希望”讲时，既可以作不可数名词表示抽象的希望概念，也可以作可数名词表示具体的希望、愿望，本句中hope表示抽象的希望，用作不可数名词，无需变复数；当表示多个具体愿望时，可变为复数hopes。"]},"sentenceWithHints":"我的 未来 充满 希望"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1575, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"futures","chinese":"未来","english":"future","examples":["I hope my future will be bright.","We are planning for the future."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"充满","english":"be full of","examples":["The box is full of books.","Her eyes were full of tears."],"phonetic":"/biː fʊl əv/","pastTense":"was/were full of","thirdPerson":"is full of","partOfSpeech":"动词短语","pastParticiple":"been full of","presentParticiple":"being full of"},{"plural":"possibilities","chinese":"可能","english":"possibility","examples":["There is a possibility of rain tomorrow.","We have many possibilities to choose from."],"phonetic":"/ˌpɑːsəˈbɪləti/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定短语 be full of 的用法","可数名词的复数形式"],"explanations":["be full of 是固定动词短语，意为“充满……”，在句中作谓语，be 动词的形式需要根据主语的人称和数进行变化。本句主语 my future 是第三人称单数，所以用 is full of。","possibility 是可数名词，意为“可能（性）”，表示多种可能性时需要使用复数形式 possibilities。以“y”结尾且“y”前是辅音字母的可数名词，变复数时要把“y”改为“i”再加“es”。"]},"sentenceWithHints":"我的 未来 充满 可能"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1576, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will arrive at 5 o''clock."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"努力","english":"work hard","examples":["He works hard to support his family.","She worked hard to pass the exam."],"phonetic":"/wɜːrk hɑːrd/","pastTense":"worked hard","thirdPerson":"works hard","partOfSpeech":"动词短语","pastParticiple":"worked hard","presentParticiple":"working hard"},{"chinese":"实现","english":"achieve","examples":["She achieved her dream of becoming a doctor.","We can achieve our goals if we try."],"phonetic":"/əˈtʃiːv/","pastTense":"achieved","thirdPerson":"achieves","partOfSpeech":"动词","pastParticiple":"achieved","presentParticiple":"achieving"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite book."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"goals","chinese":"目标","english":"goal","examples":["My goal is to learn English well.","We set new goals every year."],"phonetic":"/ɡoʊl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","动词不定式作目的状语","可数名词复数的用法"],"explanations":["一般将来时由will+动词原形构成，用来表示将来发生的动作或存在的状态，本句中用will表示说话者未来要采取的行动，表达了实现目标的意愿和计划。","动词不定式to do在句中可以作目的状语，用来说明动作的目的，本句中to achieve my goals用来补充说明work hard的目的，即努力的目的是实现目标。","可数名词goal表示多个目标时，需要使用复数形式goals。本句中说话者的目标通常不止一个，所以用复数形式，体现了名词单复数在语境中的正确运用。"]},"sentenceWithHints":"我 会 努力 实现 我的 目标"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1577, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I will go to school tomorrow."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"会","english":"will","examples":["I will help you.","She will come soon."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"努力","english":"work hard","examples":["He works hard every day.","She worked hard to pass the exam."],"phonetic":"/wɜːrk hɑːrd/","pastTense":"worked hard","thirdPerson":"works hard","partOfSpeech":"动词短语","pastParticiple":"worked hard","presentParticiple":"working hard"},{"chinese":"实现","english":"realize","examples":["I want to realize my dream.","He realized his mistake finally."],"phonetic":"/ˈriːəlaɪz/","pastTense":"realized","thirdPerson":"realizes","partOfSpeech":"动词","pastParticiple":"realized","presentParticiple":"realizing"},{"chinese":"我的","english":"my","examples":["My cat is cute.","This is my pen."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["I have many dreams.","His dream is to be a doctor."],"phonetic":"/driːm/","partOfSpeech":"名词"}],"examPoints":{"points":["一般将来时的用法","动词不定式作目的状语","可数名词复数形式"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常用结构为“will + 动词原形”，本句中用“will work hard”表达将来会做出的努力。","动词不定式“to realize”在句中作目的状语，用来说明“努力”的目的是实现梦想，这是不定式的常见用法之一。","“dream”是可数名词，当表示多个梦想或者泛指梦想时，需要使用复数形式“dreams”，本句中用复数形式体现梦想的泛指性。"]},"sentenceWithHints":"我 会 努力 实现 我的 梦想"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1578, '{"words":[{"chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"futures","chinese":"未来","english":"future","examples":["I hope my future is bright.","We should plan for the future."],"phonetic":"/ˈfjuːtʃər/","partOfSpeech":"名词"},{"chinese":"掌握","english":"be in","examples":["The decision is in your hands.","The key is in the drawer."],"phonetic":"/biː ɪn/","pastTense":"was/were in","thirdPerson":"is in","partOfSpeech":"动词","pastParticiple":"been in","presentParticiple":"being in"},{"chinese":"在","english":"in","examples":["The book is in the bag.","She is in the classroom."],"phonetic":"/ɪn/","partOfSpeech":"介词"},{"chinese":"自己","english":"own","examples":["I have my own car.","She wants her own room."],"phonetic":"/oʊn/","partOfSpeech":"形容词"},{"plural":"hands","chinese":"手中","english":"hands","examples":["He held the gift in his hands.","Put your hands on the desk."],"phonetic":"/hændz/","partOfSpeech":"名词"}],"examPoints":{"points":["名词复数的运用","介词短语表状态","形容词own的用法"],"explanations":["“手中”翻译为hands，这里用复数形式，因为人有两只手，表达“在掌控中”的含义时习惯用复数hands，体现泛指的掌控状态。","本句中用介词短语“in my own hands”来表达“掌握在...手中”的状态，这是英语中常用的表状态的表达方式，替代了中文里的动词“掌握”的直译，符合英语的表达习惯。","形容词own用于名词前，通常和形容词性物主代词搭配使用，用来强调“属于自己的”，比如my own hands，起到加强语气的作用，突出“自己”的所属关系。"]},"sentenceWithHints":"我的 未来 掌握 在 自己 手中"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1579, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will help you.","She will arrive at 6 o''clock."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my sister.","She is responsible for the project."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"自己","english":"my","examples":["This is my cat.","My favorite color is blue."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["The cover of the book is red.","This is my mother''s bag."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"futures","chinese":"未来","english":"future","examples":["I hope my future will be bright.","We should plan for the future."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"负责","english":"be responsible","examples":["You should be responsible for your mistakes.","He is responsible for managing the team."],"phonetic":"/biː rɪˈspɑːnsəbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词短语","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","固定短语be responsible for的搭配","物主代词的使用"],"explanations":["一般将来时用来表示将要发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中用“will be responsible”表达“将会负责”这个未来的状态，符合高中一年级对一般将来时基础用法的考查要求。","固定短语be responsible for意为“为……负责”，是高中阶段需要掌握的重点短语，其后可接名词、代词或动名词，本句中接名词短语my future，体现了该短语的正确使用场景。","物主代词分为形容词性物主代词和名词性物主代词，本句中使用形容词性物主代词my来修饰名词future，用来表示所属关系“我的未来”，是高中一年级代词类知识点的基础考查内容。"]},"sentenceWithHints":"我 会 为 自己 的 未来 负责"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1580, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will come back soon."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my mom.","We study hard for our future."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"自己","english":"my","examples":["My cat is cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"","examples":["This is my father''s car.","The color of the sky is blue."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["She has a big dream.","Dreams can come true if you work hard."],"phonetic":"/driːm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"努力","english":"work hard","examples":["He works hard every day.","She worked hard to pass the exam."],"phonetic":"/wɜːrk hɑːrd/","pastTense":"worked hard","thirdPerson":"works hard","partOfSpeech":"动词","pastParticiple":"worked hard","presentParticiple":"working hard"}],"examPoints":{"points":["一般将来时的用法","介词for表目的的用法","形容词hard作副词的用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常用结构为“will + 动词原形”，本句中“会”表达将来的意愿，所以用will加动词原形work构成一般将来时。","介词for可以用来表示动作的对象或目的，在本句中“为自己的梦想”表示努力的对象，所以用介词for来连接。","hard既可以作形容词也可以作副词，在短语work hard中，hard是副词，用来修饰动词work，表示“努力地”，注意不要和hardly（几乎不）混淆。"]},"sentenceWithHints":"我 会 为 自己 的 梦想 努力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1581, '{"words":[{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"futures","chinese":"未来","english":"future","examples":["I hope my future will be great.","She is planning for her future."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一片","english":"a","examples":["There is a book on the table.","He wants a new bike."],"phonetic":"/ə/","pastTense":"","thirdPerson":"","partOfSpeech":"冠词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"光明","english":"bright","examples":["The room is bright and warm.","She has a bright future ahead."],"phonetic":"/braɪt/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["The sky is blue.","He is a hard-working student."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["形容词作表语的主系表结构","物主代词的用法","不定冠词的省略"],"explanations":["主系表结构是英语中常见的句子结构，由主语+系动词+表语构成，表语常用来说明主语的特征、状态等。本句中主语是my future，系动词是is，形容词bright作表语，用来描述future的状态。","形容词性物主代词my用来修饰名词future，表明所属关系，类似的物主代词还有your, his, her等，在句中只能作定语修饰名词。","中文里的数量词“一片”在对应的英文表达中省略了不定冠词a，这是因为在描述抽象事物的状态时，英语常用“主语+系动词+形容词”的结构直接表达，无需添加冠词来对应中文的数量词，这体现了汉英表达习惯的差异。"]},"sentenceWithHints":"我的 未来 一片 光明"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1582, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will arrive at 6 o''clock."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"拥抱","english":"embrace","examples":["She embraced her child warmly.","We should embrace new challenges."],"phonetic":"/ɪmˈbreɪs/","pastTense":"embraced","thirdPerson":"embraces","partOfSpeech":"动词","pastParticiple":"embraced","presentParticiple":"embracing"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"futures","chinese":"未来","english":"future","examples":["I hope to have a bright future.","We need to plan for the future."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成与用法","及物动词embrace的用法"],"explanations":["一般将来时用来表示将要发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会”对应助动词will，后接动词原形embrace，表达对未来将要做出的动作的意愿。","embrace作为及物动词，既可以表示实际的“拥抱”这个动作，也可以引申为“欣然接受、拥抱（新事物、未来等抽象概念）”，本句中使用的是其引申义，后面可以直接接宾语，不需要加介词。"]},"sentenceWithHints":"我 会 拥抱 我的 未来"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1583, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will arrive at 5 o''clock."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"创造","english":"create","examples":["We can create a better world.","He created a new design for the project."],"phonetic":"/kriˈeɪt/","pastTense":"created","thirdPerson":"creates","partOfSpeech":"动词","pastParticiple":"created","presentParticiple":"creating"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"futures","chinese":"未来","english":"future","examples":["I hope to have a bright future.","We should plan for the future."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成与用法","形容词性物主代词的使用","及物动词create的用法"],"explanations":["一般将来时用来表示将要发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“will create”就体现了这一结构，用来表达主语“我”将要实施“创造未来”这个动作。","形容词性物主代词如“my”，后面必须接名词，用来表示所属关系，本句中“my future”表示“属于我的未来”，这类代词不能单独使用，必须和名词搭配。","create是及物动词，后面可以直接接宾语，不需要加介词，本句中直接接宾语“my future”，表示“创造我的未来”，它的过去式、过去分词为规则变化的created，第三人称单数为creates，现在分词为creating。"]},"sentenceWithHints":"我 会 创造 我的 未来"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1584, '{"words":[{"plural":"futures","chinese":"未来","english":"future","examples":["The future is full of hope.","We should plan for the future."],"phonetic":"/ˈfjuːtʃər/","partOfSpeech":"名词"},{"chinese":"属于","english":"belong","examples":["The book belongs to me.","These toys belong to the children."],"phonetic":"/bɪˈlɔːŋ/","pastTense":"belonged","thirdPerson":"belongs","partOfSpeech":"动词","pastParticiple":"belonged","presentParticiple":"belonging"},{"chinese":"我","english":"me","examples":["Please give the pen to me.","She is waiting for me."],"phonetic":"/miː/","partOfSpeech":"代词"}],"examPoints":{"points":["动词短语 belong to 的用法","人称代词宾格的使用","一般现在时第三人称单数变化"],"explanations":["belong to 是固定动词短语，意为“属于”，后面接人称代词宾格或名词，不能用于被动语态，也不能与物主代词连用。","“我”在本句中作介词 to 的宾语，所以要使用人称代词的宾格形式 me，而不是主格形式 I。","本句主语 the future 是第三人称单数，在一般现在时中，谓语动词要使用第三人称单数形式，belong 的第三人称单数是在词尾加 -s，即 belongs。"]},"sentenceWithHints":"未来 属于 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1585, '{"words":[{"plural":"futures","chinese":"未来","english":"future","examples":["The future looks bright.","We should plan for the future."],"phonetic":"/ˈfjuːtʃər/","partOfSpeech":"名词"},{"chinese":"在","english":"is","examples":["She is reading a book.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"等待","english":"wait","examples":["Please wait for me at the station.","She waits for her mom every day."],"phonetic":"/weɪt/","pastTense":"waited","thirdPerson":"waits","partOfSpeech":"动词","pastParticiple":"waited","presentParticiple":"waiting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please call me later."],"phonetic":"/miː/","partOfSpeech":"代词"}],"examPoints":{"points":["现在进行时的用法","固定短语wait for的搭配","人称代词宾格的使用"],"explanations":["现在进行时结构为“am/is/are + 现在分词”，表示此时此刻正在进行的动作或现阶段正在进行的动作。本句中“未来在等待我”表达的是一种持续的状态，用现在进行时体现当下的趋势，主语the future是第三人称单数，所以用is加上wait的现在分词waiting。","wait是不及物动词，后面接宾语时需要搭配介词for，构成固定短语wait for sb./sth.，意为“等待某人/某物”，不能直接加宾语。","人称代词分为主格和宾格，主格在句中作主语，宾格在句中作宾语。本句中“我”是介词for的宾语，所以要用宾格形式me，而不能用主格I。"]},"sentenceWithHints":"未来 在 等待 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1586, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will arrive at 5 o''clock."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"迎接","english":"welcome","examples":["We welcome new students every year.","She welcomed me with a big smile."],"phonetic":"/ˈwelkəm/","pastTense":"welcomed","thirdPerson":"welcomes","partOfSpeech":"动词","pastParticiple":"welcomed","presentParticiple":"welcoming"},{"plural":"futures","chinese":"未来","english":"future","examples":["We should look forward to the future.","Her future looks bright."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的构成与用法","定冠词the的特指用法","及物动词welcome的用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会迎接”表达将来的动作，因此使用“will welcome”的结构，适用于表达主语的意愿或将要进行的行为。","定冠词the用于特指某个特定的事物，这里“the future”特指说话人所指向的、具有唯一性的“未来”，是固定的特指用法，在表示抽象且唯一的概念时，通常需要加定冠词the。","welcome作为及物动词，后面可以直接接宾语，本句中“the future”作为welcome的宾语，符合及物动词“动词+宾语”的基本用法，同时welcome也可作形容词，此处根据语境判断为动词，表示“迎接”的动作。"]},"sentenceWithHints":"我 会 迎接 未来"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1587, '{"words":[{"plural":"futures","chinese":"未来","english":"future","examples":["The future is full of possibilities.","We should plan for our future."],"phonetic":"/ˈfjuːtʃər/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["This is my favorite book.","He is from Canada."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"mine","examples":["This book is mine.","The red bike is mine."],"phonetic":"/maɪn/","partOfSpeech":"代词"}],"examPoints":{"points":["名词的定冠词使用","名词性物主代词的用法"],"explanations":["当表示特指的抽象概念时，名词前需要加定冠词 the。本句中“未来”是特指的、独一无二的概念，所以前面加 the。","名词性物主代词 mine 相当于“形容词性物主代词 + 名词”，在句中可以直接作表语，本句中 mine 相当于 my future，避免了名词的重复使用，使表达更简洁。"]},"sentenceWithHints":"未来 是 我的"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1588, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my mom.","We need to prepare for the exam."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"futures","chinese":"未来","english":"future","examples":["I hope to have a bright future.","We should plan for the future."],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"而","english":"","examples":["我为理想而拼搏。","他为家人而努力工作。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"奋斗","english":"strive","examples":["We should strive to achieve our goals.","She strives to be a better person every day."],"phonetic":"/straɪv/","pastTense":"strove","thirdPerson":"strives","partOfSpeech":"动词","pastParticiple":"striven","presentParticiple":"striving"}],"examPoints":{"points":["介词for的用法","不及物动词strive的搭配","不规则动词的变形"],"explanations":["介词for在这里表目的，意为“为了”，后接名词、代词或动名词，用来引出动作的对象或目标，在本句中引出奋斗的目标“未来”。","strive是不及物动词，不能直接接宾语，常与介词for搭配构成短语strive for，意为“为……奋斗/努力”，用来表达为某个目标付出努力的含义。","strive是不规则动词，它的过去式为strove，过去分词为striven，第三人称单数形式为strives，现在分词为striving，这类不规则动词的变形需要特殊记忆，是高中阶段动词变形的考查重点之一。"]},"sentenceWithHints":"我 为 未来 而 奋斗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1589, '{"words":[{"plural":"futures","chinese":"未来","english":"future","examples":["The future is full of hope.","We should plan for the future."],"phonetic":"/ˈfjuːtʃər/","partOfSpeech":"名词"},{"plural":"","chinese":"因","english":"because of","examples":["He was late because of the rain.","We canceled the trip because of the bad weather."],"phonetic":"/bɪˈkʌv əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","She is waiting for me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"而","english":"/","examples":["他因努力而成功。","天气因台风而变得恶劣。"],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"精彩","english":"wonderful","examples":["We had a wonderful time at the party.","This is a wonderful movie."],"phonetic":"/ˈwʌndərfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["介词短语 because of 的用法","主系表句型的应用","物主代词与宾格代词的区分"],"explanations":["because of 是介词短语，后面接名词、代词或动名词，用来表示原因。本句中接宾格代词 me，说明未来精彩的原因是“我”。要注意和连词 because 区分，because 后面需要接完整的句子。","本句是典型的主系表句型，主语是 the future，系动词用 is（第三人称单数形式），表语是形容词 wonderful，用来描述主语的特征。主系表句型是英语基础句型之一，用于说明主语的身份、性质、状态等。","me 是第一人称代词的宾格形式，在句中作介词 because of 的宾语。而 I 是主格形式，只能作句子的主语。此处需要用宾格形式，符合介词后接宾语的语法规则。"]},"sentenceWithHints":"未来 因 我 而 精彩"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1590, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","She achieved great success in her career."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires patience.","This task requires us to finish it today."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"efforts","chinese":"努力","english":"effort","examples":["You should put more effort into your study.","His efforts finally paid off."],"phonetic":"/ˈefərt/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主谓一致规则","实义动词的第三人称单数形式"],"explanations":["抽象名词如success、effort表示抽象概念，通常为不可数名词，但表示“具体的成功事例/多次努力”时可作可数名词，本句中二者均表示抽象概念，用单数形式。","本句主语Success是单数抽象名词，作主语时谓语动词需要用第三人称单数形式，因此require变为requires，符合主谓一致中“单数主语搭配单数谓语”的规则。","实义动词的第三人称单数形式变化规则：一般情况下在动词后加-s，以s、x、sh、ch、o结尾的加-es，require属于一般情况，直接加-s变为requires，这是高中阶段动词形式变化的基础考点。"]},"sentenceWithHints":"成功 需要 努力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1591, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires a lot of patience.","This task requires us to finish it today."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"","chinese":"坚持","english":"persistence","examples":["Persistence is the key to success.","Her persistence finally paid off."],"phonetic":"/pərˈsɪstəns/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的使用","主谓一致规则","动词第三人称单数形式"],"explanations":["“成功”“坚持”均为抽象概念，在英语中对应抽象名词success和persistence，抽象名词一般为不可数名词，persistence无复数形式；success表示“成功的事或人”时可作可数名词，复数为successes。","本句主语是抽象名词success，属于第三人称单数，谓语动词需要使用第三人称单数形式，所以require变为requires，符合“主语为第三人称单数时，一般现在时谓语动词加-s/-es”的主谓一致规则。","动词require是规则动词，其第三人称单数形式直接在词尾加-s，即requires；规则动词的过去式、过去分词直接加-ed，现在分词直接加-ing，分别为required、required、requiring。"]},"sentenceWithHints":"成功 需要 坚持"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1592, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires patience.","We require more time to finish the task."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"","chinese":"勇气","english":"courage","examples":["It takes courage to admit mistakes.","She showed great courage in the face of danger."],"phonetic":"/ˈkɜːrɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主谓一致规则","及物动词的用法"],"explanations":["抽象名词如success、courage表示抽象概念，通常为不可数名词，泛指时不需要加冠词；当表示“具体的成功的人或事”时success可作可数名词，有复数形式successes。本句中success和courage均为泛指抽象概念，直接使用原形。","本句主语success是单数抽象名词，作主语时谓语动词要用第三人称单数形式，所以动词require变为requires，符合主谓一致中“单数主语搭配单数谓语”的规则。","require是及物动词，后面可以直接接名词作宾语，本句中require直接接courage作宾语，体现了及物动词后无需介词即可接宾语的用法。"]},"sentenceWithHints":"成功 需要 勇气"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1593, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires patience.","This task will require a lot of time."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"","chinese":"智慧","english":"wisdom","examples":["Wisdom is more valuable than money.","He shared his wisdom with the young people."],"phonetic":"/ˈwɪzdəm/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主谓一致规则","及物动词的用法"],"explanations":["抽象名词如success（成功）、wisdom（智慧），表示抽象概念，通常为不可数名词，wisdom属于不可数抽象名词，无复数形式；success表示“成功的事或人”时可作可数名词，有复数形式successes，本句中success表示抽象的“成功”概念，作不可数名词使用。","本句主语success是抽象不可数名词，视为第三人称单数，因此谓语动词require需要使用第三人称单数形式requires，这是主谓一致中“不可数名词作主语，谓语动词用单数形式”的规则体现。","require是及物动词，后面可以直接接名词作宾语，本句中require直接接wisdom作宾语，符合及物动词的用法规范，及物动词无需借助介词就可以带宾语来表达完整语义。"]},"sentenceWithHints":"成功 需要 智慧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1594, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"努力","english":"strive","examples":["We strive to provide the best service.","She strove to achieve her goal."],"phonetic":"/straɪv/","pastTense":"strove","thirdPerson":"strives","partOfSpeech":"动词","pastParticiple":"striven","presentParticiple":"striving"},{"chinese":"追求","english":"strive for","examples":["He strives for excellence in everything he does.","They strove for equal rights many years ago."],"phonetic":"/straɪv fɔːr/","pastTense":"strove for","thirdPerson":"strives for","partOfSpeech":"动词短语","pastParticiple":"striven for","presentParticiple":"striving for"},{"plural":"successes","chinese":"成功","english":"success","examples":["Her success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不及物动词短语 strive for 的用法","抽象名词 success 的用法"],"explanations":["strive 是不及物动词，后接宾语时需要搭配介词 for，构成短语 strive for，意为“追求，致力于”，常用于表达为某个目标付出努力的语境，过去式为 strove，过去分词为 striven，属于不规则变形，是高中阶段需要掌握的重点动词短语。","success 是抽象名词，意为“成功”，表示抽象概念时为不可数名词；当表示“成功的人或事”时，是可数名词，复数形式为 successes。本句中 success 表示抽象的“成功”概念，为不可数名词，前面不需要加冠词。"]},"sentenceWithHints":"我 努力 追求 成功"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1595, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"坚持","english":"persist","examples":["He persists in learning English every day.","She persisted in her opinion despite opposition."],"phonetic":"/pərˈsɪst/","pastTense":"persisted","thirdPerson":"persists","partOfSpeech":"动词","pastParticiple":"persisted","presentParticiple":"persisting"},{"plural":"","chinese":"追求","english":"pursue","examples":["She pursues her dream of becoming a doctor.","They are pursuing new business opportunities."],"phonetic":"/pərˈsuː/","pastTense":"pursued","thirdPerson":"pursues","partOfSpeech":"动词","pastParticiple":"pursued","presentParticiple":"pursuing"},{"plural":"successes","chinese":"成功","english":"success","examples":["Hard work leads to success.","The project was a great success."],"phonetic":"/səkˈses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词短语 persist in 的用法","动名词作介词宾语"],"explanations":["persist 是不及物动词，后接宾语需要搭配介词 in，构成 persist in (doing) sth. 的结构，意为“坚持（做）某事”，强调持续做某件事不放弃。","介词 in 后面需要接名词、代词或动名词形式作宾语，所以此处动词 pursue 要变为动名词 pursuing，这是高中阶段重点考查的介词后接非谓语动词的用法。"]},"sentenceWithHints":"我 坚持 追求 成功"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1596, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to go home."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"have","examples":["I have a cat.","She has finished her homework."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"courages","chinese":"勇气","english":"courage","examples":["It takes courage to admit mistakes.","She showed great courage in the face of danger."],"phonetic":"/ˈkɜːrɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"追求","english":"pursue","examples":["He wants to pursue a career in medicine.","She pursued her dream of becoming a singer."],"phonetic":"/pərˈsuː/","pastTense":"pursued","thirdPerson":"pursues","partOfSpeech":"动词","pastParticiple":"pursued","presentParticiple":"pursuing"},{"plural":"successes","chinese":"成功","english":"success","examples":["Hard work leads to success.","The project was a great success."],"phonetic":"/səkˈses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词不定式作后置定语","定冠词 the 的特指用法","实义动词 have 的用法"],"explanations":["动词不定式 to pursue success 在句中作后置定语，用来修饰前面的名词 courage，说明勇气的用途，即用于追求成功的勇气，这是高中阶段常见的非谓语动词作定语的用法。","定冠词 the 在这里用于特指“追求成功的这份勇气”，表示双方都明确指代的特定事物，区别于泛指的勇气，符合定冠词特指的使用规则。","实义动词 have 在这里表示“拥有”，是及物动词，后面可以直接接名词作宾语。当主语是第一人称、第二人称或复数时用 have，主语是第三人称单数时用 has，本句主语是第一人称 I，所以使用 have。"]},"sentenceWithHints":"我 有 勇气 追求 成功"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1597, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"have","examples":["I have a cat.","She has finished her homework."],"phonetic":"/hæv/","pastTense":"had","thirdPerson":"has","partOfSpeech":"动词","pastParticiple":"had","presentParticiple":"having"},{"plural":"wisdoms","chinese":"智慧","english":"wisdom","examples":["Wisdom is better than strength.","We can learn wisdom from our mistakes."],"phonetic":"/ˈwɪzdəm/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"追求","english":"pursue","examples":["She wants to pursue a career in medicine.","He pursued his dream despite difficulties."],"phonetic":"/pərˈsuː/","pastTense":"pursued","thirdPerson":"pursues","partOfSpeech":"动词","pastParticiple":"pursued","presentParticiple":"pursuing"},{"plural":"successes","chinese":"成功","english":"success","examples":["Hard work leads to success.","The project was a great success."],"phonetic":"/səkˈses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词不定式作后置定语","抽象名词的定冠词使用","实义动词have的用法"],"explanations":["本句中“to pursue success”是动词不定式短语，在句中作后置定语，修饰前面的名词“wisdom”，用来说明智慧的用途，即用于追求成功的智慧。动词不定式作后置定语常用来修饰表示“能力、意图、目的”等的名词。","“wisdom”是抽象名词，通常情况下抽象名词前不加定冠词，但当抽象名词被特定的定语修饰，表示特指的某一类或某一种相关事物时，需要加定冠词the。本句中“wisdom”被“to pursue success”修饰，特指用于追求成功的智慧，所以前面加the。","实义动词have在这里表示“拥有”，主语是第一人称I时，使用原形have；当主语是第三人称单数时，要变为has。它的过去式和过去分词都是had，现在分词是having，可用于现在完成时、现在进行时等时态中。"]},"sentenceWithHints":"我 有 智慧 追求 成功"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1598, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["His success made everyone proud.","Success comes from hard work."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"goals","chinese":"目标","english":"goal","examples":["My goal is to learn English well.","We achieved our goals this year."],"phonetic":"/ɡoʊl/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","系动词be的主谓一致","形容词性物主代词的使用"],"explanations":["抽象名词如success（成功）、goal（目标）表示抽象概念，属于不可数或可数抽象名词，success表示“成功的事或人”时可数，此处表示抽象概念“成功”，用作单数主语；goal表示“目标”时是可数名词，此处表示单个目标，用单数形式。","系动词be的形式要和主语保持主谓一致，本句主语success是单数抽象名词，因此搭配be动词的第三人称单数形式is。","形容词性物主代词my（我的）用来修饰名词goal，放在名词前表示所属关系，说明这个目标是“我”的，形容词性物主代词不能单独使用，必须和名词连用。"]},"sentenceWithHints":"成功 是 我的 目标"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1599, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["Her success made her parents proud.","We wish you every success in your new job."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["The cat is sleeping.","This is my favorite song."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My phone is lost.","I love my hometown."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["My dream is to travel around the world.","She has many big dreams."],"phonetic":"/driːm/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","系动词be的主谓一致","形容词性物主代词的使用"],"explanations":["抽象名词如success表示抽象概念，属于不可数名词，但当表示“成功的人或事”时可作可数名词，本句中success表示“成功”这一抽象概念，用作不可数名词作主语。","系动词be的形式需与主语保持一致，本句主语success是单数概念，因此使用be动词的第三人称单数形式is。","形容词性物主代词my用来修饰名词dream，表明dream的所属关系，形容词性物主代词后必须接名词，不能单独使用。"]},"sentenceWithHints":"成功 是 我的 梦想"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1600, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will help you.","She will finish the task soon."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"实现","english":"achieve","examples":["We can achieve our goals through hard work.","She achieved her dream of becoming a doctor."],"phonetic":"/əˈtʃiːv/","pastTense":"achieved","thirdPerson":"achieves","partOfSpeech":"动词","pastParticiple":"achieved","presentParticiple":"achieving"},{"plural":"successes","chinese":"成功","english":"success","examples":["Hard work leads to success.","The project was a great success."],"phonetic":"/səkˈses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","及物动词achieve的用法","抽象名词success的用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会”对应助动词will，后接动词原形achieve，构成将来时态表达未来要达成的动作。","achieve是及物动词，后面可以直接接名词作宾语，多搭配表示“目标、成功、梦想”等抽象名词，强调通过努力、技巧等达成预期的结果，不能单独使用，必须带宾语。","success是抽象名词，意为“成功”，表示抽象概念时为不可数名词；当表示“成功的人或事”时，是可数名词，复数形式为successes。本句中success表示抽象的成功概念，作achieve的宾语。"]},"sentenceWithHints":"我 会 实现 成功"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1601, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","The party was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"wills","partOfSpeech":"动词","pastParticiple":"willed","presentParticiple":"willing"},{"chinese":"属于","english":"belong to","examples":["This book belongs to me.","The house belongs to my grandparents."],"phonetic":"/bɪˈlɔːŋ tuː/","pastTense":"belonged to","thirdPerson":"belongs to","partOfSpeech":"动词","pastParticiple":"belonged to","presentParticiple":"belonging to"},{"chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"}],"examPoints":{"points":["一般将来时的用法","固定短语belong to的用法","人称代词宾格的使用"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中用“will belong”表示“将会属于”，体现未来的归属关系。","belong to是固定动词短语，意为“属于”，后面接人称代词宾格或名词，不能用于被动语态，也不能与所有格形式连用。","人称代词分为主格和宾格，me是第一人称代词I的宾格形式，在句中作介词to的宾语，所以此处要用宾格me而不是主格I。"]},"sentenceWithHints":"成功 会 属于 我"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1602, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"rewards","chinese":"奖赏","english":"reward","examples":["Hard work will bring its reward.","The police offered a reward for information."],"phonetic":"/rɪˈwɔːrd/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","系动词be的主谓一致","物主代词的使用"],"explanations":["“成功”属于抽象名词，对应的英文success是不可数名词时表示抽象的成功概念，当表示具体的成功事例或成功的人时是可数名词，本句中表示抽象概念，用作单数主语。","本句主语success是单数抽象名词，所以系动词用第三人称单数形式is，符合主谓一致的规则，即单数主语搭配单数形式的系动词。","“我的”是形容词性物主代词，对应的英文my用来修饰名词reward，表明奖赏的所属关系，形容词性物主代词后必须接名词，不能单独使用。"]},"sentenceWithHints":"成功 是 我的 奖赏"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1603, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["His success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"glories","chinese":"荣耀","english":"glory","examples":["He won glory for his country.","The old castle still retains its ancient glory."],"phonetic":"/ˈɡlɔːri/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","形容词性物主代词的使用","主系表句型的应用"],"explanations":["抽象名词表示抽象概念，如success（成功）、glory（荣耀），这类名词一般为不可数名词，但表示“具体的成功/荣耀之事”时可作可数名词，复数形式为successes、glories。本句中均表示抽象概念，用作不可数名词，作句子主语和表语。","形容词性物主代词my（我的）用来修饰名词，置于名词之前，表示所属关系，本句中my修饰glory，表明荣耀的归属者是“我”。","主系表句型的结构为“主语+系动词+表语”，本句中success是主语，is是系动词，my glory是表语，用来说明主语的属性，即“成功这件事属于我的荣耀”，这是英语中常见的句型，用于说明人或事物的特征、状态等。"]},"sentenceWithHints":"成功 是 我的 荣耀"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1604, '{"words":[{"plural":"successes","chinese":"成功","english":"success","examples":["His success made his parents proud.","She achieved great success in her career."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a talented singer.","It is a beautiful day today."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"prides","chinese":"骄傲","english":"pride","examples":["She is the pride of her family.","He swallowed his pride and apologized."],"phonetic":"/praɪd/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主系表结构的运用","物主代词的使用"],"explanations":["抽象名词如success、pride，通常表示抽象概念，属于不可数名词，但表示“多种成功/多种骄傲的事物”时可作可数名词，本句中均表示抽象概念，用作不可数名词，在句中可直接作主语或表语。","本句是典型的主系表结构，主语为抽象名词Success，系动词is根据主语的单数性质选用，表语为my pride，该结构用于说明主语的身份、性质、状态等，是英语中基础且常用的句子结构。","物主代词my属于形容词性物主代词，后面必须接名词，用来表示所属关系，本句中my修饰pride，表明“骄傲”的所属者是“我”。"]},"sentenceWithHints":"成功 是 我的 骄傲"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1605, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"因","english":"because of","examples":["He didn''t come because of the rain.","We won the game because of our teamwork."],"phonetic":"/bɪˈkʌv əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"successes","chinese":"成功","english":"success","examples":["Her success made her parents proud.","The project was a great success."],"phonetic":"/səkˈses/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"而","english":"/","examples":[""],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"自豪","english":"proud","examples":["She is proud of her children.","We are proud to be part of this team."],"phonetic":"/praʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配 be proud of 的同义表达转换","because of 的用法"],"explanations":["“因……而自豪”常见表达为 be proud of + 名词/代词/动名词，本句中通过“because of success”的结构，与 be proud 结合，本质是对“为成功自豪”的同义转换，核心是掌握 be proud 与原因状语的搭配逻辑。","because of 是介词短语，后接名词、代词或动名词短语，用来引导原因状语。需要注意和连词 because 的区别：because 后接完整的句子，而 because of 后接名词性成分。本句中 success 是名词，所以用 because of 来连接原因。"]},"sentenceWithHints":"我 因 成功 而 自豪"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1606, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"plural":"","chinese":"不","english":"not","examples":["I am not hungry.","She does not like coffee."],"phonetic":"/nɑːt/","partOfSpeech":"副词"},{"chinese":"可","english":"be","examples":["It can be difficult.","This must be your book."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"怕","english":"scary","examples":["The horror movie is really scary.","Dark forests can be scary at night."],"phonetic":"/ˈskeri/","partOfSpeech":"形容词"}],"examPoints":{"points":["抽象名词作主语","否定句的结构","形容词作表语"],"explanations":["抽象名词“失败”对应英文抽象名词failure，抽象名词属于不可数名词范畴（表示泛指概念时通常不加冠词，若表示具体的失败事件则可作可数名词），在句中作主语时，谓语动词用单数形式，本句中对应is。","本句是主系表结构的否定句，在系动词is后直接加否定副词not，构成否定形式，这是英语中主系表结构否定句的基本构成方式。","形容词scary在句中作表语，用来描述主语failure的属性，主系表结构中，形容词可以直接放在系动词之后作表语，说明主语的特征或状态。"]},"sentenceWithHints":"失败 不 可 怕"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1607, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"plural":"","chinese":"之","english":"of","examples":["the roof of the house","a cup of tea"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"mothers","chinese":"母","english":"mother","examples":["My mother is a kind woman.","The river is the mother of this city."],"phonetic":"/ˈmʌðər/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","所有格表达（of 短语）","固定谚语的英文翻译"],"explanations":["抽象名词如failure、success表示概念、状态，属于不可数名词范畴，但表示具体的人或事时可作可数名词，本句中二者均表示抽象概念，用作不可数名词。","中文的“之”在表达所属关系时，英文常用of短语来对应，结构为“the + 被修饰词 + of + 修饰词”，本句中“成功之母”译为“the mother of success”，符合这种所属关系的表达逻辑。","“失败是成功之母”是经典汉语谚语，对应的标准英文表达为“Failure is the mother of success”，需要掌握这类文化相关固定表达的精准翻译，避免直译偏差。"]},"sentenceWithHints":"失败 是 成功 之 母"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1608, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mother lets me watch TV after homework.","She let him borrow her book yesterday."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["Please pass me the pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","She has grown into a beautiful woman."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["使役动词let的用法","动词不定式的省略","抽象名词作主语"],"explanations":["let作为使役动词，常见结构为let sb. do sth.，表示“让某人做某事”，在本句中主语是第三人称单数“failure”，所以let要用第三人称单数形式lets。","在使役动词let, make, have后接宾语补足语时，不定式符号to要省略，所以本句中用grow而不是to grow。","抽象名词failure在句中作主语，属于不可数名词的抽象用法时表示泛指的“失败”概念，此时谓语动词用第三人称单数形式；当表示具体的“失败的事或人”时，是可数名词，有复数形式failures。本句中failure表示抽象概念，作单数主语。"]},"sentenceWithHints":"失败 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1609, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his life."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news made her sad.","Hard work makes success possible."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please pass me the book.","He gave me a gift."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"坚强","english":"strong","examples":["She is a strong woman.","We need strong determination to finish the task."],"phonetic":"/strɔːŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","名词作主语","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，宾语补足语可以是形容词、名词、不带to的不定式等。本句中“make me strong”就是“make + 代词宾语 + 形容词宾语补足语”的结构，用来表示“使我处于坚强的状态”。","句中“失败”译为failure，是抽象名词，在句中作主语，抽象名词表示泛指概念时，通常不需要加冠词，此处failure表示“失败这件事”，属于抽象名词的泛指用法。","在“make + 宾语 + 宾语补足语”的结构中，形容词可以用来补充说明宾语的状态或性质，本句中strong补充说明宾语me的状态，体现make作为使役动词的典型用法，这也是高中阶段重点考查的动词结构之一。"]},"sentenceWithHints":"失败 让 我 坚强"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1610, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news made her sad.","Hard work makes success possible."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成熟","english":"mature","examples":["She is a mature young woman.","It''s a mature plan."],"phonetic":"/məˈtʃʊr/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","抽象名词作主语","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，宾语补足语可以是形容词、名词、不带to的不定式等。本句中“makes me mature”就是“make + 代词宾语me + 形容词补足语mature”的结构，表达“使我变得成熟”的含义；当主语为第三人称单数时，make要变为makes。","“失败”对应的failure是抽象名词，抽象名词属于不可数名词的一种（表示概念时），可以直接作句子主语，谓语动词用第三人称单数形式，本句中主语Failure为单数概念，所以谓语动词make用第三人称单数形式makes。","在“make + 宾语 + 宾语补足语”的结构中，形容词可以充当宾语补足语，用来补充说明宾语的状态。本句中mature作为形容词作me的宾语补足语，补充说明“我”在失败的作用下所处的状态是成熟的。"]},"sentenceWithHints":"失败 让 我 成熟"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1611, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"不","english":"not","examples":["I am not hungry.","She does not like coffee."],"phonetic":"/nɑːt/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"怕","english":"afraid","examples":["She is afraid of dogs.","Don''t be afraid to ask questions."],"phonetic":"/əˈfreɪd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配 be afraid of","否定句的构成","抽象名词的用法"],"explanations":["be afraid of 是固定短语，意为“害怕……”，of 是介词，后面可接名词、代词或动名词，本句中接抽象名词 failure 表示“害怕失败”。","本句是主系表结构的否定句，在系动词 am 后直接加 not 构成否定，表达“我不……”的含义，这是主系表结构否定句的基本构成方式。","failure 作为抽象名词时，可表示“失败”这一抽象概念，此时为不可数名词；也可表示“失败的人或事”，此时为可数名词，本句中是抽象概念的用法。"]},"sentenceWithHints":"我 不 怕 失败"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1612, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"敢于","english":"dare","examples":["She dare not tell the truth.","He dares to challenge the authority."],"phonetic":"/der/","pastTense":"dared","thirdPerson":"dares","partOfSpeech":"动词","pastParticiple":"dared","presentParticiple":"daring"},{"chinese":"面对","english":"face","examples":["You have to face your mistakes.","She is facing a lot of pressure now."],"phonetic":"/feɪs/","pastTense":"faced","thirdPerson":"faces","partOfSpeech":"动词","pastParticiple":"faced","presentParticiple":"facing"},{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["实义动词dare的用法","动词不定式作宾语","抽象名词的用法"],"explanations":["dare作为实义动词时，后接动词不定式to do，有人称和数的变化，过去式为dared。本句中dare是实义动词，所以用dare to face的结构，区别于dare作为情态动词时后接动词原形且无人称变化的用法。","在dare to face这个结构中，to face是动词不定式，在句中作实义动词dare的宾语。实义动词后接动词不定式作宾语是常见的动词搭配结构，需要掌握这类动词的用法。","failure在这里是抽象名词，表示“失败”这一抽象概念，此时为不可数名词；当表示“失败的人或事”时，failure是可数名词，复数形式为failures。本句中failure表示抽象概念，所以使用单数形式。"]},"sentenceWithHints":"我 敢于 面对 失败"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1613, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"敢于","english":"dare","examples":["She dare not tell the truth.","He dares to challenge the authority."],"phonetic":"/der/","pastTense":"dared","thirdPerson":"dares","partOfSpeech":"动词","pastParticiple":"dared","presentParticiple":"daring"},{"chinese":"接受","english":"accept","examples":["I accept your apology.","She accepted the invitation happily."],"phonetic":"/əkˈsept/","pastTense":"accepted","thirdPerson":"accepts","partOfSpeech":"动词","pastParticiple":"accepted","presentParticiple":"accepting"},{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["实义动词dare的用法","动词不定式作宾语","抽象名词的使用"],"explanations":["dare作为实义动词时，后接动词不定式to do，有人称和数的变化，过去式为dared，本句中dare就是作为实义动词使用，表达“敢于做某事”的含义；此外dare还可作情态动词，后接动词原形，多用于否定句和疑问句。","在“dare to accept”结构中，to accept是动词不定式，在句中作dare的宾语，部分实义动词后需要接动词不定式来补充说明动作内容，常见的这类动词还有want, hope, decide等。","failure在这里是抽象名词，指“失败”这一抽象概念，此时为不可数名词；当它表示“失败的人或事”时，是可数名词，复数形式为failures，本句中取其抽象含义。"]},"sentenceWithHints":"我 敢于 接受 失败"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1614, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My English teacher is very humorous.","Teachers play an important role in education."],"phonetic":"/ˈtiːtʃər/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","系动词be的主谓一致","形容词性物主代词的使用"],"explanations":["抽象名词failure表示“失败”这一概念时，属于不可数名词；表示“失败的人或事”时，是可数名词，本句中是抽象概念，作主语时视为单数。此处将“失败”转化为抽象名词作主语，符合英语表达习惯，避免了使用动词fail作主语的语法错误。","系动词be的形式由主语的单复数决定，本句主语failure是单数概念，因此使用is，遵循主谓一致原则。","形容词性物主代词my用来修饰名词teacher，表明所属关系，相当于中文里的“我的”，在句中不能单独使用，必须后接名词。"]},"sentenceWithHints":"失败 是 我的 老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1615, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"friends","chinese":"朋友","english":"friend","examples":["She is my best friend.","We have been friends for ten years."],"phonetic":"/frend/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主系表结构的应用","物主代词的使用"],"explanations":["抽象名词failure表示“失败”这一抽象概念时，通常作为不可数名词；表示“失败的人或事”时，是可数名词，本句中是抽象概念作主语，此处用作单数可数名词形式表泛指概念。高中阶段需掌握抽象名词的可数与不可数的灵活转换。","本句是典型的主系表结构，主语是抽象名词Failure，系动词用is（主语为单数第三人称），表语是my friend，该结构用于说明主语的身份、性质或状态，是高中阶段句子结构的核心考点之一。","形容词性物主代词my用来修饰名词friend，表明friend的所属关系，形容词性物主代词不能单独使用，必须后接名词，这是代词用法的基础考点，在写作和语法填空题型中经常考查。"]},"sentenceWithHints":"失败 是 我的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1616, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mother lets me watch TV after homework.","She let him borrow her book yesterday."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"学习","english":"learn","examples":["I learn English every day.","She has learned how to play the piano."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"}],"examPoints":{"points":["使役动词let的用法","动名词/不定式作宾语补足语","抽象名词作主语"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，在一般现在时中，主语为第三人称单数时，let要变为lets；其过去式和过去分词均为let，属于不规则变化。","在let sb. do sth.结构中，省略to的不定式（即动词原形）作宾语补足语，这是使役动词的特殊用法，类似的使役动词还有make、have，但let的这一用法在主动语态中只能接省略to的不定式。","“失败”对应的failure是抽象名词，抽象名词属于不可数名词的一种（表示概念时），也可作为可数名词表示“一次失败的事或人”；本句中failure表示抽象概念“失败”，作句子主语，谓语动词用第三人称单数形式。"]},"sentenceWithHints":"失败 让 我 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1617, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mother lets me watch TV after finishing homework.","She let him borrow her book yesterday."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story last night."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"进步","english":"progress","examples":["He has progressed a lot in his English studies.","The project is progressing smoothly."],"phonetic":"/ˈproʊɡres/","pastTense":"progressed","thirdPerson":"progresses","partOfSpeech":"动词","pastParticiple":"progressed","presentParticiple":"progressing"}],"examPoints":{"points":["使役动词let的用法","抽象名词作主语","动词progress的用法"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，在一般现在时中，主语为第三人称单数时，let要变为lets。本句主语Failure是第三人称单数，所以谓语动词用lets。","抽象名词failure表示“失败”这一抽象概念时，属于不可数名词，可直接作句子主语，谓语动词用第三人称单数形式。当表示“失败的人或事”时，failure是可数名词，有复数形式failures。","progress既可以作名词也可以作动词，在本句中是不及物动词，意为“进步；进展”，在使役动词let后用原形，在其他时态中需要根据主语和时态变化形式，如现在进行时用progressing，现在完成时用progressed等。"]},"sentenceWithHints":"失败 让 我 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1618, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me laugh every day.","The teacher made him clean the classroom."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"反思","english":"reflect","examples":["I need to reflect on my mistakes.","The results reflect his hard work."],"phonetic":"/rɪˈflekt/","pastTense":"reflected","thirdPerson":"reflects","partOfSpeech":"动词","pastParticiple":"reflected","presentParticiple":"reflecting"}],"examPoints":{"points":["使役动词make的用法","抽象名词作主语","动词reflect的用法"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 省略to的不定式”，表示“使某人做某事”，本句中“makes me reflect”即符合该结构，当用于被动语态时，不定式符号to需要还原。","failure作为抽象名词，可直接充当句子主语，表示抽象的“失败”概念，此时为不可数名词；当表示具体的“失败的人或事”时，为可数名词，有复数形式failures。","reflect作为不及物动词时，常与on/upon搭配，表示“反思、思考”；作为及物动词时，可表示“反映、反射”，本句中是其不及物动词的用法，在使役动词make后省略了不定式符号to，直接使用动词原形。"]},"sentenceWithHints":"失败 让 我 反思"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1619, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me happy every day.","The teacher made us finish the homework on time."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"重新","english":"again","examples":["Try again, you can do it.","I will visit the city again next year."],"phonetic":"/əˈɡen/","partOfSpeech":"副词"},{"chinese":"开始","english":"start","examples":["Let''s start our meeting now.","He started to learn English when he was five."],"phonetic":"/stɑːrt/","pastTense":"started","thirdPerson":"starts","partOfSpeech":"动词","pastParticiple":"started","presentParticiple":"starting"}],"examPoints":{"points":["使役动词make的用法","名词作主语的主谓一致","副词again的位置与用法"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 省略to的不定式”，表示“使某人做某事”，本句中make me start就符合该结构，当用于被动语态时，省略的to需要还原。","句中failure作为抽象名词，在这里表示“失败这件事”，属于单数概念，所以作主语时，谓语动词make要用第三人称单数形式makes，这体现了主谓一致的原则，即主语为单数时，谓语动词要使用对应的单数形式。","again作为副词，通常用于动词之后，用来表示“再一次、重新”，在本句中放在实义动词start之后，用来修饰start，说明动作是重复进行的，在表达重复动作的语境中，again的位置一般在句末或动词短语之后。"]},"sentenceWithHints":"失败 让 我 重新 开始"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1620, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"successes","chinese":"成功","english":"success","examples":["Hard work leads to success.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["the roof of the house","a friend of mine"],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"stepping stones","chinese":"垫脚石","english":"stepping stone","examples":["Every difficulty is a stepping stone to growth.","This job is just a stepping stone to his dream career."],"phonetic":"/ˈstepɪŋ stoʊn/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","名词所有格/所属关系的表达","固定搭配stepping stone to的用法"],"explanations":["抽象名词如failure、success表示抽象概念时通常为不可数名词，当表示具体的“一次失败/成功的人或事”时为可数名词，本句中二者均表示抽象概念，failure作主语视为单数，对应系动词is。","中文中“的”表示所属关系时，英文常用介词of结构，本句中“我成功的垫脚石”译为“my stepping stone to success”，也可理解为“通往成功的我的垫脚石”，用to引出目标，同时用形容词性物主代词my体现所属。","stepping stone是固定短语，意为“垫脚石；进身之阶”，后常接介词to引出目标对象，用来表示某事物是达成另一事物的基础或途径，属于高中阶段需要掌握的固定搭配。"]},"sentenceWithHints":"失败 是 我 成功 的 垫脚石"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1621, '{"words":[{"plural":"failures","chinese":"失败","english":"failure","examples":["Failure is the mother of success.","He has experienced many failures in his career."],"phonetic":"/ˈfeɪljər/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我","english":"my","examples":["My cat is very cute.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"successes","chinese":"成功","english":"success","examples":["Success comes from hard work.","The project was a great success."],"phonetic":"/səkˈses/","partOfSpeech":"名词"},{"chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the sky is blue."],"phonetic":"","partOfSpeech":"助词"},{"plural":"motivations","chinese":"动力","english":"motivation","examples":["Her motivation to study is to get into a good university.","The team needs more motivation to win the game."],"phonetic":"/ˌmoʊtɪˈveɪʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","介词for表对象的用法","形容词性物主代词的使用"],"explanations":["抽象名词如failure、success、motivation表示概念、情感等抽象事物，通常为不可数名词，但表示具体的“一次失败/成功”或“多种动机”时可作可数名词，本句中均表示抽象概念，用作不可数名词。","介词for在这里用来引出对象，说明motivation的关联对象是success，即“为了成功的动力”，是高中阶段常考的介词搭配用法。","形容词性物主代词my用来修饰名词motivation，表明所属关系，相当于“我的”，在句中作定语，这是代词的基础用法，也是写作中明确所属关系的常用表达。"]},"sentenceWithHints":"失败 是 我 成功 的 动力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1622, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation is key to economic growth.","The company''s latest innovation has changed the market."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"推动","english":"drive","examples":["Hard work drives success.","The engine drives the car forward."],"phonetic":"/draɪv/","pastTense":"drove","thirdPerson":"drives","partOfSpeech":"动词","pastParticiple":"driven","presentParticiple":"driving"},{"chinese":"社会","english":"social","examples":["We need to solve many social problems.","She is active in social activities."],"phonetic":"/ˈsoʊʃl/","partOfSpeech":"形容词"},{"plural":"","chinese":"进步","english":"progress","examples":["We have made great progress in science.","Progress takes time and effort."],"phonetic":"/ˈprɑːɡres/","partOfSpeech":"名词"}],"examPoints":{"points":["主谓一致","抽象名词的用法","形容词作定语"],"explanations":["本句主语 innovation 是单数可数名词，在一般现在时中，主语为第三人称单数时，谓语动词要使用第三人称单数形式，所以动词 drive 变为 drives，这是大学英语写作和语法考查的核心点之一，要求掌握不同主语对应的谓语动词形式变化。","innovation 和 progress 都是抽象名词，其中 innovation 是可数抽象名词，可加复数形式表示各类创新；progress 是不可数抽象名词，不能直接加复数，也不能用不定冠词修饰，这类抽象名词的数的用法是大学英语词汇考查的重点，需要区分可数与不可数抽象名词的使用场景。","social 作为形容词修饰名词 progress，构成名词短语 social progress，形容词作定语修饰抽象名词是英语书面表达中的常见结构，大学阶段要求能够准确使用形容词修饰各类名词，尤其是抽象名词，使表达更精准具体。"]},"sentenceWithHints":"创新 推动 社会 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1623, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company is known for its innovations in renewable energy."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"改变","english":"change","examples":["She changed her mind at the last minute.","Climate change is affecting the entire planet."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"plural":"worlds","chinese":"世界","english":"world","examples":["He wants to travel around the world.","The book describes a magical world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词与可数名词的用法","一般现在时第三人称单数变化","定冠词 the 的特指用法"],"explanations":["innovation作为抽象名词时可表示泛指的创新概念，属于不可数名词范畴；当表示具体的创新成果时是可数名词，本句中是泛指创新这一行为概念，使用单数形式即可。","一般现在时中，当主语是第三人称单数（本句中主语innovation为单数名词）时，谓语动词需要变为第三人称单数形式，规则动词change直接在词尾加-s变为changes。","world表示“世界”这一独一无二的事物时，前面需要加定冠词the进行特指，因此翻译中译为the world。"]},"sentenceWithHints":"创新 改变 世界"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1624, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company is known for its innovation in design."],"phonetic":"/ˌɪnəˈveɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a talented artist.","The key to success is hard work."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"futures","chinese":"未来","english":"future","examples":["We should focus on building a better future.","What does the future hold for us?"],"phonetic":"/ˈfjuːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is broken.","This is a photo of my family."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"hopes","chinese":"希望","english":"hope","examples":["She is the hope of the whole team.","We hold high hopes for the new project."],"phonetic":"/hoʊp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["抽象名词的用法","名词所有格的表达（of 结构）","系动词与主语的主谓一致"],"explanations":["本句中的“创新”“希望”“未来”均为抽象名词，这类名词表示抽象概念，通常不可数，但在表示具体的多种类别或不同的具体事物时可作可数名词使用，如“innovations”可表示多种创新成果。在正式书面语中，抽象名词作主语时，谓语动词通常用单数形式。","英语中表示所属关系时，除了''s所有格，还常用of结构，尤其是当所属名词是无生命名词或抽象名词时，本句中“未来的希望”译为“the hope of the future”，使用of结构体现所属关系，符合正式书面语的表达习惯。","本句主语“innovation”是单数抽象名词，因此系动词使用第三人称单数形式“is”，遵循主谓一致原则，即单数主语搭配单数谓语动词，复数主语搭配复数谓语动词。"]},"sentenceWithHints":"创新 是 未来 的 希望"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1625, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like reading.","I am a college student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"热爱","english":"love","examples":["I love playing the guitar.","She loves her family deeply."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company encourages innovation among its employees."],"phonetic":"/ˌɪnəˈveɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["及物动词的用法","抽象名词的使用"],"explanations":["love 作为及物动词，后面可以直接接名词、代词或动名词作宾语，本句中直接接抽象名词 innovation 作宾语，符合及物动词的语法规则，体现了大学英语中对动词搭配的精准考查。","innovation 是抽象名词，属于不可数名词或可数名词（表具体创新成果时可数），本句中表示“创新”这一抽象概念，用作不可数名词，在大学英语写作和翻译中，准确使用抽象名词能提升表达的正式性和专业性，是重点考查内容。"]},"sentenceWithHints":"我 热爱 创新"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1626, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"追求","english":"pursue","examples":["She wants to pursue a career in medicine.","We should pursue our dreams bravely."],"phonetic":"/pərˈsuː/","pastTense":"pursued","thirdPerson":"pursues","partOfSpeech":"动词","pastParticiple":"pursued","presentParticiple":"pursuing"},{"plural":"innovations","chinese":"创新","english":"innovation","examples":["The company is known for its technological innovations.","Innovation is the key to success."],"phonetic":"/ˌɪnəˈveɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["及物动词的用法","抽象名词的使用","主谓一致"],"explanations":["pursue 是及物动词，后面可以直接接名词作宾语，不需要加介词，本句中直接接抽象名词 innovation 作宾语，符合及物动词的用法规范。","innovation 是抽象名词，意为“创新”，表示抽象概念时通常为不可数名词，当表示具体的创新成果时可作可数名词，本句中表示抽象的行为概念，用作不可数名词。","本句主语是第一人称代词 I，谓语动词用原形 pursue，符合主谓一致中“第一人称单数主语搭配动词原形”的规则，当主语为第三人称单数时，谓语动词要变为 pursues。"]},"sentenceWithHints":"我 追求 创新"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1627, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"勇于","english":"dare to","examples":["She dares to speak her mind.","He dared to challenge the authority."],"phonetic":"/der tuː/","pastTense":"dared to","thirdPerson":"dares to","partOfSpeech":"动词短语","pastParticiple":"dared to","presentParticiple":"daring to"},{"plural":"","chinese":"创新","english":"innovate","examples":["We need to innovate to stay competitive.","The company has innovated a new product."],"phonetic":"/ˈɪnəveɪt/","pastTense":"innovated","thirdPerson":"innovates","partOfSpeech":"动词","pastParticiple":"innovated","presentParticiple":"innovating"}],"examPoints":{"points":["dare 作为实义动词的用法","动词不定式作宾语"],"explanations":["dare 既可以作情态动词也可以作实义动词，在本句中是实义动词，后接带 to 的不定式，有人称和数的变化，过去式为 dared，第三人称单数为 dares。当表示“敢于做某事”的具体行为时，常用实义动词用法，符合本句“勇于（敢于）创新”的语境。","实义动词 dare 后接动词不定式 to innovate 作宾语，构成“dare to do sth.”的结构，这是英语中常见的“动词+不定式”的搭配，用来表达敢于执行某个具体动作，在正式书面语和大学阶段英语表达中较为常用。"]},"sentenceWithHints":"我 勇于 创新"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1628, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company is known for its innovations in renewable energy."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires a lot of patience.","This project will require extra funding."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"","chinese":"勇气","english":"courage","examples":["It takes courage to admit your mistakes.","She showed great courage during the crisis."],"phonetic":"/ˈkɜːrɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主谓一致规则","及物动词的搭配"],"explanations":["抽象名词如innovation、courage表示抽象概念，通常为不可数名词，一般不与不定冠词a/an搭配，也没有复数形式（innovation表“创新成果”时可作可数名词，此处表抽象概念为不可数），在句中可直接作主语或宾语。","本句主语innovation是单数抽象名词，作主语时谓语动词要用第三人称单数形式，所以动词require要变为requires，符合英语中“单数主语搭配单数谓语动词”的主谓一致规则。","require作为及物动词，后面可以直接接名词作宾语，本句中require后直接接courage，符合“及物动词+名词宾语”的常见搭配结构，类似的搭配还有require effort、require attention等。"]},"sentenceWithHints":"创新 需要 勇气"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1629, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation is key to development.","The company encourages innovation among its employees."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires a lot of patience.","This project requires our immediate attention."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"","chinese":"智慧","english":"wisdom","examples":["Wisdom comes from experience.","We should listen to the wisdom of the elderly."],"phonetic":"/ˈwɪzdəm/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主谓一致规则","正式书面语词汇的选用"],"explanations":["抽象名词如innovation、wisdom表示概念、品质等，通常为不可数名词，一般不与不定冠词a/an搭配，也无复数形式（部分抽象名词可具体化变为可数，但本句中均为抽象概念用法）。","本句主语innovation是单数不可数名词，作主语时谓语动词需要使用第三人称单数形式，所以动词require变为requires，这是英语主谓一致的核心规则之一，在正式书面表达中需严格遵循。","在大学阶段的英语表达中，需选用符合正式语境的词汇，如用innovation对应“创新”、wisdom对应“智慧”，而非口语化的表达，这类词汇常用于学术写作、正式报告等场景，是大学英语考查的重点方向。"]},"sentenceWithHints":"创新 需要 智慧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1630, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company is known for its innovation in design."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires a lot of patience.","This task will require extra effort."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"","chinese":"坚持","english":"persistence","examples":["Success often depends on persistence.","Her persistence finally paid off."],"phonetic":"/pərˈsɪstəns/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的使用","主谓一致原则","动词与抽象名词的搭配"],"explanations":["本句中“创新”“坚持”均为抽象概念，对应的英文innovation、persistence都是抽象名词，这类名词通常不可数，在句中作主语或宾语时，不需要加不定冠词，符合英语中抽象概念的表达习惯。","句子主语innovation是单数抽象名词，作主语时谓语动词需要使用第三人称单数形式，所以动词require变为requires，这是英语主谓一致的核心规则之一，在正式书面表达中需严格遵循。","动词require常与抽象名词搭配使用，表示“需要某类抽象事物/品质”，如require persistence、require dedication等，这类搭配属于英语正式表达中的常用固定搭配，常用于学术、商务等正式语境，符合大学阶段英语对正式表达的考查要求。"]},"sentenceWithHints":"创新 需要 坚持"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1631, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation is driving economic growth.","The company encourages innovation among its employees."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"需要","english":"require","examples":["The job requires a lot of patience.","This task requires us to work together."],"phonetic":"/rɪˈkwaɪər/","pastTense":"required","thirdPerson":"requires","partOfSpeech":"动词","pastParticiple":"required","presentParticiple":"requiring"},{"plural":"cooperations","chinese":"合作","english":"cooperation","examples":["International cooperation is key to solving global problems.","We appreciate your cooperation on this project."],"phonetic":"/koʊˌɑːpəˈreɪʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的使用","主谓一致规则","正式书面语词汇搭配"],"explanations":["本句中的“创新”“合作”均为抽象名词，在英语中对应的innovation、cooperation都是不可数或可数抽象名词，在表达泛指概念时常用单数形式，这类词汇常用于学术、商务等正式语境，符合大学英语对书面语词汇的考查要求。","本句主语innovation是单数抽象名词，谓语动词需要使用第三人称单数形式，所以require变为requires，这是英语主谓一致的核心规则之一，在正式写作和翻译中需严格遵循。","在正式表达中，“需要”与抽象名词搭配时，使用require比need更贴合书面语风格，innovation与cooperation的搭配体现了学术语境中常见的逻辑关联，考查学习者在专业语境下的词汇选用能力。"]},"sentenceWithHints":"创新 需要 合作"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1632, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company is known for its innovation in design."],"phonetic":"/ˌɪnəˈveɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a talented musician.","The key to success is hard work."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"sciences","chinese":"科学","english":"science","examples":["She studies computer science at university.","Science has changed our lives greatly."],"phonetic":"/ˈsaɪəns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is broken.","He is a friend of my brother''s."],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"souls","chinese":"灵魂","english":"soul","examples":["Kindness is the soul of his character.","The old town has a unique soul."],"phonetic":"/soʊl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["抽象名词的用法","所属关系的英文表达","系动词be的主谓一致"],"explanations":["本句中的“创新”“科学”“灵魂”均为抽象名词，这类名词通常表示概念、品质等抽象事物，一般不可数，但表示不同类别时可作可数名词，如“sciences”表示各类学科。在正式书面表达中，抽象名词作主语时，谓语动词用单数形式。","中文中用“的”表示所属关系，英文中常用介词“of”构成名词所有格来表达，结构为“the + 被修饰名词 + of + 所属名词”，本句中“the soul of science”就对应“科学的灵魂”，这是书面语中表达所属关系的常用结构。","本句主语“innovation”是单数抽象名词，根据主谓一致原则，谓语系动词需要使用第三人称单数形式“is”，这是英语句子结构中主语和谓语在数上保持一致的基本规则，在正式学术表达中需严格遵循。"]},"sentenceWithHints":"创新 是 科学 的 灵魂"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1633, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company encourages innovation among its employees."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a talented designer.","The key to success is hard work."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"technologies","chinese":"技术","english":"technology","examples":["Modern technology has changed our lives greatly.","The country is investing in advanced technology."],"phonetic":"/tekˈnɑːlədʒi/","partOfSpeech":"名词"},{"chinese":"的","english":"of","examples":["The roof of the house is red.","This is a photo of my family."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"driving forces","chinese":"动力","english":"driving force","examples":["Passion is the driving force behind his achievements.","Consumer demand is the main driving force of the market."],"phonetic":"/ˈdraɪvɪŋ fɔːrs/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的使用与指代","介词of表所属关系的用法","固定名词短语的翻译"],"explanations":["本句中“创新”“技术”“动力”均为抽象名词，在英语中这类抽象名词通常用作不可数名词表示泛指，但表示具体的多种类别时可作可数名词。本句里“innovation”和“technology”表示泛指概念，在句中作主语和宾语时无需冠词修饰，而“driving force”作为固定抽象名词短语，此处特指技术发展的动力，所以前面加定冠词the。","介词of在英语中常用来表示所属关系，对应中文的“的”，用于连接两个名词，说明后者从属于前者，本句中“the driving force of technology”就清晰体现了“技术的动力”这种所属关联。","中文里的“动力”在本语境下对应英语固定短语“driving force”，而非直接直译“power”或“motivation”，这类语境化的固定短语翻译是大学英语翻译的重点，需要结合具体语境选择符合英语表达习惯的固定搭配，避免中式英语。"]},"sentenceWithHints":"创新 是 技术 的 动力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1634, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company encourages innovation among its employees."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a talented designer.","The most important thing is to stay positive."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"developments","chinese":"发展","english":"development","examples":["The city has seen rapid development in recent years.","We are monitoring the development of the new project."],"phonetic":"/dɪˈveləpmənt/","partOfSpeech":"名词"},{"plural":"","chinese":"的","english":"of","examples":["The roof of the house is broken.","This is a photo of my family."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"sources","chinese":"源泉","english":"source","examples":["The river is a source of drinking water for the town.","She is a reliable source of information."],"phonetic":"/sɔːrs/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","介词of构成的所属结构","系动词的主谓一致"],"explanations":["本句中的“创新”“发展”“源泉”均为抽象名词，这类名词表示抽象概念，通常不可数，但表示具体的种类或实例时可作可数名词，在正式书面语（如学术文本、官方表述）中常被用于阐述观点，是大学英语写作和翻译中高频出现的词汇类别。","介词of用于构成所属结构，表达“……的”，在本句中“the source of development”表示“发展的源泉”，是英语中表达所属关系的常用结构，尤其用于抽象名词之间的所属关联，区别于有生命名词的''s所有格。","本句主语“innovation”是单数抽象名词，因此系动词使用第三人称单数形式is，这是主谓一致的基础规则，在正式文本中需严格遵循，确保主语和谓语动词的数保持一致。"]},"sentenceWithHints":"创新 是 发展 的 源泉"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1635, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company is known for its constant innovation."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a talented designer.","The key to success is hard work."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My dream is to travel around the world.","I finished my homework ahead of time."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"missions","chinese":"使命","english":"mission","examples":["Her mission is to help the poor.","The team completed their dangerous mission successfully."],"phonetic":"/ˈmɪʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的使用","主系表结构的陈述句表达","物主代词的搭配"],"explanations":["抽象名词如innovation（创新）、mission（使命），表示概念、情感等抽象事物，属于不可数名词或可数名词（表具体任务时可数），在本句中均表示抽象概念，作主语和表语时，若表泛指概念，可单独使用无需冠词。大学阶段英语常考查此类抽象名词在正式语境（如演讲、书面表达）中的准确运用。","本句是典型的主系表结构，主语为抽象名词Innovation，系动词用is（主语为单数第三人称），表语为my mission，这种结构常用于正式表达个人理念、目标等，大学英语写作和口语中常要求掌握此类结构来清晰传递观点。","形容词性物主代词my用于修饰名词mission，表明所属关系，在正式表达中，物主代词的正确使用能体现语言的准确性，大学英语考试中会考查物主代词与名词的搭配，避免出现冠词和物主代词的混用错误。"]},"sentenceWithHints":"创新 是 我的 使命"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1636, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company encourages innovation among its employees."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["This is my favorite book.","The most important thing is to stay positive."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My dream is to travel around the world.","I finished my homework early."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"responsibilities","chinese":"责任","english":"responsibility","examples":["Taking care of the family is her responsibility.","Each team member has their own responsibilities."],"phonetic":"/rɪˌspɑːnsəˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的用法","主系表结构的运用","物主代词的搭配"],"explanations":["抽象名词如innovation、responsibility表示概念、品质等无形事物，通常为不可数名词，但表示具体的创新成果或多项责任时可作可数名词，本句中均表示抽象概念，使用单数形式。在正式书面语（如大学阶段的学术写作、正式报告）中，这类抽象名词常被用来表达观点、定义职责等。","本句为主系表结构，主语是抽象名词innovation（单数），因此系动词用is，表语是my responsibility，用于说明主语的属性，这种结构是英语中表达观点、界定事物属性的基础且常用结构，在大学阶段的英语写作、口语表达中高频出现。","形容词性物主代词my用来修饰名词responsibility，表明责任的所属关系，形容词性物主代词必须和名词搭配使用，不能单独作成分，这是英语代词体系中的重要知识点，在大学阶段的语法考核和语用表达中均会涉及。"]},"sentenceWithHints":"创新 是 我的 责任"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1637, '{"words":[{"plural":"innovations","chinese":"创新","english":"innovation","examples":["Technological innovation drives economic growth.","The company is known for its innovation in design."],"phonetic":"/ˌɪnəˈveɪʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a talented artist.","The cat is sleeping on the couch."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My favorite color is blue.","I finished my homework early."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"pursuits","chinese":"追求","english":"pursuit","examples":["Her lifelong pursuit is to protect the environment.","Reading is one of his favorite pursuits."],"phonetic":"/pərˈsuːt/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的使用","主系表结构的应用","物主代词的搭配"],"explanations":["创新（innovation）和追求（pursuit）都属于抽象名词，这类名词表示概念、情感、状态等抽象事物，在正式书面语和学术语境中常用，大学阶段英语学习需掌握这类高频抽象名词的拼写、发音和搭配，用于表达观点和理念。","本句是典型的主系表结构，主语是抽象名词innovation，系动词用is（主语为单数第三人称），表语是my pursuit，该结构是英语中表达判断、定义的核心结构，大学英语写作和翻译中常需用该结构清晰表达观点。","物主代词my用于修饰名词pursuit，表明所属关系，在英语中物主代词分为形容词性和名词性，my是形容词性物主代词，必须后接名词，大学阶段需准确区分不同物主代词的用法，避免出现语法错误。"]},"sentenceWithHints":"创新 是 我的 追求"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1638, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","partOfSpeech":"副词"},{"chinese":"都","english":"","examples":["We all like apples.","They are all happy."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"在","english":"","examples":["I am working now.","She is singing."],"phonetic":"","partOfSpeech":"助词"},{"chinese":"进步","english":"make progress","examples":["He makes progress every week.","I have made great progress."],"phonetic":"/meɪk ˈprɑːɡres/","pastTense":"made progress","thirdPerson":"makes progress","partOfSpeech":"动词","pastParticiple":"made progress","presentParticiple":"making progress"}],"examPoints":{"points":["固定搭配 make progress","一般现在时用法","时间状语 every day 的使用"],"explanations":["make progress 是固定动词短语，意为“取得进步”，是小学阶段需要掌握的常用搭配，progress 在这里是不可数名词，不能加不定冠词或变为复数形式。","一般现在时用于表示经常性、习惯性的动作，本句中“每天都在进步”是日常的状态，主语是第一人称 I，所以动词用原形 make。当主语是第三人称单数时，动词要变为 makes。","every day 是时间状语，意为“每天”，用于一般现在时的句子中，说明动作发生的频率，在句中通常放在句末位置。"]},"sentenceWithHints":"我 每天 都 在 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1639, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"","examples":["我在吃饭。","她在写作业。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"learn","examples":["I learn English every day.","She learns to play the piano."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"}],"examPoints":{"points":["一般现在时的用法","时间状语every day的用法","动词learn的形式变化"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句中“每天都在学习”是习惯性动作，主语是第一人称“I”，所以动词用原形learn。","every day是表示频率的时间状语，意为“每天”，用于一般现在时中，说明动作发生的频率，在句中通常位于句末。","learn作为规则动词，过去式和过去分词有两种形式learned和learnt，第三人称单数形式是learns，现在分词是learning，小学阶段需要掌握其原形和第三人称单数形式的变化。"]},"sentenceWithHints":"我 每天 都 在 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1640, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school by bus."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"","examples":["我在吃饭。","她在写作业。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"成长","english":"grow","examples":["Children grow very fast.","The tree grows tall and strong."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["一般现在时的用法","频度短语every day的使用","动词grow的形式变化"],"explanations":["一般现在时用于表示经常性、习惯性的动作或状态，本句中“每天都在成长”是习惯性的状态，主语是第一人称I，所以动词用原形grow。","every day是频度副词短语，意为“每天”，用于表示动作发生的频率，通常放在句末，在一般现在时的句子中常用来体现动作的经常性。","grow是不规则动词，它的过去式为grew，过去分词为grown，第三人称单数形式为grows，现在分词为growing，小学阶段需要掌握它在一般现在时中的原形和第三人称单数形式。"]},"sentenceWithHints":"我 每天 都 在 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1641, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school by bus."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"","examples":["我在吃饭。","他在看书。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"努力","english":"work hard","examples":["She works hard to get good grades.","He worked hard to finish the project."],"phonetic":"/wɜːrk hɑːrd/","pastTense":"worked hard","thirdPerson":"works hard","partOfSpeech":"动词","pastParticiple":"worked hard","presentParticiple":"working hard"}],"examPoints":{"points":["频度副词短语的用法","一般现在时的用法","副词修饰动词的位置"],"explanations":["every day是频度副词短语，用于表示动作的经常性，通常放在句末，用来描述每天都会发生的行为，符合本句中“每天”的含义。","一般现在时用于表示经常性、习惯性的动作，本句描述“每天努力”的习惯，主语是第一人称I，所以动词用原形work。当主语是第三人称单数时，动词要变成第三人称单数形式works。","hard作为副词，用来修饰动词work，说明动作的方式，通常放在动词的后面，构成“work hard”的搭配，表示“努力工作/学习”。"]},"sentenceWithHints":"我 每天 都 在 努力。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1642, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"","examples":["我在吃饭。","他在看书。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"坚持","english":"persist","examples":["If you persist, you will succeed.","She persists in practicing the piano every day."],"phonetic":"/pərˈsɪst/","pastTense":"persisted","thirdPerson":"persists","partOfSpeech":"动词","pastParticiple":"persisted","presentParticiple":"persisting"}],"examPoints":{"points":["频度时间状语的使用","一般现在时的用法","不及物动词persist的用法"],"explanations":["every day是表示频度的时间状语，意为“每天”，用于描述习惯性、经常性的动作，在句中通常位于句末。","一般现在时用于表示经常性、习惯性的动作或状态，当主语是第一人称单数I时，谓语动词用原形。本句描述“每天坚持”的习惯性动作，所以使用一般现在时，谓语动词persist用原形。","persist是不及物动词，意为“坚持；执意”，常见搭配为persist in doing sth.，表示“坚持做某事”，在本句中直接使用动词原形表示习惯性动作。"]},"sentenceWithHints":"我 每天 都 在 坚持"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1643, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"","examples":["我在吃饭。","他在看书。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"挑战","english":"challenge","examples":["I challenge you to a game.","She challenges herself every week."],"phonetic":"/ˈtʃælɪndʒ/","pastTense":"challenged","thirdPerson":"challenges","partOfSpeech":"动词","pastParticiple":"challenged","presentParticiple":"challenging"},{"plural":"","chinese":"自己","english":"myself","examples":["I hurt myself yesterday.","I often ask myself questions."],"phonetic":"/maɪˈself/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","反身代词的使用","时间状语every day的用法"],"explanations":["一般现在时用于表示经常性、习惯性的动作。本句中“每天”说明是习惯性动作，主语是第一人称I，所以动词用原形challenge。","反身代词myself指代主语I，当主语和宾语指代同一人时，需要使用反身代词，常见的反身代词还有yourself、himself等。","every day是时间状语，表示“每天”，用于一般现在时的句子中，通常放在句末，说明动作发生的频率。"]},"sentenceWithHints":"我 每天 都 在 挑战 自己"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1644, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I read books every day.","She exercises every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"","examples":["我在吃饭。","他在看书。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"超越","english":"surpass","examples":["He wants to surpass his father.","You can surpass your own record."],"phonetic":"/sərˈpæs/","pastTense":"surpassed","thirdPerson":"surpasses","partOfSpeech":"动词","pastParticiple":"surpassed","presentParticiple":"surpassing"},{"plural":"","chinese":"自己","english":"myself","examples":["I can do it myself.","I hurt myself yesterday."],"phonetic":"/maɪˈself/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["反身代词的用法","一般现在时的用法","时间状语every day的用法"],"explanations":["反身代词myself指代主语I，在句中作宾语，用来表示动作作用于主语自身，当主语和宾语为同一个人时，需要使用反身代词。","一般现在时用于表示经常性、习惯性的动作，本句中every day表明动作是日常重复发生的，主语是第一人称I，所以动词用原形surpass。","every day是副词短语，在句中作时间状语，用于表示动作发生的频率，通常放在句末，用来说明动作每天都会发生。"]},"sentenceWithHints":"我 每天 都 在 超越 自己"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1645, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like apples.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I read books every day.","She exercises every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"","examples":["我们都喜欢唱歌。","他们都来了。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"在","english":"","examples":["我在吃饭。","他在看书。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"变","english":"become","examples":["She becomes taller every year.","I became a student last year."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"得","english":"","examples":["他跑得很快。","我做得很好。"],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"更","english":"more","examples":["She is more beautiful than me.","I need more time."],"phonetic":"/mɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"好","english":"better","examples":["You are better now.","This book is better than that one."],"phonetic":"/ˈbetər/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","形容词比较级的使用","时间状语every day的位置"],"explanations":["一般现在时用于表示经常性、习惯性的动作或状态，本句中every day表明是日常的状态变化，主语是第一人称I，所以动词用原形become。","better是good的比较级，用于表示“变得比之前更好”，此处用more+原级的形式不符合good的比较级变化，要记住good的比较级是不规则变化better。","时间状语every day通常放在句子末尾，用来说明动作发生的频率，在本句中放在句尾符合英语的表达习惯。"]},"sentenceWithHints":"我 每天 都 在 变 得 更 好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1646, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"都","english":"all","examples":["We all like cats.","They are all happy."],"phonetic":"/ɔːl/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"在","english":"be","examples":["I am at home.","She is singing."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"接近","english":"get close to","examples":["I get close to my dream step by step.","She gets close to finishing her homework."],"phonetic":"/ɡet kloʊs tuː/","pastTense":"got close to","thirdPerson":"gets close to","partOfSpeech":"动词","pastParticiple":"got close to/gotten close to","presentParticiple":"getting close to"},{"plural":"goals","chinese":"目标","english":"goal","examples":["My goal is to learn English well.","He has many goals for this year."],"phonetic":"/ɡoʊl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时的用法","形容词比较级的用法","固定搭配get close to的使用","可数名词复数形式"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句中“每天”提示动作是日常重复的，因此使用一般现在时，主语为第一人称I，动词用原形get。","closer是close的比较级，用于表示“更接近”，在这里体现出随着每天的坚持，和目标的距离在不断拉近，符合句子表达的递进含义。","get close to是固定动词短语，意为“接近、靠近”，后面可以接名词或代词，是小学阶段需要掌握的常用搭配。","goal是可数名词，当表示多个目标时需要使用复数形式goals，本句中没有特指单一目标，因此用复数形式体现泛指的目标。"]},"sentenceWithHints":"我 每天 都 在 接近 目标"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1647, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"每天","english":"every day","examples":["I exercise every day.","She reads books every day."],"phonetic":"/ˈevri deɪ/","partOfSpeech":"副词"},{"chinese":"都","english":"all","examples":["We all like music.","They are all happy."],"phonetic":"/ɔːl/","partOfSpeech":"副词"},{"chinese":"在","english":"（无对应独立译词，表持续状态）","examples":[],"phonetic":"","partOfSpeech":"助词"},{"chinese":"实现","english":"realize","examples":["I realize my mistake now.","She realizes her dream finally."],"phonetic":"/ˈriːəlaɪz/","pastTense":"realized","thirdPerson":"realizes","partOfSpeech":"动词","pastParticiple":"realized","presentParticiple":"realizing"},{"plural":"dreams","chinese":"梦想","english":"dream","examples":["I have many dreams.","His dream is to be a doctor."],"phonetic":"/driːm/","partOfSpeech":"名词"}],"examPoints":{"points":["一般现在时用法","可数名词复数","时间状语every day的使用"],"explanations":["一般现在时用于表示经常性、习惯性的动作，本句中“每天都在实现”是日常持续的动作，主语是第一人称I，所以动词用原形realize。","dream是可数名词，当表示多个梦想或者泛指梦想时，要用复数形式dreams，本句中表示泛指的梦想，所以用dreams。","every day是时间状语，意为“每天”，用于一般现在时的句子中，通常放在句末，用来说明动作发生的频率。"]},"sentenceWithHints":"我 每天 都 在 实现 梦想"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1648, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","Our school has a big playground."],"phonetic":"/skuːl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a nurse.","It is a sunny day."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to eat an apple."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"学习","english":"study","examples":["I study math after school.","She studies hard every night."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"},{"plural":"","chinese":"的","english":"","examples":["This is my mother''s bag.","The cat''s tail is long."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"地方","english":"where","examples":["Where do you live?","This is where we met."],"phonetic":"/wer/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["表语从句的使用","be动词的人称搭配","实义动词study的用法"],"explanations":["本句中用where引导表语从句，用来对主语“school”的属性进行说明，解释学校的功能属性，小学阶段需要理解“where引导从句表示地点/场所”的基础用法，能识别并简单运用该结构描述地点功能。","be动词is用于第三人称单数主语后，本句主语“school”是单数名词，属于第三人称单数范畴，因此搭配is，小学阶段需要掌握be动词（am/is/are）和不同人称主语的对应搭配规则。","study作为实义动词，意为“学习”，在一般现在时中，主语是第一人称I时用原形study；主语是第三人称单数时要变为studies，同时需要掌握它的过去式studied等变形，小学阶段需要掌握该动词在不同时态和人称下的正确形式。"]},"sentenceWithHints":"学校 是 我 学习 的 地方"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1649, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","Our school has a big playground."],"phonetic":"/skuːl/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a student.","This is my cat."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to play outside."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","I want to grow into a kind person."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"},{"plural":"","chinese":"的","english":"","examples":[""],"phonetic":"","partOfSpeech":"助词"},{"plural":"","chinese":"地方","english":"where","examples":["This is where I live.","Tell me where you found it."],"phonetic":"/wer/","partOfSpeech":"副词"}],"examPoints":{"points":["表语从句的简单运用","系动词be的用法","不规则动词grow的变形"],"explanations":["本句中“where I grow”是表语从句，用来对主语“School”进行补充说明，说明学校的属性是“我成长的地方”，小学阶段主要掌握这种用where引导的表语从句来描述地点属性的简单结构。","系动词be有am、is、are三种形式，当主语是单数名词（如本句的school）时，搭配系动词is，小学阶段需要掌握根据主语单复数来选择正确be动词的用法。","grow是不规则动词，它的过去式是grew，过去分词是grown，第三人称单数是grows，现在分词是growing，小学阶段需要重点记忆常见不规则动词的变形形式。"]},"sentenceWithHints":"学校 是 我 成长 的 地方"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1650, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","Our school has a big playground."],"phonetic":"/skuːl/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a student.","The cat is on the chair."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我","english":"I","examples":["I like apples.","I am ten years old."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","She has a happy family."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"},{"chinese":"的","english":"of","examples":["the color of the sky","a friend of mine"],"phonetic":"/ʌv/","partOfSpeech":"助词"},{"plural":"places","chinese":"地方","english":"place","examples":["This is a beautiful place.","I want to visit many places."],"phonetic":"/pleɪs/","partOfSpeech":"名词"}],"examPoints":{"points":["表语从句的简单运用","be动词的人称搭配","形容词的用法"],"explanations":["当要表达“……的地方”这类带有描述性的内容时，英语中常用where引导的表语从句来对应，本句中“where I am happy”作is的表语，说明school的属性，这是小学阶段接触的复合句基础形式。","be动词有am、is、are三种形式，am只能和主语I搭配，is用于第三人称单数主语，are用于复数主语和you。本句中“我快乐”对应的“I am happy”里，主语是I，所以搭配am；“学校是……”里主语school是第三人称单数，所以搭配is。","形容词happy用来描述人的情绪状态，在句中可以放在be动词后作表语，比如“I am happy”，也可以放在名词前作定语，比如“a happy girl”，本句中它在be动词后作表语，体现“我”的状态。"]},"sentenceWithHints":"学校 是 我 快乐 的 地方"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1651, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","There is a new school in our town."],"phonetic":"/skuːl/","partOfSpeech":"名词"},{"chinese":"有","english":"there be","examples":["There is a cat on the chair.","There are some apples in the basket."],"phonetic":"/ðer biː/","pastTense":"there was/there were","thirdPerson":"there is/there are","partOfSpeech":"动词","pastParticiple":"there been","presentParticiple":"there being"},{"plural":"","chinese":"很多","english":"many","examples":["Many people like coffee.","I have many books."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"classmates","chinese":"同学","english":"classmate","examples":["My classmate helps me with my homework.","I play with my classmates after school."],"phonetic":"/ˈklæsmeɪt/","partOfSpeech":"名词"}],"examPoints":{"points":["there be 句型的主谓一致","形容词 many 的用法","地点介词 at 的搭配"],"explanations":["there be 句型遵循就近原则，be动词的单复数由后面的名词决定。本句中名词classmates是复数，所以用are。","many是形容词，用来修饰可数名词复数，说明数量多，不能修饰不可数名词，本句中修饰可数名词复数classmates，符合其用法规则。","at后接小地点，school属于小地点范畴，所以表达“在学校”用at school，这是小学阶段需要掌握的地点介词固定搭配。"]},"sentenceWithHints":"学校 有 很多 同学"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1652, '{"words":[{"plural":"schools","chinese":"学校","english":"school","examples":["I go to school every day.","The school has a big playground."],"phonetic":"/skuːl/","partOfSpeech":"名词"},{"chinese":"有","english":"there be","examples":["There is a cat under the chair.","There are some books on the shelf."],"phonetic":"/ðer biː/","pastTense":"there was/there were","thirdPerson":"there is/there are","partOfSpeech":"动词","pastParticiple":"there been","presentParticiple":"there being"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like playing games.","I have many toys at home."],"phonetic":"/ˈmeni/","partOfSpeech":"形容词"},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","There are twenty teachers in our school."],"phonetic":"/ˈtiːtʃər/","partOfSpeech":"名词"}],"examPoints":{"points":["there be 句型的主谓一致","many 的用法","可数名词复数形式"],"explanations":["there be 句型遵循就近原则，be动词的单复数由后面紧跟的名词决定。本句中后面的名词是复数的teachers，所以be动词用are。","many是形容词，用来修饰可数名词复数，表示“许多的”，不能修饰不可数名词，常用来描述数量较多的人或事物。","可数名词表示数量大于1时，需要使用复数形式。规则名词teacher变复数直接在词尾加-s，变为teachers。"]},"sentenceWithHints":"学校 有 很多 老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1654, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are good friends.","We love playing football."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["Let''s play together.","We go to school together every day."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"study","examples":["I study English every night.","She studies hard for the test."],"phonetic":"/ˈstʌdi/","pastTense":"studied","thirdPerson":"studies","partOfSpeech":"动词","pastParticiple":"studied","presentParticiple":"studying"}],"examPoints":{"points":["人称代词主格的使用","副词在句子中的位置","一般现在时动词形式"],"explanations":["人称代词we是主格形式，在句子中作主语，用来指代说话者及其他人，对应中文的“我们”，本句中作句子的主语发出“学习”这个动作。","副词together属于方式副词，在本句中放在实义动词study之后，用来修饰动词，表示动作发生的方式，说明是“一起”进行学习这个动作。","一般现在时中，当主语是第一人称复数we时，实义动词用原形study；当主语是第三人称单数时，动词要变成对应的第三人称单数形式studies，本句主语是we，所以使用动词原形。"]},"sentenceWithHints":"我们 一起 学习"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1655, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We love playing games."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["Let''s sing together.","We go to school together every day."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"玩耍","english":"play","examples":["I play football after school.","She plays the piano well."],"phonetic":"/pleɪ/","pastTense":"played","thirdPerson":"plays","partOfSpeech":"动词","pastParticiple":"played","presentParticiple":"playing"}],"examPoints":{"points":["人称代词主格的用法","一般现在时的用法","副词在句中的位置"],"explanations":["人称代词主格we在句中作主语，指代说话者及其他人，对应英文的we，在一般现在时中，当主语是第一人称复数we时，谓语动词用原形。","一般现在时用于表示经常性、习惯性的动作或当前的状态。本句描述的是常见的行为，主语是第一人称复数we，所以谓语动词play用原形。","副词together属于方式副词，通常放在句末，用来修饰动词play，说明动作进行的方式，在本句中放在play之后，符合英语的表达习惯。"]},"sentenceWithHints":"我们 一起 玩耍"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1656, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are friends.","We love our school."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"一起","english":"together","examples":["Let''s play together.","We go to school together every day."],"phonetic":"/təˈɡeðər/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"成长","english":"grow","examples":["Children grow very fast.","She wants to grow up to be a doctor."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["人称代词主格的用法","一般现在时动词形式","副词在句中的位置"],"explanations":["人称代词主格we在句中作主语，用来指代说话者及其他人，本句中作为动作“成长”的发出者，放在句首引导句子。","一般现在时中，当主语是第一人称复数we时，谓语动词用原形，本句中grow用原形符合这一规则；同时要掌握grow的不规则变形，其过去式为grew，过去分词为grown，第三人称单数为grows，现在分词为growing。","副词together是方式副词，在本句中放在实义动词grow之后，用来修饰动词，说明动作发生的方式，这是小学阶段需要掌握的副词基本位置规则之一。"]},"sentenceWithHints":"我们 一起 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1658, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very nice.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"负责","english":"responsible","examples":["She is a responsible doctor.","You should be responsible for your actions."],"phonetic":"/rɪˈspɑːnsəbl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["名词复数与be动词的搭配","副词修饰形容词的用法"],"explanations":["当表示一类人时，常用可数名词的复数形式，此时对应的be动词要用are。本句中“老师”指的是一类群体，所以用复数teachers，搭配be动词are。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，说明形容词所描述的程度。本句中very用来修饰形容词responsible，强调负责的程度。"]},"sentenceWithHints":"老师 很 负责"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1659, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"耐心","english":"patient","examples":["The nurse is very patient with kids.","You need to be patient when learning a new language."],"phonetic":"/ˈpeɪʃnt/","partOfSpeech":"形容词"}],"examPoints":{"points":["名词复数与be动词的搭配","副词修饰形容词的用法"],"explanations":["当表示一类人时，常用可数名词的复数形式，此时对应的be动词要用are。本句中“老师”指的是老师这类群体，所以用复数teachers，搭配be动词are。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，说明形容词所描述的程度。本句中very用来修饰形容词patient，体现老师耐心的程度。"]},"sentenceWithHints":"老师 很 耐心。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1660, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"关心","english":"care about","examples":["My parents care about my study.","She cares about the environment very much."],"phonetic":"/ker əˈbaʊt/","pastTense":"cared about","thirdPerson":"cares about","partOfSpeech":"动词","pastParticiple":"cared about","presentParticiple":"caring about"},{"plural":"","chinese":"我们","english":"us","examples":["Please give us a hand.","They are waiting for us."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词短语care about的用法","人称代词宾格的使用","副词very的位置","名词复数的使用"],"explanations":["care about是固定动词短语，意为“关心；在乎”，后接名词、代词或动名词作宾语，用来表达对人或事物的关切。","“我们”在句中作动词短语care about的宾语，所以要使用人称代词的宾格形式us，而不是主格形式we。","副词very用来修饰形容词或副词，表示“很；非常”，在修饰动词短语时，通常放在短语之后，句末位置，如本句的very much用来加强关心的程度。","当表示一类人时，可数名词常用复数形式，这里“老师”指的是一类群体，所以使用teacher的复数形式teachers，不需要加不定冠词。"]},"sentenceWithHints":"老师 很 关心 我们"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1661, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","partOfSpeech":"名词"},{"chinese":"是","english":"are","examples":["You are my best friend.","They are playing football."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我们","english":"we/our","examples":["We love our school.","Our classroom is clean."],"phonetic":"/wiː/ /ˈaʊər/","partOfSpeech":"代词"},{"chinese":"的","english":"","examples":["This is my mother''s bag.","The color of the flower is pink."],"phonetic":"","partOfSpeech":"助词"},{"plural":"guides","chinese":"引路人","english":"guide","examples":["The tour guide showed us around the city.","He is a guide for the lost children."],"phonetic":"/ɡaɪd/","partOfSpeech":"名词"}],"examPoints":{"points":["名词的复数形式","be动词的主谓一致用法","形容词性物主代词的使用"],"explanations":["当指代一类人或事物时，可数名词通常使用复数形式，本句中“老师”“引路人”都是指代一类群体，所以分别使用teachers和guides。规则可数名词变复数一般在词尾加-s。","be动词的形式要和主语保持一致，主语是复数名词teachers时，对应的be动词要用are。","“我们的”是形容词性物主代词，英文用our，用来修饰后面的名词guide，表明所属关系，形容词性物主代词后面必须接名词。"]},"sentenceWithHints":"老师 是 我们 的 引路人"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1662, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","partOfSpeech":"名词"},{"chinese":"是","english":"are","examples":["You are my classmate.","They are playing games."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我们","english":"we","examples":["We love our school.","We are going to the park."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"的","english":"of","examples":["This is a photo of my family.","The color of the pen is blue."],"phonetic":"/əv/","partOfSpeech":"介词"},{"plural":"friends","chinese":"朋友","english":"friend","examples":["I have many friends.","She is my best friend."],"phonetic":"/frend/","partOfSpeech":"名词"}],"examPoints":{"points":["可数名词的复数形式","系动词be的主谓一致"],"explanations":["可数名词表示一类人或事物时，常用复数形式。规则名词变复数一般在词尾加-s，teacher和friend都是规则名词，复数分别为teachers和friends。","系动词be的形式要和主语保持一致：当主语是复数时，be动词用are。本句主语teachers是复数，所以搭配are；同时表语friends也用复数，保持前后语义一致。"]},"sentenceWithHints":"老师 是 我们 的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1663, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"尊敬","english":"respect","examples":["We should respect our parents.","He respects all his teachers."],"phonetic":"/rɪˈspekt/","pastTense":"respected","thirdPerson":"respects","partOfSpeech":"动词","pastParticiple":"respected","presentParticiple":"respecting"},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very nice.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称主语搭配动词原形","可数名词复数的用法"],"explanations":["当句子主语是第一人称I（我）时，一般现在时中谓语动词要用原形，本句中主语是I，所以动词用respect的原形。","表示一类人时，可数名词通常用复数形式，不需要加不定冠词。本句中“老师”指代的是教师这一类人，所以用teacher的复数形式teachers。"]},"sentenceWithHints":"我 尊敬 老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1664, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like apples."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱","english":"love","examples":["I love my family.","She loves reading books."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is nice.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称主语搭配动词原形","可数名词复数形式"],"explanations":["当句子主语是第一人称I（我）时，一般现在时中谓语动词要用原形，本句中主语是I，所以动词用love的原形。","可数名词表示一类人或事物的复数概念时，要使用复数形式。规则名词变复数一般在词尾加-s，teacher是规则名词，所以复数形式是teachers，这里用复数表示对多位老师的喜爱，符合表达习惯。"]},"sentenceWithHints":"我 爱 我的 老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1665, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"感谢","english":"be grateful to","examples":["I am grateful to my parents for their love.","She is grateful to her classmates for helping her."],"phonetic":"/biː ˈɡreɪtfəl tuː/","pastTense":"was/were grateful to","thirdPerson":"is/are grateful to","partOfSpeech":"动词短语","pastParticiple":"been grateful to","presentParticiple":"being grateful to"},{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["感谢的英文表达结构","可数名词复数的用法"],"explanations":["在英语中，表达“感谢某人”常用结构“be grateful to sb”，这是小学阶段需要掌握的礼貌用语表达，不同主语搭配不同的be动词形式，本句主语是I，所以用am。","可数名词teacher表示一类人时，常用复数形式teachers，不需要加不定冠词，这里用复数teachers泛指老师们，符合英语中表示一类群体的用法。"]},"sentenceWithHints":"我 感谢 老师"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1666, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","partOfSpeech":"名词"},{"chinese":"是","english":"are","examples":["You are my friend.","They are students."],"phonetic":"/ɑːr/","pastTense":"were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"role models","chinese":"榜样","english":"role model","examples":["My father is my role model.","Many athletes are role models for kids."],"phonetic":"/roʊl ˈmɑːdl/","partOfSpeech":"名词"}],"examPoints":{"points":["名词复数形式","主谓一致"],"explanations":["可数名词表示一类事物时常用复数形式，“老师”这里指代教师群体，所以用复数teachers；“榜样”对应role model，复数形式为role models，是复合名词，只需将后面的名词变为复数。","主谓一致要求主语和谓语动词在数上保持一致，本句主语teachers是复数，所以对应的be动词要用复数形式are。"]},"sentenceWithHints":"老师 是 我的 榜样"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1667, '{"words":[{"plural":"teachers","chinese":"老师","english":"teacher","examples":["My teacher is very kind.","The teachers are having a meeting."],"phonetic":"/ˈtiːtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"让","english":"make","examples":["My mom makes delicious food.","He made a mistake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"变","english":"become","examples":["I want to become a doctor.","She became happy after hearing the news."],"phonetic":"/bɪˈkʌm/","pastTense":"became","thirdPerson":"becomes","partOfSpeech":"动词","pastParticiple":"become","presentParticiple":"becoming"},{"plural":"","chinese":"得","english":"/","examples":["She runs fast.","The flower looks beautiful."],"phonetic":"/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"更好","english":"better","examples":["You are better than me at math.","This book is better than that one."],"phonetic":"/ˈbetər/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["使役动词make的用法","形容词比较级的使用","人称代词宾格的用法"],"explanations":["make作为使役动词，常见结构为make sb.+形容词/动词原形，表示“使某人……”，本句中make me better即“让我变得更好”，符合小学四年级要求掌握的使役动词基础用法。","better是good/well的比较级形式，用于两者之间的比较，此处表示“比之前更好”，小学四年级开始接触形容词的比较级基础用法，需掌握常见不规则比较级形式。","me是人称代词I的宾格形式，在句子中作动词make的宾语，小学四年级需要区分人称代词主格和宾格的用法，宾格用于动词或介词之后。"]},"sentenceWithHints":"老师 让 我 变 得 更好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1669, '{"words":[{"chinese":"画画","english":"draw","examples":["I like to draw pictures.","She draws a cat every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gives me a gift.","Please wait for me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"表达","english":"express","examples":["I want to express my thanks.","She expresses her feelings through art."],"phonetic":"/ɪkˈspres/","pastTense":"expressed","thirdPerson":"expresses","partOfSpeech":"动词","pastParticiple":"expressed","presentParticiple":"expressing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法"],"explanations":["当动词要在句子中充当主语时，需要将其变成动名词形式（动词后加-ing），本句中“画画”作主语，所以使用draw的动名词drawing。","使役动词let后接宾语（此处是me），再接不带to的动词不定式作宾语补足语，结构为let sb. do sth.，表示“让某人做某事”，所以本句中express用原形。"]},"sentenceWithHints":"画画 让 我 表达"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1670, '{"words":[{"chinese":"画画","english":"draw","examples":["I like to draw pictures.","She draws very well."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"让","english":"make","examples":["The news makes me happy.","My mom makes delicious food."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"放松","english":"relax","examples":["I relax by listening to music.","You should relax after work."],"phonetic":"/rɪˈlæks/","pastTense":"relaxed","thirdPerson":"relaxes","partOfSpeech":"动词","pastParticiple":"relaxed","presentParticiple":"relaxing"}],"examPoints":{"points":["动名词作主语","使役动词make的用法"],"explanations":["当动词要在句子中充当主语时，需要将其变为动名词形式（即动词后加-ing），本句中“画画”作主语，所以用drawing，动名词作主语时，谓语动词要用第三人称单数形式，所以make变为makes。","使役动词make常用结构为“make + 宾语 + 动词原形”，表示“让某人做某事”，本句中me是宾语，后面直接接动词原形relax，不需要加to。"]},"sentenceWithHints":"画画 让 我 放松"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1671, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"画了","english":"draw","examples":["I draw a cat every day.","She has drawn a beautiful flower."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"","chinese":"很多","english":"many","examples":["Many students like music.","I have many storybooks."],"phonetic":"/ˈmeni/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"pictures","chinese":"画","english":"picture","examples":["This is a nice picture.","She has drawn many pictures."],"phonetic":"/ˈpɪktʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["现在完成时的用法","不规则动词的过去分词变化","many的用法"],"explanations":["现在完成时结构为have/has+动词过去分词，用于表示过去发生的动作对现在造成的影响或结果。本句中“画了很多画”强调到现在为止完成的动作结果，所以用have drawn，主语I搭配助动词have。","draw是不规则动词，它的过去式是drew，过去分词是drawn，需要特殊记忆，不能直接加ed，这是小学阶段需要掌握的重点不规则动词之一。","many作为形容词，用于修饰可数名词复数，用来表示数量多，本句中修饰可数名词复数pictures，符合many的使用规则，不可修饰不可数名词。"]},"sentenceWithHints":"我 画了 很多 画"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1672, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to go home."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"画了","english":"paint","examples":["She paints a picture every day.","He painted a cat yesterday."],"phonetic":"/peɪnt/","pastTense":"painted","thirdPerson":"paints","partOfSpeech":"动词","pastParticiple":"painted","presentParticiple":"painting"},{"plural":"landscapes","chinese":"风景","english":"landscape","examples":["The landscape here is beautiful.","He painted many mountain landscapes."],"phonetic":"/ˈlændskeɪp/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词过去式的用法","可数名词复数形式"],"explanations":["句中“画了”表明动作已经完成，是一般过去时，所以动词要用过去式。paint的过去式是规则变化，直接在词尾加-ed，即painted，用来表示已经发生的动作。","landscape是可数名词，当表示泛指的一类事物时，要用复数形式。规则可数名词变复数一般在词尾加-s，所以landscape的复数是landscapes，本句中用复数表示泛指的各类风景。"]},"sentenceWithHints":"我 画了 风景"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1673, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"画了","english":"paint","examples":["I painted a cat yesterday.","She paints beautiful pictures."],"phonetic":"/peɪnt/","pastTense":"painted","thirdPerson":"paints","partOfSpeech":"动词","pastParticiple":"painted","presentParticiple":"painting"},{"plural":"people","chinese":"人物","english":"people","examples":["Many people like music.","The people in the park are happy."],"phonetic":"/ˈpiːpəl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词过去式的用法","集体名词的单复数"],"explanations":["句子中“画了”表示动作已经完成，是一般过去时，所以动词要用过去式。paint的过去式是规则变化，直接在词尾加-ed，即painted，用于描述过去发生的动作。","people作为“人、人们”讲时是集体名词，本身就表示复数概念，它的单复数同形，不需要加-s或-es，在句子中作主语时，谓语动词要用复数形式。"]},"sentenceWithHints":"我 画了 人物"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1674, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"画了","english":"paint","examples":["I paint a picture every day.","She painted a cat yesterday."],"phonetic":"/peɪnt/","pastTense":"painted","thirdPerson":"paints","partOfSpeech":"动词","pastParticiple":"painted","presentParticiple":"painting"},{"plural":"animals","chinese":"动物","english":"animal","examples":["I like small animals.","The zoo has many kinds of animals."],"phonetic":"/ˈænɪml/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般过去时的用法","可数名词复数的用法"],"explanations":["中文里用\"了\"表示动作已经完成，对应英语的一般过去时，规则动词的过去式通常在词尾加-ed，paint属于规则动词，所以过去式为painted，用来描述已经发生的动作。","可数名词表示泛指的一类事物时，要用复数形式。animal是可数名词，此处没有特指某一只动物，所以用复数animals来表示泛指的动物这类生物。"]},"sentenceWithHints":"我 画了 动物"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1676, '{"words":[{"chinese":"画画","english":"draw","examples":["I like to draw pictures.","She draws very well."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"be","examples":["It is important to study hard.","They are good friends."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"意义","english":"meaningful","examples":["Reading is meaningful.","This is a meaningful gift."],"phonetic":"/ˈmiːnɪŋfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","副词修饰形容词","系表结构"],"explanations":["动词不能直接作主语，需要将动词变为动名词形式（即动词加-ing），本句中draw变为drawing在句中作主语，表示“画画”这件事。","副词very用来修饰形容词，放在形容词前面，用来加强形容词的语气，本句中very修饰meaningful，强调“有意义”的程度。","本句使用“主语+系动词+表语”的系表结构，动名词drawing作主语，系动词is连接主语和表语meaningful，用来说明主语的性质或状态。"]},"sentenceWithHints":"画画 很 有 意义"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1677, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will help you.","She will come tomorrow."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"继续","english":"continue","examples":["He continues to study hard.","We will continue our trip tomorrow."],"phonetic":"/kənˈtɪnjuː/","pastTense":"continued","thirdPerson":"continues","partOfSpeech":"动词","pastParticiple":"continued","presentParticiple":"continuing"},{"plural":"drawings","chinese":"画画","english":"drawing","examples":["She likes drawing cats.","His drawings are very beautiful."],"phonetic":"/ˈdrɔːɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","动词continue的用法"],"explanations":["小学阶段一般将来时常用“will + 动词原形”的结构表示将来要做的动作，本句中“会”表达将来的意愿，所以用will加continue的原形来构成将来时态。","continue后可以接动名词（即动词的-ing形式）表示“继续做某事”，这里drawing是draw的动名词形式，作continue的宾语，符合“continue doing sth.”的固定搭配，这是小学阶段需要掌握的动词搭配知识点。"]},"sentenceWithHints":"我 会 继续 画画"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1678, '{"words":[{"chinese":"画画","english":"draw","examples":["I draw a picture every day.","She is drawing a cat now."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"是","english":"is","examples":["This is my pen.","He is from Canada."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My bag is blue.","This is my favorite toy."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"hobbies","chinese":"爱好","english":"hobby","examples":["Reading is my hobby.","She has many hobbies."],"phonetic":"/ˈhɑːbi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","名词单数形式"],"explanations":["当表示“做某事”这件事本身作主语时，要把动词变成动名词形式（即动词+ing），本句中“画画”作为主语，所以用drawing，这是小学五年级动名词的基础考点。","系动词be有am、is、are三种形式，当主语是单数（包括动名词作主语，视为单数概念）时，be动词用is，本句主语drawing是单数概念，所以用is。","hobby是可数名词单数，在本句中表示“我的一个爱好”，单数可数名词在句中单独使用时要符合语境，这里前面有形容词性物主代词my修饰，不需要加不定冠词，同时要注意其复数形式是变y为i加es，即hobbies。"]},"sentenceWithHints":"画画 是 我的 爱好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1679, '{"words":[{"plural":"drawings","chinese":"画画","english":"drawing","examples":["Drawing is my favorite hobby.","She does beautiful drawing in her free time."],"phonetic":"/ˈdrɔːɪŋ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is happy.","He is a student."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My book is on the desk.","This is my friend."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"friends","chinese":"朋友","english":"friend","examples":["Lily is my best friend.","We made many new friends at school."],"phonetic":"/frend/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","系动词be的用法","形容词性物主代词的使用"],"explanations":["当表示“做某事”这个行为作为句子主语时，需要把动词变成动名词形式（动词后加-ing），本句中“画画”是一个行为，所以用drawing作主语，此时主语视为单数概念。","系动词be有am、is、are三种形式，当主语是第三人称单数（包括动名词、单数名词等）时，be动词用is，本句主语drawing是单数概念，所以用is。","形容词性物主代词my用来修饰名词，表明所属关系，放在名词前，本句中my修饰friend，说明是“我的朋友”，形容词性物主代词不能单独使用，必须和名词搭配。"]},"sentenceWithHints":"画画 是 我的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1680, '{"words":[{"chinese":"画画","english":"draw","examples":["I draw a cat every day.","She is drawing a picture now."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"让","english":"make","examples":["The story makes me laugh.","She makes a cake for us."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gives me a pen.","My friend plays with me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","She is happy to see you."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法"],"explanations":["当动词要在句子中充当主语时，需要变成动名词形式（即动词+ing），本句中“画画”作为主语，所以用draw的动名词drawing，此时主语视为第三人称单数，谓语动词要用第三人称单数形式。","make作为使役动词，常用结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”就是“让我快乐”的对应表达，符合这个结构用法。"]},"sentenceWithHints":"画画 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1681, '{"words":[{"chinese":"画画","english":"draw","examples":["I draw a picture every day.","She drew a cat yesterday."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"让","english":"satisfy","examples":["The result satisfies me.","This meal satisfied everyone."],"phonetic":"/ˈsætɪsfaɪ/","pastTense":"satisfied","thirdPerson":"satisfies","partOfSpeech":"动词","pastParticiple":"satisfied","presentParticiple":"satisfying"},{"chinese":"我","english":"me","examples":["He gives me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"满足","english":"satisfied","examples":["I feel satisfied with my work.","She is satisfied with the result."],"phonetic":"/ˈsætɪsfaɪd/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","动词第三人称单数变化","人称代词宾格"],"explanations":["当动词要在句子中充当主语时，需要变成动名词形式（动词+ing），本句中“画画”作为主语，所以用 Drawing。","当句子主语是第三人称单数时，一般现在时的谓语动词要变成第三人称单数形式，satisfy 以辅音字母+y结尾，变第三人称单数要把y变i加es，即satisfies。","在句子中作动词宾语的人称代词要用宾格形式，“我”在本句中作satisfies的宾语，所以用宾格me。"]},"sentenceWithHints":"画画 让 我 满足"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1682, '{"words":[{"chinese":"画画","english":"draw","examples":["I like to draw pictures.","She draws a cat every day."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","He let his friend use his bike."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","The tree grows tall and strong."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法","不规则动词的变形"],"explanations":["当动词要在句子中充当主语时，需要变成动名词形式（即动词后加-ing），本句中“画画”作为主语，所以用drawing，这是小学阶段非谓语动词的基础考点。","使役动词let的常用结构是“let + 宾语 + 动词原形”，表示“让某人做某事”，本句中lets me grow就是遵循这个结构，let后面的宾语me之后接动词原形grow。","小学阶段需要掌握常见不规则动词的变形，比如draw的过去式是drew、过去分词是drawn；let的过去式和过去分词都是let；grow的过去式是grew、过去分词是grown，这些不规则变形是考试中动词形式考查的重点。"]},"sentenceWithHints":"画画 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1683, '{"words":[{"chinese":"画画","english":"draw","examples":["I draw a picture every day.","She is drawing a cat now."],"phonetic":"/drɔː/","pastTense":"drew","thirdPerson":"draws","partOfSpeech":"动词","pastParticiple":"drawn","presentParticiple":"drawing"},{"chinese":"是","english":"is","examples":["He is tall.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My bag is red.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"talents","chinese":"天赋","english":"talent","examples":["She has a talent for singing.","He showed his talent in the game."],"phonetic":"/ˈtælənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","形容词性物主代词的使用"],"explanations":["当表示某个动作作为句子的主语时，需要把动词变成动名词形式（即动词后加-ing），本句中“画画”作为主语，所以使用draw的动名词drawing。","系动词be有am、is、are三种形式，当主语是第三人称单数（包括动名词作主语）时，be动词用is，本句主语drawing是第三人称单数，所以用is。","形容词性物主代词my用来修饰名词，表示所属关系，本句中my修饰talent，说明天赋是“我的”，形容词性物主代词后面必须跟名词，不能单独使用。"]},"sentenceWithHints":"画画 是 我的 天赋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1685, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for me."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel happy today.","She is a happy girl."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法"],"explanations":["动词不能直接作主语，需要变成动名词形式（动词+ing），本句中sing变成singing作主语，此时主语视为第三人称单数，所以谓语动词要用第三人称单数形式。","make作为使役动词，常用结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中make me happy就是“让我快乐”的意思，符合这个固定搭配。"]},"sentenceWithHints":"唱歌 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1686, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song now."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"放松","english":"relax","examples":["I relax after school.","Reading helps me relax."],"phonetic":"/rɪˈlæks/","pastTense":"relaxed","thirdPerson":"relaxes","partOfSpeech":"动词","pastParticiple":"relaxed","presentParticiple":"relaxing"}],"examPoints":{"points":["动名词作主语","make 的使役用法"],"explanations":["动词原形不能直接作主语，需要变成动名词形式（动词+ing），本句中 sing 变成 singing 作句子主语，此时谓语动词要用第三人称单数形式，所以 make 变成 makes。","make 作为使役动词，常见用法是 make sb. do sth.，表示“让某人做某事”，这里的 do 要用动词原形，所以后面跟 relax 的原形。"]},"sentenceWithHints":"唱歌 让 我 放松"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1688, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"唱","english":"sing","examples":["She sings very well.","I sang a song at the party."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"plural":"","chinese":"中文","english":"Chinese","examples":["I like Chinese food.","She is learning Chinese."],"phonetic":"/ˌtʃaɪˈniːz/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"songs","chinese":"歌","english":"song","examples":["This is my favorite song.","We sang many songs yesterday."],"phonetic":"/sɔːŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般现在时用法","可数名词复数形式","形容词作定语"],"explanations":["一般现在时用于表示经常性、习惯性的动作或状态，当主语是第一人称I时，谓语动词用原形。本句中“我唱中文歌”是习惯性动作，所以用动词原形sing。","可数名词表示一类事物时，常用复数形式。“歌”是可数名词，这里表示中文歌曲这一类事物，所以用复数形式songs，规则可数名词复数直接在词尾加-s。","形容词可以放在名词前作定语，用来修饰名词。本句中Chinese作为形容词，放在名词songs前，用来说明歌曲的语言属性，表明是中文的歌曲。"]},"sentenceWithHints":"我 唱 中文 歌"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1689, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I go to school every day."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"唱","english":"sing","examples":["I sing songs every weekend.","She sings very well."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"plural":"","chinese":"英文","english":"English","examples":["I study English every day.","This is an English book."],"phonetic":"/ˈɪŋɡlɪʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"songs","chinese":"歌","english":"song","examples":["I like this song.","We sing songs together."],"phonetic":"/sɔːŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词的一般现在时用法","可数名词的复数形式"],"explanations":["一般现在时中，当主语是第一人称（I/we）、第二人称（you）或复数主语时，谓语动词用原形。本句主语是第一人称I，所以动词sing用原形。当主语是第三人称单数时，动词要变成第三人称单数形式，如sing变为sings。","可数名词表示一类事物时，常用复数形式。本句中“英文歌”表示的是一类歌曲，不是单指某一首，所以用song的复数形式songs，规则可数名词变复数一般直接在词尾加-s。"]},"sentenceWithHints":"我 唱 英文 歌"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1691, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","The book is very interesting."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"be","examples":["There is a cat.","They are my friends."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"意义","english":"meaningful","examples":["This is a meaningful story.","Volunteering is meaningful."],"phonetic":"/ˈmiːnɪŋfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","副词修饰形容词","系动词的用法"],"explanations":["动词不能直接作主语，需要变成动名词形式（动词后加-ing），本句中sing变成singing作句子主语，表示“唱歌”这件事。","副词very用来修饰形容词，放在形容词前面，用来加强形容词的语气，本句中very修饰meaningful，强调“有意义”的程度。","本句中系动词is用来连接主语singing和表语meaningful，构成主系表结构，说明主语的性质或状态，主语是单数概念，所以用is。"]},"sentenceWithHints":"唱歌 很 有 意义"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1692, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"继续","english":"continue","examples":["He continues to work hard.","We will continue our journey."],"phonetic":"/kənˈtɪnjuː/","pastTense":"continued","thirdPerson":"continues","partOfSpeech":"动词","pastParticiple":"continued","presentParticiple":"continuing"},{"chinese":"唱歌","english":"sing","examples":["She sings very well.","I like singing songs."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"}],"examPoints":{"points":["一般将来时的表达","continue的用法"],"explanations":["一般将来时表示将要发生的动作或存在的状态，小学阶段常用“will + 动词原形”的结构来表达，本句中“will continue”就体现了这个结构，用来表示将要继续做某事。","continue后可以接动名词（doing形式），表示“继续做正在做的同一件事”，本句中“continue singing”就是这个用法，表达继续进行唱歌这个动作。"]},"sentenceWithHints":"我 会 继续 唱歌"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1693, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song now."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"chinese":"是","english":"is","examples":["She is happy.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my favorite book."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"hobbies","chinese":"爱好","english":"hobby","examples":["Reading is my hobby.","She has many hobbies."],"phonetic":"/ˈhɑːbi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","名词单复数变化"],"explanations":["当表示某个动作作为主语时，需要把动词变成动名词形式（即动词+ing），本句中“唱歌”作为主语，所以用sing的动名词形式singing，在句首首字母大写。","系动词be有am、is、are三种形式，当主语是单数概念时，be动词用is。本句主语是Singing，属于单数概念，所以用is。","hobby是以辅音字母+y结尾的可数名词，变复数时要把y改成i再加es，所以复数形式是hobbies。"]},"sentenceWithHints":"唱歌 是 我的 爱好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1694, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song now."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"chinese":"是","english":"is","examples":["He is a student.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I love my family.","I want to play football."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"of","examples":["This is a photo of my cat.","The color of the flower is red."],"phonetic":"/əv/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"friends","chinese":"朋友","english":"friend","examples":["Lily is my best friend.","We are good friends."],"phonetic":"/frend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","形容词性物主代词的使用"],"explanations":["动词的ing形式（动名词）可以在句子中充当主语，表示一个动作或行为作为主语本句中用Singing（唱歌的动名词形式）作主语，谓语动词要用单数形式is。","系动词be有am、is、are三种形式，当主语是第三人称单数（包括动名词作主语）时，be动词用is，本句主语Singing是单数概念，所以用is。","形容词性物主代词my用来修饰名词friend，表示所属关系，说明这个朋友是“我的”，形容词性物主代词后面必须跟名词。"]},"sentenceWithHints":"唱歌 是 我 的 朋友。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1696, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song now."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"chinese":"让","english":"satisfy","examples":["The result satisfies me.","This job will satisfy your needs."],"phonetic":"/ˈsætɪsfaɪ/","pastTense":"satisfied","thirdPerson":"satisfies","partOfSpeech":"动词","pastParticiple":"satisfied","presentParticiple":"satisfying"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"满足","english":"satisfied","examples":["I feel satisfied with my work.","She is satisfied with the present."],"phonetic":"/ˈsætɪsfaɪd/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","动词第三人称单数变化","人称代词宾格的用法"],"explanations":["动词原形不能直接作主语，需要变成动名词形式（动词+ing），本句中“唱歌”作主语，所以用 singing，这是动名词作主语的用法，谓语动词要用单数形式。","当主语是第三人称单数（包括动名词作主语）时，一般现在时的谓语动词要使用第三人称单数形式，satisfy 的第三人称单数是在词尾加 -ies，即 satisfies。","人称代词分为主格和宾格，“我”的主格是 I，宾格是 me。在本句中“我”作动词 satisfy 的宾语，所以要用宾格形式 me。"]},"sentenceWithHints":"唱歌 让 我 满足"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1697, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She sang a beautiful song yesterday."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Me and my friend play together."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","She has grown into a nice young lady."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法"],"explanations":["动词原形不能直接作主语，需要变成动名词形式（动词后加-ing），本句中sing变成singing作句子主语，谓语动词用第三人称单数形式，所以let用lets。","使役动词let的常用结构是let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式，本句中let me grow符合这个结构，grow用动词原形。"]},"sentenceWithHints":"唱歌 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1698, '{"words":[{"chinese":"唱歌","english":"sing","examples":["I sing every day.","She is singing a song now."],"phonetic":"/sɪŋ/","pastTense":"sang","thirdPerson":"sings","partOfSpeech":"动词","pastParticiple":"sung","presentParticiple":"singing"},{"chinese":"是","english":"is","examples":["She is happy.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my favorite book."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"talents","chinese":"天赋","english":"talent","examples":["He has a talent for drawing.","She showed her musical talents."],"phonetic":"/ˈtælənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","物主代词的使用","系动词be的主谓一致"],"explanations":["当表示某个动作作为主语时，需要把动词变成动名词形式（即动词后加-ing），本句中“唱歌”作为主语，所以用sing的动名词形式singing，在句首首字母大写。","物主代词my用来表示所属关系，指代“我的”，后面接名词，本句中my修饰talent，表明天赋是“我的”，符合小学五年级物主代词的考查范围。","系动词be的形式要和主语保持一致，本句主语是动名词Singing，动名词作主语时视为单数，所以be动词用is。"]},"sentenceWithHints":"唱歌 是 我的 天赋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1700, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","Dancing is my favorite hobby."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake for her mom."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"快乐","english":"happy","examples":["I feel very happy today.","She is happy to see you."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法","主谓一致"],"explanations":["当表示“做某事”这个行为作为句子主语时，需要把动词变成动名词形式（即动词+ing），本句中“跳舞”作为主语，所以用Dancing。","使役动词make常见用法为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”就是“让我快乐”的对应表达，符合这个结构。","当句子主语是动名词时，属于单数第三人称概念，谓语动词需要用第三人称单数形式，本句主语Dancing是单数概念，所以make要变成makes。"]},"sentenceWithHints":"跳舞 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1701, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","Dancing is my hobby."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","My teacher likes me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"健康","english":"healthy","examples":["Eating vegetables keeps you healthy.","She looks healthy and strong."],"phonetic":"/ˈhelθi/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","使役动词make的用法"],"explanations":["当动词要在句子中充当主语时，需要将其变为动名词形式（即动词后加-ing），本句中“跳舞”作主语，所以用Dancing，动名词作主语时，谓语动词要用第三人称单数形式。","make作为使役动词，常见用法为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me healthy”就是“让我保持健康”的意思，符合这个结构。同时当主语是第三人称单数时，make要变为makes。"]},"sentenceWithHints":"跳舞 让 我 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1702, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I can swim fast."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"会","english":"can","examples":["I can sing.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"跳","english":"dance","examples":["I dance every day.","She danced at the party."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"很多","english":"many","examples":["Many students like math.","I have many books."],"phonetic":"/ˈmeni/","partOfSpeech":"形容词"},{"plural":"dances","chinese":"舞","english":"dance","examples":["She knows many dances.","We learned three new dances."],"phonetic":"/dæns/","partOfSpeech":"名词"}],"examPoints":{"points":["情态动词can的用法","可数名词的复数变化","同形异义的动词与名词"],"explanations":["情态动词can表示具备某种能力，后面要接动词原形，本句中can后接dance的原形，用来表达“会跳舞”的能力。","many用来修饰可数名词复数，dance作为可数名词表示“舞蹈种类”时，复数形式在词尾加-s，所以用many dances表示“很多种舞”。","dance既可以作动词表示“跳舞”的动作，也可以作名词表示“舞蹈（种类）”，在本句中同一个单词分别承担了动词和名词的不同功能，需要根据语境区分其词性和含义。"]},"sentenceWithHints":"我 会 跳 很多 舞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1703, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"跳","english":"dance","examples":["I dance every weekend.","She is dancing in the room."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"plural":"","chinese":"中国","english":"Chinese","examples":["Chinese food is delicious.","She speaks Chinese."],"phonetic":"/ˌtʃaɪˈniːz/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"dances","chinese":"舞","english":"dance","examples":["She is learning a new dance.","The dance is very beautiful."],"phonetic":"/dæns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","动词与名词的同形辨析","专有形容词的用法"],"explanations":["情态动词can表示“能够、会”，后面要接动词原形，用来表达具备某种能力。本句中can后面接动词dance的原形，符合这一用法。","dance既可以作动词表示“跳舞”的动作，也可以作名词表示“舞蹈”这一事物。本句中第一个dance是动词，第二个dance是名词，需要根据语境区分词性和用法。","Chinese作为专有形容词，用来修饰名词dance，表示“中国的”，专有形容词首字母需要大写，用来限定事物的所属属性。"]},"sentenceWithHints":"我 会 跳 中国 舞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1704, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim fast.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"跳","english":"dance","examples":["I dance every weekend.","She danced beautifully yesterday."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"plural":"modern dances","chinese":"现代舞","english":"modern dance","examples":["She learns modern dance.","Modern dance is a popular art form."],"phonetic":"/ˈmɑːdərn dæns/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","动词原形在情态动词后的使用","名词短语的表达"],"explanations":["情态动词can用于表示能力，意为“能，会”，后接动词原形，没有人称和数的变化，过去式为could，用于表示过去的能力。","情态动词can后面必须接动词原形，不能接动词的第三人称单数、现在分词等形式，本句中can后接dance的原形，符合语法规则。","“现代舞”对应的英文是固定名词短语modern dance，当表示多种现代舞类型时，可变为复数modern dances；在表达“跳某种舞”时，常用“dance + 舞种名词”的结构。"]},"sentenceWithHints":"我 会 跳 现代舞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1705, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","She is dancing in the room."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"很","english":"very","examples":["The cat is very cute.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"有趣","english":"interesting","examples":["This book is interesting.","We had an interesting trip."],"phonetic":"/ˈɪntrəstɪŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","副词修饰形容词","形容词的用法"],"explanations":["当表示某个动作行为作为主语时，需要将动词变为动名词形式（即动词后加-ing），本句中“跳舞”作为主语，所以用 dancing 来充当句子主语，此时谓语动词要用单数形式，所以搭配 is。","副词 very 用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中 very 修饰 interesting，用来强调有趣的程度。","interesting 是形容词，用来描述事物具有有趣的属性，通常用来修饰物，在句中可以作表语，本句中放在系动词 is 之后作表语，说明“跳舞”这件事的属性。"]},"sentenceWithHints":"跳舞 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1706, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","She is dancing in the room."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"plural":"","chinese":"很","english":"very","examples":["The cat is very cute.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"有","english":"be","examples":["It is important to study hard.","They are my good friends."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"意义","english":"meaningful","examples":["Reading is meaningful for us.","This is a meaningful gift."],"phonetic":"/ˈmiːnɪŋfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","副词修饰形容词","系动词+形容词的主系表结构"],"explanations":["当表示某个动作作为主语时，需要把动词变成动名词形式（即动词后加-ing），本句中“跳舞”作为主语，所以用 dancing，动名词作主语时，谓语动词用单数形式，因此系动词用 is。","副词 very 用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中 very 修饰形容词 meaningful，用来强调“有意义”的程度。","主系表结构是英语中常见的句子结构，由主语+系动词+表语构成，表语通常用形容词来表示主语的特征或状态。本句中 dancing 是主语，is 是系动词，very meaningful 是表语，用来描述“跳舞”这个行为的属性。"]},"sentenceWithHints":"跳舞 很 有 意义"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1707, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"继续","english":"continue","examples":["He continues to study hard.","We will continue our work."],"phonetic":"/kənˈtɪnjuː/","pastTense":"continued","thirdPerson":"continues","partOfSpeech":"动词","pastParticiple":"continued","presentParticiple":"continuing"},{"chinese":"跳舞","english":"dance","examples":["She dances well.","I like dancing."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"}],"examPoints":{"points":["一般将来时的表达","continue的用法"],"explanations":["一般将来时表示将要发生的动作或存在的状态，小学阶段常用“will + 动词原形”的结构来表达，本句中“will continue”就体现了这个结构，用来表达“将会继续”的将来动作。","continue作为动词，常见用法有“continue doing sth.”和“continue to do sth.”，前者表示继续做正在做的同一件事，后者表示继续做另一件事，本句中“continue dancing”使用了“continue doing sth.”的结构，符合语境。"]},"sentenceWithHints":"我 会 继续 跳舞"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1708, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","She is dancing in the room."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"是","english":"is","examples":["He is a student.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My bag is blue.","This is my dog."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"hobbies","chinese":"爱好","english":"hobby","examples":["Reading is my hobby.","She has many hobbies."],"phonetic":"/ˈhɑːbi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","可数名词的单复数"],"explanations":["当表示某个动作作为主语时，需要把动词变成动名词形式（即动词后加-ing），本句中“跳舞”作为主语，所以用dancing，动名词作主语时，谓语动词要用单数形式。","系动词be有am、is、are三种形式，am用于主语I，is用于第三人称单数主语，are用于复数主语和you。本句主语是动名词dancing，属于第三人称单数概念，所以用is。","hobby是可数名词，以辅音字母+y结尾，变复数时要把y变i再加-es，即hobbies；表示单个爱好时用单数形式hobby，本句中表示“我的一个爱好”，所以用单数hobby。"]},"sentenceWithHints":"跳舞 是 我的 爱好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1709, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","She is dancing in the room."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"是","english":"is","examples":["She is happy.","Dancing is my hobby."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my pencil."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"friends","chinese":"朋友","english":"friend","examples":["Lily is my best friend.","We are good friends."],"phonetic":"/frend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","形容词性物主代词的使用"],"explanations":["动词的ing形式（动名词）可以在句子中充当主语，表示某个行为或活动。本句中用“Dancing”作主语，将“跳舞”这个动作当作一个整体事物来描述，符合英语中用动名词指代抽象活动的表达习惯。","系动词be的形式要根据主语的单复数来变化，本句主语“Dancing”是单数概念的动名词，所以搭配系动词is。","形容词性物主代词my用来修饰名词friend，表明所属关系，意为“我的”，这类物主代词后面必须接名词，不能单独使用。"]},"sentenceWithHints":"跳舞 是 我的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1711, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","Dancing is my favorite hobby."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"让","english":"satisfy","examples":["The result satisfies me.","Nothing can satisfy his greed."],"phonetic":"/ˈsætɪsfaɪ/","pastTense":"satisfied","thirdPerson":"satisfies","partOfSpeech":"动词","pastParticiple":"satisfied","presentParticiple":"satisfying"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please pass me the pen."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"满足","english":"satisfied","examples":["I feel satisfied with my work.","She is satisfied with the present."],"phonetic":"/ˈsætɪsfaɪd/","partOfSpeech":"形容词"}],"examPoints":{"points":["动名词作主语","动词第三人称单数形式","人称代词宾格的用法"],"explanations":["当表示某个动作作为主语时，需要将动词变为动名词形式（即动词后加-ing），本句中“跳舞”作为主语，所以用 Dancing，动名词作主语时，谓语动词要用单数形式。","当主语是第三人称单数（包括动名词、单数名词、单数代词等）时，一般现在时的谓语动词要变为第三人称单数形式，satisfy 的第三人称单数是在词尾加 -ies，即 satisfies。","人称代词分为主格和宾格，当代词在动词或介词后作宾语时，需要用宾格形式，本句中“我”是动词 satisfies 的宾语，所以用宾格 me。"]},"sentenceWithHints":"跳舞 让 我 满足"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1712, '{"words":[{"chinese":"跳舞","english":"dance","examples":["I dance every weekend.","Dancing is my hobby."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gives me a gift.","Me and my friend play together."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow fast.","I want to grow up to be a doctor."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法"],"explanations":["当动词要在句子中充当主语时，需要变成动名词形式（即动词+ing），本句中“跳舞”作为主语，所以用Dancing，动名词作主语时，谓语动词要用第三人称单数形式，因此let变成lets。","let作为使役动词，常用结构为“let + 宾语 + 动词原形”，表示“让某人做某事”，本句中let后面接宾语me，再接动词原形grow，符合这个结构。"]},"sentenceWithHints":"跳舞 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1713, '{"words":[{"plural":"","chinese":"跳舞","english":"dance","examples":["I dance every weekend.","She is dancing in the room."],"phonetic":"/dæns/","pastTense":"danced","thirdPerson":"dances","partOfSpeech":"动词","pastParticiple":"danced","presentParticiple":"dancing"},{"plural":"","chinese":"是","english":"is","examples":["He is my brother.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My bag is blue.","This is my favorite toy."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"talents","chinese":"天赋","english":"talent","examples":["She has a talent for singing.","He showed his talents in the competition."],"phonetic":"/ˈtælənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","形容词性物主代词的用法","系动词be的主谓一致"],"explanations":["当表示某个动作作为主语时，需要把动词变成动名词形式（即动词+ing），本句中“跳舞”作为主语，所以用dancing，这是小学六年级动名词的核心考点之一。","“我的”是形容词性物主代词，对应的英文是my，它后面必须接名词，用来表示所属关系，本句中my修饰talent，说明天赋是“我”的。","本句的主语是动名词dancing，动名词作主语时视为第三人称单数，所以系动词要用is，这是主谓一致的基础考点，小学六年级需要掌握主语为单数时be动词用is的规则。"]},"sentenceWithHints":"跳舞 是 我的 天赋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1714, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"喜欢","english":"like","examples":["I like cats.","She likes playing the piano."],"phonetic":"/laɪk/","pastTense":"liked","thirdPerson":"likes","partOfSpeech":"动词","pastParticiple":"liked","presentParticiple":"liking"},{"plural":"","chinese":"编程","english":"programming","examples":["Programming is interesting.","He is learning programming."],"phonetic":"/ˈproʊɡræmɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动词like的用法","动名词作宾语"],"explanations":["like作为动词，常见用法为like doing sth.，表示长期的、习惯性的喜好，主语为第一人称I时，使用动词原形like；当主语为第三人称单数时，动词要变为likes。","programming在这里是动名词形式，在句中作like的宾语，动名词由动词原形加-ing构成，此处programming也可作为名词表示“编程”这一行为或技能，符合like后接名词/动名词表示喜好的用法。"]},"sentenceWithHints":"我 喜欢 编程"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1715, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is interesting.","I like programming."],"phonetic":"/ˈproʊɡræmɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me sad.","She made a cake yesterday."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"思考","english":"think","examples":["I think you are right.","She is thinking about the problem."],"phonetic":"/θɪŋk/","pastTense":"thought","thirdPerson":"thinks","partOfSpeech":"动词","pastParticiple":"thought","presentParticiple":"thinking"}],"examPoints":{"points":["动名词作主语","使役动词make的用法"],"explanations":["动词原形不能直接作主语，需要变为动名词形式（动词后加-ing），本句中“编程”对应的program是动词，变为动名词programming作句子主语，此时主语视为第三人称单数，谓语动词要用第三人称单数形式。","make作为使役动词，常用结构为“make + 宾语 + 动词原形”，表示“让某人做某事”，本句中“makes me think”就是遵循这个结构，me是宾语，think用动词原形作宾语补足语。"]},"sentenceWithHints":"编程 让 我 思考"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1716, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is interesting.","I like programming."],"phonetic":"/ˈproʊɡræmɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["She lets me use her pen.","My mom lets me watch TV after homework."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gives me a gift.","My teacher helps me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"创造","english":"create","examples":["We can create a nice picture.","She creates a story for her sister."],"phonetic":"/kriˈeɪt/","pastTense":"created","thirdPerson":"creates","partOfSpeech":"动词","pastParticiple":"created","presentParticiple":"creating"}],"examPoints":{"points":["动名词作主语","使役动词let的用法"],"explanations":["动词作主语时，需要变成动名词形式（即动词加-ing），本句中“编程”对应的program是动词，作主语时变为programming，此时主语为单数，所以谓语动词要用第三人称单数形式lets。","let是使役动词，常用结构为“let + 宾语 + 动词原形”，表示“让某人做某事”，本句中let后面接宾语me，再接动词原形create，符合这个固定搭配。"]},"sentenceWithHints":"编程 让 我 创造"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1717, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"写","english":"write","examples":["I write a letter every week.","She is writing a story."],"phonetic":"/raɪt/","pastTense":"wrote","thirdPerson":"writes","partOfSpeech":"动词","pastParticiple":"written","presentParticiple":"writing"},{"plural":"","chinese":"很多","english":"much","examples":["There is much water in the bottle.","I don''t have much time."],"phonetic":"/mʌtʃ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"codes","chinese":"代码","english":"code","examples":["He can write computer code.","These codes are very complex."],"phonetic":"/koʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","不可数名词的修饰词"],"explanations":["情态动词can后接动词原形，用来表达具备某种能力，本句中表示“具备写代码的能力”，其过去式为could，没有第三人称单数和现在分词的变形，也不能单独作谓语，必须和后面的实义动词原形一起构成谓语。","code在这里作为不可数名词，表示“代码”这一抽象概念，much用来修饰不可数名词，表示“很多”；如果是可数名词复数，则要用many来修饰，小学阶段需要区分much和many的用法场景。"]},"sentenceWithHints":"我 会 写 很多 代码"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1718, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can speak English well."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"写","english":"write","examples":["I write a diary every day.","She wrote a letter to her friend."],"phonetic":"/raɪt/","pastTense":"wrote","thirdPerson":"writes","partOfSpeech":"动词","pastParticiple":"written","presentParticiple":"writing"},{"plural":"","chinese":"Python","english":"Python","examples":["I am learning Python.","Python is a popular programming language."],"phonetic":"/ˈpaɪθɑːn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","实义动词的原形使用","专有名词的写法"],"explanations":["情态动词can表示具备某种能力，后面必须接动词原形，没有人称和数的变化，过去式为could。本句中用can表达“具备写Python的能力”。","在情态动词can之后，实义动词要使用原形，本句中write用原形符合这一规则。","Python是表示编程语言的专有名词，首字母必须大写，在句子中不需要添加冠词进行修饰。"]},"sentenceWithHints":"我 会 写 Python"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1719, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"can","examples":["I can swim.","She can play the piano."],"phonetic":"/kæn/","pastTense":"could","thirdPerson":"can","partOfSpeech":"动词","pastParticiple":"could","presentParticiple":""},{"chinese":"写","english":"write","examples":["I write a letter every week.","She is writing a story now."],"phonetic":"/raɪt/","pastTense":"wrote","thirdPerson":"writes","partOfSpeech":"动词","pastParticiple":"written","presentParticiple":"writing"},{"plural":"","chinese":"JavaScript","english":"JavaScript","examples":["I am learning JavaScript.","JavaScript is a programming language."],"phonetic":"/ˈdʒɑːvəˌskrɪpt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词can的用法","实义动词的原形使用","专有名词的拼写"],"explanations":["情态动词can表示“能够、会”，后接动词原形，用来表达具备某种能力。它没有人称和数的变化，过去式为could，可用于过去的能力表达。本句中用can表示“我具备写JavaScript的能力”。","情态动词后面必须接实义动词的原形，本句中can后面的write用原形，符合语法规则。","JavaScript是计算机编程语言的专有名词，属于特定称谓，首字母需要大写，拼写固定，在英语中直接使用原词作为专有名词。"]},"sentenceWithHints":"我 会 写 JavaScript"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1720, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is a useful skill.","I enjoy programming in my free time."],"phonetic":"/ˈproʊɡræmɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["The book is very interesting.","She runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有趣","english":"interesting","examples":["This is an interesting story.","We had an interesting talk."],"phonetic":"/ˈɪntrəstɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","副词修饰形容词的用法","系表结构"],"explanations":["当表示“做某事”这个行为作为主语时，可以用动词的动名词形式（即动词+ing），本句中“编程”是一个行为，所以用 programming 作句子主语，此时主语视为单数，后面的系动词用 is。","副词 very 用来修饰形容词，放在形容词前面，用来加强形容词的语气，本句中 very 修饰 interesting，强调“有趣”的程度。","本句是典型的系表结构，由系动词 is 连接主语 programming 和表语 interesting，用来描述主语的性质或状态，这是英语中描述事物特征的常用结构。"]},"sentenceWithHints":"编程 很 有趣"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1721, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is a useful skill.","I enjoy programming in my free time."],"phonetic":"/ˈproʊɡræmɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very happy.","He runs very fast."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"有","english":"be","examples":["I am a student.","They are playing games."],"phonetic":"/biː/","pastTense":"was/were","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"意义","english":"meaningful","examples":["This is a meaningful gift.","We had a meaningful conversation."],"phonetic":"/ˈmiːnɪŋfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","副词修饰形容词","主系表句型"],"explanations":["当表示“做某事”的动作作为句子主语时，需要把动词变成动名词形式（动词+ing），本句中“编程”对应的program要变为programming作主语，谓语动词用单数形式is。","副词very用来修饰形容词，放在形容词之前，用来加强形容词的语气，本句中very修饰meaningful，强调“意义”的程度。","本句是典型的主系表句型，主语是programming（动名词），系动词是is，表语是形容词meaningful，用来描述主语的性质或状态，小学阶段需要掌握这种基础的主系表结构来表达事物的特征。"]},"sentenceWithHints":"编程 很 有 意义"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1722, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will go to park tomorrow.","She will help you."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"继续","english":"continue","examples":["He will continue his work.","We continue learning English every day."],"phonetic":"/kənˈtɪnjuː/","pastTense":"continued","thirdPerson":"continues","partOfSpeech":"动词","pastParticiple":"continued","presentParticiple":"continuing"},{"plural":"","chinese":"编程","english":"programming","examples":["I like programming.","Programming is interesting."],"phonetic":"/ˈproʊɡræmɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的表达","动词continue的用法"],"explanations":["一般将来时可以用“will + 动词原形”的结构来表示将来要发生的动作或存在的状态，本句中“会继续”表达将来的动作，所以用“will continue”的结构。","动词continue后可以接动名词（即动词的-ing形式）作宾语，表示“继续做某事”，本句中“continue programming”就是“继续编程”的正确表达，符合“continue doing sth.”的用法。"]},"sentenceWithHints":"我 会 继续 编程"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1723, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is an interesting skill.","I enjoy programming in my free time."],"phonetic":"/ˈproʊɡræmɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my favorite song."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"hobbies","chinese":"爱好","english":"hobby","examples":["Reading is my hobby.","She has many hobbies like dancing and singing."],"phonetic":"/ˈhɑːbi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","系动词be的用法","可数名词的单复数"],"explanations":["当表示某项活动作主语时，可使用动词的动名词形式（即动词+ing），本句中programming是program的动名词形式，在句中作主语，表示“编程”这项活动。","系动词be有am、is、are三种形式，当主语是第三人称单数（包括单数名词、动名词等）时，be动词用is，本句主语programming是单数概念，所以用is。","hobby是可数名词，单数形式表示一个爱好，复数形式需要把y变i加es，即hobbies，用于表示多个爱好。本句中表示单个爱好，所以用单数形式hobby。"]},"sentenceWithHints":"编程 是 我的 爱好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1724, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is interesting.","I like programming."],"phonetic":"/ˈproʊɡræmɪŋ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a student.","The cat is cute."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My pen is blue.","This is my dog."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"friends","chinese":"朋友","english":"friend","examples":["He is my best friend.","We are good friends."],"phonetic":"/frend/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","系动词be的用法","形容词性物主代词"],"explanations":["动词program加上-ing后变成动名词programming，此时它具备名词的属性，可以在句子中充当主语。本句中programming作为主语，表示“编程”这个行为，属于动名词的常见用法。","系动词be有am、is、are三种形式，当主语是第三人称单数（包括可数名词单数、不可数名词、动名词等）时，be动词用is。本句主语programming是第三人称单数，所以使用is。","my是形容词性物主代词，用来修饰名词，表明名词的所属关系，只能放在名词前作定语，不能单独使用。本句中my修饰friend，说明friend是“我的”。"]},"sentenceWithHints":"编程 是 我的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1725, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is my hobby.","I enjoy programming in my free time."],"phonetic":"/ˈproʊɡræmɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"让","english":"make","examples":["She makes delicious cakes.","The news makes me sad."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","My teacher helps me with my homework."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"快乐","english":"happy","examples":["I feel happy every day.","The happy children are playing in the park."],"phonetic":"/ˈhæpi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","使役动词make的用法","形容词作宾语补足语"],"explanations":["动词的ing形式即动名词可以充当句子主语，此时谓语动词要用第三人称单数形式。本句中programming是program的动名词形式，作主语，所以谓语动词make用第三人称单数形式makes。","make作为使役动词，常见用法为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes me happy”就是“让我处于快乐的状态”。","形容词可以在使役动词后作宾语补足语，补充说明宾语的状态。本句中happy补充说明宾语me的状态，表明“我”的感受是快乐的。"]},"sentenceWithHints":"编程 让 我 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1726, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is my hobby.","I enjoy programming in my free time."],"phonetic":"/ˈproʊɡræmɪŋ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"让","english":"satisfy","examples":["The good news satisfied everyone.","She works hard to satisfy her customers."],"phonetic":"/ˈsætɪsfaɪ/","pastTense":"satisfied","thirdPerson":"satisfies","partOfSpeech":"动词","pastParticiple":"satisfied","presentParticiple":"satisfying"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","My mother told me a story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"满足","english":"satisfied","examples":["I feel satisfied with my exam results.","He is satisfied with his new bike."],"phonetic":"/ˈsætɪsfaɪd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["动名词作主语","动词第三人称单数变化","人称代词宾格的用法"],"explanations":["当动词要在句子中充当主语时，需要将其变为动名词形式（动词后加-ing），本句中“编程”对应的programming是动名词，在句中作主语。","当句子主语是第三人称单数（本句中programming属于第三人称单数主语）时，一般现在时的谓语动词要变为第三人称单数形式，satisfy的第三人称单数是satisfies，规则为以辅音字母+y结尾的动词，变y为i再加-es。","人称代词分为主格和宾格，在句子中作宾语时要用宾格形式，本句中“我”是动词satisfies的宾语，所以使用宾格me。"]},"sentenceWithHints":"编程 让 我 满足"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1727, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is interesting.","I like programming."],"phonetic":"/ˈproʊɡræmɪŋ/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","She let her dog run in the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"成长","english":"grow","examples":["Children grow quickly.","She has grown into a nice young lady."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["动名词作主语","使役动词let的用法","动词grow的不规则变化"],"explanations":["动词原形不能直接作主语，需要变为动名词形式（动词+ing），本句中\"编程\"对应programming，作为句子主语，谓语动词用第三人称单数形式，所以let变为lets。","let作为使役动词，常用结构为let sb. do sth.，表示\"让某人做某事\"，后面接不带to的动词不定式，本句中lets me grow就符合这个结构。","grow是不规则动词，它的过去式为grew，过去分词为grown，第三人称单数为grows，现在分词为growing，需要特殊记忆，不能直接加ed或s。"]},"sentenceWithHints":"编程 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1728, '{"words":[{"plural":"","chinese":"编程","english":"programming","examples":["Programming is a useful skill.","I enjoy programming in my free time."],"phonetic":"/ˈproʊɡræmɪŋ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My bag is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"talents","chinese":"天赋","english":"talent","examples":["She has a talent for singing.","Many talents are on show at the competition."],"phonetic":"/ˈtælənt/","partOfSpeech":"名词"}],"examPoints":{"points":["动名词作主语","物主代词的使用","系动词be的主谓一致"],"explanations":["当表示“做某事”这个行为作为主语时，可以使用动词的动名词形式（即动词+ing），本句中“编程”是一个行为，所以用programming作主语，这是动名词的常见用法之一。","物主代词my用于表示所属关系，指代“我的”，后面通常接名词，本句中my修饰talent，明确天赋的所属者。","系动词be的形式要和主语保持一致，本句主语programming是单数概念的动名词，所以搭配系动词is，这是主谓一致的基础规则。"]},"sentenceWithHints":"编程 是 我的 天赋"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1729, '{"words":[{"chinese":"我","english":"I","examples":["I am a student.","I like reading."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"爱","english":"love","examples":["I love my family.","She loves playing the piano."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our motherland.","He is proud of his motherland."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"}],"examPoints":{"points":["人称代词主格用法","一般现在时动词形式","名词的指代用法"],"explanations":["人称代词主格I在句中作主语，用于指代说话人自己，一般现在时中主语为I时，谓语动词用原形。","一般现在时中，当主语是第一人称单数I时，谓语动词使用原形，本句中love用原形符合该规则；当主语是第三人称单数时，谓语动词要变为第三人称单数形式loves。","motherland是可数名词，指代自己的祖国时通常用单数形式，前面常搭配形容词性物主代词my/our等表示所属关系，本句中用my来表明是“我的”祖国。"]},"sentenceWithHints":"我 爱 祖国"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1730, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our great motherland.","He left his motherland to study abroad."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My pen is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"homes","chinese":"家","english":"home","examples":["I want to go home.","They have a beautiful home in the countryside."],"phonetic":"/hoʊm/","partOfSpeech":"名词"}],"examPoints":{"points":["形容词性物主代词的使用","系动词be的主谓一致","表物抽象名词的用法"],"explanations":["形容词性物主代词my用来修饰名词，放在名词前表示所属关系，本句中my分别修饰motherland和home，体现“我的”所属。","系动词be的形式要和主语保持主谓一致，本句主语motherland是第三人称单数，所以对应的be动词用is。","motherland和home在本句中都属于表物的名词，其中motherland是抽象意义的家国概念，home可表示具象的住所也可表示抽象的家的概念，这类名词在初中阶段需要掌握其具体和抽象含义的不同用法。"]},"sentenceWithHints":"祖国 是 我的 家"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1731, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our motherland deeply.","She dedicated her life to her motherland."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"给","english":"give","examples":["My parents give me a gift every year.","Please give this book to your sister."],"phonetic":"/ɡɪv/","pastTense":"gave","thirdPerson":"gives","partOfSpeech":"动词","pastParticiple":"given","presentParticiple":"giving"},{"chinese":"我","english":"me","examples":["He told me a story.","My friend gave me a pen."],"phonetic":"/miː/","partOfSpeech":"代词"},{"plural":"","chinese":"温暖","english":"warmth","examples":["The fire filled the room with warmth.","I felt the warmth of her hug."],"phonetic":"/wɔːrθ/","partOfSpeech":"名词"}],"examPoints":{"points":["动词第三人称单数形式","人称代词宾格的用法","形容词转抽象名词的用法"],"explanations":["当句子主语是第三人称单数（本句中motherland为第三人称单数主语），一般现在时的谓语动词需要使用第三人称单数形式。give的第三人称单数形式是在词尾加-s，即gives。","人称代词在句子中作动词的宾语时，需要使用宾格形式。本句中“我”是动词give的宾语，所以使用宾格me，而非主格I。","warm是形容词，意为“温暖的”，通过在词尾加-th可以转换为抽象名词warmth，表示“温暖”，用来指代抽象的感受，在本句中作give的宾语。"]},"sentenceWithHints":"祖国 给 我 温暖"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1732, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["I love my motherland deeply.","We should devote ourselves to our motherland."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"给","english":"give","examples":["My parents give me a lot of support.","She gives away her old clothes every year."],"phonetic":"/ɡɪv/","pastTense":"gave","thirdPerson":"gives","partOfSpeech":"动词","pastParticiple":"given","presentParticiple":"giving"},{"chinese":"我","english":"me","examples":["Please pass me the pen.","My teacher gave me a gift."],"phonetic":"/miː/","partOfSpeech":"代词"},{"plural":"strengths","chinese":"力量","english":"strength","examples":["Sports give me the strength to keep going.","One of her strengths is her patience."],"phonetic":"/streŋθ/","partOfSpeech":"名词"}],"examPoints":{"points":["动词的第三人称单数变化","人称代词的宾格用法","不可数名词与可数名词的区分"],"explanations":["当句子主语是第三人称单数（本句中motherland属于第三人称单数主语），一般现在时里的实义动词需要使用第三人称单数形式。give的第三人称单数形式是gives，规则为以不发音的e结尾的动词，直接在词尾加-s。","人称代词分为主格和宾格，在句子中作宾语时需要使用宾格形式。本句中“我”是动词give的宾语，所以使用宾格me，而不是主格I。","strength表示“力量、力气”时多作不可数名词，表示“优点、长处”时为可数名词，本句中取“力量”的含义，属于不可数名词范畴，使用原形即可；当表示多个具体的长处时，可使用复数形式strengths。"]},"sentenceWithHints":"祖国 给 我 力量"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1733, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our motherland.","He returned to his motherland after many years."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me with this."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"骄傲","english":"proud","examples":["I am proud of my achievements.","She felt proud of her son."],"phonetic":"/praʊd/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","形容词作宾语补足语","人称代词宾格"],"explanations":["make作为使役动词，常见结构为make + 宾语 + 宾语补足语，表示“使某人/某物处于某种状态”。本句中主语“祖国”是第三人称单数，一般现在时中谓语动词make要变为第三人称单数形式makes。","在make的这个结构中，宾语补足语可以由形容词来充当，本句中proud作为形容词补充说明宾语me的状态，表达“让我处于骄傲的状态”。","人称代词分为主格和宾格，在句子中作宾语时要用宾格形式。本句中“我”是动词make的宾语，所以使用宾格me，而不是主格I。"]},"sentenceWithHints":"祖国 让 我 骄傲"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1734, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"of","examples":["I am fond of cats.","This is a photo of my family."],"phonetic":"/ʌv/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We should love our motherland.","He returned to his motherland after years abroad."],"phonetic":"/ˈmʌðərlænd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"自豪","english":"proud","examples":["She is proud of her achievements.","We are proud to be part of this team."],"phonetic":"/praʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["固定搭配 be proud of 的用法","物主代词的使用"],"explanations":["be proud of 是初中阶段重点掌握的形容词固定搭配，意为“为……感到自豪”，结构为“be动词 + proud + of + 名词/代词/动名词”，本句中主语是I，对应的be动词用am，接介词of引出自豪的对象。","物主代词my是形容词性物主代词，用来修饰名词motherland，表明所属关系，意为“我的”，形容词性物主代词不能单独使用，必须后跟名词，在句中作定语。"]},"sentenceWithHints":"我 为 祖国 自豪"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1735, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am from China."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"感恩","english":"be grateful to","examples":["I am grateful to my parents for their support.","We are grateful to the volunteers for their help."],"phonetic":"/biː ˈɡreɪtfəl tuː/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词短语","pastParticiple":"","presentParticiple":""},{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We should love our motherland.","He returned to his motherland after many years."],"phonetic":"/ˈmʌðərlænd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["感恩的英文表达","物主代词的使用","be动词的搭配"],"explanations":["“感恩”在英语中常用“be grateful to”这一形容词短语来表达，后接感谢的对象，不能直接逐字翻译为“thank”的单一动词形式，这是初中阶段需要掌握的固定情感表达短语。","句中“祖国”是“我的”祖国，需要使用形容词性物主代词“my”来修饰名词“motherland”，形容词性物主代词用于名词前表示所属关系，是初二代词知识点的重点内容。","“grateful”是形容词，需要和be动词搭配构成系表结构，主语是第一人称“I”，所以be动词用“am”，这是系表结构的基础用法，也是初二语法的核心考点之一。"]},"sentenceWithHints":"我 感恩 祖国"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1736, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our motherland.","Her motherland is in Asia."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"伟大","english":"great","examples":["China is a great country.","He made a great contribution."],"phonetic":"/ɡreɪt/","partOfSpeech":"形容词"}],"examPoints":{"points":["主系表结构","副词修饰形容词","名词的指代用法"],"explanations":["本句是典型的主系表结构，主语是“祖国（motherland）”，系动词用is（主语为单数可数名词），表语是由副词very修饰的形容词great，用来描述主语的特征。","副词very用来修饰形容词great，加强形容词的语气，说明程度，这类副词通常放在被修饰的形容词之前，类似用法还有very tall、very happy等。","motherland属于专属指代类名词，指代自己的国家，在表达“我的祖国”时，前面要搭配形容词性物主代词my，体现所属关系，类似的词还有fatherland、homeland。"]},"sentenceWithHints":"祖国 很 伟大"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1737, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["I love my great motherland.","We should devote ourselves to our motherland."],"phonetic":"/ˈmʌðərlænd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"很","english":"very","examples":["She is very kind.","The movie is very interesting."],"phonetic":"/ˈveri/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"美丽","english":"beautiful","examples":["The flower is beautiful.","She has a beautiful voice."],"phonetic":"/ˈbjuːtɪfəl/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"是","english":"is","examples":["He is a doctor.","The sky is blue."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"}],"examPoints":{"points":["系动词be的用法","副词修饰形容词的规则","名词的指代与使用"],"explanations":["be动词有am、is、are三种现在时形式，主语为第三人称单数（本句中motherland是单数名词，属于第三人称单数）时，使用is。","副词very用于修饰形容词，放在形容词之前，用来加强形容词的语气，说明形容词所描述的程度，本句中very用来强调beautiful的程度。","motherland作为表示国家的专属名词，在指代自己的祖国时，前面常加形容词性物主代词my/our，属于可数名词，复数形式为motherlands，初中阶段需要掌握这类表家国相关的名词拼写与用法。"]},"sentenceWithHints":"祖国 很 美丽"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1738, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our motherland.","She left her motherland to study abroad."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["The book is very interesting.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"强大","english":"powerful","examples":["China is a powerful country.","He has a powerful voice."],"phonetic":"/ˈpaʊərfl/","partOfSpeech":"形容词"}],"examPoints":{"points":["主系表结构的用法","副词修饰形容词的规则"],"explanations":["本句是典型的主系表结构，主语是“祖国（motherland）”，系动词用is（主语为单数可数名词，一般现在时中搭配系动词is），表语是形容词“强大（powerful）”，用来描述主语的特征，这是初中阶段需要掌握的基础句子结构。","副词“很（very）”属于程度副词，在英语中程度副词用来修饰形容词，放在形容词之前，用来加强形容词所表达的程度，本句中very用来修饰powerful，体现“强大”的程度，这是副词的常见用法之一，也是初中二年级需要掌握的副词用法要点。"]},"sentenceWithHints":"祖国 很 强大"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1739, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am going to school."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will come tomorrow."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my sister.","She works hard for her dream."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our motherland.","He is proud of his motherland."],"phonetic":"/ˈmʌðərlænd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"努力","english":"work hard","examples":["She works hard to pass the exam.","They worked hard on the project."],"phonetic":"/wɜːrk hɑːrd/","pastTense":"worked hard","thirdPerson":"works hard","partOfSpeech":"动词","pastParticiple":"worked hard","presentParticiple":"working hard"}],"examPoints":{"points":["一般将来时的用法","介词for的用法","副词hard修饰动词的位置"],"explanations":["一般将来时用来表示将来要发生的动作或存在的状态，常用结构为“will + 动词原形”，本句中“会”表达将来的意愿，所以用will加动词原形work来体现。","介词for在这里用来表示动作的对象或目的，意为“为了”，后接名词或代词，本句中用来表明努力的对象是祖国。","hard作为副词表示“努力地”，用来修饰动词时，通常放在动词之后，本句中放在work之后，构成work hard的搭配，表达“努力工作/奋斗”的含义。"]},"sentenceWithHints":"我 会 为 祖国 努力"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1740, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will come back soon."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"为","english":"for","examples":["I bought a gift for my sister.","We should fight for justice."],"phonetic":"/fɔːr/","pastTense":"","thirdPerson":"","partOfSpeech":"介词","pastParticiple":"","presentParticiple":""},{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We should love our motherland.","He is proud of his motherland."],"phonetic":"/ˈmʌðərlænd/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"奋斗","english":"strive","examples":["We must strive for our goals.","She strives to be a better person every day."],"phonetic":"/straɪv/","pastTense":"strove","thirdPerson":"strives","partOfSpeech":"动词","pastParticiple":"striven","presentParticiple":"striving"}],"examPoints":{"points":["一般将来时的用法","介词for的用法","不及物动词strive的搭配"],"explanations":["一般将来时表示将来某一时刻的动作或状态，常借助助动词will+动词原形构成，本句中“会”表达将来的意愿，所以用will+strive的结构来体现。","介词for在这里可表示“为了”，用来引出动作的对象或目的，本句中“为祖国”就是用for my motherland来体现动作奋斗的对象。","strive是不及物动词，后面不能直接加宾语，若要引出动作的对象或目的，需要搭配介词for，构成strive for的结构，意思是“为……奋斗/努力”。"]},"sentenceWithHints":"我 会 为 祖国 奋斗"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1741, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I will go to school tomorrow."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"会","english":"will","examples":["I will help you.","She will arrive at 5 o''clock."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"为","english":"to","examples":["I give a gift to my sister.","He contributes to the team''s success."],"phonetic":"/tuː/","partOfSpeech":"介词"},{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our motherland.","He returned to his motherland."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"贡献","english":"contribute","examples":["Everyone should contribute to society.","She contributed a lot to the project."],"phonetic":"/kənˈtrɪbjuːt/","pastTense":"contributed","thirdPerson":"contributes","partOfSpeech":"动词","pastParticiple":"contributed","presentParticiple":"contributing"}],"examPoints":{"points":["一般将来时的表达","动词短语contribute to的用法"],"explanations":["一般将来时可以用“will + 动词原形”来表达，表示将来要发生的动作或存在的状态，本句中“会”体现将来的意愿，所以用will加动词原形contribute。","contribute是不及物动词，后接宾语时需要搭配介词to，构成短语contribute to，意为“为……做贡献；有助于”，这里表示为祖国做贡献，所以使用contribute to的结构。"]},"sentenceWithHints":"我 会 为 祖国 贡献"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1742, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our great motherland.","He left his motherland to study abroad."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I like reading books.","I will go to the park tomorrow."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"plural":"","chinese":"的","english":"of","examples":["This is the cover of the book.","The color of the flower is red."],"phonetic":"/əv/","partOfSpeech":"助词"},{"plural":"supports","chinese":"依靠","english":"support","examples":["My family is my biggest support.","We need your support to finish this project."],"phonetic":"/səˈpɔːrt/","partOfSpeech":"名词"}],"examPoints":{"points":["物主代词的使用","系动词be的主谓一致","抽象名词的用法"],"explanations":["形容词性物主代词my用来修饰名词，表明所属关系，本句中my分别修饰motherland和support，对应中文里的“我的”，在初中阶段需要掌握形容词性物主代词和名词性物主代词的区分与使用。","系动词be的形式要和主语保持一致，本句主语“祖国”是单数名词，对应的英文主语motherland也是单数第三人称，因此使用is，这是初中阶段主谓一致的基础考点之一。","“依靠”在这里作为抽象名词使用，英文对应support，抽象名词表示抽象概念，一般为不可数名词，但support表示“支撑物、支持者”等具体含义时可作可数名词，本句中表示抽象的依靠、支持，属于不可数用法，初中阶段需要掌握常见抽象名词的词义和用法。"]},"sentenceWithHints":"祖国 是 我 的 依靠"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1743, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our great motherland.","He left his motherland to study abroad."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我","english":"I","examples":["I like reading books.","I will go to the park tomorrow."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"plural":"","chinese":"的","english":"my","examples":["This is my pen.","My favorite color is blue."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"prides","chinese":"骄傲","english":"pride","examples":["She is the pride of her family.","Taking pride in your work is important."],"phonetic":"/praɪd/","partOfSpeech":"名词"}],"examPoints":{"points":["物主代词的使用","系动词be的主谓一致","抽象名词的用法"],"explanations":["物主代词分为形容词性物主代词和名词性物主代词，本句中“我的”对应的形容词性物主代词my用来修饰名词pride，表明所属关系，形容词性物主代词后必须接名词。","系动词be的形式要和主语保持一致，本句主语motherland是第三人称单数，因此对应的be动词用is。","pride是抽象名词，通常表示“骄傲、自豪”这类抽象概念，一般情况下为不可数名词，表达“为……骄傲”可以用“take pride in”或“be proud of”的搭配，在本句中pride作为表语，体现主语的属性。"]},"sentenceWithHints":"祖国 是 我 的 骄傲"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1744, '{"words":[{"plural":"motherlands","chinese":"祖国","english":"motherland","examples":["We love our great motherland.","He left his motherland to study abroad."],"phonetic":"/ˈmʌðərlænd/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我","english":"I","examples":["I like reading books.","I will go to the park tomorrow."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"的","english":"my","examples":["This is my pen.","My favorite color is blue."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"glories","chinese":"荣耀","english":"glory","examples":["Winning the game was his greatest glory.","The ancient city is full of historical glories."],"phonetic":"/ˈɡlɔːri/","partOfSpeech":"名词"}],"examPoints":{"points":["物主代词的使用","系动词be的主谓一致","抽象名词的用法"],"explanations":["物主代词分为形容词性物主代词和名词性物主代词，本句中“我的”是形容词性物主代词，对应英文my，用来修饰后面的名词glory，表明所属关系。","系动词be的形式要和主语保持一致，本句主语motherland是第三人称单数，所以对应的be动词用is。","glory是抽象名词，通常表示“荣耀、光荣”这类抽象概念，一般为不可数名词，但表示“值得称赞的事、辉煌成就”时可作可数名词，本句中表示抽象的“荣耀”，用作不可数名词。"]},"sentenceWithHints":"祖国 是 我 的 荣耀"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1745, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I like reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱","english":"love","examples":["I love my family.","She loves playing the piano."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"peaces","chinese":"和平","english":"peace","examples":["We all hope for world peace.","The peace of the village was broken."],"phonetic":"/piːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["第一人称代词的用法","及物动词的用法","不可数名词的特殊用法"],"explanations":["第一人称代词“I”在句中作主语，永远大写，用于指代说话人自己，后面接动词原形（一般现在时）。本句中“I”作为主语，搭配动词“love”的原形。","“love”是及物动词，后面可以直接接宾语，不需要加介词，用来表达对人或事物的喜爱、热爱。本句中“love”直接接宾语“peace”，符合及物动词的用法规则。","“peace”表示“和平”这一抽象概念时是不可数名词，通常没有复数形式；只有在表示“和平时期、和约”等具体含义时才会用复数“peaces”，本句中“和平”是抽象概念，所以使用单数形式。"]},"sentenceWithHints":"我 爱 和平"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1746, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["We love peace.","Peace is important for everyone."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"很","english":"very","examples":["She is very happy.","This book is very interesting."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"chinese":"珍贵","english":"precious","examples":["Time is precious.","This is a precious gift."],"phonetic":"/ˈpreʃəs/","partOfSpeech":"形容词"}],"examPoints":{"points":["不可数名词的用法","副词修饰形容词的用法","主系表结构"],"explanations":["peace属于抽象不可数名词，一般没有复数形式的常规使用场景，在表示不同种类的和平时可使用peaces，但日常表达中多以单数形式出现，作主语时谓语动词用单数形式。","副词very用来修饰形容词，放在形容词之前，用来加强形容词所表达的程度，本句中very用来强化precious的程度，体现和平的珍贵程度。","本句是典型的主系表结构，主语是peace，系动词用is（因为主语是不可数名词，视为单数），表语是由副词very修饰的形容词precious，用来描述主语的性质。"]},"sentenceWithHints":"和平 很 珍贵"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1747, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is the most precious thing in the world.","We all hope for peace."],"phonetic":"/piːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"让","english":"make","examples":["The news makes me excited.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"","chinese":"我们","english":"us","examples":["He told us a funny story.","Please wait for us."],"phonetic":"/ʌs/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"快乐","english":"happy","examples":["I feel happy every day.","She is happy to see her old friend."],"phonetic":"/ˈhæpi/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["使役动词make的用法","主谓一致原则","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes us happy”就是该结构，意为“使我们快乐”。","本句主语“Peace”是不可数名词，作主语时视为第三人称单数，所以谓语动词make要用第三人称单数形式makes，这是主谓一致原则中不可数名词作主语的规则。","在“make + 宾语 + 宾补”的结构中，形容词可以充当宾语补足语，用来补充说明宾语的状态，本句中happy补充说明us的状态，即“我们”是“快乐”的。"]},"sentenceWithHints":"和平 让 我们 快乐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1748, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is important for everyone.","We hope for world peace."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes delicious food.","Hard work makes success."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please wait for us."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"安全","english":"safe","examples":["We are safe now.","It''s a safe place to live."],"phonetic":"/seɪf/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","主谓一致原则","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使某人/某物处于某种状态”，本句中“makes us safe”即表示“使我们处于安全的状态”。","本句主语“peace”是不可数名词，视为第三人称单数，所以谓语动词make需要使用第三人称单数形式makes，符合主谓一致中“不可数名词作主语，谓语动词用第三人称单数”的规则。","在“make + 宾语 + 宾补”的结构中，形容词可以充当宾语补足语，用来补充说明宾语的状态，本句中形容词safe补充说明宾语us的状态，这是初中阶段需要掌握的非谓语之外的宾补形式。"]},"sentenceWithHints":"和平 让 我们 安全"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1749, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is important for everyone.","We hope for world peace."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mother let me watch TV.","He lets his dog run in the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["Please tell us the story.","He gave us some gifts."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"发展","english":"develop","examples":["We need to develop new skills.","The country is developing quickly."],"phonetic":"/dɪˈveləp/","pastTense":"developed","thirdPerson":"develops","partOfSpeech":"动词","pastParticiple":"developed","presentParticiple":"developing"}],"examPoints":{"points":["使役动词let的用法","第三人称单数谓语动词变化","动词不定式的省略"],"explanations":["let作为使役动词，常见结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中let us develop就符合这个结构。","当句子主语是第三人称单数时，一般现在时的谓语动词需要变成第三人称单数形式。本句主语Peace是不可数名词，属于第三人称单数，所以动词let要变成lets。","在使役动词let、make、have以及感官动词see、hear等后面，作宾语补足语的动词不定式要省略to，本句中develop前省略了to，符合这个语法规则。"]},"sentenceWithHints":"和平 让 我们 发展"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1750, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is important for everyone.","We hope for world peace."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mother lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some help."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"进步","english":"progress","examples":["She is progressing well in her studies.","The project has progressed smoothly."],"phonetic":"/ˈprɑːɡres/","pastTense":"progressed","thirdPerson":"progresses","partOfSpeech":"动词","pastParticiple":"progressed","presentParticiple":"progressing"}],"examPoints":{"points":["使役动词let的用法","动词progress的用法","主谓一致"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中lets us progress就符合这个结构。","progress既可以作名词也可以作动词，在本句中是动词，意为“进步；进展”，作动词时美式音标为/ˈprɑːɡres/，作名词时美式音标为/ˈprɑːɡrəs/，初中阶段需要掌握它的两种词性及用法。","本句主语Peace是不可数名词，属于第三人称单数，所以谓语动词let要用第三人称单数形式lets，这是主谓一致的基本规则，即主语是第三人称单数时，一般现在时的谓语动词要使用相应的第三人称单数形式。"]},"sentenceWithHints":"和平 让 我们 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1752, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am from China."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"珍惜","english":"cherish","examples":["We should cherish every moment with our family.","She cherishes the gift from her friend."],"phonetic":"/ˈtʃerɪʃ/","pastTense":"cherished","thirdPerson":"cherishes","partOfSpeech":"动词","pastParticiple":"cherished","presentParticiple":"cherishing"},{"plural":"","chinese":"和平","english":"peace","examples":["We all hope for world peace.","The peace of the countryside is so nice."],"phonetic":"/piːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["及物动词的用法","不可数名词的使用"],"explanations":["cherish是及物动词，后面可以直接接宾语，不需要加介词，本句中直接接不可数名词peace作宾语，符合及物动词的使用规则。","peace属于抽象不可数名词，这类名词没有复数形式，不能在前面加不定冠词a/an，在句子中表示泛指的概念时直接使用原形即可。"]},"sentenceWithHints":"我 珍惜 和平"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1753, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a middle school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"维护","english":"maintain","examples":["We should maintain public order.","It''s important to maintain a healthy diet."],"phonetic":"/meɪnˈteɪn/","pastTense":"maintained","thirdPerson":"maintains","partOfSpeech":"动词","pastParticiple":"maintained","presentParticiple":"maintaining"},{"plural":"peaces","chinese":"和平","english":"peace","examples":["We all hope for world peace.","The peace in the small town is lovely."],"phonetic":"/piːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["及物动词的用法","不可数名词与可数名词的特殊情况","一般现在时的主谓一致"],"explanations":["maintain 是及物动词，后面可以直接接宾语，不需要加介词，本句中直接接宾语 peace，符合及物动词的使用规则。","peace 表示“和平”这一抽象概念时通常作为不可数名词使用；当表示“和平时期、和约”等具体概念时是可数名词，复数形式为 peaces，本句中是抽象概念，所以用单数形式。","一般现在时中，当主语是第一人称单数 I 时，谓语动词用原形，本句主语为 I，所以谓语动词 maintain 用原形，符合主谓一致规则。"]},"sentenceWithHints":"我 维护 和平"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1754, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is important for everyone.","We hope for world peace."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我们","english":"we","examples":["We love our country.","We will go to the park tomorrow."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"plural":"","chinese":"的","english":"of","examples":["This is the book of my brother.","The color of the sky is blue."],"phonetic":"/ʌv/","partOfSpeech":"助词"},{"plural":"wishes","chinese":"愿望","english":"wish","examples":["My wish is to travel around the world.","Best wishes for your birthday."],"phonetic":"/wɪʃ/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","形容词性物主代词的使用","可数名词的单复数"],"explanations":["系动词be有am、is、are三种形式，当主语是单数名词或第三人称单数代词时，使用is。本句主语“peace”是单数不可数名词，因此搭配is。","“我们的”对应的形容词性物主代词是our，用来修饰后面的名词wish，表明所属关系，形容词性物主代词不能单独使用，必须后接名词。","wish作为可数名词，单数形式表示单个愿望，复数形式是wishes，通常用来表示多个祝愿或愿望，本句中表示单个愿望，所以使用单数形式wish。"]},"sentenceWithHints":"和平 是 我们 的 愿望"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1755, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["We all love peace.","Peace is important for everyone."],"phonetic":"/piːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We will go to the park."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"的","english":"our","examples":["This is our classroom.","Our teacher is very nice."],"phonetic":"/ˈaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"goals","chinese":"目标","english":"goal","examples":["My goal is to learn English well.","He has achieved his goal."],"phonetic":"/ɡoʊl/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["系动词be的用法","形容词性物主代词的使用","不可数名词与可数名词的区分"],"explanations":["系动词be有am、is、are三种形式，当主语是第三人称单数或不可数名词时，使用is。本句主语“peace（和平）”是不可数名词，因此用is。","形容词性物主代词our用来修饰名词，表明所属关系，此处修饰“goal（目标）”，表示“我们的目标”，形容词性物主代词后必须接名词，不能单独使用。","“peace（和平）”属于抽象不可数名词，一般没有复数形式，表达多个不同领域的和平时可使用复数peaces；“goal（目标）”是可数名词，复数形式直接加s变为goals，可数名词单数表示泛指时需搭配冠词，本句中goal特指“我们的目标”，无需额外加冠词。"]},"sentenceWithHints":"和平 是 我们 的 目标"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1756, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["We hope for world peace.","Peace and love are important values."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我们的","english":"our","examples":["Our house is big.","We love our school."],"phonetic":"/ˈaʊər/","partOfSpeech":"代词"},{"plural":"responsibilities","chinese":"责任","english":"responsibility","examples":["It''s our responsibility to help others.","He takes his responsibilities seriously."],"phonetic":"/rɪˌspɑːnsəˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["系动词be的用法","形容词性物主代词的使用","不可数名词与可数名词的区分"],"explanations":["系动词be有am、is、are三种形式，当主语是第三人称单数或不可数名词时，使用is。本句中主语“peace”是不可数名词，因此搭配is。","“我们的”对应形容词性物主代词our，形容词性物主代词后必须接名词，用来表示所属关系，本句中our后接名词responsibility，表明责任的归属。","“和平（peace）”是不可数名词，没有复数形式的常规使用场景；“责任（responsibility）”是可数名词，复数形式为responsibilities，在表示多项责任时使用。初中阶段需要掌握常见可数与不可数名词的区分及用法。"]},"sentenceWithHints":"和平 是 我们的 责任"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1757, '{"words":[{"plural":"","chinese":"和平","english":"peace","examples":["We all long for peace.","Peace is the most precious thing in the world."],"phonetic":"/piːs/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我们的","english":"our","examples":["Our classroom is clean.","This is our new house."],"phonetic":"/ˈaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"missions","chinese":"使命","english":"mission","examples":["His mission is to help the poor.","The team completed their mission successfully."],"phonetic":"/ˈmɪʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["系动词be的用法","形容词性物主代词的使用","不可数名词与可数名词的辨析"],"explanations":["系动词be有am、is、are三种形式，当主语是第三人称单数或不可数名词时，一般现在时中要用is。本句主语peace是不可数名词，因此搭配is。","形容词性物主代词our用来修饰名词，表示所属关系，意为“我们的”，后面必须接名词，本句中它修饰mission，表明使命的归属。","peace是不可数名词，没有复数形式，不能在后面加s/es；mission是可数名词，复数形式为missions，在表示多个使命时使用。"]},"sentenceWithHints":"和平 是 我们的 使命"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1758, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is important for everyone.","We hope for world peace."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me happy.","Hard work makes success possible."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is full of wonders.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"},{"chinese":"美好","english":"beautiful","examples":["The flowers are beautiful.","She has a beautiful voice."],"phonetic":"/ˈbjuːtɪfəl/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","第三人称单数谓语动词变化","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 形容词”，表示“使……处于某种状态”，本句中“makes the world beautiful”即表达“让世界变得美好”，符合该结构。","当句子主语是第三人称单数（本句主语Peace是不可数名词，属于第三人称单数范畴）时，一般现在时的谓语动词要使用第三人称单数形式，make的第三人称单数形式是makes。","在“make + 宾语 + 宾补”的结构中，形容词可以充当宾语补足语，用来补充说明宾语的状态，本句中beautiful补充说明the world的状态，体现世界的美好属性。"]},"sentenceWithHints":"和平 让 世界 美好"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1759, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is important for everyone.","We hope for world peace."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me laugh.","Hard work makes success."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"},{"chinese":"幸福","english":"happy","examples":["I feel happy today.","She has a happy family."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","第三人称单数谓语动词变化","定冠词the的特指用法"],"explanations":["make作为使役动词，常用结构为“make + 宾语 + 形容词”，表示“使……处于某种状态”，本句中“makes the world happy”即表示“让世界处于幸福的状态”。","当句子主语是第三人称单数（本句中主语Peace是不可数名词，属于第三人称单数范畴）时，一般现在时的谓语动词要使用第三人称单数形式，make的第三人称单数形式是makes。","定冠词the用于特指独一无二的事物，“the world”特指我们生活的这个唯一的世界，属于特指用法。"]},"sentenceWithHints":"和平 让 世界 幸福"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1760, '{"words":[{"plural":"peaces","chinese":"和平","english":"peace","examples":["Peace is important for everyone.","We hope for world peace."],"phonetic":"/piːs/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me happy.","Hard work makes success."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"worlds","chinese":"世界","english":"world","examples":["The world is beautiful.","He wants to travel around the world."],"phonetic":"/wɜːrld/","partOfSpeech":"名词"},{"chinese":"和谐","english":"harmonious","examples":["We live in a harmonious community.","The harmonious music makes people relaxed."],"phonetic":"/hɑːrˈmoʊniəs/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","不可数名词与定冠词的搭配","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，表示“使……处于某种状态”。本句中主语peace是第三人称单数，所以make用第三人称单数形式makes。","“世界”对应的world在这里是特指我们生活的这个世界，前面需要加定冠词the；而peace表示抽象概念“和平”时，属于不可数名词，单独使用时不需要加冠词。","在“make + 宾语 + 宾语补足语”的结构中，宾语补足语可以由形容词担任，用来补充说明宾语的状态。本句中harmonious作为形容词，补充说明the world的状态，即“使世界处于和谐的状态”。"]},"sentenceWithHints":"和平 让 世界 和谐"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1761, '{"words":[{"plural":"environmental protections","chinese":"环保","english":"environmental protection","examples":["Environmental protection is crucial for our planet.","We should take actions for environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃn/","partOfSpeech":"名词"},{"plural":"","chinese":"很","english":"very","examples":["She is very beautiful.","He runs very fast."],"phonetic":"/ˈveri/","partOfSpeech":"副词"},{"plural":"","chinese":"重要","english":"important","examples":["It''s important to learn English well.","This is an important meeting."],"phonetic":"/ɪmˈpɔːrtnt/","partOfSpeech":"形容词"}],"examPoints":{"points":["抽象名词短语的使用","副词修饰形容词的用法","主系表句型的应用"],"explanations":["“环保”对应英文抽象名词短语environmental protection，这类抽象名词短语在句中可作主语，属于初中阶段需要掌握的话题类名词短语，常用于表达社会议题相关内容。","副词very用来修饰形容词important，用来加强形容词的语气，说明形容词所描述的程度，这是副词修饰形容词的基础用法，在初中阶段的写作和翻译中经常考查。","本句是典型的主系表句型，主语是environmental protection，系动词用is（主语是单数抽象名词，视为第三人称单数），表语是由副词very修饰的形容词important，该句型是初中阶段必须掌握的核心句型之一，用于说明主语的性质或状态。"]},"sentenceWithHints":"环保 很 重要"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1762, '{"words":[{"plural":"environmental protections","chinese":"环保","english":"environmental protection","examples":["Environmental protection is crucial for our planet.","We should take actions for environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我们","english":"we","examples":["We love our school.","We will go to the park tomorrow."],"phonetic":"/wiː/","partOfSpeech":"代词"},{"chinese":"每个","english":"every","examples":["Every student should study hard.","I read every book in the library."],"phonetic":"/ˈevri/","partOfSpeech":"形容词"},{"plural":"people","chinese":"人","english":"person","examples":["Each person has his own dream.","There is a person waiting for you."],"phonetic":"/ˈpɜːrsn/","partOfSpeech":"名词"},{"chinese":"的","english":"''s / of","examples":["This is my mother''s bag.","The color of the flower is red."],"phonetic":"/əv/","partOfSpeech":"助词"},{"plural":"responsibilities","chinese":"责任","english":"responsibility","examples":["It''s our responsibility to help others.","He takes his responsibilities seriously."],"phonetic":"/rɪˌspɑːnsəˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["名词性短语的翻译","名词所有格的用法","系动词be的主谓一致"],"explanations":["中文的“环保”是一个名词性短语，对应的英文固定表达为“environmental protection”，属于复合名词，在翻译这类中文凝练的名词性短语时，需要使用对应的英文固定搭配，不能逐字直译。","表示“某人的”所属关系时，在单数名词后加“''s”，本句中“每个人的责任”翻译为“everyone''s responsibility”，使用了所有格形式来体现所属关系；当指代无生命事物的所属时常用“of”结构，而指代有生命的人时常用“''s”所有格。","本句主语“environmental protection”是单数名词短语，所以系动词使用第三人称单数形式“is”，主谓一致要求系动词或谓语动词的形式要和主语的单复数保持匹配，单数主语搭配单数形式的系动词/谓语动词，复数主语搭配复数形式。"]},"sentenceWithHints":"环保 是 我们 每个 人 的 责任"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1764, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our country."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"应该","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"节约","english":"save","examples":["We should save water.","She saved money to buy a bike."],"phonetic":"/seɪv/","pastTense":"saved","thirdPerson":"saves","partOfSpeech":"动词","pastParticiple":"saved","presentParticiple":"saving"},{"plural":"energies","chinese":"能源","english":"energy","examples":["We need to save energy.","Solar energy is clean and renewable."],"phonetic":"/ˈenərdʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词should的用法","动词save的词义及用法","不可数名词/可数名词的用法"],"explanations":["should作为情态动词，后接动词原形，用来表示责任、义务或建议，本句中用来表达“我们有义务节约能源”的建议性语气，没有人称和数的变化。","save作为动词，常见词义有“节约；节省；拯救”，在本句中取“节约”的含义，情态动词should后接其原形，其变形遵循规则变化，过去式、过去分词加-ed，第三人称单数加-s，现在分词加-ing。","energy表示“能源”时，既可以作不可数名词表示泛指的能源，也可以作可数名词（energies）表示具体的多种能源类型，本句中泛指能源，用作不可数名词。"]},"sentenceWithHints":"我们 应该 节约 能源"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1765, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our country."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"应该","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"减少","english":"reduce","examples":["We need to reduce waste.","The company will reduce its costs."],"phonetic":"/rɪˈduːs/","pastTense":"reduced","thirdPerson":"reduces","partOfSpeech":"动词","pastParticiple":"reduced","presentParticiple":"reducing"},{"plural":"","chinese":"污染","english":"pollution","examples":["Air pollution is a serious problem.","We must fight against pollution."],"phonetic":"/pəˈluːʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词should的用法","及物动词reduce的用法","不可数名词pollution的用法"],"explanations":["should作为情态动词，后接动词原形，用来表达义务、建议或责任，本句中用来提出“减少污染”的建议，符合其表建议的用法。","reduce是及物动词，后面可以直接接宾语，本句中直接接不可数名词pollution，构成“reduce pollution”的动宾结构，表达“减少污染”的含义。","pollution是不可数名词，没有复数形式，在句中可以直接作宾语，不需要加不定冠词或变为复数形式，常用来表示“污染”这一抽象概念。"]},"sentenceWithHints":"我们 应该 减少 污染"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1766, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"们","english":"","examples":["They are my friends.","We love our country."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"应","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"该","english":"","examples":["We should finish our homework.","You should be careful."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"garbages","chinese":"垃","english":"garbage","examples":["Please take out the garbage.","We should reduce garbage."],"phonetic":"/ˈɡɑːrbɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"圾","english":"","examples":["Don''t litter garbage everywhere.","Garbage classification is important."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"chinese":"分","english":"sort","examples":["Please sort the clothes by color.","We need to sort the mail."],"phonetic":"/sɔːrt/","pastTense":"sorted","thirdPerson":"sorts","partOfSpeech":"动词","pastParticiple":"sorted","presentParticiple":"sorting"},{"plural":"","chinese":"类","english":"","examples":["We should sort garbage into different classes.","Classification helps protect the environment."],"phonetic":"","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词should的用法","动词sort的用法","环保类词汇的积累"],"explanations":["should作为情态动词，后接动词原形，用来表示责任、义务或建议，本句中用来表达“应该做垃圾分类”的义务和建议，符合初中三年级对情态动词用法的考查要求。","sort作为动词，常见含义为“分类、整理”，在本句中构成sort garbage的动宾结构，考查学生对实义动词搭配及词义的掌握，其过去式、过去分词为sorted，第三人称单数为sorts，现在分词为sorting，属于规则变化。","garbage是初中阶段需要掌握的环保类核心词汇，属于不可数名词（也可作可数名词表示不同类型的垃圾），在环保主题的英语表达中经常出现，考查学生对主题类词汇的积累和运用。"]},"sentenceWithHints":"我 们 应 该 垃 圾 分 类"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1767, '{"words":[{"plural":"","chinese":"我们","english":"we","examples":["We are students.","We love our country."],"phonetic":"/wiː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"应该","english":"should","examples":["You should study hard.","We should help others."],"phonetic":"/ʃʊd/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱护","english":"cherish","examples":["We should cherish every moment.","She cherishes her family very much."],"phonetic":"/ˈtʃerɪʃ/","pastTense":"cherished","thirdPerson":"cherishes","partOfSpeech":"动词","pastParticiple":"cherished","presentParticiple":"cherishing"},{"plural":"","chinese":"大自然","english":"nature","examples":["Nature gives us many resources.","We need to protect nature."],"phonetic":"/ˈneɪtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["情态动词should的用法","不可数名词的使用","及物动词cherish的用法"],"explanations":["情态动词should后接动词原形，用来表达义务、建议或责任，本句中用should提出爱护大自然的建议，后面接动词cherish的原形。","nature表示“大自然”时是不可数名词，前面不需要加不定冠词a/an，也没有复数形式，直接使用原形即可。","cherish是及物动词，后面可以直接接宾语，不需要加介词，本句中直接接宾语nature，表达“珍视、爱护”的含义，适合用于表达对自然、情感等事物的珍视。"]},"sentenceWithHints":"我们 应该 爱护 大自然"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1768, '{"words":[{"plural":"environmental protections","chinese":"环保","english":"environmental protection","examples":["Environmental protection is everyone''s responsibility.","We should pay attention to environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃn/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some advice."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"健康","english":"healthy","examples":["She looks very healthy.","Eating vegetables keeps you healthy."],"phonetic":"/ˈhelθi/","partOfSpeech":"形容词"}],"examPoints":{"points":["make的使役用法","名词短语的使用","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为make + 宾语 + 宾语补足语，意为“使……处于某种状态”。本句中us是宾语，healthy是宾语补足语，用来补充说明us的状态。","“环保”对应的英文是固定名词短语environmental protection，属于抽象名词短语，表达环境保护的概念，在句中作主语时，谓语动词要根据其单复数形式变化，此处短语整体作单数概念，所以谓语动词用第三人称单数形式makes。","在make的使役结构中，宾语补足语可以由形容词来充当，用来描述宾语的状态。本句中healthy作为形容词，补充说明“我们”在环保的作用下处于健康的状态，符合该结构的用法要求。"]},"sentenceWithHints":"环保 让 我们 健康"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1769, '{"words":[{"plural":"environmental protections","chinese":"环保","english":"environmental protection","examples":["Environmental protection is everyone''s responsibility.","We should pay more attention to environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃn/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me excited.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我们","english":"us","examples":["He told us a story.","Please give us some advice."],"phonetic":"/ʌs/","partOfSpeech":"代词"},{"chinese":"幸福","english":"happy","examples":["I feel happy every day.","They are happy to see each other."],"phonetic":"/ˈhæpi/","partOfSpeech":"形容词"}],"examPoints":{"points":["make的使役用法","抽象名词的使用","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，表示“使某人/某物处于某种状态”。本句中“makes us happy”就是该结构，主语为第三人称单数“environmental protection”，所以make用第三人称单数形式makes。","“环保”对应英文抽象名词短语environmental protection，这类抽象名词表示抽象概念，通常作为不可数名词使用，强调行为或概念本身，在句中可作主语、宾语等成分。","在“make + 宾语 + 宾语补足语”结构中，宾语补足语可以由形容词充当，用来补充说明宾语的状态。本句中形容词happy补充说明宾语us的状态，体现“我们”处于幸福的状态。"]},"sentenceWithHints":"环保 让 我们 幸福"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1770, '{"words":[{"plural":"","chinese":"环保","english":"environmental protection","examples":["Environmental protection is everyone''s responsibility.","We should pay more attention to environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃən/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"earths","chinese":"地球","english":"earth","examples":["The earth goes around the sun.","We need to protect the earth."],"phonetic":"/ɜːrθ/","partOfSpeech":"名词"},{"chinese":"美丽","english":"beautiful","examples":["She has a beautiful voice.","The park is beautiful in spring."],"phonetic":"/ˈbjuːtɪfəl/","partOfSpeech":"形容词"}],"examPoints":{"points":["make的使役用法","抽象名词的使用","定冠词the的特指用法"],"explanations":["make作为使役动词，常见用法为\"make + 宾语 + 形容词\"，表示\"使某人/某物处于某种状态\"，本句中\"makes the earth beautiful\"即表示\"使地球变得美丽\"，这是初中阶段重点掌握的动词固定搭配。","\"环保\"对应的\"environmental protection\"是抽象名词短语，属于不可数的抽象概念，在句中作主语时，谓语动词用第三人称单数形式，初中阶段需要掌握常见的抽象名词短语的表达和主谓一致规则。","earth表示\"地球\"这一独一无二的事物时，前面需要加定冠词the进行特指，这是定冠词的核心用法之一，初中阶段需要区分定冠词用于独一无二事物、特指事物等不同场景的使用规则。"]},"sentenceWithHints":"环保 让 地球 美丽"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1771, '{"words":[{"plural":"environmental protections","chinese":"环保","english":"environmental protection","examples":["Environmental protection is everyone''s responsibility.","We should pay more attention to environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃn/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["The news makes me happy.","She made a cake for her family."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"plural":"earths","chinese":"地球","english":"earth","examples":["The earth goes around the sun.","We need to protect the earth."],"phonetic":"/ɜːrθ/","partOfSpeech":"名词"},{"chinese":"可持续","english":"sustainable","examples":["We should pursue sustainable development.","This is a sustainable way of living."],"phonetic":"/səˈsteɪnəbl/","partOfSpeech":"形容词"}],"examPoints":{"points":["make的使役用法","环保类词汇的英文表达","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为make + 宾语 + 宾语补足语，此处宾语是the earth，宾语补足语是形容词sustainable，用来补充说明宾语的状态，表达“使地球处于可持续的状态”。","“环保”对应的英文是固定表达environmental protection，属于初中阶段需要掌握的环保主题核心词汇，在书面表达和阅读理解中较为常见。","在make的使役结构中，除了可以接动词原形作宾语补足语，还可以接形容词来补充说明宾语的性质或状态，本句中sustainable作宾语补足语，体现了这种用法，是初中阶段需要掌握的语法点。"]},"sentenceWithHints":"环保 让 地球 可持续"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1772, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am going to school."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will go to the park tomorrow.","She will help you with your homework."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"保护","english":"protect","examples":["We should protect wild animals.","Law protects people''s rights."],"phonetic":"/prəˈtekt/","pastTense":"protected","thirdPerson":"protects","partOfSpeech":"动词","pastParticiple":"protected","presentParticiple":"protecting"},{"plural":"environments","chinese":"环境","english":"environment","examples":["We need to improve the living environment.","The environment has a great influence on us."],"phonetic":"/ɪnˈvaɪrənmənt/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","定冠词the的特指用法","及物动词protect的使用"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，结构“will + 动词原形”是最常用的表达之一，本句中“会”体现将来的意愿，所以用will加protect的原形来表达。","定冠词the用于特指双方都知晓的或特定的事物，本句中“环境”特指人类共同生存的自然环境，是双方默认的特定事物，所以前面加the。","protect是及物动词，后面可以直接接宾语，不需要加介词，常见搭配为protect sth.（保护某物），本句中直接接宾语the environment符合其用法要求。"]},"sentenceWithHints":"我 会 保护 环境"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1773, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am going to the park."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you tomorrow.","She will come to the party."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"chinese":"节约","english":"save","examples":["We should save water.","He saved a lot of money last year."],"phonetic":"/seɪv/","pastTense":"saved","thirdPerson":"saves","partOfSpeech":"动词","pastParticiple":"saved","presentParticiple":"saving"},{"plural":"energies","chinese":"能源","english":"energy","examples":["We need to save energy.","Solar energy is a kind of renewable energy."],"phonetic":"/ˈenərdʒi/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","及物动词 save 的用法","不可数名词与可数名词的区分"],"explanations":["一般将来时用来表示将要发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会”表达将来的意愿，所以用“will + save”的结构来体现。","save 作为及物动词，后面可以直接接宾语，常见搭配有 save energy（节约能源）、save water（节约用水）、save money（省钱）等，在本句中接宾语 energy 构成动宾结构。","energy 表示“能源”时通常作为不可数名词使用，表达总称；当表示“精力、活力”等具体含义时可作可数名词，复数形式为 energies。本句中表示“能源”，按不可数名词使用。"]},"sentenceWithHints":"我 会 节约 能源"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1774, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will help you.","She will come back soon."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"减少","english":"reduce","examples":["We need to reduce waste.","The company reduced its costs last year."],"phonetic":"/rɪˈduːs/","pastTense":"reduced","thirdPerson":"reduces","partOfSpeech":"动词","pastParticiple":"reduced","presentParticiple":"reducing"},{"plural":"","chinese":"污染","english":"pollution","examples":["Air pollution is a serious problem.","We should fight against water pollution."],"phonetic":"/pəˈluːʃn/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","及物动词reduce的用法","不可数名词pollution的用法"],"explanations":["一般将来时用于表示将来要发生的动作或存在的状态，常见结构为“will + 动词原形”，本句中“会”体现将来的意愿，所以用“will + reduce”的结构来表达。","reduce是及物动词，后面可以直接接宾语，此处接不可数名词pollution，表示“减少污染”这一动作，在初中阶段需要掌握这类及物动词的直接带宾语的用法。","pollution是不可数名词，没有复数形式，在句子中可以直接作宾语，不需要加不定冠词或变复数，初中阶段需要区分可数名词和不可数名词的用法差异。"]},"sentenceWithHints":"我 会 减少 污染"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1775, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am going to the park."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"会","english":"will","examples":["I will help you.","She will come tomorrow."],"phonetic":"/wɪl/","pastTense":"would","thirdPerson":"will","partOfSpeech":"动词","pastParticiple":"","presentParticiple":""},{"plural":"garbages","chinese":"垃圾","english":"garbage","examples":["Please take out the garbage.","We should reduce garbage."],"phonetic":"/ˈɡɑːrbɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"分类","english":"sort","examples":["We need to sort the clothes by color.","She sorts the mail every morning."],"phonetic":"/sɔːrt/","pastTense":"sorted","thirdPerson":"sorts","partOfSpeech":"动词","pastParticiple":"sorted","presentParticiple":"sorting"}],"examPoints":{"points":["一般将来时的用法","及物动词sort的用法"],"explanations":["一般将来时用来表示将来要发生的动作或存在的状态，常见结构为“will + 动词原形”。本句中“会”表达将来的意愿或能力，因此使用“will + sort”的结构来体现将要进行垃圾分类这个动作。","sort作为及物动词，意为“分类；整理”，后面可以直接接宾语，本句中直接接宾语garbage，构成“sort garbage”的动宾结构，符合英语中及物动词的使用规则，在初中阶段需要掌握这类常用及物动词的搭配和用法。"]},"sentenceWithHints":"我 会 垃圾 分类"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1776, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I will go to the park tomorrow."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"会","english":"will","examples":["I will help you.","She will finish the task soon."],"phonetic":"/wɪl/","pastTense":"","thirdPerson":"","partOfSpeech":"助词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"爱护","english":"cherish","examples":["We should cherish our time.","She cherishes the gift from her grandma."],"phonetic":"/ˈtʃerɪʃ/","pastTense":"cherished","thirdPerson":"cherishes","partOfSpeech":"动词","pastParticiple":"cherished","presentParticiple":"cherishing"},{"plural":"","chinese":"大自然","english":"nature","examples":["We need to protect nature.","Nature gives us many resources."],"phonetic":"/ˈneɪtʃər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["一般将来时的用法","不可数名词的用法","动词cherish的词义与用法"],"explanations":["一般将来时用来表示将来发生的动作或存在的状态，结构为“will + 动词原形”，本句中“会”表达将来的意愿，所以用“will + cherish”的结构来体现。","nature表示“大自然”时是不可数名词，前面不需要加不定冠词a/an，也没有复数形式，直接使用原形即可。","cherish作为及物动词，意为“爱护；珍视”，后面可以直接接名词作宾语，除了接nature这类表示事物的名词，还可以接time, friendship等抽象名词，强调对事物的珍视与爱护。"]},"sentenceWithHints":"我 会 爱护 大自然"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1777, '{"words":[{"plural":"environmental protections","chinese":"环保","english":"environmental protection","examples":["Environmental protection is crucial for our planet.","We should take action for environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My pen is lost.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"responsibilities","chinese":"责任","english":"responsibility","examples":["It''s my responsibility to take care of my little sister.","The manager has many responsibilities."],"phonetic":"/rɪˌspɑːnsəˈbɪləti/","partOfSpeech":"名词"}],"examPoints":{"points":["合成名词的使用","系动词be的主谓一致","物主代词的用法"],"explanations":["“环保”对应的英文是合成名词environmental protection，由形容词environmental和名词protection组合而成，这类合成名词在表达特定概念时常用，需要掌握常见的环保类相关英文词汇搭配。","本句主语environmental protection是单数概念的名词短语，所以系动词用第三人称单数形式is，这体现了主谓一致的规则，即主语为单数时，对应的be动词用is。","“我的”对应的英文是形容词性物主代词my，用来修饰后面的名词responsibility，表明所属关系，形容词性物主代词后面必须接名词，不能单独使用。"]},"sentenceWithHints":"环保 是 我的 责任"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1778, '{"words":[{"plural":"environmental protections","chinese":"环保","english":"environmental protection","examples":["Environmental protection is crucial for our planet.","We should take actions for environmental protection."],"phonetic":"/ɪnˌvaɪrənˈmentl prəˈtekʃn/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping on the sofa."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My pen is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"missions","chinese":"使命","english":"mission","examples":["His mission is to help the poor.","The team completed their mission successfully."],"phonetic":"/ˈmɪʃn/","partOfSpeech":"名词"}],"examPoints":{"points":["抽象名词的使用","系动词be的主谓一致","物主代词的用法"],"explanations":["“环保”对应的environmental protection是抽象名词，这类名词表示抽象概念，通常当作不可数名词使用，在表达泛指概念时无需加冠词；当表示不同类别的相关概念时可作可数名词变复数。本句中表示泛指的环保概念，所以用单数形式。","系动词be的形式要和主语保持主谓一致，本句主语environmental protection是单数概念，因此使用be动词的第三人称单数形式is。","“我的”对应的my是形容词性物主代词，后面必须接名词，用来表示所属关系，本句中my修饰mission，说明使命的归属者是“我”。"]},"sentenceWithHints":"环保 是 我的 使命"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1779, '{"words":[{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is the key to success.","We should gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"就是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"powers","chinese":"力量","english":"power","examples":["He has the power to change the situation.","Wind power is a kind of clean energy."],"phonetic":"/ˈpaʊər/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词的用法","系动词be的主谓一致"],"explanations":["knowledge属于抽象不可数名词，一般没有复数形式，在句中作主语时视为单数概念，不需要加不定冠词a/an。","本句主语knowledge是不可数名词，视为第三人称单数，所以系动词用is，符合主谓一致的语法规则，即主语为第三人称单数时，一般现在时的系动词用is。"]},"sentenceWithHints":"知识 就是 力量"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1780, '{"words":[{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"改变","english":"change","examples":["She changed her mind.","The weather changes quickly."],"phonetic":"/tʃeɪndʒ/","pastTense":"changed","thirdPerson":"changes","partOfSpeech":"动词","pastParticiple":"changed","presentParticiple":"changing"},{"plural":"destinies","chinese":"命运","english":"destiny","examples":["We control our own destiny.","It was his destiny to become a doctor."],"phonetic":"/ˈdestəni/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词的用法","一般现在时第三人称单数变化"],"explanations":["knowledge 是不可数名词，没有复数形式，不能直接在词尾加-s/es，表达“多种知识”时常用“kinds of knowledge”这类结构。本句中 knowledge 作为主语，视为单数概念。","一般现在时中，当主语是第三人称单数（本句中主语 knowledge 为不可数名词，属于第三人称单数范畴）时，谓语动词需要变为第三人称单数形式，规则动词一般在词尾加-s，change 的第三人称单数形式为 changes。"]},"sentenceWithHints":"知识 改变 命运"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1781, '{"words":[{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"让","english":"let","examples":["My mom let me go to the party.","He lets his dog run in the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"plural":"","chinese":"我","english":"me","examples":["Please give me a pen.","She told me a story."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"成长","english":"grow","examples":["Children grow very fast.","I want to grow into a responsible person."],"phonetic":"/ɡroʊ/","pastTense":"grew","thirdPerson":"grows","partOfSpeech":"动词","pastParticiple":"grown","presentParticiple":"growing"}],"examPoints":{"points":["使役动词let的用法","不可数名词的主谓一致","不带to的不定式作宾语补足语"],"explanations":["let作为使役动词，常见用法为let sb. do sth.，表示“让某人做某事”，其后接不带to的不定式作宾语补足语；其过去式和过去分词为不规则变化，均为let，第三人称单数形式为lets，现在分词为letting。","knowledge是不可数名词，作主语时，谓语动词要用第三人称单数形式，本句中let使用第三人称单数lets，符合主谓一致规则。","在使役动词let, make, have后接宾语补足语时，不定式要省略to，本句中let me grow符合该规则，不用写成let me to grow。"]},"sentenceWithHints":"知识 让 我 成长"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1782, '{"words":[{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"让","english":"let","examples":["My mom let me go to the party.","He lets his dog run in the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"plural":"","chinese":"我","english":"me","examples":["She gave me a gift.","Please wait for me."],"phonetic":"/miː/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"chinese":"进步","english":"progress","examples":["He is progressing well in his studies.","The project has progressed smoothly."],"phonetic":"/ˈprɑːɡres/","pastTense":"progressed","thirdPerson":"progresses","partOfSpeech":"动词","pastParticiple":"progressed","presentParticiple":"progressing"}],"examPoints":{"points":["使役动词let的用法","不可数名词的使用","动词progress的用法"],"explanations":["let作为使役动词，常用结构为let sb. do sth.，表示“让某人做某事”，其后接不带to的动词不定式作宾语补足语；该动词的过去式和过去分词为不规则变化，均为let，第三人称单数形式为lets，现在分词为letting。","knowledge是不可数名词，没有复数形式，不能直接加-s，表达“多种知识”时常用“kinds of knowledge”这类结构，在句中作主语时，谓语动词用单数形式。","progress既可用作名词也可用作动词，在本句中是动词，意为“进步、进展”，作动词时为规则变化，过去式和过去分词加-ed，第三人称单数加-es，现在分词加-ing；作名词时发音为/ˈprɑːɡres/，作动词时发音为/prəˈɡres/。"]},"sentenceWithHints":"知识 让 我 进步"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1783, '{"words":[{"plural":"knowledges","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me laugh every day.","Hard work makes success possible."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["Please give me a pen.","He told me a story."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"强大","english":"strong","examples":["He is a strong man.","Our team is getting stronger."],"phonetic":"/strɔːŋ/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","不可数名词的主谓一致","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，表示“使某人/某物处于某种状态”，本句中“makes me strong”就是该结构的体现，用形容词strong补充说明宾语me的状态。","knowledge表示“知识”时通常为不可数名词，作主语时谓语动词要用第三人称单数形式，本句中主语Knowledge是不可数名词，所以谓语动词make用第三人称单数形式makes。","在“make + 宾语 + 宾补”的结构中，除了可以接形容词作宾补，还可以接不带to的不定式等，本句中使用形容词strong作宾补，用来描述宾语“me”的状态，这是使役动词的常见搭配方式。"]},"sentenceWithHints":"知识 让 我 强大"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1784, '{"words":[{"plural":"knowledges","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"},{"chinese":"让","english":"make","examples":["She makes me happy.","The news made him sad."],"phonetic":"/meɪk/","pastTense":"made","thirdPerson":"makes","partOfSpeech":"动词","pastParticiple":"made","presentParticiple":"making"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please help me."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"智慧","english":"wise","examples":["She is a wise woman.","It''s wise to save money."],"phonetic":"/waɪz/","partOfSpeech":"形容词"}],"examPoints":{"points":["使役动词make的用法","不可数名词的主谓一致","形容词作宾语补足语"],"explanations":["make作为使役动词，常见结构为“make + 宾语 + 宾语补足语”，表示“使某人/某物处于某种状态”，本句中me是宾语，wise是形容词作宾语补足语，补充说明“我”的状态。","knowledge表示“知识”时通常为不可数名词，作主语时谓语动词要用第三人称单数形式，所以本句中make变为makes。","在“make + 宾语 + 宾补”结构中，宾补可以是形容词，用来描述宾语的状态，本句中wise作宾补，说明“我”被知识影响后处于智慧的状态。"]},"sentenceWithHints":"知识 让 我 智慧"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1785, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I am a student.","I like reading."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"热爱","english":"love","examples":["I love my family.","She loves playing the piano."],"phonetic":"/lʌv/","pastTense":"loved","thirdPerson":"loves","partOfSpeech":"动词","pastParticiple":"loved","presentParticiple":"loving"},{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词的用法","一般现在时主谓一致"],"explanations":["knowledge属于抽象不可数名词，没有复数形式，不能直接用不定冠词a/an修饰，也不能在词尾加-s/-es变复数，在句子中作宾语时直接使用原形即可。","一般现在时中，当主语是第一人称单数I时，谓语动词用原形。本句主语是I，所以谓语动词love使用原形；若主语是第三人称单数，谓语动词则要变为相应的第三人称单数形式loves。"]},"sentenceWithHints":"我 热爱 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1786, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I want to be a doctor."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"追求","english":"pursue","examples":["She wants to pursue a career in medicine.","We should pursue our dreams bravely."],"phonetic":"/pərˈsuː/","pastTense":"pursued","thirdPerson":"pursues","partOfSpeech":"动词","pastParticiple":"pursued","presentParticiple":"pursuing"},{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge about science."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["及物动词的用法","不可数名词的用法"],"explanations":["pursue是及物动词，后面可以直接接宾语，不需要加介词，本句中直接接宾语knowledge，符合及物动词的使用规则。","knowledge是不可数名词，没有复数形式，不能在后面加-s或-es，也不能直接用不定冠词a/an修饰，在句子中表示抽象的知识概念。"]},"sentenceWithHints":"我 追求 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1787, '{"words":[{"plural":"","chinese":"我","english":"I","examples":["I love reading.","I am a high school student."],"phonetic":"/aɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"","chinese":"学习","english":"learn","examples":["We learn English every day.","She learned to play the piano last year."],"phonetic":"/lɜːrn/","pastTense":"learned/learnt","thirdPerson":"learns","partOfSpeech":"动词","pastParticiple":"learned/learnt","presentParticiple":"learning"},{"plural":"","chinese":"知识","english":"knowledge","examples":["We should gain more knowledge.","Knowledge is power."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["及物动词的用法","不可数名词的用法"],"explanations":["learn作为及物动词时，后面可以直接接宾语，本句中knowledge就是learn的宾语，构成动宾结构，表示学习的对象。","knowledge是不可数名词，没有复数形式，不能在后面加-s/-es，也不能直接用不定冠词a/an修饰，表达“一些知识”可以用some knowledge这类搭配。"]},"sentenceWithHints":"我 学习 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1788, '{"words":[{"chinese":"我","english":"I","examples":["I love reading.","I am a high school student."],"phonetic":"/aɪ/","partOfSpeech":"代词"},{"chinese":"掌握","english":"master","examples":["You need to master this skill.","She masters English quickly."],"phonetic":"/ˈmæstər/","pastTense":"mastered","thirdPerson":"masters","partOfSpeech":"动词","pastParticiple":"mastered","presentParticiple":"mastering"},{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"}],"examPoints":{"points":["及物动词的用法","不可数名词的用法"],"explanations":["master作为及物动词，后面可以直接接宾语，不需要加介词，本句中直接接宾语knowledge，符合及物动词的使用规则。","knowledge属于不可数名词，没有复数形式，不能在后面加-s或-es，也不能直接用不定冠词a/an修饰，在句子中表示泛指的知识概念时直接使用原形即可。"]},"sentenceWithHints":"我 掌握 知识"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1789, '{"words":[{"plural":"knowledges","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is happy.","He is a student."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My book is on the desk.","This is my friend."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"wealths","chinese":"财富","english":"wealth","examples":["Health is wealth.","He inherited a large wealth."],"phonetic":"/welθ/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词的用法","系动词be的主谓一致"],"explanations":["knowledge和wealth都属于抽象不可数名词，通常情况下没有复数形式，也不能直接用不定冠词a/an修饰，在句子中作主语时视为单数概念。","当主语是第三人称单数（包括不可数名词）时，系动词be需要使用is的形式，本句主语knowledge是不可数名词，属于第三人称单数范畴，因此搭配系动词is。"]},"sentenceWithHints":"知识 是 我的 财富"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1790, '{"words":[{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new bag."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"friends","chinese":"朋友","english":"friend","examples":["He is my best friend.","We made a lot of friends at school."],"phonetic":"/frend/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词的用法","系动词be的主谓一致","形容词性物主代词的使用"],"explanations":["knowledge属于不可数名词，没有复数形式，不能直接和不定冠词a/an搭配，表达数量时需要借助量词短语，比如a piece of knowledge。本句中直接使用knowledge作主语，体现了不可数名词的基本用法。","系动词be的形式需要和主语保持一致，本句主语knowledge是不可数名词，视为第三人称单数，因此搭配be动词的第三人称单数形式is。","my是形容词性物主代词，后面必须接名词，用来表示所属关系，本句中my修饰friend，表明friend属于说话者。"]},"sentenceWithHints":"知识 是 我的 朋友"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1791, '{"words":[{"plural":"knowledges","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My cat is cute.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"strengths","chinese":"力量","english":"strength","examples":["He has great physical strength.","Patience is her greatest strength."],"phonetic":"/streŋθ/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词与系动词的搭配","物主代词的用法","抽象名词的使用"],"explanations":["knowledge 是抽象不可数名词，作主语时视为第三人称单数，因此搭配系动词 is。在英语中，抽象不可数名词一般没有复数形式的常规使用场景，但若表示不同领域的知识时可加s，本句中表示泛指知识，用单数形式即可。","my 是形容词性物主代词，后面必须接名词，用来表示所属关系，本句中 my 修饰 strength，表明“力量”的所属者是“我”。","knowledge 和 strength 都属于抽象名词，抽象名词通常表示概念、性质、情感等抽象事物，一般不与具体的数量词搭配，在句子中可以直接作主语或宾语，本句中分别作主语和表语，符合抽象名词的使用规则。"]},"sentenceWithHints":"知识 是 我的 力量"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1792, '{"words":[{"plural":"","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"我的","english":"my","examples":["My cat is cute.","This is my new bag."],"phonetic":"/maɪ/","pastTense":"","thirdPerson":"","partOfSpeech":"代词","pastParticiple":"","presentParticiple":""},{"plural":"weapons","chinese":"武器","english":"weapon","examples":["He used a knife as a weapon.","Education is a powerful weapon."],"phonetic":"/ˈwepən/","pastTense":"","thirdPerson":"","partOfSpeech":"名词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词的用法","物主代词的使用","系动词be的主谓一致"],"explanations":["knowledge属于抽象不可数名词，没有复数形式，在句子中作主语时视为单数概念，其后的谓语动词要用第三人称单数形式。","my是形容词性物主代词，用来修饰后面的名词weapon，表明所属关系，形容词性物主代词不能单独使用，必须和名词连用。","本句主语knowledge是不可数名词，视为第三人称单数，因此系动词使用is，遵循主谓一致原则，即主语为第三人称单数时，一般现在时的be动词用is。"]},"sentenceWithHints":"知识 是 我的 武器"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1793, '{"words":[{"plural":"knowledges","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The cat is sleeping."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"chinese":"我的","english":"my","examples":["My pen is blue.","This is my favorite song."],"phonetic":"/maɪ/","partOfSpeech":"代词"},{"plural":"wings","chinese":"翅膀","english":"wing","examples":["The bird spreads its wings.","He felt he had wings and could fly."],"phonetic":"/wɪŋ/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词的用法","系动词be的主谓一致","名词复数的象征用法"],"explanations":["knowledge表示“知识、学识”时通常作为不可数名词使用，作主语时谓语动词用单数形式；只有表示“不同的知识门类”时才用作可数名词，本句中是泛指知识这一抽象概念，作不可数名词。","系动词be的形式要和主语保持一致，本句主语knowledge是不可数名词，视为单数概念，所以搭配系动词is。","wing作为“翅膀”是可数名词，本句中用复数wings，是用具体的事物象征抽象的能力，表达“知识能像翅膀一样带‘我’提升、前进”的抽象含义，这种将具体事物用于抽象表意的用法在英语写作中可以增强表达的生动性。"]},"sentenceWithHints":"知识 是 我的 翅膀"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1794, '{"words":[{"plural":"knowledges","chinese":"知识","english":"knowledge","examples":["Knowledge is power.","We need to gain more knowledge."],"phonetic":"/ˈnɑːlɪdʒ/","partOfSpeech":"名词"},{"chinese":"让","english":"let","examples":["My mom lets me watch TV after homework.","Let''s go to the park."],"phonetic":"/let/","pastTense":"let","thirdPerson":"lets","partOfSpeech":"动词","pastParticiple":"let","presentParticiple":"letting"},{"chinese":"我","english":"me","examples":["He gave me a gift.","Please tell me the truth."],"phonetic":"/miː/","partOfSpeech":"代词"},{"chinese":"飞翔","english":"fly","examples":["Birds fly in the sky.","I want to fly to Paris."],"phonetic":"/flaɪ/","pastTense":"flew","thirdPerson":"flies","partOfSpeech":"动词","pastParticiple":"flown","presentParticiple":"flying"}],"examPoints":{"points":["使役动词let的用法","不可数名词的主谓一致","动词不定式的省略"],"explanations":["let作为使役动词，常见结构为let sb. do sth.，表示“让某人做某事”，后面接不带to的动词不定式作宾语补足语，本句中let me fly就符合这个结构。","knowledge表示“知识”时通常为不可数名词，作主语时谓语动词要用第三人称单数形式，所以本句中谓语动词let使用了第三人称单数形式lets。","在使役动词let、make、have以及感官动词see、hear等后面，作宾语补足语的动词不定式要省略to，本句中fly前省略了to，符合这个语法规则。"]},"sentenceWithHints":"知识 让 我 飞翔"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1795, '{"words":[{"plural":"times","chinese":"时间","english":"time","examples":["Time flies.","I don''t have much time."],"phonetic":"/taɪm/","partOfSpeech":"名词"},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is interesting."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"宝贵的","english":"precious","examples":["Water is precious in the desert.","She has some precious memories."],"phonetic":"/ˈpreʃəs/","pastTense":"","thirdPerson":"","partOfSpeech":"形容词","pastParticiple":"","presentParticiple":""}],"examPoints":{"points":["不可数名词的主谓一致","形容词作表语的用法"],"explanations":["time表示“时间”时是不可数名词，作主语时视为第三人称单数，因此对应的系动词要用is，这是主谓一致规则中不可数名词作主语的典型应用。","形容词precious在句中作表语，用于说明主语time的性质和特征，系动词is连接主语和表语形容词，构成主系表结构，这是英语中描述事物属性的常用句式。"]},"sentenceWithHints":"时间 是 宝贵的。"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1796, '{"words":[{"plural":"times","chinese":"时间","english":"time","examples":["Time flies.","I don''t have enough time."],"phonetic":"/taɪm/","partOfSpeech":"名词"},{"plural":"","chinese":"就","english":"just","examples":["It''s just a cat.","I just finished my homework."],"phonetic":"/dʒʌst/","pastTense":"","thirdPerson":"","partOfSpeech":"副词","pastParticiple":"","presentParticiple":""},{"chinese":"是","english":"is","examples":["She is a doctor.","The book is on the shelf."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"","chinese":"金钱","english":"money","examples":["Money can''t buy happiness.","I need some money to buy food."],"phonetic":"/ˈmʌni/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词的用法","系动词be的主谓一致"],"explanations":["time表示“时间”、money表示“金钱”时均为不可数名词，不可数名词没有复数形式，在句中作主语时视为单数概念，不需要加不定冠词a/an。","系动词be的形式需要和主语保持主谓一致，本句中主语time是不可数名词，视为第三人称单数，因此搭配系动词is。"]},"sentenceWithHints":"时间 就 是 金钱"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1797, '{"words":[{"plural":"times","chinese":"时间","english":"time","examples":["Time flies.","I don''t have much time."],"phonetic":"/taɪm/","partOfSpeech":"名词"},{"plural":"","chinese":"就","english":"just","examples":["It is just a cat.","I just finished my homework."],"phonetic":"/dʒʌst/","partOfSpeech":"副词"},{"plural":"","chinese":"是","english":"is","examples":["She is a doctor.","This is my pen."],"phonetic":"/ɪz/","pastTense":"was","thirdPerson":"is","partOfSpeech":"动词","pastParticiple":"been","presentParticiple":"being"},{"plural":"lives","chinese":"生命","english":"life","examples":["We should value life.","Many lives were saved."],"phonetic":"/laɪf/","partOfSpeech":"名词"}],"examPoints":{"points":["不可数名词的用法","系动词be的主谓一致","抽象名词的翻译"],"explanations":["本句中的“时间”和“生命”在这里作为抽象名词，属于不可数名词范畴，在英语中表示抽象概念时通常不需要变复数，直接用原形即可；但time表示“次数、倍数”等具体概念时可作可数名词，复数为times，life表示“生命（多个）”时复数为lives，属于不规则变形。","本句主语time是抽象不可数名词，视为第三人称单数，因此系动词使用is，符合主谓一致原则：当主语是第三人称单数时，一般现在时的系动词用is。","将中文抽象概念“时间”“生命”翻译为对应的英语抽象名词time和life，是中英翻译中抽象名词的常见对应译法，需要掌握常见抽象概念的英文表达，同时注意这类名词在具体语境中的可数性变化。"]},"sentenceWithHints":"时间 就 是 生命"}');
INSERT INTO question_hints (question_id, hint_data) VALUES (1798, '{"words":[{"plural":"times","chinese":"时间","english":"time","examples":["Time flies.","I don''t have much time."],"phonetic":"/taɪm/","partOfSpeech":"名词"},{"chinese":"不能","english":"cannot","examples":["I cannot swim.","He cannot come to the party."],"phonetic":"/ˈkænɑːt/","pastTense":"could not","thirdPerson":"cannot","partOfSpeech":"动词","pastParticiple":"been unable to","presentParticiple":""},{"chinese":"浪费","english":"waste","examples":["Don''t waste your money.","He wasted a lot of time playing games."],"phonetic":"/weɪst/","pastTense":"wasted","thirdPerson":"wastes","partOfSpeech":"动词","pastParticiple":"wasted","presentParticiple":"wasting"}],"examPoints":{"points":["被动语态的使用","情态动词cannot的用法"],"explanations":["本句中“时间”是被“浪费”的对象，在英语中需要使用被动语态来体现这种逻辑关系，结构为“情态动词+be+动词过去分词”，即“cannot be wasted”，表示“不能被浪费”。","cannot是情态动词can的否定形式，用于表示“不能、不可以”，后接动词原形，在被动语态结构中接be动词原形，再接动词的过去分词，用来表达禁止、不允许的含义。"]},"sentenceWithHints":"时间 不能 浪费"}');
